INSERT INTO public.questions VALUES ('aec05918-0096-4abe-a415-fc5229b35944', '05e635d8-e209-4fcb-ac52-b312817d5248', 'matrix', 'Questions 27–30', NULL, '<p>Label the diagram below.</p>
<p>Write the correct letter, <strong>A-G</strong>, next to questions 27-30.</p>
<p><img decoding="async" src="data:image/png;base64," width="521" height="494" loading="lazy"></p>
', 'other', 'null', 'null', 'null', '{"layoutType": "simple", "legendTitle": null, "matrixItems": [{"itemText": "Metal container", "correctCategoryLetter": "D"}, {"itemText": "Integral strainer", "correctCategoryLetter": "F"}, {"itemText": "Drip tip", "correctCategoryLetter": "G"}, {"itemText": "Pottery container", "correctCategoryLetter": "C"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}]}', '[{"content": "<p>1</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('ff04f702-3952-469d-8b63-7f5996d916ab', '144e4363-7b6d-4453-9401-5831fc3ea9db', 'radio', 'Questions 21-25', '', '<p>Choose the correct letter, <strong>A</strong>, <strong>B</strong>, or <strong>C</strong>.</p>', 'multiple_choice', '[{"correct": 1, "options": [{"option_text": "At first, it was unpopular with customers."}, {"option_text": "It has gained a lot of interest from chefs."}, {"option_text": "Many shops are using the idea now."}], "question": "According to Dominic, what is surprising about the supermarket garden project?"}, {"correct": 2, "options": [{"option_text": "The technology might not be well developed."}, {"option_text": "The cost could be too high."}, {"option_text": "There may not be enough room."}], "question": "What do the speakers identify as a possible problem with the solar carpark idea?"}, {"correct": 1, "options": [{"option_text": "they are much cheaper to build than was predicted."}, {"option_text": "animal populations become more genetically diverse."}, {"option_text": "they greatly reduce the number of car accidents."}], "question": "According to the speakers, the unexpected benefit of wildlife crossings is that"}, {"correct": 2, "options": [{"option_text": "how many countries the movement has spread to"}, {"option_text": "how fast cities can convert to 100% renewable energy"}, {"option_text": "how much help is given to participating communities"}], "question": "What is impressive about the 100% renewable energy campaign?"}, {"correct": 0, "options": [{"option_text": "It helps businesses undertake eco-friendly projects."}, {"option_text": "It encourages people to buy sustainable products."}, {"option_text": "It creates a sense of community in the people who participate."}], "question": "What positive point about “carrot-mobbing” does Elia describe?"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"1\"><strong data-path-to-node=\"1\" data-index-in-node=\"0\">Part 3: </strong></p>\n<p data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">Tutor:</strong> Okay everyone, get into pairs and look at the innovative environmental solutions we’ve been reading about this week. Discuss some of the pros and cons of each one.</p>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Dominic:</strong> You want to work together Ella?</p>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Ella:</strong> Sure Dominic. Which solution do you wanna look at first?</p>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">Dominic:</strong> I think the supermarket garden project’s interesting.</p>\n<p data-path-to-node=\"5\"><strong>Ella: </strong>That’s where the supermarket grows fruit and vegetables in the store and sells them.</p>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">Dominic:</strong> Yes, understandably, only a few shops have decided to adopt this idea. It’s hard to set up.</p>\n<p data-path-to-node=\"6\"><strong>Ella: </strong>What’s the reaction from customers?</p>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Dominic:</strong> Well, of course they love the idea.<span style=\"text-decoration: underline;\"> <span style=\"background-color: #ffe786;\"><strong data-path-to-node=\"7\" data-index-in-node=\"45\">(21) One thing I didn’t expect though was that the idea is hugely popular with local chefs [Answer: B]</strong></span></span>, and many of them are finding new ways to use the plants in all their different stages of growth.</p>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">Ella:</strong> I see. I found the solar car park idea to be really practical.</p>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Dominic:</strong> I know what you mean. Putting solar panels on the roofs of car parks to generate electricity might be a cost-effective way to power a whole shopping centre.</p>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">Ella:</strong> <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"10\" data-index-in-node=\"6\">(22) The difficulty could be finding space to put all the panels [Answer: C]</strong></span>. Some smaller shopping centres probably don’t have covered car parks.</p>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Dominic:</strong> That’s right. It’s a shame because the technology seems to be all there and ready to go if the conditions are right.</p>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">Ella: </strong>What do you think of the wildlife crossing solution? You know, when a bridge or a tunnel is built over or under a major roadway so that animals can cross.</p>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">Dominic:</strong> That idea has become very popular and has so many benefits. A lot of research has been done, hasn’t it?</p>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">Ella:</strong> Yes. It’s not surprising that the data reveals a huge drop in the number of road accidents in areas where there are wildlife crossings. That’s one of the predicted outcomes.</p>\n<p data-path-to-node=\"13\"><strong>Dominic</strong>: Something I read about in the research, which I’d never considered before, was how the animal populations in these areas are affected. Naturally more of them survive, but <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"13\" data-index-in-node=\"354\">(23) because their habitat is not interrupted too much by the roads, the genetic diversity of local species has improved [Answer: B]</strong>.</span></p>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">Ella:</strong> That’s true. It’s worth the huge cost of building them if the result is a win-win for people and animals. I found the 100% <strong>renewable energy campaign</strong>, like solar and wind energy, to be really impressive.</p>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">Dominic:</strong> Yes, it’s not so much the size of the movement—I mean only a few countries are involved—as <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"15\" data-index-in-node=\"100\">(24) the amount of support offered once a community joins [Answer: C]</strong></span>.</p>\n<p data-path-to-node=\"15\"><strong>Ella: </strong>Considering the sheer amount of time and planning it takes for a city to convert completely to renewables, the organizers of the movement would need to do that.</p>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">Ella:</strong> Did you read about <strong>carrot mobbing</strong> as an environmental movement?</p>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">Dominic:</strong> What’s that?</p>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">Ella:</strong> It’s where huge numbers of people learn through the internet about where to shop at stores that use the profits to support environmental projects.</p>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">Dominic:</strong> So they stop buying products that aren’t eco-friendly? Like a boycott?</p>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">Ella:</strong> No, actually it’s the opposite of that.<span style=\"text-decoration: underline;\"> <span style=\"background-color: #ffe786;\"><strong data-path-to-node=\"20\" data-index-in-node=\"46\">(25) It allows businesses to fund initiatives to help protect the environment by boosting their profiles [Answer: A]</strong></span></span>. It’s a pity that most participants don’t get to know each other personally; it’s all through online notices.</p>\n<hr data-path-to-node=\"21\">\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">Aerial Reforestation Process (Flow Chart)</strong></p>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">Tutor:</strong> Now everyone, let’s look at one particular environmental innovation: aerial reforestation. With your partner, discuss the process involved in this idea.</p>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\"><span class=\"citation-2902\">Ella:</span></strong><span class=\"citation-2902 citation-end-2902\"> So aerial reforestation is where they drop mixtures from planes to sow vegetables, grains or trees and so on in areas that might be hard to reach.<sup class=\"superscript\" data-turn-source-index=\"1\"><!----></sup></span> Let’s see, what are the steps?</p>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">Dominic:</strong> Well, the first step is choosing the right area. Whatever size land you’re working on, <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"25\" data-index-in-node=\"96\">(26) ensuring there’s enough light [H] is crucial</strong>.</span></p>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"26\" data-index-in-node=\"0\">Ella:</strong> The next step, whatever you’re planting, is to make sure you have the <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"26\" data-index-in-node=\"76\">(27) right seeds [C]</strong></span>.</p>\n<p data-path-to-node=\"24\"><strong>Dominic :</strong>To give them a better chance against the competition from other plants, you need to use a lot.</p>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">Ella:</strong> So then you make a mixture with decent quality, <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"27\" data-index-in-node=\"57\">(28) durable compost [E] for nourishment</strong>.</span></p>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"28\" data-index-in-node=\"0\">Dominic :</strong> Then do they infuse it with insecticide?</p>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">Ella:</strong> That’s not necessary in this model. <span style=\"text-decoration: underline; background-color: #ffe786;\">The next step is pressing the whole thing into a small chunk of <strong data-path-to-node=\"29\" data-index-in-node=\"109\">(29) clay [G] to make a ball</strong>.</span><button class=\"button ng-star-inserted\" aria-label=\"View source details for citation from Penn State University. Opens side panel.\" data-hveid=\"0\" data-ved=\"0CAAQvoAQahgKEwibysXC1LWSAxUAAAAAHQAAAAAQmgQ\"><!----><!----></button><!----><!----><!----><!----></p>\n<p data-path-to-node=\"2\"><!----><!----><!----><!----><!----><!----><!----><!----><!----></p>\n<p data-path-to-node=\"30\"><strong data-path-to-node=\"30\" data-index-in-node=\"0\">Ella:</strong> This may then be covered in an outer material, such as paper,</p>\n<p data-path-to-node=\"30\"><strong>Dominic: </strong>right? <span style=\"text-decoration: underline; background-color: #ffe786;\">That way, when it lands, <strong data-path-to-node=\"30\" data-index-in-node=\"100\">(30) it will add balanced nutrients [D] to the mixture</strong></span>,</p>\n<p data-path-to-node=\"30\"><strong>Ella: </strong>Yes, and it may also protect it from insects and other plants.</p>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"31\" data-index-in-node=\"0\">Dominic:</strong> Yes, and a few days before they release it from the plane onto the land below, the final step is dipping it in water just enough to get the germination process started.</p>\n<p data-path-to-node=\"32\"><strong data-path-to-node=\"32\" data-index-in-node=\"0\">Ella:</strong> Yes, and after that…</p>"}]', 0);
INSERT INTO public.questions VALUES ('2cb462c7-e6c1-4342-b02f-ccf31f930c9d', '71286907-199c-4713-aac8-fe32a61243db', 'fillup', 'Questions 15 – 20', '<p>Complete the sentences below.</p>
<p>Choose <strong>ONE WORD ONLY </strong>from the text for each answer.</p>
<p>Write your answers in boxes 15-20 on your answer sheet.</p>
<p>A friendly {personality} is an asset for a teller.</p>
<p>Building good working {relationships} with local clientele can help with a teller’s career goals.</p>
<p>Tellers can get help from {colleagues} if they are unsure of bank procedures.</p>
<p>A {promotion} is possible after taking bank-related courses.</p>
<p>Being a teller is good training for an eventual job as a local {manager}.</p>
<p>Most full-time bank employees do not need to pay for their own healthcare {insurance}.</p>', '', 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p><strong data-path-to-node=\"4\" data-index-in-node=\"0\">15. A friendly {personality} is an asset for a teller.</strong></p>\n<ul data-path-to-node=\"5\">\n<li><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"11\">“It is helpful to have an <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"37\">outgoing personality</strong> if you want to be a teller…”</em></li>\n<li><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Friendly” đồng nghĩa với “outgoing” (cởi mở, thân thiện). “An asset” (một tài sản/lợi thế) tương ứng với “helpful”. Đặc điểm cần thiết ở đây chính là tính cách (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"174\">personality</strong>).</li>\n</ul>\n<p><strong data-path-to-node=\"6\" data-index-in-node=\"0\">16. Building good working {relationships} with local clientele can help with a teller’s career goals.</strong></p>\n<ul data-path-to-node=\"7\">\n<li><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"11\">“Developing <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"23\">business relationships</strong> with people in the community can be very rewarding and helpful as you <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"116\">advance through the bank</strong>.”</em></li>\n<li><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Local clientele” (khách hàng địa phương) tương ứng với “people in the community”. Việc phát triển các mối quan hệ (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"128\">relationships</strong>) sẽ giúp ích cho mục tiêu thăng tiến sự nghiệp (advance through the bank).</li>\n</ul>\n<p><strong data-path-to-node=\"8\" data-index-in-node=\"0\">17. Tellers can get help from {colleagues} if they are unsure of bank procedures.</strong></p>\n<ul data-path-to-node=\"9\">\n<li><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"11\">“If you’re <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"22\">not sure of something</strong>, you can <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"53\">turn to your colleagues for assistance</strong>.”</em></li>\n<li><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Get help” và “assistance” là từ đồng nghĩa. Khi không chắc chắn về điều gì đó (unsure), giao dịch viên có thể nhờ cậy sự giúp đỡ từ đồng nghiệp (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"158\">colleagues</strong>).</li>\n</ul>\n<p><strong data-path-to-node=\"10\" data-index-in-node=\"0\">18. A {promotion} is possible after taking bank-related courses.</strong></p>\n<ul data-path-to-node=\"11\">\n<li><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"11\">“Working as a bank teller will also prepare you for a <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"65\">possible promotion</strong>, especially if you <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"103\">take some courses</strong>…”</em></li>\n<li><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc tham gia các khóa học (take courses) sẽ tạo điều kiện cho một sự thăng tiến (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"94\">promotion</strong>) có thể xảy ra.</li>\n</ul>\n<p><strong data-path-to-node=\"12\" data-index-in-node=\"0\">19. Being a teller is good training for an eventual job as a local {manager}.</strong></p>\n<ul data-path-to-node=\"13\">\n<li><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"11\">“…especially if you take some courses… This may lead to the position of <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"87\">branch manager</strong> in time.”</em></li>\n<li><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Eventual job” (công việc sau này) tương ứng với “in time”. Vị trí cụ thể mà bài đọc nhắc tới là quản lý (<strong data-path-to-node=\"13,1,0\" data-index-in-node=\"118\">manager</strong>) chi nhánh.</li>\n</ul>\n<p><strong data-path-to-node=\"14\" data-index-in-node=\"0\">20. Most full-time bank employees do not need to pay for their own healthcare {insurance}.</strong></p>\n<ul data-path-to-node=\"15\">\n<li><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"15,0,0\" data-index-in-node=\"11\">“For full-time employees, most banks provide <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"56\">insurance</strong> to cover prescriptions, dental and vision care.”</em></li>\n<li><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Healthcare” bao gồm chăm sóc nha khoa, thị lực và thuốc men. Vì ngân hàng đã cung cấp (provide), nên nhân viên không cần tự trả tiền cho gói bảo hiểm (<strong data-path-to-node=\"15,1,0\" data-index-in-node=\"164\">insurance</strong>) này.</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('8d76f8c1-b2bb-43f9-b9bc-be6118f3f165', '144e4363-7b6d-4453-9401-5831fc3ea9db', 'matching', 'Questions 26–30', '', '<p>Complete the flow chart below.</p>
<p>Choose <strong>FIVE </strong>answers from the box and write the correct letter, A–H, next to questions 26–30.</p>', 'summary_completion', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p style=\"text-align: center;\"><strong>Aerial Reforestation Process<br></strong></p>\n<p style=\"text-align: center;\"> </p>\n<p style=\"text-align: center;\">Choose a reforestation area with plenty of {H light}</p>\n<p style=\"text-align: center;\">↓</p>\n<p style=\"text-align: center;\">Take a lot of suitable {C seeds} appropriate to your purposes.</p>\n<p style=\"text-align: center;\">↓</p>\n<p style=\"text-align: center;\">Mix with long-lasting {E compost}</p>\n<p style=\"text-align: center;\">↓</p>\n<p style=\"text-align: center;\">Press into lumps of {G clay}</p>\n<p style=\"text-align: center;\">↓</p>\n<p style=\"text-align: center;\">Apply an outer coating, e.g. paper, to provide appropriate levels of {D nutrients}<br> and protection.</p>", "answerOptions": [{"optionText": "A land"}, {"optionText": "B plants"}, {"optionText": "C seeds"}, {"optionText": "D nutrients"}, {"optionText": "E compost"}, {"optionText": "F insecticide"}, {"optionText": "G clay"}, {"optionText": "H light"}], "matchingItems": []}', 'null', '[{"content": "<p>1</p>"}]', 1);
INSERT INTO public.questions VALUES ('0ce2e015-0c05-42d5-b26e-484561c52cee', '0bdcc88d-ac3d-4023-aed2-6ec717b355a1', 'matching', 'Questions 27–31', '', '<p><em data-path-to-node="3" data-index-in-node="0">Complete each sentence with the correct ending, <strong data-path-to-node="3" data-index-in-node="48">A–H</strong>, below.</em></p>
<p><em data-path-to-node="3" data-index-in-node="60">Write the correct letter, <strong data-path-to-node="3" data-index-in-node="86">A–H</strong>, in boxes 27–31 on your answer sheet.</em></p>', 'matching_name', 'null', 'null', '{"layoutType": "standard", "summaryText": "", "answerOptions": [{"optionText": "should be easy to understand"}, {"optionText": "can improve without treatment"}, {"optionText": "can cost the patient less"}, {"optionText": "ought to last a minimum length of time"}, {"optionText": "can require a range of different products"}, {"optionText": "can be described as serious"}, {"optionText": "should give it greater recognition"}, {"optionText": "should be able to get a high income"}], "matchingItems": [{"questionPart": "An appointment with an alternative practitioner", "correctAnswer": "D"}, {"questionPart": "An alternative practitioner’s explanation of their treatment", "correctAnswer": "A"}, {"questionPart": "If alternative practitioners have faith in their treatment, they", "correctAnswer": "H"}, {"questionPart": "Quite often, a patient’s illness", "correctAnswer": "B"}, {"questionPart": "Conventional doctors are aware of the placebo effect and they", "correctAnswer": "G"}]}', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">27. An appointment with an alternative practitioner — {D} ought to last a minimum length of time.</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…each session with your patients should take <strong data-path-to-node=\"4,0,0\" data-index-in-node=\"59\">at least half an hour</strong>.” (Đoạn 1)</p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “At least half an hour” tương ứng với “a minimum length of time”.</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">28. An alternative practitioner’s explanation of their treatment — {A} should be easy to understand.</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “Describe your treatment in <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"39\">familiar words</strong>…” (Đoạn 1)</p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Sử dụng “từ ngữ quen thuộc” nghĩa là cách giải thích đó phải dễ hiểu với bệnh nhân.</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">29. If alternative practitioners have faith in their treatment, they — {H} should be able to get a high income.</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “And a <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"18\">very good living</strong> if you are sufficiently convincing or, better still, really <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"95\">believe in your therapy</strong>.” (Đoạn 2)</p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “A very good living” (có cuộc sống tốt) đồng nghĩa với “get a high income” (có thu nhập cao).</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">30. Quite often, a patient’s illness — {B} can improve without treatment.</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “<strong data-path-to-node=\"10,0,0\" data-index-in-node=\"12\">Many illnesses get better on their own</strong>, so if you are lucky… you’ll get the credit.” (Đoạn 2)</p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Get better on their own” tương ứng với “improve without treatment” (tự khỏi mà không cần điều trị).</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">31. Conventional doctors are aware of the placebo effect and they — {G} should give it greater recognition.</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…conventional medicine recognizes but remains <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"60\">oddly ambivalent</strong> about [it]… though its role is <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"110\">often neglected and misunderstood</strong>.” (Đoạn 2 &amp; 3)</p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Vì y học hiện đại vẫn còn “mơ hồ” (ambivalent) và “bỏ qua/hiểu sai” (neglected/misunderstood) về hiệu ứng này, nên tác giả ngụ ý họ cần phải công nhận nó nhiều hơn.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('e2e959fe-2b0f-4e1b-8136-32b70c948767', '71286907-199c-4713-aac8-fe32a61243db', 'fillup', 'Questions 21 – 27', '<p>Complete the notes below.</p>
<p>Choose <strong>ONE WORD ONLY</strong> from the text for each answer.</p>
<p>Write your answers in boxes 21-27 on your answer sheet.</p>
<p style="text-align: center;" data-path-to-node="8"><span style="font-size: 12pt;"><strong data-path-to-node="8" data-index-in-node="0">Productive and Happy Employees</strong></span></p>
<p data-path-to-node="9"><strong data-path-to-node="9" data-index-in-node="0">To keep employees happy, employers should:</strong></p>
<ul data-path-to-node="10">
<li>
<p data-path-to-node="10,0,0">show good {leadership} by setting clear expectations</p>
</li>
<li>
<p data-path-to-node="10,1,0">avoid {problems} by giving adequate instructions</p>
</li>
<li>
<p data-path-to-node="10,2,0">give {encouragement} when training workers</p>
</li>
<li>
<p data-path-to-node="10,3,0">do a {survey} to assess employee satisfaction</p>
</li>
<li>
<p data-path-to-node="10,4,0">provide a pleasing {environment} that encourages workers’ efficiency</p>
</li>
<li>
<p data-path-to-node="10,5,0">provide healthy things to eat to improve the mood of workers</p>
</li>
<li>
<p data-path-to-node="10,6,0">have {meetings} in which all workers can participate and feel included</p>
</li>
<li>
<p data-path-to-node="10,7,0">make employees feel they are a valuable part of the {company}</p>
</li>
</ul>', '', 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p><strong data-path-to-node=\"4\" data-index-in-node=\"0\">21. Show good {leadership} by setting clear expectations.</strong></p>\n<ul data-path-to-node=\"5\">\n<li><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"11\">“You need to demonstrate healthy <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"44\">leadership</strong> and be direct. Let employees know what is to be done…”</em> (Mục 1)</li>\n<li><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Demonstrate healthy leadership” tương ứng với “show good leadership”. Việc cho nhân viên biết cần làm gì (be direct) chính là thiết lập kỳ vọng rõ ràng (setting clear expectations).</li>\n</ul>\n<p><strong data-path-to-node=\"6\" data-index-in-node=\"0\">22. Avoid {problems} by giving adequate instructions.</strong></p>\n<ul data-path-to-node=\"7\">\n<li><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"11\">“The more you outline how things are to be done [instructions], the fewer <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"85\">problems</strong> arise…”</em> (Mục 1)</li>\n<li><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Fewer problems arise” đồng nghĩa với việc tránh được các vấn đề (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"78\">problems</strong>). “Outline how things are to be done” chính là đưa ra hướng dẫn đầy đủ (adequate instructions).</li>\n</ul>\n<p><strong data-path-to-node=\"8\" data-index-in-node=\"0\">23. Give {encouragement} when training workers.</strong></p>\n<ul data-path-to-node=\"9\">\n<li><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"11\">“Offer <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"18\">encouragement</strong> while teaching them correct ways of doing things…”</em> (Mục 2)</li>\n<li><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Teaching them correct ways of doing things” chính là hoạt động đào tạo (training). Trong quá trình này, chủ doanh nghiệp cần đưa ra sự khích lệ (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"158\">encouragement</strong>).</li>\n</ul>\n<p><strong data-path-to-node=\"10\" data-index-in-node=\"0\">24. Do a {survey} to assess employee satisfaction.</strong></p>\n<ul data-path-to-node=\"11\">\n<li><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"11\">“You may want to conduct a <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"38\">survey</strong> of your workers… to make sure they are <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"86\">happy with the job</strong>.”</em> (Mục 2)</li>\n<li><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Happy with the job” tương ứng với sự hài lòng của nhân viên (employee satisfaction). Công cụ để đánh giá việc này là một bản khảo sát (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"148\">survey</strong>).</li>\n</ul>\n<p><strong data-path-to-node=\"12\" data-index-in-node=\"0\">25. Provide a pleasing {environment} that encourages workers’ efficiency.</strong></p>\n<ul data-path-to-node=\"13\">\n<li><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"11\">“A comfortable and satisfying working <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"49\">environment</strong> is what employees need in order to be able to maximize their <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"122\">productivity</strong>.”</em> (Mục 3)</li>\n<li><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Pleasing” đồng nghĩa với “comfortable and satisfying”. “Maximize productivity” tương ứng với việc khuyến khích hiệu quả làm việc (encourage efficiency).</li>\n</ul>\n<p><strong data-path-to-node=\"14\" data-index-in-node=\"0\">26. Have {meetings} in which all workers can participate and feel included.</strong></p>\n<ul data-path-to-node=\"15\">\n<li><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"15,0,0\" data-index-in-node=\"11\">“Regular <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"20\">meetings</strong> make employees feel involved, as everyone can <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"75\">voice their opinions</strong>.”</em> (Mục 4)</li>\n<li><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Feel involved” tương ứng với “feel included”. Việc mọi người có thể nói lên ý kiến (voice opinions) chính là sự tham gia (<strong data-path-to-node=\"15,1,0\" data-index-in-node=\"135\">participate</strong>).</li>\n</ul>\n<p><strong data-path-to-node=\"16\" data-index-in-node=\"0\">27. Make employees feel they are a valuable part of the {company}.</strong></p>\n<ul data-path-to-node=\"17\">\n<li><strong data-path-to-node=\"17,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"17,0,0\" data-index-in-node=\"11\">“Ask employees for their ideas… so they feel a sense of <strong data-path-to-node=\"17,0,0\" data-index-in-node=\"69\">ownership with the company</strong>.”</em> (Mục 4)</li>\n<li><strong data-path-to-node=\"17,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Sense of ownership” (cảm giác làm chủ/thuộc về) tương ứng với việc cảm thấy mình là một phần giá trị (valuable part) của công ty (<strong data-path-to-node=\"17,1,0\" data-index-in-node=\"143\">company</strong>).</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('41fd1c99-4c76-41b0-bd06-e7c06f4d4ef3', '0bdcc88d-ac3d-4023-aed2-6ec717b355a1', 'radio', 'Questions 32–34', '', '<p><em data-path-to-node="9" data-index-in-node="0"><span class="citation-6165 citation-6166 citation-end-6166">Choose the correct le</span><span class="citation-6165">tter, </span><strong data-path-to-node="9" data-index-in-node="27"><span class="citation-6165">A, B, C</span></strong><span class="citation-6165"> or </span><strong data-path-to-node="9" data-index-in-node="38"><span class="citation-6165">D</span></strong><span class="citation-6165 citation-end-6165">.</span></em></p>
<p><em data-path-to-node="9" data-index-in-node="41"><span class="citation-6164 citation-end-6164">Write the correct letter in b</span>oxes 32–34 on your answer sheet.</em></p>', 'multiple_choice', '[{"correct": 3, "options": [{"option_text": "A works best in tablet form."}, {"option_text": "B is a new type of medical treatment."}, {"option_text": "C is trusted more by some patients than by others."}, {"option_text": "D has a significant role in both alternative and conventional medicine."}], "question": "In the third paragraph, the writer says that the placebo effect"}, {"correct": 0, "options": [{"option_text": "A personal feelings can alter our physical condition."}, {"option_text": "B some human behaviour has no clear explanation."}, {"option_text": "C placebos, like emotions, are experienced by everyone."}, {"option_text": "D people find some physical reactions hard to control."}], "question": "A reference is made to anger and sadness in order to show that"}, {"correct": 2, "options": [{"option_text": "A Only a limited amount of research has been conducted so far."}, {"option_text": "B Scientists have discovered that endorphins can help to reduce pain."}, {"option_text": "C Pain-reducing agents might also be involved in the placebo effect."}, {"option_text": "D Patients often experience pain and like to complain about it."}], "question": "Research on pain control attracts most of the attention because"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">32. In the third paragraph, the writer says that the placebo effect — {D} has a significant role in both alternative and conventional medicine.</strong></p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “In fact, the placebo is a <strong data-path-to-node=\"16,0,0\" data-index-in-node=\"38\">powerful part of all medical care, orthodox or otherwise</strong>…” (Đoạn 3)</p>\n</li>\n<li>\n<p data-path-to-node=\"16,1,0\"><strong data-path-to-node=\"16,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Orthodox or otherwise” có nghĩa là cả y học chính thống (conventional) và các loại hình khác (alternative).</p>\n</li>\n</ul>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">33. A reference is made to anger and sadness in order to show that — {A} personal feelings can alter our physical condition.</strong></p>\n<ul data-path-to-node=\"18\">\n<li>\n<p data-path-to-node=\"18,0,0\"><strong data-path-to-node=\"18,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…our <strong data-path-to-node=\"18,0,0\" data-index-in-node=\"19\">state of mind can influence our physiology</strong>: anger opens the superficial blood vessels… sadness pumps the tear glands.” (Đoạn 4)</p>\n</li>\n<li>\n<p data-path-to-node=\"18,1,0\"><strong data-path-to-node=\"18,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cảm xúc (anger, sadness) dẫn đến các thay đổi vật lý (mặt đỏ, chảy nước mắt) chứng minh tâm trí có thể thay đổi tình trạng cơ thể.</p>\n</li>\n</ul>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">34. Research on pain control attracts most of the attention because — {C} Pain-reducing agents might also be involved in the placebo effect.</strong></p>\n<ul data-path-to-node=\"20\">\n<li>\n<p data-path-to-node=\"20,0,0\"><strong data-path-to-node=\"20,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “Any of the <strong data-path-to-node=\"20,0,0\" data-index-in-node=\"23\">neurochemicals involved in transmitting pain impulses</strong>… might also be involved in <strong data-path-to-node=\"20,0,0\" data-index-in-node=\"106\">generating the placebo response</strong>…” (Đoạn 4)</p>\n</li>\n<li>\n<p data-path-to-node=\"20,1,0\"><strong data-path-to-node=\"20,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Các chất dẫn truyền thần kinh liên quan đến giảm đau được cho là cũng tham gia vào việc tạo ra phản ứng giả dược.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('31af6886-1804-441c-ab54-22c3eb1e3928', '9c6bd3a7-4154-4ae7-a079-5cbd103a29d6', 'radio', 'Questions 1–6', '', '<p>Choose <strong data-path-to-node="3" data-index-in-node="7">TRUE</strong> if the statement agrees with the information given in the text, choose <strong data-path-to-node="3" data-index-in-node="83">FALSE</strong> if the statement contradicts the information, or choose <strong data-path-to-node="3" data-index-in-node="145">NOT GIVEN</strong> if there is no information on this.</p>', 'true_false_not_given', '[{"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "In 1986 Luc Long had been looking for an opportunity to dive in the Rhône for some time."}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Long and his friend were the first divers to find Roman remains in the Rhône."}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Long’s work in the Rhône attracted immediate interest."}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "It was thought that the Neptune statue would be of interest to thieves."}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Benoît Poinard doubted that the barge could be raised in one diving season."}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The restorers were surprised to discover a silver coin on the barge."}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">1. In 1986 Luc Long had been looking for an opportunity to dive in the Rhône for some time. — {FALSE}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 2):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“In 1986, a friend persuaded him to dive for the first time in his home river. <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"99\">Long reluctantly agreed</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi nói Long đã tìm kiếm cơ hội lặn ở sông Rhône từ lâu. Tuy nhiên, bài đọc cho biết ông chỉ lặn vì được bạn thuyết phục và ông đã <strong data-path-to-node=\"5,1,0\" data-index-in-node=\"147\">“reluctantly agreed”</strong> (đồng ý một cách miễn cưỡng). Hai thông tin này trái ngược nhau hoàn toàn.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">2. Long and his friend were the first divers to find Roman remains in the Rhône. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 2):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“The two men… discovered an ancient Roman jar – known as an amphora…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ kể về việc Long và bạn của ông tìm thấy cổ vật, nhưng <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"78\">không hề khẳng định</strong> họ là những người đầu tiên tìm thấy tàn tích La Mã ở con sông này hay đã có ai tìm thấy trước đó chưa. Vì thiếu thông tin để so sánh “người đầu tiên”, đáp án là Not Given.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">3. Long’s work in the Rhône attracted immediate interest. — {FALSE}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 3):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">“For the <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"29\">first 20 years or so, no one paid much attention</strong> to what Long was doing.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi nói công việc của Long thu hút sự chú ý ngay lập tức (<em data-path-to-node=\"9,1,0\" data-index-in-node=\"74\">immediate interest</em>). Thực tế bài đọc ghi rõ trong khoảng 20 năm đầu không ai quan tâm đến việc ông làm. Thông tin này trái ngược nhau.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">4. It was thought that the Neptune statue would be of interest to thieves. — {TRUE}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 3):</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"20\">“The French customs police warned Long that <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"64\">antiquities thieves might be watching</strong> his operation. So when his divers found a two-metre statue of the god Neptune, <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"181\">they brought it to the surface at night</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cảnh sát đã cảnh báo về kẻ trộm, và vì lo ngại bức tượng Neptune bị đánh cắp nên họ đã phải đưa nó lên mặt nước vào ban đêm. Điều này xác nhận rằng bức tượng được cho là sẽ thu hút sự quan tâm của kẻ trộm.</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">5. Benoît Poinard doubted that the barge could be raised in one diving season. — {TRUE}</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 5):</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"20\">“‘<strong data-path-to-node=\"13,0,0\" data-index-in-node=\"22\">We thought the project was doomed to fail</strong>,’ said Benoit Poinard… Three or four months would not be enough to excavate Arles-Rhône 3.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Poinard tin rằng dự án sẽ thất bại vì thời gian lặn an toàn trên sông Rhône quá ngắn (chỉ 3-4 tháng), không đủ để trục vớt con tàu trong một mùa. Tức là ông nghi ngờ khả năng thành công của việc trục vớt trong một mùa lặn.</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">6. The restorers were surprised to discover a silver coin on the barge. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 6):</strong> <em data-path-to-node=\"15,0,0\" data-index-in-node=\"20\">“When the restorers were taking the boat apart, they also found a silver coin… <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"101\">it had been put there to bring good luck</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc có nhắc đến việc tìm thấy đồng xu bạc và lý do nó ở đó (để cầu may), nhưng <strong data-path-to-node=\"15,1,0\" data-index-in-node=\"95\">không có thông tin</strong> nào nói rằng các nhà phục chế cảm thấy “ngạc nhiên” (<em data-path-to-node=\"15,1,0\" data-index-in-node=\"167\">surprised</em>). </p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('e2006db8-d9ff-43ac-a1a4-e8531962618a', '1b48b8ab-5ec7-4a8e-89d9-4acf0335fd69', 'radio', 'Questions 28 – 31', '', '<p><em data-path-to-node="3" data-index-in-node="0">Choose the correct letter, <strong data-path-to-node="3" data-index-in-node="27">A</strong>, <strong data-path-to-node="3" data-index-in-node="30">B</strong>, <strong data-path-to-node="3" data-index-in-node="33">C</strong> or <strong data-path-to-node="3" data-index-in-node="38">D</strong>.</em></p>
<p><em data-path-to-node="3" data-index-in-node="41">Write the correct letter in boxes 28-31 on your answer sheet.</em></p>', 'multiple_choice', '[{"correct": 2, "options": [{"option_text": "A Outside of Brazil, it is known about only by academics."}, {"option_text": "B Of all the world''s languages, it is the most endangered."}, {"option_text": "C There is no similar language to it anywhere in the world."}, {"option_text": "D It has fewer vowels and consonants than any other language."}], "question": "What does John Colapinto say about the Pirahã language in the first paragraph?"}, {"correct": 1, "options": [{"option_text": "A encouraged him to do further tests."}, {"option_text": "B confirmed the result of his earlier test."}, {"option_text": "C contained weaknesses in how it was set up."}, {"option_text": "D made him think some of the Pirahã could actually count."}], "question": "According to the fifth paragraph, the clapping experiment conducted by Caleb Everett"}, {"correct": 0, "options": [{"option_text": "A may be exploited financially by outsiders."}, {"option_text": "B are unable to exchange goods with outsiders."}, {"option_text": "C demand too high a price for the goods they sell."}, {"option_text": "D have experienced financial disputes with traders."}], "question": "According to the sixth paragraph, a drawback for the Pirahã of their language is that they"}, {"correct": 0, "options": [{"option_text": "A They appear quite happy to live with their lack of numeracy."}, {"option_text": "B They should learn to count as nobody can live without money."}, {"option_text": "C They will continue to make every effort to reject the modern world."}, {"option_text": "D They could look after their health better if they could use numbers."}], "question": "In the final paragraph, what does the writer suggest about the Pirahã?"}]', 'null', 'null', 'null', '[{"content": "<p><strong data-path-to-node=\"4\" data-index-in-node=\"0\">28. What does John Colapinto say about the Pirahã language in the first paragraph? — {C} There is no similar language to it anywhere in the world.</strong></p>\n<ul data-path-to-node=\"5\">\n<li><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"11\">“…John Colapinto, who wrote, ‘<strong data-path-to-node=\"5,0,0\" data-index-in-node=\"43\">Unrelated to any other tongue</strong>… Pirahã has one of the simplest sound systems known.’”</em></li>\n<li><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm từ “Unrelated to any other tongue” (không liên quan đến bất kỳ ngôn ngữ nào khác) đồng nghĩa với việc không có ngôn ngữ nào tương tự như nó trên thế giới (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"171\">no similar language</strong>).</li>\n</ul>\n<p><strong data-path-to-node=\"6\" data-index-in-node=\"0\">29. According to the fifth paragraph, the clapping experiment conducted by Caleb Everett — {B} confirmed the result of his earlier test.</strong></p>\n<ul data-path-to-node=\"7\">\n<li><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"11\">“English speakers make few errors… but, <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"53\">again, the Pirahã appeared not to be counting</strong>. Instead, they were employing a strategy Caleb calls ‘analog estimation’…”</em></li>\n<li><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Ở thí nghiệm trước đó với những viên pin, Caleb đã thấy họ không đếm được quá số 3. Khi làm thí nghiệm vỗ tay (clapping experiment), kết quả <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"153\">lại một lần nữa</strong> (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"170\">again</strong>) cho thấy họ không hề đếm. Điều này xác nhận (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"222\">confirmed</strong>) kết quả của thí nghiệm trước đó.</li>\n</ul>\n<p><strong data-path-to-node=\"8\" data-index-in-node=\"0\">30. According to the sixth paragraph, a drawback for the Pirahã of their language is that they — {A} may be exploited financially by outsiders.</strong></p>\n<ul data-path-to-node=\"9\">\n<li><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"11\">“Nothing about the Pirahã’s… daily existence seems to require quantity recognition… a fact that’s not lost on outsiders, who sometimes <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"150\">take advantage of them when trading goods</strong>.”</em></li>\n<li><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Drawback” (hạn chế/bất lợi) của việc không biết đếm là họ dễ bị người ngoài “tận dụng/lợi dụng” (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"110\">take advantage of</strong>) khi trao đổi hàng hóa. Trong ngữ cảnh thương mại, điều này tương ứng với việc bị lợi dụng về mặt tài chính (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"237\">exploited financially</strong>).</li>\n</ul>\n<p><strong data-path-to-node=\"10\" data-index-in-node=\"0\">31. In the final paragraph, what does the writer suggest about the Pirahã? — {A} They appear quite happy to live with their lack of numeracy.</strong></p>\n<ul data-path-to-node=\"11\">\n<li><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"11\">“…the Pirahã are simply <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"37\">getting on with enjoying life</strong>, <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"68\">immune</strong> to the relentless tyranny of numbers.”</em></li>\n<li><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả mô tả người Pirahã vẫn đang tận hưởng cuộc sống (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"69\">enjoying life</strong>) và “miễn nhiễm” (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"101\">immune</strong>) với sự kìm kẹp của những con số. Điều này cho thấy họ hoàn toàn vui vẻ/hài lòng (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"190\">happy</strong>) dù thiếu kỹ năng tính toán (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"225\">lack of numeracy</strong>).</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('01647ac8-d73f-4e5f-b559-9d84d6b50f02', '9bc03f30-fa12-4e03-b7bd-8215caf3dde0', 'fillup', 'Questions 1–4', '<p>Complete the summary below.</p>
<p>Write <strong>NO MORE THAN THREE WORDS</strong> from the passage for each answer.</p>
<p>The pronunciation of living language undergoes changes throughout thousands of years. Large-scale regular changes are usually called {sound laws} There are three reasons for these changes. Firstly, the influence of one language on another; when one person imitates another pronunciation (the most prestige’s), the imitation always partly involving factor of {fashion}. Secondly, the imitation of children from adults language sometimes are {imperfect} , and may also contribute to this change if there are insignificant deviations though later they may be corrected. Finally, for those random variations in pronunciation, the deeper evidence lies in the {principle of ease} or minimization of effort.</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p>1. sound laws<br />\n(Đoạn B: “Such regular changes are often called sound laws.”)<br />\n→ Các thay đổi phát âm quy mô lớn, mang tính quy luật, được gọi là sound laws.</p>\n<p>2. fashion<br />\n(Đoạn C: “It is also possible that fashion plays a part in the process of change.”)<br />\n→ Khi người này bắt chước cách phát âm của người khác (đặc biệt là người có địa vị cao hơn), yếu tố fashion – hay xu hướng xã hội – là nguyên nhân thúc đẩy sự thay đổi.</p>\n<p>3. imperfect<br />\n(Đoạn D: “The imitation of children is imperfect: they copy their parents’ speech, but never reproduce it exactly.”)<br />\n→ Trẻ em bắt chước cách nói của người lớn nhưng không bao giờ sao chép chính xác — việc imperfect imitation này góp phần vào sự biến đổi ngôn ngữ.</p>\n<p>4. principle of ease<br />\n(Đoạn E: “One such force&#8230; is the principle of ease, or minimization of effort.”)<br />\n→ Các biến đổi ngẫu nhiên trong phát âm phần lớn bắt nguồn từ principle of ease – quy luật tiết kiệm công sức khi nói.</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('8d2c1a7e-139c-4849-ba27-70dc7a13dcda', '9bc03f30-fa12-4e03-b7bd-8215caf3dde0', 'radio', 'Questions 5–11', NULL, '<p>Choose <strong>TRUE </strong>if the statement agrees with the information given in the text, choose <strong>FALSE </strong>if the statement contradicts the information, or choose<strong> NOT GIVEN </strong>if there is no information on this.</p>
', 'multiple_choice_single', '[{"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "It is impossible for modern people to find pronunciation of words in an earlier age"}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "The great change of language in Russian history is related to the rising status and fortune of middle classes."}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "All the children learn speeches from adults white they assume that certain language is difficult to imitate exactly."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Pronunciation with causal inaccuracy will not exert big influence on language changes."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "The word ‘scant’ can be pronounced more easily than ‘skamt’."}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "The [g] in gnat not being pronounced will not be spelt out in the future."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "The sound of ‘temporary’ cannot wholly present its spelling."}]', 'null', 'null', 'null', '[{"content": "<p>5. FALSE<br />\n(Đoạn A: “&#8230;can often give us a very good idea of the pronunciation of an earlier age, though absolute certainty is never possible.”)<br />\n→ Không phải impossible mà là có thể biết khá rõ nhưng không hoàn toàn chắc chắn → phát biểu sai.</p>\n<p>6. FALSE<br />\n(Đoạn C: “&#8230;pronunciation of Russian&#8230; became undesirable&#8230; so that people tried to disguise it.”)<br />\n→ Thay đổi trong phát âm tiếng Nga liên quan tới sự suy giảm địa vị của một nhóm xã hội, chứ không phải sự đi lên của tầng lớp trung lưu như câu hỏi nêu.</p>\n<p>7. NOT GIVEN<br />\n→ Không có thông tin về việc tất cả trẻ em đều học nói từ người lớn hay ngôn ngữ đó khó bắt chước, nên không thể xác định.</p>\n<p>8. TRUE<br />\n(Đoạn D: “&#8230;if they are merely random deviations they will cancel one another out and there will be no net change&#8230;”)<br />\n→ Nếu sai lệch trong phát âm chỉ là ngẫu nhiên, chúng sẽ tự triệt tiêu, không ảnh hưởng lớn tới sự thay đổi ngôn ngữ.</p>\n<p>9. TRUE<br />\n(Đoạn E: “Greater efficiency has hereby been achieved&#8230; /n/ and /t/ are articulated in the same place&#8230;”)<br />\n→ scant ([skant]) dễ phát âm hơn skamt vì /n/ và /t/ cùng vị trí phát âm → phát biểu đúng.</p>\n<p>10. NOT GIVEN<br />\n→ Văn bản nói về cách mất âm trong các từ như knight, know, Christmas, nhưng không đề cập tương lai của âm [g] trong gnat, nên không có thông tin.</p>\n<p>11. TRUE<br />\n(Đoạn F: “&#8230;temporary&#8230; is often pronounced as if it were tempory.”)<br />\n→ Phát âm hiện nay không phản ánh đầy đủ cách viết → phát biểu đúng.</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('abead5b0-054c-435c-abbf-c3a0d64284f3', 'e1e1482a-3e84-4eee-82e2-f3ea4a9b352f', 'matching', 'Questions 14-20', NULL, '<p>Reading Passage 2 has seven paragraphs.</p>
<p>Choose the correct heading for each paragraph from the list of headings below.</p>
<p>Choose the correct number, <strong>i-x</strong>, in boxes 14-20.</p>
', 'matching_features', 'null', 'null', '{"layoutType": "heading", "summaryText": null, "answerOptions": [{"optionText": "i The best moment to migrate"}, {"optionText": "ii The unexplained rejection of closer feeding grounds"}, {"optionText": "iii The influence of weather on the migration route"}, {"optionText": "iv Physical characteristics that allow birds to migrate"}, {"optionText": "v The main reason why birds migrate"}, {"optionText": "vi The best wintering grounds for birds"}, {"optionText": "vii Research findings on how birds migrate"}, {"optionText": "viii Successful migration despite the trouble of wind"}, {"optionText": "ix The contrast between long-distance migration and short-distance migration"}, {"optionText": "x Mysterious migration despite lack of teaching"}], "matchingItems": null}', 'null', '[{"content": "<p data-path-to-node=\"1\">Câu 14: iv (Physical characteristics that allow birds to migrate)</p>\n<ul data-path-to-node=\"2\">\n<li>\n<p data-path-to-node=\"2,0,0\"><strong data-path-to-node=\"2,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 1.</p>\n</li>\n<li>\n<p data-path-to-node=\"2,1,0\"><strong data-path-to-node=\"2,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Birds have many unique design features that enable them to perform such amazing feats of endurance.”</p>\n</li>\n<li>\n<p data-path-to-node=\"2,2,0\"><strong data-path-to-node=\"2,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn văn này tập trung liệt kê hàng loạt các đặc điểm cấu tạo cơ thể giúp chim di cư như: xương rỗng nhẹ, lông thiết kế tinh xảo, hệ thống hô hấp hiệu quả và khả năng tích trữ mỡ để cung cấp năng lượng.</p>\n</li>\n</ul>\n<p data-path-to-node=\"3\">Câu 15: v (The main reason why birds migrate)</p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 2.</p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “The fundamental reason that birds migrate is to find adequate food during the winter months when it is in short supply.”</p>\n</li>\n<li>\n<p data-path-to-node=\"4,2,0\"><strong data-path-to-node=\"4,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả khẳng định lý do cơ bản và quan trọng nhất khiến loài chim phải di cư chính là để tìm kiếm nguồn thức ăn đầy đủ khi mùa đông đến (đặc biệt là ở vùng Bắc Cực và ôn đới).</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\">Câu 16: ii (The unexplained rejection of closer feeding grounds)</p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 3.</p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “One puzzling fact is that many birds journey much further than would be necessary just to find food and good weather.”</p>\n</li>\n<li>\n<p data-path-to-node=\"6,2,0\"><strong data-path-to-node=\"6,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn này nói về một điều bí ẩn: tại sao chim lại bay qua những nơi có môi trường sống phù hợp để đi đến những nơi xa hơn rất nhiều (ví dụ như chim swallow bay tận sang Nam Phi thay vì dừng lại ở xích đạo Phi Châu).</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\">Câu 17: x (Mysterious migration despite lack of teaching)</p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 4.</p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “One of the greatest mysteries is how young birds know how to find the traditional wintering areas without parental guidance.”</p>\n</li>\n<li>\n<p data-path-to-node=\"8,2,0\"><strong data-path-to-node=\"8,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Nội dung nhấn mạnh vào việc chim non (như loài cuckoo) có thể tự tìm đường đến nơi tránh rét của tổ tiên mà không cần sự dạy dỗ hay dẫn dắt của chim bố mẹ.</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\">Câu 18: vii (Research findings on how birds migrate)</p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 5.</p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Mounting evidence has confirmed that birds use the positions of the sun and stars to obtain compass directions. They also seem to be able to detect the earth’s magnetic field…”</p>\n</li>\n<li>\n<p data-path-to-node=\"10,2,0\"><strong data-path-to-node=\"10,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn văn trình bày các kết quả nghiên cứu và thí nghiệm về cách chim định vị bằng ánh sáng mặt trời, các vì sao và từ trường trái đất để di chuyển chính xác.</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\">Câu 19: i (The best moment to migrate)</p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 6.</p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…part of the skill in arriving safely is setting off at the right time. This means accurate weather forecasting and utilizing favourable winds.”</p>\n</li>\n<li>\n<p data-path-to-node=\"12,2,0\"><strong data-path-to-node=\"12,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn này nói về kỹ năng chọn thời điểm khởi hành dựa trên khả năng dự báo thay đổi thời tiết và áp suất của loài chim để đảm bảo hành trình an toàn.</p>\n</li>\n</ul>\n<p data-path-to-node=\"13\">Câu 20: viii (Successful migration despite the trouble of wind)</p>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 7.</p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong data-path-to-node=\"14,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Conversely, each autumn a small number of North American birds are blown across the Atlantic by fast-moving westerly tailwinds. Not only do they arrive safely in Europe, but… some make it back to North America…”</p>\n</li>\n<li>\n<p data-path-to-node=\"14,2,0\"><strong data-path-to-node=\"14,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả đưa ra ví dụ về những con chim bị gió thổi bay lệch hướng qua đại dương nhưng vẫn sống sót, đến nơi an toàn và thậm chí có thể quay trở về vào mùa xuân sau.</p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('4401ee0b-cb92-49e8-8ce0-3aad5209081f', '9bc03f30-fa12-4e03-b7bd-8215caf3dde0', 'matching', 'Questions 12-14', NULL, '<p>Look at the following sentences and the list of statements below.</p>
<p>Match each statement with the correct sentence, A-D.</p>
<p>Choose the correct letter, A-D, in boxes 12-14 on your answer sheet.</p>
', 'matching_features', 'null', 'null', '{"layoutType": "standard", "summaryText": null, "answerOptions": [{"optionText": "A. Since the speakers can pronounce it with less effort"}, {"optionText": "B. Assimilation of a sound under the influence of a neighbouring one"}, {"optionText": "C. It is a trend for changes in pronunciation in a large scale in a given period"}, {"optionText": "D. Because the speaker can pronounce [n] and [t] both in the same time"}], "matchingItems": [{"questionPart": "As a consequence, ‘b’ will be pronounced as", "correctAnswer": "C. It is a trend for changes in pronunciation in a large scale in a given period", "sectionContent": null}, {"questionPart": "The pronunciation of [mt] changed to [nt]", "correctAnswer": "B. Assimilation of a sound under the influence of a neighbouring one", "sectionContent": null}, {"questionPart": "The omit of ‘f in the sound of Christmas", "correctAnswer": "A. Since the speakers can pronounce it with less effort", "sectionContent": null}]}', 'null', '[{"content": "<p>12. C<br />\n(Đoạn B: “Such regular changes are often called sound laws&#8230;”)<br />\n→ Đây là xu hướng thay đổi phát âm quy mô lớn trong một giai đoạn nhất định → sound laws.</p>\n<p>13. B<br />\n(Đoạn E: “Assimilation is the changing of a sound under the influence of a neighbouring one.”)<br />\n→ /mt/ đổi thành /nt/ là hiện tượng assimilation – âm bị ảnh hưởng bởi âm bên cạnh.</p>\n<p>14. A<br />\n(Đoạn F: “It is very common for consonants to be lost at the end of a word&#8230;”)<br />\n→ Âm bị lược bỏ vì người nói phát âm dễ hơn, ít tốn sức hơn → “since speakers can pronounce it with less</p>\n"}]', 2);
INSERT INTO public.questions VALUES ('ec0f73b1-723b-401e-9bec-2b360b353e7b', 'e719714f-40e6-4ffe-8ca4-4176308f8e0c', 'radio', 'Questions 27-31', NULL, '<p>Choose the correct answers</p>
', 'multiple_choice_single', '[{"correct": 2, "options": [{"content": "They thought there was only one large island."}, {"content": "They had not come to study natural history."}, {"content": "They had no interest in the tuatara."}, {"content": "They sent a tuatara to the British Museum."}], "question": "What are we told about the Europeans who arrived in 1769?"}, {"correct": 1, "options": [{"content": "He believed the tuatara could fetch a high price."}, {"content": "He was typical of his generation of scientists."}, {"content": "He disagreed with Charles Darwin''s theory."}, {"content": "He wanted to stop the tuatara becoming extinct."}], "question": "What does the writer say about Albert Gunther in paragraph 3?"}, {"correct": 1, "options": [{"content": "They did not eat the tuatara."}, {"content": "There was one species of rat."}, {"content": "There had always been rats in New Zealand."}, {"content": "They were killed by Polynesians."}], "question": "What did Albert Gunther think about the rats in New Zealand?"}, {"correct": 3, "options": [{"content": "Tuatara are safe on small islands."}, {"content": "Ship''s rats kill more tuatara than kiore."}, {"content": "Kiore cannot swim to offshore islands."}, {"content": "Rats and tuatara cannot live together."}], "question": "What did Ian Crook conclude from his research?"}, {"correct": 3, "options": [{"content": "Maori settled more recently than previously thought."}, {"content": "The first Polynesian explorers formed permanent settlements."}, {"content": "Ship''s rats are the oldest rat species in the country."}, {"content": "Rats caused extinctions before any humans settled."}], "question": "What were the findings of Richard Holdaway''s research?"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">27. What are we told about the Europeans who arrived in 1769?</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Đáp án:</strong> C. They had no interest in the tuatara.</p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 2, dòng 3–4.</p>\n</li>\n<li>\n<p data-path-to-node=\"4,2,0\"><strong data-path-to-node=\"4,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;The naturalists who came with the explorers <strong data-path-to-node=\"4,2,0\" data-index-in-node=\"56\">disregarded the tuatara</strong>, though it is improbable none were seen.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"4,3,0\"><strong data-path-to-node=\"4,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Từ <strong data-path-to-node=\"4,3,0\" data-index-in-node=\"15\">&#8220;disregarded&#8221;</strong> có nghĩa là lờ đi, không quan tâm hoặc coi thường. Mặc dù chắc chắn họ đã nhìn thấy chúng, nhưng những nhà tự nhiên học đi cùng đoàn thám hiểm đã không mảy may để ý đến loài này.</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">28. What does the writer say about Albert Gunther in paragraph 2?</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Đáp án:</strong> B. He was typical of his generation of scientists.</p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 2, dòng 8–11.</p>\n</li>\n<li>\n<p data-path-to-node=\"6,2,0\"><strong data-path-to-node=\"6,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;He and his contemporaries were <strong data-path-to-node=\"6,2,0\" data-index-in-node=\"43\">products of their age</strong>, strongly influenced by Charles Darwin’s theory&#8230; Their views were something like this: Extinction is a natural process.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"6,3,0\"><strong data-path-to-node=\"6,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm từ <strong data-path-to-node=\"6,3,0\" data-index-in-node=\"19\">&#8220;products of their age&#8221;</strong> ngụ ý rằng Gunther và những người cùng thời chịu ảnh hưởng sâu sắc bởi tư tưởng của thời đại đó (đặc biệt là thuyết tiến hóa của Darwin). Do đó, thái độ &#8220;bình thản&#8221; của ông trước sự tuyệt chủng của Tuatara là đặc trưng tiêu biểu của giới khoa học thời bấy giờ.</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">29. What did Albert Gunther think about the rats in New Zealand?</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Đáp án:</strong> B. There was one species of rat.</p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 3, dòng cuối.</p>\n</li>\n<li>\n<p data-path-to-node=\"8,2,0\"><strong data-path-to-node=\"8,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;Gunther <strong data-path-to-node=\"8,2,0\" data-index-in-node=\"20\">failed to recognise the distinction</strong>, believing <strong data-path-to-node=\"8,2,0\" data-index-in-node=\"67\">all rats</strong> to be a relatively recent introduction.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"8,3,0\"><strong data-path-to-node=\"8,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ ra rằng có hai loài chuột (chuột tàu biển và chuột kiore), nhưng Gunther đã không nhận ra sự khác biệt này (<strong data-path-to-node=\"8,3,0\" data-index-in-node=\"132\">failed to recognise the distinction</strong>) và coi tất cả chuột chỉ là một nhóm mới được đưa vào New Zealand gần đây.</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">30. What did Ian Crook conclude from his research?</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Đáp án:</strong> D. Rats and tuatara cannot live together.</p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 4, dòng cuối.</p>\n</li>\n<li>\n<p data-path-to-node=\"10,2,0\"><strong data-path-to-node=\"10,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;This should not be seen, however, as evidence that <strong data-path-to-node=\"10,2,0\" data-index-in-node=\"63\">tuatara and kiore can coexist</strong>. Rather&#8230; small populations represent extinctions in progress.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"10,3,0\"><strong data-path-to-node=\"10,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Ian Crook khẳng định việc tìm thấy Tuatara sống cùng chuột kiore không phải là bằng chứng của sự chung sống hòa bình (<strong data-path-to-node=\"10,3,0\" data-index-in-node=\"130\">coexist</strong>), mà thực chất là dấu hiệu cho thấy loài Tuatara đang dần bị tiêu diệt (extinctions in progress). Nói cách khác, chúng không thể sống cùng nhau lâu dài.</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">31. What were the findings of Richard Holdaway&#8217;s research?</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Đáp án:</strong> D. Rats caused extinctions before any humans settled.</p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 5, dòng 6–8.</p>\n</li>\n<li>\n<p data-path-to-node=\"12,2,0\"><strong data-path-to-node=\"12,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;Thereafter, the rats were agents of ecological warfare, exterminating perhaps 1000-3000 species. Thus, tuatara and many other species were <strong data-path-to-node=\"12,2,0\" data-index-in-node=\"151\">already rare or extinct when permanent human inhabitants&#8230; arrived around 1300</strong>.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"12,3,0\"><strong data-path-to-node=\"12,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Nghiên cứu của Holdaway cho thấy chuột kiore đến New Zealand khoảng 1800 năm trước (theo chân các nhà thám hiểm nhưng họ không định cư). Đến khi người Maori chính thức định cư (khoảng năm 1300), các loài chuột này đã kịp tiêu diệt hàng ngàn loài khác. Vậy nên, chuột đã gây ra sự tuyệt chủng trước khi con người định cư lâu dài.</p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('cf73649f-ca80-46dd-af7a-6037e8ecf4b5', '05527816-3ef3-4aae-819f-925e36ed4ea6', 'matrix', 'Questions 31-39', '', '<p data-path-to-node="2">Which paragraph contains the following information?</p>
<p data-path-to-node="3">Write the correct letter, <strong>A–H</strong>, in boxes 31–39 on your answer sheet.</p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "simple", "matrixItems": [{"itemText": "the areas of study that help us understand risk", "correctCategoryLetter": "B"}, {"itemText": "reference to key actions that might benefit the world", "correctCategoryLetter": "F"}, {"itemText": "examples of statistical predictions that the majority of the public react to in the same way", "correctCategoryLetter": "C"}, {"itemText": "the variety of contexts in which risk occurs", "correctCategoryLetter": "A"}, {"itemText": "mention of a habit that has been proved to be very risky", "correctCategoryLetter": "B"}, {"itemText": "reference to market forces motivating change", "correctCategoryLetter": "E"}, {"itemText": "the writer''s current attitude towards risk", "correctCategoryLetter": "H"}, {"itemText": "a reason why some individuals avoid making a career change", "correctCategoryLetter": "D"}, {"itemText": "how some people over-react to information about risk", "correctCategoryLetter": "C"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}, {"categoryText": "H", "categoryLetter": "H"}]}', '[{"content": "<ul>\n<li>\n<p data-path-to-node=\"3,0,0\"><strong data-path-to-node=\"3,0,0\" data-index-in-node=\"0\">31. the areas of study that help us understand risk — {B}</strong></p>\n<ul data-path-to-node=\"3,0,1\">\n<li>\n<p data-path-to-node=\"3,0,1,0,0\"><strong data-path-to-node=\"3,0,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…those risks can be clarified, at least in part, by <strong data-path-to-node=\"3,0,1,0,0\" data-index-in-node=\"66\">science, technology or mathematics</strong>…” (Đoạn B)</p>\n</li>\n<li>\n<p data-path-to-node=\"3,0,1,1,0\"><strong data-path-to-node=\"3,0,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Các lĩnh vực nghiên cứu (areas of study) giúp làm rõ rủi ro bao gồm khoa học, công nghệ và toán học.</p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"3,1,0\"><strong data-path-to-node=\"3,1,0\" data-index-in-node=\"0\">32. reference to key actions that might benefit the world — {F}</strong></p>\n<ul data-path-to-node=\"3,1,1\">\n<li>\n<p data-path-to-node=\"3,1,1,0,0\"><strong data-path-to-node=\"3,1,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…clarifying which critical decision would have the <strong data-path-to-node=\"3,1,1,0,0\" data-index-in-node=\"65\">highest pay-offs for the environment</strong>.” (Đoạn F)</p>\n</li>\n<li>\n<p data-path-to-node=\"3,1,1,1,0\"><strong data-path-to-node=\"3,1,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Các hành động then chốt (key actions/critical decisions) mang lại lợi ích lớn nhất cho môi trường (thế giới).</p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"3,2,0\"><strong data-path-to-node=\"3,2,0\" data-index-in-node=\"0\">33. examples of statistical predictions that the majority of the public react to in the same way — {C}</strong></p>\n<ul data-path-to-node=\"3,2,1\">\n<li>\n<p data-path-to-node=\"3,2,1,0,0\"><strong data-path-to-node=\"3,2,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Hearing the <strong data-path-to-node=\"3,2,1,0,0\" data-index-in-node=\"24\">prediction of 60% chance of rain</strong>… or… <strong data-path-to-node=\"3,2,1,0,0\" data-index-in-node=\"66\">flu shot</strong>, <strong data-path-to-node=\"3,2,1,0,0\" data-index-in-node=\"76\">most people understand the right responses</strong>…” (Đoạn C)</p>\n</li>\n<li>\n<p data-path-to-node=\"3,2,1,1,0\"><strong data-path-to-node=\"3,2,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Ví dụ về dự báo thời tiết hoặc tiêm chủng mà đa số mọi người đều có phản ứng đúng đắn giống nhau.</p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"3,3,0\"><strong data-path-to-node=\"3,3,0\" data-index-in-node=\"0\">34. the variety of contexts in which risk occurs — {A}</strong></p>\n<ul data-path-to-node=\"3,3,1\">\n<li>\n<p data-path-to-node=\"3,3,1,0,0\"><strong data-path-to-node=\"3,3,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Risks arise in <strong data-path-to-node=\"3,3,1,0,0\" data-index-in-node=\"27\">sports, in business, in personal relationships… laboratory… political calculations, everywhere</strong>.” (Đoạn A)</p>\n</li>\n<li>\n<p data-path-to-node=\"3,3,1,1,0\"><strong data-path-to-node=\"3,3,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Liệt kê hàng loạt các bối cảnh (contexts) khác nhau mà rủi ro xuất hiện, từ thể thao đến chính trị.</p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"3,4,0\"><strong data-path-to-node=\"3,4,0\" data-index-in-node=\"0\">35. mention of a habit that has been proved to be very risky — {B}</strong></p>\n<ul data-path-to-node=\"3,4,1\">\n<li>\n<p data-path-to-node=\"3,4,1,0,0\"><strong data-path-to-node=\"3,4,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…even when the evidence of high risk is clear – about <strong data-path-to-node=\"3,4,1,0,0\" data-index-in-node=\"68\">smoking</strong>, for instance…” (Đoạn B)</p>\n</li>\n<li>\n<p data-path-to-node=\"3,4,1,1,0\"><strong data-path-to-node=\"3,4,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Thói quen hút thuốc được đưa ra làm ví dụ điển hình cho một hành vi cực kỳ rủi ro đã được chứng minh.</p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"3,5,0\"><strong data-path-to-node=\"3,5,0\" data-index-in-node=\"0\">36. reference to market forces motivating change — {E}</strong></p>\n<ul data-path-to-node=\"3,5,1\">\n<li>\n<p data-path-to-node=\"3,5,1,0,0\"><strong data-path-to-node=\"3,5,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…transformed by a <strong data-path-to-node=\"3,5,1,0,0\" data-index-in-node=\"32\">flood of low-cost memory chips from Japan</strong>…” (Đoạn E)</p>\n</li>\n<li>\n<p data-path-to-node=\"3,5,1,1,0\"><strong data-path-to-node=\"3,5,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Sự xuất hiện của chip giá rẻ từ Nhật Bản là một áp lực thị trường (market forces) buộc Intel phải thay đổi chiến lược.</p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"3,6,0\"><strong data-path-to-node=\"3,6,0\" data-index-in-node=\"0\">37. the writer’s current attitude towards risk — {H}</strong></p>\n<ul data-path-to-node=\"3,6,1\">\n<li>\n<p data-path-to-node=\"3,6,1,0,0\"><strong data-path-to-node=\"3,6,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Nevertheless, I confess to being an <strong data-path-to-node=\"3,6,1,0,0\" data-index-in-node=\"48\">optimist</strong>.” (Đoạn H)</p>\n</li>\n<li>\n<p data-path-to-node=\"3,6,1,1,0\"><strong data-path-to-node=\"3,6,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả trực tiếp bày tỏ thái độ lạc quan (optimist) của mình ở đoạn cuối bài.</p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"3,7,0\"><strong data-path-to-node=\"3,7,0\" data-index-in-node=\"0\">38. a reason why some individuals avoid making a career change — {D}</strong></p>\n<ul data-path-to-node=\"3,7,1\">\n<li>\n<p data-path-to-node=\"3,7,1,0,0\"><strong data-path-to-node=\"3,7,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…won’t even risk pursuing an exciting job, if the current job… remains <strong data-path-to-node=\"3,7,1,0,0\" data-index-in-node=\"87\">comfortable</strong>.” (Đoạn D)</p>\n</li>\n<li>\n<p data-path-to-node=\"3,7,1,1,0\"><strong data-path-to-node=\"3,7,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Lý do mọi người ngại đổi việc là vì công việc hiện tại vẫn đang ở trong “vùng an toàn/thoải mái” (comfortable).</p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"3,8,0\"><strong data-path-to-node=\"3,8,0\" data-index-in-node=\"0\">39. how some people over-react to information about risk — {C}</strong></p>\n<ul data-path-to-node=\"3,8,1\">\n<li>\n<p data-path-to-node=\"3,8,1,0,0\"><strong data-path-to-node=\"3,8,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…some, <strong data-path-to-node=\"3,8,1,0,0\" data-index-in-node=\"21\">fearfully but irrationally, go to the extreme and stay at home and avoid all contact</strong>…” (Đoạn C)</p>\n</li>\n<li>\n<p data-path-to-node=\"3,8,1,1,0\"><strong data-path-to-node=\"3,8,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Mô tả những phản ứng thái quá (over-react), cực đoan và phi lý trí của một số người khi nghe về rủi ro.</p>\n</li>\n</ul>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('1179fadd-3289-4b35-b130-e7339c4c2f68', '1b48b8ab-5ec7-4a8e-89d9-4acf0335fd69', 'matrix', 'Questions 32 – 37', '', '<p data-path-to-node="14"><em data-path-to-node="14" data-index-in-node="132">Write the correct letter, <strong data-path-to-node="14" data-index-in-node="158">A-E</strong>, in boxes 32-37 on your answer sheet.</em></p>
<p data-path-to-node="15"><strong data-path-to-node="15" data-index-in-node="0">NB</strong> <em data-path-to-node="15" data-index-in-node="3">You may use any letter more than once.</em></p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": "List of People", "matrixItems": [{"itemText": "He found that the Pirahã could successfully complete challenges involving numbers up to three.", "correctCategoryLetter": "D"}, {"itemText": "He argued that people can only formulate ideas when they have the words to express them.", "correctCategoryLetter": "C"}, {"itemText": "He explains that the Pirahã view their language as better than all others.", "correctCategoryLetter": "A"}, {"itemText": "He argues that the Pirahã don''t count because they don''t need to.", "correctCategoryLetter": "D"}, {"itemText": "He is one of the few outsiders to learn Pirahã very well.", "correctCategoryLetter": "E"}, {"itemText": "He highlighted the musical nature of Pirahã.", "correctCategoryLetter": "A"}], "matrixCategories": [{"categoryText": "John Colapinto", "categoryLetter": "A"}, {"categoryText": "Peter Gordon", "categoryLetter": "B"}, {"categoryText": "Benjamin Whorf", "categoryLetter": "C"}, {"categoryText": "Caleb Everett", "categoryLetter": "D"}, {"categoryText": "Daniel Everett", "categoryLetter": "E"}]}', '[{"content": "<p><strong data-path-to-node=\"4\" data-index-in-node=\"0\">32. He found that the Pirahã could successfully complete challenges involving numbers up to three. — {D} Caleb Everett</strong></p>\n<ul data-path-to-node=\"5\">\n<li><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 5):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“In his initial test, he [Caleb] laid down… a line of batteries… What he found was that <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"112\">no mistakes were made providing the lines were just two or three items long</strong>.”</em></li>\n<li><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Thí nghiệm với các viên pin của Caleb Everett cho thấy người Pirahã làm đúng hoàn toàn khi số lượng chỉ từ 2 đến 3 vật.</li>\n</ul>\n<p><strong data-path-to-node=\"6\" data-index-in-node=\"0\">33. He argued that people can only formulate ideas when they have the words to express them. — {C} Benjamin Whorf</strong></p>\n<ul data-path-to-node=\"7\">\n<li><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 3):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“Under <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"27\">Whorf’s theory</strong>, people can only <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"59\">construct thoughts for which they possess actual words</strong>.”</em></li>\n<li><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Formulate ideas” (hình thành ý tưởng) đồng nghĩa với “construct thoughts”. “Possess actual words” tương ứng với “have the words to express them”. Đây là cốt lõi của giả thuyết Sapir-Whorf.</li>\n</ul>\n<p><strong data-path-to-node=\"8\" data-index-in-node=\"0\">34. He explains that the Pirahã view their language as better than all others. — {A} John Colapinto</strong></p>\n<ul data-path-to-node=\"9\">\n<li><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 6):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">“As <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"24\">Colapinto</strong> points out, ‘The Pirahã consider all other forms of human discourse to be <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"108\">laughably inferior</strong>…’”</em></li>\n<li><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Laughably inferior” (thấp kém một cách nực cười) chứng tỏ họ coi ngôn ngữ của mình là vượt trội/tốt hơn tất cả những ngôn ngữ khác (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"145\">better than all others</strong>).</li>\n</ul>\n<p><strong data-path-to-node=\"10\" data-index-in-node=\"0\">35. He argues that the Pirahã don’t count because they don’t need to. — {D} Caleb Everett</strong></p>\n<ul data-path-to-node=\"11\">\n<li><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 6):</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"20\">“Nothing about the Pirahã’s self-contained daily existence seems to <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"88\">require quantity recognition above the number three, says Caleb</strong>…”</em></li>\n<li><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Caleb lập luận rằng cuộc sống tự cung tự cấp của họ không yêu cầu (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"79\">require</strong>) phải nhận biết số lượng trên 3, tức là họ không đếm vì không cần thiết (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"160\">don’t need to</strong>).</li>\n</ul>\n<p><strong data-path-to-node=\"12\" data-index-in-node=\"0\">36. He is one of the few outsiders to learn Pirahã very well. — {E} Daniel Everett</strong></p>\n<ul data-path-to-node=\"13\">\n<li><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 4):</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"20\">“His father [Daniel Everett]… speaks Pirahã <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"66\">as fluently as any Westerner ever has</strong> – a real achievement given that the language is almost impossible for a non-native speaker to master.”</em></li>\n<li><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Daniel Everett (cha của Caleb) được mô tả là nói tiếng Pirahã trôi chảy (fluently) nhất trong số những người phương Tây (outsiders) từng thử học.</li>\n</ul>\n<p><strong data-path-to-node=\"14\" data-index-in-node=\"0\">37. He highlighted the musical nature of Pirahã. — {A} John Colapinto</strong></p>\n<ul data-path-to-node=\"15\">\n<li><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 1):</strong> <em data-path-to-node=\"15,0,0\" data-index-in-node=\"20\">“…John Colapinto, who wrote… ‘its speakers can… <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"74\">sing, hum or whistle conversations</strong>.’”</em></li>\n<li><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc có thể hát, ngân nga hay huýt sáo để giao tiếp chính là đặc tính mang tính âm nhạc (<strong data-path-to-node=\"15,1,0\" data-index-in-node=\"101\">musical nature</strong>) của ngôn ngữ này mà Colapinto đã nhấn mạnh.</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('dede7abd-24c3-43b4-b2cb-a382923a774f', '0bdcc88d-ac3d-4023-aed2-6ec717b355a1', 'radio', 'Questions 35–40', '', '<p data-path-to-node="19,0,0">Choose<strong data-path-to-node="19,0,0" data-index-in-node="0"> YES</strong> if the statement agrees with the views of the writer,<strong data-path-to-node="19,1,0" data-index-in-node="0">NO</strong> if the statement contradicts the views of the writer,<strong data-path-to-node="19,2,0" data-index-in-node="0">NOT GIVEN</strong> if it is impossible to say what the writer thinks about this</p>', 'yes_no_not_given', '[{"correct": 1, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Scientists now have enough information to understand how the placebo effect becomes active in people."}, {"correct": 2, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "As a result of experiments, some painkillers have been taken off the market."}, {"correct": 0, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Individual preference can have an impact on the effectiveness of different brands of headache tablets."}, {"correct": 0, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Doctors expressed a range of views on the drug chlorpromazine when it was first introduced."}, {"correct": 2, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Ernst’s study had a big influence on doctors’ behaviour with patients."}, {"correct": 0, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Alternative practitioners work in a way that is likely to trigger the placebo effect."}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">35. Scientists now have enough information to understand how the placebo effect becomes active… — {NO}</strong></p>\n<ul data-path-to-node=\"24\">\n<li>\n<p data-path-to-node=\"24,0,0\"><strong data-path-to-node=\"24,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “But exactly <strong data-path-to-node=\"24,0,0\" data-index-in-node=\"24\">how placebos work their medical magic is still largely unknown</strong>.” (Đoạn 4)</p>\n</li>\n<li>\n<p data-path-to-node=\"24,1,0\"><strong data-path-to-node=\"24,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Trái ngược hoàn toàn với ý “đã có đủ thông tin để hiểu”.</p>\n</li>\n</ul>\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">36. As a result of experiments, some painkillers have been taken off the market. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"26\">\n<li>\n<p data-path-to-node=\"26,0,0\"><strong data-path-to-node=\"26,0,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ nói về các thí nghiệm màu sắc viên thuốc (đỏ, xanh, xanh lá) hoặc thương hiệu (Aspro, Tylenol), <strong data-path-to-node=\"26,0,0\" data-index-in-node=\"120\">không hề đề cập</strong> đến việc có loại thuốc nào bị thu hồi khỏi thị trường.</p>\n</li>\n</ul>\n<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">37. Individual preference can have an impact on the effectiveness of different brands… — {YES}</strong></p>\n<ul data-path-to-node=\"28\">\n<li>\n<p data-path-to-node=\"28,0,0\"><strong data-path-to-node=\"28,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…if Aspro or Tylenol are <strong data-path-to-node=\"28,0,0\" data-index-in-node=\"39\">what you like</strong> to take… their chemically identical generic equivalents <strong data-path-to-node=\"28,0,0\" data-index-in-node=\"111\">may be less effective</strong>.” (Đoạn 6)</p>\n</li>\n<li>\n<p data-path-to-node=\"28,1,0\"><strong data-path-to-node=\"28,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “What you like” chính là sở thích cá nhân (<em data-path-to-node=\"28,1,0\" data-index-in-node=\"55\">individual preference</em>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">38. Doctors expressed a range of views on the drug chlorpromazine… — {YES}</strong></p>\n<ul data-path-to-node=\"30\">\n<li>\n<p data-path-to-node=\"30,0,0\"><strong data-path-to-node=\"30,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…categorised his colleagues according to whether they were <strong data-path-to-node=\"30,0,0\" data-index-in-node=\"73\">keen on it, openly sceptical… or took a let’s-try-and-see attitude</strong>.” (Đoạn 7)</p>\n</li>\n<li>\n<p data-path-to-node=\"30,1,0\"><strong data-path-to-node=\"30,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Các thái độ “thích thú”, “hoài nghi” và “thử xem sao” chính là “một loạt các quan điểm” (<em data-path-to-node=\"30,1,0\" data-index-in-node=\"101\">range of views</em>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"31\" data-index-in-node=\"0\">39. Ernst’s study had a big influence on doctors’ behaviour with patients. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"32\">\n<li>\n<p data-path-to-node=\"32,0,0\"><strong data-path-to-node=\"32,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “A recent survey by Ernst on doctors’ bedside manners turned up one consistent finding…” (Đoạn 7)</p>\n</li>\n<li>\n<p data-path-to-node=\"32,1,0\"><strong data-path-to-node=\"32,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ nêu kết quả khảo sát của Ernst về phong cách tiếp xúc bệnh nhân, <strong data-path-to-node=\"32,1,0\" data-index-in-node=\"89\">không nói</strong> khảo sát này có làm thay đổi hành vi của các bác sĩ sau đó hay không.</p>\n</li>\n</ul>\n<p data-path-to-node=\"33\"><strong data-path-to-node=\"33\" data-index-in-node=\"0\">40. Alternative practitioners work in a way that is likely to trigger the placebo effect. — {YES}</strong></p>\n<ul data-path-to-node=\"34\">\n<li>\n<p data-path-to-node=\"34,0,0\"><strong data-path-to-node=\"34,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…complementary practitioners are <strong data-path-to-node=\"34,0,0\" data-index-in-node=\"47\">generally best at mobilising the placebo effect</strong>…” (Đoạn 8)</p>\n</li>\n<li>\n<p data-path-to-node=\"34,1,0\"><strong data-path-to-node=\"34,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Mobilising” (huy động/kích hoạt) tương ứng với “trigger”.</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('c2711da4-4d2b-40f9-a567-98f7ba94060e', '05527816-3ef3-4aae-819f-925e36ed4ea6', 'radio', 'Question 40', '', '<p data-path-to-node="8">Choose the correct letter,<strong> A</strong>, <strong>B</strong>, <strong>C</strong> or<strong> D</strong>.</p>
<p data-path-to-node="9">Write the correct letter in box 40 on your answer sheet.</p>', 'multiple_choice', '[{"correct": 1, "options": [{"option_text": "A risk is something we must try to avoid."}, {"option_text": "B experts should be truthful about risk to the public."}, {"option_text": "C optimists are better able to deal with risk than pessimists."}, {"option_text": "D it is important to take risks in order to fulfil social obligations."}], "question": "At the end of the passage the writer concludes that"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">40. At the end of the passage the writer concludes that — {B} experts should be truthful about risk to the public.</strong></p>\n<ul data-path-to-node=\"18\">\n<li>\n<p data-path-to-node=\"18,0,0\"><strong data-path-to-node=\"18,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…everyone in our scientific and engineering community has a social responsibility: <strong data-path-to-node=\"18,0,0\" data-index-in-node=\"97\">measure with care and portray with honesty the level of risk</strong>…” (Đoạn H)</p>\n</li>\n<li>\n<p data-path-to-node=\"18,1,0\"><strong data-path-to-node=\"18,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả kết luận rằng trách nhiệm xã hội của cộng đồng khoa học là phải đo lường cẩn thận và mô tả trung thực (portray with honesty) mức độ rủi ro cho công chúng.</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('f8cc52ad-8dd2-4ab3-9ed4-8d28c96d6ef7', '3b38da13-ebed-422e-a9c5-fa824dc893b0', 'radio', 'Questions 1–6', NULL, '<p>Choose <strong>TRUE </strong>if the statement agrees with the information. <strong>FALSE </strong>if the statement contradicts the information  <strong>NOT GIVEN </strong>if there is no information on this</p>
', 'multiple_choice_single', '[{"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "In the cultivation of olives, a period without rain is advantageous."}, {"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "The most fertile fields are usually chosen for growing olives."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "In ancient Greece, the olive tree was said to have divine origins."}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Olive oil was more costly to buy in Greece than gold."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Plato mentions the use of olive oil in the preparation of food."}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "North African farmers initially resisted the introduction of olive trees."}]', 'null', 'null', 'null', '[{"content": "<p><strong>1. In the cultivation of olives, a period without rain is advantageous.</strong></p>\n<ul>\n<li><strong>Đáp án: TRUE</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn A) “They actually <strong>produce better when subjected to these stressful conditions</strong>, and as a result, olive trees have traditionally been grown on land where little else will survive.”</li>\n<li><strong>Giải thích:</strong> Cây olive cho quả tốt hơn trong điều kiện căng thẳng (stressful conditions), bao gồm điều kiện <strong>khô hạn</strong> (dry conditions – thiếu mưa) được đề cập trước đó.</li>\n</ul>\n<p><strong>2. The most fertile fields are usually chosen for growing olives.</strong></p>\n<ul>\n<li><strong>Đáp án: FALSE</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn A) “…olive trees have traditionally been grown on <strong>land where little else will survive</strong>.”</li>\n<li><strong>Giải thích:</strong> Cây olive được trồng ở đất xấu, nơi ít loài cây khác sống được, mâu thuẫn với việc chọn ruộng màu mỡ (most fertile fields).</li>\n</ul>\n<p><strong>3. In ancient Greece, the olive tree was said to have divine origins.</strong></p>\n<ul>\n<li><strong>Đáp án: TRUE</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn C) “The ancient Greeks believed the olive tree was a <strong>priceless gift from the goddess Athena</strong>…”</li>\n<li><strong>Giải thích:</strong> Món quà từ nữ thần Athena (divine origins) là minh chứng cho nguồn gốc thần thánh.</li>\n</ul>\n<p><strong>4. Olive oil was more costly to buy in Greece than gold.</strong></p>\n<ul>\n<li><strong>Đáp án: NOT GIVEN</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn C) “…the Greek poet Homer called olive oil <strong>‘liquid gold’</strong>…”</li>\n<li><strong>Giải thích:</strong> Homer gọi dầu olive là “vàng lỏng” chỉ là một phép ẩn dụ để ca ngợi giá trị, <strong>không có sự so sánh</strong> về giá cả thực tế.</li>\n</ul>\n<p><strong>5. Plato mentions the use of olive oil in the preparation of food.</strong></p>\n<ul>\n<li><strong>Đáp án: TRUE</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn D) “<strong>Its employment in cooking dates at least as far back as the 5th century BC, as described by the Greek philosopher Plato</strong>.”</li>\n<li><strong>Giải thích:</strong> Plato mô tả việc sử dụng dầu olive trong nấu ăn (preparation of food).</li>\n</ul>\n<p><strong>6. North African farmers initially resisted the introduction of olive trees.</strong></p>\n<ul>\n<li><strong>Đáp án: NOT GIVEN</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn D) “…olive trees were taken to <strong>North Africa and then to Spain</strong>…”</li>\n<li><strong>Giải thích:</strong> Có thông tin về việc đưa cây olive đến Bắc Phi, nhưng <strong>không có thông tin</strong> về phản ứng hay sự chống đối (resisted) của nông dân địa phương.</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('4532a9a7-0ee7-49bc-a73c-7692ac93e0b9', 'e719714f-40e6-4ffe-8ca4-4176308f8e0c', 'radio', 'Questions 32-35', NULL, '<p>Choose <strong>YES </strong>if the statement agrees with the claims of the writer <strong>NO </strong>if the statement contradicts the claims of the writer <strong>NOT GIVEN </strong>if it is impossible to say what the writer thinks about this</p>
', 'multiple_choice_single', '[{"correct": 0, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "The available research supports Holdaway''s theory but it has not been proved."}, {"correct": 0, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Nowadays, it is possible to totally destroy a population of rats on a small island."}, {"correct": 2, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Crook was the first person to recognize the potential of offshore islands as sanctuaries."}, {"correct": 1, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Tuatara numbers are continuing to fall."}]', 'null', 'null', 'null', '[{"content": "<p><strong data-path-to-node=\"3\" data-index-in-node=\"0\">32. The available research supports Holdaway&#8217;s theory but it has not been proved.</strong></p>\n<ul data-path-to-node=\"4\">\n<li><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"4,0,0\" data-index-in-node=\"8\">YES</strong></li>\n<li><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 5, câu cuối.</li>\n<li><strong data-path-to-node=\"4,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;This <strong data-path-to-node=\"4,2,0\" data-index-in-node=\"17\">hypothesis is still being debated</strong>, but the <strong data-path-to-node=\"4,2,0\" data-index-in-node=\"60\">evidence continues to accumulate in its favour</strong>.&#8221;</li>\n<li><strong data-path-to-node=\"4,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm &#8220;still being debated&#8221; (vẫn đang được tranh luận) tương ứng với ý &#8220;it has not been proved&#8221; (chưa được chứng minh tuyệt đối). Cụm &#8220;evidence continues to accumulate in its favour&#8221; (bằng chứng tiếp tục tích lũy theo hướng có lợi cho nó) tương ứng với &#8220;available research supports&#8221; (nghiên cứu hiện có ủng hộ).</li>\n</ul>\n<p><strong data-path-to-node=\"5\" data-index-in-node=\"0\">33. Nowadays, it is possible to totally destroy a population of rats on a small island.</strong></p>\n<ul data-path-to-node=\"6\">\n<li><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"8\">YES</strong></li>\n<li><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 6, câu 1 và 2.</li>\n<li><strong data-path-to-node=\"6,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;Eradication of rats from any given environment was believed to be virtually impossible until about 1980, but <strong data-path-to-node=\"6,2,0\" data-index-in-node=\"121\">since then has become routine</strong>.&#8221;</li>\n<li><strong data-path-to-node=\"6,3,0\" data-index-in-node=\"0\">Giải thích:</strong> &#8220;Eradication&#8221; có nghĩa là sự tiêu diệt hoàn toàn (totally destroy). &#8220;Since then has become routine&#8221; (kể từ đó đã trở thành việc thường quy) xác nhận rằng ngày nay (nowadays) việc này là hoàn toàn khả thi và có thể thực hiện được.</li>\n</ul>\n<p><strong data-path-to-node=\"7\" data-index-in-node=\"0\">34. Crook was the first person to recognize the potential of offshore islands as sanctuaries.</strong></p>\n<ul data-path-to-node=\"8\">\n<li><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"8\">NOT GIVEN</strong></li>\n<li><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 4 và đoạn 6.</li>\n<li><strong data-path-to-node=\"8,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Bài đọc có nói Ian Crook công bố phát hiện vào năm 1973 (đoạn 4) và các hòn đảo ngoài khơi đang cung cấp nơi trú ẩn (sanctuaries) (đoạn 6).</li>\n<li><strong data-path-to-node=\"8,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Mặc dù bài đọc nhấn mạnh tầm quan trọng của nghiên cứu của Crook đối với việc bảo tồn trên đảo, nhưng <strong data-path-to-node=\"8,3,0\" data-index-in-node=\"114\">không có thông tin nào khẳng định</strong> ông là <strong data-path-to-node=\"8,3,0\" data-index-in-node=\"155\">người đầu tiên</strong> (the first person) nhận ra tiềm năng này. Có thể đã có người khác nhận ra trước đó nhưng chưa công bố rộng rãi hoặc nghiên cứu của họ không được nhắc đến trong bài.</li>\n</ul>\n<p><strong data-path-to-node=\"9\" data-index-in-node=\"0\">35. Tuatara numbers are continuing to fall.</strong></p>\n<ul data-path-to-node=\"10\">\n<li><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"8\">NO</strong></li>\n<li><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 6, câu cuối.</li>\n<li><strong data-path-to-node=\"10,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;&#8230;but for the first time in 1800 years the <strong data-path-to-node=\"10,2,0\" data-index-in-node=\"56\">decline has been reversed</strong>.&#8221;</li>\n<li><strong data-path-to-node=\"10,3,0\" data-index-in-node=\"0\">Giải thích:</strong> &#8220;The decline has been reversed&#8221; nghĩa là sự sụt giảm đã được đảo ngược (số lượng không còn giảm nữa mà đang có xu hướng ổn định hoặc tăng lên). Điều này trực tiếp phủ định (contradicts) khẳng định &#8220;numbers are continuing to fall&#8221; của câu hỏi.</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('d372940f-8ab7-4b1f-b20f-58d31b992b33', 'e719714f-40e6-4ffe-8ca4-4176308f8e0c', 'matching', 'Questions 36-40', NULL, '<p>Complete the summary using the list of words, A-H, below.<br />Choose the correct letter, A-H, in boxes 36-40</p>
', 'matching_features', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p style=\"text-align: center;\"><strong>What conclusions can we draw?</strong></p>\n<p style=\"text-align: left;\">The most important result of the tuatara research is that it frees our {B creative thought} . For example, there are many similarities between rats and {D trout} . Should we now go further and consider reintroducing {G native fish} to our mainland rivers? Perhaps our children will come to believe in the {F restoration} of species, in the same way that our generation refuses to accept {H extinction} .</p>", "answerOptions": [{"optionText": "A natural evolution"}, {"optionText": "B creative thought"}, {"optionText": "C indigenous plants"}, {"optionText": "D trout"}, {"optionText": "E pollution"}, {"optionText": "F restoration"}, {"optionText": "G native fish"}, {"optionText": "H extinction"}], "matchingItems": null}', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">36. B (creative thought)</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 7, dòng 1–2.</p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;&#8230;the truly significant outcome of this research is that it <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"73\">liberates the imagination</strong>.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"4,2,0\"><strong data-path-to-node=\"4,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm từ &#8220;liberates the imagination&#8221; (giải phóng trí tưởng tượng) trong bài tương ứng hoàn toàn với &#8220;frees our <strong data-path-to-node=\"4,2,0\" data-index-in-node=\"121\">creative thought</strong>&#8221; (khơi dậy tư duy sáng tạo) trong đoạn tóm tắt. Thành công với loài Tuatara giúp chúng ta dám nghĩ đến những mục tiêu bảo tồn tham vọng hơn.</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">37. D (trout)</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 7, dòng 4–5.</p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;Our rivers, for example, are full of <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"49\">surrogate rats</strong>, in the form of introduced species of fish called <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"114\">trout</strong>.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"6,2,0\"><strong data-path-to-node=\"6,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả dùng phép ẩn dụ &#8220;surrogate rats&#8221; (vật thay thế cho chuột) để nói về cá hồi (<strong data-path-to-node=\"6,2,0\" data-index-in-node=\"96\">trout</strong>). Ý nói cá hồi gây hại cho hệ sinh thái dưới nước tương tự như cách loài chuột gây hại trên đất liền.</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">38. G (native fish)</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 7, dòng 8–9.</p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;&#8230;where we can once again establish those species of <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"66\">indigenous fish</strong> that used to live in our rivers?&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"8,2,0\"><strong data-path-to-node=\"8,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Trong bài dùng từ &#8220;indigenous fish&#8221;, và từ đồng nghĩa trong danh sách lựa chọn là <strong data-path-to-node=\"8,2,0\" data-index-in-node=\"94\">native fish</strong> (cá bản địa). Tác giả đặt vấn đề về việc đưa các loài cá nguyên bản trở lại sông ngòi.</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">39. F (restoration)</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 8, dòng 4–6.</p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;&#8230;imagining and then <strong data-path-to-node=\"10,1,0\" data-index-in-node=\"34\">creating the future</strong> we wish for&#8230; we may no longer accept a mainland <strong data-path-to-node=\"10,1,0\" data-index-in-node=\"104\">devoid of the biological wonders of our past</strong>.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"10,2,0\"><strong data-path-to-node=\"10,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Toàn bộ ngữ cảnh đoạn cuối nói về việc đưa các loài vật của quá khứ trở lại và tái thiết lập hệ sinh thái. Do đó, từ <strong data-path-to-node=\"10,2,0\" data-index-in-node=\"129\">restoration</strong> (sự phục hồi/khôi phục) là từ phù hợp nhất để mô tả niềm tin của thế hệ tương lai.</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">40. H (extinction)</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 8, dòng 4.</p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;Just as we now no longer tolerate <strong data-path-to-node=\"12,1,0\" data-index-in-node=\"46\">extinction</strong>&#8230;&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"12,2,0\"><strong data-path-to-node=\"12,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Đây là một dẫn chứng trực tiếp. Tác giả so sánh: nếu thế hệ chúng ta không chấp nhận sự tuyệt chủng (<strong data-path-to-node=\"12,2,0\" data-index-in-node=\"113\">extinction</strong>), thì thế hệ con cháu sẽ tin tưởng vào sự phục hồi (restoration).</p>\n</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('15e35d3d-1e46-44fb-b535-dc1c01202067', '77b2d76e-80d1-4bc3-8243-c8d4ed26476c', 'matrix', 'Questions 18 - 21', '', '<p>Write the correct letter, <strong>A-E</strong>, in boxes 18-21 on your answer sheet.<br><strong>NB</strong> You may use any letter more than once.</p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": "List of People", "matrixItems": [{"itemText": "We changed our farm because of what people around us were doing.", "correctCategoryLetter": "B"}, {"itemText": "Today''s problems with biodiversity have older origins than people realise.", "correctCategoryLetter": "E"}, {"itemText": "Farmers are more cautious about water use than non-farmers realise.", "correctCategoryLetter": "B"}, {"itemText": "The number of naturally occurring species has been seriously reduced by modern farming", "correctCategoryLetter": "D"}], "matrixCategories": [{"categoryText": "Graham Robertson", "categoryLetter": "A"}, {"categoryText": "Richard Johnson", "categoryLetter": "B"}, {"categoryText": "Murray Rogers", "categoryLetter": "C"}, {"categoryText": "Colin Meurk", "categoryLetter": "D"}, {"categoryText": "Keith Woodford", "categoryLetter": "E"}]}', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">18. We changed our farm because of what people around us were doing. — {B. Richard Johnson}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn C):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“Mid-Canterbury farmer <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"43\">Richard Johnson</strong>… converted from growing crops to dairy farming five years ago, because he could see himself <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"153\">getting left behind by neighbours who’d made the switch</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Richard Johnson quyết định chuyển đổi (changed/converted) trang trại của mình vì thấy các hàng xóm (neighbours – tương ứng với “people around us”) đã chuyển đổi hết và ông không muốn bị bỏ lại phía sau.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">19. Today’s problems with biodiversity have older origins than people realise. — {E. Keith Woodford}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn D):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“However, <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"30\">Keith Woodford</strong>… doesn’t accept that dairying is responsible for this problem… Much of the <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"124\">degradation you see in lowland areas is actually the result of practices going back to the 1960s</strong>…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Older origins” tương ứng với việc các vấn đề này bắt nguồn từ tận những năm 1960 (going back to the 1960s). Keith Woodford nhấn mạnh rằng sự suy thoái không phải do kỹ thuật canh tác hiện đại mà có nguồn gốc từ lâu hơn mọi người vẫn tưởng.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">20. Farmers are more cautious about water use than non-farmers realise. — {B. Richard Johnson}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn C):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">“<strong data-path-to-node=\"9,0,0\" data-index-in-node=\"21\">Public perception</strong> is that this water is being wasted,’ says <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"81\">Johnson</strong>. ‘But <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"95\">farmers think long and hard before they turn the irrigation on</strong>, because it’s expensive.’”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Trong khi dư luận (public perception/non-farmers) nghĩ rằng nước đang bị lãng phí, thì Richard Johnson khẳng định nông dân phải cân nhắc rất kỹ (think long and hard/cautious) vì chi phí sử dụng nước rất đắt đỏ.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">21. The number of naturally occurring species has been seriously reduced by modern farming — {D. Colin Meurk}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn D):</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"20\">“Another critic is <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"39\">ecologist Colin Meurk</strong>, who argues that <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"78\">dairying has caused serious damage to Canterbury’s biodiversity</strong>… found that <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"156\">precious little native habitat has survived</strong>…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Naturally occurring species” chính là các loài bản địa (native habitat/species). Colin Meurk lập luận rằng việc nuôi bò sữa (dairying/modern farming) đã gây thiệt hại nghiêm trọng khiến rất ít loài bản địa còn sống sót (seriously reduced).</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('62773a95-da60-4d70-b7e0-e12cfd8a1495', 'c09ee800-0d6b-47ee-bfa4-c4e3bd5263b3', 'checkbox', 'Questions 25 and 26', '', '<p><span class="citation-24792 citation-24793 citation-24794 citation-24795">Choose </span><strong data-path-to-node="15" data-index-in-node="7"><span class="citation-24792 citation-24793 citation-24794 citation-24795">TWO</span></strong><span class="citation-24792 citation-24793 citation-24794 citation-24795"> letters, </span><strong data-path-to-node="15" data-index-in-node="20"><span class="citation-24792 citation-24793 citation-24794 citation-24795">A–E</span></strong><span class="citation-24792 citation-24793 citation-24794 citation-24795 citation-end-24795">.<sup class="superscript" data-turn-source-index="62"><!----></sup></span><span class="citation-24792 citation-24793 citation-24794 citation-end-24794"><sup class="superscript" data-turn-source-index="63"><!----></sup></span><span class="citation-24792 citation-24793 citation-end-24793"><sup class="superscript" data-turn-source-index="64"><!----></sup></span><span class="citation-24792 citation-end-24792"><sup class="superscript" data-turn-source-index="65"><!----></sup></span></p>
<p><span class="citation-24788 citation-24789 citation-24790 citation-24791 citation-end-24791">Write the correct letters in boxes 25 and 2<sup class="superscript" data-turn-source-index="66"><!----></sup></span><span class="citation-24788 citation-24789 citation-24790 citation-end-24790">6 on your answer sheet.</span></p>', 'multiple_choice', 'null', '[{"correct": true, "option_text": "A the factors which determine how severe it may be"}, {"correct": false, "option_text": "B how long it takes for its effects to become apparent"}, {"correct": false, "option_text": "C which of its symptoms is most frequently encountered"}, {"correct": false, "option_text": "D the types of athletes who are most likely to suffer from it"}, {"correct": true, "option_text": "E the harm that can result if athletes experience it too often"}]', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong class=\"\" data-path-to-node=\"4\" data-index-in-node=\"0\">25. A. the factors which determine how severe it may be — {ĐÚNG}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong class=\"\" data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn E):</strong> <em class=\"\" data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">\"The <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"25\">intensity</strong> with which a person experiences anxiety <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"75\">depends on the demands and resources they have</strong>.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong class=\"\" data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> \"Intensity\" (cường độ/mức độ mạnh nhẹ) tương ứng với \"how severe\" (mức độ nghiêm trọng).</span><span class=\"\"> Yếu tố quyết định mức độ này chính là sự cân bằng giữa yêu cầu (</span><strong class=\"\" data-path-to-node=\"5,1,0\" data-index-in-node=\"165\">demands</strong><span class=\"\">) và nguồn lực (</span><strong class=\"\" data-path-to-node=\"5,1,0\" data-index-in-node=\"188\">resources</strong><span class=\"\">) mà vận động viên có.</span></p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong class=\"\" data-path-to-node=\"6\" data-index-in-node=\"0\">26. E. the harm that can result if athletes experience it too often — {ĐÚNG}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong class=\"\" data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn E):</strong> <em class=\"\" data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">\"...and <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"28\">repeated episodes of anxiety</strong> coupled with negative responses <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"89\">can increase risk of heart disease and depression</strong>.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong class=\"\" data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> \"Repeated episodes\" (các giai đoạn lặp đi lặp lại) tương ứng với \"experience it too often\".</span><span class=\"\"> Tác giả nêu rõ tác hại (</span><strong class=\"\" data-path-to-node=\"7,1,0\" data-index-in-node=\"128\">harm</strong><span class=\"\">) của việc này là làm tăng nguy cơ mắc bệnh tim và trầm cảm.</span></p>\n</li>\n</ul>"}]', 3);
INSERT INTO public.questions VALUES ('0c89253c-6ab1-4cb2-9819-35e96281f1e0', '7167e7de-4bd1-4951-aefa-176570cc33db', 'fillup', 'Questions 14–18', '<p>Complete the summary below</p>
<p>Choose <strong>NO MORE THAN TWO WORDS AND/OR A NUMBER</strong> from the passage for each answer.</p>
<p>The thylacine was a dog-like which had a 14. {striped} coat and was carnivorous.It was originally spread widely throughout the mainland of 15. {Australia}, but started to disappear from that area around 16. {12 million years} ago because of climate change. In the end, thylacines were found only on the island of 17. {Tasmania} until the arrival of 18. {Europeans}, with their farming practices brought about a drastic reduction in thylacine numbers. The last one is thought to have died in Hobart Zoo in 1936.</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p><strong class=\"\">14. striped</strong><span class=\"\"> (Đoạn 1,</span><span class=\"\"> &#8220;It was given the name “tiger” because it had </span><strong class=\"\">striped fur</strong><span class=\"\">&#8230;</span><span class=\"\">&#8220;) → Lông của Thylacine có sọc.</span><span class=\"\"> → Đáp án là </span><strong class=\"\">striped</strong><span class=\"\">.</span></p>\n<p><strong class=\"\">15. Australia</strong><span class=\"\"> (Đoạn 1,</span><span class=\"\"> &#8220;Between 24 million and 15 million years ago,</span><span class=\"\"> many types of thylacine roamed across </span><strong class=\"\">Australia</strong><span class=\"\">&#8230;</span><span class=\"\">&#8220;) → Ban đầu,</span><span class=\"\"> chúng phân bố rộng rãi khắp lục địa Australia.</span><span class=\"\"> → Đáp án là </span><strong class=\"\">Australia</strong><span class=\"\">.</span></p>\n<p><strong class=\"\">16. 12 million years</strong><span class=\"\"> (Đoạn 2,</span><span class=\"\"> &#8220;But when a period of climate change cooled Australia about </span><strong class=\"\">12 million years ago</strong><span class=\"\">,</span><span class=\"\"> the number of these ancient thylacines began to decline.</span><span class=\"\">&#8220;) → Sự suy giảm bắt đầu khoảng 12 triệu năm trước.</span><span class=\"\"> → Đáp án là </span><strong class=\"\">12 million years</strong><span class=\"\">.</span></p>\n<p><strong class=\"\">17. Tasmania</strong><span class=\"\"> (Đoạn 2,</span><span class=\"\"> &#8220;&#8230;</span><span class=\"\">these vanished completely from the Australian mainland,</span><span class=\"\"> so that </span><strong class=\"\">Tasmania</strong><span class=\"\">,</span><span class=\"\"> a large island to the south of Australia,</span><span class=\"\"> was then the last remaining place where thylacines existed.</span><span class=\"\">&#8220;) → Cuối cùng,</span><span class=\"\"> chúng chỉ còn được tìm thấy ở Tasmania.</span><span class=\"\"> → Đáp án là </span><strong class=\"\">Tasmania</strong><span class=\"\">.</span></p>\n<p><strong class=\"\">18. Europeans</strong><span class=\"\"> (Đoạn 2,</span><span class=\"\"> &#8220;&#8230;</span><span class=\"\">They ruled the animal life of that island unchallenged until </span><strong class=\"\">Europeans</strong><span class=\"\"> with sheep,</span><span class=\"\"> dogs&#8230;</span><span class=\"\"> seemed to have brought about their extinction.</span><span class=\"\">&#8220;) → Sự xuất hiện của người châu Âu dẫn đến sự tuyệt chủng của chúng.</span><span class=\"\"> → Đáp án là </span><strong class=\"\">Europeans</strong><span class=\"\">.</span></p>\n"}]', 0);
INSERT INTO public.questions VALUES ('d252b57c-170d-45f4-8fc6-67950b3db336', '7167e7de-4bd1-4951-aefa-176570cc33db', 'matrix', 'Questions 19–24', NULL, '<p>Match each statement with the correct person, A, B, C or D.</p>
<p>Choose the correct letter, A, B, C or D</p>
<p><em><strong>NB You may use any letter more than once </strong></em></p>
', 'other', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": null, "matrixItems": [{"itemText": "There is no longer any hope of finding a surviving Tasmanian tiger.", "correctCategoryLetter": "B"}, {"itemText": "It would be preferable not to disturb any surviving Tasmanian tigers.", "correctCategoryLetter": "A"}, {"itemText": "Many who claim to have seen Tasmanian tigers are not objective witnesses.", "correctCategoryLetter": "D"}, {"itemText": "Expert estimates of numbers needed to ensure species survival may be inaccurate.", "correctCategoryLetter": "C"}, {"itemText": "There is a great deal of international interest in Tasmanian tiger stories.", "correctCategoryLetter": "A"}, {"itemText": "Some fresh evidence provided by a visitor to Tasmania seems credible.", "correctCategoryLetter": "D"}], "matrixCategories": [{"categoryText": "Hans Naarding", "categoryLetter": "A"}, {"categoryText": "Randolph Rose", "categoryLetter": "B"}, {"categoryText": "David Pemberton", "categoryLetter": "C"}, {"categoryText": "Nick Mooney", "categoryLetter": "D"}]}', '[{"content": "<p><strong>19. B</strong> (Đoạn 4, &#8220;<strong>Randolph Rose</strong>&#8230; is now <strong>convinced that his dream will go unfulfilled</strong>&#8230; Take it from me, <strong>the tiger is gone</strong>.&#8221;) → Randolph Rose tin rằng không còn hy vọng tìm thấy hổ Tasmania còn sống sót. → Đáp án là <strong>B</strong>.</p>\n<p><strong>20. A</strong> (Đoạn 7, &#8220;If there are thylacines out there, <strong>they are better off right where they are</strong>.&#8221;) → Hans Naarding tin rằng nếu thylacine còn sống, tốt nhất là không nên quấy rầy chúng. → Đáp án là <strong>A</strong>.</p>\n<p><strong>21. D</strong> (Đoạn 5, &#8220;<strong>Nick Mooney</strong>&#8230; says, this particular account&#8230; amount to one of the most convincing cases&#8230; <strong>Many other sightings have been hoaxes, and many sincere seekers are victims of obsession</strong>.&#8221;) → Nick Mooney chỉ ra rằng nhiều người tuyên bố nhìn thấy hổ là nạn nhân của sự ám ảnh chứ không phải nhân chứng khách quan. → Đáp án là <strong>D</strong>.</p>\n<p><strong>22. C</strong> (Đoạn 4, &#8220;<strong>Dr David Pemberton</strong>&#8230; states that, despite scientific thinking that a relatively large number of animals are required to sustain a population <strong>the Florida panther is down to a dozen or so animals</strong>&#8230; is <strong>still ticking along</strong>.&#8221;) → David Pemberton đưa ra ví dụ về báo Florida để chứng minh rằng ước tính của chuyên gia về số lượng cần thiết để duy trì loài có thể không chính xác. → Đáp án là <strong>C</strong>.</p>\n<p><strong>23. A</strong> (Đoạn 3, &#8220;When the news broke, said <strong>Naarding</strong>, “I was <strong>besieged by television crews, including four or five from Japan, and others</strong> from the United Kingdom, Germany, New Zealand and South America.&#8221;) → Hans Naarding là người mô tả sự quan tâm quốc tế lớn đến câu chuyện về hổ Tasmania sau lần nhìn thấy của ông. → Đáp án là <strong>A</strong>.</p>\n<p><strong>24. D</strong> (Đoạn 5, &#8220;<strong>Nick Mooney</strong>&#8230; says, <strong>this particular account of a sighting and the photographs submitted as proof amount to one of the most convincing cases</strong> for the species’ survival that he has seen.&#8221;) → Nick Mooney là người nhận định bằng chứng mới nhất do một du khách cung cấp dường như đáng tin cậy. → Đáp án là <strong>D</strong>.</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('f74dc35e-b865-4e13-9cb5-0fdec8ccdfb6', '052bff80-0f32-4578-9649-7e76f09b9878', 'matrix', 'Questions 27–34', NULL, '<p>The Reading Passage 3 has seven paragraphs A-I.</p>
<p>Which paragraph contains the following information?</p>
<p>Choose the correct letter, A-I, in boxes 27-34.</p>
', 'classification', 'null', 'null', 'null', '{"layoutType": "simple", "legendTitle": null, "matrixItems": [{"itemText": "Experiment on bitterness conducted", "correctCategoryLetter": "B"}, {"itemText": " Look into the future application", "correctCategoryLetter": "I"}, {"itemText": "Bitterness means different information for human and animals", "correctCategoryLetter": "C"}, {"itemText": "Spread process of bitterness inside of body", "correctCategoryLetter": "E"}, {"itemText": " How AMP blocks bitterness", "correctCategoryLetter": "G"}, {"itemText": "Some bitterness blocker may help lower unhealthy impact", "correctCategoryLetter": "H"}, {"itemText": "Bitterness introduced from a fruit", "correctCategoryLetter": "A"}, {"itemText": "Genetic feature determines sensitivity", "correctCategoryLetter": "D"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}, {"categoryText": "H", "categoryLetter": "H"}, {"categoryText": "I", "categoryLetter": "I"}]}', '[{"content": "<p><strong>27. An experience of the writer in a test — Đáp án: B</strong></p>\n<ul data-path-to-node=\"5\">\n<li><strong>Dẫn chứng:</strong> “I found that out by <strong>participating in a test</strong> conducted at the Linguagen Corporation… Sets of two miniature white paper cups… were placed before five people…”</li>\n<li><strong>Giải thích:</strong> Đoạn B mô tả trực tiếp việc tác giả (<em>the writer</em>) tham gia vào một cuộc thử nghiệm nếm hai mẫu nước bưởi (304 và 305) để kiểm chứng tác dụng của chất AMP.</li>\n</ul>\n<p><strong>28. The future of bitter blockers — Đáp án: I</strong></p>\n<ul data-path-to-node=\"7\">\n<li><strong>Dẫn chứng:</strong> “<strong>In a few years, perhaps</strong>, after food companies have taken the bitterness from canned soup… they can set their sights on something more useful: a <strong>bitter blocker in a bottle</strong> that any of us can sprinkle…”</li>\n<li><strong>Giải thích:</strong> Đoạn I đưa ra dự đoán về tương lai khi người tiêu dùng có thể tự mua chai chất chặn vị đắng để sử dụng tại nhà như một loại gia vị thông thường.</li>\n</ul>\n<p><strong>29. The evolution of bitter taste — Đáp án: C</strong></p>\n<ul data-path-to-node=\"9\">\n<li><strong>Dẫn chứng:</strong> “They defend plants by warning animals away… humans are the only species that enjoys bitter taste… Every other species is averse to bitter… <strong>But we have learned to enjoy it</strong>.”</li>\n<li><strong>Giải thích:</strong> Đoạn C nói về quá trình tiến hóa: từ một cơ chế cảnh báo chất độc trong tự nhiên, con người đã dần học cách yêu thích và đưa vị đắng vào văn hóa ẩm thực (cà phê, rượu tonic).</li>\n</ul>\n<p><strong>30. The identification of gustducin — Đáp án: E</strong></p>\n<ul data-path-to-node=\"11\">\n<li><strong>Dẫn chứng:</strong> “The G protein involved in the perception of bitterness… was <strong>identified in the early 1990s</strong> by Linguagen’s founder, Robert Margolskee… <strong>Known as gustducin</strong>…”</li>\n<li><strong>Giải thích:</strong> Đoạn E cung cấp thông tin về việc phát hiện và định danh loại protein tên là <strong>Gustducin</strong>, mắt xích quan trọng trong việc truyền tín hiệu vị đắng lên não.</li>\n</ul>\n<p><strong>31. The mechanism of AMP — Đáp án: G</strong></p>\n<ul data-path-to-node=\"13\">\n<li><strong>Dẫn chứng:</strong> “…AMP… has no bitterness of its own, but when put it in foods… <strong>it attaches to bitter-taste receptors</strong>.”</li>\n<li><strong>Giải thích:</strong> Đoạn G giải thích cơ chế khoa học của AMP: nó hoạt động bằng cách “chiếm chỗ” trên các thụ thể vị giác, ngăn không cho các phân tử gây đắng bám vào.</li>\n</ul>\n<p><strong>32. The potential medical applications — Đáp án: H</strong></p>\n<ul data-path-to-node=\"15\">\n<li><strong>Dẫn chứng:</strong> “Bitter blockers could also be used… to take the harshness out of <strong>children’s cough syrup</strong>, and they could dampen the bitterness of <strong>antihistamines, antibiotics, certain HIV drugs</strong>…”</li>\n<li><strong>Giải thích:</strong> Đoạn H liệt kê một loạt các ứng dụng tiềm năng trong y tế, giúp các loại thuốc điều trị trở nên dễ uống hơn đối với bệnh nhân.</li>\n</ul>\n<p><strong>33. The antioxidant properties of naringin — Đáp án: A</strong></p>\n<ul data-path-to-node=\"17\">\n<li><strong>Dẫn chứng:</strong> “…though the compound [naringin] has <strong>antioxidant properties</strong> that some nutritionists contend may <strong>help prevent cancer and arteriosclerosis</strong>.”</li>\n<li><strong>Giải thích:</strong> Đoạn A giải thích về Naringin (chất gây đắng trong bưởi) và những lợi ích sức khỏe của nó như một chất chống oxy hóa giúp phòng ngừa bệnh tật.</li>\n</ul>\n<p><strong>34. Genetic differences in taste capacity — Đáp án: D</strong></p>\n<ul data-path-to-node=\"19\">\n<li><strong>Dẫn chứng:</strong> “People have <strong>varying capacities</strong> for tasting bitterness, and the differences appear to be <strong>genetic</strong>.”</li>\n<li><strong>Giải thích:</strong> Đoạn D thảo luận về việc khả năng nếm vị đắng (như người siêu vị giác – supertasters) được quyết định bởi các yếu tố di truyền và số lượng chồi vị giác trên lưỡi.</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('6b7cbbab-de52-4785-9a2c-252d7ef933a6', '3b38da13-ebed-422e-a9c5-fa824dc893b0', 'fillup', 'Questions 7–9', '<p>Complete the flow-chart below.</p>
<p>Write <strong>ONE WORD ONLY</strong> from the passage for each answer.</p>
<p class="MsoNormal" style="margin-bottom: 0in; text-align: center; line-height: 1; background: white;" align="center"><strong style="mso-bidi-font-weight: normal;"><span lang="EN" style="font-size: 11.0pt; font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: #15191e;">Ancient olive oil processing</span></strong><span lang="EN" style="font-size: 11.0pt; font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: #15191e;"> </span></p>
<p class="MsoNormal" style="margin-bottom: 0in; text-align: center; line-height: 1; background: white;" align="center"><span lang="EN" style="font-size: 11.0pt; font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: #15191e;">olives are harvested by picking them or {beating}</span><span lang="EN" style="font-size: 11.0pt; font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: #15191e;"> the trees<br /></span><span lang="EN" style="font-size: 11.0pt; font-family: ''Arial'',sans-serif; color: black; mso-color-alt: windowtext;"><span style="mso-fareast-font-family: Cardo; color: #15191e;">⬇<br /></span></span><span lang="EN" style="font-size: 11.0pt; font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: #15191e;">milling stage<br /></span>⬇<br /><span lang="EN" style="font-size: 11.0pt; font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: #15191e;">olives are washed and crushed and seeds removed<br /></span>⬇<br /><span lang="EN" style="font-size: 11.0pt; font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: #15191e;">olive flesh is placed in {bags}</span><span lang="EN" style="font-size: 11.0pt; font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: #15191e;"> and pressed<br /></span>⬇<br /><span lang="EN" style="font-size: 11.0pt; font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: #15191e;">water is poured over the mixture<br /></span>⬇<br /><span lang="EN" style="font-size: 11.0pt; font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: #15191e;">resulting liquid is given time to settle and separate, and {salt}</span><span lang="EN" style="font-size: 11.0pt; font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: #15191e;"> is used to aid the process<br /></span>⬇<br /><span lang="EN" style="font-size: 11.0pt; font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: #15191e;">oil is drawn off and separation repeated</span></p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p><strong>7. olives are harvested by picking them or beating the trees</strong></p>\n<ul>\n<li><strong>Đáp án:</strong> <strong>beating</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn E) “The olives were harvested from the trees by hand or by <strong>beating</strong> the fruit from the trees with long sticks.”</li>\n</ul>\n<p><strong>8. olive flesh is placed in bags and pressed</strong></p>\n<ul>\n<li><strong>Đáp án:</strong> <strong>bags</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn E) “The remaining seedless flesh was put in woven <strong>bags</strong> and pressed.”</li>\n</ul>\n<p><strong>9. resulting liquid is given time to settle and separate, and salt is used to aid the process</strong></p>\n<ul>\n<li><strong>Đáp án:</strong> <strong>salt</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn E) “In cold weather a bit of <strong>salt</strong> was added to speed up the process.”</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('8b9742fa-20ec-4715-88a4-e1f826028b20', '052bff80-0f32-4578-9649-7e76f09b9878', 'fillup', 'Questions 35–38', '<p>Complete the following summary of the paragraphs of Reading Passage 3.</p>
<p>Write <strong>NO MORE THAN TWO WORDS</strong> for each answer.</p>
<p>The reason why grapefruit tastes bitter is because a substance called {naringin} contained in it. However, bitterness plays a significant role for plants. It gives a signal that certain plant is {poisonous}. For human beings, different person carries various genetic abilities of tasting bitterness. According to a scientist at the University of Utah, {supertasters} have exceptionally plenty of {taste buds}, which allows them to perceive bitter compounds.</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\">35. The reason why grapefruit tastes bitter is because a substance called {naringin} contained in it.</p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong>Đáp án:</strong> <strong>naringin</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong>Vị trí:</strong> Đoạn A, dòng 2.</p>\n</li>\n<li>\n<p data-path-to-node=\"5,2,0\"><strong>Dẫn chứng:</strong> “<strong>Naringin</strong>, a natural chemical compound found in grapefruit, tastes bitter.”</p>\n</li>\n<li>\n<p data-path-to-node=\"5,3,0\"><strong>Giải thích:</strong> Bài đọc chỉ rõ hợp chất hóa học tự nhiên có tên là naringin chính là nguyên nhân tạo ra vị đắng của quả bưởi.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\">36. It gives a signal that certain plant is {poisonous}.</p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong>Đáp án:</strong> <strong>poisonous</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong>Vị trí:</strong> Đoạn C, dòng 5.</p>\n</li>\n<li>\n<p data-path-to-node=\"7,2,0\"><strong>Dẫn chứng:</strong> “They defend plants by warning animals away and protect animals by letting them know when a plant may be <strong>poisonous</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"7,3,0\"><strong>Giải thích:</strong> Trong tự nhiên, vị đắng đóng vai trò như một hệ thống cảnh báo. Nó giúp động vật nhận biết cây đó có thể chứa độc tố (<em>poisonous</em>) để tránh ăn phải.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\">37. &amp; 38. According to a scientist at the University of Utah, {supertasters} have exceptionally plenty of {taste buds}, which allows them to perceive bitter compounds.</p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong>Đáp án 37:</strong> <strong>supertasters</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong>Đáp án 38:</strong> <strong>taste buds</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"9,2,0\"><strong>Vị trí:</strong> Đoạn D, dòng 5-6.</p>\n</li>\n<li>\n<p data-path-to-node=\"9,3,0\"><strong>Dẫn chứng:</strong> “Some people, known as <strong>supertasters</strong>, are especially sensitive… because they have an unusually high number of <strong>taste buds</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"9,4,0\"><strong>Giải thích:</strong> Bài viết đề cập rằng những người có khả năng cảm nhận vị giác cực nhạy được gọi là “supertasters”. Lý do sinh học cho khả năng này là do họ sở hữu số lượng gai vị giác (<em>taste buds</em>) nhiều hơn mức bình thường.</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('40937bc7-8615-4d75-a326-e334d9d6a72d', '21fb339b-0a32-4d16-987c-195c52eee36b', 'fillup', 'Questions 31–40', '<p>Write <strong>ONE WORD ONLY</strong> for each answer.</p>
<h3><strong>  Ethics in Engineering</strong></h3>
<p><strong>Ethics – principles relating to right and wrong conduct</strong></p>
<p>– at first, engineers saw ethics as a {personal} issue</p>
<p>– attitudes changed because of three disasters involving the collapse of {bridges}</p>
<p>1876 – USA (metal fatigue)</p>
<p>1879 – Scotland (the impact of {wind} on the structure was miscalculated)</p>
<p>1907 – Canada (the structure could not support its own {weight})</p>
<p><strong>Boston Molasses Disaster</strong></p>
<p>At the time, molasses was the main {sweetener} used in the USA</p>
<p>– Boston company: collapse of a {tank} released 8 million litres of molasses</p>
<p>– the wave of molasses destroyed buildings and the railway</p>
<p>– local residents insisted on a {trial} of the molasses company</p>
<p><strong>Causes of the accident:</strong></p>
<p>– insufficient {safety} check</p>
<p>– the fermentation caused the rising of {pressure}</p>
<p>Now, every engineer has to have a {license |lice}</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p>Good afternoon. Today we’re starting a series of lectures on ethics in engineering, that is, engineering principles relating to right and wrong conduct and the sorts of moral responsibilities that you will have to uphold in your professional lives. I’m going to start by giving you a brief outline of the history of ethics in engineering. It was, of course, only in the 19th century that engineering really emerged as a profession. <span class=\"citation-359\">Initially, ethical issues were considered to be a </span><strong><span class=\"citation-359\">(31) personal</span></strong><span class=\"citation-359 citation-end-359\"> issue </span><span class=\"citation-358 citation-end-358\">—something to be decided in accordance with one’s own principles and values</span>. <span class=\"citation-357 citation-end-357\">However, things gradually changed as the profession grew, and as engineering projects became larger and more complex, a need began to be felt for a more codified set of principles that all engineers would agree to follow</span>.<button class=\"button ng-star-inserted\" data-hveid=\"0\" data-ved=\"0CAAQvoAQahgKEwjjpIjIuu-QAxUAAAAAHQAAAAAQwAo\"></button><button class=\"button ng-star-inserted\" data-hveid=\"0\" data-ved=\"0CAAQvoAQahgKEwjjpIjIuu-QAxUAAAAAHQAAAAAQvwo\"></button><button class=\"button ng-star-inserted\" data-hveid=\"0\" data-ved=\"0CAAQvoAQahgKEwjjpIjIuu-QAxUAAAAAHQAAAAAQvgo\"></button></p>\n<p>&nbsp;</p>\n<p>&nbsp;</p>\n<p>&nbsp;</p>\n<blockquote>\n<p><strong>Dịch:</strong> Chào buổi chiều. <span class=\"citation-356 citation-end-356\">Hôm nay chúng ta sẽ bắt đầu loạt bài giảng về đạo đức trong kỹ thuật </span><span class=\"citation-355 citation-end-355\">, tức là các nguyên tắc kỹ thuật liên quan đến hành vi đúng sai và các loại trách nhiệm đạo đức mà các bạn sẽ phải tuân thủ trong cuộc sống nghề nghiệp của mình</span>. <span class=\"citation-354 citation-end-354\">Tôi sẽ bắt đầu bằng cách đưa ra một phác thảo ngắn gọn về lịch sử đạo đức trong kỹ thuật</span>. <span class=\"citation-353 citation-end-353\">Tất nhiên, chỉ đến thế kỷ 19 thì kỹ thuật mới thực sự nổi lên như một nghề nghiệp</span>. <span class=\"citation-352\">Ban đầu, các vấn đề đạo đức được coi là vấn đề </span><strong><span class=\"citation-352\">(31) cá nhân</span></strong> <span class=\"citation-351 citation-end-351\">—một điều gì đó được quyết định theo các nguyên tắc và giá trị của riêng mỗi người</span>. <span class=\"citation-350 citation-end-350\">Tuy nhiên, mọi thứ dần thay đổi khi nghề nghiệp phát triển, và khi các dự án kỹ thuật trở nên lớn hơn và phức tạp hơn, nhu cầu về một bộ nguyên tắc được hệ thống hóa hơn mà tất cả các kỹ sư đồng ý tuân theo bắt đầu được cảm nhận</span>.<button class=\"button ng-star-inserted\" data-hveid=\"0\" data-ved=\"0CAAQvoAQahgKEwjjpIjIuu-QAxUAAAAAHQAAAAAQwgo\"></button><button class=\"button ng-star-inserted\" data-hveid=\"0\" data-ved=\"0CAAQvoAQahgKEwjjpIjIuu-QAxUAAAAAHQAAAAAQwQo\"></button><button class=\"button ng-star-inserted\" data-hveid=\"0\" data-ved=\"0CAAQvoAQahgKEwjjpIjIuu-QAxUAAAAAHQAAAAAQwwo\"></button><button class=\"button ng-star-inserted\" data-hveid=\"0\" data-ved=\"0CAAQvoAQahgKEwjjpIjIuu-QAxUAAAAAHQAAAAAQxAo\"></button></p>\n<p>&nbsp;</p>\n</blockquote>\n<hr />\n<p><span class=\"citation-349 citation-end-349\">Unfortunately, it took three major disasters to bring about this change in attitude</span>. <span class=\"citation-348\">All three of these involved the collapse of </span><strong><span class=\"citation-348\">(32) bridges</span></strong>. <span class=\"citation-347 citation-end-347\">The first, known as the Ashtabula River Railroad disaster, happened in 1876 in the USA, and we now think it was probably caused by metal fatigue</span>. <span class=\"citation-346 citation-end-346\">Then in 1879, there was a second disaster, this time in Scotland</span>. <span class=\"citation-345\">This occurred because engineers had failed to correctly calculate the effects that </span><strong><span class=\"citation-345\">(33) wind</span></strong><span class=\"citation-345 citation-end-345\"> would have on the structure</span>. <span class=\"citation-344 citation-end-344\">The third collapse occurred in 1907 in Canada</span>. <span class=\"citation-343\">This was also due to an engineering design problem: the </span><strong><span class=\"citation-343\">(34) weight</span></strong><span class=\"citation-343 citation-end-343\"> of the structure was so great that it could not support itself and it collapsed</span>. <span class=\"citation-342 citation-end-342\">Public outcry over disasters such as these eventually led to the establishment of professional societies for engineers in most industrializing societies</span>.<button class=\"button ng-star-inserted\" data-hveid=\"0\" data-ved=\"0CAAQvoAQahgKEwjjpIjIuu-QAxUAAAAAHQAAAAAQxwo\"></button><button class=\"button ng-star-inserted\" data-hveid=\"0\" data-ved=\"0CAAQvoAQahgKEwjjpIjIuu-QAxUAAAAAHQAAAAAQyAo\"></button><button class=\"button ng-star-inserted\" data-hveid=\"0\" data-ved=\"0CAAQvoAQahgKEwjjpIjIuu-QAxUAAAAAHQAAAAAQyQo\"></button><button class=\"button ng-star-inserted\" data-hveid=\"0\" data-ved=\"0CAAQvoAQahgKEwjjpIjIuu-QAxUAAAAAHQAAAAAQxgo\"></button><button class=\"button ng-star-inserted\" data-hveid=\"0\" data-ved=\"0CAAQvoAQahgKEwjjpIjIuu-QAxUAAAAAHQAAAAAQxQo\"></button></p>\n<p>&nbsp;</p>\n<p>&nbsp;</p>\n<p>&nbsp;</p>\n<p>&nbsp;</p>\n<p>&nbsp;</p>\n<blockquote>\n<p><strong><span class=\"citation-341\">Dịch:</span></strong><span class=\"citation-341 citation-end-341\"> Thật không may, phải mất ba thảm họa lớn để tạo ra sự thay đổi thái độ này</span>. <span class=\"citation-340\">Cả ba đều liên quan đến sự sụp đổ của </span><strong><span class=\"citation-340\">(32) những cây cầu</span></strong>. <span class=\"citation-339 citation-end-339\">Thảm họa đầu tiên, được gọi là thảm họa Đường sắt sông Ashtabula, xảy ra vào năm 1876 tại Hoa Kỳ, và chúng ta hiện cho rằng nó có thể do mỏi kim loại</span>. <span class=\"citation-338 citation-end-338\">Sau đó, vào năm 1879, có một thảm họa thứ hai, lần này ở Scotland</span>. <span class=\"citation-337\">Điều này xảy ra vì các kỹ sư đã không tính toán chính xác các tác động mà </span><strong><span class=\"citation-337\">(33) gió</span></strong><span class=\"citation-337 citation-end-337\"> sẽ gây ra đối với cấu trúc</span>. <span class=\"citation-336 citation-end-336\">Sự sụp đổ thứ ba xảy ra vào năm 1907 tại Canada</span>. <span class=\"citation-335\">Điều này cũng do vấn đề thiết kế kỹ thuật: </span><strong><span class=\"citation-335\">(34) trọng lượng</span></strong><span class=\"citation-335 citation-end-335\"> của cấu trúc quá lớn đến nỗi nó không thể tự hỗ trợ và đã sụp đổ</span>. <span class=\"citation-334 citation-end-334\">Sự phản đối kịch liệt của công chúng đối với những thảm họa như thế này cuối cùng đã dẫn đến việc thành lập các hiệp hội chuyên nghiệp dành cho kỹ sư ở hầu hết các xã hội công nghiệp hóa</span>.<button class=\"button ng-star-inserted\" data-hveid=\"0\" data-ved=\"0CAAQvoAQahgKEwjjpIjIuu-QAxUAAAAAHQAAAAAQywo\"></button><button class=\"button ng-star-inserted\" data-hveid=\"0\" data-ved=\"0CAAQvoAQahgKEwjjpIjIuu-QAxUAAAAAHQAAAAAQzQo\"></button><button class=\"button ng-star-inserted\" data-hveid=\"0\" data-ved=\"0CAAQvoAQahgKEwjjpIjIuu-QAxUAAAAAHQAAAAAQzAo\"></button><button class=\"button ng-star-inserted\" data-hveid=\"0\" data-ved=\"0CAAQvoAQahgKEwjjpIjIuu-QAxUAAAAAHQAAAAAQzgo\"></button><button class=\"button ng-star-inserted\" data-hveid=\"0\" data-ved=\"0CAAQvoAQahgKEwjjpIjIuu-QAxUAAAAAHQAAAAAQygo\"></button></p>\n<p>&nbsp;</p>\n</blockquote>\n<hr />\n<p><span class=\"citation-333 citation-end-333\">Another different type of disaster also had an impact on the development of professional engineering organizations, and I’d like to talk about this in a little more detail</span>. <span class=\"citation-332 citation-end-332\">This incident, which happened early in the 20th century, is known as the Boston Molasses Disaster</span>. <span class=\"citation-331\">At the time, molasses was used rather than sugar as the principal </span><strong><span class=\"citation-331\">(35) sweetener</span></strong><span class=\"citation-331 citation-end-331\"> in the USA</span>. <span class=\"citation-330 citation-end-330\">It was also used in the manufacture of a number of other important products</span>. <span class=\"citation-329 citation-end-329\">One company in the city of Boston had a large amount of molasses waiting to be transferred to another factory</span>. <span class=\"citation-328\">The molasses—more than 8 million liters of thick, sticky liquid—was stored in a </span><strong><span class=\"citation-328\">(36) tank</span></strong>. <span class=\"citation-327 citation-end-327\">Suddenly, this collapsed, unleashing a wave of molasses up to 5 meters high</span>. <span class=\"citation-326 citation-end-326\">Nearby buildings were swept off their foundations and crashed to the ground</span>. <span class=\"citation-325 citation-end-325\">The wave also swept away a considerable stretch of railway track</span>.<button class=\"button ng-star-inserted\" data-hveid=\"0\" data-ved=\"0CAAQvoAQahgKEwjjpIjIuu-QAxUAAAAAHQAAAAAQ0go\"></button><button class=\"button ng-star-inserted\" data-hveid=\"0\" data-ved=\"0CAAQvoAQahgKEwjjpIjIuu-QAxUAAAAAHQAAAAAQ0Ao\"></button><button class=\"button ng-star-inserted\" data-hveid=\"0\" data-ved=\"0CAAQvoAQahgKEwjjpIjIuu-QAxUAAAAAHQAAAAAQ0Qo\"></button><button class=\"button ng-star-inserted\" data-hveid=\"0\" data-ved=\"0CAAQvoAQahgKEwjjpIjIuu-QAxUAAAAAHQAAAAAQzwo\"></button></p>\n<p>&nbsp;</p>\n<p>&nbsp;</p>\n<p>&nbsp;</p>\n<blockquote>\n<p><strong><span class=\"citation-324\">Dịch:</span></strong><span class=\"citation-324 citation-end-324\"> Một loại thảm họa khác cũng có tác động đến sự phát triển của các tổ chức kỹ thuật chuyên nghiệp, và tôi muốn nói chi tiết hơn một chút về điều này</span>. <span class=\"citation-323 citation-end-323\">Sự cố này, xảy ra vào đầu thế kỷ 20, được gọi là Thảm họa Rỉ mật Boston</span>. <span class=\"citation-322\">Vào thời điểm đó, rỉ mật được sử dụng thay vì đường như là chất </span><strong><span class=\"citation-322\">(35) tạo ngọt</span></strong><span class=\"citation-322 citation-end-322\"> chính ở Hoa Kỳ</span>. <span class=\"citation-321 citation-end-321\">Nó cũng được sử dụng trong sản xuất một số sản phẩm quan trọng khác</span>. <span class=\"citation-320 citation-end-320\">Một công ty ở thành phố Boston có một lượng lớn rỉ mật đang chờ được chuyển đến một nhà máy khác</span>. <span class=\"citation-319\">Rỉ mật—hơn 8 triệu lít chất lỏng đặc, dính—được lưu trữ trong một </span><strong><span class=\"citation-319\">(36) bể</span></strong>. <span class=\"citation-318 citation-end-318\">Đột nhiên, bể này sụp đổ, giải phóng một làn sóng rỉ mật cao tới 5 mét</span>. <span class=\"citation-317 citation-end-317\">Các tòa nhà gần đó bị quét khỏi móng và đổ sập xuống đất</span>. <span class=\"citation-316 citation-end-316\">Làn sóng cũng cuốn trôi một đoạn đường sắt đáng kể</span>.<button class=\"button ng-star-inserted\" data-hveid=\"0\" data-ved=\"0CAAQvoAQahgKEwjjpIjIuu-QAxUAAAAAHQAAAAAQ2Ao\"></button><button class=\"button ng-star-inserted\" data-hveid=\"0\" data-ved=\"0CAAQvoAQahgKEwjjpIjIuu-QAxUAAAAAHQAAAAAQ1wo\"></button><button class=\"button ng-star-inserted\" data-hveid=\"0\" data-ved=\"0CAAQvoAQahgKEwjjpIjIuu-QAxUAAAAAHQAAAAAQ1go\"></button><button class=\"button ng-star-inserted\" data-hveid=\"0\" data-ved=\"0CAAQvoAQahgKEwjjpIjIuu-QAxUAAAAAHQAAAAAQ1Qo\"></button><button class=\"button ng-star-inserted\" data-hveid=\"0\" data-ved=\"0CAAQvoAQahgKEwjjpIjIuu-QAxUAAAAAHQAAAAAQ1Ao\"></button></p>\n<p>&nbsp;</p>\n</blockquote>\n<hr />\n<p><span class=\"citation-315 citation-end-315\">Local residents were furious, as they felt that the company was to blame</span>. <span class=\"citation-314\">They banded together and succeeded in bringing about a </span><strong><span class=\"citation-314\">(37) trial</span></strong><span class=\"citation-314 citation-end-314\"> charging the company with negligence</span>. <span class=\"citation-313 citation-end-313\">After three years, the company was found responsible for the accident and required to pay out in damages—the equivalent of six or seven million dollars in today’s money</span>.<button class=\"button ng-star-inserted\" data-hveid=\"0\" data-ved=\"0CAAQvoAQahgKEwjjpIjIuu-QAxUAAAAAHQAAAAAQ3Ao\"></button><button class=\"button ng-star-inserted\" data-hveid=\"0\" data-ved=\"0CAAQvoAQahgKEwjjpIjIuu-QAxUAAAAAHQAAAAAQ3Qo\"></button><button class=\"button ng-star-inserted\" data-hveid=\"0\" data-ved=\"0CAAQvoAQahgKEwjjpIjIuu-QAxUAAAAAHQAAAAAQ2wo\"></button><button class=\"button ng-star-inserted\" data-hveid=\"0\" data-ved=\"0CAAQvoAQahgKEwjjpIjIuu-QAxUAAAAAHQAAAAAQ2go\"></button><button class=\"button ng-star-inserted\" data-hveid=\"0\" data-ved=\"0CAAQvoAQahgKEwjjpIjIuu-QAxUAAAAAHQAAAAAQ2Qo\"></button></p>\n<p>&nbsp;</p>\n<p>&nbsp;</p>\n<p>&nbsp;</p>\n<p>&nbsp;</p>\n<p>&nbsp;</p>\n<p><span class=\"citation-312 citation-end-312\">Even today, no one is absolutely sure about the immediate causes of the accident</span>. <span class=\"citation-311\">However, it is certainly clear that not enough </span><strong><span class=\"citation-311\">(38) safety</span></strong><span class=\"citation-311 citation-end-311\"> tests were carried out</span>. <span class=\"citation-310 citation-end-310\">Had these been done in accordance with the standards now applicable, then the accident would almost certainly have been prevented</span>. <span class=\"citation-309\">It seems that the collapse was probably brought about by fermentation of the molasses, which led to an increase in </span><strong><span class=\"citation-309\">(39) pressure</span></strong>. <span class=\"citation-308 citation-end-308\">This increase probably exerted too much force against a fatigue crack or some other weakness</span>.<button class=\"button ng-star-inserted\" data-hveid=\"0\" data-ved=\"0CAAQvoAQahgKEwjjpIjIuu-QAxUAAAAAHQAAAAAQ4Ao\"></button><button class=\"button ng-star-inserted\" data-hveid=\"0\" data-ved=\"0CAAQvoAQahgKEwjjpIjIuu-QAxUAAAAAHQAAAAAQ4Qo\"></button><button class=\"button ng-star-inserted\" data-hveid=\"0\" data-ved=\"0CAAQvoAQahgKEwjjpIjIuu-QAxUAAAAAHQAAAAAQ3wo\"></button><button class=\"button ng-star-inserted\" data-hveid=\"0\" data-ved=\"0CAAQvoAQahgKEwjjpIjIuu-QAxUAAAAAHQAAAAAQ4go\"></button><button class=\"button ng-star-inserted\" data-hveid=\"0\" data-ved=\"0CAAQvoAQahgKEwjjpIjIuu-QAxUAAAAAHQAAAAAQ3go\"></button></p>\n<p>&nbsp;</p>\n<p>&nbsp;</p>\n<p>&nbsp;</p>\n<p>&nbsp;</p>\n<blockquote>\n<p><strong><span class=\"citation-307\">Dịch:</span></strong><span class=\"citation-307 citation-end-307\"> Cư dân địa phương vô cùng tức giận, vì họ cảm thấy công ty phải chịu trách nhiệm</span>. <span class=\"citation-306\">Họ cùng nhau liên kết lại và thành công trong việc khởi kiện </span><strong><span class=\"citation-306\">(37) xét xử</span></strong><span class=\"citation-306 citation-end-306\"> công ty về tội sơ suất</span>. <span class=\"citation-305 citation-end-305\">Sau ba năm, công ty bị xác định là phải chịu trách nhiệm về vụ tai nạn và phải bồi thường thiệt hại—tương đương với sáu hoặc bảy triệu đô la theo giá trị ngày nay</span>.<button class=\"button ng-star-inserted\" data-hveid=\"0\" data-ved=\"0CAAQvoAQahgKEwjjpIjIuu-QAxUAAAAAHQAAAAAQ5wo\"></button><button class=\"button ng-star-inserted\" data-hveid=\"0\" data-ved=\"0CAAQvoAQahgKEwjjpIjIuu-QAxUAAAAAHQAAAAAQ5Qo\"></button><button class=\"button ng-star-inserted\" data-hveid=\"0\" data-ved=\"0CAAQvoAQahgKEwjjpIjIuu-QAxUAAAAAHQAAAAAQ5Ao\"></button><button class=\"button ng-star-inserted\" data-hveid=\"0\" data-ved=\"0CAAQvoAQahgKEwjjpIjIuu-QAxUAAAAAHQAAAAAQ5go\"></button><button class=\"button ng-star-inserted\" data-hveid=\"0\" data-ved=\"0CAAQvoAQahgKEwjjpIjIuu-QAxUAAAAAHQAAAAAQ4wo\"></button></p>\n<p>&nbsp;</p>\n<p><span class=\"citation-304 citation-end-304\">Ngay cả ngày nay, không ai hoàn toàn chắc chắn về nguyên nhân trực tiếp của vụ tai nạn</span>. <span class=\"citation-303\">Tuy nhiên, rõ ràng là không có đủ các thử nghiệm </span><strong><span class=\"citation-303\">(38) an toàn</span></strong><span class=\"citation-303 citation-end-303\"> được thực hiện</span>. <span class=\"citation-302 citation-end-302\">Nếu những điều này được thực hiện theo các tiêu chuẩn hiện hành, thì vụ tai nạn gần như chắc chắn đã được ngăn chặn</span>. <span class=\"citation-301\">Có vẻ như sự sụp đổ có thể là do sự lên men của rỉ mật, dẫn đến sự gia tăng </span><strong><span class=\"citation-301\">(39) áp suất</span></strong>. <span class=\"citation-300 citation-end-300\">Sự gia tăng này có lẽ đã gây ra quá nhiều lực tác dụng chống lại một vết nứt mỏi hoặc một điểm yếu khác</span>.<button class=\"button ng-star-inserted\" data-hveid=\"0\" data-ved=\"0CAAQvoAQahgKEwjjpIjIuu-QAxUAAAAAHQAAAAAQ7Ao\"></button><button class=\"button ng-star-inserted\" data-hveid=\"0\" data-ved=\"0CAAQvoAQahgKEwjjpIjIuu-QAxUAAAAAHQAAAAAQ6go\"></button><button class=\"button ng-star-inserted\" data-hveid=\"0\" data-ved=\"0CAAQvoAQahgKEwjjpIjIuu-QAxUAAAAAHQAAAAAQ6Qo\"></button><button class=\"button ng-star-inserted\" data-hveid=\"0\" data-ved=\"0CAAQvoAQahgKEwjjpIjIuu-QAxUAAAAAHQAAAAAQ6wo\"></button><button class=\"button ng-star-inserted\" data-hveid=\"0\" data-ved=\"0CAAQvoAQahgKEwjjpIjIuu-QAxUAAAAAHQAAAAAQ6Ao\"></button></p>\n<p>&nbsp;</p>\n</blockquote>\n<hr />\n<p><span class=\"citation-299 citation-end-299\">However, this was one of the main incidents which led to increased legislation in the 1920s to regulate engineers and the engineering profession</span>. <span class=\"citation-298\">It is the reason why we can now only operate if we have gained a </span><strong><span class=\"citation-298\">(40) license</span></strong>. <span class=\"citation-297 citation-end-297\">This requires us always to be conscientious about doing everything necessary to avoid disasters, however time consuming or expensive this may sometimes seem</span>. <span class=\"citation-296 citation-end-296\">Let’s move on now to another… </span><button class=\"button ng-star-inserted\" data-hveid=\"0\" data-ved=\"0CAAQvoAQahgKEwjjpIjIuu-QAxUAAAAAHQAAAAAQ7go\"></button><button class=\"button ng-star-inserted\" data-hveid=\"0\" data-ved=\"0CAAQvoAQahgKEwjjpIjIuu-QAxUAAAAAHQAAAAAQ7wo\"></button><button class=\"button ng-star-inserted\" data-hveid=\"0\" data-ved=\"0CAAQvoAQahgKEwjjpIjIuu-QAxUAAAAAHQAAAAAQ7Qo\"></button></p>\n<p>&nbsp;</p>\n<p>&nbsp;</p>\n<p>&nbsp;</p>\n<blockquote>\n<p><strong><span class=\"citation-295\">Dịch:</span></strong><span class=\"citation-295 citation-end-295\"> Tuy nhiên, đây là một trong những sự cố chính dẫn đến việc tăng cường luật pháp vào những năm 1920 để điều chỉnh các kỹ sư và nghề kỹ thuật</span>. <span class=\"citation-294\">Đó là lý do tại sao chúng ta hiện chỉ có thể hoạt động nếu đã có được </span><strong><span class=\"citation-294\">(40) giấy phép</span></strong>. <span class=\"citation-293 citation-end-293\">Điều này đòi hỏi chúng ta phải luôn tận tâm làm mọi điều cần thiết để tránh thảm họa, bất kể đôi khi điều này có vẻ tốn thời gian hay tốn kém đến mức nào</span>. <span class=\"citation-292 citation-end-292\">Bây giờ, chúng ta hãy chuyển sang một… </span></p>\n</blockquote>\n"}]', 0);
INSERT INTO public.questions VALUES ('a3fc4f09-412b-4c55-bad4-c6eb847a881e', 'bf725440-7036-485f-bc47-2dc540499522', 'matching', 'Questions 27–32', '', '<p>Complete the summary using the list of phrases, <strong data-path-to-node="3" data-index-in-node="48">A–K</strong>, below.</p>
<p>Write the correct letter, <strong data-path-to-node="3" data-index-in-node="86">A–K</strong>, in boxes 27–32 on your answer sheet.</p>', 'summary_completion', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p data-path-to-node=\"4,0\"><span style=\"font-size: 12pt;\"><strong data-path-to-node=\"4,0\" data-index-in-node=\"0\">Maryam Mirzakhani</strong></span></p>\n<p id=\"p-rc_5086358d4a0212dc-247\" data-path-to-node=\"4,1\"><span class=\"citation-29751 citation-29752 citation-29753 citation-29754 citation-29755\">Maryam Mirzakhani is regarded as {H unique}</span><span class=\"citation-29751 citation-29752 citation-29753 citation-29754 citation-29755 citation-end-29755\"> in the field of mathematics because she was the only female holder of the prestigious Fields Medal – a record that she retained at the time of her death. However, maths held lit<sup class=\"superscript\" data-turn-source-index=\"1\"><!----></sup></span><span class=\"citation-29751 citation-29752 citation-29753 citation-29754\">tle {A appeal}</span><span class=\"citation-29751 citation-29752 citation-29753 citation-29754 citation-end-29754\"> for her as a c<sup class=\"superscript\" data-turn-source-index=\"2\"><!----></sup></span><span class=\"citation-29751 citation-29752 citation-29753\">hild and in fact her performance was below average until she was {C intrigued}</span><span class=\"citation-29751 citation-29752 citation-29753 citation-end-29753\"> by a difficult puzzle that one of her siblings showed her.<sup class=\"superscript\" data-turn-source-index=\"3\"><!----></sup></span><span class=\"citation-29751 citation-29752 citation-end-29752\"><sup class=\"superscript\" data-turn-source-index=\"4\"><!----></sup></span><span class=\"citation-29751 citation-end-29751\"><sup class=\"superscript\" data-turn-source-index=\"5\"><!----></sup></span></p>\n<p class=\"source-inline-chip-container ng-star-inserted\"><!----><!----></p>\n<p><!----><!----><!----><!----><!----><!----><!----><!----></p>\n<p id=\"p-rc_5086358d4a0212dc-248\" data-path-to-node=\"4,2\"><span class=\"citation-29748 citation-29749 citation-29750 citation-end-29750\">Lat<sup class=\"superscript\" data-turn-source-index=\"6\"><!----></sup></span><span class=\"citation-29748 citation-29749\">er, as a professional mathematician, she had an inquiring mind and proved herself to be {B determined}</span><span class=\"citation-29748 citation-29749 citation-end-29749\"> when things did not go smoothly. She sai<sup class=\"superscript\" data-turn-source-index=\"7\"><!----></sup></span><span class=\"citation-29748\">d she got the greatest {J satisfaction}</span><span class=\"citation-29748\"> from making ground-breaking discoveries and in fact she was responsible for some extremely {I innovative}</span><span class=\"citation-29748 citation-end-29748\"> mathematical s<sup class=\"superscript\" data-turn-source-index=\"8\"><!----></sup></span>tudies.</p>", "answerOptions": [{"optionText": "A appeal"}, {"optionText": "B determined"}, {"optionText": "C intrigued"}, {"optionText": "D single"}, {"optionText": "E achievement"}, {"optionText": "F devoted"}, {"optionText": "G involved"}, {"optionText": "H unique"}, {"optionText": "I innovative"}, {"optionText": "J satisfaction"}, {"optionText": "K intent"}], "matchingItems": []}', 'null', '[{"content": "<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">27. H (unique) — {Mirzakhani is regarded as unique in the field of mathematics}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 1):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">\"She was the <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"33\">only woman</strong> to win the Fields Medal...\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Only woman\" (người phụ nữ duy nhất) tương ứng với tính chất duy nhất, độc nhất (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"93\">unique</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">28. A (appeal) — {maths held little appeal for her as a child}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 1):</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"20\">\"...maths <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"30\">wasn’t her interest</strong> – reading was.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Vì toán học không phải là sở thích của cô khi còn nhỏ, nên nó có rất ít sức hút (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"93\">appeal</strong>) đối với cô.</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">29. C (intrigued) — {until she was intrigued by a difficult puzzle}</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 1):</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"20\">\"He shared a famous maths problem... that <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"62\">fascinated</strong> her – and she was <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"91\">hooked</strong>.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Fascinated\" và \"hooked\" (bị cuốn hút/mê hoặc) đồng nghĩa với việc cô bị làm cho tò mò/hứng thú (<strong data-path-to-node=\"13,1,0\" data-index-in-node=\"109\">intrigued</strong>) bởi bài toán đố.</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">30. B (determined) — {proved herself to be determined when things did not go smoothly}</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 2):</strong> <em data-path-to-node=\"15,0,0\" data-index-in-node=\"20\">\"...resolute in the face of setbacks.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Resolute\" (kiên định) và \"in the face of setbacks\" (khi đối mặt với khó khăn/thất bại) tương ứng với việc cô rất quyết tâm (<strong data-path-to-node=\"15,1,0\" data-index-in-node=\"137\">determined</strong>) khi mọi việc không suôn sẻ.</p>\n</li>\n</ul>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">31. J (satisfaction) — {she got the greatest satisfaction from making ground-breaking discoveries}</strong></p>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong data-path-to-node=\"17,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 2):</strong> <em data-path-to-node=\"17,0,0\" data-index-in-node=\"20\">\"Of course, the most <strong data-path-to-node=\"17,0,0\" data-index-in-node=\"41\">rewarding</strong> part is the ''Aha'' moment, the <strong data-path-to-node=\"17,0,0\" data-index-in-node=\"81\">excitement</strong> of discovery and <strong data-path-to-node=\"17,0,0\" data-index-in-node=\"109\">enjoyment</strong> of understanding...\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong data-path-to-node=\"17,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Những từ như \"rewarding\", \"excitement\", \"enjoyment\" khi khám phá ra điều mới đều chỉ trạng thái thỏa mãn (<strong data-path-to-node=\"17,1,0\" data-index-in-node=\"118\">satisfaction</strong>) cực độ.</p>\n</li>\n</ul>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">32. I (innovative) — {responsible for some extremely innovative mathematical studies}</strong></p>\n<ul data-path-to-node=\"19\">\n<li>\n<p data-path-to-node=\"19,0,0\"><strong data-path-to-node=\"19,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 2):</strong> <em data-path-to-node=\"19,0,0\" data-index-in-node=\"20\">\"That trail took her to the heights of <strong data-path-to-node=\"19,0,0\" data-index-in-node=\"59\">original research</strong> into mathematics.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"19,1,0\"><strong data-path-to-node=\"19,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Original research\" (nghiên cứu nguyên bản/gốc) trong khoa học đồng nghĩa với những nghiên cứu mang tính đổi mới, sáng tạo (<strong data-path-to-node=\"19,1,0\" data-index-in-node=\"136\">innovative</strong>).</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('7425b55c-695b-4fa6-a28f-80dde03d124b', '6f3d84bb-2560-4142-80c9-021752ef5534', 'fillup', 'Questions 1–10', '<div class="quests-inner-desc">
<div class="txt">
<p>Write<strong> ONE WORD AND/OR A NUMBER</strong> for each answer.</p>
</div>
</div>
<div class="quests-des">
<div class="content-write">
<table class="quill-better-table choice-table" style="border-collapse: collapse; border: 1px solid #000000; border-spacing: 1px;" border="1"><colgroup> <col width="696"> </colgroup>
<tbody>
<tr data-row="row-2zcw">
<td style="border-width: 1px; border-color: #000000; padding: 1px;" data-row="row-2zcw">
<p class="qlbt-cell-line ql-align-center" data-row="row-2zcw" data-cell="cell-jkqg" data-rowspan="1" data-colspan="1"><span style="font-size: 14pt;"><strong>Campsite Reservation Form</strong></span></p>
</td>
</tr>
<tr data-row="row-6gyt">
<td style="border-width: 1px; border-color: #000000; padding: 1px;" data-row="row-6gyt">
<p class="qlbt-cell-line" data-row="row-6gyt" data-cell="cell-rabp" data-rowspan="1" data-colspan="1"><strong>Name:</strong> Sandra Kemp</p>
<p class="qlbt-cell-line" data-row="row-6gyt" data-cell="cell-rabp" data-rowspan="1" data-colspan="1"><strong>Park region: </strong>{Southern} California</p>
<p class="qlbt-cell-line" data-row="row-6gyt" data-cell="cell-rabp" data-rowspan="1" data-colspan="1"><strong>Campground name: </strong>{Mountain} Campground</p>
<p class="qlbt-cell-line" data-row="row-6gyt" data-cell="cell-rabp" data-rowspan="1" data-colspan="1"><strong>Type of site:</strong> {tent}</p>
<p class="qlbt-cell-line" data-row="row-6gyt" data-cell="cell-rabp" data-rowspan="1" data-colspan="1"><strong>Type of vehicle: </strong>will be driving a <span class="fill-history-correct">{truck}</span></p>
<p class="qlbt-cell-line" data-row="row-6gyt" data-cell="cell-rabp" data-rowspan="1" data-colspan="1"><strong>Licence plate number</strong> <span class="fill-history-correct">{QY0918}</span></p>
<p class="qlbt-cell-line" data-row="row-6gyt" data-cell="cell-rabp" data-rowspan="1" data-colspan="1"><strong><span class="note-highlight" data-highlight-idx="1" data-hilight-id="hquest_cjm163">Number of nights:</span></strong> tw<span class="note-highlight" data-highlight-idx="2" data-hilight-id="hquest_cjm360">o</span></p>
<p class="qlbt-cell-line" data-row="row-6gyt" data-cell="cell-rabp" data-rowspan="1" data-colspan="1"><strong><span class="note-highlight" data-highlight-idx="4" data-hilight-id="hquest_cjm407">Departure date:</span></strong> <span class="note-highlight" data-highlight-idx="5" data-hilight-id="hquest_cjm52">{April 12th| April 12 | 12th April | 12 April }</span></p>
</td>
</tr>
<tr data-row="row-mdys">
<td style="border-width: 1px; border-color: #000000; padding: 1px;" data-row="row-mdys">
<p class="qlbt-cell-line" data-row="row-mdys" data-cell="cell-0ttv" data-rowspan="1" data-colspan="1"><strong>Bear-proof food container:</strong> size required : <span class="fill-history-correct">{small}</span></p>
<p class="qlbt-cell-line" data-row="row-mdys" data-cell="cell-0ttv" data-rowspan="1" data-colspan="1"><strong>Type of nature walk booked: </strong>the {flower} walk</p>
<p class="qlbt-cell-line" data-row="row-mdys" data-cell="cell-0ttv" data-rowspan="1" data-colspan="1"><strong>Type of park pass: </strong>the <span class="fill-history-correct">{one year|1 year}</span> pass</p>
<p class="qlbt-cell-line" data-row="row-mdys" data-cell="cell-0ttv" data-rowspan="1" data-colspan="1"><strong>Donation programme selection: </strong>the {youth}programme</p>
</td>
</tr>
</tbody>
</table>
<div class="quill-better-table-wrapper"> </div>
</div>
</div>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<h2 data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">PART 1: CAMPSITE RESERVATION</strong></h2>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Employee:</strong> Nature Park Services, how may I help you today?</p>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Sandra:</strong> Hello, I’m calling to make a campsite reservation.</p>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">Employee:</strong> Great, let me just pull up the reservation form and we can get started.</p>\n<p data-path-to-node=\"6\">Okay, first, could I get your name?</p>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Sandra:</strong> Sure, it’s Sandra Camp.</p>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">Employee:</strong> All right, Miss Camp. I can make reservations for the Northern, Central, and Southern California parks.</p>\n<p data-path-to-node=\"9\">Which region will you be traveling to?</p>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">Sandra:</strong> Is Mount Laguna in the central or southern region?</p>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Employee:</strong> Is that where you’re going? Yes, that’s <strong data-path-to-node=\"11\" data-index-in-node=\"50\">(Q1) Southern</strong>.</p>\n<p data-path-to-node=\"12\">Do you know which campground?</p>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">Sandra:</strong> Actually, I was hoping you could help me with that.</p>\n<p data-path-to-node=\"14\">I’ve read a lot about two different campgrounds: Sunrise and Mountain, but I can’t decide.</p>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">Employee:</strong> Mountain Campground has many hiking trails close by, but then again, Sunrise Campground is next to the lake and my husband loves to fish.</p>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">Sandra:</strong> Hmm, they’re both really beautiful spots.</p>\n<p data-path-to-node=\"17\">I guess it depends on when you’re going, really.</p>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">Employee:</strong> Well, we’re going in April.</p>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">Sandra:</strong> The thing is, fishing at Sunrise Campground is only allowed from June to September, so I suggest <strong data-path-to-node=\"19\" data-index-in-node=\"105\">(Q2) Mountain</strong>.</p>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">Employee:</strong> Okay, then that makes it easy. So we’ve selected the campground.</p>\n<p data-path-to-node=\"21\">So now we need to think about which sort of site.</p>\n<p data-path-to-node=\"22\">There are different options: you can stay at a cabin, a tent, or a recreational vehicle campsite.</p>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">Sandra:</strong> Which type of site offers the most peace and quiet?</p>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">Employee:</strong> A <strong data-path-to-node=\"24\" data-index-in-node=\"12\">(Q3) tent</strong> site would be your best bet.</p>\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">Sandra:</strong> That sounds good to me.</p>\n<p data-path-to-node=\"26\">Um, so if you’ve read about the park, you probably know that some vehicles aren’t suitable for the park roads.</p>\n<p data-path-to-node=\"27\">Cars tend to get stuck when it rains.</p>\n<p data-path-to-node=\"28\">If you have a <strong data-path-to-node=\"28\" data-index-in-node=\"14\">(Q4) truck</strong>, you won’t have any trouble.</p>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">Employee:</strong> Luckily, we do, and we’ll be driving that instead of our car.</p>\n<p data-path-to-node=\"30\">I hope we don’t get any rain, but I’d rather be safe than sorry.</p>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"31\" data-index-in-node=\"0\">Sandra:</strong> Perfect. I’ll just need to get your license plate number.</p>\n<p data-path-to-node=\"32\"><strong data-path-to-node=\"32\" data-index-in-node=\"0\">Employee:</strong> That’s <strong data-path-to-node=\"32\" data-index-in-node=\"17\">(Q5) QY0918</strong>.</p>\n<p data-path-to-node=\"33\"><strong data-path-to-node=\"33\" data-index-in-node=\"0\">Sandra:</strong> Thanks. And what about your trip dates?</p>\n<p data-path-to-node=\"34\"><strong data-path-to-node=\"34\" data-index-in-node=\"0\">Employee:</strong> We’d like to stay for three days.</p>\n<p data-path-to-node=\"35\"><strong data-path-to-node=\"35\" data-index-in-node=\"0\">Sandra:</strong> Does that mean you’ll be staying two nights?</p>\n<p data-path-to-node=\"36\"><strong data-path-to-node=\"36\" data-index-in-node=\"0\">Employee:</strong> That’s right. We’ll be arriving on April 10th and leaving on the <strong data-path-to-node=\"36\" data-index-in-node=\"75\">(Q6) twelfth</strong> (April 12th).</p>\n<hr data-path-to-node=\"37\">\n<h2 data-path-to-node=\"38\"><strong data-path-to-node=\"38\" data-index-in-node=\"0\">SPECIAL REQUIREMENTS</strong></h2>\n<p data-path-to-node=\"39\"><strong data-path-to-node=\"39\" data-index-in-node=\"0\">Employee:</strong> Now, the park is home to some black bears, so you’ll need to rent a bear-proof food container to lock your food inside for hikes.</p>\n<p data-path-to-node=\"40\">It’s really just a precaution. We have small, medium, and large food containers for campers.</p>\n<p data-path-to-node=\"41\"><strong data-path-to-node=\"41\" data-index-in-node=\"0\">Sandra:</strong> Oh, I’m familiar with food containers, but they can be heavy.</p>\n<p data-path-to-node=\"42\"><strong data-path-to-node=\"42\" data-index-in-node=\"0\">Employee:</strong> Well, the large one is, but if you get the <strong data-path-to-node=\"42\" data-index-in-node=\"53\">(Q7) small</strong> size, it’s not so heavy.</p>\n<p data-path-to-node=\"43\"><strong data-path-to-node=\"43\" data-index-in-node=\"0\">Sandra:</strong> Oh, let’s do that. I really want something lightweight.</p>\n<p data-path-to-node=\"44\"><strong data-path-to-node=\"44\" data-index-in-node=\"0\">Employee:</strong> Would you be interested in signing up for a guided nature walk on the second day of your trip?</p>\n<p data-path-to-node=\"45\"><strong data-path-to-node=\"45\" data-index-in-node=\"0\">Sandra:</strong> A what kind of walk?</p>\n<p data-path-to-node=\"46\"><strong data-path-to-node=\"46\" data-index-in-node=\"0\">Employee:</strong> Well, at 7:00 AM, there are three different ones near your campground:</p>\n<p data-path-to-node=\"47\">There’s the flower walk, the bird watching walk, and the waterfall walk.</p>\n<p data-path-to-node=\"48\"><strong data-path-to-node=\"48\" data-index-in-node=\"0\">Sandra:</strong> Really? I love gardening, so the <strong data-path-to-node=\"48\" data-index-in-node=\"41\">(Q8) flower</strong> walk sounds interesting.</p>\n<p data-path-to-node=\"49\">My son might be more into the waterfall one, but I can’t imagine him getting up in time.</p>\n<p data-path-to-node=\"50\">Maybe I could go alone. Could you sign me up?</p>\n<p data-path-to-node=\"51\"><strong data-path-to-node=\"51\" data-index-in-node=\"0\">Employee:</strong> Sure. Now, just a few more things.</p>\n<p data-path-to-node=\"52\">Visitors must purchase park passes as well.</p>\n<p data-path-to-node=\"53\">You have the option of the one-day pass, which would be cheaper, or the <strong data-path-to-node=\"53\" data-index-in-node=\"72\">(Q9) one-year</strong> pass, which is a better deal if you plan to go to more parks.</p>\n<p data-path-to-node=\"54\"><strong data-path-to-node=\"54\" data-index-in-node=\"0\">Sandra:</strong> Let’s go ahead and get that. I’m sure we’ll visit more parks soon. It’s a really good bargain.</p>\n<p data-path-to-node=\"55\"><strong data-path-to-node=\"55\" data-index-in-node=\"0\">Employee:</strong> Plus, we donate $5 of the pass fee to one of our three park programs.</p>\n<p data-path-to-node=\"56\">You get to choose which one.</p>\n<p data-path-to-node=\"57\"><strong data-path-to-node=\"57\" data-index-in-node=\"0\">Sandra:</strong> Park programs?</p>\n<p data-path-to-node=\"58\"><strong data-path-to-node=\"58\" data-index-in-node=\"0\">Employee:</strong> Yes, well, we run a <strong data-path-to-node=\"58\" data-index-in-node=\"30\">(Q10) youth</strong> program for local kids to attend a nature camp in the summer.</p>\n<p data-path-to-node=\"59\">The other two options are conservation projects: there’s a wildlife program and a tree planting program.</p>\n<p data-path-to-node=\"60\"><strong data-path-to-node=\"60\" data-index-in-node=\"0\">Sandra:</strong> Wow, they all sound worthwhile. What should I do?</p>\n<p data-path-to-node=\"61\">Um, it’s important for children to appreciate the outdoors.</p>\n<p data-path-to-node=\"62\">Let’s go with the youth program.</p>\n<p data-path-to-node=\"63\"><strong data-path-to-node=\"63\" data-index-in-node=\"0\">Employee:</strong> Okay, we just need to review the fee and payment information.</p>"}]', 0);
INSERT INTO public.questions VALUES ('8ee6eb28-8238-45e0-81d9-197156173d47', '1b48b8ab-5ec7-4a8e-89d9-4acf0335fd69', 'fillup', 'Questions 38 – 40', '<p>Complete the summary below.</p>
<p>Choose <strong>NO MORE THAN TWO WORDS</strong> from the text for each answer.</p>
<p>Write your answers in boxes 38-40 on your answer sheet.</p>
<p style="text-align: center;" data-path-to-node="4"><span style="font-size: 12pt;"><strong data-path-to-node="4" data-index-in-node="0">Number tests conducted on the Pirahã</strong></span></p>
<p>Psycholinguist Peter Gordon spent time with the Pirahã, conducting several tests on their numeracy. For example, he wanted them to identify how many {nuts} there were in a container, which they didn’t succeed in doing. His conclusion was that they lacked the ability to carry out his task because their language has only general words for quantities.</p>
<p>Anthropological linguist Caleb Everett’s test involved laying out a row of {batteries} in front of the Pirahã and asking them to copy it. Caleb concluded that the Pirahã were using what he referred to as {analog estimation} in order to attempt his tasks.</p>', '', 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p><strong data-path-to-node=\"4\" data-index-in-node=\"0\">38. Psycholinguist Peter Gordon… wanted them to identify how many {nuts} there were in a container.</strong></p>\n<ul data-path-to-node=\"5\">\n<li><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 3):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“For example, they were asked to remember whether Gordon had placed either three or eight <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"110\">nuts</strong> in a <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"120\">can</strong>.”</em></li>\n<li><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Container” (vật chứa) trong bài đọc chính là cái lon (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"67\">can</strong>). Vật mà Gordon bỏ vào trong đó để thử thách trí nhớ và khả năng đếm của người Pirahã chính là những hạt dẻ/hạt hạch (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"189\">nuts</strong>).</li>\n</ul>\n<p><strong data-path-to-node=\"6\" data-index-in-node=\"0\">39. Caleb Everett’s test involved laying out a row of {batteries} in front of the Pirahã and asking them to copy it.</strong></p>\n<ul data-path-to-node=\"7\">\n<li><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 5):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“In his initial test, he laid down on a table a <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"68\">line of batteries</strong>, and asked the Pirahã to <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"111\">make a second line just like the first</strong>.”</em></li>\n<li><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Laying out a row” tương ứng với “laid down a line”. “Copy it” tương ứng với “make a second line just like the first”. Vật dụng mà Caleb sử dụng cho thí nghiệm này là những viên pin (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"195\">batteries</strong>).</li>\n</ul>\n<p><strong data-path-to-node=\"8\" data-index-in-node=\"0\">40. Caleb concluded that the Pirahã were using what he referred to as {analog estimation} in order to attempt his tasks.</strong></p>\n<ul data-path-to-node=\"9\">\n<li><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 5):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">“Instead, they were employing a strategy Caleb calls ‘<strong data-path-to-node=\"9,0,0\" data-index-in-node=\"74\">analog estimation</strong>’, which worked adequately for a few claps but broke down beyond that.”</em></li>\n<li><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Referred to as” tương ứng với “calls” (gọi là). Chiến thuật mà người Pirahã sử dụng thay vì đếm chính xác được Caleb đặt tên là ước tính tương tự (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"160\">analog estimation</strong>).</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('7e31c50a-75b7-41de-94a6-4b67f0f32e1e', '1fdd86cb-25eb-4b10-b925-7ce9cbc5371f', 'fillup', 'Questions 31–40', '<p>Write <strong>ONE WORD AND/OR A NUMBER</strong> for each answer.</p>
<p><span style="font-size: 14pt;"><strong>Saffron</strong></span></p>
<p>Saffron: a spice which comes from the crocus flower</p>
<p><strong>Cultivation and production</strong></p>
<p>Harvested in October</p>
<p>Number of stigmas needed for 50 grams: {14,000 | 14000}</p>
<p>Method of preservation: {drying}</p>
<p>Taste and aroma: like honey</p>
<p>Forms in which sold: as whole stigmas and as a {powder}</p>
<p><strong>Uses of saffron today</strong></p>
<p>To colour and flavour food in many countries especially for making {rice} dishes</p>
<p>In medicine</p>
<p>• as a drug in treatment of problems affecting the {eye}</p>
<p>• experiments with rats as protection from exposure to some types of {lights}</p>
<p><strong>History of saffron use</strong></p>
<p>Ancient Crete as a dye for {clothes}</p>
<p>Roman Empire</p>
<p>• in oil used for the production of {cosmetics}</p>
<p>• as a {perfume} in public baths</p>
<p>Persia (Iran) as a dye used in the making of {carpets}</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p><strong>Narrator:</strong> You will hear a lecturer giving a talk to some engineering students about ethics in engineering. First you have some time to look at questions 31 to forty. Now listen carefully and answer questions 31 to forty.</p>\n<p>For my investigation into the history and uses of plant products, I have focused on the cultivation and production of saffron, an expensive bright yellow spice made from crocus flowers. Unlike most other species of crocus, the saffron crocus doesn’t flower in February or March, but in October, when it produces fragrant lilac coloured flowers, which are harvested at that time. During the harvest, the flower petals are discarded and only the stigmas, the three dark orange or red colored reproductive parts of the flower, are commercially used. One person must pick for almost 400 hours to produce just one kilo of saffron, and amazingly to produce just 50 grams it takes about <strong>(31) 14,000</strong> individual stigmas. No wonder the spice is so expensive.</p>\n<blockquote>\n<p><strong>Dịch:</strong> Trong nghiên cứu của tôi về lịch sử và công dụng của các sản phẩm thực vật, tôi đã tập trung vào việc trồng trọt và sản xuất saffron, một loại gia vị màu vàng tươi đắt tiền được làm từ hoa nghệ tây (crocus). Không giống như hầu hết các loài hoa nghệ tây khác, hoa nghệ tây saffron không nở vào tháng Hai hoặc tháng Ba, mà vào tháng Mười, khi nó tạo ra những bông hoa màu tím tử đinh hương thơm ngát, được thu hoạch vào thời điểm đó. Trong quá trình thu hoạch, cánh hoa bị loại bỏ và chỉ nhụy hoa—ba phần sinh sản có màu cam đậm hoặc đỏ của hoa—là được sử dụng thương mại. Một người phải hái gần 400 giờ mới thu được chỉ một ký saffron, và thật đáng kinh ngạc, để sản xuất chỉ 50 gram, cần khoảng <strong>(31) 14.000</strong> nhụy hoa riêng lẻ. Thảo nào loại gia vị này lại đắt tiền đến vậy.</p>\n</blockquote>\n<hr />\n<p>After this painstaking harvesting, and to preserve the intensive taste, smell and color of the product, the stigmas are subject to a process of <strong>(32) drying</strong> by which some 98% of their moisture content is removed. This makes it possible to keep saffron on the shelf to be used for many years. The highly prized spice is famous for the flavor and aroma it imparts, which are often compared to that of honey. Saffron is also prized for its rich golden color, which makes food look so tempting and indulgent. If you want to buy some of this fabled spice, you will find that saffron is either sold as whole stigmas or ground up as a <strong>(33) powder</strong>.</p>\n<blockquote>\n<p><strong>Dịch:</strong> Sau quá trình thu hoạch tỉ mỉ này, và để bảo quản hương vị, mùi thơm và màu sắc đậm đà của sản phẩm, nhụy hoa được đưa vào quy trình <strong>(32) sấy khô</strong> để loại bỏ khoảng 98% độ ẩm của chúng. Điều này giúp có thể giữ saffron trên kệ để sử dụng trong nhiều năm. Loại gia vị được đánh giá cao này nổi tiếng vì hương vị và mùi thơm mà nó mang lại, thường được so sánh với mật ong. Saffron cũng được trân trọng vì màu vàng óng phong phú, khiến món ăn trông rất hấp dẫn và xa hoa. Nếu bạn muốn mua loại gia vị huyền thoại này, bạn sẽ thấy saffron được bán dưới dạng nhụy nguyên sợi hoặc xay thành <strong>(33) bột</strong>.</p>\n</blockquote>\n<hr />\n<p>Today, saffron is used in both eastern and western cuisines to add both color and flavor to an enormous range of recipes, though cooks would agree that it is most commonly added to recipes for the cooking of <strong>(34) rice</strong> because somehow it seems to complement such dishes perfectly. It is found to varying degrees in Italian, Spanish, Indian and Iranian food. Although food preparation is its most common present day use, medical research indicates that saffron may have important applications as a drug in the clinical treatment of a number of problems affecting the <strong>(35) eye</strong>. Patients given saffron in their regular diet seem to show remarkable signs of recovery from serious conditions. And although scientists are still unsure of exactly why, recent experiments with laboratory rats have shown saffron to be effective in protecting the animals from damage caused when they are exposed to potentially harmful <strong>(36) lights</strong>.</p>\n<blockquote>\n<p><strong>Dịch:</strong> Ngày nay, saffron được sử dụng trong cả ẩm thực phương Đông và phương Tây để thêm cả màu sắc và hương vị cho vô số công thức nấu ăn, mặc dù các đầu bếp đồng ý rằng nó thường được thêm vào các công thức nấu <strong>(34) cơm</strong> vì bằng cách nào đó, nó dường như bổ sung hoàn hảo cho các món ăn như vậy. Nó được tìm thấy ở nhiều mức độ khác nhau trong ẩm thực Ý, Tây Ban Nha, Ấn Độ và Iran. Mặc dù chuẩn bị thức ăn là công dụng phổ biến nhất hiện nay, nghiên cứu y học chỉ ra rằng saffron có thể có các ứng dụng quan trọng như một loại thuốc trong điều trị lâm sàng một số vấn đề ảnh hưởng đến <strong>(35) mắt</strong>. Bệnh nhân được cho saffron vào chế độ ăn uống thường xuyên của họ dường như cho thấy những dấu hiệu phục hồi đáng kể khỏi các tình trạng nghiêm trọng. Và mặc dù các nhà khoa học vẫn chưa chắc chắn chính xác lý do tại sao, các thí nghiệm gần đây trên chuột trong phòng thí nghiệm đã cho thấy saffron có hiệu quả trong việc bảo vệ động vật khỏi bị tổn thương khi chúng tiếp xúc với <strong>(36) ánh sáng</strong> có khả năng gây hại.</p>\n</blockquote>\n<hr />\n<p>Now I’d like to give a few examples of how saffron has been used since ancient times. Some of the earliest evidence of saffron cultivation comes from archaeological excavations dating back 4,000 years on the island of Crete, where paintings and other artifacts have been found indicating that women wore beautiful saffron colored <strong>(37) clothes</strong>. This is the earliest evidence of saffron being used as a dye. During the Roman Empire saffron oil was produced, which because of both its color and aroma was used to create <strong>(38) cosmetics</strong>, but only the wealthiest citizens could afford these. Another use of saffron was to be found in the public baths—there saffron was used as a <strong>(39) perfume</strong> to keep the places smelling fresh and aromatic. It is even said that the streets of Rome were strewn with saffron threads to greet Emperor Nero as an extravagant and sweet smelling gesture when he made a triumphal entrance into the city.</p>\n<blockquote>\n<p><strong>Dịch:</strong> Bây giờ tôi muốn đưa ra một vài ví dụ về cách saffron đã được sử dụng từ thời cổ đại. Một số bằng chứng sớm nhất về việc trồng saffron đến từ các cuộc khai quật khảo cổ học có niên đại 4.000 năm trên đảo Crete, nơi các bức tranh và hiện vật khác đã được tìm thấy cho thấy phụ nữ mặc <strong>(37) quần áo</strong> màu saffron tuyệt đẹp. Đây là bằng chứng sớm nhất về việc saffron được sử dụng làm thuốc nhuộm. Trong Đế chế La Mã, dầu saffron được sản xuất, do cả màu sắc và mùi thơm của nó nên được sử dụng để tạo ra <strong>(38) mỹ phẩm</strong>, nhưng chỉ những công dân giàu có nhất mới có thể mua được những thứ này. Một công dụng khác của saffron được tìm thấy trong các nhà tắm công cộng—ở đó saffron được sử dụng làm <strong>(39) nước hoa</strong> để giữ cho những nơi này có mùi thơm mát và dễ chịu. Thậm chí người ta còn kể rằng các con phố ở Rome đã được rắc sợi saffron để chào đón Hoàng đế Nero như một cử chỉ xa hoa và ngọt ngào khi ông khải hoàn tiến vào thành phố.</p>\n</blockquote>\n<hr />\n<p>Other parts of the ancient world use saffron extensively. One of the most well known examples was in Persia, which is modern day Iran, where saffron was a vital part of the process of manufacturing <strong>(40) carpets</strong> being used as a traditional dye along with other natural products like berries and minerals. To end my presentation, I’d like to read out a recipe written by a…</p>\n<blockquote>\n<p><strong>Dịch:</strong> Các khu vực khác của thế giới cổ đại cũng sử dụng saffron rộng rãi. Một trong những ví dụ nổi tiếng nhất là ở Ba Tư, tức Iran ngày nay, nơi saffron là một phần quan trọng của quá trình sản xuất <strong>(40) thảm</strong>, được sử dụng làm thuốc nhuộm truyền thống cùng với các sản phẩm tự nhiên khác như quả mọng và khoáng chất. Để kết thúc bài thuyết trình của mình, tôi muốn đọc một công thức được viết bởi một…</p>\n</blockquote>\n<p><strong>Narrator:</strong> That is the end of part 4. You now have one minute to check your answers to part four.</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('4dfe723b-b34e-4729-88ec-5135ffdc56cc', 'be5e39bd-aca6-4cbe-82ee-14c894f52c97', 'radio', 'Questions 37–40', '', '<p>Choose <strong>YES</strong> if the statement agrees with the claims of the writer, choose <strong>NO</strong> if the statement contradicts the claims of the writer, or <strong>NOT GIVEN</strong>  if it is impossible to say what the writer thinks about this.</p>', 'yes_no_not_given', '[{"correct": 1, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "The price of materials is one drawback to using traditional architecture."}, {"correct": 2, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Earthen structures can easily be built in all regions of the U.S."}, {"correct": 0, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Working with a traditional earthen structure can have physical benefits."}, {"correct": 2, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "A traditional architecture curriculum is best suited to middle school level students."}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">37. The price of materials is one drawback to using traditional architecture. — {NO}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn C):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“Traditional architectural materials, such as earth, clay and straw, are <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"93\">cheap, easy to work with and readily available</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả khẳng định các vật liệu truyền thống như đất, sét và rơm thì <strong data-path-to-node=\"5,1,0\" data-index-in-node=\"81\">rẻ</strong> (cheap) và dễ kiếm. Do đó, nói giá cả vật liệu là một “trở ngại” (drawback) là sai (contradicts) với quan điểm của người viết.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">38. Earthen structures can easily be built in all regions of the U.S. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn D):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“In New Mexico, examples of hand-built earthen structures still abound… Traditional building materials and the land that supplies them are so accessible that handcrafting a house still remains feasible.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ đề cập đến việc xây dựng nhà bằng đất rất khả thi tại <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"78\">New Mexico</strong> (Tây Nam Hoa Kỳ). Tác giả <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"115\">không đưa ra khẳng định</strong> nào về việc liệu kiến trúc này có thể dễ dàng xây dựng ở <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"196\">tất cả các vùng khác</strong> (all regions) của Mỹ hay không.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">39. Working with a traditional earthen structure can have physical benefits. — {YES}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn E):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">“During the project, a student will get to know the materials… solve problems, work with classmates, and <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"127\">exercise muscles</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm từ “exercise muscles” (rèn luyện cơ bắp/vận động cơ bắp) chính là minh chứng cho các lợi ích về mặt thể chất (physical benefits) mà học sinh nhận được khi tham gia dự án.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">40. A traditional architecture curriculum is best suited to middle school level students. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn I):</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"20\">“This experiment in adobe conservation with middle school students convinced me that traditional architecture deserves a place in the <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"154\">regular curriculum</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả khẳng định kiến trúc truyền thống xứng đáng có một vị trí trong <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"84\">chương trình học chính quy</strong> (regular curriculum) sau khi thực hiện thành công với học sinh trung học (middle school). Tuy nhiên, tác giả <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"220\">không hề nói</strong> rằng nó “phù hợp nhất” (best suited) cho cấp học này so với các cấp học khác.</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('098171ce-d7a2-4cba-bc43-c8e3bcbbbe03', '81506d49-fb5d-415b-9b2b-d202c542cadc', 'fillup', 'Questions 31–40', '<p>Complete the notes below..</p>
<p>Write <strong>ONE WORD AND/OR A NUMBER</strong> for each answer.</p>
<p style="text-align: center;"><strong>The Africa clawed frog (Xenopus laevis)</strong></p>
<p><strong>Description</strong></p>
<p>∙ Skin is {smooth} and can vary in colour</p>
<p>∙ Skin is coated with a slippery film for {protection}</p>
<p>∙ Males are {half} the size of females</p>
<p><strong>Habitats</strong></p>
<p>∙ Native to Africa</p>
<p>∙ Live in fresh water – prefered water that is {still}</p>
<p>∙ Can survive high levels of {salt} in water</p>
<p>∙ Cannot survive if there is any metal in water</p>
<p>∙ In drought conditions, may live in {mud} for up to a year</p>
<p><strong>Diet</strong></p>
<p>∙ Eat living or dead water creatures</p>
<p>∙ Find food using their sense of {smell}, their fingers, and their lateral lines</p>
<p>∙ Take food into their mouths using from legs and a {pump} system</p>
<p><strong>Other information</strong></p>
<p>∙ Now popular as a pet in the US</p>
<p>∙ In some US states they are identified as a {pest}</p>
<p>∙ Used in laboratories for developmental research</p>
<p>∙ Mucus from the skin was {antibiotic} properties</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p class=\"MsoNormal\"><strong>SECTION 4: THE AFRICAN CLAWED FROG (XENOPUS LAEVIS)</strong></p>\n<p class=\"MsoNormal\"><strong>Student:</strong> The aim of our study was to look at how naturally occurring substances can be used to treat infections, and we carried out a laboratory study using a frog called the African clawed frog, which has the scientific name <em>Xenopus laevis</em>.</p>\n<p class=\"MsoNormal\">So before I describe our study in detail, let me give you a general description about this frog. Like most other frogs, the African clawed frogs have a <span style=\"background-color: #f3db7b;\"><strong>(31) smooth</strong></span> skin. This is one way you can distinguish them from toads, whose skin is rough, and they can change the colour of their skin to blend in with their surroundings.</p>\n<p class=\"MsoNormal\">The surface of their skin also has another feature: it&#8217;s covered with a layer of mucus. This makes it hard for other creatures to pick them up, and so it provides <span style=\"background-color: #f3db7b;\"><strong>(32) protection</strong></span> against predators.</p>\n<p class=\"MsoNormal\">How big are they? Well, it depends on whether they&#8217;re male or female, because the females in this case are a whole lot bigger than the males. A large-sized female may be 8 inches long, while the males are about <span style=\"background-color: #f3db7b;\"><strong>(33) half</strong></span> that size, so they&#8217;re pretty small in comparison.</p>\n<div class=\"MsoNormal\" style=\"text-align: center;\" align=\"center\">\n<hr align=\"center\" size=\"2\" width=\"100%\"></div>\n<p class=\"MsoNormal\"><strong>HABITAT</strong></p>\n<p class=\"MsoNormal\"><strong>Student:</strong> What about their natural habitat? As their name suggests, these frogs are native to Africa and they&#8217;re found in most parts of Africa south of the Sahara Desert. They make their houses in fresh water, but they&#8217;re rarely found in running streams; they like <span style=\"background-color: #f3db7b;\"><strong>(34) still</strong></span> water.</p>\n<p class=\"MsoNormal\">As far as the temperature of the water goes, they&#8217;re not too fussy; it can be warm or cool. They don&#8217;t need to be in water where there are plants growing, and they can live in water that has quite a lot of <span style=\"background-color: #f3db7b;\"><strong>(35) salt</strong> </span>in it, so they can live in brackish areas such as marshes and estuaries.</p>\n<p class=\"MsoNormal\">However, although they can live in a wide range of conditions, one thing that they are unable to tolerate is even very small traces of metal. That&#8217;s immediately fatal to them. In their natural habitat, the frogs normally live in water the whole time, but in unfavorable conditions such as drought, they can burrow into the <span style=\"background-color: #f3db7b;\"><strong>(36) mud</strong></span> and survive there for up to a year until conditions improve.</p>\n<div class=\"MsoNormal\" style=\"text-align: center;\" align=\"center\">\n<hr align=\"center\" size=\"2\" width=\"100%\"></div>\n<p class=\"MsoNormal\"><strong>DIET</strong></p>\n<p class=\"MsoNormal\"><strong>Student:</strong> As far as their diet is concerned, they&#8217;re carnivorous. They eat other creatures they find in the water, and they&#8217;re scavengers, which means they&#8217;ll eat almost anything living or dead.</p>\n<p class=\"MsoNormal\">Because the water they live in is often quite dirty and visibility is limited, they can&#8217;t locate their food using their sense of sight. Instead, they use<span style=\"background-color: #f3db7b;\"> <strong>(37) smell</strong>,</span> and also the sensitive fingers on their front legs, and they also have what&#8217;s called a lateral line system on the sides of their bodies which is sensitive to vibrations in the water.</p>\n<p class=\"MsoNormal\">They use their front legs to get the food into their mouths, together with a type of <span style=\"background-color: #f3db7b;\"><strong>(38) pump</strong></span> arrangement that sucks the food into the mouth and down into their stomach. They don&#8217;t have any teeth, so everything just goes straight down.</p>\n<div class=\"MsoNormal\" style=\"text-align: center;\" align=\"center\">\n<hr align=\"center\" size=\"2\" width=\"100%\"></div>\n<p class=\"MsoNormal\"><strong>OTHER INFORMATION</strong></p>\n<p class=\"MsoNormal\"><strong>Student:</strong> Okay well, although Xenopus started off in Africa, they&#8217;re now quite widespread. One of the reasons for this is that a lot of people in the US like keeping them at home as a pet. They&#8217;re quite easy to look after and they can live for up to 20 years.</p>\n<p class=\"MsoNormal\">But in some states of the US, such as California and Virginia, they have escaped from captivity and are reproducing in the wild and threatening native species there. So they&#8217;ve been classified as a<span style=\"background-color: #f3db7b;\"> <strong>(39) pest</strong></span> in these areas.</p>\n<p class=\"MsoNormal\">But another very important use for the frogs is for research in laboratories. Because the females lay large numbers of eggs and the embryos are transparent, it&#8217;s easy to see how they are developing. Also, the slippery mucus that covers their skin acts as an<span style=\"background-color: #f3db7b;\"> <strong>(40) antibiotic</strong></span>, killing parasites and bacteria. And this is why we chose this frog for our research.</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('ef1aeb41-a4f6-4de0-af95-acbf69472eae', '77b2d76e-80d1-4bc3-8243-c8d4ed26476c', 'fillup', 'Questions 22 - 26', '<p>Complete the summary below.</p>
<p>Choose <strong>ONE WORD ONLY</strong> from the passage for each answer.</p>
<p>Write your answers in boxes 22-26 on your answer sheet.</p>
<p><span style="font-size: 12pt;"><strong>The changing population of Ashburton</strong></span></p>
<p>The Canterbury town of Ashburton is thriving thanks in large part to wealth created by the dairy farming industry, which has replaced the more traditional farming of sheep. However, other factors have also been involved such as the success of the {wine} industry in recent years. For a long time {tourism} has brought wealth to the region, and today the industry is so successful that traffic is becoming a problem. The social make-up of Canterbury has also been affected by a group known as {lifestylers} who have moved out from the city. Disagreements between these newcomers and established farmers sometimes occur when it comes to the use of {chemicals} on crops. This social diversity is increased when {migrants} are temporarily employed to work on farms.</p>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">22. wine — {the success of the wine industry in recent years}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn E):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“…land has been given over to a relatively new industry: the <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"83\">production of wine</strong>, which has taken off in Canterbury…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm “taken off” đồng nghĩa với “success” (trở nên thành công/phát triển mạnh). Ngoài ngành sữa, sự thành công của ngành sản xuất rượu vang (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"152\">wine</strong>) cũng đóng góp vào sự hưng thịnh của vùng.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">23. tourism — {For a long time tourism has brought wealth…}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn E):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“…Canterbury’s natural beauty has meant <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"62\">tourism has contributed to its prosperity for decades</strong>…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “For a long time” tương ứng với “for decades” (trong nhiều thập kỷ). Ngành du lịch (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"96\">tourism</strong>) đã mang lại sự thịnh vượng cho khu vực này từ rất lâu rồi.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">24. lifestylers — {…a group known as lifestylers who have moved out from the city}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn E):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">“…tended by the so-called <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"48\">lifestylers</strong> – people who once lived in urban areas but have come to enjoy the rural culture…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Những người từng sống ở thành thị (moved out from the city/lived in urban areas) và chuyển về nông thôn được gọi là các <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"132\">lifestylers</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">25. chemicals — {…disagreements… when it comes to the use of chemicals on crops}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn F):</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"20\">“…disputes arising over such issues as the intensification of farming and the heavy <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"106\">dependence on chemicals</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Disagreements” đồng nghĩa với “disputes” (tranh chấp/mâu thuẫn). Một trong những vấn đề gây tranh cãi giữa nông dân cũ và người mới đến là việc phụ thuộc quá nhiều vào hóa chất (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"191\">chemicals</strong>) trong trồng trọt.</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">26. migrants — {when migrants are temporarily employed to work on farms}</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn F):</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"20\">“…modern rural workforce… is increasingly reliant on <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"77\">migrants</strong> who are <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"94\">brought in at harvest time</strong>…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Temporarily employed” (được thuê tạm thời) tương ứng với việc được đưa đến vào mùa vụ (brought in at harvest time). Lực lượng lao động nhập cư (<strong data-path-to-node=\"13,1,0\" data-index-in-node=\"157\">migrants</strong>) làm cho thành phần xã hội ở đây trở nên đa dạng hơn.</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('d70820b9-3bb7-4017-93e2-2a42b145e13d', 'd6fb36fd-e352-4b62-a33c-6dc1a2ef2ce9', 'fillup', 'Questions 1- 10', '<p>Complete the notes below.</p>
<p>Write <strong>ONE WORD AND/OR A NUMBER</strong> for each answer.</p>
<p style="text-align: left;"><span style="font-size: 14pt;"><strong>Campsites</strong></span></p>
<p style="text-align: left;"><strong>Westerly Campsite</strong></p>
<ul>
<li>
<p>Campsite for families with children under 12</p>
</li>
<li>
<p>Location: near the {sea}</p>
</li>
<li>
<p>Special attraction for children: the {animals}</p>
</li>
<li>
<p>A local farmer sells {eggs}</p>
</li>
<li>
<p>Campers are allowed to have a {fire}</p>
</li>
<li>
<p>Cost per night: £ {15.75} for a family</p>
</li>
</ul>
<p><strong>Snetton Forest Campsite</strong></p>
<ul>
<li>
<p>Cost per night: £5 per adult (children free)</p>
</li>
<li>
<p>Recommended for people who like {fishing}</p>
</li>
<li>
<p>Campers can hire a {bike}</p>
</li>
<li>
<p>Activity organised for children: {football}</p>
</li>
</ul>
<p><strong>Trent Valley Campsite</strong></p>
<ul>
<li>
<p>Better month for families to go: {July}</p>
</li>
<li>
<p>Has an outdoor {pool}</p>
</li>
</ul>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">PART 1: CHOOSING A CAMPSITE</strong></h3>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Man:</strong> Shall we have a look at this information about campsites and then perhaps we can choose where to go on holiday?</p>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">Woman:</strong> Yes, my children are very excited about our two families going away together again this year. Shall we look at Westerly Campsite first?</p>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">Man:</strong> Yes, it says it''s most suitable for children under 12 years old, so that should be fine for us. Your daughter''s just 11, isn''t she?</p>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Woman:</strong> Hmm, yes, that''s right.</p>\n<p data-path-to-node=\"7\"><strong>Man:</strong>Now where is the Westerly Campsite? Is it the one next to a lake?</p>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">Woman:</strong> That''s another one. This one''s by the <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"8\" data-index-in-node=\"45\">(Q1) sea</strong></span>. Perfect!</p>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Man:</strong> Yes, that''s a good place to go in the summer when the weather''s hot.</p>\n<p data-path-to-node=\"9\"><strong>Woman: </strong>This brochure says that most children who go to Westerly Campsite love the <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"9\" data-index-in-node=\"149\">(Q2) animals</strong></span> they can see there. There''s a special area where they can go and feed them.</p>\n<p data-path-to-node=\"9\"><strong>Man:</strong>We might see some interesting birds too.</p>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">Woman:</strong> Hmm,</p>\n<p data-path-to-node=\"10\"><strong>Man:</strong> Oh and look! It says a farmer comes every day and you can buy <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"10\" data-index-in-node=\"74\">(Q3) eggs</strong></span> from him.</p>\n<p data-path-to-node=\"10\"><strong>Woman:</strong>Great for breakfast! I wonder if he sells other things like cheese, but it''s not mentioned.</p>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Man:</strong> I don''t know... I think they grow a lot of fruit in that area, so he might sell that.</p>\n<p data-path-to-node=\"11\"><strong>Woman:</strong>Hmm, another thing I like about this campsite is that they let you make a <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"11\" data-index-in-node=\"236\">(Q4) fire</strong></span>. We could cook some sausages and sing songs around it in the evenings. And perhaps it would be a good way to meet other families there too.</p>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">Man:</strong> Great! And it isn''t too expensive. £6 per adult per night, £3 per child. But wait, families of four can get it for <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"12\" data-index-in-node=\"122\">(Q5) £15.75</strong>  </span>a night. That works out even cheaper.</p>\n<hr data-path-to-node=\"13\">\n<h3 data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">OTHER CAMPSITES (Questions 6–10)</strong></h3>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">Woman:</strong> Let''s look at a couple of other campsites before we decide.</p>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">Man:</strong> Yes, let''s look at Snetterton Forest Campsite. It''s even cheaper: £5 per adult and children under 10 are free. They say it''s a very good place if you''re keen on <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"16\" data-index-in-node=\"168\">(Q6) fishing</strong></span>, and they even give you tips on where to go to have the best chance of catching some.</p>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">Woman:</strong> I prefer walking or hiking, and so do the rest of my family, so I''m not sure that will attract us that much.</p>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">Woman:</strong> Oh look, it says you can rent a <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"18\" data-index-in-node=\"39\">(Q7) bike</strong></span> to go around the forest. I''d do that, and your children would like that too, wouldn''t they?</p>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">Man:</strong> Absolutely! We could all go somewhere and have a picnic.</p>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">Man:</strong> Look, this is interesting too. At Snetterton, they get all the children together to play <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"20\" data-index-in-node=\"96\">(Q8) football</strong></span>. Oh, and your children would love that! And your husband Mike plays too, doesn''t he?</p>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">Woman:</strong> Yes, that sounds good. Well, Mike''s more into tennis actually, but I''m sure he''d be happy to be a referee if they needed one.</p>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">Woman:</strong> Here''s some information about Trent Valley Campsite. I''ve heard about this one. There''s a festival near the campsite in June and it''s really busy, so they say for families it''s better in <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"22\" data-index-in-node=\"194\">(Q9) July</strong></span> when it''s a bit quieter.</p>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">Man:</strong> Well, that would be just right for us because we have to go in the school summer holidays.</p>\n<p data-path-to-node=\"23\"><strong>Woman: </strong>Hmm</p>\n<p data-path-to-node=\"23\"><strong>Man:</strong> Let''s look at what it says about it. Oh look, it''s quite a long way to the nearest village—8 km. It''s too far to walk.</p>\n<p data-path-to-node=\"23\"><strong>Woman:</strong>But this one has got an outdoor <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"23\" data-index-in-node=\"252\">(Q10) pool</strong></span>, which we''d all love in the summer. And they have a little shop where you can buy basic things like bread and milk.</p>\n<p data-path-to-node=\"23\"><strong>Man:</strong>That''s really useful.And there''s lots to do there, I think on Saturday nights... </p>"}]', 0);
INSERT INTO public.questions VALUES ('e929fed4-38d6-4eb8-8a18-53e6859dd754', 'be5e39bd-aca6-4cbe-82ee-14c894f52c97', 'radio', 'Questions 27–31', '', '<p>Choose the correct answer.</p>', 'multiple_choice', '[{"correct": 2, "options": [{"option_text": "multimedia presentation of information in classrooms"}, {"option_text": "the study of monumental buildings throughout history"}, {"option_text": "the practice of designing architectural structures"}, {"option_text": "processes to add more art classes in schools"}], "question": "What education initiative does the American Institute of Architects currently promote?"}, {"correct": 1, "options": [{"option_text": "Technology-based courses are unavailable."}, {"option_text": "Students cannot always construct their designs."}, {"option_text": "The curriculum is too traditional."}, {"option_text": "Students lack motivation."}], "question": "In the third paragraph, what problem with teaching architecture on art courses does the writer note?"}, {"correct": 0, "options": [{"option_text": "personal connection to the end result"}, {"option_text": "participation in a cooperative project"}, {"option_text": "building of problem-solving skills"}, {"option_text": "conservation of a traditional building"}], "question": "What is the greatest benefit for students that the writer sees in a traditional architecture project?"}, {"correct": 1, "options": [{"option_text": "to explain why it is important that projects be small"}, {"option_text": "to outline the multiple skills involved in one project"}, {"option_text": "to discuss strategies for connecting content areas"}, {"option_text": "to propose suggestions for traditional earth projects"}], "question": "What is the purpose of the eighth paragraph?"}, {"correct": 3, "options": [{"option_text": "Earthen architecture is becoming a profitable business."}, {"option_text": "Earthen architecture is less feasible in some areas of the country."}, {"option_text": "Interest in earthen architecture varies from region to region."}, {"option_text": "People are attracted to earthen architecture for different reasons."}], "question": "What does the writer say about traditional building and the general population?"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">27. What education initiative does the American Institute of Architects currently promote? — {C. the practice of designing architectural structures}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn A):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“…the American Institute of Architects has fostered the idea that the <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"92\">process of architectural design</strong>, not just the appreciation of architecture, is a beneficial aspect of the art curriculum.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Viện Kiến trúc sư Hoa Kỳ thúc đẩy ý tưởng rằng <strong data-path-to-node=\"5,1,0\" data-index-in-node=\"59\">quy trình thiết kế kiến trúc</strong> (process of architectural design) mới là khía cạnh có lợi, thay vì chỉ là việc thưởng thức/ngắm nhìn các tòa nhà lịch sử như trước đây.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">28. In the third paragraph, what problem with teaching architecture on art courses does the writer note? — {B. Students cannot always construct their designs.}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn C):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“Although the technology and expertise required of modern architecture can <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"95\">prohibit students from actually realizing their designs</strong>…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Từ “prohibit” (ngăn cản/làm cho không thể) và “actually realizing their designs” (thực sự hiện thực hóa bản thiết kế) tương ứng với việc học sinh không phải lúc nào cũng có thể xây dựng được những gì mình thiết kế do yêu cầu về kỹ thuật và chuyên môn quá cao của kiến trúc hiện đại.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">29. What is the greatest benefit for students that the writer sees in a traditional architecture project? — {A. personal connection to the end result}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn E):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">“But <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"25\">most significantly</strong>, this type of project-based activity motivates students to <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"103\">invest intellectually and emotionally in the outcome</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm “most significantly” (quan trọng nhất) báo hiệu đây là lợi ích lớn nhất. Việc học sinh đầu tư cả trí tuệ và tình cảm (intellectually and emotionally) vào kết quả cuối cùng (outcome) chính là sự kết nối cá nhân (personal connection).</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">30. What is the purpose of the eighth paragraph? — {B. to outline the multiple skills involved in one project}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn H):</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"20\">“The same project may provide an opportunity to focus on the <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"81\">chemistry of soil</strong> or the <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"106\">structural dynamics</strong>… Design goals might guide students to involve <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"174\">traditional forms</strong>… or integrate <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"208\">math skills</strong> of measuring and estimating.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn 8 liệt kê một loạt các kỹ năng và kiến thức từ nhiều lĩnh vực khác nhau (hóa học, động lực học, nghệ thuật truyền thống, toán học) có thể được tích hợp chỉ trong một dự án nhỏ. Điều này khớp với việc “outline the multiple skills”.</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">31. What does the writer say about traditional building and the general population? — {D. People are attracted to earthen architecture for different reasons.}</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn I):</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"20\">“It is the <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"31\">connection to a cultural heritage</strong> that interests some; the <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"90\">quality of living</strong>… that attracts others; or for others, the <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"152\">sustainability</strong> of the process…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả liệt kê nhiều lý do khác nhau khiến mọi người quan tâm đến kiến trúc đất: có người vì di sản văn hóa, có người vì chất lượng không gian sống, có người vì tính bền vững (sustainability). Điều này khẳng định mỗi người bị thu hút bởi một lý do khác nhau.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('d7902176-c462-4253-a3cf-261570e6c739', '7167e7de-4bd1-4951-aefa-176570cc33db', 'radio', 'Questions 25 and 26', NULL, '<p>Choose the correct letter A, B, C or D.</p>
', 'multiple_choice_single', '[{"correct": 1, "options": [{"content": "A. the capture of the tiger."}, {"content": "B. an extensive follow up."}, {"content": "C. many other sightings."}, {"content": "D. the death of the tiger."}], "question": "Hans Naarding’s sighting of a Tasmanian tiger resulted in"}, {"correct": 3, "options": [{"content": "A. new animal species are still evolving."}, {"content": "B. animals can possess surprising physical characteristics."}, {"content": "C. species of sea animals can be saved from extinction."}, {"content": "D. opinions regarding extinction of animal species can be mistaken."}], "question": "The example of the coelacanth is used to show that"}]', 'null', 'null', 'null', '[{"content": "<p><strong>25. B</strong> (Đoạn 3, &#8220;Government and private search parties <strong>combed the region, but no further sightings were made</strong>.&#8221;) → Lần nhìn thấy của Hans Naarding đã dẫn đến việc chính phủ và các bên tư nhân tổ chức tìm kiếm rộng rãi (<strong>an extensive follow up</strong>). → Đáp án là <strong>B</strong>.</p>\n<p><strong>26. D</strong> (Đoạn 4, &#8220;The strange fish known as coelacanth&#8230; <strong>was thought to have died out with the dinosaurs</strong>&#8230; until a specimen was dragged to the surface in a shark net&#8230; in 1938.&#8221;) → Ví dụ về Coelacanth (một loài cá được cho là đã tuyệt chủng) được dùng để cho thấy rằng ý kiến về sự tuyệt chủng của một loài có thể bị sai lầm (<strong>opinions regarding extinction of animal species can be mistaken</strong>). → Đáp án là <strong>D</strong>.</p>\n"}]', 2);
INSERT INTO public.questions VALUES ('45a93f42-ae24-431a-ab6a-64b1060e47fb', '3b38da13-ebed-422e-a9c5-fa824dc893b0', 'fillup', 'Questions 10–13', '<p>Complete the notes below.</p>
<p>Write <strong>ONE WORD ONLY</strong> from the passage for each answer.</p>
<h3 style="text-align: center;"><strong>Amurca</strong></h3>
<p>In ancient times, this waste liquid was usually thrown away, which led to {pollution}</p>
<p>However, Romans had practical applications for America:</p>
<p>• when dried, created hard surface, so used on {floors} of certain buildings</p>
<p>• used when making {leather}</p>
<p>• into goods to wear fed to livestock</p>
<p>• used on farms as a {pesticide} to stop insects or animals damaging crops</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p><strong>10. In ancient times, this waste liquid was usually thrown away, which led to pollution.</strong></p>\n<ul>\n<li><strong>Đáp án:</strong> <strong>pollution</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn F) “In many ancient civilisations it was often simply discarded, causing serious <strong>pollution</strong> because of its acidity and high salt content.”</li>\n</ul>\n<p><strong>11. when dried, created hard surface, so used on floors of certain buildings</strong></p>\n<ul>\n<li><strong>Đáp án:</strong> <strong>floors</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn F) “When spread on surfaces, amurca forms a hard finish and therefore it was often applied to the <strong>floors</strong> of grain storage buildings…”</li>\n</ul>\n<p><strong>12. used when making leather into goods to wear</strong></p>\n<ul>\n<li><strong>Đáp án:</strong> <strong>leather</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn F) “When boiled down amurca was applied to <strong>leather</strong> to soften it so that it was easier to shape into articles of clothing and shoes.”</li>\n</ul>\n<p><strong>13. used on farms as a pesticide to stop insects or animals damaging crops</strong></p>\n<ul>\n<li><strong>Đáp án:</strong> <strong>pesticide</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn F) “According to ancient texts, amurca was also utilised in moderate amounts by farmers as a fertiliser or as a <strong>pesticide</strong> helping them to protect their crops from insects and even small rodents.”</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('d50f2c73-c1b1-4381-9a3a-a4d3b14a9414', '422f4a24-a1b5-4b44-9d2e-0511f4919fbf', 'matrix', 'Questions 14–20', NULL, '<p>Reading Passage 2 has eight paragraphs, <strong>A-H.</strong></p>
<p>Which paragraph contains the following information?</p>
', 'classification', 'null', 'null', 'null', '{"layoutType": "simple", "legendTitle": null, "matrixItems": [{"itemText": "A description of how a test showed some evidence to be fake", "correctCategoryLetter": "E"}, {"itemText": "Reasons why scientists may be unwilling to admit that they play", "correctCategoryLetter": "A"}, {"itemText": "The result of a trick going wrong", "correctCategoryLetter": "F"}, {"itemText": "The similarity between a skill used in play and one used in science", "correctCategoryLetter": "B"}, {"itemText": "How a group of scientists stopped a colleague misusing their results", "correctCategoryLetter": "G"}, {"itemText": "Some examples of the playful nature of scientific language", "correctCategoryLetter": "D"}, {"itemText": "An example of an everyday object put to a scientific use", "correctCategoryLetter": "C"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}, {"categoryText": "H", "categoryLetter": "H"}]}', '[{"content": "<p><strong>14. A description of how a test showed some evidence to be fake</strong></p>\n<ul>\n<li><strong>Đáp án: E</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn E) “But in 1977, Helen Michel and Frank Asaro… showed that the <strong>copper and zinc used in the plate were of a higher quality than would have been available in the 1500s</strong>. They concluded that Drake’s plate was most likely crafted much closer to the time when it was first brought to light.”</li>\n<li><strong>Giải thích:</strong> Việc phân tích chất liệu (đồng và kẽm) đã chứng minh tấm bảng là giả mạo (fake).</li>\n</ul>\n<p><strong>15. Reasons why scientists may be unwilling to admit that they play</strong></p>\n<ul>\n<li><strong>Đáp án: A</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn A) “…perhaps because scientists take it for granted, or because <strong>they are a little self-conscious about it and therefore try to hide it</strong>.”</li>\n<li><strong>Giải thích:</strong> Việc cảm thấy bối rối/ngượng ngùng (self-conscious) là lý do họ che giấu/ngại thừa nhận.</li>\n</ul>\n<p><strong>16. The result of a trick going wrong</strong></p>\n<ul>\n<li><strong>Đáp án: F</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn F) “Some of Bolton’s friends decided to play a joke on him, but <strong>things misfired</strong> after Bolton went public and announced that the relic was authentic <strong>before he could be told about the joke</strong>.”</li>\n<li><strong>Giải thích:</strong> Trò đùa bị phản tác dụng (misfired) khi nạn nhân công bố thông tin trước khi biết đó là trò đùa.</li>\n</ul>\n<p><strong>17. The similarity between a skill used in play and one used in science</strong></p>\n<ul>\n<li><strong>Đáp án: B</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn B) “Guessing the solution of a scientific problem has <strong>many similarities to completing a jigsaw puzzle</strong>… The best scientists are those who make the best guesses.”</li>\n<li><strong>Giải thích:</strong> Kỹ năng đoán (guessing) trong giải đố (play) giống với việc giải quyết vấn đề khoa học.</li>\n</ul>\n<p><strong>18. How a group of scientists stopped a colleague misusing their results</strong></p>\n<ul>\n<li><strong>Đáp án: G</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn G) “Lewis decided to set a trap for the co-worker… [but] <strong>this stopped him temporarily from taking our data and interpreting it before making sure that it was right</strong>.”</li>\n<li><strong>Giải thích:</strong> Họ dùng một dữ liệu giả (fake NMR spectrum) để bẫy đồng nghiệp và ngăn anh ta công bố dữ liệu sai.</li>\n</ul>\n<p><strong>19. Some examples of the playful nature of scientific language</strong></p>\n<ul>\n<li><strong>Đáp án: D</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn D) “Take, for example, the <strong>funny names</strong> that scientists have given to various chemical substances: <strong>tristane, windowpane, penguinone or megaphone</strong>.”</li>\n<li><strong>Giải thích:</strong> Các tên hài hước của hóa chất là ví dụ về sự vui đùa trong ngôn ngữ khoa học.</li>\n</ul>\n<p><strong>20. An example of an everyday object put to a scientific use</strong></p>\n<ul>\n<li><strong>Đáp án: C</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn C) “The apparatus put together by Robert Millikan and Harvey Fletcher to measure the charge of the electron, which involved a <strong>perfume atomiser bought at a local pharmacy</strong>, is a classic example of such inspired tinkering.”</li>\n<li><strong>Giải thích:</strong> Bình xịt nước hoa (perfume atomiser) là một vật dụng hàng ngày được dùng trong thí nghiệm.</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('2290b373-ecc8-480b-a971-20ddb2305c19', '422f4a24-a1b5-4b44-9d2e-0511f4919fbf', 'checkbox', 'Questions 21–22', '<p>Choose TWO correct answers.</p>
<p>21-22 Which TWO of the following reasons are given as possible explanations of scientists play behaviour?</p>
', '<p>Choose <strong>TWO </strong>correct answers.</p>
<p><strong>21-22 Which TWO of the following reasons are given as possible explanations of scientists play behaviour?</strong></p>
', 'multiple_choice_many', 'null', '[{"option": "A Play may provide relief from their work.", "correct": true}, {"option": "B Scientists sometimes spend time as teachers.", "correct": false}, {"option": "C The age of scientists predisposes them to play.", "correct": true}, {"option": "D Scientists get ideas from children''s questions", "correct": false}, {"option": "E Scientists are secretive about their work.", "correct": false}]', 'null', 'null', '[{"content": "<p>Đáp án: A và C<br />\nDẫn chứng: (Đoạn H) “The psychologist’s answer might be that scientists tend to play because science presents them with too much seriousness [A – relief from their work]… Another possibility might be that scientists like to play because they tend to be very young [C – age].”</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('8be17d4c-6fba-4e9f-876c-6a33cb5127e9', '422f4a24-a1b5-4b44-9d2e-0511f4919fbf', 'fillup', 'Questions 23–26', '<p>Complete the summary below.</p>
<p>Write <strong>NO MORE THAN THREE WORDS</strong> from the passage for each answer.</p>
<h3 style="text-align: center;"><strong>Scientists play tricks</strong></h3>
<p>The passage gives two examples of tricks arising from the playfulness of scientists. Researchers at Caltech found that a colleague had been stealing their {data} and used a hoax involving a fake NMR spectrum to trap the offender. Another story concerns a plate which a famous {English navigator} is said to have left behind on a visit to California.</p>
<p>The {copper and zinc} that the plate was made of later revealed that it was a fake, a hoax carried out by friends of the director of the {bancroft library}</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p><strong>23. Researchers at Caltech found that a colleague had been stealing their data…</strong></p>\n<ul>\n<li><strong>Đáp án:</strong> <strong>data</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn G) “Another co-worker had the habit of going through their <strong>data</strong> and rushing to Gray with his interpretation.”</li>\n</ul>\n<p><strong>24. Another story concerns a plate which a famous English navigator is said to have left behind on a visit to California.</strong></p>\n<ul>\n<li><strong>Đáp án:</strong> <strong>English navigator</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn E) “…the ‘Plate of Brasse’, which stated England’s claim to California and was supposedly left by the <strong>English navigator</strong> Sir Francis Drake during his visit in 1579.”</li>\n</ul>\n<p><strong>25. The copper &amp; zinc that the plate was made of later revealed that it was a fake…</strong></p>\n<ul>\n<li><strong>Đáp án:</strong> <strong>copper &amp; zinc</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn E) “…Helen Michel and Frank Asaro… showed that the <strong>copper and zinc</strong> used in the plate were of a higher quality than would have been available in the 1500s.”</li>\n</ul>\n<p><strong>26. …a hoax carried out by friends of the director of the Bancroft Library.</strong></p>\n<ul>\n<li><strong>Đáp án:</strong> <strong>Bancroft Library</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn F) “…a group of friends of Herbert E Bolton, who directed the <strong>Bancroft Library</strong> at the University’s Berkeley campus.”</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('fb5efe17-86a7-4823-8656-b902d1cbf49c', '6c0a9a17-d8b7-4e0d-b5c1-f1a2893290d7', 'matching', 'Questions 16- 20', '', '<p>Which job did Stephen do on his placement in each of the following countries?</p>
<p>Choose <strong>FIVE </strong>answers from the box and write the correct letter; <strong>A</strong>-<strong>G</strong>, next to questions 16-20.</p>', 'summary_completion', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p><span style=\"font-size: 12pt;\"><strong>Countries</strong></span></p>\n<p> </p>\n<p>Portugal {Editor}</p>\n<p> </p>\n<p>Australia {cook}</p>\n<p> </p>\n<p>South Korea {tour guide}</p>\n<p> </p>\n<p>USA {gardener}</p>\n<p> </p>\n<p>Italy {construction worker}</p>", "answerOptions": [{"optionText": "cook"}, {"optionText": "gardener"}, {"optionText": "construction worker"}, {"optionText": "tour guide"}, {"optionText": "farm labourer"}, {"optionText": "Editor"}, {"optionText": "swimming pool cleaner"}], "matchingItems": []}', 'null', 'null', 1);
INSERT INTO public.questions VALUES ('3ba9f664-5e09-46b6-847f-6b6c50ace7fe', '2317924d-3cb5-43e1-8389-9e541963795c', 'fillup', 'Questions 31–40', '<p>Write <strong>ONE WORD ONLY</strong> for each answer.</p>
<p><strong><span style="font-size: 14pt;">The world’s oldest mechanical computer: the Antikythera mechanism</span></strong></p>
<p><strong>Discovery</strong></p>
<p>It was part of a ship’s {cargo} , found in the sea near Antikythera, in Greece.</p>
<p>It was wrongly thought to be a piece of {rock}.</p>
<p>It was later found to be a mechanism that had broken into pieces.</p>
<p><strong>Equipment used for analysis of the mechanism</strong></p>
<p>“Dome” – produces photographs which make the {inscriptions} clearer</p>
<p>“BladeRunner” – produces X-prays</p>
<p>– originally used to identify {cracks} in engines</p>
<p><strong>Description</strong></p>
<p>The mechanism consisted of:</p>
<p>– 30 or more gear wheels made of {metal}</p>
<p>– models of the sun, moon and planets</p>
<p>– a framework made of {wood}</p>
<p><strong>How the mechanism was used</strong></p>
<p>The operator turned a {handle} to move the gear wheels.</p>
<p>The sun, moon and planets could be moved into their correct positions for any date.</p>
<p>Most surprisingly, the mechanism could calculate when an {eclipse} would occur.</p>
<p>It may have been used as a {calendar} when planning festivals.</p>
<p><strong>Later use of similar technology</strong></p>
<p>13th – 14th centuries: used for making {clocks} in Western Europe.</p>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p><strong>Lecturer:</strong> Good morning everyone. Today, I’m going to talk about what is sometimes described as the world’s oldest mechanical computer—the Antikythera mechanism.</p>\n<p>This device was able to calculate where the sun, moon, and planets would be in the sky on any date in the past or future. It has transformed our understanding both of the world of ancient Greece and of the history of science.</p>\n<h3>Discovery and Initial Analysis</h3>\n<p>The mechanism was discovered in 1900 at the bottom of the sea off the Greek island of Antikythera, hence the name by which it’s now known. It was in the<span style=\"background-color: #f1c40f;\"> <strong>(31) cargo</strong></span> of a ship that sank about 2,100 years ago. Divers brought various items to the surface, and they were taken to a museum for examination.</p>\n<p>One item was assumed to be a lump of<span style=\"background-color: #f1c40f;\"> <strong>(32) rock</strong></span>. However, a few months later, the object started splitting, and a museum curator realized that it was actually something man-made, covered with shells and other objects from the sea. Further investigation revealed that it was in fact some sort of mechanism, and they decided to call it the Antikythera mechanism.</p>\n<p>Although it was badly damaged, it had survived in three main parts and around 80 smaller fragments. The Antikythera mechanism has been studied a great deal since its discovery, and particularly in recent years, when highly sophisticated equipment has been available to analyse it.</p>\n<h3>Equipment Used for Analysis</h3>\n<p>One machine called a Dome can surround a sample and take photographs with the light coming from slightly different angles. This has made far more of the <span style=\"background-color: #f1c40f;\"><strong>(33) inscriptions</strong></span> on the mechanism legible, even though they’re faded and worn.</p>\n<p>Another state-of-the-art machine, the BladeRunner, has been used to take X-rays, which show parts of the mechanism that would otherwise be invisible. Despite weighing nearly 8 tons, it was transported from its place of manufacture to Greece, as the Antikythera mechanism is too fragile to be moved from there. The BladeRunner was originally designed to examine engines for <span style=\"background-color: #f1c40f;\"><strong>(34) cracks</strong></span>, and it can work at an accuracy of less than a tenth of a millimeter.</p>\n<h3>Description and Structure</h3>\n<p>It seems the device was originally about 33 cm high, 17 cm wide, and 9 cm thick. It consisted of at least 30<strong> <span style=\"background-color: #f4d24a;\">(35) metal </span></strong>gear wheels —that is, wheels which interlocked with each other. The surfaces of the gear wheels were inscribed with the names of the months, explanations of how the different parts of the device were to be operated, and other information.</p>\n<p>These gear wheels in turn operated small, movable models of the sun, moon, and the five planets that were known to the ancient Greeks. The mechanism is thought to have been mounted in a frame, for which <span style=\"background-color: #f4d24a;\"><strong>(36) wood</strong></span> was used.</p>\n<h3>Function and Significance</h3>\n<p>So what was the Antikythera mechanism used for? It clearly had an astronomical function. The person using the device simply rotated a <span style=\"background-color: #f1c40f;\"><strong>(37) handle</strong></span> to operate the gear wheels. These engaged with each other to move the sun, moon, and planets around the earth, to show how they would appear on whatever particular date the operator was interested in, which could be years into the future.</p>\n<p>Bearing in mind that the ancient Greeks believed the sun and planets all revolved around the earth, their movements are shown with remarkable accuracy. Perhaps most astonishing of all, the mechanism also showed when an<span style=\"background-color: #f1c40f;\"> <strong>(38) eclipse</strong></span> was going to take place. This was very important in the ancient world, and being able to predict this accurately would have given the user great power. The mechanism probably also helped in planning the timing of festivals, both agricultural and religious, by acting as a kind of <span style=\"background-color: #f1c40f;\"><strong>(39) calendar</strong></span> of events.</p>\n<h3>Later Technology</h3>\n<p>Surprisingly, to the best of our knowledge, no device equaled the complexity of the Antikythera mechanism for at least 1,000 years afterwards. The ideas seem to have survived in some form, however, particularly in the Byzantine Empire of the eastern Mediterranean. Around the 13th or 14th century, knowledge of the technology seems to have reached Western Europe, and a large number of <span style=\"background-color: #f1c40f;\"><strong>(40) clocks</strong></span> were made, providing astronomical information as well as showing the time of day. It’s hard to believe that nothing reached the sophistication of the anticithara mechanism for 1,000 years, yet that might well be the case, and that has implications for our understanding of how scientific knowledge progresses.</p>"}]', 0);
INSERT INTO public.questions VALUES ('1e3e6c22-2990-4e79-8091-a296fe217074', 'bbf97bc1-c25f-49c7-a11f-aac66ec0f6dd', 'matrix', 'Questions 27–31', NULL, '<p>Reading Passage 3 has six sections, A-F.</p>
<p>Which section contains the following information?</p>
<p><em><strong>NB </strong>You may use any letter more than once</em></p>
', 'classification', 'null', 'null', 'null', '{"layoutType": "simple", "legendTitle": null, "matrixItems": [{"itemText": "Detailed criticism of the methodology of a project", "correctCategoryLetter": "D"}, {"itemText": "A comparison of the data from class-reduction projects", "correctCategoryLetter": "F"}, {"itemText": "The level of public interest in the issues of class-size reduction", "correctCategoryLetter": "A"}, {"itemText": "Details of action taken to protect the validity of a project", "correctCategoryLetter": "C"}, {"itemText": "Reasons why class composition changed during a project", "correctCategoryLetter": "D"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}]}', '[{"content": "<p><strong>27. detailed criticism of the methodology of a project</strong></p>\n<ul>\n<li><strong>Đáp án: D</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn D) Eric Hanushek <strong>“criticises some of STAR’s key conclusions”</strong> và nêu chi tiết các lỗi trong phương pháp luận (methodology): <strong>“does not prove that gains persist long after students return to regular classes”</strong>, <strong>“failed to ensure good randomisation of teacher and student assignments”</strong>.</li>\n</ul>\n<p><strong>28. a comparison of the data from class-reduction projects</strong></p>\n<ul>\n<li><strong>Đáp án: F</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn F) “Analysts have studied the results of first-grade students in these schools and similar first-grade students elsewhere and found the results <strong>accord with those from STAR</strong>.”</li>\n<li><strong>Giải thích:</strong> Đoạn F so sánh kết quả của dự án SAGE với dự án STAR.</li>\n</ul>\n<p><strong>29. the level of public interest in the issues of class-size reduction</strong></p>\n<ul>\n<li><strong>Đáp án: A</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn A) “With its uncomplicated appeal, class-size reduction in the U.S. has lately gone from being a subject of primary academic interest to a <strong>policy juggernaut</strong> with over twenty states aiming at decreasing class sizes.”</li>\n<li><strong>Giải thích:</strong> Việc trở thành một “policy juggernaut” và được hơn 20 tiểu bang theo đuổi cho thấy mức độ quan tâm và ủng hộ cao của công chúng và chính phủ.</li>\n</ul>\n<p><strong>30. details of action taken to protect the validity of a project</strong></p>\n<ul>\n<li><strong>Đáp án: C</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn C) “<strong>To ensure that teaching quality did not differ, teachers were randomly assigned to small and regular-size classrooms.</strong>“</li>\n<li><strong>Giải thích:</strong> Việc sắp xếp giáo viên ngẫu nhiên là hành động nhằm bảo vệ tính hợp lệ (validity) của nghiên cứu.</li>\n</ul>\n<p><strong>31. reasons why class composition changed during a project</strong></p>\n<ul>\n<li><strong>Đáp án: D</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn D) “…too many children moved from regular to small classes, <strong>probably because school personnel caved in to parent demands</strong>.”</li>\n<li><strong>Giải thích:</strong> Nhu cầu từ phụ huynh khiến thành phần lớp học bị thay đổi trong dự án STAR.</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('34f6f812-16c2-480e-96bd-3a7946f99f8a', 'bbf97bc1-c25f-49c7-a11f-aac66ec0f6dd', 'matrix', 'Questions 32–40', NULL, '<p>Classify the following statements as referring to</p>
', 'other', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": "Classification", "matrixItems": [{"itemText": "The student composition of each class was left to chance", "correctCategoryLetter": "A"}, {"itemText": "A long-term improvement in performance was claimed.", "correctCategoryLetter": "A"}, {"itemText": "Similar results were obtained for all social groups", "correctCategoryLetter": "B"}, {"itemText": "The project was a preliminary to a more comprehensive study.", "correctCategoryLetter": "C"}, {"itemText": "Several different class types were involved in the project.", "correctCategoryLetter": "A"}, {"itemText": "A special group of schools was selected to take part.", "correctCategoryLetter": "C"}, {"itemText": "Classroom assistants were used as part of the project.", "correctCategoryLetter": "A"}, {"itemText": "The project was responsible for aggravating existing problems", "correctCategoryLetter": "B"}, {"itemText": "Certain groups of pupils within the sample were identified as having benefited", "correctCategoryLetter": "A"}], "matrixCategories": [{"categoryText": "Project STAR", "categoryLetter": "A"}, {"categoryText": "The California Project", "categoryLetter": "B"}, {"categoryText": "SAGE", "categoryLetter": "C"}]}', '[{"content": "<p><strong>32. The student composition of each class was left to chance.</strong></p>\n<ul>\n<li><strong>Đáp án: A</strong> (Project STAR)</li>\n<li><strong>Dẫn chứng:</strong> (Đoạn C) “Students entering kindergarten were <strong>randomly assigned</strong> to one of three kinds of classes…”</li>\n<li><strong>Giải thích:</strong> Học sinh được phân công ngẫu nhiên (randomly assigned) vào các loại lớp.</li>\n</ul>\n<p><strong>33. A long-term improvement in performance was claimed.</strong></p>\n<ul>\n<li><strong>Đáp án: A</strong> (Project STAR)</li>\n<li><strong>Dẫn chứng:</strong> (Đoạn D) “…this advantage <strong>persisted even after students returned to larger classes</strong>.”</li>\n<li><strong>Giải thích:</strong> Lợi thế học tập vẫn duy trì ngay cả khi học sinh chuyển về lớp lớn hơn (long-term improvement).</li>\n</ul>\n<p><strong>34. Similar results were obtained for all social groups.</strong></p>\n<ul>\n<li><strong>Đáp án: B</strong> (The California Project)</li>\n<li><strong>Dẫn chứng:</strong> (Đoạn E) “Researchers found a statistically significant achievement advantage… What is more, <strong>the effect did not vary for students of different backgrounds</strong>.”</li>\n<li><strong>Giải thích:</strong> Kết quả không khác biệt giữa các học sinh có hoàn cảnh khác nhau.</li>\n</ul>\n<p><strong>35. The project was a preliminary to a more comprehensive study.</strong></p>\n<ul>\n<li><strong>Đáp án: C</strong> (SAGE)</li>\n<li><strong>Dẫn chứng:</strong> (Đoạn F) “Wisconsin’s SAGE was a five-year <strong>pilot study to do some of the groundwork for a major project</strong>.”</li>\n<li><strong>Giải thích:</strong> SAGE là một nghiên cứu thử nghiệm (pilot study) chuẩn bị cho một dự án lớn hơn.</li>\n</ul>\n<p><strong>36. Several different class types were involved in the project.</strong></p>\n<ul>\n<li><strong>Đáp án: A</strong> (Project STAR)</li>\n<li><strong>Dẫn chứng:</strong> (Đoạn C) “…randomly assigned to <strong>one of three kinds of classes</strong>: a small class… a regular-size class… or a regular-size class with both a teacher and a full-time teacher’s aide.”</li>\n</ul>\n<p><strong>37. A special group of schools was selected to take part.</strong></p>\n<ul>\n<li><strong>Đáp án: C</strong> (SAGE)</li>\n<li><strong>Dẫn chứng:</strong> (Đoạn F) “…it was noteworthy for <strong>targeting schools at which 30% of the students were below poverty level</strong>…”</li>\n<li><strong>Giải thích:</strong> SAGE chọn các trường có tỷ lệ học sinh nghèo cao.</li>\n</ul>\n<p><strong>38. Classroom assistants were used as part of the project.</strong></p>\n<ul>\n<li><strong>Đáp án: A</strong> (Project STAR)</li>\n<li><strong>Dẫn chứng:</strong> (Đoạn C) “…a regular-size class with both a teacher and a <strong>full-time teacher’s aide</strong>.”</li>\n</ul>\n<p><strong>39. The project was responsible for aggravating existing problems.</strong></p>\n<ul>\n<li><strong>Đáp án: B</strong> (The California Project)</li>\n<li><strong>Dẫn chứng:</strong> (Đoạn E) “This is <strong>exacerbating the disparity</strong> in resources available to rich and poor schools in California…”</li>\n<li><strong>Giải thích:</strong> Dự án California làm trầm trọng thêm (aggravating) sự chênh lệch (disparity) giữa trường giàu và trường nghèo.</li>\n</ul>\n<p><strong>40. Certain groups of pupils within the sample were identified as having benefited.</strong></p>\n<ul>\n<li><strong>Đáp án: A</strong> (Project STAR)</li>\n<li><strong>Dẫn chứng:</strong> (Đoạn D) “They also found that the effect was <strong>stronger for black and Hispanic minority groups</strong>…”</li>\n<li><strong>Giải thích:</strong> Các nhóm thiểu số (black and Hispanic) được xác định là hưởng lợi nhiều hơn.</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('eafef108-89cc-4c3e-8957-e94f877c2836', 'be5e39bd-aca6-4cbe-82ee-14c894f52c97', 'matching', 'Questions 32–36', '', '<p>Complete the summary using the list of words, <strong>A-H</strong>, below.</p>', 'summary_completion', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p class=\"MsoNormal\" style=\"text-align: center;\" align=\"center\"><span style=\"font-size: 14pt;\"><strong>The Zuni earthen architecture project</strong></span></p>\n<p class=\"MsoNormal\">The students in Zuni chose to renovate an old building which was being used for {D storage}. They came to an agreement that the building was worthy of rehabilitation based on its functional {C design}. At the beginning of the project, students were given the task to discover the history of the building through interviews with local residents. Through the course of the project, they learned where to locate {F resources} for the project. They also worked closely with a number of {A experts} on each step of the project. During the project, students were also given {G training} to build useful skills.</p>", "answerOptions": [{"optionText": "A experts"}, {"optionText": "B location"}, {"optionText": "C design"}, {"optionText": "D storage"}, {"optionText": "E students"}, {"optionText": "F resources"}, {"optionText": "G training"}, {"optionText": "H businesses"}], "matchingItems": []}', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">32. D (storage) — {being used for storage}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn F):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“Now it served as a place where <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"52\">old furniture could be kept</strong>… now it was full of <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"102\">broken desks</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Một nơi dùng để cất giữ đồ đạc cũ (old furniture) và bàn ghế hỏng (broken desks) chính là mục đích lưu trữ (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"120\">storage</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">33. C (design) — {based on its functional design}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn G):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“The building’s <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"36\">design kept it relatively warm in the winter</strong>… and it <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"91\">stayed cool in the summer</strong>… Because of this, my students agreed it was <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"163\">worth preserving</strong>…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Các bạn học sinh đồng ý rằng tòa nhà xứng đáng được bảo tồn dựa trên các đặc điểm chức năng như giữ ấm mùa đông và làm mát mùa hè. Những yếu tố này đều thuộc về thiết kế (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"183\">design</strong>) của tòa nhà.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">34. F (resources) — {learn where to locate resources}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn G):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">“She showed us where to find <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"49\">local supplies of sand and clay soil</strong> for the plaster mix.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Local supplies” (nguồn cung ứng địa phương) như cát và đất sét chính là các nguồn lực/nguyên liệu (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"112\">resources</strong>) cần thiết cho dự án.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">35. A (experts) — {worked closely with a number of experts}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn G):</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"20\">“<strong data-path-to-node=\"11,0,0\" data-index-in-node=\"21\">Preservationist</strong> Shalie Gasper arrived… To teach the traditional skills, Gasper and <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"106\">other local specialists</strong> joined us.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Những người như nhà bảo tồn (preservationist) hay chuyên gia địa phương (specialists) được gọi chung là các chuyên gia (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"132\">experts</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">36. G (training) — {students were also given training to build useful skills}</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn G):</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"20\">“They gave my class three full mornings of <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"63\">intensive workshops</strong> on history and preservation as well as mud-plastering <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"137\">technique</strong>…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc tổ chức các buổi hội thảo chuyên sâu (intensive workshops) để dạy về kỹ thuật chính là hình thức đào tạo (<strong data-path-to-node=\"13,1,0\" data-index-in-node=\"123\">training</strong>) để xây dựng kỹ năng cho học sinh.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('e2b17769-45b0-4a54-b9b9-39eccad53a94', 'bda17de2-e4f0-4f95-b624-5b17e82226a7', 'fillup', 'Questions 1–5', '<p class="MsoNormal" style="margin-bottom: 0in; line-height: 150%; background: white;"><span lang="EN" style="font-size: 11.0pt; line-height: 150%; font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: black;">Complete the notes below.</span></p>
<p class="MsoNormal" style="margin-bottom: 0in; line-height: 150%; background: white;"><span lang="EN" style="font-size: 11.0pt; line-height: 150%; font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: black;">Write <strong>ONE WORD ONLY</strong> from the passage for each answer.</span></p>
<p class="MsoNormal" style="margin-bottom: 0in; text-align: center; line-height: 150%; background: white;" align="center"><strong><span lang="EN" style="font-size: 16.0pt; mso-bidi-font-size: 11.0pt; line-height: 150%; font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: black;">Carnivorous Plants</span></strong></p>
<p class="MsoNormal" style="margin-bottom: 0in; line-height: 150%; background: white;"><span lang="EN" style="font-size: 11.0pt; line-height: 150%; font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: black;">Darwin’s experiments:</span></p>
<p class="MsoNormal" style="margin-bottom: 0in; line-height: 150%; background: white;"><span lang="EN" style="font-size: 11.0pt; line-height: 150%; font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: black;">Drosera</span></p>
<ul style="margin-top: 0in;" type="circle">
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 150%; mso-list: l3 level1 lfo1; background: white;"><span lang="EN" style="font-size: 11.0pt; line-height: 150%; font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: black;">He put insects and small amounts of meat onto leaves and observed what happened.</span></li>
</ul>
<ul style="margin-top: 0in;" type="circle">
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 150%; mso-list: l7 level1 lfo6; background: white;"><span lang="EN" style="font-size: 11.0pt; line-height: 150%; font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: black;">He was amazed that one human hair triggered a response.</span></li>
</ul>
<ul style="margin-top: 0in;" type="circle">
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 150%; mso-list: l9 level1 lfo7; background: white;"><span lang="EN" style="font-size: 11.0pt; line-height: 150%; font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: black;">He understood why the plant did not respond to {raindrops}</span></li>
</ul>
<p class="MsoNormal" style="margin-bottom: 0in; line-height: 150%; background: white;"><span lang="EN" style="font-size: 11.0pt; line-height: 150%; font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: black;">Venus Flytrap</span></p>
<ul style="margin-top: 0in;" type="circle">
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 150%; mso-list: l4 level1 lfo8; background: white;"><span lang="EN" style="font-size: 11.0pt; line-height: 150%; font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: black;">He demonstrated how leaves close and then, for a short period, act like a {stomach}</span></li>
</ul>
<ul style="margin-top: 0in;" type="circle">
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 150%; mso-list: l10 level1 lfo9; background: white;"><span lang="EN" style="font-size: 11.0pt; line-height: 150%; font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: black;">He noted the structure of leaves ensures small insects are released.</span></li>
</ul>
<p class="MsoNormal" style="margin-bottom: 0in; line-height: 150%; background: white;"><span lang="EN" style="font-size: 11.0pt; line-height: 150%; font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: black;">Biology today:</span></p>
<p class="MsoNormal" style="margin-bottom: 0in; line-height: 150%; background: white;"><span lang="EN" style="font-size: 11.0pt; line-height: 150%; font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: black;">Venus Flytrap</span></p>
<ul style="margin-top: 0in;" type="circle">
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 150%; mso-list: l12 level1 lfo10; background: white;"><span lang="EN" style="font-size: 11.0pt; line-height: 150%; font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: black;">If insects come into contact with leaf hairs, their movement produces an electric charge.</span></li>
</ul>
<ul style="margin-top: 0in;" type="circle">
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 150%; mso-list: l5 level1 lfo11; background: white;"><span lang="EN" style="font-size: 11.0pt; line-height: 150%; font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: black;">The charge enters fluid-filled tunnels, causing {pores}</span><span lang="EN" style="font-size: 11.0pt; line-height: 150%; font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman'';">.in the cell walls to open.</span></li>
</ul>
<ul style="margin-top: 0in;" type="circle">
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 150%; mso-list: l1 level1 lfo12; background: white;"><span lang="EN" style="font-size: 11.0pt; line-height: 150%; font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: black;">Water moves between cells and then the leaf changes from convex to concave, trapping the insect inside.</span></li>
</ul>
<p class="MsoNormal" style="margin-bottom: 0in; line-height: 150%; background: white;"><span lang="EN" style="font-size: 11.0pt; line-height: 150%; font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: black;">Bladderwort</span></p>
<ul style="margin-top: 0in;" type="circle">
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 150%; mso-list: l2 level1 lfo13; background: white;"><span lang="EN" style="font-size: 11.0pt; line-height: 150%; font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: black;">Hairs bend when insects swim past, resulting in opening of a flap.</span></li>
</ul>
<ul style="margin-top: 0in;" type="circle">
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 150%; mso-list: l0 level1 lfo2; background: white;"><span lang="EN" style="font-size: 11.0pt; line-height: 150%; font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: black;">Water is sucked in.</span></li>
</ul>
<ul style="margin-top: 0in;" type="circle">
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 150%; mso-list: l6 level1 lfo3; background: white;"><span lang="EN" style="font-size: 11.0pt; line-height: 150%; font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: black;">When water is pumped out of bladder cells, a {vacuum}</span><span lang="EN" style="font-size: 11.0pt; line-height: 150%; font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman'';"> builds up inside.</span></li>
</ul>
<p class="MsoNormal" style="margin-bottom: 0in; line-height: 150%; background: white;"><span lang="EN" style="font-size: 11.0pt; line-height: 150%; font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: black;">Pitcher Plants</span></p>
<ul style="margin-top: 0in;" type="circle">
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 150%; mso-list: l8 level1 lfo4; background: white;"><span lang="EN" style="font-size: 11.0pt; line-height: 150%; font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: black;">The plants have tube-shaped leaves that insects fall into.</span></li>
</ul>
<ul style="margin-top: 0in;" type="circle">
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 150%; mso-list: l11 level1 lfo5; background: white;"><span lang="EN" style="font-size: 11.0pt; line-height: 150%; font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: black;">Some plants are big enough to capture and eat {frogs}</span></li>
</ul>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p><strong>1. He understood why the plant did not respond to raindrops</strong></p>\n<ul>\n<li>\n<p><strong>Đáp án:</strong> <strong>raindrops</strong></p>\n</li>\n<li>\n<p><strong>Dẫn chứng:</strong> (Đoạn 1) &#8220;Yet sundews, he observed, ignored <strong>raindrops</strong>.&#8221;</p>\n</li>\n<li>\n<p><strong>Giải thích:</strong> Darwin nhận thấy cây gọng vó (sundews) lờ đi giọt mưa để tránh phản ứng sai và tốn năng lượng.</p>\n</li>\n</ul>\n<p><strong>2. He demonstrated how leaves close and then, for a short period, act like a stomach</strong></p>\n<ul>\n<li>\n<p><strong>Đáp án:</strong> <strong>stomach</strong></p>\n</li>\n<li>\n<p><strong>Dẫn chứng:</strong> (Đoạn 2) &#8220;&#8230;it formed itself into a temporary ‘<strong>stomach</strong>’&#8230;&#8221;</p>\n</li>\n<li>\n<p><strong>Giải thích:</strong> Lá cây bắt ruồi Venus khi kẹp lại hoạt động như một &#8220;dạ dày&#8221; tạm thời.</p>\n</li>\n</ul>\n<p><strong>3. The charge enters fluid-filled tunnels, causing pores in the cell walls to open.</strong></p>\n<ul>\n<li>\n<p><strong>Đáp án:</strong> <strong>pores</strong></p>\n</li>\n<li>\n<p><strong>Dẫn chứng:</strong> (Đoạn 4) &#8220;&#8230;which opens up <strong>pores</strong> in cell membranes.&#8221;</p>\n</li>\n<li>\n<p><strong>Giải thích:</strong> Dòng điện mở ra các lỗ (pores) trên màng tế bào, kích hoạt sự thay đổi hình dạng.</p>\n</li>\n</ul>\n<p><strong>4. When water is pumped out of bladder cells, a vacuum builds up inside.</strong></p>\n<ul>\n<li>\n<p><strong>Đáp án:</strong> <strong>vacuum</strong></p>\n</li>\n<li>\n<p><strong>Dẫn chứng:</strong> (Đoạn 5) &#8220;&#8230;creating a new <strong>vacuum</strong>.&#8221;</p>\n</li>\n<li>\n<p><strong>Giải thích:</strong> Việc bơm nước ra ngoài tạo ra một chân không (vacuum) bên trong bọng.</p>\n</li>\n</ul>\n<p><strong>5. Some plants are big enough to capture and eat frogs</strong></p>\n<ul>\n<li>\n<p><strong>Đáp án:</strong> <strong>frogs</strong></p>\n</li>\n<li>\n<p><strong>Dẫn chứng:</strong> (Đoạn 5) &#8220;&#8230;and can consume whole <strong>frogs</strong> unlucky enough to fall into them.&#8221;</p>\n</li>\n<li>\n<p><strong>Giải thích:</strong> Các cây nắp ấm lớn có thể bắt và ăn cả ếch (frogs).</p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('f642afc4-45d6-4f9c-9b5e-aec688cde8c9', 'bda17de2-e4f0-4f95-b624-5b17e82226a7', 'radio', 'Questions 6–13', NULL, '<p>Choose <strong>TRUE </strong>if the statement agrees with the information  <strong>FALSE </strong>if the statement contradicts the information  <strong>NOT GIVEN</strong> if there is no information on this</p>
', 'multiple_choice_single', '[{"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Pitcher plants increase in size after they have digested a lot of insects."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Carnivorous plants produce light-harvesting enzymes with the nutrients they extract from animals."}, {"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Pitcher plants and Venus flytraps are more efficient at photosynthesis than plants with ordinary leaves."}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Venus flytraps are better adapted to the soil of swamps and bogs than other carnivorous plants."}, {"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Carnivorous plants frequently find it difficult to photosynthesise in bogs due to a lack of sunlight."}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Scientists have campaigned to reduce the amount of nitrogen that is released into the soil by agricultural practices."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "A lot of exotic carnivorous plants are sold illegally."}, {"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Preventing wildfires is beneficial to the Venus flytrap"}]', 'null', 'null', 'null', '[{"content": "<p><strong>6. Pitcher plants increase in size after they have digested a lot of insects.</strong></p>\n<ul>\n<li><strong>Đáp án: TRUE</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 6) &#8220;When scientists feed <strong>pitcher plants extra bugs, the plants get bigger</strong>.&#8221;</li>\n<li><strong>Giải thích:</strong> Ăn thêm côn trùng khiến cây nắp ấm tăng kích thước.</li>\n</ul>\n<p><strong>7. Carnivorous plants produce light-harvesting enzymes with the nutrients they extract from animals.</strong></p>\n<ul>\n<li><strong>Đáp án: TRUE</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 6) &#8220;&#8230;take <strong>nitrogen and phosphorus from the flesh in order to build light-harvesting enzymes</strong>.&#8221;</li>\n<li><strong>Giải thích:</strong> Cây ăn thịt sử dụng chất dinh dưỡng từ động vật để tạo enzyme quang hợp.</li>\n</ul>\n<p><strong>8. Pitcher plants and Venus flytraps are more efficient at photosynthesis than plants with ordinary leaves.</strong></p>\n<ul>\n<li><strong>Đáp án: FALSE</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 7) &#8220;A pitcher or a flytrap is <strong>not very good at photosynthesis</strong> because, unlike plants with ordinary leaves&#8230;&#8221;</li>\n<li><strong>Giải thích:</strong> Chúng kém hiệu quả quang hợp hơn cây có lá thông thường.</li>\n</ul>\n<p><strong>9. Venus flytraps are better adapted to the soil of swamps and bogs than other carnivorous plants.</strong></p>\n<ul>\n<li><strong>Đáp án: NOT GIVEN</strong></li>\n<li><strong>Giải thích:</strong> Văn bản chỉ nói chung về khả năng thích nghi của <strong>carnivorous plants</strong> ở bogs, <strong>không so sánh</strong> Venus flytraps với các loài ăn thịt khác.</li>\n</ul>\n<p><strong>10. Carnivorous plants frequently find it difficult to photosynthesise in bogs due to a lack of sunlight.</strong></p>\n<ul>\n<li><strong>Đáp án: FALSE</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 7) &#8220;Also, bogs are often <strong>flooded with sunshine</strong>&#8230;&#8221;</li>\n<li><strong>Giải thích:</strong> Đầm lầy thường ngập tràn ánh nắng, mâu thuẫn với việc thiếu ánh sáng.</li>\n</ul>\n<p><strong>11. Scientists have campaigned to reduce the amount of nitrogen that is released into the soil by agricultural practices.</strong></p>\n<ul>\n<li><strong>Đáp án: NOT GIVEN</strong></li>\n<li><strong>Giải thích:</strong> Có thông tin về vấn đề nitơ dư thừa, nhưng <strong>không có thông tin</strong> về việc các nhà khoa học đã tổ chức chiến dịch (campaigned) để giảm nó.</li>\n</ul>\n<p><strong>12. A lot of exotic carnivorous plants are sold illegally.</strong></p>\n<ul>\n<li><strong>Đáp án: TRUE</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 8) &#8220;The <strong>black market trade</strong> in exotic carnivorous plants is strong&#8230;&#8221;</li>\n<li><strong>Giải thích:</strong> &#8220;Black market trade&#8221; (thị trường chợ đen) đồng nghĩa với việc buôn bán bất hợp pháp (illegally).</li>\n</ul>\n<p><strong>13. Preventing wildfires is beneficial to the Venus flytrap.</strong></p>\n<ul>\n<li><strong>Đáp án: FALSE</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 8) &#8220;The <strong>suppression of wildfires</strong>&#8230; <strong>allows other plants to grow quickly and outcompete the Venus flytraps</strong>.&#8221;</li>\n<li><strong>Giải thích:</strong> Ngăn chặn cháy rừng gây hại vì nó khiến cây khác lấn át cây bắt ruồi Venus.</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('001d023c-ac5d-496f-a384-03d7fcf8b410', '631e7cf3-cca3-4842-88c7-61cd2acab1b6', 'fillup', 'Questions 1–6', '<p>Complete the table below.</p>
<p>Choose<strong> ONE WORD ONLY</strong> from the passage for each answer.</p>
<p><strong data-path-to-node="2,0,0" data-index-in-node="0">1600s</strong>: Early inventors like Papin started to develop boats that relied on steam instead of manpower or wind.</p>
<p><strong data-path-to-node="2,1,0" data-index-in-node="0">1730s</strong>: The engine of Jonathan Hulls’ steamboat was { inefficient} due to its weight.</p>
<p><strong data-path-to-node="2,2,0" data-index-in-node="0">1780s</strong>: A French paddle steamer did not have the {endurance} to keep going for more than a quarter of an hour.</p>
<p><strong data-path-to-node="2,3,0" data-index-in-node="0">1780s</strong>: John Fitch overcame a number of {technical} problems with his steamboat designs.</p>
<p><strong data-path-to-node="2,4,0" data-index-in-node="0">Early 1800s</strong>: The Charlotte Dundas pulled barges to Glasgow.</p>
<p><strong data-path-to-node="2,5,0" data-index-in-node="0">Early 1800s</strong>: In France, Fulton used a steamboat to try to raise interest in a {submarine}.</p>
<p><strong data-path-to-node="2,6,0" data-index-in-node="0">Early 1800s</strong>: Passengers in the US began to be carried regularly by a steamboat called the {Clermont}.</p>
<p><strong data-path-to-node="2,7,0" data-index-in-node="0">1812 onward</strong>: In Scotland, steamboats transported some passengers, but mostly {cargo}.</p>', '', 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">1. 1730s: The engine of Jonathan Hulls’ steamboat was {inefficient} due to its weight.</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…it was to be driven by a Newcomen engine, which was <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"67\">heavy</strong> and therefore <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"87\">inefficient</strong>…” (Đoạn 2)</p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Động cơ Newcomen quá nặng nên hoạt động không hiệu quả (inefficient).</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">2. 1780s: A French paddle steamer did not have the {endurance} to keep going for more than a quarter of an hour.</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…managed to last <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"31\">fifteen minutes</strong> [a quarter of an hour]… but lacked the <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"88\">endurance</strong> for longer trips.” (Đoạn 2)</p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Con tàu này chỉ chạy được 15 phút vì thiếu khả năng chịu đựng/bền bỉ (endurance).</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">3. 1780s: John Fitch overcame a number of {technical} problems with his steamboat designs.</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…although he tried a number of designs and solved many <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"69\">technical</strong> challenges…” (Đoạn 2)</p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Solved challenges” tương đương với “overcame problems” (vượt qua các vấn đề kỹ thuật).</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">4. Early 1800s: In France, Fulton used a steamboat to try to raise interest in a {submarine}.</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…Fulton ran steamboat trials on the River Seine, in an attempt to attract French support for his <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"111\">submarine</strong> Nautilus.” (Đoạn 3)</p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Fulton thử nghiệm tàu hơi nước để thu hút sự chú ý/hỗ trợ cho con tàu ngầm (submarine) của mình.</p>\n</li>\n</ul>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">5. Early 1800s: Passengers in the US began to be carried regularly by a steamboat called the {Clermont}.</strong></p>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “In 1807, the <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"25\">Clermont</strong> began a scheduled <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"52\">passenger</strong> steamboat service…” (Đoạn 3)</p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong data-path-to-node=\"14,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Clermont là tên con tàu hơi nước đầu tiên chạy dịch vụ hành khách định kỳ tại Mỹ.</p>\n</li>\n</ul>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">6. 1812 onward: In Scotland, steamboats transported some passengers, but mostly {cargo}.</strong></p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…dozens of steamboats were to be seen… carrying <strong data-path-to-node=\"16,0,0\" data-index-in-node=\"64\">cargo</strong> and occasionally [some] <strong data-path-to-node=\"16,0,0\" data-index-in-node=\"94\">passengers</strong>.” (Đoạn 3)</p>\n</li>\n<li>\n<p data-path-to-node=\"16,1,0\"><strong data-path-to-node=\"16,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Ở Scotland, tàu chủ yếu chở hàng hóa (cargo), thỉnh thoảng mới chở khách.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('9783d129-fb96-4b8c-a754-e8618c500ab4', '8cc6fe60-2f66-41b9-a6cf-2ca5d78168ee', 'fillup', 'Questions 1–7', '<p>Complete the notes below.</p>
<p>Choose <strong>ONE WORD ONLY </strong>from the passage for each answer</p>
<h3 style="text-align: center;" data-start="63" data-end="104"><strong data-start="63" data-end="104">The life and work of Georgia O’Keeffe</strong></h3>
<ul data-start="106" data-end="794" data-is-last-node="" data-is-only-node="">
<li data-start="106" data-end="187">
<p data-start="108" data-end="187">studied art, then worked as a  {teacher} in various places in the USA</p>
</li>
<li data-start="188" data-end="271">
<p data-start="190" data-end="271">created drawings using  {charcoal} which were exhibited in New York City</p>
</li>
<li data-start="272" data-end="362">
<p data-start="274" data-end="362">moved to New York and became famous for her paintings of the city’s  {skyscrapers  }</p>
</li>
<li data-start="363" data-end="439">
<p data-start="365" data-end="439">produced a series of innovative close-up paintings of  {flowers}</p>
</li>
<li data-start="440" data-end="552">
<p data-start="442" data-end="552">went to New Mexico and was initially inspired to paint the many  {bones} that could be found there</p>
</li>
<li data-start="553" data-end="680">
<p data-start="555" data-end="680">continued to paint various features that together formed the dramatic  {landscape}of New Mexico for over forty years</p>
</li>
<li data-start="681" data-end="794" data-is-last-node="">
<p data-start="683" data-end="794" data-is-last-node="">travelled widely by plane in later years, and painted pictures of clouds and {rivers} seen from above</p>
</li>
</ul>
', NULL, 'gap_filling', NULL, NULL, '{"layoutType": ["standard"], "summaryText": null, "answerOptions": null, "matchingItems": null}', '{"layoutType": ["standard"], "legendTitle": null, "matrixItems": null, "matrixCategories": null}', '[{"content": "<p>1. teacher<br />(Đoạn: “she became an art teacher and taught in elementary schools, high schools, and colleges…”)<br />→ Sau khi học nghệ thuật, O’Keeffe làm giáo viên (teacher) ở nhiều nơi tại Mỹ.</p>\n<p> <br />2. charcoal<br />(Đoạn: “O’Keeffe began to experiment with creating abstract compositions in charcoal…”)<br />→ Cô vẽ bằng than chì (charcoal) – đây là loạt tranh đầu tiên được trưng bày ở New York.</p>\n<p> <br />3. skyscrapers<br />(Đoạn: “She was widely known for the architectural pictures that dramatically depict the soaring skyscrapers of New York.”)<br />→ O’Keeffe nổi tiếng với tranh vẽ những tòa nhà chọc trời (skyscrapers) của thành phố.</p>\n<p> <br />4. flowers<br />(Đoạn: “In her magnified images depicting flowers, begun in 1924…”)<br />→ Cô tạo ra loạt tranh cận cảnh độc đáo về hoa (flowers).</p>\n<p> <br />5. bones<br />(Đoạn: “At first, it was the numerous sun-bleached bones she came across in the state’s rugged terrain…”)<br />→ Khi đến New Mexico, cô được truyền cảm hứng từ những chiếc xương (bones).</p>\n<p> <br />6. landscape<br />(Đoạn: “However, it was the region’s spectacular landscape… that held the artist’s imagination for more than four decades.”)<br />→ Cô vẽ cảnh quan (landscape) của New Mexico suốt hơn 40 năm.</p>\n<p> <br />7. rivers<br />(Đoạn: “Flying in planes inspired her last two major series – aerial views of rivers and expansive paintings of the sky…”)<br />→ Trong những năm cuối, cô vẽ những con sông (rivers) nhìn từ trên cao.</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('0252f251-6658-484f-bb65-142b29753e15', 'f4fcaea8-157d-4b4d-af6c-75fc3ce1a17e', 'radio', 'Questions 14–16', NULL, '<p>Choose the correct answers</p>
', 'multiple_choice_single', '[{"correct": 3, "options": [{"content": "A the curiosity of historians about the original purpose of these ruins."}, {"content": "B the vast geographical areas covered by these structures."}, {"content": "C their profound impact on the field of archaeological research"}, {"content": "D the mixture of beauty and mystery these sites represent."}], "question": "In describing the appeal of monumental ruins, the writer highlights"}, {"correct": 2, "options": [{"content": "A upended established theories."}, {"content": "B Triggered a heated debate among scientists."}, {"content": "C emerged from a range of disciplines."}, {"content": "D confirmed a major cause of environmental destruction."}], "question": "Recent findings regarding lost civilisations have"}, {"correct": 0, "options": [{"content": "A the pace of collapse showed some resemblance across societies."}, {"content": "B the decline of societies was usually a slow and predictable process"}, {"content": "C all societies peaked in terms of population and power before collapsing."}, {"content": "D ordinary people could occasionally affect the course of events."}], "question": "In discussing how previous societies fell, the writer mentions that"}]', 'null', 'null', 'null', '[{"content": "<p><strong>14. In describing the appeal of monumental ruins, the writer highlights</strong></p>\n<ul>\n<li><strong>Đáp án: D. the mixture of beauty and mystery these sites represent.</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 2) &#8220;We are drawn to their <strong>magnificent and haunting beauty, as well as the enigmas they present</strong>.&#8221;</li>\n<li><strong>Giải thích:</strong> Tác giả nhấn mạnh sự pha trộn giữa vẻ đẹp và sự bí ẩn (enigmas/mystery).</li>\n</ul>\n<p><strong>15. Recent findings regarding lost civilisations have</strong></p>\n<ul>\n<li><strong>Đáp án: C. emerged from a range of disciplines.</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 3) &#8220;This suspicion&#8230; has been <strong>substantiated by discoveries made in recent decades by archaeologists, climatologists, historians, palaeontologists, and palynologists</strong>&#8230;&#8221;</li>\n<li><strong>Giải thích:</strong> Các khám phá đến từ nhiều lĩnh vực khác nhau (a range of disciplines).</li>\n</ul>\n<p><strong>16. In discussing how previous societies fell, the writer mentions that</strong></p>\n<ul>\n<li><strong>Đáp án: A. the pace of collapse showed some resemblance across societies.</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 4) &#8220;Historical collapses generally <strong>followed similar patterns</strong> resembling variations on a theme.&#8221;</li>\n<li><strong>Giải thích:</strong> Sự sụp đổ thường theo những khuôn mẫu tương tự (similar patterns), cho thấy sự tương đồng (resemblance) về tốc độ/quá trình.</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('36a43c30-f79c-4362-9f27-c6598e80da02', '542b2040-3f68-499d-a7b0-f76d6580181c', 'matching', 'Questions 14 – 19', NULL, '<p>Choose the correct heading for each section from the list of headings below.<br />
Choose the correct number, i – ix, in boxes 14 – 19 below.</p>
', 'matching', 'null', 'null', '{"layoutType": "heading", "summaryText": null, "answerOptions": [{"optionText": "i. How hearing loss may be caused by certain types of sounds"}, {"optionText": "ii. Uses for Turner’s research in media and communications"}, {"optionText": "iii. Creating a model for the classification of sounds"}, {"optionText": "iv. Potential developments that still require further research"}, {"optionText": "v. A drawback in the help currently available to those with hearing problems"}, {"optionText": "vi. Providing the hearing-impaired with training in new technology"}, {"optionText": "vii. A more effective way to take attention away from a hearing problem"}, {"optionText": "viii. Analysing the sounds produced in the process of speaking"}, {"optionText": "ix. The possibility of a hearing aid that can adjust itself to different environments"}], "matchingItems": null}', 'null', '[{"content": "<p>14. v – A drawback in the help currently available to those with hearing problems<br />\n(Đoạn 1: “Helpful as hearing aids are, those who wear them often complain that background noise continues to interfere with their understanding.”)<br />\n→ Mô tả hạn chế của thiết bị trợ thính hiện nay — chúng vẫn để tiếng ồn nền làm cản trở khả năng nghe rõ.</p>\n<p>15. iii – Creating a model for the classification of sounds<br />\n(Đoạn 2: “He believes that the brain may be able to group similar types of sounds together based on their specific characteristics.” … “Turner and his colleagues have analysed this process mathematically and then developed algorithms that mimic what the brain is doing.”)<br />\n→ Đoạn này nói về việc xây dựng mô hình phân loại âm thanh dựa trên đặc điểm và thống kê của từng loại tiếng.</p>\n<p>16. ix – The possibility of a hearing aid that can adjust itself to different environments<br />\n(Đoạn 3: “Future devices will have several different modes… The device might intelligently select an appropriate mode based on the characteristics of the incoming sound.”)<br />\n→ Mô tả thiết bị trợ thính tương lai có khả năng tự điều chỉnh phù hợp với môi trường âm thanh khác nhau.</p>\n<p>17. iv – Potential developments that still require further research<br />\n(Đoạn 4: “Turner anticipates that his team will need two more years of simulating the effect of modifications… before they start to work with device specialists.”)<br />\n→ Cho thấy công nghệ vẫn đang trong quá trình nghiên cứu và cần thời gian thử nghiệm thêm trước khi ứng dụng thực tế.</p>\n<p>18. vii – A more effective way to take attention away from a hearing problem<br />\n(Đoạn 5: “Tinnitus sufferers… With the new technology, individual patients could select the best sound to distract them from their tinnitus.”)<br />\n→ Nói về cách hiệu quả hơn để giúp người bị ù tai (tinnitus) phân tán sự chú ý khỏi âm thanh khó chịu.</p>\n<p>19. ii – Uses for Turner’s research in media and communications<br />\n(Đoạn 6: “The technology not only holds promise for helping the hearing impaired, but it also has the potential to improve phone calls… Systems that can deal with unwanted audio content would also be welcomed by video-sharing websites.”)<br />\n→ Trình bày ứng dụng của công nghệ Turner trong truyền thông, gọi điện và chỉnh sửa video.</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('6891cdb3-3780-4a52-9e05-9c49053cb93e', '542b2040-3f68-499d-a7b0-f76d6580181c', 'fillup', 'Questions 20 – 23', '<p>Complete the summary below.<br />
Choose <strong>NO MORE THAN TWO WORDS</strong> from the passage for each answer.<br />
Write your answers in boxes 20 – 23 below.</p>
<p style="text-align: center;"><strong>Improving the performance of hearing aids</strong></p>
<p style="text-align: left;">At present, many people find their hearing aids do not work well when there is background noise. This also applies to people without hearing aids who have had implants fitted to help with hearing loss. Dr Richard Turner is looking for a solution to this problem. Although sounds are never {repeated}, he believes they do share some similarities. He and his colleagues have worked on a mathematical system using {algorithms}, which replicate how we hear sounds. To allow this system to be ‘trained’, they have applied procedures used in machine learning and found that many different sounds can be described using a limited number of {statistics}. They have now developed a system that can distinguish {speech} from other sounds.</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p>20. repeated<br />\n(Đoạn 2: “No two rain sounds are identical because the precise arrangement of falling water droplets is never repeated.”)<br />\n→ Turner chỉ ra rằng âm thanh không bao giờ lặp lại y hệt nhau, ví dụ như tiếng mưa — mỗi lần rơi đều khác nhau, dù có những nét tương đồng.</p>\n<p>21. algorithms<br />\n(Đoạn 2: “Turner and his colleagues have analysed this process mathematically and then developed algorithms that mimic what the brain is doing.”)<br />\n→ Ông và nhóm của mình xây dựng hệ thống toán học gồm các thuật toán mô phỏng cách bộ não xử lý âm thanh.</p>\n<p>22. statistics<br />\n(Đoạn 2: “‘A relatively small set of statistics is sufficient to describe a large number of sounds,’ he says.”)<br />\n→ Nhóm nghiên cứu phát hiện rằng chỉ cần một tập hợp thống kê nhỏ cũng đủ để mô tả nhiều loại âm thanh khác nhau.</p>\n<p>23. speech<br />\n(Đoạn 2: “The system that Turner and his team have come up with is capable of telling the difference between speech and other types of sound.”)<br />\n→ Hệ thống được phát triển có thể phân biệt được lời nói (speech) với các loại âm thanh khác.</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('ceff6c76-4886-4592-9eb4-e4742ea60ea9', '02b5ca32-7c52-4bb3-b34f-64a64a6ded61', 'radio', 'Questions 11–14', NULL, '<p>Choose the correct answer.</p>
', 'multiple_choice_single', '[{"correct": 1, "options": [{"content": "A.are given a litte money."}, {"content": "B.do not receive payment."}, {"content": "C.can apply for expenses."}], "question": "People who act as hosts for Connections"}, {"correct": 0, "options": [{"content": "A.have difficulty making friends."}, {"content": "B.are looking for temporary work."}, {"content": "C.can offer language support."}], "question": "Connections is for people from other countries who"}, {"correct": 2, "options": [{"content": "A.cook food for their host family"}, {"content": "B.explain their own family traditions."}, {"content": "C.discuss matters of personal interest."}], "question": "According to the speaker, what can a guest expect to do during their stay?"}, {"correct": 0, "options": [{"content": "A.an increased understanding between cultures."}, {"content": "B.a programme of weekly visits."}, {"content": "C.more involvement from people of different communities."}], "question": "According to the speaker, a long-term benefit of the Connections scheme could be"}]', 'null', 'null', 'null', '[{"content": "<p><strong>Narrator:</strong> Section 2, you will hear part of a radio programme in which the speaker is talking about a new organisation called connections. First you have some time to look at questions 11 to 14 on page three. Now listen carefully and answer questions 11 to fourteen.</p>\n<p>Hello listeners. To this program will know that we’re very keen to foster links within communities, and we think we’ve hit on a winning idea. I’m going to tell you about a scheme which has been set up as part of our Communities in Action program for those who’d like to be put in touch with people from different countries and cultures.</p>\n<p>As the name Connections suggests, we’re hoping that the scheme will introduce people who live in this country who will act as hosts to people who’ve recently arrived here to study or to work for a limited period of time, who will be their guests.</p>\n<blockquote>\n<p><strong>Dịch:</strong> Xin chào thính giả. Những ai theo dõi chương trình này đều biết rằng chúng tôi rất muốn thúc đẩy sự gắn kết trong các cộng đồng, và chúng tôi nghĩ rằng mình đã có một ý tưởng tuyệt vời. Tôi sẽ kể cho các bạn nghe về một chương trình đã được thiết lập như một phần của dự án ‘Cộng đồng hành động’ của chúng tôi dành cho những ai muốn kết nối với những người đến từ các quốc gia và nền văn hóa khác nhau.</p>\n<p>Đúng như tên gọi Connections (Kết nối) gợi ý, chúng tôi hy vọng chương trình sẽ giới thiệu những người đang sống ở đất nước này, họ sẽ đóng vai trò là chủ nhà, với những người mới đến đây để học tập hoặc làm việc trong một khoảng thời gian giới hạn, họ sẽ là khách của họ.</p>\n</blockquote>\n<p>Now if you’ve got a spare room in your house or flat, you might like to be a host and have someone stay for a weekend. I should point out that no money is involved as all our hosts are <strong>(11) unpaid (B)</strong>. But you should not have too much extra expense other than one more person joining you at mealtimes.</p>\n<blockquote>\n<p><strong>Dịch:</strong> Nếu bạn có một phòng trống trong nhà hoặc căn hộ của mình, bạn có thể muốn làm chủ nhà và mời ai đó ở lại vào cuối tuần. Tôi phải chỉ ra rằng không có tiền bạc liên quan vì tất cả các chủ nhà của chúng tôi đều <strong>(11) không được trả công (B)</strong>. Nhưng bạn sẽ không phải chịu quá nhiều chi phí phát sinh ngoài việc có thêm một người dùng bữa cùng bạn.</p>\n</blockquote>\n<p>In the course of their studies or work in this country, some people rarely get the opportunity to socialize. There may be language problems or feelings of shyness, which mean that whatever their age, people can become quite <strong>lonely or isolated (A)</strong>. If you are prepared to invite someone into your home, you can rely on Connections for a personal introduction, and the timing of the invitation will be to suit you, as I said, the stay is always over a weekend for two or three nights, and as the host, the arrangements you make for your visitor will depend on your other commitments.</p>\n<blockquote>\n<p><strong>Dịch:</strong> Trong quá trình học tập hoặc làm việc tại đất nước này, một số người hiếm khi có cơ hội giao tiếp xã hội. Có thể có vấn đề về ngôn ngữ hoặc cảm giác ngại ngùng, điều này có nghĩa là bất kể tuổi tác nào, mọi người đều có thể trở nên khá <strong>cô đơn hoặc bị cô lập (A)</strong>. Nếu bạn sẵn lòng mời ai đó vào nhà mình, bạn có thể tin tưởng vào Connections để có một sự giới thiệu cá nhân, và thời gian mời sẽ phù hợp với bạn. Như tôi đã nói, việc lưu trú luôn diễn ra vào cuối tuần trong hai hoặc ba đêm, và với tư cách là chủ nhà, các sắp xếp của bạn cho khách sẽ phụ thuộc vào các cam kết khác của bạn.</p>\n</blockquote>\n<p>If you’re listening to this program and you would like to take advantage of what Connections can offer a guest, then what I’m going on to say will apply to you. So what will you, the guest, get out of a visit? You’ll gain an insight into the customs and way of life of the country you’re staying in and you’ll enjoy home cooked meals, and be able to <strong>(13) ask questions about things which interest you or perhaps even puzzle you (C)</strong>.</p>\n<blockquote>\n<p><strong>Dịch:</strong> Nếu bạn đang nghe chương trình này và bạn muốn tận dụng những gì Connections có thể cung cấp cho khách, thì những gì tôi sắp nói sẽ áp dụng cho bạn. Vậy bạn, với tư cách là khách, sẽ nhận được gì từ chuyến thăm này? Bạn sẽ hiểu rõ hơn về phong tục và lối sống của đất nước bạn đang ở và bạn sẽ được thưởng thức các bữa ăn nấu tại nhà, và có thể <strong>(13) hỏi những câu hỏi về những điều bạn quan tâm hoặc thậm chí khiến bạn băn khoăn (C)</strong>.</p>\n</blockquote>\n<p>It’s early days, but if a weekend stay goes well, relationships might develop over time and turn into lasting and genuine friendships. This would undoubtedly be of advantage to the whole community, as we all become more <strong>(14) aware of the ways in which people in different countries live their lives (A)</strong>. There’s also the possibility that when you return to your own country, you might one day want to invite your hosts to stay with you.</p>\n<blockquote>\n<p><strong>Dịch:</strong> Mặc dù mới bắt đầu, nhưng nếu kỳ nghỉ cuối tuần diễn ra tốt đẹp, các mối quan hệ có thể phát triển theo thời gian và trở thành những tình bạn lâu dài và chân thật. Điều này chắc chắn sẽ mang lại lợi ích cho toàn bộ cộng đồng, khi tất cả chúng ta ngày càng <strong>(14) nhận thức rõ hơn về cách mọi người ở các quốc gia khác nhau sống cuộc sống của họ (A)</strong>. Cũng có khả năng là khi bạn trở về đất nước của mình, một ngày nào đó bạn có thể muốn mời chủ nhà của mình đến ở lại với bạn.</p>\n</blockquote>\n<p><strong>Narrator:</strong> Before you hear the rest of the program, you have some time to look at questions 15 to 20 on page four. Now listen and answer questions 15 to twenty.</p>\n<p>Right, I hope I’ve given you enough information on the scheme and what we’re setting out to do. I’ll now deal with the process for applying, if you’d like to be involved from the point of view of a guest. So have a pencil and some paper ready to jot down what you need to do.</p>\n<blockquote>\n<p><strong>Dịch:</strong> Được rồi, tôi hy vọng tôi đã cung cấp đủ thông tin về chương trình và những gì chúng tôi đang đặt ra để làm. Bây giờ tôi sẽ đề cập đến quy trình đăng ký, nếu bạn muốn tham gia với tư cách là khách. Vì vậy, hãy chuẩn bị sẵn bút chì và giấy để ghi lại những gì bạn cần làm.</p>\n</blockquote>\n<p>Connections is broken up into various small sections which will deal with your application through the different stages. To begin with, we ask you to make a phone call to our <strong>(15) vetting (H)</strong> people. We need to know some basic information about you, like how long you’re intending to be in this country, the minimum time limit is 3 months, whether you’re working or studying.</p>\n<blockquote>\n<p><strong>Dịch:</strong> Connections được chia thành nhiều phần nhỏ khác nhau sẽ xử lý đơn đăng ký của bạn qua các giai đoạn khác nhau. Để bắt đầu, chúng tôi yêu cầu bạn gọi điện thoại đến bộ phận <strong>(15) kiểm tra (H)</strong> của chúng tôi. Chúng tôi cần biết một số thông tin cơ bản về bạn, như bạn dự định ở lại đất nước này bao lâu, thời hạn tối thiểu là 3 tháng, liệu bạn đang làm việc hay học tập.</p>\n</blockquote>\n<p>We require a reference, which must be from the person in authority who you’re working with or studying under. This will be used for an <strong>(16) identity (C)</strong> check. Once that’s been sent to the authorities and approved, we’ll email you an application form which you can download.</p>\n<blockquote>\n<p><strong>Dịch:</strong> Chúng tôi yêu cầu một thư giới thiệu, thư này phải từ người có thẩm quyền mà bạn đang làm việc cùng hoặc học tập dưới sự hướng dẫn của họ. Điều này sẽ được sử dụng để kiểm tra <strong>(16) danh tính (C)</strong>. Sau khi thư đó được gửi đến cơ quan chức năng và được chấp thuận, chúng tôi sẽ gửi email cho bạn một mẫu đơn đăng ký mà bạn có thể tải xuống.</p>\n</blockquote>\n<p>You should complete this and return it with two recent passport sized photographs of yourself. One photo will be held in our <strong>(17) records (F)</strong> and the other will be sent to your host family prior to your first weekend visit.</p>\n<blockquote>\n<p><strong>Dịch:</strong> Bạn nên hoàn thành mẫu đơn này và gửi lại kèm theo hai ảnh thẻ gần đây của bạn. Một ảnh sẽ được lưu giữ trong <strong>(17) hồ sơ (F)</strong> của chúng tôi và ảnh kia sẽ được gửi cho gia đình chủ nhà của bạn trước chuyến thăm cuối tuần đầu tiên của bạn.</p>\n</blockquote>\n<p>Our Centre Manager will get back to you within a week of receiving your form to let you know that we have it <strong>(18) (A: Acknowledgement)</strong>. And if we think there’s a suitable match on our files, someone from our interview team will contact you for a face to face meeting with a member of staff <strong>(19) (D: An interview)</strong>. At that point, you should have some idea of weekend dates when you’re free, which we can put to the host family.</p>\n<blockquote>\n<p><strong>Dịch:</strong> Quản lý Trung tâm của chúng tôi sẽ liên hệ lại với bạn trong vòng một tuần kể từ khi nhận được mẫu đơn của bạn để thông báo rằng chúng tôi đã nhận được nó <strong>(18) (A: Xác nhận)</strong>. Và nếu chúng tôi nghĩ rằng có một sự kết hợp phù hợp trong hồ sơ của chúng tôi, ai đó từ đội phỏng vấn của chúng tôi sẽ liên hệ với bạn để sắp xếp một cuộc gặp mặt trực tiếp với một thành viên của nhân viên <strong>(19) (D: Một cuộc phỏng vấn)</strong>. Vào thời điểm đó, bạn nên có một số ý tưởng về những ngày cuối tuần mà bạn rảnh, chúng tôi có thể đề xuất với gia đình chủ nhà.</p>\n</blockquote>\n<p>However, decisions are not made at the meeting, but you can expect to hear the <strong>(20) result (B: Decision)</strong> from us in a couple of days. Now the process for those of you interested in welcoming someone…</p>\n<blockquote>\n<p><strong>Dịch:</strong> Tuy nhiên, các quyết định không được đưa ra tại cuộc họp, nhưng bạn có thể mong đợi nhận được <strong>(20) kết quả (B: Quyết định)</strong> từ chúng tôi trong vài ngày. Bây giờ, quy trình dành cho những người trong số các bạn quan tâm đến việc chào đón ai đó…</p>\n</blockquote>\n<p><strong>Narrator:</strong> That is the end of Section 2. You now have half a minute to check your answers. Now turn to Section 3 on page 5.</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('76f00685-947b-4238-b597-f4dd8044d000', 'aac63b35-48f6-4960-811a-ca521dccb2b5', 'radio', 'Questions 1–5', NULL, '<p>Choose <strong>TRUE </strong>if the statement agrees with the information given in the text, choose <strong>FALSE </strong>if the statement contradicts the information, or choose <strong>NOT GIVEN </strong>if there is no information on this.</p>
', 'multiple_choice_single', '[{"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Donald Johanson was uncertain about the nature of the elbow bone he found in Afar."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": " Several bones were found by Donald Johanson at the same site in Afar."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "The experts realised the importance of the discovery at Afar."}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "It was the upper part of the skeleton that had suffered the least damage."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "The skeleton’s measurements helped Johanson’s team to decide if it was male or female."}]', NULL, '{"layoutType": ["standard"], "summaryText": null, "answerOptions": null, "matchingItems": null}', '{"layoutType": ["standard"], "legendTitle": null, "matrixItems": null, "matrixCategories": null}', '[{"content": "<p data-path-to-node=\"1\">Câu 1: FALSE</p>\n<ul data-path-to-node=\"2\">\n<li><strong data-path-to-node=\"2,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 1, dòng 6-7.</li>\n<li><strong data-path-to-node=\"2,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Straight away, he recognized it as coming from the elbow of a human ancestor.”</li>\n<li><strong data-path-to-node=\"2,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả dùng cụm từ <strong data-path-to-node=\"2,2,0\" data-index-in-node=\"32\">“Straight away”</strong> (Ngay lập tức) để khẳng định việc Donald Johanson nhận ra mảnh xương khuỷu tay. Điều này trái ngược hoàn toàn với từ <strong data-path-to-node=\"2,2,0\" data-index-in-node=\"165\">“uncertain”</strong> (không chắc chắn) trong câu hỏi.</li>\n</ul>\n<p data-path-to-node=\"3\">Câu 2: TRUE</p>\n<ul data-path-to-node=\"4\">\n<li><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 1, dòng 8-9.</li>\n<li><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “I saw bits of the skull, a chunk of jaw, a couple of vertebrae…”</li>\n<li><strong data-path-to-node=\"4,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Johanson liệt kê một loạt các phần xương khác nhau được tìm thấy tại cùng một địa điểm (mảnh hộp sọ, xương hàm, đốt sống). Vì vậy, thông tin tìm thấy <strong data-path-to-node=\"4,2,0\" data-index-in-node=\"162\">“nhiều mảnh xương”</strong> (several bones) là chính xác.</li>\n</ul>\n<p data-path-to-node=\"5\">Câu 3: TRUE</p>\n<ul data-path-to-node=\"6\">\n<li><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 2, dòng 1-2.</li>\n<li><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “It was immediately obvious that the skeleton was a significant find…”</li>\n<li><strong data-path-to-node=\"6,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm từ <strong data-path-to-node=\"6,2,0\" data-index-in-node=\"19\">“significant find”</strong> (phát hiện quan trọng) chính là cách viết khác của <strong data-path-to-node=\"6,2,0\" data-index-in-node=\"89\">“importance of the discovery”</strong>. Bài đọc khẳng định tầm quan trọng này là “hiển nhiên ngay lập tức” (immediately obvious) đối với các chuyên gia.</li>\n</ul>\n<p data-path-to-node=\"7\">Câu 4: NOT GIVEN</p>\n<ul data-path-to-node=\"8\">\n<li><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 2, dòng 4-5.</li>\n<li><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…it was also the most complete – 40% of the skeleton had been preserved.”</li>\n<li><strong data-path-to-node=\"8,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ cung cấp con số 40% bộ xương được bảo tồn. Tác giả <strong data-path-to-node=\"8,2,0\" data-index-in-node=\"75\">không hề cung cấp thông tin hay so sánh</strong> xem phần phía trên (upper part) bị hư hại nhiều hay ít hơn các phần khác, nên thông tin này không có trong bài.</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('08eabbb3-917a-4f9e-b1ba-d1076c063d94', 'f4fcaea8-157d-4b4d-af6c-75fc3ce1a17e', 'matching', 'Questions 22–26', NULL, '<p>Complete each sentence with the correct ending, A-F, below.</p>
', 'matching_features', 'null', 'null', '{"layoutType": "standard", "summaryText": null, "answerOptions": [{"optionText": "A are not implacable to all socities.   "}, {"optionText": "B provide a hopeful perspective."}, {"optionText": "C is embodied all physical features"}, {"optionText": "D is potentially both positive and negative"}, {"optionText": "E will not address current issues directly."}, {"optionText": "F have increased compared to the past "}], "matchingItems": [{"questionPart": "Evidence of remarkable achievements of certain past civilisations ", "correctAnswer": "C is embodied all physical features", "sectionContent": null}, {"questionPart": "Analogies between the development of an individual and that of a society ", "correctAnswer": "A are not implacable to all socities.   ", "sectionContent": null}, {"questionPart": "The environmental challenges that societies encounter ", "correctAnswer": "F have increased compared to the past ", "sectionContent": null}, {"questionPart": "In modern society, powerful technology ", "correctAnswer": "D is potentially both positive and negative", "sectionContent": null}, {"questionPart": "Reflections on ancient events and tendencies ", "correctAnswer": "E will not address current issues directly.", "sectionContent": null}]}', 'null', '[{"content": "<p><strong>22. Evidence of remarkable achievements of certain past civilisations <span class=\"math-inline\" data-math=\"rightarrow\">$rightarrow$</span> C. is embodied all physical features</strong></p>\n<ul>\n<li>\n<p><strong>Dẫn chứng:</strong> (Đoạn 2) &#8220;The grandeur of these ruins <strong>attests to the previous wealth and power</strong> of their builders&#8230;&#8221;</p>\n</li>\n<li>\n<p><strong>Giải thích:</strong> Sự vĩ đại của các tàn tích (physical features/grandeur) chứng minh (attests/embodied) cho sự giàu có và quyền lực trước đây.</p>\n</li>\n</ul>\n<p><strong>23. Analogies between the development of an individual and that of a society <span class=\"math-inline\" data-math=\"rightarrow\">$rightarrow$</span> A. are not implacable to all socities.</strong></p>\n<ul>\n<li>\n<p><strong>Dẫn chứng:</strong> (Đoạn 4) &#8220;However, <strong>this metaphor proves inaccurate for many past societies</strong>&#8230; It is evident that <strong>not all past societies followed this trajectory uniformly</strong>&#8230;&#8221;</p>\n</li>\n<li>\n<p><strong>Giải thích:</strong> Phép ẩn dụ này không chính xác cho nhiều xã hội (not implacable to all societies).</p>\n</li>\n</ul>\n<p><strong>24. The environmental challenges that societies encounter <span class=\"math-inline\" data-math=\"rightarrow\">$rightarrow$</span> F. have increased compared to the past</strong></p>\n<ul>\n<li>\n<p><strong>Dẫn chứng:</strong> (Đoạn 5) &#8220;These environmental problems encompass the same eight factors that contributed to past societies&#8217; downfalls, <strong>plus four new ones</strong>&#8230;&#8221;</p>\n</li>\n<li>\n<p><strong>Giải thích:</strong> Các thách thức hiện đại bao gồm 8 yếu tố cũ cộng thêm 4 yếu tố mới, tức là đã gia tăng.</p>\n</li>\n</ul>\n<p><strong>25. In modern society, powerful technology <span class=\"math-inline\" data-math=\"rightarrow\">$rightarrow$</span> D. is potentially both positive and negative</strong></p>\n<ul>\n<li>\n<p><strong>Dẫn chứng:</strong> (Đoạn 6) &#8220;We have certain advantages over past societies that reduce our risks, including our <strong>powerful technology (i.e. its beneficial effects)</strong>&#8230; At the same time&#8230; again, our <strong>potent technology (i.e. its unintended destructive effects)</strong>&#8230;&#8221;</p>\n</li>\n<li>\n<p><strong>Giải thích:</strong> Công nghệ có cả tác động có lợi và gây hủy hoại.</p>\n</li>\n</ul>\n<p><strong>26. Reflections on ancient events and tendencies <span class=\"math-inline\" data-math=\"rightarrow\">$rightarrow$</span> E. will not address current issues directly.</strong></p>\n<ul>\n<li>\n<p><strong>Dẫn chứng:</strong> (Đoạn 6) &#8220;It would be naive to assume that studying the past will yield <strong>straightforward answers directly applicable to today&#8217;s world</strong>.&#8221;</p>\n</li>\n<li>\n<p><strong>Giải thích:</strong> Bài học từ quá khứ không cung cấp câu trả lời trực tiếp cho các vấn đề hiện tại.</p>\n</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('f925a5c2-a35c-4c73-ab48-a2f34fcb8654', '455988cd-132f-448d-9ef3-f9277e530a70', 'matching', 'Questions 27–31', NULL, '<p>Choose the correct heading for each paragraph from the list of headings below.</p>
', 'matching', 'null', 'null', '{"layoutType": "heading", "summaryText": null, "answerOptions": [{"optionText": "i Evidence of outdoor dwellings fire"}, {"optionText": "ii Learning to make"}, {"optionText": "iii A perfect place to live"}, {"optionText": "iv Examining the cave contents"}, {"optionText": "v Contrasting two types of home"}, {"optionText": "vi A vital source of power"}], "matchingItems": null}', 'null', '[{"content": "<p><strong>27. Paragraph A</strong></p>\n<ul>\n<li><strong>Đáp án: v. Contrasting two types of home</strong></li>\n<li><strong>Giải thích:</strong> Đoạn A đối chiếu hai loại nơi ở chính của người Neanderthal: <strong>caves</strong> (hang động) ở Tây Âu và <strong>open-air sites</strong> (nơi ở ngoài trời) ở phía Đông.</li>\n</ul>\n<p><strong>28. Paragraph B</strong></p>\n<ul>\n<li><strong>Đáp án: iii. A perfect place to live</strong></li>\n<li><strong>Giải thích:</strong> Đoạn B mô tả khu vực Périgord là <strong>&#8220;ideal homes&#8221;</strong> (ngôi nhà lý tưởng) với khí hậu ôn hòa, nguồn thức ăn dồi dào và bảo vệ tốt.</li>\n</ul>\n<p><strong>29. Paragraph C</strong></p>\n<ul>\n<li><strong>Đáp án: i. Evidence of outdoor dwellings fire</strong></li>\n<li><strong>Giải thích:</strong> Đoạn C nói về các địa điểm ngoài trời ở Đông Âu, nơi các nhà khảo cổ tìm thấy bằng chứng về <strong>wind-break structures</strong> (chỗ trú gió) và <strong>ash</strong> (tro) trong vòng xương voi ma mút (minh chứng cho lửa/nơi ở ngoài trời).</li>\n</ul>\n<p><strong>30. Paragraph D</strong></p>\n<ul>\n<li><strong>Đáp án: iv. Examining the cave contents</strong></li>\n<li><strong>Giải thích:</strong> Đoạn D chi tiết hóa các vật phẩm và cấu trúc được tìm thấy trong hang động (Grotte du Lazaret và Baume-Bonne): vỏ sò, xương thú, tro, đá cuội, lều da.</li>\n</ul>\n<p><strong>31. Paragraph E</strong></p>\n<ul>\n<li><strong>Đáp án: vi. A vital source of power</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn E) &#8220;survival in the <strong>sub-arctic conditions</strong> faced by the Neanderthalers is <strong>inconceivable without control of fire</strong>.&#8221;</li>\n<li><strong>Giải thích:</strong> Lửa là thứ không thể thiếu (vital source of power) để sưởi ấm, nấu ăn và phòng thủ.</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('84a566e2-a8e7-46af-9fc4-98e2a2e59553', 'c4c786e9-5a41-4f9a-a64d-2d81c42e3c2d', 'fillup', 'Questions 15 – 20', '<p>Complete the sentences below.</p>
<p>Choose<strong> ONE WORD ONLY</strong> from the text for each answer.</p>
<p>Write your answers in boxes 15-20 on your answer sheet.</p>
<p>Relevant {software} can be purchased, but it cannot turn someone into a team leader.</p>
<p>A project is a {temporary} activity because its purpose is to achieve one particular result.</p>
<p>Successful project leaders make use of a {combination} of leadership styles.</p>
<p>The project team is likely to consist of {externals} plus people from the leader’s company.</p>
<p>Remember to deal with whatever {concerns} the team may have.</p>
<p>If the project has to keep to a strict {budget} , make full use of any unpaid help.</p>', '', 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p><strong data-path-to-node=\"4\" data-index-in-node=\"0\">15. Relevant {software} can be purchased, but it cannot turn someone into a team leader.</strong></p>\n<ul data-path-to-node=\"5\">\n<li><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 2):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“Project management <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"40\">software</strong> is of course available for a <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"78\">reasonable charge</strong>, but this will <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"111\">not help you</strong> if you can’t do the key task of <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"156\">leading a team</strong>!”</em></li>\n<li><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Relevant software” (phần mềm liên quan) tương ứng với “Project management software”. “Can be purchased” (có thể mua) tương ứng với “available for a reasonable charge”. Bài đọc nhấn mạnh phần mềm không giúp ích nếu bạn không biết dẫn dắt (cannot turn someone into a team leader).</li>\n</ul>\n<p><strong data-path-to-node=\"6\" data-index-in-node=\"0\">16. A project is a {temporary} activity because its purpose is to achieve one particular result.</strong></p>\n<ul data-path-to-node=\"7\">\n<li><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Mục “What is a project?”):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"38\">“A project is undertaken to <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"66\">create a certain outcome</strong>, so it is <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"101\">temporary</strong> in nature.”</em></li>\n<li><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Achieve one particular result” tương ứng với “create a certain outcome”. Do đó, tính chất của dự án là mang tính tạm thời (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"136\">temporary</strong>), khác với công việc vận hành hàng ngày.</li>\n</ul>\n<p><strong data-path-to-node=\"8\" data-index-in-node=\"0\">17. Successful project leaders make use of a {combination} of leadership styles.</strong></p>\n<ul data-path-to-node=\"9\">\n<li><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Mục “Leading a project team”):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"42\">“Effective leadership requires a <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"75\">combination</strong> of both styles [task-oriented and people-oriented].”</em></li>\n<li><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Successful project leaders” tương ứng với “Effective leadership”. Một người lãnh đạo giỏi cần sử dụng sự kết hợp (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"127\">combination</strong>) của cả hai phong cách: tập trung vào công việc và tập trung vào con người.</li>\n</ul>\n<p><strong data-path-to-node=\"10\" data-index-in-node=\"0\">18. The project team is likely to consist of {externals} plus people from the leader’s company.</strong></p>\n<ul data-path-to-node=\"11\">\n<li><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng (Mục “Building the ideal project team”):</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"51\">“These will probably include <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"80\">employees of the organisation</strong> as well as <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"121\">externals</strong>.”</em></li>\n<li><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “People from the leader’s company” tương ứng với “employees of the organisation”. Ngoài nhân viên nội bộ, đội ngũ dự án thường bao gồm cả những người từ bên ngoài (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"176\">externals</strong>).</li>\n</ul>\n<p><strong data-path-to-node=\"12\" data-index-in-node=\"0\">19. Remember to deal with whatever {concerns} the team may have.</strong></p>\n<ul data-path-to-node=\"13\">\n<li><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng (Mục “Building the ideal project team”):</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"51\">“Discuss and sort out any <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"77\">concerns</strong>“</em></li>\n<li><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Deal with” (giải quyết) đồng nghĩa với “sort out”. Người lãnh đạo cần thảo luận và giải quyết bất kỳ lo ngại hay thắc mắc nào (<strong data-path-to-node=\"13,1,0\" data-index-in-node=\"140\">concerns</strong>) của các thành viên.</li>\n</ul>\n<p><strong data-path-to-node=\"14\" data-index-in-node=\"0\">20. If the project has to keep to a strict {budget}, make full use of any unpaid help.</strong></p>\n<ul data-path-to-node=\"15\">\n<li><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn cuối):</strong> <em data-path-to-node=\"15,0,0\" data-index-in-node=\"23\">“This can help to achieve project management on a <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"73\">tight budget</strong>, as long as everyone’s roles are well defined…”</em></li>\n<li><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Keep to a strict budget” tương ứng với “tight budget”. Khi ngân sách eo hẹp, việc tận dụng sự trợ giúp không chính thức/không trả lương (informal advisors and helpers/unpaid help) là một giải pháp hữu hiệu.</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('2265d2be-34aa-4443-8a00-f93529ee78c0', 'c4c786e9-5a41-4f9a-a64d-2d81c42e3c2d', 'fillup', 'Questions 21 – 27', '<p>Complete the notes below.</p>
<p>Choose <strong>ONE WORD ONLY</strong> from the text for each answer.</p>
<p>Write your answers in boxes 21-27 on your answer sheet.</p>
<p style="text-align: center;"><span style="font-size: 12pt;"><strong data-path-to-node="8" data-index-in-node="0">Guidelines for the interview panel</strong></span></p>
<p><strong data-path-to-node="9" data-index-in-node="0">The Chair must</strong></p>
<ul data-path-to-node="10">
<li>
<p>begin by carrying out {introductions} of all panel members</p>
</li>
<li>
<p>be ready to cope with {emergencies} e.g. alarms sounding</p>
</li>
<li>
<p>interrupt at any hint of {discrimination} in the panel’s questioning</p>
</li>
<li>
<p>ensure each interview follows a {structure} that covers similar areas</p>
</li>
</ul>
<p><strong data-path-to-node="11" data-index-in-node="0">Panel members should</strong></p>
<ul data-path-to-node="12">
<li>
<p>make sure they only pay attention to a candidate’s {presentation} if the job requires it</p>
</li>
<li>
<p>sit in a position which shows that they are listening</p>
</li>
<li>
<p>avoid negative facial expressions e.g. a {frown}</p>
</li>
<li>
<p>write down {facts} and not personal views on their forms</p>
</li>
</ul>', '', 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p><strong data-path-to-node=\"4\" data-index-in-node=\"0\">21. begin by carrying out {introductions} of all panel members</strong></p>\n<ul data-path-to-node=\"5\">\n<li><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"11\">“The first step is to <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"33\">open with introductions</strong> of the interviewers…”</em></li>\n<li><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Begin” tương ứng với “The first step” và “open with”. Công việc đầu tiên của Chủ tịch là giới thiệu các thành viên trong hội đồng phỏng vấn.</li>\n</ul>\n<p><strong data-path-to-node=\"6\" data-index-in-node=\"0\">22. be ready to cope with {emergencies} e.g. alarms sounding</strong></p>\n<ul data-path-to-node=\"7\">\n<li><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"11\">“It will also be the Chair’s responsibility to deal with any <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"72\">emergencies</strong> – a candidate who becomes unwell, or <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"121\">alarms going off</strong>.”</em></li>\n<li><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Cope with” đồng nghĩa với “deal with”. Ví dụ về chuông báo động (alarms sounding/going off) cho thấy đây là các tình huống khẩn cấp (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"146\">emergencies</strong>).</li>\n</ul>\n<p><strong data-path-to-node=\"8\" data-index-in-node=\"0\">23. interrupt at any hint of {discrimination} in the panel’s questioning</strong></p>\n<ul data-path-to-node=\"9\">\n<li><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"11\">“The Chair must also <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"32\">intervene</strong> if a line of questioning could be seen as involving <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"94\">discrimination</strong> in any way.”</em></li>\n<li><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Interrupt” (ngắt lời) tương ứng với “intervene” (can thiệp). Chủ tịch phải can thiệp ngay nếu các câu hỏi có dấu hiệu phân biệt đối xử (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"149\">discrimination</strong>).</li>\n</ul>\n<p><strong data-path-to-node=\"10\" data-index-in-node=\"0\">24. ensure each interview follows a {structure} that covers similar areas</strong></p>\n<ul data-path-to-node=\"11\">\n<li><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"11\">“To ensure all candidates are treated equally, a <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"60\">planned structure</strong> is essential.”</em></li>\n<li><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Để đảm bảo tính công bằng và các ứng viên được hỏi các lĩnh vực tương đương, cuộc phỏng vấn cần có một cấu trúc (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"125\">structure</strong>) đã được lập kế hoạch trước.</li>\n</ul>\n<p><strong data-path-to-node=\"12\" data-index-in-node=\"0\">25. make sure they only pay attention to a candidate’s {presentation} if the job requires it</strong></p>\n<ul data-path-to-node=\"13\">\n<li><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"11\">“One of the limitations… is that <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"46\">presentation</strong> can be the main factor assessed. <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"92\">Depending on the job</strong> in question, this <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"131\">may or may not be an important skill</strong>.”</em></li>\n<li><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Pay attention to” tương ứng với “assessed” (đánh giá). Việc đánh giá vẻ ngoài/cách trình bày (<strong data-path-to-node=\"13,1,0\" data-index-in-node=\"107\">presentation</strong>) của ứng viên chỉ nên thực hiện nếu công việc đó thực sự cần kỹ năng này.</li>\n</ul>\n<p><strong data-path-to-node=\"14\" data-index-in-node=\"0\">26. avoid negative facial expressions e.g. a {frown}</strong></p>\n<ul data-path-to-node=\"15\">\n<li><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"15,0,0\" data-index-in-node=\"11\">“…as is leaning back in a chair… and a <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"54\">frown</strong>, which seems to indicate profound disagreement.”</em></li>\n<li><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Negative facial expressions” (biểu cảm gương mặt tiêu cực) ở đây ví dụ là sự cau mày (<strong data-path-to-node=\"15,1,0\" data-index-in-node=\"99\">frown</strong>) – một hành động thể hiện sự không đồng tình sâu sắc.</li>\n</ul>\n<p><strong data-path-to-node=\"16\" data-index-in-node=\"0\">27. write down {facts} and not personal views on their forms</strong></p>\n<ul data-path-to-node=\"17\">\n<li><strong data-path-to-node=\"17,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"17,0,0\" data-index-in-node=\"11\">“Notes should record <strong data-path-to-node=\"17,0,0\" data-index-in-node=\"32\">facts</strong> rather than <strong data-path-to-node=\"17,0,0\" data-index-in-node=\"50\">opinions</strong>.”</em></li>\n<li><strong data-path-to-node=\"17,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Write down” tương ứng với “record”. “Personal views” (quan điểm cá nhân) tương ứng với “opinions”. Người phỏng vấn chỉ nên ghi lại các sự thật/dữ liệu khách quan (<strong data-path-to-node=\"17,1,0\" data-index-in-node=\"176\">facts</strong>).</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('7d62be44-9427-45a2-b520-978e97d4080a', 'd26d0cca-9498-4b9e-91e4-2383a2c39a59', 'fillup', 'Questions 31–40', '<p>Write<strong> ONE WORD ONLY</strong> for each answer.</p>
<p><span style="font-size: 12pt;"><strong>Plant Behaviour</strong></span></p>
<p><strong>Changing ideas</strong></p>
<p>Scientists once thought of plants as being {passive} organisms.<br />
Now there is evidence that this is not true.</p>
<p><strong>Recent studies</strong></p>
<p><strong>Great Lakes sea rocket</strong></p>
<p>Found on {beaches}<br />
When near other plants, it normally produces extra {roots} to compete for nutrients.<br />
However, it behaves differently if it is related to the other plants.</p>
<p><strong>Sagebrush and thomapple</strong></p>
<p>Recognise surrounding plants by the type of {light} that they reflect.<br />
Identification is possible because all plants have a particular {signature}</p>
<p><strong>Dodder plant</strong></p>
<p>Is unable to produce {sugar}<br />
Needs to feed off another plant to survive.<br />
Affects farmers’ crops, e.g. alfalfa, {potatoes}, and citrus.<br />
Identifies suitable “hosts” by detecting the {chemicals} they give off.<br />
Moves in a {circle} to check the environment, then grows towards the most suitable host.</p>
<p><strong>Plant science</strong></p>
<p>Use of modern {equipment} provides evidence of plant behaviour.</p>
', NULL, 'fill-in-the-blank', 'null', 'null', 'null', 'null', '[{"content": "<p data-start=\"383\" data-end=\"449\"><strong data-start=\"383\" data-end=\"396\">LECTURER:</strong> Good morning everyone.<br data-start=\"419\" data-end=\"422\" />🎧 <em data-start=\"425\" data-end=\"449\">Chào buổi sáng các em.</em></p>\n<p data-start=\"451\" data-end=\"676\"><strong data-start=\"451\" data-end=\"464\">LECTURER:</strong> In the last few weeks, we looked at ways in which different types of animals use their senses.<br data-start=\"559\" data-end=\"562\" />🎧 <em data-start=\"565\" data-end=\"676\">Trong vài tuần qua, chúng ta đã tìm hiểu cách mà các loài động vật khác nhau sử dụng các giác quan của chúng.</em></p>\n<p data-start=\"678\" data-end=\"1006\"><strong data-start=\"678\" data-end=\"691\">LECTURER:</strong> And today, I’m going to introduce the topic of <strong data-start=\"739\" data-end=\"758\">plant behaviour</strong>, and we’ll look at the reasons why ideas about plants have been changing in the last few years.<br data-start=\"854\" data-end=\"857\" />🎧 <em data-start=\"860\" data-end=\"1006\">Hôm nay, cô sẽ giới thiệu chủ đề <strong data-start=\"894\" data-end=\"918\">hành vi của thực vật</strong>, và tìm hiểu lý do tại sao quan điểm về thực vật lại thay đổi trong những năm gần đây.</em></p>\n<hr data-start=\"1008\" data-end=\"1011\" />\n<p data-start=\"1013\" data-end=\"1349\"><strong data-start=\"1013\" data-end=\"1026\">LECTURER:</strong> So, up until fairly recently, plants’ lack of eyes or ears or noses or mouths made them less interesting to many members of the public compared to animal species.<br data-start=\"1189\" data-end=\"1192\" />🎧 <em data-start=\"1195\" data-end=\"1349\">Cho đến gần đây, việc thực vật không có mắt, tai, mũi hay miệng khiến chúng trở nên kém thú vị hơn nhiều so với các loài động vật, trong mắt công chúng.</em></p>\n<p data-start=\"1351\" data-end=\"1638\"><strong data-start=\"1351\" data-end=\"1364\">LECTURER:</strong> And even by scientists, they were generally regarded as organisms which were essentially <strong data-start=\"1454\" data-end=\"1480\">(Question 31) passive.</strong><br data-start=\"1480\" data-end=\"1483\" />🎧 <em data-start=\"1486\" data-end=\"1611\">Và ngay cả với các nhà khoa học, chúng thường được xem là những sinh vật <strong data-start=\"1560\" data-end=\"1582\">thụ động (passive)</strong>, không có phản ứng đáng kể.</em><br data-start=\"1611\" data-end=\"1614\" />✅ <strong data-start=\"1616\" data-end=\"1638\">Answer 31: passive</strong></p>\n<hr data-start=\"1640\" data-end=\"1643\" />\n<p data-start=\"1645\" data-end=\"1947\"><strong data-start=\"1645\" data-end=\"1658\">LECTURER:</strong> However, in the last 20 years or so, evidence has started to emerge that plants can sense their surroundings in quite sophisticated ways.<br data-start=\"1796\" data-end=\"1799\" />🎧 <em data-start=\"1802\" data-end=\"1947\">Tuy nhiên, khoảng 20 năm trở lại đây, đã xuất hiện nhiều bằng chứng cho thấy thực vật có thể “cảm nhận” môi trường xung quanh một cách tinh vi.</em></p>\n<p data-start=\"1949\" data-end=\"2261\"><strong data-start=\"1949\" data-end=\"1962\">LECTURER:</strong> But because scientific attitudes towards plants and their capabilities had been fixed for such a long time, this evidence has been met with some disbelief.<br data-start=\"2118\" data-end=\"2121\" />🎧 <em data-start=\"2124\" data-end=\"2261\">Nhưng vì quan điểm khoa học về khả năng của thực vật đã bị đóng khung quá lâu, nên những bằng chứng mới này ban đầu thường bị nghi ngờ.</em></p>\n<hr data-start=\"2263\" data-end=\"2266\" />\n<p data-start=\"2268\" data-end=\"2522\"><strong data-start=\"2268\" data-end=\"2281\">LECTURER:</strong> So, let’s look at some of these recent findings that are starting to change the way some scientists view plant life.<br data-start=\"2398\" data-end=\"2401\" />🎧 <em data-start=\"2404\" data-end=\"2522\">Giờ hãy cùng xem một số phát hiện gần đây đang dần thay đổi cách các nhà khoa học nhìn nhận về sự sống của thực vật.</em></p>\n<hr data-start=\"2524\" data-end=\"2527\" />\n<p data-start=\"2529\" data-end=\"2761\"><strong data-start=\"2529\" data-end=\"2542\">LECTURER:</strong> It all began with a Canadian study that looked at a species of plant known as the <strong data-start=\"2625\" data-end=\"2651\">Great Lakes sea rocket</strong>.<br data-start=\"2652\" data-end=\"2655\" />🎧 <em data-start=\"2658\" data-end=\"2761\">Tất cả bắt đầu với một nghiên cứu ở Canada về một loài thực vật có tên là <strong data-start=\"2733\" data-end=\"2759\">Great Lakes sea rocket</strong>.</em></p>\n<p data-start=\"2763\" data-end=\"2934\"><strong data-start=\"2763\" data-end=\"2776\">LECTURER:</strong> This is a wild plant which grows on <strong data-start=\"2813\" data-end=\"2839\">(Question 32) beaches.</strong><br data-start=\"2839\" data-end=\"2842\" />🎧 <em data-start=\"2845\" data-end=\"2907\">Đây là một loài cây dại mọc trên <strong data-start=\"2879\" data-end=\"2905\">các bãi biển (beaches)</strong>.</em><br data-start=\"2907\" data-end=\"2910\" />✅ <strong data-start=\"2912\" data-end=\"2934\">Answer 32: beaches</strong></p>\n<hr data-start=\"2936\" data-end=\"2939\" />\n<p data-start=\"2941\" data-end=\"3129\"><strong data-start=\"2941\" data-end=\"2954\">LECTURER:</strong> In appearance, it’s perfectly ordinary, with little purple flowers and a long stalk.<br data-start=\"3039\" data-end=\"3042\" />🎧 <em data-start=\"3045\" data-end=\"3129\">Bề ngoài, trông nó rất bình thường, có những bông hoa nhỏ màu tím và một thân dài.</em></p>\n<p data-start=\"3131\" data-end=\"3248\"><strong data-start=\"3131\" data-end=\"3144\">LECTURER:</strong> But actually, the plant is far from ordinary.<br data-start=\"3190\" data-end=\"3193\" />🎧 <em data-start=\"3196\" data-end=\"3248\">Nhưng trên thực tế, loài cây này lại rất đặc biệt.</em></p>\n<p data-start=\"3250\" data-end=\"3510\"><strong data-start=\"3250\" data-end=\"3263\">LECTURER:</strong> Normally, when the sea rocket detects other plants growing nearby, it quickly grows additional <strong data-start=\"3359\" data-end=\"3382\">(Question 33) roots</strong>.<br data-start=\"3383\" data-end=\"3386\" />🎧 <em data-start=\"3389\" data-end=\"3485\">Thông thường, khi cây sea rocket phát hiện có cây khác mọc gần, nó sẽ mọc thêm <strong data-start=\"3469\" data-end=\"3483\">rễ (roots)</strong>.</em><br data-start=\"3485\" data-end=\"3488\" />✅ <strong data-start=\"3490\" data-end=\"3510\">Answer 33: roots</strong></p>\n<p data-start=\"3512\" data-end=\"3767\"><strong data-start=\"3512\" data-end=\"3525\">LECTURER:</strong> This is so it can compete with these other plants for the available nutrients in the soil by soaking up as many of them as possible.<br data-start=\"3658\" data-end=\"3661\" />🎧 <em data-start=\"3664\" data-end=\"3767\">Việc này giúp nó cạnh tranh chất dinh dưỡng với những cây khác bằng cách hấp thụ càng nhiều càng tốt.</em></p>\n<hr data-start=\"3769\" data-end=\"3772\" />\n<p data-start=\"3774\" data-end=\"4020\"><strong data-start=\"3774\" data-end=\"3787\">LECTURER:</strong> But scientists found that the sea rocket doesn’t do that when the surrounding plants are related to it.<br data-start=\"3891\" data-end=\"3894\" />🎧 <em data-start=\"3897\" data-end=\"4020\">Tuy nhiên, các nhà khoa học phát hiện rằng cây sea rocket không làm vậy nếu các cây xung quanh có quan hệ họ hàng với nó.</em></p>\n<p data-start=\"4022\" data-end=\"4260\"><strong data-start=\"4022\" data-end=\"4035\">LECTURER:</strong> And as even animals sometimes find this type of recognition difficult, such a finding was very unexpected.<br data-start=\"4142\" data-end=\"4145\" />🎧 <em data-start=\"4148\" data-end=\"4260\">Và vì ngay cả động vật cũng khó nhận biết được điều này, nên phát hiện ấy khiến giới khoa học vô cùng bất ngờ.</em></p>\n<hr data-start=\"4262\" data-end=\"4265\" />\n<p data-start=\"4267\" data-end=\"4515\"><strong data-start=\"4267\" data-end=\"4280\">LECTURER:</strong> Since then, it’s been suggested that two other plants may have a similar ability — these are sagebrush and thornapple.<br data-start=\"4399\" data-end=\"4402\" />🎧 <em data-start=\"4405\" data-end=\"4515\">Kể từ đó, người ta cho rằng hai loài khác, là “sagebrush” và “thornapple”, có thể cũng có khả năng tương tự.</em></p>\n<p data-start=\"4517\" data-end=\"4867\"><strong data-start=\"4517\" data-end=\"4530\">LECTURER:</strong> It’s been claimed that these plants can recognize the characteristics of their neighbors by sensing properties of the <strong data-start=\"4649\" data-end=\"4672\">(Question 34) light</strong> that is reflected from them.<br data-start=\"4701\" data-end=\"4704\" />🎧 <em data-start=\"4707\" data-end=\"4842\">Người ta cho rằng chúng có thể nhận biết đặc điểm của các cây xung quanh bằng cách cảm nhận <strong data-start=\"4800\" data-end=\"4820\">ánh sáng (light)</strong> phản chiếu từ chúng.</em><br data-start=\"4842\" data-end=\"4845\" />✅ <strong data-start=\"4847\" data-end=\"4867\">Answer 34: light</strong></p>\n<hr data-start=\"4869\" data-end=\"4872\" />\n<p data-start=\"4874\" data-end=\"5119\"><strong data-start=\"4874\" data-end=\"4887\">LECTURER:</strong> The reason they are able to do this is that all plant species are slightly different to each other in this respect.<br data-start=\"5003\" data-end=\"5006\" />🎧 <em data-start=\"5009\" data-end=\"5119\">Lý do chúng có thể làm được điều đó là vì mỗi loài thực vật có những khác biệt nhỏ về cách phản xạ ánh sáng.</em></p>\n<p data-start=\"5121\" data-end=\"5341\"><strong data-start=\"5121\" data-end=\"5134\">LECTURER:</strong> So each plant species has what you could call its own <strong data-start=\"5189\" data-end=\"5217\">(Question 35) signature.</strong><br data-start=\"5217\" data-end=\"5220\" />🎧 <em data-start=\"5223\" data-end=\"5312\">Vì vậy, mỗi loài cây đều có thể xem như có một <strong data-start=\"5271\" data-end=\"5303\">“dấu hiệu riêng” (signature)</strong> của nó.</em><br data-start=\"5312\" data-end=\"5315\" />✅ <strong data-start=\"5317\" data-end=\"5341\">Answer 35: signature</strong></p>\n<p data-start=\"396\" data-end=\"591\"><strong data-start=\"396\" data-end=\"409\">LECTURER:</strong> Another type of plant which can sense things in its surroundings is the <strong data-start=\"482\" data-end=\"498\">dodder plant</strong>.<br data-start=\"499\" data-end=\"502\" />🎧 <em data-start=\"505\" data-end=\"591\">Một loài thực vật khác cũng có thể cảm nhận môi trường xung quanh là <strong data-start=\"575\" data-end=\"589\">cây dodder</strong>.</em></p>\n<hr data-start=\"593\" data-end=\"596\" />\n<p data-start=\"598\" data-end=\"901\"><strong data-start=\"598\" data-end=\"611\">LECTURER:</strong> This plant is different from most others because it doesn’t have the ability to make <strong data-start=\"697\" data-end=\"720\">(Question 36) sugar</strong> by converting nutrients from the soil.<br data-start=\"759\" data-end=\"762\" />🎧 <em data-start=\"765\" data-end=\"876\">Loài này khác với hầu hết các cây khác vì nó không thể tạo ra <strong data-start=\"828\" data-end=\"845\">đường (sugar)</strong> từ chất dinh dưỡng trong đất.</em><br data-start=\"876\" data-end=\"879\" />✅ <strong data-start=\"881\" data-end=\"901\">Answer 36: sugar</strong></p>\n<hr data-start=\"903\" data-end=\"906\" />\n<p data-start=\"908\" data-end=\"1229\"><strong data-start=\"908\" data-end=\"921\">LECTURER:</strong> This means that as soon as the dodder has sprouted from a seed, it needs to find another plant in order to survive. In other words, it’s a parasite.<br data-start=\"1070\" data-end=\"1073\" />🎧 <em data-start=\"1076\" data-end=\"1229\">Điều này có nghĩa là ngay khi hạt dodder nảy mầm, nó phải tìm được một cây khác để sống ký sinh – nói cách khác, nó là loài <strong data-start=\"1201\" data-end=\"1227\">ký sinh trùng thực vật</strong>.</em></p>\n<hr data-start=\"1231\" data-end=\"1234\" />\n<p data-start=\"1236\" data-end=\"1577\"><strong data-start=\"1236\" data-end=\"1249\">LECTURER:</strong> Dodders infest a variety of food crops around the world as they wrap themselves like string around their target plants, and the effect can be devastating for farmers.<br data-start=\"1416\" data-end=\"1419\" />🎧 <em data-start=\"1422\" data-end=\"1577\">Cây dodder tấn công nhiều loại cây trồng trên thế giới bằng cách quấn quanh vật chủ như một sợi dây, và hậu quả có thể rất nghiêm trọng đối với nông dân.</em></p>\n<hr data-start=\"1579\" data-end=\"1582\" />\n<p data-start=\"1584\" data-end=\"1849\"><strong data-start=\"1584\" data-end=\"1597\">LECTURER:</strong> It’s particularly damaging to alfalfa as well as to <strong data-start=\"1650\" data-end=\"1676\">(Question 37) potatoes</strong> and different varieties of citrus.<br data-start=\"1711\" data-end=\"1714\" />🎧 <em data-start=\"1717\" data-end=\"1821\">Nó gây hại đặc biệt cho cỏ linh lăng, <strong data-start=\"1756\" data-end=\"1780\">khoai tây (potatoes)</strong> và các giống cây có múi như cam, chanh.</em><br data-start=\"1821\" data-end=\"1824\" />✅ <strong data-start=\"1826\" data-end=\"1849\">Answer 37: potatoes</strong></p>\n<hr data-start=\"1851\" data-end=\"1854\" />\n<p data-start=\"1856\" data-end=\"2057\"><strong data-start=\"1856\" data-end=\"1869\">LECTURER:</strong> At first, scientists were puzzled as to how the dodder knows which plants to prey on.<br data-start=\"1955\" data-end=\"1958\" />🎧 <em data-start=\"1961\" data-end=\"2057\">Ban đầu, các nhà khoa học bối rối không hiểu làm sao cây dodder biết chọn đúng cây để ký sinh.</em></p>\n<hr data-start=\"2059\" data-end=\"2062\" />\n<p data-start=\"2064\" data-end=\"2431\"><strong data-start=\"2064\" data-end=\"2077\">LECTURER:</strong> But now they’ve found that the plant can identify a suitable host by sensing the <strong data-start=\"2159\" data-end=\"2186\">(Question 38) chemicals</strong> that other plants release into the soil and air.<br data-start=\"2235\" data-end=\"2238\" />🎧 <em data-start=\"2241\" data-end=\"2402\">Nhưng giờ đây, họ phát hiện cây dodder nhận biết vật chủ thích hợp bằng cách phát hiện <strong data-start=\"2329\" data-end=\"2357\">các hóa chất (chemicals)</strong> mà cây khác tiết ra trong đất và không khí.</em><br data-start=\"2402\" data-end=\"2405\" />✅ <strong data-start=\"2407\" data-end=\"2431\">Answer 38: chemicals</strong></p>\n<hr data-start=\"2433\" data-end=\"2436\" />\n<p data-start=\"2438\" data-end=\"2701\"><strong data-start=\"2438\" data-end=\"2451\">LECTURER:</strong> What really surprised researchers was how extremely quickly and accurately the dodder identifies a possible host.<br data-start=\"2565\" data-end=\"2568\" />🎧 <em data-start=\"2571\" data-end=\"2701\">Điều khiến các nhà nghiên cứu ngạc nhiên là cây dodder xác định vật chủ tiềm năng một cách nhanh chóng và chính xác đến mức nào.</em></p>\n<hr data-start=\"2703\" data-end=\"2706\" />\n<p data-start=\"2708\" data-end=\"3231\"><strong data-start=\"2708\" data-end=\"2721\">LECTURER:</strong> They used time-lapse videos to study the mechanism and saw from these that when the dodder is trying to check out its environment, it rotates in a <strong data-start=\"2869\" data-end=\"2893\">(Question 39) circle</strong>, and then, without touching any other plants, it heads directly towards its selected host.<br data-start=\"2984\" data-end=\"2987\" />🎧 <em data-start=\"2990\" data-end=\"3205\">Họ đã dùng video tua nhanh thời gian để nghiên cứu và nhận thấy rằng khi cây dodder thăm dò môi trường, nó xoay <strong data-start=\"3103\" data-end=\"3131\">thành vòng tròn (circle)</strong>, rồi – không chạm vào bất kỳ cây nào – mọc thẳng đến vật chủ mà nó chọn.</em><br data-start=\"3205\" data-end=\"3208\" />✅ <strong data-start=\"3210\" data-end=\"3231\">Answer 39: circle</strong></p>\n<hr data-start=\"3233\" data-end=\"3236\" />\n<p data-start=\"3238\" data-end=\"3506\"><strong data-start=\"3238\" data-end=\"3251\">LECTURER:</strong> Scientists who were working on the project reported that the dodder sprout resembled a worm as it moved towards the other plant.<br data-start=\"3380\" data-end=\"3383\" />🎧 <em data-start=\"3386\" data-end=\"3506\">Các nhà khoa học tham gia dự án cho biết mầm cây dodder trông giống như một con sâu khi nó di chuyển về phía cây khác.</em></p>\n<hr data-start=\"3508\" data-end=\"3511\" />\n<p data-start=\"3513\" data-end=\"3700\"><strong data-start=\"3513\" data-end=\"3526\">LECTURER:</strong> Well, those are some examples of the new discoveries about plant characteristics.<br data-start=\"3608\" data-end=\"3611\" />🎧 <em data-start=\"3614\" data-end=\"3700\">Trên đây là một vài ví dụ về những khám phá mới liên quan đến đặc tính của thực vật.</em></p>\n<hr data-start=\"3702\" data-end=\"3705\" />\n<p data-start=\"3707\" data-end=\"3850\"><strong data-start=\"3707\" data-end=\"3720\">LECTURER:</strong> So, which direction is plant science likely to go in next?<br data-start=\"3779\" data-end=\"3782\" />🎧 <em data-start=\"3785\" data-end=\"3850\">Vậy, hướng nghiên cứu tiếp theo của khoa học thực vật sẽ là gì?</em></p>\n<hr data-start=\"3852\" data-end=\"3855\" />\n<p data-start=\"3857\" data-end=\"4195\"><strong data-start=\"3857\" data-end=\"3870\">LECTURER:</strong> Many of the phenomena related to plant behaviour that I’ve just described are now quite easy to observe using up-to-date <strong data-start=\"3992\" data-end=\"4019\">(Question 40) equipment</strong>.<br data-start=\"4020\" data-end=\"4023\" />🎧 <em data-start=\"4026\" data-end=\"4166\">Hiện nay, nhiều hiện tượng liên quan đến hành vi của thực vật mà cô vừa nói có thể dễ dàng quan sát nhờ <strong data-start=\"4131\" data-end=\"4164\">thiết bị hiện đại (equipment)</strong>.</em><br data-start=\"4166\" data-end=\"4169\" />✅ <strong data-start=\"4171\" data-end=\"4195\">Answer 40: equipment</strong></p>\n<hr data-start=\"4197\" data-end=\"4200\" />\n<p data-start=\"4202\" data-end=\"4428\"><strong data-start=\"4202\" data-end=\"4215\">LECTURER:</strong> So gradually, scientists are accepting the fact that plants are more capable than we used to believe.<br data-start=\"4317\" data-end=\"4320\" />🎧 <em data-start=\"4323\" data-end=\"4428\">Vì vậy, dần dần, giới khoa học đang chấp nhận thực tế rằng thực vật có khả năng nhiều hơn ta từng nghĩ.</em></p>\n"}]', 0);
INSERT INTO public.questions VALUES ('7b597fb4-bd42-4393-b5b1-6abf32191bf4', '542b2040-3f68-499d-a7b0-f76d6580181c', 'radio', 'Questions 24 – 26', NULL, '<p>Choose the correct letter, A, B, C or D.<br />
Write the correct letter in boxes 24–26 on your answer sheet.</p>
', 'multiple_choice_single', '[{"correct": 1, "options": [{"content": "A. allow sound to be heard at a greater distance."}, {"content": "B. adapt itself to different kinds of background noise."}, {"content": "C. allow a user to remove all types of sound completely."}, {"content": "D. adapt itself to disorders involving other senses."}], "question": "Turner’s team are now planning a new development involving a device which could"}, {"correct": 0, "options": [{"content": "A. can currently use to help their condition."}, {"content": "B. might choose to use if they were available."}, {"content": "C. hear in their ears as a result of their condition."}, {"content": "D. find to be the most natural solutions to their problem."}], "question": "In section E, a stream, waves and leaves are examples of the sounds that tinnitus sufferers"}, {"correct": 0, "options": [{"content": "A. unwanted noise could be erased from video recordings."}, {"content": "B. some environments are difficult for the hearing-impaired."}, {"content": "C. when noises are combined in a video they are difficult to erase."}, {"content": "D. people must cooperate in order to learn how to apply the technology."}], "question": "The writer refers to ‘a busy roadside on a windy day’ in section F to illustrate that"}]', 'null', 'null', 'null', '[{"content": "<p>24. B – adapt itself to different kinds of background noise<br />\n(Đoạn 3: “Future devices will have several different modes… The device might intelligently select an appropriate mode based on the characteristics of the incoming sound.”)<br />\n→ Turner và nhóm đang phát triển thiết bị có thể tự điều chỉnh phù hợp với từng loại tiếng ồn nền.<br />\n→ Do đó, đáp án đúng là B – adapt itself to different kinds of background noise.</p>\n<p>25. A – can currently use to help their condition<br />\n(Đoạn 5: “At present, people with tinnitus sometimes use environmental sound generators as a distraction… such generators offer only a limited selection of sounds — a gently flowing stream, waves lapping on the seashore, or leaves rustling.”)<br />\n→ Các ví dụ “stream, waves, leaves” là những âm thanh mà hiện nay người bị ù tai (tinnitus) đang sử dụng để giúp họ giảm chú ý vào tiếng ù.<br />\n→ Do đó, đáp án đúng là A – can currently use to help their condition.</p>\n<p>26. A – unwanted noise could be erased from video recordings<br />\n(Đoạn 6: “A video containing a conversation that takes place by a busy roadside on a windy day could be made more intelligible by isolating the speech from the noises — users could even be offered the chance to de-noise their video during the upload process.”)<br />\n→ Hình ảnh “busy roadside on a windy day” được dùng để minh họa khả năng loại bỏ tiếng ồn khỏi video (de-noising).<br />\n→ Do đó, đáp án đúng là A – unwanted noise could be erased from video recordings.</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}]', 2);
INSERT INTO public.questions VALUES ('8b15a069-873d-4773-bd5c-64f247db9679', '86f7ac1f-88d1-4514-9bca-d6837758866d', 'fillup', 'Questions 31–40', '<p class="MsoNormal" style="margin-bottom: 0in; text-align: justify; line-height: normal; background: white;"><span style="font-size: 12.0pt; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Times; color: black;">Write <strong style="mso-bidi-font-weight: normal;">ONE WORD ONLY</strong> for each answer.</span><span style="font-size: 12.0pt; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Times; color: #15191e;"> </span></p>
<p class="MsoNormal" style="margin-bottom: 0in; line-height: normal; background: white; text-align: left;" align="center"><strong style="mso-bidi-font-weight: normal;"><span style="font-size: 14.0pt; mso-bidi-font-size: 12.0pt; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Times; color: #15191e;">Public Monument Assignment</span></strong></p>
<p class="MsoNormal" style="margin-bottom: 0in; text-align: justify; line-height: 150%; background: white;"><strong style="mso-bidi-font-weight: normal;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Times; color: #15191e;">Section one</span></strong></p>
<p class="MsoNormal" style="margin-bottom: 0in; text-align: justify; line-height: 150%; background: white;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Times; color: #15191e;">First, identify the monument and justify your choice</span></p>
<p class="MsoNormal" style="margin-bottom: 0in; text-align: justify; line-height: 150%; background: white;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Times; color: #15191e;">Comment on the </span><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Times; color: #15191e;"><strong>{success} </strong></span><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Times; color: #15191e;">of the monument</span></p>
<p class="MsoNormal" style="margin-bottom: 0in; text-align: justify; line-height: 150%; background: white;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Times; color: #15191e;">Add information about its:</span></p>
<p class="MsoNormal" style="text-align: justify; line-height: 150%; background: white; margin: 0in 0in 0in .5in;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Times; color: #15191e;">• geographical location</span></p>
<p class="MsoNormal" style="text-align: justify; line-height: 150%; background: white; margin: 0in 0in 0in .5in;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Times; color: #15191e;">• </span><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Times; color: #15191e;"><strong>{social} </strong></span><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Times; color: #15191e;">significance</span></p>
<p class="MsoNormal" style="text-align: justify; line-height: 150%; background: white; margin: 0in 0in 0in .5in;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Times; color: #15191e;">• historical context</span></p>
<p class="MsoNormal" style="margin-bottom: 0in; text-align: justify; line-height: 150%; background: white;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Times; color: #15191e;">Illustrate assignment with:</span></p>
<p class="MsoNormal" style="text-align: justify; line-height: 150%; background: white; margin: 0in 0in 0in .5in;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Times; color: #15191e;">• {plans}</span></p>
<p class="MsoNormal" style="text-align: justify; line-height: 150%; background: white; margin: 0in 0in 0in .5in;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Times; color: #15191e;">• photos (with captions)</span></p>
<p class="MsoNormal" style="margin-bottom: 0in; text-align: justify; line-height: 150%; background: white;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Times; color: #15191e;">End with: record of architect’s achievements</span></p>
<p class="MsoNormal" style="margin-bottom: 0in; text-align: justify; line-height: 150%; background: white;"><strong style="mso-bidi-font-weight: normal;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Times; color: #15191e;">Section two: Design and construction</span></strong></p>
<p class="MsoNormal" style="margin-bottom: 0in; text-align: justify; line-height: 150%; background: white;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Times; color: #15191e;">Include information about</span></p>
<p class="MsoNormal" style="text-align: justify; line-height: 150%; background: white; margin: 0in 0in 0in .5in;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Times; color: #15191e;">• The </span><strong><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Times; color: black;">{influence}</span></strong><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Times; color: #15191e;"> of any particular style on the design</span></p>
<p class="MsoNormal" style="text-align: justify; line-height: 150%; background: white; margin: 0in 0in 0in .5in;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Times; color: #15191e;">• The </span><strong><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Times; color: black;">{materials}</span></strong><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Times; color: #15191e;"> used in construction</span></p>
<p class="MsoNormal" style="text-align: justify; line-height: 150%; background: white; margin: 0in 0in 0in .5in;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Times; color: #15191e;">• Specialist </span><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Times; color: #15191e;"><strong>{skills} </strong></span><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Times; color: #15191e;">required</span></p>
<p class="MsoNormal" style="margin-bottom: 0in; text-align: justify; line-height: 150%; background: white;"><strong style="mso-bidi-font-weight: normal;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Times; color: #15191e;">Section three: Assessment of design</span></strong></p>
<p class="MsoNormal" style="margin-bottom: 0in; text-align: justify; line-height: 150%; background: white;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Times; color: #15191e;">Content should include:</span></p>
<p class="MsoNormal" style="text-align: justify; line-height: 150%; background: white; margin: 0in 0in 0in .5in;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Times; color: #15191e;">• personal assessment</span></p>
<p class="MsoNormal" style="text-align: justify; line-height: 150%; background: white; margin: 0in 0in 0in .5in;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Times; color: #15191e;">• results of your survey</span></p>
<p class="MsoNormal" style="margin-bottom: 0in; text-align: justify; line-height: 150%; background: white;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Times; color: #15191e;">Use personal assessment and survey to consider:</span></p>
<p class="MsoNormal" style="text-align: justify; line-height: 150%; background: white; margin: 0in 0in 0in .5in;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Times; color: #15191e;">• the </span><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Times; color: #15191e;"><strong>{reason}</strong></span><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Times; color: #15191e;"> for building the monument</span></p>
<p class="MsoNormal" style="text-align: justify; line-height: 150%; background: white; margin: 0in 0in 0in .5in;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Times; color: #15191e;">• the monument’s </span><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Times; color: #15191e;"><strong>{emotional} </strong></span><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Times; color: #15191e;">effect on members of the public</span></p>
<p class="MsoNormal" style="text-align: justify; line-height: 150%; background: white; margin: 0in 0in 0in .5in;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Times; color: #15191e;">• how well the monument suits its <strong>{environment}</strong></span></p>
<p class="MsoNormal" style="margin-bottom: 0in; text-align: justify; line-height: 150%; background: white;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Times; color: #15191e;">Remember!</span></p>
<p class="MsoNormal" style="margin-bottom: 0in; text-align: justify; line-height: 150%; background: white;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Times; color: #15191e;">Credit given for good </span><strong><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Times; color: black;">{analysis}</span></strong></p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p><strong>Narrator:</strong> You will hear a university lecturer talking to his students about an architectural studies assignment. First you have some time to look at questions 31 to 40 on pages 7 and eight. Now listen carefully and answer questions 31 to forty.</p>\n<p><strong>Lecturer:</strong> Okay, before this morning’s lecture on successful design of public buildings, I want to draw your attention to your next assignment. So your assignment is on public monuments, and by that I mean any structure or statue that is built to remind us of important events or of historic figures.</p>\n<blockquote>\n<p><strong>Dịch:</strong> Được rồi, trước bài giảng sáng nay về thiết kế thành công các tòa nhà công cộng, tôi muốn hướng sự chú ý của các bạn đến bài tập tiếp theo. Bài tập của các bạn là về các công trình kỷ niệm công cộng, và ý tôi là bất kỳ cấu trúc hoặc bức tượng nào được xây dựng để nhắc nhở chúng ta về các sự kiện quan trọng hoặc các nhân vật lịch sử.</p>\n</blockquote>\n<p>The assignment should be divided into three sections. At the beginning of Section 1, you should identify the monument you’re examining and say why you’ve chosen it. Include a comment on whether you think the Monument works—by that I mean its <strong>(31) success</strong>. You may think it’s wonderful, you may think it’s a public eyesore, something that people hate looking at. Next you should also include in this first section information about where the Monument was built, its geographical site, and also a discussion of its <strong>(32) social</strong> importance—how relevant it was for the people of the time. You should also include information on when it was built, its historical background, and make sure you illustrate the assignment appropriately too. I shall expect that <strong>(33) plans</strong> you can find and make sure any photographs you use have captions and are clearly referred to in the text, or they will be meaningless. To end this section, you should include something about the record of the person who designed the Monument, showing how the Monument relates to his or her other work.</p>\n<blockquote>\n<p><strong>Dịch:</strong> Bài tập nên được chia thành ba phần. Ở phần đầu tiên (Section 1), bạn nên xác định công trình kỷ niệm mà bạn đang xem xét và nói lý do tại sao bạn chọn nó. Đưa ra bình luận về việc bạn có nghĩ công trình đó có hiệu quả không—ý tôi là <strong>(31) sự thành công</strong> của nó. Bạn có thể nghĩ nó tuyệt vời, bạn có thể nghĩ nó là một vật chướng mắt công cộng, thứ mà mọi người ghét nhìn. Tiếp theo, bạn cũng nên bao gồm thông tin về nơi công trình được xây dựng, vị trí địa lý của nó, và thảo luận về ý nghĩa <strong>(32) xã hội</strong> của nó—mức độ liên quan của nó đối với người dân thời bấy giờ. Bạn cũng nên bao gồm thông tin về thời gian nó được xây dựng, bối cảnh lịch sử, và đảm bảo minh họa bài tập của bạn một cách thích hợp. Tôi sẽ mong đợi các <strong>(33) bản vẽ</strong> mà bạn có thể tìm thấy và đảm bảo bất kỳ bức ảnh nào bạn sử dụng đều có chú thích và được đề cập rõ ràng trong văn bản, nếu không chúng sẽ vô nghĩa. Để kết thúc phần này, bạn nên đưa vào điều gì đó về hồ sơ của người đã thiết kế công trình, cho thấy công trình đó liên quan như thế nào đến các tác phẩm khác của họ.</p>\n</blockquote>\n<hr />\n<p><strong>Lecturer:</strong> Right, in Section 2 of the assignment, you’ll need to give a detailed account of the design and construction of the Monument. Firstly, I want to read about any particular <strong>(34) influence</strong> you think is apparent in the design. More often than not there will be something in it that links it to an established style, Classical Greek for example, or it may reflect a movement like Bauhaus or Art Nouveau; you decide. Secondly, I want information about the choice of <strong>(35) materials</strong>—not only those which were used, but reasons why they may have been selected from others that were available at the time and in the area where the designer worked. Next I want a mention of any particular <strong>(36) skills</strong> that were necessary in the construction too.</p>\n<blockquote>\n<p><strong>Dịch:</strong> Đúng, trong Phần 2 của bài tập, bạn sẽ cần trình bày chi tiết về thiết kế và xây dựng công trình kỷ niệm. Thứ nhất, tôi muốn đọc về bất kỳ <strong>(34) ảnh hưởng</strong> cụ thể nào mà bạn nghĩ là rõ ràng trong thiết kế. Thông thường, sẽ có điều gì đó liên kết nó với một phong cách đã được thiết lập, ví dụ như Hy Lạp Cổ điển, hoặc nó có thể phản ánh một phong trào như Bauhaus hay Art Nouveau; bạn quyết định. Thứ hai, tôi muốn có thông tin về sự lựa chọn <strong>(35) vật liệu</strong>—không chỉ những thứ đã được sử dụng, mà cả lý do tại sao chúng có thể được chọn từ những vật liệu khác có sẵn vào thời điểm đó và trong khu vực nơi nhà thiết kế làm việc. Tiếp theo, tôi muốn đề cập đến bất kỳ <strong>(36) kỹ năng</strong> đặc biệt nào cần thiết trong quá trình xây dựng.</p>\n</blockquote>\n<hr />\n<p><strong>Lecturer:</strong> The third section is the most important one. Here you’ll go into much more critical detail. To add to your own comments, you’ll need to carry out a survey for this section to be as comprehensive and rounded as possible. Ask yourself and others the following questions. Firstly, was the <strong>(37) reason</strong> for erecting the Monument a valid one? For example, was it one that ordinary members of the public, the man or woman on the street, can readily relate to, and did it justify how much public money it cost? Was it a waste, or does it represent a sound cultural investment? Then think about its <strong>(38) emotional</strong> impact. When someone looks at it, how do they feel: angry, sad, indifferent? And don’t forget to consider how well the Monument sits in its <strong>(39) environment</strong>. Does it harmonize with it or does it clash with it, and is that important? Does it add to the effect or take away from it?</p>\n<blockquote>\n<p><strong>Dịch:</strong> Phần ba là phần quan trọng nhất. Ở đây, bạn sẽ đi sâu vào chi tiết phê bình hơn nhiều. Để bổ sung cho ý kiến ​​của riêng bạn, bạn sẽ cần thực hiện một cuộc khảo sát để phần này toàn diện và đầy đủ nhất có thể. Tự hỏi bản thân và những người khác các câu hỏi sau. Thứ nhất, <strong>(37) lý do</strong> xây dựng công trình kỷ niệm có hợp lệ không? Ví dụ, nó có phải là một lý do mà các thành viên bình thường của công chúng, người dân bình thường, có thể dễ dàng liên tưởng đến không, và nó có xứng đáng với số tiền công mà nó đã tiêu tốn không? Nó có phải là một sự lãng phí, hay nó đại diện cho một khoản đầu tư văn hóa đúng đắn? Sau đó, hãy nghĩ về tác động <strong>(38) cảm xúc</strong> của nó. Khi ai đó nhìn vào nó, họ cảm thấy thế nào: tức giận, buồn bã, thờ ơ? Và đừng quên xem xét mức độ phù hợp của công trình với <strong>(39) môi trường</strong> xung quanh. Nó có hòa hợp với môi trường hay đối lập với nó, và điều đó có quan trọng không? Nó tăng thêm hiệu ứng hay làm giảm bớt hiệu ứng?</p>\n</blockquote>\n<hr />\n<p><strong>Lecturer:</strong> Right, those guidelines should help. Oh, and remember, it is important to weigh up carefully how to make the maximum impact in this kind of critique within the number of words allowable. You don’t get extra marks for lots of factual information. You get those for a well constructed <strong>(40) analysis</strong>. That’s what counts, and that needs to be based on your personal opinion.</p>\n<blockquote>\n<p><strong>Dịch:</strong> Được rồi, những hướng dẫn đó sẽ giúp ích. Ồ, và hãy nhớ, điều quan trọng là phải cân nhắc cẩn thận cách tạo ra tác động tối đa trong loại phê bình này trong giới hạn số lượng từ cho phép. Bạn không nhận được điểm cộng cho nhiều thông tin thực tế. Bạn nhận được điểm cho một <strong>(40) phân tích</strong> được xây dựng tốt. Đó là điều quan trọng, và điều đó cần phải dựa trên ý kiến cá nhân của bạn.</p>\n</blockquote>\n<p><strong>Narrator:</strong> That is the end of Section 4. You now have half a minute to check your answers</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('60a3e809-6eb8-45a7-9e7c-89f67b4fc917', '455988cd-132f-448d-9ef3-f9277e530a70', 'matrix', 'Questions 32–36', NULL, '<p>Look at the following findings and the list of places below.</p>
<p>Match each finding with the correct place A-E.</p>
<p><em><strong>NB </strong>You may use any letter more than once.</em></p>
', 'other', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": "List of Places", "matrixItems": [{"itemText": "A burnt piece of wood", "correctCategoryLetter": "E"}, {"itemText": "Evidence of efforts to prevent pools of water forming", "correctCategoryLetter": "D"}, {"itemText": "The remains of sea creatures", "correctCategoryLetter": "C"}, {"itemText": "A circular arrangement of animal bones", "correctCategoryLetter": "B"}, {"itemText": "Evidence suggesting the use of animal fur for warmth", "correctCategoryLetter": "C"}], "matrixCategories": [{"categoryText": "The Périgord region", "categoryLetter": "A"}, {"categoryText": "Moldova", "categoryLetter": "B"}, {"categoryText": "The Grotte du Lazaret", "categoryLetter": "C"}, {"categoryText": "The cave of Baume-Bonne", "categoryLetter": "D"}, {"categoryText": "Krapina", "categoryLetter": "E"}]}', '[{"content": "<p><strong>32. a burnt piece of wood</strong></p>\n<ul>\n<li><strong>Đáp án: E</strong> (Krapina)</li>\n<li><strong>Dẫn chứng:</strong> (Đoạn E) &#8220;A <strong>charred piece of birch from Krapina</strong> in Croatia, is thought to be the remains of a fire-making twirl stick.&#8221;</li>\n</ul>\n<p><strong>33. evidence of efforts to prevent pools of water forming</strong></p>\n<ul>\n<li><strong>Đáp án: D</strong> (The cave of Baume-Bonne)</li>\n<li><strong>Dẫn chứng:</strong> (Đoạn D) &#8220;&#8230;The cave of <strong>Baume-Bonne</strong>&#8230; boasts ten square metres of cobbles&#8230; laid down, <strong>as though to take care of a puddle area</strong> in the cave&#8230;&#8221;</li>\n</ul>\n<p><strong>34. the remains of sea creatures</strong></p>\n<ul>\n<li><strong>Đáp án: C</strong> (The Grotte du Lazaret)</li>\n<li><strong>Dẫn chứng:</strong> (Đoạn D) &#8220;The two patches of ash at <strong>Lazaret</strong>&#8230; are <strong>edged with small marine molluse shells</strong>&#8230;&#8221;</li>\n</ul>\n<p><strong>35. a circular arrangement of animal bones</strong></p>\n<ul>\n<li><strong>Đáp án: B</strong> (Moldova)</li>\n<li><strong>Dẫn chứng:</strong> (Đoạn C) &#8220;From <strong>Moldova</strong>, for example, comes evidence that has been interpreted as the remains of&#8230; a large tent: <strong>n ring&#8230; of mainly mammoth bones</strong> enclosing a dense concentration of stone tools&#8230;&#8221;</li>\n</ul>\n<p><strong>36. evidence suggesting the use of animal fur for warmth</strong></p>\n<ul>\n<li><strong>Đáp án: C</strong> (The Grotte du Lazaret)</li>\n<li><strong>Dẫn chứng:</strong> (Đoạn D) &#8220;&#8230;finds of <strong>wolf and fox foot bones</strong>&#8230; inside these ‘tents’ have been thought to indicate the <strong>use of animal pelts as bed coverings</strong>.&#8221;</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('fd5b49b2-2b32-4626-83d6-a080f2c17123', '455988cd-132f-448d-9ef3-f9277e530a70', 'fillup', 'Questions 37–39', '<p>Complete the summary below.</p>
<p>Write <strong>NO MORE THAN TWO WORDS</strong> from the passage for each answer.</p>
<p style="text-align: center;"><strong>The use of fire</strong></p>
<p>Neanderthalers could not have survived without fire because the conditions they lived in were {sub-arctic} Most evidence of purpose-built fires takes the form of ash piles, features of which suggest that the fires lasted a {short} time. It is hard to be certain about the size and structure of the fires, though they were certainly needed to protect the occupants from dangerous {animals} among other things.</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p><strong>37. Neanderthalers could not have survived without fire because the conditions they lived in were sub-arctic&#8230;</strong></p>\n<ul>\n<li><strong>Đáp án:</strong> <strong>sub-arctic</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn E) &#8220;&#8230;survival in the <strong>sub-arctic conditions</strong> faced by the Neanderthalers is inconceivable without control of fire.&#8221;</li>\n</ul>\n<p><strong>38. &#8230;features of which suggest that the fires lasted a short time.</strong></p>\n<ul>\n<li><strong>Đáp án:</strong> <strong>short</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn E) &#8220;Judging from the shallow penetration of heat effects under the ash, this fire was only of a <strong>short duration</strong>.&#8221;</li>\n</ul>\n<p><strong>39. &#8230;to protect the occupants from dangerous animals among other things.</strong></p>\n<ul>\n<li><strong>Đáp án:</strong> <strong>animals</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn E) &#8220;Fire gave warmth, light, heat for cooking and <strong>defence against predatory animals</strong>.&#8221;</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('82e7d5dc-e858-4fa0-b5fe-e030fefa10f1', '2a652167-fe58-4517-a8e2-1ada73982b30', 'matrix', 'Questions 27-33', NULL, '<p>Look at the following statements (Questions 27–33) and the list of experts below.</p>
<p>Match each statement with the correct expert, A, B or C.</p>
<p>NB You may use any letter more than once.</p>
', 'other', NULL, '[{"option": "A", "correct": false}, {"option": "B", "correct": false}, {"option": "C", "correct": false}]', '{"layoutType": "standard", "summaryText": null, "answerOptions": null, "matchingItems": null}', '{"layoutType": "standard", "legendTitle": "List of experts", "matrixItems": [{"itemText": "For our own safety, humans will need to restrict the abilities of robots.", "correctCategoryLetter": "A"}, {"itemText": "The risk of robots harming us is less serious than humans believe it to be.", "correctCategoryLetter": "C"}, {"itemText": "It will take many decades for robot intelligence to be as imaginative as human intelligence.", "correctCategoryLetter": "B"}, {"itemText": "We may have to start considering whether we are treating robots fairly.", "correctCategoryLetter": "A"}, {"itemText": "Robots are probably of more help to us on Earth than in space.", "correctCategoryLetter": "B"}, {"itemText": "The ideas in high-quality science fiction may prove to be just as accurate as those found in the work of mediocre scientists.", "correctCategoryLetter": "A"}, {"itemText": "There are those who look forward to robots developing greater intelligence.", "correctCategoryLetter": "C"}], "matrixCategories": [{"categoryText": "Martin Rees", "categoryLetter": "A"}, {"categoryText": "Daniel Wolpert", "categoryLetter": "B"}, {"categoryText": "Kathleen Richardson", "categoryLetter": "C"}]}', '[{"content": "<p>27. For our own safety, humans will need to restrict the abilities of robots. → A (Martin Rees)<br />(Đoạn: “I think we should ensure that robots remain as no more than ‘idiot savants’ lacking the capacity to outwit us.”)<br />→ Rees cảnh báo rằng con người nên giới hạn khả năng của robot để đảm bảo an toàn.</p>\n<p> <br />28. The risk of robots harming us is less serious than humans believe it to be. → C (Kathleen Richardson)<br />(Đoạn: “We need to ask why fears of artificial intelligence and robots persist… none have in fact risen up and challenged human supremacy.”)<br />→ Richardson cho rằng nỗi sợ robot quá mức, thực tế chúng không hề đe dọa con người.</p>\n<p> <br />29. It will take many decades for robot intelligence to be as imaginative as human intelligence. → B (Daniel Wolpert)<br />(Đoạn: “Expecting a machine close to the creative intelligence of a human within the next 50 years would be highly ambitious.”)<br />→ Wolpert nói rằng trí thông minh sáng tạo của máy sẽ cần rất lâu mới bằng con người.</p>\n<p> <br />30. We may have to start considering whether we are treating robots fairly. → A (Martin Rees)<br />(Đoạn: “Should we feel guilty about exploiting sophisticated robots?&#8230; Should we fret if they are underemployed, frustrated, or bored?”)<br />→ Rees đặt ra câu hỏi đạo đức: con người có đang đối xử công bằng với robot không?</p>\n<p> <br />31. Robots are probably of more help to us on Earth than in space. → B (Daniel Wolpert)<br />(Đoạn: “Using robots to gather resources nearer to home would seem to be a better use of our robotic tools.”)<br />→ Wolpert cho rằng robot hữu ích hơn khi phục vụ trên Trái Đất.</p>\n<p> <br />32. The ideas in high-quality science fiction may prove to be just as accurate as those found in the work of mediocre scientists. → A (Martin Rees)<br />(Đoạn: “It’s better to read first-rate science fiction than second-rate science – more stimulating, and perhaps no more likely to be wrong.”)<br />→ Rees so sánh giá trị của sci-fi với khoa học tầm trung, cho rằng chúng có thể đúng ngang nhau.</p>\n<p> <br />33. There are those who look forward to robots developing greater intelligence. → C (Kathleen Richardson)<br />(Đoạn: “Not all fear robots; many people welcome machine intelligence.”)<br />→ Richardson nói rằng nhiều người hoan nghênh trí tuệ máy phát triển hơn nữa.</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('b9a314ab-a237-4283-b120-47cdda23f9db', '455988cd-132f-448d-9ef3-f9277e530a70', 'radio', 'Questions 40', NULL, '<p>Choose the correct answer.</p>
', 'multiple_choice_single', '[{"correct": 2, "options": [{"content": "A argue that Neanderthal homes were bigger than originally thought."}, {"content": "B explain why Neanderthal people migrated to Western Europe."}, {"content": "C discuss what is known about Neanderthal settlements."}, {"content": "D track the progress of early Neanderthal development"}], "question": "The purpose of the writer of this article is to"}]', 'null', 'null', 'null', '[{"content": "<p>40. The purpose of the writer of this article is to</p>\n<p>Đáp án: C. discuss what is known about Neanderthal settlements.<br />Giải thích: Toàn bộ bài đọc liệt kê và phân tích các bằng chứng khảo cổ về nơi ở, cấu trúc và cách sống (settlements) của người Neanderthal ở các khu vực khác nhau.</p>\n"}]', 3);
INSERT INTO public.questions VALUES ('ccd4ed60-6b04-4bbe-be4e-114ab7321467', 'c998782e-6b84-420b-aada-527740c37a19', 'radio', 'Questions 21-25', '', NULL, 'multiple_choice', '[{"correct": 0, "options": [{"option_text": "A take great skill to produce."}, {"option_text": "B are fascinating curved shapes."}, {"option_text": "C have interesting stories behind them."}], "question": " Amy and Mike agree that the greenstone tikis"}, {"correct": 2, "options": [{"option_text": "A Not many people know about them."}, {"option_text": "B They tend to be stolen by treasure hunters."}, {"option_text": "C The majority become inherited items."}], "question": "According to Amy, why are so few genuine old tikis found on archaeological dig sites?"}, {"correct": 1, "options": [{"option_text": "A decorative items."}, {"option_text": "B religious objects."}, {"option_text": "C tribal symbols."}], "question": "The Maori people considered tikis to be"}, {"correct": 2, "options": [{"option_text": "A where they originated."}, {"option_text": "B the materials used."}, {"option_text": "C the position of the body."}], "question": "Tikis are classified into one type or the other by"}, {"correct": 1, "options": [{"option_text": "A The materials differ."}, {"option_text": "B They are too regular in shape."}, {"option_text": "C They are of different sizes. "}], "question": "How can modern reproductions be easily distinguished from genuine Maori carving"}]', 'null', 'null', 'null', '[{"content": "<h3 class=\"\" data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">PART 3: MAORI GREENSTONE TIKIS</strong></h3>\n<p data-path-to-node=\"4\"><strong class=\"\" data-path-to-node=\"4\" data-index-in-node=\"0\">Amy:</strong><span class=\"\"> Hi Mike,</span><span class=\"\"> aren''t these New Zealand carvings we''ve been studying in class fascinating?</span></p>\n<p data-path-to-node=\"5\"><strong class=\"\" data-path-to-node=\"5\" data-index-in-node=\"0\">Mike:</strong><span class=\"\"> Oh hi Amy.</span><span class=\"\"> Oh,</span><span class=\"\"> the Maori greenstone Tikis?</span><span class=\"\"> They''re all a bit organic for my taste,</span><span class=\"\"> you know,</span><span class=\"\"> all curves and twisting shapes.</span><span class=\"\"> I like modern stuff,</span><span class=\"\"> geometric shapes.</span> <strong class=\"\" data-path-to-node=\"5\" data-index-in-node=\"170\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(Q21) But I can see the skill involved in making them</span>.</strong></p>\n<p data-path-to-node=\"6\"><strong class=\"\" data-path-to-node=\"6\" data-index-in-node=\"0\">Amy:</strong> <span class=\"\"> But the stories behind the Tikis are what make them interesting.</span><span class=\"\"> Besides,</span><span class=\"\"> I imagine it would be difficult to create geometric patterns; the shape of each Tiki seems to follow the natural contours of the stone.</span><span class=\"\"> It''s extremely hard and it requires expertise and time to shape.</span></p>\n<p data-path-to-node=\"7\"><strong class=\"\" data-path-to-node=\"7\" data-index-in-node=\"0\">Mike:</strong><span class=\"\"> <span style=\"background-color: #f1c40f;\"><strong>(Q21) That''s true, I suppose  that’s why modern greenstone carvings are so expensive.</strong></span></span><span class=\"\"> But there aren''t that many genuine old ones around.</span><span class=\"\"> Archaeologists rarely discover such treasures,</span><span class=\"\"> which is odd given they are such a huge part of Maori culture.</span><span class=\"\">I wonder if archaeological dig sites were raided and the Tikis were taken to sell?</span></p>\n<p data-path-to-node=\"9\"><span class=\"\"><strong class=\"\" data-path-to-node=\"6\" data-index-in-node=\"0\">Amy:</strong> I believe it’s because the owners valued them and so preserved them.</span> <strong class=\"\" data-path-to-node=\"9\" data-index-in-node=\"75\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(Q22) Many of them would have been passed down through the generations and remain in the possession of the families today, like heirlooms</span>.</strong></p>\n<p data-path-to-node=\"10\"><strong class=\"\" data-path-to-node=\"10\" data-index-in-node=\"0\">Amy:</strong><span class=\"\"> Do you know what they were used for?</span></p>\n<p data-path-to-node=\"10\"><span class=\"\"><strong class=\"\" data-path-to-node=\"11\" data-index-in-node=\"0\">Mike:</strong>I thought they were just an art form or a means of decoration.</span></p>\n<p data-path-to-node=\"11\"><strong class=\"\" data-path-to-node=\"11\" data-index-in-node=\"0\">Mike:</strong><span class=\"\"> But Professor Matthew says that the Maori believed Tikis were sacred and could be used as a pathway to their ancestors.</span> <strong class=\"\" data-path-to-node=\"11\" data-index-in-node=\"126\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(Q23) They believed the dead could speak to them through these talismans (religious objects)</span>.</strong></p>\n<p data-path-to-node=\"12\"><strong class=\"\" data-path-to-node=\"12\" data-index-in-node=\"0\">Amy:</strong><span class=\"\"> So they don''t represent tribes or anything.</span><span class=\"\"> Interesting!</span><span class=\"\"> How many different kinds are there?There must be hundreds of variations.</span></p>\n<p data-path-to-node=\"12\"><span class=\"\"><strong class=\"\" data-path-to-node=\"13\" data-index-in-node=\"0\">Mike:</strong>There are other greenstone carvings beside Tikis, although I can''t remember all their names. Traditional Tikis themselves can be divided into two distinct groups though.</span></p>\n<p data-path-to-node=\"13\"><span class=\"\"><strong class=\"\" data-path-to-node=\"14\" data-index-in-node=\"0\">Amy:</strong> Can they?</span><span class=\"\"> By the materials? I''ve seen some with metal features.</span><span class=\"\"> Or is it to do with size or where they were made??</span></p>\n<p data-path-to-node=\"14\"><strong class=\"\" data-path-to-node=\"15\" data-index-in-node=\"0\">Mike:</strong> <strong class=\"\" data-path-to-node=\"14\" data-index-in-node=\"5\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(Q24) Actually, it is the ways that their feet, heads, and hands are placed that make the major difference (position of the body)</span>.</strong></p>\n<p data-path-to-node=\"15\"><span class=\"\"><strong class=\"\" data-path-to-node=\"14\" data-index-in-node=\"0\">Amy:</strong> Is it easy to discern the difference between the ancient stones and more modern reproductions? Are the styles very different?</span></p>\n<p data-path-to-node=\"16\"><span class=\"\"><strong class=\"\" data-path-to-node=\"17\" data-index-in-node=\"0\">Mike:</strong>Modern reproductions usually use a different type of stone, although they may be of the same design. They may also be of a smaller size.</span><span class=\"\"> But it’s actually quite easy to tell if you are buying a genuine carving or a mass-produced souvenir.</span></p>\n<p data-path-to-node=\"17\"><span class=\"\"><strong class=\"\" data-path-to-node=\"18\" data-index-in-node=\"0\">Amy:</strong> How?</span></p>\n<p data-path-to-node=\"18\"><span class=\"\"><strong class=\"\" data-path-to-node=\"17\" data-index-in-node=\"0\">Mike:</strong> Nowadays they are produced by machine using lasers,</span><span class=\"\"> even so they have no blemishes.</span> <strong class=\"\" data-path-to-node=\"18\" data-index-in-node=\"89\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(Q25) In genuine carvings, they aren''t always perfect (too regular in shape) because the Maori used simple hand tools</span>.</strong><span class=\"\"> For example,</span><span class=\"\"> the hole that the cord is fed through isn''t perfectly round.</span></p>\n<p data-path-to-node=\"18\"><span class=\"\"><strong class=\"\" data-path-to-node=\"18\" data-index-in-node=\"0\">Amy:</strong>That makes sense.</span></p>\n<hr class=\"\" data-path-to-node=\"19\">\n<h3 class=\"\" data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">THE CARVING PROCESS (Questions 26–30)</strong></h3>\n<p data-path-to-node=\"21\"><span class=\"\"><strong class=\"\" data-path-to-node=\"22\" data-index-in-node=\"0\">Amy:</strong> Actually, it''s amazing that they produce such detailed Tikis with such simple tools and materials.Talk me through the process.</span><span class=\"\"> I know the basic shape is carved from New Zealand greenstone.</span></p>\n<p data-path-to-node=\"22\"><span class=\"\"><strong class=\"\" data-path-to-node=\"23\" data-index-in-node=\"0\">Mike:</strong> Yes,</span><span class=\"\"> but first they had to get a blank of the right size.</span></p>\n<p data-path-to-node=\"22\"><span class=\"\"><strong class=\"\" data-path-to-node=\"22\" data-index-in-node=\"0\">Amy: </strong>You mean a piece of stone of the right size and basic shape?</span></p>\n<p data-path-to-node=\"22\"><span class=\"\"><strong class=\"\" data-path-to-node=\"23\" data-index-in-node=\"0\">Mike:</strong>That''s right. They used a </span><span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong class=\"\" data-path-to-node=\"22\" data-index-in-node=\"75\">(Q26) hard stone tool (C - Stone scoring tool)</strong></span><span class=\"\">,</span><span class=\"\"> something rough,</span><span class=\"\"> to wear a groove into a piece of greenstone.</span><span class=\"\"> After they’d scored it with that,</span><span class=\"\"> they could just snap it in two.I guess they could have used some kind of hammer though. They repeated the process until they had a piece of stone suitable for what they wanted to carve—usually flat pieces for Tikis.</span></p>\n<p data-path-to-node=\"23\"><span class=\"\"><strong class=\"\" data-path-to-node=\"24\" data-index-in-node=\"0\">Amy:</strong> Right, because they''re fairly small and quite thin.Then they started carving?</span></p>\n<p class=\"animating\" data-path-to-node=\"24\"><span class=\"\"><strong class=\"\" data-path-to-node=\"25\" data-index-in-node=\"0\">Mike:</strong> Not right away.</span><span class=\"\"> Before they could start carving,</span><span class=\"\"> they needed an absolutely smooth,</span><span class=\"\"> flat surface. Nowadays, when we want to do something like that, we''d clamp the stone in a vice and use a sander. But</span> <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong class=\"\" data-path-to-node=\"24\" data-index-in-node=\"102\">(Q27) they used a heavy block of sandstone (A)</strong></span><span class=\"\"> and rubbed the piece of greenstone on it over and over to prepare it for carving.</span></p>\n<p class=\"animating\" data-path-to-node=\"25\"><span class=\"\"><strong class=\"\" data-path-to-node=\"26\" data-index-in-node=\"0\">Amy:</strong> It must have been very time-consuming. So how did they cut out the little details like hands and feet?</span></p>\n<p class=\"animating\" data-path-to-node=\"26\"><span class=\"\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">Mike:</strong> They had carving tools.They used small chips of stone glued and tied onto a wooden handle. Then</span> they also used a piece of <strong data-path-to-node=\"26\" data-index-in-node=\"57\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(Q28) sharpened bone made into a point (D - Bone point)</span>.</strong></p>\n<p data-path-to-node=\"27\"><strong data-path-to-node=\"28\" data-index-in-node=\"0\">Amy:</strong> Is that what they used to make the holes?</p>\n<p data-path-to-node=\"28\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">Mike:</strong> Actually, they had a special tool to make holes. <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"28\" data-index-in-node=\"54\">(Q29) It was a stick tied between two heavy pebbles (E - Stick drill)</strong></span> with a point at the end. They would wrap string around it, pull it back and forth to wear a hole into the Tiki.They used the same technique to make round shapes too, but didn''t make the hole go all the way through.</p>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"30\" data-index-in-node=\"0\">Amy:</strong> And I’ve seen some Tikis with coloured eyes or decorations. Are they painted?</p>\n<p data-path-to-node=\"30\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">Mike:</strong> Mostly they are inlaid with different coloured stone or mother of pearl from <strong data-path-to-node=\"11\" data-index-in-node=\"1929\">shells</strong>, or sometimes dyed pieces of bone. <strong data-path-to-node=\"30\" data-index-in-node=\"78\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(Q30) They were fixed in place using tarata gum, a sticky plant resin (B - Plant glue)</span>.</strong>They used plants to make the natural strings too?</p>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"30\" data-index-in-node=\"0\">Amy: </strong>That''s right. The Maori were very resourceful, weren''t they?</p>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"11\" data-index-in-node=\"2158\">Mike:</strong> They certainly were.</p>"}]', 0);
INSERT INTO public.questions VALUES ('a03407c7-7c45-416b-9200-8ec7cb713e7a', 'c998782e-6b84-420b-aada-527740c37a19', 'matching', 'Questions 26-30', '', '<p>What tool did Maoris use to carry out each of the following tasks?</p>
<p>Choose <strong>FIVE</strong> answers from the box and write the correct letter, <strong>A</strong>-<strong>E </strong>next to Question 26 -30</p>', 'summary_completion', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p> </p>\n<p> </p>\n<p>creating a blank {C Stone scoring tool}</p>\n<p> </p>\n<p>smoothing the surface {A Sandstone block}</p>\n<p> </p>\n<p>carving details {D Bone point}</p>\n<p> </p>\n<p>making holes {E Stick drill}</p>\n<p> </p>\n<p>fixing coloured {B Plant glue}</p>", "answerOptions": [{"optionText": "A Sandstone block"}, {"optionText": "B Plant glue"}, {"optionText": "C Stone scoring tool"}, {"optionText": "D Bone point"}, {"optionText": "E Stick drill"}], "matchingItems": []}', 'null', 'null', 1);
INSERT INTO public.questions VALUES ('8aef40c8-b1a7-403b-8b81-217db9326622', '597baadc-be27-4191-a973-89470c2898da', 'checkbox', 'Questions 21 and 22', '', '<p>Choose <strong>TWO</strong> letters, A-E.</p>
<p>Which are the <strong>TWO </strong>main duties for Personal Support Workers (PSWs)?</p>', 'multiple_choice', 'null', '[{"correct": false, "option_text": "talking with clients"}, {"correct": false, "option_text": "helping clients to eat and drink"}, {"correct": true, "option_text": "helping with physical needs"}, {"correct": true, "option_text": "ensuring clients are well and safe"}, {"correct": false, "option_text": "managing clients'' pills"}]', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">PART 3: PERSONAL SUPPORT WORKER PROGRAM</strong></h3>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Jason:</strong> Becky, hi! What are you doing here at the college?</p>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">Becky:</strong> Hi Jason. Just using the library. What about you?</p>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">Jason:</strong> I''m taking the PSW program—you know, Personal Support Worker.</p>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Becky:</strong> You''re kidding! I''ve just qualified as a PSW.</p>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">Jason:</strong> Really? I''d love to talk to you about the program.</p>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Becky:</strong> Okay. Well, first off, the main duties they taught me here were exactly what I needed on the job.</p>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">Jason:</strong> You mean like bathing and dressing people?</p>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Becky:</strong> Yes, young and old need this. You''ll work with people of all ages, from young people with disabilities to seniors. <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"11\" data-index-in-node=\"122\">(Q21/22 - C: helping with physical needs)</strong></span>. But you know, nothing really prepares you for how alone many people are. They crave conversation and I don''t mind chatting with them while I work, though that''s not officially in my job description.</p>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">Jason:</strong> I think I''d like to focus on seniors care. And with the country''s older population growing, maybe I''ll get a job fast. Do we have to be responsible for any medication?</p>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">Becky:</strong> No, that''s not for us to do. And while you will prepare meals, you won''t feed people. But working to keep clients healthy and able to live on their own, without risk as long as possible, is always the goal.And we''re recognizing that with life spans increasing, long-term care facilities won''t be able to keep up with the number of people who will need care. <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"13\" data-index-in-node=\"214\">(Q21/22 - D: ensuring clients are well and safe)</strong></span>.</p>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">Jason:</strong> I almost didn''t meet the requirements for entry into the PSW program. I was one course short getting my <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"14\" data-index-in-node=\"111\">(Q23/24 - A: high school completion)</strong></span> diploma, so I had to go back to summer school. I took science because I''m no good at math.</p>\n<p data-path-to-node=\"15\"><strong>Jason:</strong>Oh, and speaking of not getting in, having my <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"15\" data-index-in-node=\"53\">(Q23/24 - E: First Aid training)</strong></span> certificate was a real piece of luck. I would have been turned down without that too.</p>\n<p id=\"p-rc_94e6262a860d0b2b-164\" data-path-to-node=\"16\"><strong>Becky:</strong>Hmm, <span class=\"citation-2112 citation-end-2112\">and I would have had a problem with immunizations except that I traveled the year before and when the doctor checked my records, they were up to date. I also had to hand in a written essay on why I wanted to be <sup class=\"superscript\" data-turn-source-index=\"1\"><!----></sup></span>a PSW.</p>\n<div class=\"source-inline-chip-container ng-star-inserted\"><!----><!----></div>\n<p><!----><!----><!----><!----><!----><!----><!----><!----></p>\n<p> </p>\n<hr data-path-to-node=\"17\">\n<h3 data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">COURSE TOPICS (Questions 25–30)</strong></h3>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">Jason:</strong> So Becky, what did you think about the courses you had to take in the Personal Support Worker program?</p>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">Becky:</strong> Well, I used to think I got my points across pretty well until I took the <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"20\" data-index-in-node=\"81\">Understanding is Essential</strong></span> course. For starters, it taught me how to express myself much more effectively. I also learned a lot about preparing clear reports for my supervisors and dealing in a better way with people in general—you know, like giving facts without personal views. You''ll find that you need those skills every single day. <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"20\" data-index-in-node=\"259\">(Q25 - D: workplace communication)</strong></span>.</p>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">Jason:</strong> I''m enjoying the <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"21\" data-index-in-node=\"24\">Foundations</strong> </span>course. I''m taking it now and I''m getting a lot out of it. Because support workers are a newer level of care in the province, I think we absolutely have to understand <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"22\" data-index-in-node=\"115\">(Q26 - C: PSWs’ role in health care)</strong></span> how we fit into the overall system. It''s a great place to voice your opinions freely, some are quite personal. Did you have to take a course called <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"23\" data-index-in-node=\"44\">The Way We Work</strong></span>? I didn''t know psychology was part of the program.</p>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">Becky:</strong> Hmm, that course was a favorite of mine, but it''s probably not what you''re thinking, Jason. It''s about what happens on the inside of the body and covers <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"24\" data-index-in-node=\"160\">(Q27 - G: biological systems)</strong></span> the functions that keep our bodies operating well.Even if you''re not a PSW, the course is really interesting. I learned so much.</p>\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">Jason:</strong> What do you think about <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"25\" data-index-in-node=\"31\">Residence Care</strong></span>?I know the thinking now is that long-term care facilities aren''t the answer for our aging population.</p>\n<p data-path-to-node=\"26\"><strong data-path-to-node=\"26\" data-index-in-node=\"0\">Becky:</strong> Hmm, right. And so this course zeros in on the changes people can make to their homes so they can stay there <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"26\" data-index-in-node=\"97\">(Q28 - A: independent living)</strong></span>, like installing higher toilets, for example. You''ll also learn about specialized equipment people can get to help themselves: safety bars for the shower and so on.</p>\n<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">Jason:</strong> Do any of the courses focus on the families of our clients?After all, any kind of illness or disability affects everybody.</p>\n<p data-path-to-node=\"28\"><strong data-path-to-node=\"28\" data-index-in-node=\"0\">Becky:</strong> So true. And yes, there is one called <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"28\" data-index-in-node=\"32\">Dynamics</strong></span>. You usually get that in your last term.You''ll learn different strategies to help relieve some of the anxiety and <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"28\" data-index-in-node=\"116\">(Q29 - F: handling stress)</strong></span> strain that happens within the family.I got a lot out of that course. It''s the only one that focuses on emotions rather than facts, I think. Giving people this kind of help is just as valuable as any kind of expensive equipment they buy to help themselves.</p>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">Jason:</strong> The course I''m really looking forward to is <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"29\" data-index-in-node=\"51\">The Power Within</strong></span>.</p>\n<p data-path-to-node=\"30\"><strong data-path-to-node=\"30\" data-index-in-node=\"0\">Becky:</strong> Oh, it''s terrific! Getting old has quite an impact on the mind, as you know, but you''ll be taught ways to help clients keep the mind active so they''re not so forgetful <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"30\" data-index-in-node=\"113\">(Q30 - E: memory stimulation activities)</strong></span>. You''d be surprised how much improvement you can see in clients when you apply these methods. </p>"}]', 0);
INSERT INTO public.questions VALUES ('acdda91e-099e-4092-a5ad-f01df6b7fdab', '597f0956-1ce6-4b86-a544-8d889853bbde', 'matching', 'Questions 11–16', '', '<p>What tourist attraction does each of the following locations have?</p>
<p>Choose six answers from the box and write the corrct letter, A- I, next to Questions 11-16</p>', 'summary_completion', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p data-path-to-node=\"1,0,0\"><span style=\"font-size: 12pt;\"><strong>Locations</strong></span></p>\n<p data-path-to-node=\"1,0,0\"> </p>\n<p data-path-to-node=\"1,0,0\">Sheepfold: {I hills}</p>\n<p data-path-to-node=\"1,1,0\"> </p>\n<p data-path-to-node=\"1,1,0\">Brown Mare {H wild flowers}</p>\n<p data-path-to-node=\"1,2,0\"> </p>\n<p data-path-to-node=\"1,2,0\">Doris {B nature reserve}</p>\n<p data-path-to-node=\"1,3,0\"> </p>\n<p data-path-to-node=\"1,3,0\">Lodge Estate {E newly born deer}</p>\n<p data-path-to-node=\"1,4,0\"> </p>\n<p data-path-to-node=\"1,4,0\">Aurden {D old ruins}</p>\n<p data-path-to-node=\"1,5,0\"> </p>\n<p data-path-to-node=\"1,5,0\">Eastlake: {F birds}</p>", "answerOptions": [{"optionText": "A farming life in the past"}, {"optionText": "B Nature reserve"}, {"optionText": "C canoes"}, {"optionText": "D old ruins"}, {"optionText": "E newly born deer"}, {"optionText": "F birds"}, {"optionText": "G waterfalls"}, {"optionText": "H wild flowers"}, {"optionText": "I hills "}], "matchingItems": []}', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Sally:</strong> Good morning, everyone. I’m Sally, tour guide from Travel-lite Travel Agency. Today, I’m going to introduce a great trip to Southern Scotland for you. I’m sure you will find it a fantastic place. There is lots to see in Southern Scotland.</p>\n<p data-path-to-node=\"4\">To begin with, we will go to Sheepfold, which has one or two beautiful gardens. One thing that’s definitely worth doing is climbing to the top of the mountain. You’ll be fascinated by the beautiful scenery alongside the mountain road. When you get to the top, you can overlook the coastline and enjoy the stunning view. <strong data-path-to-node=\"4\" data-index-in-node=\"320\">{I hills}</strong></p>\n<p data-path-to-node=\"5\">From there, we will go on to Brown Mare. Brown Mare used to be famous for its farm, but it is being refurbished at the moment and isn’t likely to be reopened by the time we go there. But you can walk for hours there in the peaceful green surroundings along a wide variety of tracks. I think you’ll be struck by the beautiful roses and mother nature. <strong data-path-to-node=\"5\" data-index-in-node=\"350\">{H wild flowers}</strong></p>\n<p data-path-to-node=\"6\">In Doris, there were several old barns, but they have been converted into a special section where animals and plants are protected. From there, you can see a range of rare breeds, as well as flowers. This place is usually favored by university students as a destination for their field trips. <strong data-path-to-node=\"6\" data-index-in-node=\"293\">{B nature reserve}</strong></p>\n<p data-path-to-node=\"7\">Then, we will go to Lodge Estate, which is the most favorite location for children, as they can watch the baby deer. But remember, don’t give food to them. Photography is allowed there, and when you leave, you can get one free photo at the exit. But please don’t move rocks or branches to take photos. You should leave the site intact. <strong data-path-to-node=\"7\" data-index-in-node=\"336\">{E newly born deer}</strong></p>\n<p data-path-to-node=\"8\">Our next stop is Orton (Aurden). I strongly recommend that you visit the ancient town which was constructed nearly 1,000 years ago. There is not much of the original buildings left, but still plenty to see. The site is being excavated, and you’ll be able to help out if you want to. <strong data-path-to-node=\"8\" data-index-in-node=\"283\">{D old ruins}</strong></p>\n<p data-path-to-node=\"9\">Finally, we will spend some time in East Lake, which changes with the seasons, with different events happening at different times of the year. At the moment when we arrive there, it will be the most spectacular month with the arrival of Canada geese. I’m pretty sure that this visit will give you an unforgettable experience. <strong data-path-to-node=\"9\" data-index-in-node=\"326\">{F birds}</strong></p>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">ACCOMMODATION &amp; BENEFITS (Questions 17–20)</strong></p>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">Sally:</strong> Some of you have asked me about the place where we’re going to stay. So next, I will introduce different types of accommodation there.</p>\n<p data-path-to-node=\"13\">First, many tourists may consider visiting a <strong data-path-to-node=\"13\" data-index-in-node=\"45\">bed and breakfast</strong>, also called a B&amp;B, as they don’t have to be worried about what to eat in the morning. But you have to pay attention that this type of accommodation is only available on a daily basis.</p>\n<p data-path-to-node=\"14\">The cheapest possible option is to stay in a <strong data-path-to-node=\"14\" data-index-in-node=\"45\">hostel</strong>, but you should be aware that sometimes you are provided with only a single bed with several people sharing the same room, and meals are not included. But some people think they have never had such an experience before that they want to have a try. More importantly, they don’t have to change accommodation for a whole week.</p>\n<p data-path-to-node=\"15\">For those who want to visit the castles, I recommend you stay in the <strong data-path-to-node=\"15\" data-index-in-node=\"69\">cottages</strong> nearby with beautiful surroundings. The owner promises that the rent can be paid every seven days, so just be relieved to have a peaceful life there.</p>\n<p data-path-to-node=\"16\">For our members, I will introduce some benefits you can get from our travel agency. As for the accommodation I just mentioned, someone has asked if we offer a <strong data-path-to-node=\"16\" data-index-in-node=\"159\">discount</strong>. I’m afraid to tell you this is only for premium members, who can benefit from 10% off the original price.</p>\n<p data-path-to-node=\"17\">For those self-driving travelers, you might be interested in the <strong data-path-to-node=\"17\" data-index-in-node=\"65\">parking space</strong>. This is always limited at the hotel, so we only offer free parking service to premium members as well, I’m afraid. Ordinary members have to pay a fee for parking.</p>\n<p data-path-to-node=\"18\">The good news is, all of you can enjoy your <strong data-path-to-node=\"18\" data-index-in-node=\"44\">guide service</strong> without any charge, including the visit to attractions like the castles. But remember, the entrance fee has to be paid by yourself.</p>\n<p data-path-to-node=\"19\">Oh, I nearly forgot! You can also receive regular copies of <strong data-path-to-node=\"19\" data-index-in-node=\"60\">magazines</strong> about the native food and attractions in Scotland, absolutely for free. It’s a gift for you. I hope you will like it. Okay, that’s all I want to share today. If you have any more questions about the trip, please call me.</p>"}]', 0);
INSERT INTO public.questions VALUES ('0665751a-ef90-46c4-b304-6c30d6887430', '597baadc-be27-4191-a973-89470c2898da', 'checkbox', 'Questions 23 and 24', '', '<p>Choose <strong>TWO</strong> letters, A-E.<br>Which are the <strong>TWO</strong> requirements to do the PSW programme?</p>', 'multiple_choice', 'null', '[{"correct": true, "option_text": "high school completion"}, {"correct": false, "option_text": " a maths course"}, {"correct": false, "option_text": "a language qualification"}, {"correct": false, "option_text": "a clear driving record"}, {"correct": true, "option_text": "First Aid training"}]', 'null', 'null', 'null', 1);
INSERT INTO public.questions VALUES ('1b0fe4ae-5b21-4779-946d-a5117a5d2b72', '27f36c71-9e8c-4730-9717-7c53af88b36f', 'fillup', 'Questions 31-40', '<p><span style="font-size: 12.0pt; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">Complete the notes below.</span></p>
<p><span style="font-size: 12.0pt; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">Write <strong style="mso-bidi-font-weight: normal;">NO MORE THAN TWO WORDS</strong> for each answer.</span></p>
<p><strong style="mso-bidi-font-weight: normal;"><span style="font-size: 14.0pt; mso-bidi-font-size: 12.0pt; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">Impact of cars in Australia (1940s – 1990s)</span></strong></p>
<p><strong style="mso-bidi-font-weight: normal;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">1940s</span></strong></p>
<ul style="margin-top: 0in;" type="circle">
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 150%; mso-outline-level: 3; mso-list: l4 level1 lfo1; tab-stops: list .5in; vertical-align: baseline;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;">One person in eight owned a car</span></li>
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 150%; mso-outline-level: 3; mso-list: l4 level1 lfo1; tab-stops: list .5in; vertical-align: baseline;"><strong><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: black;">{public}</span></strong><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;"> transport was used for 60% of journeys</span></li>
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 150%; mso-outline-level: 3; mso-list: l4 level1 lfo1; tab-stops: list .5in; vertical-align: baseline;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;">Buses:</span></li>
</ul>
<p><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">Problems – crowded and {uncomfortable}</span></p>
<p><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">Advantage – affordable</span></p>
<ul style="margin-top: 0in;" type="circle">
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 150%; mso-outline-level: 3; mso-list: l2 level1 lfo2; tab-stops: list .5in; vertical-align: baseline;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;"><span style="color: #15191e;">Cars were associated with {freedom}</span></span></li>
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 150%; mso-outline-level: 3; mso-list: l2 level1 lfo2; tab-stops: list .5in; vertical-align: baseline;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;">Problems of car ownerships</span></li>
</ul>
<p><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">i. cost</span></p>
<p><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">ii. many spare parts were imported</span></p>
<p><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">iii. restrictions on fuel</span></p>
<p><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">iv. high {taxes}</span><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;"> on cars</span></p>
<ul style="margin-top: 0in;" type="circle">
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 150%; mso-outline-level: 3; mso-list: l0 level1 lfo3; tab-stops: list .5in; vertical-align: baseline;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;">Result of pressure form motorists – new {government}</span><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;"> in Australia in 1949</span></li>
</ul>
<p><strong style="mso-bidi-font-weight: normal;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">1960s</span></strong></p>
<ul style="margin-top: 0in;" type="circle">
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 150%; mso-outline-level: 3; mso-list: l5 level1 lfo4; tab-stops: list .5in; vertical-align: baseline;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;">Cars were cheaper and more reliable</span></li>
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 150%; mso-outline-level: 3; mso-list: l5 level1 lfo4; tab-stops: list .5in; vertical-align: baseline;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;">More people lived in the suburbs</span></li>
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 150%; mso-outline-level: 3; mso-list: l5 level1 lfo4; tab-stops: list .5in; vertical-align: baseline;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;">Main streets were congested and {polluted}</span><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;"> (and usually straight)</span></li>
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 150%; mso-outline-level: 3; mso-list: l5 level1 lfo4; tab-stops: list .5in; vertical-align: baseline;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;">New streets were built with curves to make drivers slow down</span></li>
</ul>
<p><strong style="mso-bidi-font-weight: normal;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">1970s</span></strong></p>
<ul style="margin-top: 0in;" type="circle">
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 150%; mso-outline-level: 3; mso-list: l3 level1 lfo5; tab-stops: list .5in; vertical-align: baseline;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;"><span style="color: #15191e;">Roads had more {lanes}</span></span></li>
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 150%; mso-outline-level: 3; mso-list: l3 level1 lfo5; tab-stops: list .5in; vertical-align: baseline;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;">More commuters</span></li>
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 150%; mso-outline-level: 3; mso-list: l3 level1 lfo5; tab-stops: list .5in; vertical-align: baseline;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;">Car use affected the {relationships}</span><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;"> between people</span></li>
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 150%; mso-outline-level: 3; mso-list: l3 level1 lfo5; tab-stops: list .5in; vertical-align: baseline;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;">New types of {advertisements}</span><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;"> were designed to attract motorists</span></li>
</ul>
<p><strong style="mso-bidi-font-weight: normal;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">1980s and 1990s</span></strong></p>
<ul style="margin-top: 0in;" type="circle">
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 150%; mso-outline-level: 3; mso-list: l1 level1 lfo6; tab-stops: list .5in; vertical-align: baseline;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;"><span style="color: #15191e;">Less business in town centres because of introduction of {shopping malls}</span></span></li>
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 150%; mso-outline-level: 3; mso-list: l1 level1 lfo6; tab-stops: list .5in; vertical-align: baseline;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;">Introduction of drive-in facilities, e.g. restaurants</span></li>
</ul>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p><strong>Lecturer:</strong> Good morning everyone. Today in this second lecture of the series, we turn our attention to transportation. In particular, we’re going to take a look at the way the motor car influenced urban development in Australia and changed our lifestyle from the 1940s to the end of the 1990s.</p>\n<blockquote>\n<p><strong>Dịch:</strong> Chào buổi sáng mọi người. Hôm nay trong buổi giảng thứ hai của loạt bài này, chúng ta sẽ chuyển sự chú ý sang giao thông vận tải. Cụ thể, chúng ta sẽ xem xét cách ô tô đã ảnh hưởng đến sự phát triển đô thị ở Úc và thay đổi lối sống của chúng ta từ những năm 1940 đến cuối những năm 1990.</p>\n</blockquote>\n<p>The car is so common nowadays that we all take it for granted and we barely think about the major effect it has had on our society. But let’s go back for a while to the late 1940s. Although they had been around since the start of the 20th century, only one person in eight owned a car in Australia’s major cities at that time. Nearly <strong>(31) 60% of journeys</strong> were still made by various means of <strong>public</strong> transport, and only 15% by car, which is clearly very few compared to statistics now.</p>\n<blockquote>\n<p><strong>Dịch:</strong> Ngày nay, ô tô đã trở nên phổ biến đến mức chúng ta coi đó là điều hiển nhiên và hầu như không nghĩ về những tác động lớn mà nó đã gây ra đối với xã hội của chúng ta. Nhưng chúng ta hãy quay trở lại một chút với cuối những năm 1940. Mặc dù ô tô đã xuất hiện từ đầu thế kỷ 20, nhưng chỉ một trong tám người sở hữu ô tô tại các thành phố lớn của Úc vào thời điểm đó. Gần <strong>(31) 60% chuyến đi</strong> vẫn được thực hiện bằng các phương tiện giao thông <strong>công cộng</strong> khác nhau, và chỉ 15% bằng ô tô, rõ ràng là rất ít so với thống kê hiện tại.</p>\n</blockquote>\n<p>Buses were very crowded in the days before extensive car use, and they were also considered to be <strong>(32) uncomfortable</strong>, despite providing a cheap option that most people could afford. Remember this wasn’t long after the Second World War. People were tired of living without things, of making do, and to them cars represented <strong>(33) freedom</strong>.</p>\n<blockquote>\n<p><strong>Dịch:</strong> Xe buýt rất đông đúc vào những ngày trước khi ô tô được sử dụng rộng rãi, và chúng cũng bị coi là <strong>(32) không thoải mái</strong>, mặc dù cung cấp một lựa chọn rẻ tiền mà hầu hết mọi người đều có thể chi trả. Hãy nhớ rằng đây là thời điểm không lâu sau Thế chiến thứ hai. Mọi người đã mệt mỏi vì phải sống thiếu thốn, vì phải xoay sở, và đối với họ, ô tô đại diện cho <strong>(33) tự do</strong>.</p>\n</blockquote>\n<p>But even for the wealthy few who did have vehicles, it wasn’t easy to run a car at this time. As well as the expense of buying a car, spare parts were difficult to get as many were imported. Another problem for car owners was that fuel was still rationed, and car <strong>(34) taxes</strong> were very high. Strong public feeling on issues like these from various pressure groups resulted in a change of <strong>(35) government</strong> in Australia after the general election in 1949, which undoubtedly shaped the future of our nation.</p>\n<blockquote>\n<p><strong>Dịch:</strong> Nhưng ngay cả đối với số ít người giàu có sở hữu xe cộ, việc vận hành một chiếc ô tô vào thời điểm này cũng không dễ dàng. Ngoài chi phí mua xe, phụ tùng thay thế cũng khó kiếm vì nhiều loại được nhập khẩu. Một vấn đề khác đối với những người sở hữu ô tô là nhiên liệu vẫn bị phân phối theo định mức, và <strong>(34) thuế</strong> ô tô rất cao. Cảm xúc mạnh mẽ của công chúng về những vấn đề này từ nhiều nhóm áp lực đã dẫn đến việc thay đổi <strong>(35) chính phủ</strong> ở Úc sau cuộc tổng tuyển cử năm 1949, điều này chắc chắn đã định hình tương lai của quốc gia chúng ta.</p>\n</blockquote>\n<hr />\n<p>In the 1960s, cheaper, more reliable cars became available, and this coincided with the rapid expansion of the suburbs. The car enabled these to grow in all directions, far beyond the train lines laid down in the 19th century. For the previous 150 years, the city centre had been a prestigious area, but the addition of cars made the main streets congested. This wasn’t the only problem; now they were <strong>(36) polluted</strong> as well.</p>\n<blockquote>\n<p><strong>Dịch:</strong> Vào những năm 1960, những chiếc ô tô rẻ hơn, đáng tin cậy hơn đã xuất hiện, và điều này trùng hợp với sự mở rộng nhanh chóng của các vùng ngoại ô. Ô tô cho phép các khu vực này phát triển theo mọi hướng, vượt xa các tuyến đường sắt được xây dựng vào thế kỷ 19. Trong 150 năm trước đó, trung tâm thành phố là một khu vực uy tín, nhưng sự xuất hiện của ô tô đã làm cho các đường phố chính bị tắc nghẽn. Đây không phải là vấn đề duy nhất; giờ đây chúng còn bị <strong>(36) ô nhiễm</strong> nữa.</p>\n</blockquote>\n<p>Since these streets were usually straight, they tempted motorists to speed, so the layout of newer streets was affected by this change towards private transport. In the newer areas roads were no longer built straight; instead they had curves that were specially designed to force drivers to slow down. This meant they were longer, but this was not a problem because people rarely walked anymore.</p>\n<blockquote>\n<p><strong>Dịch:</strong> Vì những con phố này thường thẳng, chúng cám dỗ người lái xe chạy quá tốc độ, vì vậy bố cục của những con phố mới hơn đã bị ảnh hưởng bởi sự thay đổi này theo hướng giao thông cá nhân. Ở các khu vực mới, đường không còn được xây thẳng nữa; thay vào đó, chúng có những khúc cua được thiết kế đặc biệt để buộc người lái xe phải giảm tốc độ. Điều này có nghĩa là đường dài hơn, nhưng đây không phải là vấn đề vì mọi người hiếm khi đi bộ nữa.</p>\n</blockquote>\n<hr />\n<p>By the 1970s the type of roads being built changed, with more <strong>(37) lanes</strong> in each direction. There were more commuters because now there was faster access to the city where they worked. By this time the motor car was affecting many different areas of life. It even surprisingly affected <strong>(38) relationships</strong>. Before this meeting, anyone who lived beyond walking or cycling distance was impractical, if not impossible. The car brought people together.</p>\n<blockquote>\n<p><strong>Dịch:</strong> Đến những năm 1970, loại đường được xây dựng đã thay đổi, với nhiều <strong>(37) làn đường</strong> hơn ở mỗi hướng. Có nhiều người đi làm hơn vì giờ đây đã có thể tiếp cận thành phố nhanh hơn nơi họ làm việc. Vào thời điểm này, ô tô đã ảnh hưởng đến nhiều lĩnh vực khác nhau của cuộc sống. Thậm chí đáng ngạc nhiên là nó còn ảnh hưởng đến <strong>(38) các mối quan hệ</strong>. Trước cuộc gặp gỡ này, bất cứ ai sống ngoài khoảng cách đi bộ hoặc đi xe đạp đều không khả thi, nếu không muốn nói là không thể. Chiếc ô tô đã đưa mọi người đến gần nhau hơn.</p>\n</blockquote>\n<p>What other effects did the car have? The increase in car use changed the way we advertise. Previously, advertisements had been designed to attract slow-moving pedestrians, so they were located at eye level and designed on a human scale. By the late 1970s, massive <strong>(39) advertisements</strong> were designed to attract the notice of the passing motorist.</p>\n<blockquote>\n<p><strong>Dịch:</strong> Ô tô còn có những tác động nào khác? Việc tăng cường sử dụng ô tô đã thay đổi cách chúng ta quảng cáo. Trước đây, quảng cáo được thiết kế để thu hút người đi bộ di chuyển chậm, vì vậy chúng được đặt ngang tầm mắt và thiết kế theo tỷ lệ con người. Đến cuối những năm 1970, những <strong>(39) quảng cáo</strong> lớn được thiết kế để thu hút sự chú ý của người lái xe đang đi qua.</p>\n</blockquote>\n<hr />\n<p>In the 1980s and 90s, even the location of shops began to change. We built <strong>(40) shopping malls</strong> out in the suburbs, which meant that Old Town centres did far less business. Next, we saw the development of drive-in shopping centres, theatres and even restaurants, which now ensure we get out of our cars as little as possible.</p>\n<blockquote>\n<p><strong>Dịch:</strong> Vào những năm 1980 và 90, ngay cả vị trí của các cửa hàng cũng bắt đầu thay đổi. Chúng ta đã xây dựng <strong>(40) các trung tâm mua sắm</strong> ở ngoại ô, điều đó có nghĩa là các trung tâm Phố Cổ cũ hoạt động kinh doanh ít hơn rất nhiều. Tiếp theo, chúng ta chứng kiến sự phát triển của các trung tâm mua sắm, rạp chiếu phim và thậm chí cả nhà hàng kiểu drive-in (lái xe vào), những nơi hiện đảm bảo rằng chúng ta ra khỏi xe càng ít càng tốt.</p>\n</blockquote>\n<p>Now, I’d like to turn your attention to a few statistics related to car ownership over the same period…</p>\n<blockquote>\n<p><strong>Dịch:</strong> Bây giờ, tôi muốn chuyển sự chú ý của các bạn sang một vài số liệu thống kê liên quan đến việc sở hữu ô tô trong cùng thời kỳ…</p>\n</blockquote>\n"}]', 0);
INSERT INTO public.questions VALUES ('f4284699-1c0b-48a0-a9c7-27849ab60145', 'b11a3056-77f7-4f34-b9fc-62622338e8e3', 'checkbox', 'Questions 17–18', '', '<div class="quests-inner-desc">
<div class="txt">
<p>Choose <strong>TWO</strong> correct answers.</p>
<p>Which <strong>TWO </strong>free things does the family ticket on the steam train include?</p>
</div>
</div>
<div class="quests-list">
<div id="4750" class="quests-item quests-numctn quests-item-history quests-skip" data-question-id="1876" data-numctn="17" data-count="17" data-quest="17-18" data-choices="2">
<div class="tt-head"> </div>
</div>
</div>', 'multiple_choice', 'null', '[{"correct": false, "option_text": "an educational talk"}, {"correct": true, "option_text": "a children''s book"}, {"correct": false, "option_text": "a short film"}, {"correct": true, "option_text": "a flag"}, {"correct": false, "option_text": "a tour of the Ipswich Museum"}]', 'null', 'null', 'null', 1);
INSERT INTO public.questions VALUES ('1fd82844-6e6a-4884-b248-e1f7c95d252a', '3d102ddd-fdef-428e-a636-cc198e05c0a8', 'fillup', 'Questions 31–40', '<div class="quests-inner-desc">
<div class="txt">
<p><em>Write </em><strong><em>ONE WORD ONLY</em></strong><em> for each answer.</em></p>
</div>
</div>
<div class="quests-des">
<div class="content-write">
<p class="ql-align-center" style="text-align: center;"><strong>ABORIGINAL TEXTILE DESIGN</strong></p>
<p><strong>Ernabella Arts Centre</strong></p>
<p>– Artists produce craft and learn new techniques</p>
<p>– Initially, artists produced rugs made from {wool}</p>
<p>– Later artists made batik and screen-printed fabrics</p>
<p><strong>Tiwi Designs</strong></p>
<p>– Early designs included {bird} images</p>
<p>– Designs are linked to traditional beliefs, e g. some designs are believed to bring {rain}</p>
<p><strong>Jimmy Pike</strong></p>
<p>– Inspired by the Australian landscape, especially the {desert}</p>
<p>– Started creating art when he was in {prison}</p>
<p>– His textiles were used to make {clothing}</p>
<p><strong>Bronwyn Bancroft</strong></p>
<p>– Her work is a modern look at {family} and nature</p>
<p>– 1995 – painted a successful Aboriginal athlete’s jeans with lizards and a {rainbow}</p>
<p>– 2001 – designed a ‘Journey of a Nation’ parade outfit with part of a {snake} on it</p>
<p><strong>Copyright Issues</strong></p>
<p>– Exploiting Aboriginal imagery affects the artists and the cultural group, e.g. ‘The {Carpet} Case’</p>
</div>
</div>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p><strong>Narrator:</strong> You will hear part of a lecture given by an art and design lecturer on the topic of Aboriginal textile design in Australia. First you have some time to look at questions 31 to 40 on page seven. Now listen carefully and answer questions 31 to forty.</p>\n<blockquote data-path-to-node=\"5\">\n<p><strong>Dịch:</strong> <strong>Người dẫn chuyện:</strong> Bạn sẽ nghe một phần bài giảng của một giảng viên nghệ thuật và thiết kế về chủ đề thiết kế vải dệt thổ dân ở Úc. Đầu tiên, bạn có thời gian để xem các câu hỏi 31 đến 40 trên trang bảy. Bây giờ hãy lắng nghe cẩn thận và trả lời các câu hỏi 31 đến 40.</p>\n</blockquote>\n<p><strong>Lecturer:</strong> The indigenous people of Australia or Aborigines have a long history of using animal and plant fibres to make a variety of fabric over the years. Their traditional designs and stories have been incorporated into various textiles. The Ernabella Arts Centre is a place where local Aborigines can produce their traditional craft and also learn new techniques to decorate fabric. For the first thirty years, the artists crafted rugs working with <strong>(31) wool</strong>. These rugs incorporated their own unique designs. However, as they became less economical to produce, the artists were introduced to batik, which is an Indonesian method of dyeing textiles. Screen printing was later introduced to the Centre and Ernabella’s artists were commissioned to produce fabric for <strong>(32) furniture</strong> that was to be used at popular tourist destinations such as the National Park offices at Uluru.</p>\n<blockquote data-path-to-node=\"7\">\n<p><strong>Dịch:</strong> <strong>Giảng viên:</strong> Người dân bản địa của Úc, hay thổ dân, có lịch sử lâu đời trong việc sử dụng sợi động vật và thực vật để tạo ra nhiều loại vải khác nhau qua nhiều năm. Các thiết kế và câu chuyện truyền thống của họ đã được đưa vào nhiều loại vải dệt khác nhau. Trung tâm Nghệ thuật Ernabella là nơi mà thổ dân địa phương có thể sản xuất thủ công truyền thống của họ và cũng học các kỹ thuật mới để trang trí vải. Trong ba mươi năm đầu tiên, các nghệ sĩ chế tác thảm bằng cách làm việc với <strong>(31) len</strong>. Tuy nhiên, khi việc sản xuất trở nên kém hiệu quả hơn, các nghệ sĩ đã được giới thiệu kỹ thuật batik. Sau đó, in lưới được giới thiệu và các nghệ sĩ của Ernabella đã được ủy quyền sản xuất vải cho <strong>(32) đồ nội thất</strong> được sử dụng tại các điểm du lịch nổi tiếng.</p>\n</blockquote>\n<p><strong>Lecturer:</strong> Screen printing has also been used successfully by the Tiwi people who live on islands north of Darwin. Their company, Tiwi Designs, produces fabric that is inspired by their surroundings. For example, they incorporated <strong>(33) Bird</strong> motifs into their early designs. Tiwi art, culture, and language are very different from those of mainland Aboriginal groups. The patterns on their fabric are related to the beliefs and legends in their culture. For example, some textile designs are chosen because they are thought to cause <strong>(34) rain</strong>.</p>\n<blockquote data-path-to-node=\"9\">\n<p><strong>Dịch:</strong> <strong>Giảng viên:</strong> In lưới cũng đã được sử dụng thành công bởi người Tiwi, những người sống trên các hòn đảo phía bắc Darwin. Công ty của họ, Tiwi Designs, sản xuất vải lấy cảm hứng từ môi trường xung quanh họ. Ví dụ, họ đưa các họa tiết <strong>(33) chim</strong> vào các thiết kế ban đầu của mình. Các hoa văn trên vải của họ liên quan đến tín ngưỡng và truyền thuyết trong văn hóa. Ví dụ, một số thiết kế vải dệt được chọn vì chúng được cho là gây ra <strong>(34) mưa</strong>.</p>\n</blockquote>\n<p><strong>Lecturer:</strong> Another successful Aboriginal design company was founded by <strong>Jimmy Pike</strong>. His dynamic prints, paintings, and fabrics are greatly influenced by the Australian landscape, in particular that of the <strong>(35) desert</strong>, which is often featured in his work. Surprisingly, Jimmy Pike’s life as an artist began in <strong>(36) prison</strong>, where he was serving a sentence for murder. The art teachers there recognized his talent and gave him the technical skills he needed to become a successful artist. After Pike’s release, he started his own company… eventually, he decided to bring his artwork onto textiles, which were used to produce <strong>(37) clothing</strong>.</p>\n<blockquote data-path-to-node=\"11\">\n<p><strong>Dịch:</strong> <strong>Giảng viên:</strong> Một công ty thiết kế thổ dân thành công khác được thành lập bởi <strong>Jimmy Pike</strong>. Các tác phẩm của ông bị ảnh hưởng lớn bởi phong cảnh Úc, đặc biệt là <strong>(35) sa mạc</strong>, nơi thường xuyên xuất hiện trong tác phẩm của ông. Đáng ngạc nhiên, cuộc đời nghệ sĩ của Jimmy Pike bắt đầu trong <strong>(36) tù</strong>. Sau khi Pike được thả, ông thành lập công ty riêng và cuối cùng quyết định đưa tác phẩm nghệ thuật của mình lên vải dệt, được sử dụng để sản xuất <strong>(37) quần áo</strong>.</p>\n</blockquote>\n<p><strong>Lecturer:</strong> <strong>Bronwyn Bancroft</strong> is one of the most successful Aboriginal artists and designers to date. Her work reflects her Aboriginal roots but always with a contemporary, fresh view of <strong>(38) family</strong> and the natural environment. In nineteen ninety-five, she was chosen by a charity organisation to paint a pair of jeans owned by Kathy Freeman, a famous Aboriginal Australian athlete… she added a <strong>(39) Rainbow</strong>, which represents the optimism that Kathy symbolizes for all Aboriginal people. In two thousand and one, she was chosen to design costumes for the opening of the biggest street parade ever held in Australia… It featured the image of a <strong>(40) snake</strong> that had no head or tail, to represent an ongoing culture.</p>\n<blockquote data-path-to-node=\"13\">\n<p><strong>Dịch:</strong> <strong>Giảng viên:</strong> <strong>Bronwyn Bancroft</strong> là một trong những nghệ sĩ và nhà thiết kế thổ dân thành công nhất cho đến nay. Tác phẩm của bà phản ánh cội nguồn thổ dân nhưng luôn mang cái nhìn đương đại, mới mẻ về <strong>(38) gia đình</strong> và môi trường tự nhiên. Năm 1995, bà được chọn để vẽ một chiếc quần jean, nơi bà thêm vào hình ảnh cầu <strong>(39) vồng</strong>, tượng trưng cho sự lạc quan. Năm 2001, bà được chọn thiết kế trang phục cho lễ khai mạc cuộc diễu hành lớn nhất từng được tổ chức ở Úc. Trang phục có hình ảnh một con <strong>(40) rắn</strong> không đầu hoặc đuôi, để đại diện cho một nền văn hóa không ngừng tiếp diễn.</p>\n</blockquote>\n<p><strong>Lecturer:</strong> Exploitation of creative work can be a problem for any artist, and copyright laws exist to protect individual artists… An example of this was when a businessman had rugs made overseas incorporating images stolen from Aboriginal paintings. The <strong>Carpet Case</strong> as it became known was taken to court, where luckily the artists won.</p>\n<blockquote data-path-to-node=\"15\">\n<p><strong>Dịch:</strong> <strong>Giảng viên:</strong> Việc khai thác tác phẩm sáng tạo có thể là một vấn đề đối với bất kỳ nghệ sĩ nào, và luật bản quyền tồn tại để bảo vệ các nghệ sĩ cá nhân… Một ví dụ về điều này là khi một doanh nhân đã sản xuất thảm ở nước ngoài sử dụng hình ảnh bị đánh cắp từ các bức tranh thổ dân. <strong>Vụ kiện Thảm</strong> nổi tiếng đã được đưa ra tòa, và may mắn là các nghệ sĩ đã thắng kiện.</p>\n</blockquote>\n<p><strong>Narrator:</strong> That is the end of Section 4. You now have half a minute to check your answers.</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('3f6396de-df0a-43f1-a13b-9cb0aa4da53b', 'fa26f410-379f-4ed4-a66a-0b3c60667954', 'radio', 'Questions 1-8', '', '<p>Choose TRUE if the statement agrees with the information given in the text, choose FALSE if the statement contradicts the information, or choose NOT GIVEN if there is no information on this.</p>', 'true_false_not_given', '[{"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "People have mistaken opinions about fishing hooks'' functions."}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Fishing is more difficult in New Zealand than Pacific islands."}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Maoris use new materials to build hooks after they arrived New Zealand."}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Maoris'' hooks are limited in forms because of the material limitation it used."}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The fishing line of Maoris is worse than the European."}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Europeans are given fishing hooks as a gift from local Maoris."}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "According to WA, Maoris have already engaged in crop growing."}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Hooks of Maoris are functioned in the same way to the hooks of European."}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">1. People have mistaken opinions about fishing hooks’ functions. — {TRUE}</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 1):</strong> <em data-path-to-node=\"8,0,0\" data-index-in-node=\"20\">“…for many centuries, their <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"50\">true purpose was misunderstood</strong>… Many assumed these… hooks served only <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"124\">decorative, ceremonial, or ritualistic</strong> purposes…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Suốt nhiều thế kỷ, mục đích thực sự của lưỡi câu bị hiểu lầm. Nhiều người cho rằng chúng chỉ để trang trí hay làm lễ nghi, trong khi thực tế chúng là công cụ đánh cá cực kỳ chuẩn xác.</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">2. Fishing is more difficult in New Zealand than Pacific islands. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 2):</strong> Chỉ nói khi đến New Zealand, họ thấy môi trường giàu tài nguyên và họ thích nghi nhanh chóng.</p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc <strong data-path-to-node=\"10,1,0\" data-index-in-node=\"20\">không hề so sánh</strong> độ khó của việc đánh cá giữa New Zealand và các đảo Thái Bình Dương.</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">3. Maoris use new materials to build hooks after they arrived New Zealand. — {FALSE}</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 2):</strong> <em data-path-to-node=\"12,0,0\" data-index-in-node=\"20\">“They quickly adapted by using <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"51\">familiar materials</strong> such as bones and stones…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài nói họ dùng các nguyên liệu <strong data-path-to-node=\"12,1,0\" data-index-in-node=\"44\">quen thuộc</strong> (familiar) như xương và đá, chứ không phải nguyên liệu “mới” (new). (Họ chỉ dùng nguyên liệu mới là kim loại sau khi người châu Âu đến ở thế kỷ 18).</p>\n</li>\n</ul>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">4. Maoris’ hooks are limited in forms because of the material limitation it used. — {TRUE}</strong></p>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 2):</strong> <em data-path-to-node=\"14,0,0\" data-index-in-node=\"20\">“…their form was somewhat <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"48\">limited</strong>. This was because the <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"78\">materials… could not be forged or bent like metal</strong>, thus <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"136\">restricting the range of shapes</strong>…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong data-path-to-node=\"14,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Hình dáng lưỡi câu bị giới hạn vì chất liệu (xương, đá) không thể rèn hay uốn như kim loại. Điều này khớp hoàn toàn với câu hỏi.</p>\n</li>\n</ul>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">5. The fishing line of Maoris is worse than the European. — {FALSE}</strong></p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 2):</strong> <em data-path-to-node=\"16,0,0\" data-index-in-node=\"20\">“Their fishing lines… proved <strong data-path-to-node=\"16,0,0\" data-index-in-node=\"51\">just as strong—if not stronger—than those used by Europeans</strong>…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"16,1,0\"><strong data-path-to-node=\"16,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Dây câu của người Māori bền bằng, thậm chí là bền hơn của người châu Âu, chứ không phải tệ hơn (worse).</p>\n</li>\n</ul>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">6. Europeans are given fishing hooks as a gift from local Maoris. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"18\">\n<li>\n<p data-path-to-node=\"18,0,0\"><strong data-path-to-node=\"18,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 3 &amp; 5):</strong> Có nói người châu Âu thấy các công cụ này khi thám hiểm, và sau này có việc trao đổi kim loại/kim đóng tàu.</p>\n</li>\n<li>\n<p data-path-to-node=\"18,1,0\"><strong data-path-to-node=\"18,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc <strong data-path-to-node=\"18,1,0\" data-index-in-node=\"20\">không nhắc đến</strong> việc người Māori tặng lưỡi câu như một món quà (gift) cho người châu Âu.</p>\n</li>\n</ul>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">7. According to WA (William Anderson), Maoris have already engaged in crop growing. — {TRUE}</strong></p>\n<ul data-path-to-node=\"20\">\n<li>\n<p data-path-to-node=\"20,0,0\"><strong data-path-to-node=\"20,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 3):</strong> <em data-path-to-node=\"20,0,0\" data-index-in-node=\"20\">“In 1777… William Anderson… noted that… the Māori had already developed advanced methods of <strong data-path-to-node=\"20,0,0\" data-index-in-node=\"118\">intensive farming</strong>…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"20,1,0\"><strong data-path-to-node=\"20,1,0\" data-index-in-node=\"0\">Giải thích:</strong> William Anderson ghi nhận người Māori đã có các phương pháp thâm canh (intensive farming), tức là trồng trọt (crop growing).</p>\n</li>\n</ul>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">8. Hooks of Maoris are functioned in the same way to the hooks of European. — {FALSE}</strong></p>\n<ul data-path-to-node=\"22\">\n<li>\n<p data-path-to-node=\"22,0,0\"><strong data-path-to-node=\"22,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 4):</strong> <em data-path-to-node=\"22,0,0\" data-index-in-node=\"20\">“Māori fishing hooks <strong data-path-to-node=\"22,0,0\" data-index-in-node=\"41\">functioned quite differently</strong> from those used by Europeans. Rather than piercing directly… Māori hooks worked by <strong data-path-to-node=\"22,0,0\" data-index-in-node=\"155\">rotating</strong>…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"22,1,0\"><strong data-path-to-node=\"22,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Lưỡi câu Māori hoạt động theo cơ chế xoay, khác hoàn toàn (differently) với cơ chế đâm xuyên trực tiếp của người châu Âu.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('7297adb3-3c83-4967-bf07-ef60c9936c71', '02b5ca32-7c52-4bb3-b34f-64a64a6ded61', 'matching', 'Questions 15–20', NULL, '<p>Complete the fow – chart below.</p>
<p>Choose SIX correct answers, A – H, next to questions 15 – 20.</p>
', 'matching_features', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p class=\"MsoNormal\" style=\"text-align: center; background: white;\" align=\"center\"><strong><span lang=\"vi\" style=\"font-size: 16.0pt; line-height: 115%; font-family: ''Calibri'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: #15191e;\">To apply to <em style=\"mso-bidi-font-style: normal;\">Connections</em> as a guest</span></strong></p>\r\n<p class=\"MsoNormal\" style=\"text-align: center; background: white; line-height: 1;\" align=\"center\"><span lang=\"vi\" style=\"font-size: 14.0pt; line-height: 115%; font-family: ''Calibri'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: black; mso-color-alt: windowtext;\">The applicant makes an initial phone call to the <strong>{H Vetting}</strong></span><span lang=\"vi\" style=\"font-size: 14.0pt; line-height: 115%; font-family: ''Calibri'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: #15191e;\"> department.</span></p>\r\n<p class=\"MsoNormal\" style=\"text-align: center; background: white; line-height: 1;\" align=\"center\"><span lang=\"vi\" style=\"font-size: 14.0pt; line-height: 115%; font-family: ''Calibri'',sans-serif; color: black; mso-color-alt: windowtext;\"><span style=\"mso-fareast-font-family: Cardo; color: #15191e;\">↓</span></span></p>\r\n<p class=\"MsoNormal\" style=\"text-align: center; background: white; line-height: 1;\" align=\"center\"><span lang=\"vi\" style=\"font-size: 14.0pt; line-height: 115%; font-family: ''Calibri'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: black; mso-color-alt: windowtext;\">The applicant sends in a reference to confirm his/her <strong>{C Identity}</strong></span><span lang=\"vi\" style=\"font-size: 14.0pt; line-height: 115%; font-family: ''Calibri'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: #15191e;\"> .</span></p>\r\n<p class=\"MsoNormal\" style=\"text-align: center; background: white; line-height: 1;\" align=\"center\"><span lang=\"vi\" style=\"font-size: 14.0pt; line-height: 115%; font-family: ''Calibri'',sans-serif; color: black; mso-color-alt: windowtext;\"><span style=\"mso-fareast-font-family: Cardo; color: #15191e;\">↓</span></span></p>\r\n<p class=\"MsoNormal\" style=\"text-align: center; background: white; line-height: 1;\" align=\"center\"><span lang=\"vi\" style=\"font-size: 14.0pt; line-height: 115%; font-family: ''Calibri'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: black; mso-color-alt: windowtext;\">Following approval, an application form is emailed to the applicant.</span></p>\r\n<p class=\"MsoNormal\" style=\"text-align: center; background: white; line-height: 1;\" align=\"center\"><span lang=\"vi\" style=\"font-size: 14.0pt; line-height: 115%; font-family: ''Calibri'',sans-serif; color: black; mso-color-alt: windowtext;\"><span style=\"mso-fareast-font-family: Cardo; color: #15191e;\">↓</span></span></p>\r\n<p class=\"MsoNormal\" style=\"text-align: center; background: white; line-height: 1;\" align=\"center\"><span lang=\"vi\" style=\"font-size: 14.0pt; line-height: 115%; font-family: ''Calibri'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: black; mso-color-alt: windowtext;\">The applicant returns the completed form with two photographs (one for </span><span lang=\"vi\" style=\"font-size: 14.0pt; line-height: 115%; font-family: ''Calibri'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: #15191e;\"><span style=\"mso-spacerun: yes;\"> </span><strong>{F Records} </strong>and one for the family).</span></p>\r\n<p class=\"MsoNormal\" style=\"text-align: center; background: white; line-height: 1;\" align=\"center\"><span lang=\"vi\" style=\"font-size: 14.0pt; line-height: 115%; font-family: ''Calibri'',sans-serif; color: black; mso-color-alt: windowtext;\"><span style=\"mso-fareast-font-family: Cardo; color: #15191e;\">↓</span></span></p>\r\n<p class=\"MsoNormal\" style=\"text-align: center; background: white; line-height: 1;\" align=\"center\"><span lang=\"vi\" style=\"font-size: 14.0pt; line-height: 115%; font-family: ''Calibri'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: black; mso-color-alt: windowtext;\">The applicant receives <strong>{A Acknowledgement}</strong></span><span lang=\"vi\" style=\"font-size: 14.0pt; line-height: 115%; font-family: ''Calibri'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: #15191e;\"><span style=\"mso-spacerun: yes;\"> </span>within seven days.</span></p>\r\n<p class=\"MsoNormal\" style=\"text-align: center; background: white; line-height: 1;\" align=\"center\"><span lang=\"vi\" style=\"font-size: 14.0pt; line-height: 115%; font-family: ''Calibri'',sans-serif; color: black; mso-color-alt: windowtext;\"><span style=\"mso-fareast-font-family: Cardo; color: #15191e;\">↓</span></span></p>\r\n<p class=\"MsoNormal\" style=\"text-align: center; background: white; line-height: 1;\" align=\"center\"><span lang=\"vi\" style=\"font-size: 14.0pt; line-height: 115%; font-family: ''Calibri'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: black; mso-color-alt: windowtext;\">The applicant has<span style=\"mso-spacerun: yes;\">  </span><strong>{D An interview}</strong></span><span lang=\"vi\" style=\"font-size: 14.0pt; line-height: 115%; font-family: ''Calibri'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: #15191e;\"> with a staff member.</span></p>\r\n<p class=\"MsoNormal\" style=\"text-align: center; background: white; line-height: 1;\" align=\"center\"><span lang=\"vi\" style=\"font-size: 14.0pt; line-height: 115%; font-family: ''Calibri'',sans-serif; color: black; mso-color-alt: windowtext;\"><span style=\"mso-fareast-font-family: Cardo; color: #15191e;\">↓</span></span></p>\r\n<p class=\"MsoNormal\" style=\"text-align: center; background: white; line-height: 1;\" align=\"center\"><span lang=\"vi\" style=\"font-size: 14.0pt; line-height: 115%; font-family: ''Calibri'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: black; mso-color-alt: windowtext;\">The applicant receives a final <strong>{B Decision}</strong> </span><span lang=\"vi\" style=\"font-size: 14.0pt; line-height: 115%; font-family: ''Calibri'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: #15191e;\"><span style=\"mso-spacerun: yes;\"> </span>in writing.</span></p>", "answerOptions": [{"optionText": "A Acknowledgement"}, {"optionText": "B Decision"}, {"optionText": "C Identity"}, {"optionText": "D An interview"}, {"optionText": "E Legal status"}, {"optionText": "F Records"}, {"optionText": "G Rejection"}, {"optionText": "H Vetting"}], "matchingItems": null}', 'null', '[{"content": "<p>1</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('173ca9d8-4a67-4013-87dd-ac8aba29e822', '95d4b4ef-2803-4f2e-8ceb-ea411b28caae', 'fillup', 'Questions 22 - 26', '<p>Complete the summary below.</p>
<p>Choose <strong>ONE WORD ONLY</strong> from the passage for each answer.</p>
<p>Write your answers in boxes 22-26 on your answer sheet.</p>
<p><span style="font-size: 14pt;"><strong>The changing population of Ashburton</strong></span></p>
<p>The Canterbury town of Ashburton is thriving thanks in large part to wealth created by the dairy farming industry, which has replaced the more traditional farming of sheep. However, other factors have also been involved such as the success of the {wine} industry in recent years. For a long time {tourism} has brought wealth to the region, and today the industry is so successful that traffic is becoming a problem. The social make-up of Canterbury has also been affected by a group known as {lifestylers} who have moved out from the city. Disagreements between these newcomers and established farmers sometimes occur when it comes to the use of {chemicals} on crops. This social diversity is increased when {migrants} are temporarily employed to work on farms.</p>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">22. wine — {the success of the wine industry in recent years}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn E):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“…land has been given over to a relatively new industry: the <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"83\">production of wine</strong>, which has taken off in Canterbury…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm “taken off” đồng nghĩa với “success” (trở nên thành công/phát triển mạnh). Ngoài ngành sữa, sự thành công của ngành sản xuất rượu vang (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"152\">wine</strong>) cũng đóng góp vào sự hưng thịnh của vùng.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">23. tourism — {For a long time tourism has brought wealth…}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn E):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“…Canterbury’s natural beauty has meant <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"62\">tourism has contributed to its prosperity for decades</strong>…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “For a long time” tương ứng với “for decades” (trong nhiều thập kỷ). Ngành du lịch (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"96\">tourism</strong>) đã mang lại sự thịnh vượng cho khu vực này từ rất lâu rồi.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">24. lifestylers — {…a group known as lifestylers who have moved out from the city}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn E):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">“…tended by the so-called <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"48\">lifestylers</strong> – people who once lived in urban areas but have come to enjoy the rural culture…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Những người từng sống ở thành thị (moved out from the city/lived in urban areas) và chuyển về nông thôn được gọi là các <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"132\">lifestylers</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">25. chemicals — {…disagreements… when it comes to the use of chemicals on crops}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn F):</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"20\">“…disputes arising over such issues as the intensification of farming and the heavy <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"106\">dependence on chemicals</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Disagreements” đồng nghĩa với “disputes” (tranh chấp/mâu thuẫn). Một trong những vấn đề gây tranh cãi giữa nông dân cũ và người mới đến là việc phụ thuộc quá nhiều vào hóa chất (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"191\">chemicals</strong>) trong trồng trọt.</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">26. migrants — {when migrants are temporarily employed to work on farms}</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn F):</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"20\">“…modern rural workforce… is increasingly reliant on <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"77\">migrants</strong> who are <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"94\">brought in at harvest time</strong>…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Temporarily employed” (được thuê tạm thời) tương ứng với việc được đưa đến vào mùa vụ (brought in at harvest time). Lực lượng lao động nhập cư (<strong data-path-to-node=\"13,1,0\" data-index-in-node=\"157\">migrants</strong>) làm cho thành phần xã hội ở đây trở nên đa dạng hơn.</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('09e2e30d-8a3c-4c5a-9a17-ba64e207bde6', 'fa26f410-379f-4ed4-a66a-0b3c60667954', 'fillup', 'Questions 9-13', '<p data-path-to-node="7">Complete the notes below.</p>
<p data-path-to-node="7">Choose <strong data-path-to-node="7" data-index-in-node="33">ONE WORD ONLY</strong> from the passage for each answer.</p>
<p data-path-to-node="8"><span style="font-size: 12pt;"><strong data-path-to-node="8" data-index-in-node="0">How hooks changed after Europeans arrived</strong></span></p>
<p data-path-to-node="9"><strong data-path-to-node="9" data-index-in-node="0">After 1700s</strong></p>
<ul data-path-to-node="10">
<li>
<p data-path-to-node="10,0,0">They abandoned their previous hooks.</p>
</li>
<li>
<p data-path-to-node="10,1,0">Some valued hooks are made into {jewelry}</p>
</li>
</ul>
<p data-path-to-node="11"><strong data-path-to-node="11" data-index-in-node="0">After 1800s</strong></p>
<ul data-path-to-node="12">
<li>
<p data-path-to-node="12,0,0">Mass production makes production cheaper and Maoris import more.</p>
</li>
<li>
<p data-path-to-node="12,1,0">The difficulty associated with the material like {nails} and other metals makes the hooks production less.</p>
</li>
</ul>
<p data-path-to-node="13"><strong data-path-to-node="13" data-index-in-node="0">After 1900s</strong></p>
<ul data-path-to-node="14">
<li>
<p data-path-to-node="14,0,0">Some {collectors} were again interested in hooks.</p>
</li>
<li>
<p data-path-to-node="14,1,0">Many hooks are {fake} which can be identified easily.</p>
</li>
</ul>
<p data-path-to-node="15"><strong data-path-to-node="15" data-index-in-node="0">Conclusion</strong></p>
<ul data-path-to-node="16">
<li>
<p data-path-to-node="16,0,0">We can find the hooks’ design of old times today on {boats}</p>
</li>
</ul>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">9. jewelry — {Some valued hooks are made into jewelry}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 5):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“…crafting hooks that were later taken into luxury markets and sold as <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"93\">jewelry</strong>, blurring the line between utility and art.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Những chiếc lưỡi câu làm từ vật liệu quý hiếm (như ngà voi hay đá ngọc bích) đã được đưa vào thị trường xa xỉ và bán như đồ trang sức (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"147\">jewelry</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">10. nails — {The difficulty associated with the material like nails… makes the hooks production less}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 6):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“…the production of traditional Māori hooks declined due to the <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"86\">nails</strong> and other metallic materials required, which were difficult to manipulate…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc sản xuất lưỡi câu truyền thống bị giảm sút (less) do các vật liệu kim loại như đinh (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"102\">nails</strong>) rất khó để chế tác nếu không có dụng cụ chuyên dụng.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">11. collectors — {Some collectors were again interested in hooks}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 6):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">“…interest in Pacific culture grew, and <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"62\">collectors</strong> began to seek out original Māori fishing hooks once again.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Vào đầu những năm 1900, những nhà sưu tập (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"55\">collectors</strong>) bắt đầu quan tâm và tìm kiếm lại những chiếc lưỡi câu Māori nguyên bản.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">12. fake — {Many hooks are fake which can be identified easily}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 6):</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"20\">“Unfortunately, the demand also led to a wave of imitations—many of the hooks appearing on the market today are <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"132\">fake</strong>, though they can usually be <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"165\">identified by their inconsistent design</strong>…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Do nhu cầu cao nên xuất hiện nhiều hàng nhái, hàng giả (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"68\">fake</strong>), nhưng chúng có thể được nhận biết dễ dàng qua sự thiếu nhất quán trong thiết kế và chất liệu.</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">13. boats — {We can find the hooks’ design of old times today on boats}</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 7):</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"20\">“…many hooks found on <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"44\">boats</strong> in New Zealand today still bear a striking resemblance to the ancient forms…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Một minh chứng cho sự trường tồn của thiết kế Māori là ngày nay trên các con tàu/thuyền (<strong data-path-to-node=\"13,1,0\" data-index-in-node=\"101\">boats</strong>), người ta vẫn thấy những chiếc lưỡi câu mang hình dáng giống hệt các mẫu cổ xưa.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('90b276de-5786-41de-8832-3b2999565d17', '631e7cf3-cca3-4842-88c7-61cd2acab1b6', 'radio', 'Questions 7-13', '', '<p data-path-to-node="3,0,0">Choose<strong data-path-to-node="3,0,0" data-index-in-node="0"> TRUE</strong> if the statement agrees with the information,<strong data-path-to-node="3,1,0" data-index-in-node="0">FALSE</strong> if the statement contradicts the information,<strong data-path-to-node="3,2,0" data-index-in-node="0">NOT GIVEN</strong> if there is no information on this</p>', 'true_false_not_given', '[{"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "For steamboats to cross the Atlantic Ocean, engines which used fuel economically were needed."}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Using paddle wheels guaranteed reliability on ocean crossings."}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The Savannah was much faster than a regular paddle steamer."}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Brunel preferred designing railways to steamships."}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The Great Britain had more than one innovative feature."}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The design of the riverboat Archimedes was widely admired."}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Modern ships that cross the Atlantic use the same energy source as the early steamships."}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">7. For steamboats to cross the Atlantic, engines which used fuel economically were needed. — {TRUE}</strong></p>\n<ul data-path-to-node=\"20\">\n<li>\n<p data-path-to-node=\"20,0,0\"><strong data-path-to-node=\"20,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Travelling under steam power alone would require engines to <strong data-path-to-node=\"20,0,0\" data-index-in-node=\"72\">use less coal</strong> [economically] so the ship could stay at the sea for several weeks.” (Đoạn 4)</p>\n</li>\n<li>\n<p data-path-to-node=\"20,1,0\"><strong data-path-to-node=\"20,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Để vượt Đại Tây Dương, tàu cần động cơ tốn ít than hơn để có thể đi biển dài ngày.</p>\n</li>\n</ul>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">8. Using paddle wheels guaranteed reliability on ocean crossings. — {FALSE}</strong></p>\n<ul data-path-to-node=\"22\">\n<li>\n<p data-path-to-node=\"22,0,0\"><strong data-path-to-node=\"22,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…it was also necessary to <strong data-path-to-node=\"22,0,0\" data-index-in-node=\"40\">replace paddle wheels</strong>… with something <strong data-path-to-node=\"22,0,0\" data-index-in-node=\"80\">less affected</strong> by the rolling of the ship.” (Đoạn 4)</p>\n</li>\n<li>\n<p data-path-to-node=\"22,1,0\"><strong data-path-to-node=\"22,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bánh guồng (paddle wheels) bị ảnh hưởng bởi sóng biển làm tàu mất ổn định, nên người ta phải thay thế chúng để đảm bảo độ tin cậy. Vậy dùng bánh guồng không hề đảm bảo độ tin cậy.</p>\n</li>\n</ul>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">9. The Savannah was much faster than a regular paddle steamer. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"24\">\n<li>\n<p data-path-to-node=\"24,0,0\"><strong data-path-to-node=\"24,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “crossings… got underway in 1819 with the American ship <strong data-path-to-node=\"24,0,0\" data-index-in-node=\"69\">Savannah</strong>.” (Đoạn 5)</p>\n</li>\n<li>\n<p data-path-to-node=\"24,1,0\"><strong data-path-to-node=\"24,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ nhắc đến Savannah là con tàu đầu tiên kết hợp buồm và hơi nước để vượt biển, <strong data-path-to-node=\"24,1,0\" data-index-in-node=\"101\">không có thông tin</strong> so sánh tốc độ của nó với các tàu khác.</p>\n</li>\n</ul>\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">10. Brunel preferred designing railways to steamships. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"26\">\n<li>\n<p data-path-to-node=\"26,0,0\"><strong data-path-to-node=\"26,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Brunel… had already built the Great Western Railway. He created ever bigger ships…” (Đoạn 6)</p>\n</li>\n<li>\n<p data-path-to-node=\"26,1,0\"><strong data-path-to-node=\"26,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc liệt kê ông đã xây dựng cả đường sắt và tàu thủy, nhưng <strong data-path-to-node=\"26,1,0\" data-index-in-node=\"76\">không nói ông thích (preferred)</strong> cái nào hơn.</p>\n</li>\n</ul>\n<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">11. The Great Britain had more than one innovative feature. — {TRUE}</strong></p>\n<ul data-path-to-node=\"28\">\n<li>\n<p data-path-to-node=\"28,0,0\"><strong data-path-to-node=\"28,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…was the <strong data-path-to-node=\"28,0,0\" data-index-in-node=\"23\">first</strong> oceangoing steamship made of <strong data-path-to-node=\"28,0,0\" data-index-in-node=\"58\">iron</strong>, and the <strong data-path-to-node=\"28,0,0\" data-index-in-node=\"72\">first</strong> to use the <strong data-path-to-node=\"28,0,0\" data-index-in-node=\"89\">underwater screw propeller</strong>…” (Đoạn 6)</p>\n</li>\n<li>\n<p data-path-to-node=\"28,1,0\"><strong data-path-to-node=\"28,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Con tàu này có ít nhất hai đặc điểm cải tiến: làm bằng sắt và sử dụng chân vịt dưới nước thay cho bánh guồng.</p>\n</li>\n</ul>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">12. The design of the riverboat Archimedes was widely admired. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"30\">\n<li>\n<p data-path-to-node=\"30,0,0\"><strong data-path-to-node=\"30,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…the riverboat <strong data-path-to-node=\"30,0,0\" data-index-in-node=\"29\">Archimedes</strong> built by Francis Pettit Smith.” (Đoạn 6)</p>\n</li>\n<li>\n<p data-path-to-node=\"30,1,0\"><strong data-path-to-node=\"30,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ nhắc đến tên con tàu này như một ví dụ về việc dùng chân vịt, <strong data-path-to-node=\"30,1,0\" data-index-in-node=\"86\">không đề cập</strong> đến việc nó có được ngưỡng mộ rộng rãi (widely admired) hay không.</p>\n</li>\n</ul>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"31\" data-index-in-node=\"0\">13. Modern ships that cross the Atlantic use the same energy source as the early steamships. — {FALSE}</strong></p>\n<ul data-path-to-node=\"32\">\n<li>\n<p data-path-to-node=\"32,0,0\"><strong data-path-to-node=\"32,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…steam turbines have replaced engines with pistons with <strong data-path-to-node=\"32,0,0\" data-index-in-node=\"70\">fuel oil instead of coal</strong>… Diesel engines keep others moving.” (Đoạn 7)</p>\n</li>\n<li>\n<p data-path-to-node=\"32,1,0\"><strong data-path-to-node=\"32,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tàu hiện đại dùng dầu hỏa (fuel oil) hoặc diesel, trong khi tàu hơi nước đời đầu dùng than (coal).</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('9555580c-fa65-4f96-abb4-b8eebc1fcb49', '765f01d6-abb7-41b8-b35a-3b839543d5ef', 'matrix', 'Questions 14-20', '', '<p>Which section contains the following information?</p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "simple", "matrixItems": [{"itemText": "a description of a barrier designed to stop dingoes, which also divides two kinds of non-native animals", "correctCategoryLetter": "E"}, {"itemText": "how dingoes ensure that rival species do not dominate", "correctCategoryLetter": "D"}, {"itemText": "a reference to a widespread non-native species that other animals feed on", "correctCategoryLetter": "C"}, {"itemText": "a mention of the dingo''s arrival in Australia", "correctCategoryLetter": "B"}, {"itemText": "research which has proved that dingoes have resorted to eating young livestock", "correctCategoryLetter": "F"}, {"itemText": "a description of a method used to kill dingoes", "correctCategoryLetter": "A"}, {"itemText": "the way that the structure of dingo groups affects how quickly their numbers grow", "correctCategoryLetter": "D"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}, {"categoryText": "H", "categoryLetter": "H"}]}', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">14. a description of a barrier designed to stop dingoes, which also divides two kinds of non-native animals — {E}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…the world’s longest <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"35\">fence</strong>… it is there to keep dingoes out… the fence <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"89\">separates the main types of livestock</strong>… cattle… sheep.”</p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn E mô tả hàng rào (barrier) dài 2.500 km dùng để ngăn dingo và chia cắt khu vực chăn nuôi bò (cattle) và cừu (sheep) — hai loài động vật không bản địa.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">15. how dingoes ensure that rival species do not dominate — {D}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…dingoes are the solution… because they <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"56\">keep cat and fox populations under control</strong>. Besides regularly eating the smaller predators, dingoes will <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"161\">kill them simply to lessen competition</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Chó dingo kiểm soát số lượng các loài đối thủ (mèo rừng, cáo) bằng cách ăn thịt hoặc giết chúng để giảm sự cạnh tranh.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">16. a reference to a widespread non-native species that other animals feed on — {C}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…the <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"19\">rabbit</strong> was unleashed on Australia… Rabbits provide <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"72\">huge prey base for two other introduced species</strong>: the feral cat and the red fox.”</p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Thỏ là loài ngoại lai lan rộng và là nguồn thức ăn chính cho mèo và cáo.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">17. a mention of the dingo’s arrival in Australia — {B}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “About <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"18\">4,000 years ago</strong>, Asian sailors <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"49\">introduced dingoes to Australia</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn B nói về thời điểm và cách thức chó dingo đặt chân đến nước Úc.</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">18. research which has proved that dingoes have resorted to eating young livestock — {F}</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…study… some of the <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"36\">highest rates of calf predation occurred in areas that had been baited</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Nghiên cứu của Lee Allen cho thấy ở những nơi bị đánh bả, các con dingo trẻ và đơn độc đã chuyển sang ăn thịt bê (young livestock) do không săn được kangaroo.</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">19. a description of a method used to kill dingoes — {A}</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…drop 1,000 small pieces of meat… each piece <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"61\">laced with poison</strong>; this practice is known as <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"106\">baiting</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn A mô tả phương pháp rải thịt tẩm thuốc độc (đánh bả) từ máy bay để tiêu diệt dingo.</p>\n</li>\n</ul>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">20. the way that the structure of dingo groups affects how quickly their numbers grow — {D}</strong></p>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong data-path-to-node=\"17,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Dingo packs… generally have <strong data-path-to-node=\"17,0,0\" data-index-in-node=\"42\">only one fertile female, which limits their rate of increase</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong data-path-to-node=\"17,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cấu trúc bầy đàn (chỉ một con cái sinh sản) giúp giới hạn tốc độ tăng trưởng số lượng của chúng.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('a04e7079-85fe-455c-bdd1-aeed1e97c24e', '9a8c54d0-fadf-4120-aba9-afd6f8ef67b7', 'radio', 'Questions 28 – 32', '', '<p>Choose<strong data-path-to-node="5,0" data-index-in-node="0"> TRUE</strong> if the statement agrees with the information,<strong data-path-to-node="5,0" data-index-in-node="50">FALSE</strong> if the statement contradicts the information,<strong data-path-to-node="5,0" data-index-in-node="101">NOT GIVEN</strong> if there is no information on this</p>', 'true_false_not_given', '[{"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The original festival was connected to agriculture."}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The festival has been celebrated without a break for hundreds of years."}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The Straw Bear costume must be worn by a local resident."}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Some of Whittlesey’s residents attend the festival in Walldurn too."}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Dorothy and Frank are typical of the procession members."}]', 'null', 'null', 'null', '[{"content": "<p><strong data-path-to-node=\"4\" data-index-in-node=\"0\">28. The original festival was connected to agriculture. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"5\">\n<li><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn C):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“What is certain is that the original Straw Bear Festival ran for centuries, <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"97\">celebrating Plough Monday</strong> – the bear raising money for that year’s <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"164\">crop</strong>…”</em></li>\n<li><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc có nhắc đến “Plough Monday” (Ngày thứ Hai đi cày) và “crop” (vụ mùa) — những thứ liên quan đến nông nghiệp (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"128\">agriculture</strong>). Tuy nhiên, đề bài hỏi liệu lễ hội <em data-path-to-node=\"5,1,0\" data-index-in-node=\"176\">nguyên thủy</em> có “kết nối” với nông nghiệp hay không, trong khi bài chỉ nói nó dùng để “ăn mừng” và “quyên góp tiền cho vụ mùa”.</li>\n</ul>\n<p><strong data-path-to-node=\"6\" data-index-in-node=\"0\">29. The festival has been celebrated without a break for hundreds of years. — {FALSE}</strong></p>\n<ul data-path-to-node=\"7\">\n<li><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn C):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“The custom <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"32\">died out in 1909</strong>… but was <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"60\">revived in 1980</strong> by Brian Kell…”</em></li>\n<li><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Without a break” nghĩa là liên tục không nghỉ. Nhưng bài đọc xác nhận lễ hội đã bị lụi tàn/ngừng lại vào năm 1909 và mãi đến năm 1980 mới được khôi phục lại. Vậy là có một quãng nghỉ dài hơn 70 năm.</li>\n</ul>\n<p><strong data-path-to-node=\"8\" data-index-in-node=\"0\">30. The Straw Bear costume must be worn by a local resident. — {TRUE}</strong></p>\n<ul data-path-to-node=\"9\">\n<li><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn C):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">“…the man inside – known as ‘the driver’ and <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"67\">selected exclusively from the population of Whittlesey</strong>…”</em></li>\n<li><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Selected exclusively from the population of Whittlesey” nghĩa là chỉ được chọn duy nhất từ dân cư vùng Whittlesey. Điều này đồng nghĩa với việc người mặc trang phục phải là cư dân địa phương (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"205\">local resident</strong>).</li>\n</ul>\n<p><strong data-path-to-node=\"10\" data-index-in-node=\"0\">31. Some of Whittlesey’s residents attend the festival in Walldurn too. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"11\">\n<li><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn C):</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"20\">“He is joined from time to time by a slightly smaller bear who <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"83\">travels over from Walldurn, in Germany</strong>, where a similar festival is held…”</em></li>\n<li><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ nói có người từ Walldurn (Đức) sang tham gia lễ hội ở Anh. Còn việc cư dân Whittlesey có sang Đức tham gia lễ hội bên đó hay không thì <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"159\">không được nhắc tới</strong>.</li>\n</ul>\n<p><strong data-path-to-node=\"12\" data-index-in-node=\"0\">32. Dorothy and Frank are typical of the procession members. — {FALSE}</strong></p>\n<ul data-path-to-node=\"13\">\n<li><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn E):</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"20\">“Dorothy and Frank are <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"43\">unusually talkative</strong> for Straw Bearers. <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"82\">By contrast</strong>, most of the <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"107\">locals remain tight-lipped</strong>…”</em></li>\n<li><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Typical” nghĩa là điển hình/giống với đa số. Bài đọc nói Dorothy và Frank “nói nhiều một cách bất thường”, trái ngược với đa số người dân địa phương vốn “kín tiếng” (tight-lipped). Do đó, họ không phải là những thành viên điển hình.</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('95a53696-ea61-400b-8b31-f4e42e0e9eb0', '390674a8-0f9c-4184-b071-7e638ff6fffb', 'matching', 'Questions 14 – 20', '', '<p><span class="citation-3788 citation-3789 citation-3790 citation-3791 citation-3792">Write the correct number, </span><strong data-path-to-node="7" data-index-in-node="26"><span class="citation-3788 citation-3789 citation-3790 citation-3791 citation-3792">i-viii</span></strong><span class="citation-3788 citation-3789 citation-3790 citation-3791 citation-3792 citation-end-3792">, in boxes 14-20 on your answer sheet.</span></p>', 'matching_paragraph_information', 'null', 'null', '{"layoutType": "heading", "summaryText": "", "answerOptions": [{"optionText": "i Technological developments improve CRSP data"}, {"optionText": "ii Initial findings of the CRSP project"}, {"optionText": " iii A request and a far-reaching result"}, {"optionText": "iv Difficulties in collecting CRSP data"}, {"optionText": "v What the future holds"}, {"optionText": "vi Too much data for people to have an overall understanding"}, {"optionText": "vii Other university departments which depend on CRSP"}, {"optionText": "viii CRSP data not always being a useful basis for investment"}], "matchingItems": []}', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">14. Paragraph A — {iii. A request and a far-reaching result}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"11\">“It all began in 1958 with a <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"40\">phone call from Louis Engel… who wanted to know</strong> [A request]… The result… was the launch of the University’s Center for Research in Security Prices… <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"196\">data are everywhere. They provided the foundation of at least one-third of all empirical research</strong> [A far-reaching result].”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn A kể về một lời yêu cầu (request) từ Louis Engel hỏi về hiệu suất cổ phiếu và kết quả là sự ra đời của CRSP – một tổ chức có tầm ảnh hưởng sâu rộng (far-reaching), cung cấp nền tảng cho 1/3 nghiên cứu tài chính 40 năm qua.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">15. Paragraph B — {iv. Difficulties in collecting CRSP data}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"11\">“Getting the CRSP data together was a <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"49\">tough process</strong>… pieces of information… were <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"96\">transferred from paper… to magnetic tape</strong>. A lot of <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"149\">time was spent adjusting prices to take account of complexities</strong>…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn B mô tả quy trình thu thập dữ liệu đầy khó khăn (difficulties/tough process) trong thời kỳ đầu của máy tính, bao gồm việc chuyển dữ liệu từ giấy sang băng từ và xử lý các biến số phức tạp của thị trường.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">16. Paragraph C — {ii. Initial findings of the CRSP project}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"11\">“When these two economists published the <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"52\">first study</strong>… they <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"72\">reported</strong> that the annual compound return… between 6.8% and 9%… the study claimed that the rate of return on shares was <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"195\">substantially higher than for alternative investment</strong>…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn C tập trung vào những phát hiện đầu tiên (initial findings) của dự án: cổ phiếu có tỉ lệ lợi nhuận cao hơn các kênh khác và đưa ra khái niệm “equity risk premium” (phần bù rủi ro vốn cổ phần).</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">17. Paragraph D — {i. Technological developments improve CRSP data}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"11\">“…this resource became <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"36\">ever more useful as computing power became more affordable</strong>. The CRSP database has since been <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"129\">expanded</strong> to include a full range of different types of investments.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn D nói về việc dữ liệu CRSP ngày càng hoàn thiện và hữu ích hơn nhờ vào sự phát triển của công nghệ máy tính (computing power) giúp việc xử lý dữ liệu rẻ và nhanh hơn.</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">18. Paragraph E — {viii. CRSP data not always being a useful basis for investment}</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"11\">“…meaning there are <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"33\">no predictable movements</strong> in prices for smart investors to exploit… it seems that <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"116\">no sooner are such anomalies discovered and reported… than they typically disappear</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn E thảo luận về “giả thuyết thị trường hiệu quả”. Dữ liệu cho thấy giá biến động ngẫu nhiên và các kịch bản kiếm lời (anomalies) thường biến mất ngay khi bị phát hiện. Vì vậy, dữ liệu lịch sử không phải lúc nào cũng là cơ sở hữu ích (not always a useful basis) để đầu tư sinh lời trong thực tế.</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">19. Paragraph F — {vi. Too much data for people to have an overall understanding}</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"15,0,0\" data-index-in-node=\"11\">“Some economists worry that much of this statistical analysis is… <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"79\">drowning out serious thinking</strong>… economists who are <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"131\">so specialized in data analysis that they fail to see and understand the whole</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Robert Shiller lo ngại rằng việc có quá nhiều dữ liệu khiến các nhà kinh tế quá sa đà vào chi tiết (chuyên môn hóa hẹp) mà mất đi cái nhìn tổng thể (fail to see the whole/overall understanding), dẫn đến việc không dự báo được các cuộc khủng hoảng lớn như năm 2008.</p>\n</li>\n</ul>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">20. Paragraph G — {v. What the future holds}</strong></p>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong data-path-to-node=\"17,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"17,0,0\" data-index-in-node=\"11\">“…<strong data-path-to-node=\"17,0,0\" data-index-in-node=\"15\">plans were unveiled</strong> to publish indicators on an <strong data-path-to-node=\"17,0,0\" data-index-in-node=\"63\">expanding range of investments</strong>… these indicators… will be more academically rigorous and cheaper… ensure CRSP’s <strong data-path-to-node=\"17,0,0\" data-index-in-node=\"181\">continuing success</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong data-path-to-node=\"17,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn cuối nói về các kế hoạch tương lai (plans/future) của CRSP: mở rộng phạm vi chỉ số đầu tư và duy trì sự thành công bền vững.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('d2c098f4-abd8-4334-949b-8c2da15fe6a0', '9c785f96-eb67-439a-b7ea-d01f8f297493', 'matrix', 'Questions 23–26', NULL, '<p>Look at the following statements (Questions 23–26) and the list of people below.</p>
<p>Match each statement with the correct person, <strong>A–E</strong>.</p>
', 'other', NULL, NULL, '{"layoutType": "standard", "summaryText": null, "answerOptions": [{"optionText": "Yanira Pineda"}, {"optionText": "Susanna Tol"}, {"optionText": "Elizabeth English"}, {"optionText": "Raisa Chowdhury"}, {"optionText": "Greg Spotts"}], "matchingItems": [{"questionPart": "It is essential to adopt strategies which involve and help residents of the region.", "correctAnswer": "Susanna Tol", "sectionContent": null}, {"questionPart": "Interventions which reduce heat are absolutely vital for our survival in this location.", "correctAnswer": "Greg Spotts", "sectionContent": null}, {"questionPart": "More work will need to be done in future decades to deal with the impact of rising water levels.", "correctAnswer": "Yanira Pineda", "sectionContent": null}, {"questionPart": "The number of locations requiring action to adapt to flooding has grown in recent years.", "correctAnswer": "Elizabeth English", "sectionContent": null}]}', '{"layoutType": "standard", "legendTitle": "List of people", "matrixItems": [{"itemText": "It is essential to adopt strategies which involve and help residents of the region.", "correctCategoryLetter": "B"}, {"itemText": "Interventions which reduce heat are absolutely vital for our survival in this location.", "correctCategoryLetter": "E"}, {"itemText": "More work will need to be done in future decades to deal with the impact of rising water levels.", "correctCategoryLetter": "A"}, {"itemText": "The number of locations requiring action to adapt to flooding has grown in recent years.", "correctCategoryLetter": "C"}], "matrixCategories": [{"categoryText": "Yanira Pineda", "categoryLetter": "A"}, {"categoryText": "Susanna Tol", "categoryLetter": "B"}, {"categoryText": "Elizabeth English", "categoryLetter": "C"}, {"categoryText": "Raisa Chowdhury", "categoryLetter": "D"}, {"categoryText": "Greg Spotts", "categoryLetter": "E"}]}', '[{"content": "<p>23. B – Susanna Tol<br />(Đoạn C: “&#8230;it’s critical that we transition towards multifunctional approaches that embed natural processes and that engage and benefit communities and local decision-makers.”)<br />→ Tol nhấn mạnh rằng các chiến lược thành công cần sự tham gia và hỗ trợ của người dân địa phương, cũng như chính quyền. → B.</p>\n<p> <br />24. E – Greg Spotts<br />(Đoạn F: “Urban cooling is literally a matter of life and death for our future in LA.”)<br />→ Spotts nói rằng giảm nhiệt đô thị là yếu tố sống còn cho tương lai thành phố Los Angeles, nên các biện pháp làm mát là rất cần thiết để tồn tại. → E.</p>\n<p> <br />25. A – Yanira Pineda<br />(Đoạn B: “&#8230;she knows that they’re essential. In the face of floods, climate-mitigation strategies have often been overlooked.”)<br />→ Pineda nói rằng cần phải làm nhiều hơn trong các thập kỷ tới để đối phó với mực nước biển dâng, và các chiến lược giảm nhẹ là điều không thể thiếu. → A.</p>\n<p> <br />26. C – Elizabeth English<br />(Đoạn D: “We know that in 20, 30, 40 years, we’ll need to go back in there and adjust to the changing environment.”)<br />→ English dự đoán rằng trong tương lai sẽ có nhiều khu vực hơn cần điều chỉnh và thích ứng với ngập lụt, vì môi trường tiếp tục thay đổi. → C.</p>\n"}]', 2);
INSERT INTO public.questions VALUES ('b509551d-1d69-42c5-b5ee-39cdae416cd7', '765f01d6-abb7-41b8-b35a-3b839543d5ef', 'matrix', 'Questions 21-23', '', '<p>Match each statement with the correct person (<strong>A</strong>, <strong>B</strong>, <strong>C </strong>or <strong>D</strong>).</p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": "List of people", "matrixItems": [{"itemText": "Dingoes tend to hunt native animals rather than hunting other non-native predators.", "correctCategoryLetter": "D"}, {"itemText": "The presence of dingoes puts the income of some people at risk.", "correctCategoryLetter": "A"}, {"itemText": "Dingoes have had little impact on the dying out of animal species in Australia.", "correctCategoryLetter": "B"}], "matrixCategories": [{"categoryText": "Stuart McKechnie", "categoryLetter": "A"}, {"categoryText": "Chris Johnson", "categoryLetter": "B"}, {"categoryText": "Lee Allen", "categoryLetter": "C"}, {"categoryText": "Mark Clifford", "categoryLetter": "D"}]}', '[{"content": "<ul>\n<li>\n<p data-path-to-node=\"3,0,0\"><strong data-path-to-node=\"3,0,0\" data-index-in-node=\"0\">21. Dingoes tend to hunt native animals rather than hunting other non-native predators. — {D} Mark Clifford</strong></p>\n<ul data-path-to-node=\"3,0,1\">\n<li>\n<p data-path-to-node=\"3,0,1,0,0\"><strong data-path-to-node=\"3,0,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Clifford… is <strong data-path-to-node=\"3,0,1,0,0\" data-index-in-node=\"27\">not convinced</strong> that they manage to catch cats that often, believing they are <strong data-path-to-node=\"3,0,1,0,0\" data-index-in-node=\"103\">more likely to catch small native animals</strong> instead.” (Đoạn G)</p>\n</li>\n<li>\n<p data-path-to-node=\"3,0,1,1,0\"><strong data-path-to-node=\"3,0,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Mark Clifford là người phản đối dingo. Ông không tin dingo giúp ích cho sinh thái bằng cách bắt mèo/cáo, mà cho rằng chúng sẽ ăn thịt các loài vật bản địa nhỏ (small native animals).</p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"3,1,0\"><strong data-path-to-node=\"3,1,0\" data-index-in-node=\"0\">22. The presence of dingoes puts the income of some people at risk. — {A} Stuart McKechnie</strong></p>\n<ul data-path-to-node=\"3,1,1\">\n<li>\n<p data-path-to-node=\"3,1,1,0,0\"><strong data-path-to-node=\"3,1,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Stuart McKechnie… complains that <strong data-path-to-node=\"3,1,1,0,0\" data-index-in-node=\"47\">graziers’ livelihoods are threatened</strong> when dingoes prey on cattle.” (Đoạn A)</p>\n</li>\n<li>\n<p data-path-to-node=\"3,1,1,1,0\"><strong data-path-to-node=\"3,1,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> McKechnie là quản lý trang trại, ông khẳng định sinh kế (livelihoods) hay thu nhập của nông dân bị đe dọa khi dingo săn bắt gia súc.</p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"3,2,0\"><strong data-path-to-node=\"3,2,0\" data-index-in-node=\"0\">23. Dingoes have had little impact on the dying out of animal species in Australia. — {B} Chris Johnson</strong></p>\n<ul data-path-to-node=\"3,2,1\">\n<li>\n<p data-path-to-node=\"3,2,1,0,0\"><strong data-path-to-node=\"3,2,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “In the 4,000 years that dingoes have been Australia, they have contributed to <strong data-path-to-node=\"3,2,1,0,0\" data-index-in-node=\"90\">few, if any, extinctions</strong>, Johnson says.” (Đoạn D)</p>\n</li>\n<li>\n<p data-path-to-node=\"3,2,1,1,0\"><strong data-path-to-node=\"3,2,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Giáo sư Chris Johnson là người bảo vệ dingo. Ông đưa ra số liệu lịch sử rằng dingo rất ít khi (hoặc chưa từng) gây ra sự tuyệt chủng (extinction) cho các loài khác.</p>\n</li>\n</ul>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('240114cf-0ad3-43da-bbfd-485a0409101e', '16b5fe53-5af2-4dfc-8826-8dd5bb934d50', 'radio', 'Question 34-36', NULL, '<p>Choose the correct answers</p>
', 'multiple_choice_single', '[{"correct": 2, "options": [{"content": "Interest students in careers in industry"}, {"content": "Help provide finance for universities"}, {"content": "Find useful new design features"}], "question": " The purpose of holding the race is to"}, {"correct": 0, "options": [{"content": "The software design"}, {"content": "Good, solid construction"}, {"content": "Sophisticated mechanisms"}], "question": "The tutor says success will depend on"}, {"correct": 1, "options": [{"content": "Were so easy to design"}, {"content": "Were as successful as they were"}, {"content": "Took such a short time to construct"}], "question": "This year’s competitors were surprised that the vehicles"}]', 'null', 'null', 'null', '[{"content": "<p>1</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('52aa5943-4dd1-432f-9880-db0f8760e457', '1098faf0-b686-4692-9b43-9e095d1476f5', 'radio', 'Questions 1–7', NULL, '<p>Choose <strong>TRUE</strong> if the statement agrees with the information given in the text, choose <strong>FALSE </strong>if the statement contradicts the information, or choose <strong>NOT GIVEN</strong> if there is no information on this.</p>
', 'multiple_choice_single', '[{"correct": 2, "options": [{"content": "TRUE"}, {"content": " FALSE "}, {"content": "NOT GIVEN"}], "question": "Early European settlers made detailed studies of the morepork."}, {"correct": 1, "options": [{"content": "TRUE"}, {"content": " FALSE "}, {"content": "NOT GIVEN"}], "question": "The Polynesian rat had a negative effect on the number of laughing owls."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": " FALSE "}, {"content": "NOT GIVEN"}], "question": "The laughing owl was larger than the morepork"}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": " FALSE "}, {"content": "NOT GIVEN"}], "question": "Rats pose a risk to young moreporks."}, {"correct": 1, "options": [{"content": "TRUE"}, {"content": " FALSE "}, {"content": "NOT GIVEN"}], "question": "The New Zealand Department of Conservation is hoping to limit the population of moreporks."}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": " FALSE "}, {"content": "NOT GIVEN"}], "question": "Other bird species are frightened away when they hear the morepork’s cry."}, {"correct": 1, "options": [{"content": "TRUE"}, {"content": " FALSE "}, {"content": "NOT GIVEN"}], "question": "In Maori tradition, the low call of the morepork had negative associations."}]', 'null', 'null', 'null', '[{"content": "<p>1. Early European settlers made detailed studies of the morepork.</p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong>Đáp án:</strong> <strong>NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 1) Văn bản đề cập đến việc những người châu Âu định cư đã đến (<em>“European settlers arrived in the middle of the 19th century”</em>), nhưng không có thông tin chi tiết về việc họ có thực hiện các nghiên cứu tỉ mỉ (<em>detailed studies</em>) về chim morepork hay không.</p>\n</li>\n<li>\n<p data-path-to-node=\"4,2,0\"><strong>Giải thích:</strong> Không có thông tin để xác nhận hoặc phủ nhận tuyên bố này.</p>\n</li>\n</ul>\n<p>2. The Polynesian rat had a negative effect on the number of laughing owls.</p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong>Đáp án:</strong> <strong>FALSE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 1) “Where other native birds suffered from predation by the Polynesian rat, the laughing turned the tables and <strong>adapted its diet to include the rodent</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"6,2,0\"><strong>Giải thích:</strong> Chim cú cười (<em>laughing owl</em>) đã thích nghi và ăn thịt chuột Polynesian, vì vậy chuột trở thành nguồn thức ăn và <strong>không gây tác động tiêu cực</strong> lên số lượng chim cú cười.</p>\n</li>\n</ul>\n<p>3. The laughing owl was larger than the morepork.</p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong>Đáp án:</strong> <strong>TRUE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 1) Chim cú cười có khả năng bắt và giết <strong>“the other New Zealand owl, the Morepork, and even larger birds, such as the weka”</strong>.</p>\n</li>\n<li>\n<p data-path-to-node=\"8,2,0\"><strong>Giải thích:</strong> Việc cú cười có thể bắt và giết Morepork (<em>“capable of catching and killing the other New Zealand owl, the Morepork”</em>) ngụ ý rằng nó lớn hơn Morepork.</p>\n</li>\n</ul>\n<p>4. Rats pose a risk to young moreporks.</p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong>Đáp án:</strong> <strong>TRUE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 6) “…and <strong>eggs and chicks are also be at risk from rats</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"10,2,0\"><strong>Giải thích:</strong> Chuột là mối đe dọa đối với trứng và chim non Morepork.</p>\n</li>\n</ul>\n<p>5. The New Zealand Department of Conservation is hoping to limit the population of moreporks.</p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong>Đáp án:</strong> <strong>FALSE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 7) “The New Zealand Department of Conservation is taking steps to <strong>ensure the preservation</strong> of New Zealand’s only native owl… it is hoped that the morepork will <strong>continue to survive and thrive</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"12,2,0\"><strong>Giải thích:</strong> Mục tiêu của cơ quan bảo tồn là <strong>bảo tồn</strong> (preservation) và giúp Morepork <strong>sinh tồn và phát triển</strong> (<em>survive and thrive</em>), trái ngược với việc hạn chế số lượng.</p>\n</li>\n</ul>\n<p>6. Other bird species are frightened away when they hear the morepork’s cry.</p>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong>Đáp án:</strong> <strong>NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 8) Văn bản nói tiếng kêu <em>ruru</em> là để <strong>gọi các con khác và tuyên bố lãnh thổ</strong> (<em>“calls to other moreporks and claims territory”</em>), nhưng không nói về phản ứng sợ hãi của các loài chim khác.</p>\n</li>\n<li>\n<p data-path-to-node=\"14,2,0\"><strong>Giải thích:</strong> Không có thông tin để xác nhận việc tiếng kêu gây sợ hãi.</p>\n</li>\n</ul>\n<p>7. In Maori tradition, the low call of the morepork had negative associations.</p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong>Đáp án:</strong> <strong>FALSE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"16,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 8) “The occasional high, piercing call of the morepork signified bad news, but the <strong>lower-pitched and more common ‘ruru’ call heralded good news</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"16,2,0\"><strong>Giải thích:</strong> Tiếng kêu <em>thấp</em> (<em>lower-pitched</em>) và phổ biến hơn (<em>ruru</em>) mang lại điềm <strong>lành</strong> (<em>good news</em>), trái ngược với nhận định về sự liên hệ tiêu cực (negative associations).</p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('1c1aa34f-61ab-48ad-b7d6-120c370d0d81', '597f0956-1ce6-4b86-a544-8d889853bbde', 'checkbox', 'Questions 17-18', '', '<div class="quests-inner-desc">
<div class="txt">Choose <strong>TWO</strong> correct answers.</div>
</div>
<div class="quests-list">
<div id="1310" class="quests-item quests-numctn quests-item-history quests-skip" data-question-id="407" data-numctn="17" data-count="17" data-quest="17-18" data-choices="2">
<div class="tt-head">
<p class="tt"><span class="numquest">17-18</span> Which TWO types of accommodation are available on a weekly basis?</p>
</div>
</div>
</div>', 'multiple_choice_many', 'null', '[{"correct": false, "option_text": "lighthouse"}, {"correct": true, "option_text": "hostel"}, {"correct": false, "option_text": "castle"}, {"correct": true, "option_text": "cottages"}, {"correct": false, "option_text": "bed and breakfast"}]', 'null', 'null', 'null', 1);
INSERT INTO public.questions VALUES ('7e8a3ce6-7328-4898-8e6e-2872bac181ea', 'd7cb58be-aa39-4b65-96aa-60db984bb893', 'radio', 'Questions 1-6', NULL, '<p>Choose <strong>TRUE </strong>if the statement agrees with the information given in the text, choose <strong>FALSE </strong>if the statement contradicts the information, or choose <strong>NOT GIVEN </strong>if there is no information on this.</p>
', 'multiple_choice_single', '[{"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "The instrument found in Queen Shub-Ad’s tomb is the world’s oldest known version of a harp"}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Today’s Afghan panchtar is very similar to an ancient Mesopotamian instrument."}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "The Egyptian singer Har-Mole was an excellent tanbur player."}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Cairo Archaeological Museum contains many historic musical instruments."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "The instrument carved in stone at Alaca Huyuk is consistent with Dr Michael Kasha’s definition of a guitar"}, {"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "The different instruments that appeared in medieval literature had the same number of strings."}]', 'null', 'null', 'null', '[{"content": "<p>1. The instrument found in Queen Shub-Ad’s tomb is the world’s oldest known version of a harp.</p>\n<ul data-path-to-node=\"3\">\n<li>\n<p data-path-to-node=\"3,0,0\"><strong>Đáp án: FALSE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"3,1,0\"><strong>Dẫn chứng:</strong> (Đoạn A) “The <strong>earliest stringed instruments currently known</strong> to archaeologists are bowl harps… Around 2500-2000 BC more advanced harps, such as the beautifully carved 11-stringed instrument <strong>found in the tomb of Queen Shub-Ad</strong>… <strong>started to appear</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"3,2,0\"><strong>Giải thích:</strong> Bowl harps là những nhạc cụ dây được biết đến sớm nhất. Cây đàn trong lăng mộ Queen Shub-Ad là một ví dụ về harp <strong>tiên tiến hơn</strong> (more advanced) và <strong>chỉ bắt đầu xuất hiện</strong> khoảng 2500-2000 TCN, trong khi bowl harps đã có từ hàng thiên niên kỷ trước.</p>\n</li>\n</ul>\n<p>2. Today’s Afghan panchtar is very similar to an ancient Mesopotamian instrument.</p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong>Đáp án: TRUE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong>Dẫn chứng:</strong> (Đoạn B) “Archaeologists have also found <strong>many similar relics amongst the ruins of the ancient Mesopotamian civilisation</strong>. <span class=\"citation-9\">Many of these instruments have </span><strong><span class=\"citation-9\">survived into modern times in almost unchanged form</span></strong><span class=\"citation-9\">, for example folk instruments of the region such as the Turkish saz and Afghan </span><strong><span class=\"citation-9\">panchtar</span></strong><span class=\"citation-9 citation-end-9\">.”</span></p>\n<p>&nbsp;</li>\n<li>\n<p data-path-to-node=\"5,2,0\"><strong>Giải thích:</strong> Văn bản khẳng định panchtar ngày nay rất giống (almost unchanged form) với các di vật cổ của Lưỡng Hà (Mesopotamian).</p>\n</li>\n</ul>\n<p>3. The Egyptian singer Har-Mole was an excellent tanbur player.</p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong>Đáp án: NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong>Dẫn chứng:</strong><span class=\"citation-8\"> (Đoạn C) “At 3,500 years old, the tanbur which belonged to the Egyptian </span><strong><span class=\"citation-8\">singer Har-Mose</span></strong><span class=\"citation-8 citation-end-8\"> is the earliest known example of this instrument.</span></p>\n<p>&nbsp;</li>\n<li>\n<p data-path-to-node=\"7,2,0\"><strong>Giải thích:</strong> Har-Mose được biết đến là ca sĩ, nhưng <strong>không có thông tin</strong> đánh giá khả năng chơi tanbur của ông.</p>\n</li>\n</ul>\n<p>4. <span class=\"citation-7 citation-end-7\">Cairo Archaeological Museum contains many historic musical instruments.</span></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong>Đáp án: NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong>Dẫn chứng:</strong> (Đoạn C) “It can be seen today at the <strong>Archaeological Museum in Cairo</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"9,2,0\"><strong>Giải thích:</strong> Văn bản chỉ nói chiếc tanbur của Har-Mose được trưng bày ở đó, <strong>không đề cập</strong> đến số lượng nhạc cụ lịch sử nói chung.</p>\n</li>\n</ul>\n<p>5. The instrument carved in stone at Alaca Huyuk is consistent with Dr Michael Kasha’s definition of a guitar.</p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong>Đáp án: TRUE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong>Dẫn chứng:</strong> (Đoạn D) “Dr Michael Kasha defines a guitar as having ‘a long, fretted neck, flat wooden soundboard, ribs, and a <strong>flat back, most often with sides that curve inwards</strong>‘… The oldest known visual representation… shows a 3,300-year-old instrument with a long neck and <strong>sides that clearly curve inwards</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"11,2,0\"><strong>Giải thích:</strong> Mô tả về nhạc cụ ở Alaca Huyuk (“long neck and sides that clearly curve inwards”) <strong>phù hợp</strong> (consistent) với phần định nghĩa quan trọng của Kasha.</p>\n</li>\n</ul>\n<p>6. The different instruments that appeared in medieval literature had the same number of strings.</p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong>Đáp án: FALSE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong>Dẫn chứng:</strong> (Đoạn F) “The earliest guitar-like instruments to arrive in Europe had, most often, <strong>four strings</strong>. Many such instruments, and <strong>variations with from three to five strings</strong>, can be seen in mediaeval illustrated manuscripts.”</p>\n</li>\n<li>\n<p data-path-to-node=\"13,2,0\"><strong>Giải thích:</strong> Các nhạc cụ này có số lượng dây khác nhau (từ ba đến năm), mâu thuẫn với việc có cùng số lượng dây.</p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('efa21f2a-0785-434b-a969-b1034b57a0cb', '07102e8a-fbfb-4807-85f6-b9a79dbcdeb3', 'fillup', 'Questions 1–10', '<p>Write <strong>ONE WORD AND/OR A NUMBER</strong> for each answer.</p>
<p><span style="font-size: 14pt;"><strong>Planning a party</strong></span></p>
<p><em>Example</em></p>
<p>Reason for event: wife’s <strong><span style="text-decoration: underline;">promotion</span></strong><br><strong> </strong></p>
<p><strong>EVENT DETAILS</strong></p>
<p>Event option: large surprise party</p>
<p>Number of people: {80}</p>
<p>Date: {26 September | 26th September}</p>
<p>Day of week: Friday</p>
<p>Time: 6 – 10 p.m.</p>
<p>Location: the {king} Room</p>
<p>Type of music {jazz}</p>
<p><strong>FOOD</strong></p>
<p>Service option {table}</p>
<p>Flavour of cake: {lemon}</p>
<p>Message on cake: {congratulations}</p>
<p><strong>PAYMENT</strong></p>
<p>Reservation fee paid: $100</p>
<p>Credit card type: Mastercard</p>
<p>Credit card number: {5544120043268887}</p>
<p>Name: Brian {SEBASTIAN} Troy</p>
<p>Additional fees: extra charge for {service}</p>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p><strong>Narrator:</strong> You will hear a telephone conversation between a man who is planning a party for his wife and a woman who organizes special events at a restaurant. First you have some time to look at questions 1 to 4 on page two. You will see that there is an example that has been done for you. On this occasion only, the conversation relating to this will be played first.</p>\n<p><strong>Michelle:</strong> Good afternoon, Good Time Restaurant.</p>\n<p><strong>Brian:</strong> Hi, is this Michelle?</p>\n<p><strong>Michelle:</strong> Yes, speaking.</p>\n<p><strong>Brian:</strong> This is Brian Troy. We spoke last week about planning a party to celebrate my wife’s promotion. Well, I would like to go ahead with it, and I have a list of things that I would like to go through with you.</p>\n<p><strong>Narrator:</strong> The reason for the event is his wife’s promotion, so <em>promotion</em> has been written in the space. Now we shall begin. You should answer the questions as you listen because you will not hear the recording a second time. Listen carefully and answer questions 1 to four.</p>\n<p><strong>Michelle:</strong> Good afternoon, Good Time Restaurant.</p>\n<p><strong>Brian:</strong> Hi, is this Michelle?</p>\n<p><strong>Michelle:</strong> Yes, speaking. This is Brian Troy. We spoke last week about planning a party to celebrate my wife’s promotion. Well, I would like to go ahead with it, and I have a list of things that I would like to go through with you.</p>\n<p><strong>Michelle:</strong> Yes, I remember. We’d spoken about a few dinner options, like a romantic dinner for two or a small group for dinner. Have you decided yet?</p>\n<p><strong>Brian:</strong> Well, I think I would like to surprise my wife with a huge party. In fact, I’ve already started to contact a few of our friends and family, as well as some of the people my wife works with.</p>\n<p><strong>Michelle:</strong> All right. So let’s get the party details confirmed. So how many guests would you like? Are you thinking of over 100?</p>\n<p><strong>Brian:</strong> No, I was thinking of more like 50, but then I realized that we have friends that are living out of town, so let’s say <span style=\"background-color: #f1c40f;\"><strong>(1) 80</strong></span> in case everyone wants to come.</p>\n<p><strong>Michelle:</strong> Okay. And do you still want October 6th?</p>\n<p><strong>Brian:</strong> Actually, no. I need to change that. My daughter can’t make it then because she has a piano recital. Would<span style=\"background-color: #f1c40f;\"> <strong>(2) </strong><strong>26th</strong> </span><strong><span style=\"background-color: #f1c40f;\">September</span> </strong>work for you?</p>\n<p><strong>Michelle:</strong> No problem. That date still open. Now, do you realize that’s not a Saturday? Are you okay with that?</p>\n<p><strong>Brian:</strong> Yes, I am. When I look at my schedule, Friday is a better choice for all of us.</p>\n<p><strong>Michelle:</strong> Great. Now we need to decide on the times. How does 6:00 to 10:00 sound?</p>\n<p><strong>Brian:</strong> That’s fine. So now let’s talk about the room. I have several options that might work: there’s the Queen Room, the Royal Room, the Palace Room, and the the <span style=\"background-color: #f1c40f;\"><strong>(3) King</strong> </span>Room.</p>\n<p><strong>Michelle:</strong> Right. I’ve been there before actually. We recently renovated that room, and I think that it would be great for your party. You’ll be very happy with it. Shall I book it for you?</p>\n<p><strong>Brian:</strong> Sure, that would be fine. Have you planned on having music while you’re eating?</p>\n<p><strong>Brian:</strong> Um, I hadn’t thought about it, but it would be nice.</p>\n<p><strong>Michelle:</strong> Well, you have some choices. We can arrange for a group to play jazz or one to play the latest pop.</p>\n<p><strong>Brian:</strong> I suspect my kids would prefer to have the pop music, but my wife is a<span style=\"background-color: #f1c40f;\"> <strong>(4) jazz</strong> </span>fan. So let’s book that.</p>\n<p><strong>Michelle:</strong> Okay, then I’ll book that today. They’re very good, and they might even sing at your table.</p>\n<p><strong>Brian:</strong> Great.</p>\n<hr>\n<p><strong>Narrator:</strong> Before you hear the rest of the conversation, you have some time to look at questions 5 to 10 on page two. Now listen and answer questions 5 to ten.</p>\n<p><strong>Michelle:</strong> Okay, now we need to talk about the type of<span style=\"background-color: #f1c40f;\"> <strong>(5) service</strong></span> you want for the dinner. We have two options: a self-service buffet or table.</p>\n<p><strong>Brian:</strong> Let’s go with the last choice.</p>\n<p><strong>Michelle:</strong> Just so you know, the price is the same for either chicken or a vegetarian plate. One last thing to decide on: are you planning anything special for your wife?</p>\n<p><strong>Brian:</strong> Well, uh, I was thinking that at 8:00 or so, I would like to have a cake brought out.</p>\n<p><strong>Michelle:</strong> Very nice. And because you’re making reservations for such a large group, the cake is complimentary. What flavor would you like?</p>\n<p><strong>Brian:</strong> Well, uh, it would have to be <span style=\"background-color: #f1c40f;\"><strong>(6) lemon</strong>.</span> I really love chocolate, but it is her day, so let’s go with her favorite.</p>\n<p><strong>Michelle:</strong> Good decision. Now let me tell you about the cakes. We have a square cake, which would easily serve all of your guests, or you could have two cheesecakes. They’re really popular right now.</p>\n<p><strong>Brian:</strong> I prefer the first option because I would like to have something special written on it. But let’s keep it simple. How about<span style=\"background-color: #f1c40f;\"> <strong>(7) congratulations</strong></span>?</p>\n<p><strong>Michelle:</strong> Okay, I can have our baker take care of that. He’s happy to show you what it would look like if you wish. Now, is there anything else?</p>\n<p><strong>Brian:</strong> No, I don’t think so. I think that we have pretty well talked about everything. So let’s look after the reservation detail. I’ll need to have a deposit of $50.</p>\n<p><strong>Brian:</strong> Let’s make it for <span style=\"background-color: #f1c40f;\"><strong>(8) $100</strong></span> and I’ll put it on my Mastercard. Is that okay?</p>\n<p><strong>Michelle:</strong> Sure. What’s the 16 digit account?</p>\n<p><strong>Brian:</strong> No. <span style=\"background-color: #f1c40f;\"><strong>(9) 5544120043268887</strong>.</span></p>\n<p><strong>Michelle:</strong> And it expires in November. Is there another name on the card beside Brian Troy? A middle name or initial?</p>\n<p><strong>Brian:</strong> Yes, <span style=\"background-color: #f1c40f;\"><strong>(10) Sebastian</strong>.</span> I will spell it for you: S-E-B-A-S-T-I-A-N.</p>\n<p><strong>Michelle:</strong> Is there anything else?</p>\n<p><strong>Brian:</strong> No, I think that’s it.</p>\n<p><strong>Michelle:</strong> However, you need to be aware of an additional fee for large groups. There is an extra charge which covers <strong>service</strong>, but I think that that’s all for now. We look forward to having your celebration dinner here.</p>\n<p><strong>Narrator:</strong> That is the end of Section 1. You now have half a minute to check your answers. Now turn to Section 2 on page 3.</p>"}]', 0);
INSERT INTO public.questions VALUES ('655504fa-c7e2-4e07-a87d-0501e40ac60d', 'd7cb58be-aa39-4b65-96aa-60db984bb893', 'fillup', 'Questions 7–13', '<p>Complete the table below.</p>
<p>Write<strong> ONE WORD ONLY </strong>from the passage for each answer.</p>
<p><span style="font-size: 12pt;"><strong>The development of the guitar</strong></span></p>
<table class="MsoNormalTable" style="border-collapse: collapse; border: 1px solid rgb(0, 0, 0); width: 100%; height: 255.75px;" border="1" cellpadding="0">
<thead>
<tr style="height: 42.1875px;">
<td style="border: 1px solid rgb(0, 0, 0); padding: 0.75pt; width: 14.8739%; text-align: center;">
<p><strong>Date</strong></p>
</td>
<td style="border: 1px solid rgb(0, 0, 0); padding: 0.75pt; width: 14.1049%; text-align: center;">
<p><strong>Type of instrument</strong></p>
</td>
<td style="border: 1px solid rgb(0, 0, 0); padding: 0.75pt; width: 69.5947%; text-align: center;">
<p><strong>Notes</strong></p>
</td>
</tr>
</thead>
<tbody>
<tr style="height: 50.5938px;">
<td style="border: 1px solid rgb(0, 0, 0); padding: 0.75pt; width: 14.8739%;">
<p><strong>13th–19th century</strong></p>
</td>
<td style="border: 1px solid rgb(0, 0, 0); padding: 0.75pt; width: 14.1049%;">
<p>Chitarra</p>
</td>
<td style="border: 1px solid rgb(0, 0, 0); padding: 0.75pt; width: 69.5947%;">
<p>was a development of an earlier instrument called the {Chartar} • extra strings added in 16th century in Italy</p>
</td>
</tr>
<tr style="height: 50.5938px;">
<td style="border: 1px solid rgb(0, 0, 0); padding: 0.75pt; width: 14.8739%;">
<p><strong>from around the 1850s</strong></p>
</td>
<td style="border: 1px solid rgb(0, 0, 0); padding: 0.75pt; width: 14.1049%;">
<p>Classical guitar</p>
</td>
<td style="border: 1px solid rgb(0, 0, 0); padding: 0.75pt; width: 69.5947%;">
<p>its shape a result of modifications including a larger {body} introduced by Antonio Torres • changes produced better tone and greater {volume}</p>
</td>
</tr>
<tr style="height: 70.1875px;">
<td style="border: 1px solid rgb(0, 0, 0); padding: 0.75pt; width: 14.8739%;"> </td>
<td style="border: 1px solid rgb(0, 0, 0); padding: 0.75pt; width: 14.1049%;">
<p>X-braced top guitar</p>
</td>
<td style="border: 1px solid rgb(0, 0, 0); padding: 0.75pt; width: 69.5947%;">
<p>first made in {America} in mid-19th century • strings made of {steel} became available around 1900</p>
</td>
</tr>
<tr style="height: 42.1875px;">
<td style="border: 1px solid rgb(0, 0, 0); padding: 0.75pt; width: 14.8739%;">
<p><strong>1920s onwards</strong></p>
</td>
<td style="border: 1px solid rgb(0, 0, 0); padding: 0.75pt; width: 14.1049%;">
<p>Electric guitar</p>
</td>
<td style="border: 1px solid rgb(0, 0, 0); padding: 0.75pt; width: 69.5947%;">
<p>in the 1920s, {pickups} added to guitars • a well-known version brought out by {Gibson}</p>
</td>
</tr>
</tbody>
</table>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p>7. Chitarra… was a development of an earlier instrument called the <strong>chartar</strong>.</p>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong>Đáp án:</strong> <strong>chartar</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong><span class=\"citation-6\">Dẫn chứng:</span></strong><span class=\"citation-6\"> (Đoạn G) “When the four-stringed Persian </span><strong><span class=\"citation-6\">chartar</span></strong><span class=\"citation-6 citation-end-6\"> arrived in Spain, however, it changed in form and construction…</span> It became known as the <strong>chitarra</strong>.</p>\n<p> </p>\n</li>\n</ul>\n<p>8. Classical guitar… modifications including a larger <strong>body</strong> introduced by Antonio Torres.</p>\n<ul data-path-to-node=\"19\">\n<li>\n<p data-path-to-node=\"19,0,0\"><strong>Đáp án:</strong> <strong>body</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"19,1,0\"><strong><span class=\"citation-5\">Dẫn chứng:</span></strong><span class=\"citation-5\"> (Đoạn H) “…the Spanish guitar maker Antonio Torres </span><strong><span class=\"citation-5\">increased the size of the body</span></strong><span class=\"citation-5 citation-end-5\">…”</span></p>\n<p> </p>\n</li>\n</ul>\n<p>9. Classical guitar… changes produced better tone and greater <strong>volume</strong>.</p>\n<ul data-path-to-node=\"21\">\n<li>\n<p data-path-to-node=\"21,0,0\"><strong>Đáp án:</strong> <strong>volume</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"21,1,0\"><strong>Dẫn chứng:</strong> (Đoạn H) “His design radically increased the <strong>volume</strong> and improved the tone of the instrument…”</p>\n</li>\n</ul>\n<p>10. X-braced top guitar… first made in <strong>America</strong> in mid-19th century.</p>\n<ul data-path-to-node=\"23\">\n<li>\n<p data-path-to-node=\"23,0,0\"><strong>Đáp án:</strong> <strong>America</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"23,1,0\"><strong>Dẫn chứng:</strong> (Đoạn I) “German immigrants to <strong>America</strong> – among them Christian Fredrich Martin – began making guitars with X-braced tops.”</p>\n</li>\n</ul>\n<p>11. X-braced top guitar… strings made of <strong>steel</strong> became available around 1900.</p>\n<ul data-path-to-node=\"25\">\n<li>\n<p data-path-to-node=\"25,0,0\"><strong>Đáp án:</strong> <strong>steel</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"25,1,0\"><strong>Dẫn chứng:</strong> (Đoạn I) “<strong>Steel</strong> strings, which became widely available several decades later in the early 1900s…”</p>\n</li>\n</ul>\n<p>12. Electric guitar… in the 1920s, <strong>pickups</strong> added to guitars.</p>\n<ul data-path-to-node=\"27\">\n<li>\n<p data-path-to-node=\"27,0,0\"><strong>Đáp án:</strong> <strong>pickups</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"27,1,0\"><strong>Dẫn chứng:</strong> (Đoạn J) “The electric guitar was born when <strong>pickups</strong> were fitted to Hawaiian and jazz guitars in the late 1920s…”</p>\n</li>\n</ul>\n<p>13. Electric guitar… a well-known version brought out by <strong>Gibson</strong>.<button class=\"button ng-star-inserted\" data-hveid=\"0\" data-ved=\"0CAAQvoAQahgKEwjP3Z24ivKQAxUAAAAAHQAAAAAQ5gE\"></button></p>\n<p> </p>\n<p> </p>\n<ul data-path-to-node=\"29\">\n<li>\n<p data-path-to-node=\"29,0,0\"><strong>Đáp án:</strong> <strong>Gibson</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"29,1,0\"><strong>Dẫn chứng:</strong> (Đoạn J) “…met with little success until 1836, when <strong>Gibson</strong> introduced its famous ES150 model.”</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('0c4a7d34-b4c7-4d4e-ba87-cbb75cfc3982', '47b99efa-22f0-40a8-97f6-c7890d0324e6', 'checkbox', 'Questions 21 and 22', '<p>Choose TWO letters, A–E.</p>
<p>21–22. Which TWO benefits for children of learning to write did both students find surprising?</p>
', '<p>Choose <strong>TWO</strong> correct answers.</p>
', 'multiple_choice_many', NULL, '[{"option": "A. improved fine motor skills", "correct": false}, {"option": "B. improved memory", "correct": false}, {"option": "C. improved concentration", "correct": true}, {"option": "D. improved imagination", "correct": false}, {"option": "E. improved spatial awareness", "correct": true}]', '{"layoutType": ["standard"], "summaryText": null, "answerOptions": null, "matchingItems": null}', '{"layoutType": ["standard"], "legendTitle": null, "matrixItems": null, "matrixCategories": null}', '[{"content": "<p>1. Lợi ích của Việc Học Viết Tay (Questions 21–24)<br /> </p>\n<p>STUDENT 1: How are you getting on with the assignment on handwriting?</p>\n<p>STUDENT 2: Not too bad.</p>\n<p>STUDENT 2: You know, I hadn&#8217;t realised that children benefit in so many ways from learning to write.</p>\n<p>STUDENT 2: It&#8217;s such an important skill and yet most people think handwriting is less important than in the past because people hardly ever write by hand these days.</p>\n<p>STUDENT 1: Yes, and all the evidence suggests children should learn to write by hand before they learn to type, not least because it helps their memory. (Question 21)</p>\n<p>STUDENT 2: That&#8217;s right.</p>\n<p>STUDENT 2: The physical act of writing helps children to remember letters.</p>\n<p>STUDENT 2: That seems pretty obvious when you think about it.</p>\n<p>STUDENT 1: What&#8217;s less obvious is how it helps develop their concentration. (Question 22)</p>\n<p>STUDENT 1: They have to sit still and focus on one thing.</p>\n<p>STUDENT 2: Yeah, that aspect of handwriting had never occurred to me before.</p>\n<p>STUDENT 1: Same here.</p>\n<p>STUDENT 1: I&#8217;m not sure I understand how it improves children&#8217;s imagination though. (Question 23)</p>\n<p>STUDENT 2: Well, there was that study which showed that primary age children generated more ideas when they were writing by hand than using a keyboard.</p>\n<p>STUDENT 2: I would have guessed that would be the case.</p>\n<p>STUDENT 1: Hmm, yeah.</p>\n<p>STUDENT 1: I&#8217;d never associated spatial awareness with handwriting either. (Question 24)</p>\n<p>STUDENT 1: I thought spatial awareness was more to do with knowing where you are in relation to objects or other people.</p>\n<p>STUDENT 2: I thought that too.</p>\n<p>STUDENT 2: But good spatial awareness is essential for writing because you have to space words correctly.</p>\n<p>STUDENT 2: It&#8217;s not just fine motor skills that improve through writing as I&#8217;d always assumed.</p>\n<p>STUDENT 1: Handwriting is so much harder for children with dyspraxia who have problems coordinating movement.</p>\n<p>STUDENT 1: It&#8217;s good there are lots of things you can do in the classroom to help them.</p>\n<p>STUDENT 1: They need so much more support with letter formation.</p>\n<p>STUDENT 1: You need to play lots of games to help them distinguish letter shapes.</p>\n<p>STUDENT 1: It takes a lot of patience.</p>\n<p>STUDENT 2: Yeah.</p>\n<p>STUDENT 2: I like the idea of using one of those pens that lights up if you press too hard.</p>\n<p>STUDENT 2: That seems like a really simple solution.</p>\n<p>STUDENT 1: Yes, absolutely.</p>\n<p>STUDENT 1: I&#8217;m not sure there&#8217;s much you can do about children with dyspraxia writing very slowly.</p>\n<p>STUDENT 1: It&#8217;s more important to focus on accuracy and as they get more confident, I think they eventually speed up.</p>\n<p>STUDENT 2: One quite simple thing you can do is to use grid paper.</p>\n<p>STUDENT 2: So they write each letter in a box and that trains them to space the letters correctly.</p>\n<p>STUDENT 1: Indeed.</p>\n<p>STUDENT 1: That&#8217;s more important for legibility than trying to get them to write in a straight line.</p>\n<p> <br /> </p>\n<p>2. Các Vấn đề và Tương lai của Chữ Viết Tay (Questions 25–30)<br /> </p>\n<p>STUDENT 1: For some children, it might be better to teach them to write on a laptop rather than by hand, like children with dyslexia. (Question 25)</p>\n<p>STUDENT 1: They often really struggle with handwriting and some just give up.</p>\n<p>STUDENT 2: Yeah.</p>\n<p>STUDENT 2: It&#8217;s not as frustrating for them if they get things wrong.</p>\n<p>STUDENT 2: On a keyboard, they can be more willing to have a go.</p>\n<p>STUDENT 2: But I read that developing fluency isn&#8217;t any faster.</p>\n<p>STUDENT 1: That&#8217;s right.</p>\n<p>STUDENT 1: Did you read that article on the benefits of teaching print rather than cursive handwriting, where the letters are joined up? (Question 26)</p>\n<p>STUDENT 2: Yes.</p>\n<p>STUDENT 2: Well, in the past, cursive writing was certainly considered more stylish and educated, but not anymore.</p>\n<p>STUDENT 2: Teachers&#8217; attitudes have changed because it&#8217;s been proved that cursive is more difficult to learn, especially for children with learning difficulties who find joining up letters really challenging.</p>\n<p>STUDENT 1: I agree.</p>\n<p>STUDENT 1: I was always worried that my poor handwriting affected my exam results.</p>\n<p>STUDENT 1: And now research shows that I was right to worry.</p>\n<p>STUDENT 1: I&#8217;m sure a lot of students think it&#8217;s unfair that they&#8217;re being judged on their handwriting, not just their knowledge. (Question 27)</p>\n<p>STUDENT 2: Marks are definitely affected if examiners can&#8217;t read the script.</p>\n<p>STUDENT 2: That&#8217;s why it&#8217;s always been so important to teach children to write legibly.</p>\n<p>STUDENT 2: Do you think the role of handwriting will change in the future?</p>\n<p>STUDENT 1: I can&#8217;t see that changing much.</p>\n<p>STUDENT 1: Touch typing still isn&#8217;t taught in most schools, which is a shame.</p>\n<p>STUDENT 1: But maybe that won&#8217;t be necessary in the future because people will also be able to write by hand on digital devices. (Question 28)</p>\n<p>STUDENT 1: Anyway, teachers understand the value of handwriting.</p>\n<p>STUDENT 1: It&#8217;s a basic life skill.</p>\n<p>STUDENT 2: True.</p>\n<p>STUDENT 2: However, the fact is that people are writing by hand less and less and relying on digital devices.</p>\n<p>STUDENT 2: That does cause some problems.</p>\n<p>STUDENT 1: You mean like note-taking?</p>\n<p>STUDENT 1: There are lots of apps for that.</p>\n<p>STUDENT 2: And for reading historical documents, apparently. (Question 29)</p>\n<p>STUDENT 2: But my mum is shocked by my awful spelling and the fact that my punctuation is really inconsistent.</p>\n<p>STUDENT 2: I think you can put that down to lack of practice.</p>\n<p>STUDENT 1: I expect so.</p>\n<p>STUDENT 1: Personally, I miss writing by hand.</p>\n<p>STUDENT 1: I hardly ever write anything now.</p>\n<p>STUDENT 1: I remember my grandparents had such beautiful handwriting and it was so individual. (Question 30)</p>\n<p>STUDENT 1: Nobody I know would be able to identify my handwriting now.</p>\n<p>STUDENT 1: It&#8217;s a shame.</p>\n<p>STUDENT 2: I know.</p>\n<p>STUDENT 2: I feel the same way.</p>\n<p>STUDENT 2: I used to write a diary by hand and now I do that digitally.</p>\n<p>STUDENT 2: It just seems less effort to do it that way.</p>\n<p>STUDENT 2: So, it&#8217;s not just a problem</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('13c49549-4442-4a4d-a7e9-26f4b697fd62', 'c0718dc1-b223-44fa-bc28-771b2b4b0817', 'matrix', 'Questions 14-19', NULL, '<p>Reading Passage 2 has seven sections, A-G.</p>
<p>Which section contains the following information?</p>
<p>Choose the correct letter, A-G, to boxes 14-19.</p>
', 'other', 'null', 'null', 'null', '{"layoutType": "simple", "legendTitle": null, "matrixItems": [{"itemText": "a contrast between the ways young players gain experience of playing different positions", "correctCategoryLetter": "E"}, {"itemText": "examples outside sport of greater emphasis on individual safety", "correctCategoryLetter": "C"}, {"itemText": "a description of methods of selection for leadership on soccer teams", "correctCategoryLetter": "F"}, {"itemText": "details of urban changes that discourage street soccer", "correctCategoryLetter": "B"}, {"itemText": "a mention of the lesson that failure teaches street soccer players", "correctCategoryLetter": "G"}, {"itemText": "an explanation of why youth soccer emphasises the need for coaches", "correctCategoryLetter": "D"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}]}', '[{"content": "<p data-path-to-node=\"3\"><strong class=\"\">14. a contrast between the ways young players gain experience of playing different positions</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong class=\"\">Đáp án:</strong> <strong class=\"\">E</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong class=\"\">Dẫn chứng:</strong><span class=\"\"> (Đoạn E) “One of the basic ideas of street soccer is that young players are assigned a particular role…</span><span class=\"\"> Such an assignment </span><strong class=\"\">runs counter to the idea of youth soccer that every child needs to learn every position</strong><span class=\"\">…</span><span class=\"\">“</span></p>\n</li>\n<li>\n<p data-path-to-node=\"4,2,0\"><strong class=\"\">Giải thích:</strong><span class=\"\"> Đoạn E so sánh sự khác biệt trong việc phân công vai trò (vị trí) giữa hai loại hình bóng đá (cụ thể hóa cách thức nhận kinh nghiệm vị trí).</span></p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong class=\"\">15. examples outside sport of greater emphasis on individual safety</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong class=\"\">Đáp án:</strong> <strong class=\"\">C</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong class=\"\">Dẫn chứng:</strong><span class=\"\"> (Đoạn C) “Like the 1960s consumer movement which </span><strong class=\"\">brought seat belts and airbags to cars</strong><span class=\"\">,</span><span class=\"\"> the (youth) soccer movement felt like it could create a set of …</span><span class=\"\"> regulations that would protect both the child’s body and mind from damage.</span><span class=\"\">“</span></p>\n</li>\n<li>\n<p data-path-to-node=\"6,2,0\"><strong class=\"\">Giải thích:</strong><span class=\"\"> Tác giả dùng dây an toàn và túi khí ô tô làm ví dụ về sự chú trọng an toàn cá nhân ngoài lĩnh vực thể thao.</span></p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong class=\"\">16. a description of methods of selection for leadership on soccer teams</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong class=\"\">Đáp án:</strong> <strong class=\"\">F</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong class=\"\">Dẫn chứng:</strong><span class=\"\"> (Đoạn F) “</span><strong class=\"\">Positions of responsibility are earned through competition within the team</strong><span class=\"\">…</span><span class=\"\"> In youth soccer,</span><span class=\"\"> however,</span><span class=\"\"> with its overly democratic values,</span><span class=\"\"> youngsters are </span><strong class=\"\">guaranteed their time in the spotlight</strong><span class=\"\">.</span><span class=\"\">“</span></p>\n</li>\n<li>\n<p data-path-to-node=\"8,2,0\"><strong class=\"\">Giải thích:</strong><span class=\"\"> Đoạn F mô tả cách thức đạt được vị trí có trách nhiệm (leadership) trong cả hai loại hình bóng đá (bằng cạnh tranh trong street soccer và bằng luân phiên/dân chủ quá mức trong youth soccer).</span></p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong class=\"\">17. details of urban changes that discourage street soccer</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong class=\"\">Đáp án:</strong> <strong>B</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong>Dẫn chứng:</strong> (Đoạn B) “<strong>Congested traffic</strong> now dominates where games were once played. <strong>Parks and open fields are used as hangouts</strong>… Add to this the requirement in many localities for <strong>official permits</strong>…”</p>\n</li>\n<li>\n<p data-path-to-node=\"10,2,0\"><strong>Giải thích:</strong> Đoạn B chi tiết hóa các yếu tố thay đổi môi trường đô thị (giao thông, thiếu không gian, yêu cầu giấy phép) khiến bóng đá đường phố khó thực hiện.</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong>18. a mention of the lesson that failure teaches street soccer players</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong>Đáp án:</strong> <strong>G</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong>Dẫn chứng:</strong> (Đoạn G) “<strong>Losing a game is a common experience and players learn early on how to handle this</strong>. As a result… they <strong>acquire resilience</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"12,2,0\"><strong>Giải thích:</strong> Thất bại (Losing a game) dạy cho người chơi street soccer bài học về sự kiên cường (resilience).</p>\n</li>\n</ul>\n<p data-path-to-node=\"13\"><strong>19. an explanation of why youth soccer emphasises the need for coaches</strong></p>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong>Đáp án:</strong> <strong>D</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong>Dẫn chứng:</strong> (Đoạn D) “They argue that <strong>children need to be taught by experts</strong>… This need to get ahead brings with it a <strong>fear of falling behind that only expert instruction can prevent</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"14,2,0\"><strong>Giải thích:</strong> Nhu cầu được dạy bởi chuyên gia (coaches/experts) xuất phát từ nỗi sợ bị tụt lại phía sau.</p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('a5307165-7ba2-4ed3-8a43-d2ea1db5e951', 'c0718dc1-b223-44fa-bc28-771b2b4b0817', 'checkbox', 'Questions 20-21', NULL, '<p>Choose <strong>TWO </strong>correct answers.</p>
<p>The list below gives some possible reasons for the popularity of street soccer.</p>
<p>Which <strong>TWO</strong> of these reasons are mentioned by the writer of the text?</p>
', 'multiple_choice_many', 'null', '[{"option": "Many famous soccer players got their start in street soccer.", "correct": false}, {"option": "Young people can begin playing street soccer at a very early age.", "correct": false}, {"option": "You do not need elaborate facilities to play street soccer.", "correct": true}, {"option": "Inexperienced street soccer players are not criticised for mistakes.", "correct": false}, {"option": "Street soccer teams can have varying numbers of players.", "correct": true}]', 'null', 'null', '[{"content": "<p data-path-to-node=\"16\"><strong>20-21. Which TWO of these reasons are mentioned by the writer of the text?</strong> (Lý do Street Soccer phổ biến)</p>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong>Đáp án: C (You do not need elaborate facilities to play street soccer.) và E (Street soccer teams can have varying numbers of players.)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong>Dẫn chứng cho C:</strong> (Đoạn A) “…<strong>no large space is needed</strong>, and goal posts, corner markers, and marked lines… <strong>are typically absent</strong>…” (Không cần cơ sở vật chất phức tạp).</p>\n</li>\n<li>\n<p data-path-to-node=\"17,2,0\"><strong>Dẫn chứng cho E:</strong> (Đoạn A) “…does not necessarily require standard 11-a-side teams or <strong>fixed playing positions</strong>.” (Số lượng đội có thể thay đổi, không cần đội cố định 11 người).</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('c0c179a2-12b9-41ad-a31f-1d58f8bec45e', 'd0161c1b-2bf2-48d5-84cd-fcfa9f229b9f', 'matrix', 'Questions 27–35', NULL, '<p>Reading Passage has seven paragraphs, A–G.<br />
Which paragraph contains the following information?<br />
Choose the correct letter, A–G, in boxes 27–35 on your answer sheet.</p>
<p>NB: You may use any letter more than once.</p>
', 'other', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": null, "matrixItems": [{"itemText": "An overview of the range of methods that have been used over time to document history", "correctCategoryLetter": "C"}, {"itemText": "The main reason why many historians are unwilling to use films in their work", "correctCategoryLetter": "E"}, {"itemText": "A reference to some differences between oral and written communication", "correctCategoryLetter": "F"}, {"itemText": "How most citizens today gain an understanding of history", "correctCategoryLetter": "A"}, {"itemText": "How current student events are sometimes captured for future audiences", "correctCategoryLetter": "B"}, {"itemText": "Mention of the fact that the advantages of film are greater than the disadvantages", "correctCategoryLetter": "G"}, {"itemText": "The claim that there is no official title for film-based historical work", "correctCategoryLetter": "C"}, {"itemText": "To the active role the audience plays when watching films", "correctCategoryLetter": "F"}, {"itemText": "A list of requirements that historians see as obstacles to their use of film to record history", "correctCategoryLetter": "E"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}]}', '[{"content": "<p>27. C<br />\n(Đoạn C, “The study of history, as conceived of today, began with the transition from oral to literate culture&#8230; A further turning point came with the advent of printing&#8230;”)<br />\n→ Đoạn này mô tả các phương pháp ghi chép lịch sử qua thời gian – từ truyền miệng, chữ viết, in ấn đến truyền thông mới → đúng với yêu cầu “overview of the range of methods”.</p>\n<p>28. E<br />\n(Đoạn E, “The barrier seems to be that the profession is structured around the medium of the written word&#8230; historians have rejected the necessity to learn complicated new skills.”)<br />\n→ Nguyên nhân chính khiến nhiều sử gia không muốn dùng phim là họ quen với chữ viết và ngại học kỹ năng mới.</p>\n<p>29. F<br />\n(Đoạn F, “&#8230;oral communication is not limited to words: it also includes body language, expression and tone, and is embedded in a context. Little of this is evident in a written transcript.”)<br />\n→ Đoạn này chỉ ra sự khác biệt giữa truyền miệng và chữ viết, đúng yêu cầu câu hỏi.</p>\n<p>30. A<br />\n(Đoạn A, “&#8230;film and video, especially as broadcast on television, are probably the major influence on the public’s consciousness of history.”)<br />\n→ Người dân hiện nay hiểu biết lịch sử chủ yếu qua phim ảnh và truyền hình → đúng với “how most citizens today gain an understanding of history”.</p>\n<p>31. B<br />\n(Đoạn B, “&#8230;a great many people now document local and family events in the form of videos; many schools, too, produce video yearbooks&#8230;”)<br />\n→ Nói về việc mọi người ghi lại sự kiện hiện tại để lưu cho tương lai, đúng với “current events captured for future audiences”.</p>\n<p>32. G<br />\n(Đoạn G, “The many benefits of using moving images as historical evidence easily outweigh worries about cost, technical skills, or the effect of a camera&#8230;”)<br />\n→ Khẳng định ưu điểm của phim lớn hơn nhược điểm, nên đáp án là G.</p>\n<p>33. C<br />\n(Đoạn C, “&#8230;the use of moving images as a record of events and a source of historical evidence has hardly been accepted in its own right and gained parity of name.”)<br />\n→ Có nghĩa là chưa có “tên chính thức” cho dạng nghiên cứu lịch sử bằng phim.</p>\n<p>34. F<br />\n(Đoạn F, “&#8230;the viewer becomes involved in the process of interpreting and understanding history.”)<br />\n→ Người xem đóng vai trò tích cực trong việc hiểu và diễn giải lịch sử qua phim → đúng với “active role of the audience”.</p>\n<p>35. E<br />\n(Đoạn E, “&#8230;historians have rejected the training, institutions and motivations&#8230; Above all, they have rejected the necessity to learn complicated new skills.”)<br />\n→ Đoạn này liệt kê các yếu tố mà sử gia xem là trở ngại: đào tạo, kỹ năng, tổ chức – đúng yêu cầu câu hỏi.</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('e3a13a34-0bed-44d5-b3bb-538ae0de2027', 'c0718dc1-b223-44fa-bc28-771b2b4b0817', 'checkbox', 'Questions 22-23', NULL, '<p>Choose <strong>TWO </strong>correct answers.</p>
<p>The list below goes some possible results of the 1960s parenting style.</p>
<p>Which <strong>TWO</strong> of these results are mentioned by Franklin Foer in the excerpt from How Soccer Explains the World?</p>
', 'multiple_choice_many', 'null', '[{"option": "Participation in youth soccer became much more expensive.", "correct": false}, {"option": "Some youth soccer leagues adopted more restrictive rules of play.", "correct": true}, {"option": "Fewer young people joined youth soccer teams.", "correct": false}, {"option": "Youth soccer players were sometimes rewarded for simply playing in games.", "correct": true}, {"option": "Soccer equipment manufacturers directed advertising towards parents.", "correct": false}]', 'null', 'null', '[{"content": "<p data-path-to-node=\"19\"><strong>22-23. Which TWO of these results are mentioned by Franklin Foer in the excerpt from <em>How Soccer Explains the World</em>?</strong></p>\n<ul data-path-to-node=\"20\">\n<li>\n<p data-path-to-node=\"20,0,0\"><strong>Đáp án: B (Some youth soccer leagues adopted more restrictive rules of play.) và D (Youth soccer players were sometimes rewarded for simply playing in games.)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"20,1,0\"><strong>Dẫn chứng cho B:</strong> (Đoạn C) “…<strong>some youth leagues prohibited heading the ball altogether</strong>.” (Cấm đánh đầu là một luật lệ hạn chế hơn/restrictive rules).</p>\n</li>\n<li>\n<p data-path-to-node=\"20,2,0\"><strong>Dẫn chứng cho D:</strong> (Đoạn C) “Soccer leagues like the one I played in as a child handed out <strong>‘participation’ prizes to every player</strong>, no matter how few games his (or her) team won…” (Thưởng cho việc tham gia).</p>\n</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('6cca854b-90c0-4296-babf-4715c98ab3ac', 'd7d01f0a-07af-463b-bef3-a9fa68f2ee8e', 'checkbox', 'Questions 29 and 30', NULL, '<p>Choose <strong>TWO </strong>letters, A–E.</p>
<p>Which <strong>TWO </strong>sections of the project will Rob write alone?</p>
', 'multiple_choice_many', 'null', '[{"option": "A. Methodology", "correct": false}, {"option": "B. Literature review", "correct": false}, {"option": "C. Introduction", "correct": true}, {"option": "D. Analysis", "correct": false}, {"option": "E. Discussion and conclusions", "correct": true}]', 'null', 'null', '[{"content": "<p>1</p>\n"}]', 3);
INSERT INTO public.questions VALUES ('0396fa34-cae0-4d5b-ac61-e75fe56143e9', 'c0718dc1-b223-44fa-bc28-771b2b4b0817', 'fillup', 'Questions 24-26', '<p>Complete the summary below.</p>
<p>Write <strong>ONE WORD ONLY</strong> from the passage for each answer.</p>
<p style="text-align: center;"><span style="font-size: 12pt;"><strong>Winners and losers</strong></span></p>
<p>For youth soccer players, a key {Principle} is that they should always come away from the game with a positive attitude. In this respect, regardless of the effort the players make, they get some kind of {Reward} at the end of a game.</p>
<p>In street soccer, however, players gain resilience because they have to learn to cope with failure. But the outcome of a match isn’t remembered for long. In fact, no-one ever keeps a {record} of the results of games.</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"22\"><strong>24. For youth soccer players, a key principle is that they should always come away from the game with a positive attitude.</strong></p>\n<ul data-path-to-node=\"23\">\n<li>\n<p data-path-to-node=\"23,0,0\"><strong>Đáp án:</strong> <strong class=\"animating\">principle</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"23,1,0\"><strong>Dẫn chứng:</strong> (Đoạn G) “<strong>‘Everyone’s a winner; no one’s a loser’ is a guiding principle of youth soccer</strong>.” (Nguyên tắc hướng dẫn).</p>\n</li>\n</ul>\n<p data-path-to-node=\"24\"><strong>25. In this respect, regardless of the effort the players make, they get some kind of reward at the end of a game.</strong></p>\n<ul data-path-to-node=\"25\">\n<li>\n<p data-path-to-node=\"25,0,0\"><strong>Đáp án:</strong> <strong>reward</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"25,1,0\"><strong>Dẫn chứng:</strong> (Đoạn G) “<strong>Since giving less than your best receives the same reward as giving your best</strong> why go to any extra effort?” (Việc nhận được phần thưởng bất kể nỗ lực).</p>\n</li>\n</ul>\n<p data-path-to-node=\"26\"><strong>26. In fact, no-one ever keeps a record of the results of games.</strong></p>\n<ul data-path-to-node=\"27\">\n<li>\n<p data-path-to-node=\"27,0,0\"><strong>Đáp án:</strong> <strong>record</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"27,1,0\"><strong>Dẫn chứng:</strong> (Đoạn G – cuối) “In street soccer a formal <strong>record</strong> is not kept.”</p>\n</li>\n</ul>\n"}]', 3);
INSERT INTO public.questions VALUES ('d9844231-07f4-4d7f-8232-1a2ccfb8b9f3', '8159bd63-d283-4ff0-ae73-f75f62bea308', 'matching', 'Questions 27-30', NULL, '<p>Complete the summary using the list of words and phrases, A-H, below.</p>
', 'matching', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p style=\"text-align: center;\"><span style=\"font-size: 12pt;\"><strong>MEHRABIAN’S 1967 STUDY</strong></span></p>\r\n<p>Albert Mehrabian and his colleagues carried out an influential study comparing the {D effects} of verbal and non-verbal communication. This involved two experiments. In both experiments, subjects had to identify the {G feelings} being communicated by other people. The two main areas focused on in the first experiment were voice tones and {A facial expressions} while the second focused mainly on voice tones and {E word meanings}</p>", "answerOptions": [{"optionText": "A facial expressions"}, {"optionText": "B purposes"}, {"optionText": "C printed words"}, {"optionText": "D effects "}, {"optionText": "E word meanings"}, {"optionText": "F gender differences"}, {"optionText": "G feelings"}, {"optionText": "H characteristics"}], "matchingItems": null}', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong>27. &#8230;Albert Mehrabian and his colleagues carried out an influential study comparing the <span class=\"math-inline\" data-math=\"rightarrow\">$rightarrow$</span> D. effects of verbal and non-verbal communication.</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong>Dẫn chứng:</strong> (Đoạn 2) &#8220;The findings of a study on verbal and non-verbal messages in communication by Albert Mehrabian&#8230; have been quoted so frequently&#8230;&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong>Giải thích:</strong> Nghiên cứu so sánh <strong>tác động</strong> (<strong>effects</strong>) của các kênh giao tiếp khác nhau lên thông điệp.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong>28. In both experiments, subjects had to identify the <span class=\"math-inline\" data-math=\"rightarrow\">$rightarrow$</span> G. feelings being communicated by other people.</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong>Dẫn chứng:</strong> (Đoạn 2) &#8220;&#8230;were asked to <strong>guess the emotions</strong> in the recorded voice and the photos.&#8221; và &#8220;&#8230;the subjects had to <strong>guess the speaker&#8217;s emotions</strong>.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong>Giải thích:</strong> Cả hai thí nghiệm đều yêu cầu đối tượng nhận biết <strong>cảm xúc</strong> (<strong>emotions</strong> / <strong>feelings</strong>) được truyền đạt.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong>29. The two main areas focused on in the first experiment were voice tones and <span class=\"math-inline\" data-math=\"rightarrow\">$rightarrow$</span> A. facial expressions&#8230;</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong>Dẫn chứng:</strong> (Đoạn 2) &#8220;&#8230;three tones of voice&#8230; The subjects were then shown photos of female faces&#8230;&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong>Giải thích:</strong> Thí nghiệm đầu tiên so sánh giọng điệu (<strong>tone of voice</strong>) và biểu cảm khuôn mặt (<strong>facial expressions</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong>30. &#8230;while the second focused mainly on voice tones and <span class=\"math-inline\" data-math=\"rightarrow\">$rightarrow$</span> E. word meanings.</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong>Dẫn chứng:</strong> (Đoạn 2) &#8220;&#8230;listened to nine recorded words spoken in different tones of voice. Three words had positive <strong>meanings</strong> (e.g. <em>honey</em>)&#8230;&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong>Giải thích:</strong> Thí nghiệm thứ hai so sánh giọng điệu và <strong>ý nghĩa từ ngữ</strong> (<strong>word meanings</strong>).</p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('ee050bc3-e54a-4277-8dea-c317731a1d4a', '8159bd63-d283-4ff0-ae73-f75f62bea308', 'radio', 'Questions 31-35', NULL, '<p>Choose <strong>YES </strong>if the statement agrees with the claims of the writer, choose <strong>NO </strong>if the statement contradicts the claims of the writer, or <strong>NOT GIVEN</strong> if it is impossible to say what the writer thinks about this.</p>
', 'multiple_choice_single', '[{"correct": 0, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "One limitation of the study was that there were too few subjects involved."}, {"correct": 1, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "The fact that the subjects in the study came from a similar background was an advantage"}, {"correct": 2, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "The two experiments should have been carried out in a different order"}, {"correct": 1, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "The researchers'' choice of a neutral word was helpful in the context of the study."}, {"correct": 2, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "The study would have been more valid if it had included a range of languages."}]', 'null', 'null', 'null', '[{"content": "<p>31. One limitation of the study was that there were too few subjects involved.</p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong>Đáp án: YES</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 3) &#8220;The first is that the entire study involved <strong>only 62 subjects</strong>&#8230; comparing verbal and non-verbal communication &#8211; was determined by only the 37 remaining subjects.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"15,2,0\"><strong>Giải thích:</strong> Tác giả xem số lượng đối tượng tham gia ít ỏi (chỉ 62) là một <strong>hạn chế</strong> (<strong>limitation</strong>).</p>\n</li>\n</ul>\n<p>32. The fact that the subjects in the study came from a similar background was an advantage.</p>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong>Đáp án: NO</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 3) &#8220;&#8230;their ages and academic qualifications seem remarkably uniform. <strong>Thus, the findings may simply be a product of the nature of the sample</strong>.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"17,2,0\"><strong>Giải thích:</strong> Tác giả xem tính đồng nhất của mẫu là vấn đề, vì nó khiến kết quả thiếu tính đại diện, không phải lợi thế.</p>\n</li>\n</ul>\n<p>33. The two experiments should have been carried out in a different order.</p>\n<ul data-path-to-node=\"19\">\n<li>\n<p data-path-to-node=\"19,0,0\"><strong>Đáp án: NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"19,1,0\"><strong>Giải thích:</strong> Có sự phê bình về việc kết hợp dữ liệu từ hai thí nghiệm khác nhau, nhưng <strong>không có thông tin</strong> nào cho rằng thứ tự (order) của chúng là vấn đề.</p>\n</li>\n</ul>\n<p>34. The researchers&#8217; choice of a neutral word was helpful in the context of the study.</p>\n<ul data-path-to-node=\"21\">\n<li>\n<p data-path-to-node=\"21,0,0\"><strong>Đáp án: NO</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"21,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 4) &#8220;The researchers intentionally used a ‘neutral’ word so <strong>naturally the subjects found little meaning there</strong>. Clearly, such a methodology <strong>lacks validity</strong>.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"21,2,0\"><strong>Giải thích:</strong> Việc sử dụng từ trung tính khiến phương pháp luận <strong>thiếu tính hợp lệ</strong> (lacks validity), tức là không hữu ích.</p>\n</li>\n</ul>\n<p>35. The study would have been more valid if it had included a range of languages.</p>\n<ul data-path-to-node=\"23\">\n<li>\n<p data-path-to-node=\"23,0,0\"><strong>Đáp án: NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"23,1,0\"><strong>Giải thích:</strong> Bài không đề cập đến việc sử dụng nhiều ngôn ngữ (a range of languages) như một cách để tăng tính hợp lệ của nghiên cứu.</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('a9c93daa-4e09-45f5-ba87-1c85274edacc', '8159bd63-d283-4ff0-ae73-f75f62bea308', 'radio', 'Questions 36-40', NULL, '<p>Choose the correct answer.</p>
', 'multiple-choice', '[{"correct": 0, "options": [{"content": "A It makes the claims more attractive."}, {"content": "B It is the strongest point of the study."}, {"content": "C It will appeal to superstitious people"}, {"content": "D It allows comparison between languages."}], "question": "What does the writer say about the ‘numerical precision’ of Mehrabian’s study?"}, {"correct": 1, "options": [{"content": "A It is unlikely to maintain its present status"}, {"content": "B It is leading to an undervaluing of language."}, {"content": "C It should be applied in a more practical way"}, {"content": "D It may help understanding of non-verbal messages."}], "question": "What does the writer say about the popularity of the 7-38-55 formula?"}, {"correct": 3, "options": [{"content": "A Language could be learned more efficiently than it is."}, {"content": "B More research is needed into attitudes to communication."}, {"content": "C More time should be spent looking at tone and body language."}, {"content": "D Language must be important since we make an effort to acquire it."}], "question": "What point is Bradley making about language learning?"}, {"correct": 0, "options": [{"content": "A They are relevant to only one area of communication."}, {"content": "B It is only in maths that 100% of communication is verbal."}, {"content": "C Feelings are more difficult to communicate than numerical facts."}, {"content": "D Non-verbal communication is the main part of the message."}], "question": "What does Mehrabian himself say about his findings?"}, {"correct": 2, "options": [{"content": "A to justify the strong points of Mehrabian’s study"}, {"content": "B to outline other research on non-verbal behaviour"}, {"content": "C to present varying interpretations of Mehrabian’s study"}, {"content": "D to show that textbooks tend to ignore non-verbal behaviour"}], "question": "What is the writer’s purpose in the paragraph beginning ‘To be fair …’?"}]', 'null', 'null', 'null', '[{"content": "<p>36. What does the writer say about the ‘numerical precision’ of Mehrabian’s study?</p>\n<ul data-path-to-node=\"27\">\n<li>\n<p data-path-to-node=\"27,0,0\"><strong>Đáp án: A. It makes the claims more attractive.</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"27,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 5) &#8220;Clearly, one <strong>appealing aspect</strong> of the Mehrabian study is its <strong>numerical precision</strong>&#8230; Communication is a complex phenomenon, but it seems less so when we can rely on these three magical numbers.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"27,2,0\"><strong>Giải thích:</strong> Tính chính xác bằng số (numerical precision) làm cho nghiên cứu trở nên hấp dẫn hơn (<strong>appealing</strong>).</p>\n</li>\n</ul>\n<p>37. What does the writer say about the popularity of the 7-38-55 formula?</p>\n<ul data-path-to-node=\"29\">\n<li>\n<p data-path-to-node=\"29,0,0\"><strong>Đáp án: B. It is leading to an undervaluing of language.</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"29,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 5) &#8220;&#8230;the continued references to this research sustain it, encouraging people to believe in the overwhelming importance of the non-verbal message compared with the verbal one. <strong>Yet we know that even one ill-chosen word to a colleague or friend can make or break a communicative effort</strong>.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"29,2,0\"><strong>Giải thích:</strong> Sự phổ biến của công thức khiến người ta đề cao phi ngôn ngữ và <strong>đánh giá thấp</strong> (<strong>undervaluing</strong>) vai trò thực sự của ngôn ngữ.</p>\n</li>\n</ul>\n<p>38. What point is Bradley making about language learning?</p>\n<ul data-path-to-node=\"31\">\n<li>\n<p data-path-to-node=\"31,0,0\"><strong>Đáp án: D. Language must be important since we make an effort to acquire it.</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"31,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 5) Bradley observes, <strong>‘If we could communicate 93% of information and attitudes with vocal and facial cues, it would be wasteful to spend time learning a language.’</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"31,2,0\"><strong>Giải thích:</strong> Bradley lập luận rằng việc con người nỗ lực học ngôn ngữ cho thấy ngôn ngữ phải có vai trò quan trọng, nếu không thì việc học sẽ là lãng phí.</p>\n</li>\n</ul>\n<p>39. What does Mehrabian himself say about his findings?</p>\n<ul data-path-to-node=\"33\">\n<li>\n<p data-path-to-node=\"33,0,0\"><strong>Đáp án: A. They are relevant to only one area of communication.</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"33,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 6) &#8220;<strong>Please remember that alt my findings … dealt with communications of feelings and attitudes</strong> … it is absurd to imply or suggest that the verbal portion of all communication constitutes only 7% of the message&#8230;&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"33,2,0\"><strong>Giải thích:</strong> Mehrabian tự giới hạn phạm vi áp dụng của nghiên cứu chỉ trong việc truyền đạt cảm xúc và thái độ (<strong>feelings and attitudes</strong>).</p>\n</li>\n</ul>\n<p>40. What is the writer’s purpose in the paragraph beginning ‘To be fair …’?</p>\n<ul data-path-to-node=\"35\">\n<li>\n<p data-path-to-node=\"35,0,0\"><strong>Đáp án: C. to present varying interpretations of Mehrabian’s study</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"35,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 7) &#8220;To be fair, <strong>many textbook writers attempt to be faithful to the context</strong>&#8230; <strong>Others try to play down the specific percentages</strong>&#8230; <strong>Nonetheless, ether textbook authors simply use the numbers</strong>&#8230;&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"35,2,0\"><strong>Giải thích:</strong> Đoạn văn mô tả <strong>các cách hiểu khác nhau</strong> (varying interpretations) về nghiên cứu của Mehrabian trong sách giáo khoa.</p>\n</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('81f33c4f-f94d-4a9a-9a68-fec4cd4b2e85', '597f0956-1ce6-4b86-a544-8d889853bbde', 'checkbox', 'Questions 19–20', '', '<div class="quests-inner-desc">
<div class="txt">Choose <strong>TWO</strong> correct answers.</div>
</div>
<div class="quests-list">
<div id="1311" class="quests-item quests-numctn quests-item-history quests-skip" data-question-id="408" data-numctn="19" data-count="19" data-quest="19-20" data-choices="2">
<div class="tt-head">
<p class="tt"><span class="numquest">19-20</span> Which TWO benefits can all the members get?</p>
</div>
</div>
</div>', 'multiple_choice_many', 'null', '[{"correct": false, "option_text": "free entry to some castles"}, {"correct": true, "option_text": "subscription of Scottish magazines"}, {"correct": false, "option_text": "discount of apartment rent"}, {"correct": true, "option_text": "free visitor guide"}, {"correct": false, "option_text": "free parking"}]', 'null', 'null', 'null', 2);
INSERT INTO public.questions VALUES ('fe9fdce4-73fb-4ae0-9f0e-4a6029099940', '0ae89ddd-e8b4-4ee8-b577-7458b35e4cca', 'fillup', 'Questions 31-36', '<p>Write <strong>ONE WORD ONLY</strong> for each answer.</p>
<p><span style="font-size: 12pt;"><strong>GRAPHICAL SYMBOL</strong></span></p>
<p><strong>‘Graphical symbol’</strong></p>
<p>– includes the logographs in Egyptian hieroglyphic writing and ancient Chinese pictograms</p>
<p>– found in Africa, the Americas, and Oceania</p>
<p>– still has something to do with {commercial} use today</p>
<p><strong>Ancient graphic writing systems</strong></p>
<p>– Researchers obtain a wide range of {knowledge} about past civilisations.</p>
<p>– Rosetta Stone was found in 1799 when members of Napoleon’s expedition got to Egypt.</p>
<p>– Frenchman Jean-Francois Champollion determined the phonetic values of the symbols in 1822.</p>
<p>– In those symbols, {lines} are used to depict various meanings.</p>
<p><strong>Camera obscura</strong></p>
<p>–  {Photography} helps people understand history better.</p>
<p>– Some charities will {advertise} many endangered species.</p>
<p>– A camera was tied to one {foot} of a bird.</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<h2>(Questions 31–36)</h2>\n<p data-path-to-node=\"3\"><strong>Narrator:</strong> You will hear a talk on the research of the graphical symbol. First you have some time to look at questions thirty one to forty. Now listen carefully and answer questions thirty-one to forty.</p>\n<p data-path-to-node=\"4\"><strong>Lecturer:</strong> Good morning everyone. Today I’m going to talk about the graphical symbol. A graphic symbol is a written symbol that is used to represent speech, such as those used in the Greek alphabet. The term graphic symbol encompasses anything from the logographs used in Egyptian hieroglyphic writing to ancient Chinese pictograms.</p>\n<p data-path-to-node=\"5\"><strong>Lecturer:</strong> Early symbols were based on pictographs and ideograms before they were developed into logographic writing systems. These systems are still in use in some non-literate cultures in Africa, the Americas, and Oceania. Indeed, elements of pictography are still found in modern Chinese characters, and it is often an interesting exercise to trace the origins of some Chinese characters.</p>\n<p data-path-to-node=\"6\"><strong>Lecturer:</strong> Pictographs remain in <strong>(31) common commercial</strong> use today as signs, instructions, or statistical diagrams. Road signs and public toilet signs and even flat pack assembly instructions utilizing pictures are considered pictographic. Ancient graphic writing systems provide researchers with a wealth of <strong>(32) knowledge</strong> about past civilizations.</p>\n<p data-path-to-node=\"7\"><strong>Lecturer:</strong> In seventeen ninety nine, one of the most important historical discoveries was made by accident when members of Napoleon’s expedition to Egypt found a stone in Rosetta that exhibited three different scripts. The stone, now known as the Rosetta Stone, was studied in significant depth by scholars and was first deciphered by Frenchman Jean-François Champollion in eighteen twenty-two. He was able to correctly determine the phonetic values of the symbols, and later research has confirmed his findings. In many of these symbols, <strong>(33) Lines</strong> are used to portray a multitude of meanings, and knowledge and understanding of these Lines holds the key to comprehension of graphic writing systems.</p>\n<p data-path-to-node=\"8\"><strong>Lecturer:</strong> A key moment in the history of communication was the invention of the camera obscura, or camera. Although the concept can be traced back to the fifth century BC Chinese philosopher Mo Ti, the first photographic image was ultimately created in eighteen twenty six by Joseph Nicéphore Niépce. <strong>(34) Photography</strong>, as it was later known, enables researchers to piece together and better understand history.</p>\n<p data-path-to-node=\"9\"><strong>Lecturer:</strong> Today photography forms a huge part of everyday life, and most publications contain a vast number of photographs. Photography is used in advertising and is now becoming a way to increase awareness of existing world issues. For example, Animal welfare charities are increasingly using photography to <strong>(35) advertise</strong> animals that are at high risk of endangerment. Charity workers are sometimes flown to far flung locations to document the suffering endured by high risk animals in an attempt to raise human awareness of their consumption activities and how they impact others.</p>\n<p data-path-to-node=\"10\"><strong>Lecturer:</strong> One recent high-profile campaign was undertaken by attaching a camera to the <strong>(36) foot</strong> of a bird in order to obtain photographs of the animals in their natural habitats and understand how often they come into contact with human waste.</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('fc41a45f-e39c-43e5-9863-793ea0c4f6c9', '30cc5ddf-20e1-41e7-af22-e96be223faaf', 'radio', 'Questions 32–36', NULL, '<p>Choose <strong>YES </strong>if the statement agrees with the claims of the writer, choose <strong>NO </strong>if the statement contradicts the claims of the writer, or <strong>NOT GIVEN</strong> if it is impossible to say what the writer thinks about this.</p>
', 'multiple_choice_single', '[{"correct": 0, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "The ability of online courses to meet an individual participant''s needs is unclear."}, {"correct": 2, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Researchers caution against building strong online relationships."}, {"correct": 1, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Common assumptions about the benefits of face-to-face courses have proved to be correct."}, {"correct": 0, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "The meaning of presence is still being clarified"}, {"correct": 1, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Research on the impacts of interaction on learning outcomes has produced consistent results."}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">Câu 32</strong></p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"16,0,0\" data-index-in-node=\"8\">YES</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"16,1,0\"><strong data-path-to-node=\"16,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…the effectiveness of online courses, particularly in relation to individual student needs… is sometimes questioned.”</p>\n</li>\n<li>\n<p data-path-to-node=\"16,2,0\"><strong data-path-to-node=\"16,2,0\" data-index-in-node=\"0\">Giải thích:</strong> “Questioned” (bị đặt dấu hỏi) có nghĩa là tính hiệu quả của nó đối với nhu cầu cá nhân vẫn chưa rõ ràng (unclear).</p>\n</li>\n</ul>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">Câu 33</strong></p>\n<ul data-path-to-node=\"18\">\n<li>\n<p data-path-to-node=\"18,0,0\"><strong data-path-to-node=\"18,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"18,0,0\" data-index-in-node=\"8\">NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"18,1,0\"><strong data-path-to-node=\"18,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…this same student may develop a relationship with other students in the class…”</p>\n</li>\n<li>\n<p data-path-to-node=\"18,2,0\"><strong data-path-to-node=\"18,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ nhắc đến việc sinh viên có thể phát triển mối quan hệ, nhưng không đề cập đến việc các nhà nghiên cứu có đưa ra lời cảnh báo “chống lại” (caution against) việc xây dựng mối quan hệ trực tuyến hay không.</p>\n</li>\n</ul>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">Câu 34</strong></p>\n<ul data-path-to-node=\"20\">\n<li>\n<p data-path-to-node=\"20,0,0\"><strong data-path-to-node=\"20,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"20,0,0\" data-index-in-node=\"8\">NO</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"20,1,0\"><strong data-path-to-node=\"20,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “It is generally assumed that when a student is physically present… he or she has a sense of belonging… However, this is an assumption and not always true.”</p>\n</li>\n<li>\n<p data-path-to-node=\"20,2,0\"><strong data-path-to-node=\"20,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc nói rằng giả định thông thường này “không phải lúc nào cũng đúng” (not always true), trái ngược với khẳng định của câu hỏi là nó “đã được chứng minh là đúng” (proved to be correct).</p>\n</li>\n</ul>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">Câu 35</strong></p>\n<ul data-path-to-node=\"22\">\n<li>\n<p data-path-to-node=\"22,0,0\"><strong data-path-to-node=\"22,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"22,0,0\" data-index-in-node=\"8\">YES</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"22,1,0\"><strong data-path-to-node=\"22,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…as this concept is studied, the definition is expanding and being refined to include telepresence, cognitive presence…”</p>\n</li>\n<li>\n<p data-path-to-node=\"22,2,0\"><strong data-path-to-node=\"22,2,0\" data-index-in-node=\"0\">Giải thích:</strong> “Expanding and being refined” (đang mở rộng và được tinh lọc) cho thấy ý nghĩa của sự hiện diện vẫn đang tiếp tục được làm rõ.</p>\n</li>\n</ul>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">Câu 36</strong></p>\n<ul data-path-to-node=\"24\">\n<li>\n<p data-path-to-node=\"24,0,0\"><strong data-path-to-node=\"24,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"24,0,0\" data-index-in-node=\"8\">NO</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"24,1,0\"><strong data-path-to-node=\"24,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…the results of the study indicated that the relationship of actual measures of interaction and performance is mixed.”</p>\n</li>\n<li>\n<p data-path-to-node=\"24,2,0\"><strong data-path-to-node=\"24,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Kết quả nghiên cứu là “mixed” (hỗn hợp/không đồng nhất), trong khi câu hỏi cho rằng kết quả là “consistent” (nhất quán).</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('dc5fc148-2f32-4177-b9dc-5532403bf65b', '0ed2539e-aa7d-4760-a637-36285ec31e72', 'fillup', 'Questions 7–9', '<p>Complete the flow-chart below.</p>
<p>Write <strong>ONE WORD ONLY</strong> from the passage for each answer.</p>
<p class="MsoNormal" style="margin-bottom: 0in; text-align: center; line-height: 1; background: white;" align="center"><strong style="mso-bidi-font-weight: normal;"><span lang="EN" style="font-size: 11.0pt; font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: #15191e;">Ancient olive oil processing</span></strong><span lang="EN" style="font-size: 11.0pt; font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: #15191e;"> </span></p>
<p class="MsoNormal" style="margin-bottom: 0in; text-align: center; line-height: 1; background: white;" align="center"><span lang="EN" style="font-size: 11.0pt; font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: #15191e;">olives are harvested by picking them or {beating}</span><span lang="EN" style="font-size: 11.0pt; font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: #15191e;"> the trees</span></p>
<p class="MsoNormal" style="margin-bottom: 0in; text-align: center; line-height: 1; background: white;" align="center"><span lang="EN" style="font-size: 11.0pt; font-family: ''Arial'',sans-serif; color: black; mso-color-alt: windowtext;"><span style="mso-fareast-font-family: Cardo; color: #15191e;">↓</span></span></p>
<p class="MsoNormal" style="margin-bottom: 0in; text-align: center; line-height: 1; background: white;" align="center"><span lang="EN" style="font-size: 11.0pt; font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: #15191e;">milling stage</span></p>
<p class="MsoNormal" style="margin-bottom: 0in; text-align: center; line-height: 1; background: white;" align="center"><span lang="EN" style="font-size: 11.0pt; font-family: ''Arial'',sans-serif; color: black; mso-color-alt: windowtext;"><span style="mso-fareast-font-family: Cardo; color: #15191e;">↓</span></span></p>
<p class="MsoNormal" style="margin-bottom: 0in; text-align: center; line-height: 1; background: white;" align="center"><span lang="EN" style="font-size: 11.0pt; font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: #15191e;">olives are washed and crushed and seeds removed</span></p>
<p class="MsoNormal" style="margin-bottom: 0in; text-align: center; line-height: 1; background: white;" align="center"><span lang="EN" style="font-size: 11.0pt; font-family: ''Arial'',sans-serif; color: black; mso-color-alt: windowtext;"><span style="mso-fareast-font-family: Cardo; color: #15191e;">↓</span></span></p>
<p class="MsoNormal" style="margin-bottom: 0in; text-align: center; line-height: 1; background: white;" align="center"><span lang="EN" style="font-size: 11.0pt; font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: #15191e;">olive flesh is placed in {bags}</span><span lang="EN" style="font-size: 11.0pt; font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: #15191e;"> and pressed</span></p>
<p class="MsoNormal" style="margin-bottom: 0in; text-align: center; line-height: 1; background: white;" align="center"><span lang="EN" style="font-size: 11.0pt; font-family: ''Arial'',sans-serif; color: black; mso-color-alt: windowtext;"><span style="mso-fareast-font-family: Cardo; color: #15191e;">↓</span></span></p>
<p class="MsoNormal" style="margin-bottom: 0in; text-align: center; line-height: 1; background: white;" align="center"><span lang="EN" style="font-size: 11.0pt; font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: #15191e;">water is poured over the mixture</span></p>
<p class="MsoNormal" style="margin-bottom: 0in; text-align: center; line-height: 1; background: white;" align="center"><span lang="EN" style="font-size: 11.0pt; font-family: ''Arial'',sans-serif; color: black; mso-color-alt: windowtext;"><span style="mso-fareast-font-family: Cardo; color: #15191e;">↓</span></span></p>
<p class="MsoNormal" style="margin-bottom: 0in; text-align: center; line-height: 1; background: white;" align="center"><span lang="EN" style="font-size: 11.0pt; font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: #15191e;">resulting liquid is given time to settle and separate, and {salt}</span><span lang="EN" style="font-size: 11.0pt; font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: #15191e;"> is used to aid the process</span></p>
<p class="MsoNormal" style="margin-bottom: 0in; text-align: center; line-height: 1; background: white;" align="center"><span lang="EN" style="font-size: 11.0pt; font-family: ''Arial'',sans-serif; color: black; mso-color-alt: windowtext;"><span style="mso-fareast-font-family: Cardo; color: #15191e;">↓</span></span></p>
<p class="MsoNormal" style="margin-bottom: 0in; text-align: center; line-height: 1; background: white;" align="center"><span lang="EN" style="font-size: 11.0pt; font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: #15191e;">oil is drawn off and separation repeated</span></p>
', NULL, 'gap_filling', NULL, NULL, '{"layoutType": ["standard"], "summaryText": null, "answerOptions": null, "matchingItems": null}', '{"layoutType": ["standard"], "legendTitle": null, "matrixItems": null, "matrixCategories": null}', '[{"content": "<p><strong>7. olives are harvested by picking them or beating the trees</strong></p>\n<ul>\n<li><strong>Đáp án:</strong> <strong>beating</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn E) “The olives were harvested from the trees by hand or by <strong>beating</strong> the fruit from the trees with long sticks.”</li>\n</ul>\n<p><strong>8. olive flesh is placed in bags and pressed</strong></p>\n<ul>\n<li><strong>Đáp án:</strong> <strong>bags</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn E) “The remaining seedless flesh was put in woven <strong>bags</strong> and pressed.”</li>\n</ul>\n<p><strong>9. resulting liquid is given time to settle and separate, and salt is used to aid the process</strong></p>\n<ul>\n<li><strong>Đáp án:</strong> <strong>salt</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn E) “In cold weather a bit of <strong>salt</strong> was added to speed up the process.”</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('a10093df-7e0a-4809-b64e-8c42b606d7b1', '9a8c54d0-fadf-4120-aba9-afd6f8ef67b7', 'radio', 'Questions 33 – 36', '', '<p>Choose<strong data-path-to-node="11,0" data-index-in-node="0"> YES</strong> if the statement reflects the claims of the writer,<strong data-path-to-node="11,0" data-index-in-node="55">NO</strong> if the statement contradicts the claims of the writer,<strong data-path-to-node="11,0" data-index-in-node="112">NOT GIVEN</strong> if it is impossible to say what the writer thinks about this</p>', 'yes_no_not_given', '[{"correct": 1, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "The local people are willing to answer questions about the festival."}, {"correct": 2, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "More people are attending this festival every year."}, {"correct": 0, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "The organisers of this and similar festivals in the UK are keen to avoid a lot of publicity."}, {"correct": 1, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "The writer got some of his information from the bear ‘handler’."}]', 'null', 'null', 'null', '[{"content": "<p><strong data-path-to-node=\"4\" data-index-in-node=\"0\">33. The local people are willing to answer questions about the festival. — {NO}</strong></p>\n<ul data-path-to-node=\"5\">\n<li><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn E &amp; G):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"24\">“Most of the <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"37\">locals remain tight-lipped</strong> in the face of interrogation… many of the leading figures involved in the festivities <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"152\">refuse to talk to me</strong>.”</em></li>\n<li><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Willing to answer” (sẵn lòng trả lời) trái ngược hoàn toàn với “tight-lipped” (kín tiếng/câm như hến) và “refuse to talk” (từ chối nói chuyện). Do đó, nhận định này mâu thuẫn với khẳng định của tác giả.</li>\n</ul>\n<p><strong data-path-to-node=\"6\" data-index-in-node=\"0\">34. More people are attending this festival every year. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"7\">\n<li><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn F):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“Indeed, the Association of Festival Organisers says that the folk festival movement in the UK is <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"118\">thriving</strong>, with 350 festivals taking place each year.”</em></li>\n<li><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc có nói phong trào lễ hội đang “thriving” (phát triển mạnh) và có 350 lễ hội mỗi năm. Tuy nhiên, <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"116\">không có số liệu cụ thể</strong> nào nói rằng số lượng người tham gia lễ hội Gấu Rơm này đang <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"201\">tăng lên hàng năm</strong> (more… every year).</li>\n</ul>\n<p><strong data-path-to-node=\"8\" data-index-in-node=\"0\">35. The organisers of this and similar festivals in the UK are keen to avoid a lot of publicity. — {YES}</strong></p>\n<ul data-path-to-node=\"9\">\n<li><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn F):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">“…the organisers <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"39\">don’t necessarily want to advertise them and get swamped with tourists</strong>. They’re understandably <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"134\">very wary of the media</strong>.”</em></li>\n<li><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Keen to avoid a lot of publicity” (muốn tránh sự chú ý của công chúng/truyền thông) tương ứng với việc không muốn quảng cáo (don’t want to advertise) và rất cảnh giác với truyền thông (wary of the media). Điều này khớp với ý của tác giả.</li>\n</ul>\n<p><strong data-path-to-node=\"10\" data-index-in-node=\"0\">36. The writer got some of his information from the bear ‘handler’. — {NO}</strong></p>\n<ul data-path-to-node=\"11\">\n<li><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn G):</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"20\">“The bear itself cannot be approached, and its <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"67\">handler looks like someone you wouldn’t want to argue with, so I steer clear of him</strong>.”</em></li>\n<li><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả nói rằng người điều khiển gấu (handler) trông có vẻ đáng sợ nên tác giả đã <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"95\">“steer clear of him”</strong> (tránh xa anh ta). Vì tránh xa nên tác giả không thể lấy được thông tin từ người này. Khẳng định “got some information” là sai.</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('fa6eeb3e-54ca-4b5e-9c57-53eb8c8d5288', 'e7a86d3b-1abf-4933-9a9d-ed6f24522c7c', 'fillup', 'Questions 31–40', '<p data-start="61" data-end="155"><strong data-start="83" data-end="112">Complete the notes below.</strong><br data-start="112" data-end="115"><strong data-start="115" data-end="155">Write ONE WORD ONLY for each answer.</strong></p>
<h3 style="text-align: center;" data-start="78" data-end="102"><strong data-start="82" data-end="102">Inclusive Design</strong></h3>
<p data-start="104" data-end="118"><strong data-start="104" data-end="118">Definition</strong></p>
<ul data-start="119" data-end="340">
<li data-start="119" data-end="223">
<p data-start="121" data-end="223">Designing products that can be accessed by a diverse range of people without the need for any <strong data-start="215" data-end="221">{ adaptation} </strong></p>
</li>
<li data-start="224" data-end="340">
<p data-start="226" data-end="340">Not the same as universal design: that is design for everyone, including catering for people with <strong data-start="324" data-end="330">{cognitive } </strong> problems.</p>
</li>
</ul>
<p data-start="347" data-end="379"><strong data-start="347" data-end="379">Examples of inclusive design</strong></p>
<ul data-start="380" data-end="496">
<li data-start="380" data-end="443">
<p data-start="382" data-end="443"><strong data-start="382" data-end="388">{desks } </strong>which are adjustable, avoiding back or neck problems</p>
</li>
<li data-start="444" data-end="496">
<p data-start="446" data-end="496"><strong data-start="446" data-end="452">{taps } </strong> in public toilets which are easier to use</p>
</li>
</ul>
<p data-start="498" data-end="522">To assist the elderly:</p>
<ul data-start="523" data-end="636">
<li data-start="523" data-end="569">
<p data-start="525" data-end="569">designers avoid using <strong data-start="547" data-end="553">{blue } </strong> in interfaces</p>
</li>
<li data-start="570" data-end="636">
<p data-start="572" data-end="636">people can make commands using a mouse, keyboard or their <strong data-start="630" data-end="636">{voice } </strong></p>
</li>
</ul>
<p data-start="643" data-end="678"><strong data-start="643" data-end="678">Impact of non-inclusive designs</strong></p>
<p data-start="680" data-end="690"><strong data-start="680" data-end="690">Access</strong></p>
<ul data-start="691" data-end="734">
<li data-start="691" data-end="734">
<p data-start="693" data-end="734">Loss of independence for disabled people.</p>
</li>
</ul>
<p data-start="736" data-end="746"><strong data-start="736" data-end="746">Safety</strong></p>
<ul data-start="747" data-end="952">
<li data-start="747" data-end="805">
<p data-start="749" data-end="805">Seatbelts are especially problematic for <strong data-start="790" data-end="796">{pregnant} </strong> women.</p>
</li>
<li data-start="806" data-end="880">
<p data-start="808" data-end="880">PPE jackets are often unsuitable because of the size of women’s <strong data-start="872" data-end="878">{ shoulders} </strong></p>
</li>
<li data-start="881" data-end="952">
<p data-start="883" data-end="952">PPE for female <strong data-start="898" data-end="904">{police } </strong> officers dealing with emergencies is the worst.</p>
</li>
</ul>
<p data-start="954" data-end="982"><strong data-start="954" data-end="982">Comfort in the workplace</strong></p>
<ul data-start="983" data-end="1034">
<li data-start="983" data-end="1034">
<p data-start="985" data-end="1034">The <strong data-start="989" data-end="995">{ temperature} </strong> in offices is often too low for women.</p>
</li>
</ul>
', NULL, 'gap_filling', NULL, NULL, '{"layoutType": ["standard"], "summaryText": null, "answerOptions": null, "matchingItems": null}', '{"layoutType": ["standard"], "legendTitle": null, "matrixItems": null, "matrixCategories": null}', '[{"content": "<p>SPEAKER: It&#8217;s only relatively recently that designers have become aware of the need to be inclusive when designing products. But what does that mean exactly? Well, it simply means designing products that span economic, social and cultural barriers. It means making sure products are accessible so that as many different types of people as possible can use them without any type of adaptation having to be made to the original design. (Question 31)</p>\n<p>Inclusive design is often linked with universal design, although they are not quite the same thing. Universal design aims to make products that work for everyone, and that includes considering the needs of people who have cognitive difficulties, which can present quite a challenge. (Question 32)</p>\n<p>Today, examples of successful inclusive design can be seen all around us. In workplaces, it is common to see desks which can be adjusted to suit people of different heights, or for wheelchair users. (Question 33) This still isn&#8217;t always the case, however, and is one reason why office workers often suffer from back or neck problems.</p>\n<p>You&#8217;ll find another example in the public toilets of countless hotels, airports and offices. Taps that you activate by sensor require no pressing or twisting movements. (Question 34) These are not only more hygienic, they&#8217;re also easier for people with dexterity or mobility issues.</p>\n<p>The tech industry has been criticised in the past for focusing too much on young consumers, but this is changing. Many products are now designed with the elderly in mind. For example, it&#8217;s well known that vision declines with age, and that we also become worse at distinguishing between similar colours. In particular, shades of blue, which is why software designers rarely create interfaces with this colour. (Question 35) Motor skills also decline with age, and some people have difficulty doing everyday things, like picking up a cup or opening a door. This can also affect their ability to use a mouse or keyboard, so voice access is now a routine way of making commands. (Question 36)</p>\n<p>It&#8217;s worth looking at the problems non-inclusive designs cause when not enough consideration is given to a range of users, as it can have a serious impact on people&#8217;s lives. Access is one obvious example, because it has such a huge impact on disabled people&#8217;s independence. Not being able to access public transport because buses or trains are not wheelchair friendly, means many disabled people can&#8217;t go out unless someone goes with them.</p>\n<p>Safety is another issue. Inexplicably, most cars are still crash-tested using a dummy based on an average-sized male. This has safety implications for all women, particularly those who are pregnant, as the seatbelts worn by the dummy are not adapted to accommodate them. (Question 37)</p>\n<p>Over the past 100 years, workplaces in the UK have, on the whole, become considerably safer. Employers are legally required to provide well-maintained personal protective equipment, or PPE, anything from goggles to full bodysuits, to workers who need it free of charge. But most PPE is designed to fit men. (Question 38) A recent report found that employers often think that when it comes to female workers, all they need to do to comply with this legal requirement is to buy jackets, for example, designed for a small man. The problem with this is that women can be tall and still have much smaller shoulders than the average man. Ill-fitting PPE, such as high-vis jackets, vests and body armour, can put women at risk. The report found that 95% of women said that their PPE often hampered their work, and that this problem was worst in the emergency services, particularly the police. (Question 39)</p>\n<p>Another problem is related to comfort at work. A very common scenario in offices in summertime is to see women wrapped in blankets or wearing sweaters while the air-conditioning is on high. Meanwhile, the men are in shorts and T-shirts. This is due to differences in metabolic rates for men and women. (Question 40) There is a standard setting for air-conditioning to be at a temperature of 21 degrees, designed to suit men, and in most modern offices it&#8217;s not possible to turn the air-conditioning up or down. This means that many offices which mainly employ women are wasting energy by having the air-conditioning set too high.</p>\n<p>As you can see from the examples I&#8217;ve just mentioned, there are serious consequences for designs which don&#8217;t consider the needs of all users.</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('a3636345-02d0-4ab1-bb3e-e162d580b603', '052bff80-0f32-4578-9649-7e76f09b9878', 'radio', 'Questions 39-40', NULL, '<p>Choose the correct answer.</p>
', 'multiple-choice', '[{"correct": 0, "options": [{"content": "offset bitter flavour in food"}, {"content": "only exist in 304 cup"}, {"content": "tastes like citrus"}, {"content": "chemical reaction when meets biscuit"}], "question": "What is the main feature of AMP according to this passage?"}, {"correct": 3, "options": [{"content": "collecting taste molecule"}, {"content": "identifying different flavors elements"}, {"content": "resolving large molecules"}, {"content": "transmitting bitter signals to the brain"}], "question": "What is the main function of G protein?"}]', 'null', 'null', 'null', '[{"content": "<p><strong class=\"\">39. What is the main feature of AMP according to this passage?</strong></p>\n<p><strong class=\"\">Đáp án:</strong><span class=\"\"> A.</span><span class=\"\"> offset bitter flavour in food</span></p>\n<p><strong class=\"\">Vị trí:</strong><span class=\"\"> Đoạn H,</span><span class=\"\"> dòng 6–10.</span></p>\n<p><strong class=\"\">Dẫn chứng:</strong><span class=\"\"> “Potassium chloride has a bitter aftertaste,</span><span class=\"\"> but that could be </span><strong class=\"\">eliminated</strong><span class=\"\"> with a dose of AMP…</span><span class=\"\"> they could </span><strong class=\"\">dampen</strong><span class=\"\"> the bitterness of antihistamines,</span><span class=\"\"> antibiotics…</span><span class=\"\">“</span></p>\n<p><strong class=\"\">Giải thích:</strong><span class=\"\"> Trong đoạn H,</span><span class=\"\"> tác giả sử dụng các động từ mạnh như “eliminated” (loại bỏ) và “dampen” (làm dịu/giảm bớt) để mô tả tác động của AMP đối với vị đắng của muối Kali và các loại thuốc.</span><span class=\"\"> Những hành động này khớp hoàn toàn với ý nghĩa của từ “offset” (bù trừ/làm mất đi) trong câu hỏi.</span></p>\n<p><strong>40. What is the main function of G protein?</strong></p>\n<p><strong>Đáp án:</strong> D. transmitting bitter signals to the brain</p>\n<p><strong>Vị trí:</strong> Đoạn E, dòng 8–13.</p>\n<p><strong>Dẫn chứng:</strong> “Once a bitter signal has been received, it is <strong>relayed via proteins known as G proteins</strong>. […] Ultimately, this <strong>delivers a signal to the brain</strong> that registers as bitter.”</p>\n<p><strong>Giải thích:</strong> Bài đọc mô tả G protein đóng vai trò “relayed” (chuyển tiếp) tín hiệu và kết quả là “delivers a signal to the brain” (gửi tín hiệu đến não). Hai hành động này chính là chức năng “transmitting” (truyền dẫn) tín hiệu vị đắng đến não bộ.</p>\n"}]', 2);
INSERT INTO public.questions VALUES ('b8260d64-a104-44f9-8c08-4a89b2a0a15f', '0ae89ddd-e8b4-4ee8-b577-7458b35e4cca', 'fillup', 'Questions 37-40', '<p>Complete the sentences below.</p>
<p>Write <strong>ONE WORD ONLY</strong> for each answer.</p>
<p>More {objects} will be included in the future with the development of photography.</p>
<p>Companies would like to invest a lot to advertise in {newspapers}.</p>
<p>Designing appealing {packaging} is used as a way of effective branding.</p>
<p>Graphic writing systems are of great importance in the subject of {mathematics | math | maths}.</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<h2>(Questions 37–40)</h2>\n<p data-path-to-node=\"3\"><strong>Lecturer:</strong> …One recent high profile campaign was undertaken by attaching a camera to the foot of a Bird in order to obtain photographs of the animals in their natural habitats and understand how often they come into contact with human waste.</p>\n<p data-path-to-node=\"4\"><strong>Lecturer:</strong> A soon-to-be-released documentary about the suffering of animals on Midway Island shows the full extent to which human consumption is harming animals thousands of miles away from us. As photography continues to progress, with the use of drones now becoming somewhat commonplace, we should expect more and more <strong>(37) objects</strong> to be included in the future, expanding the horizon of photography ever further.</p>\n<p data-path-to-node=\"5\"><strong>Lecturer:</strong> Indeed, the downward pressure on traditional media prices means that media companies are being forced to get creative on how to make a profit. Many have found that the answer to this lies in advertising, and companies are now willing to devote a large portion of their budgets to advertising in <strong>(38) newspapers</strong>.</p>\n<p data-path-to-node=\"6\"><strong>Lecturer:</strong> By the same token, marketing has become an essential part of a company’s business model, often meaning the success or failure of a company. As a result, much time and money has been pumped into the development of effective branding, with attractive <strong>(39) packaging</strong> playing a large role in this. However, many governments are now seen to be cracking down on marketing and packaging in an attempt to protect consumers from being misled. In particular, tobacco companies are now subject to ever-increasing regulation…</p>\n<p data-path-to-node=\"7\"><strong>Lecturer:</strong> Finally, one must not forget the fundamental role that graphic writing systems have had to play in <strong>(40) mathematics</strong>. Graphs, icons, and diagrams often form the very basis of these branches of academia. Indeed, one needs to look no further than chemistry’s periodic table to see a perfect example of graphic writing systems in use today.</p>\n<p data-path-to-node=\"8\"><strong>Narrator:</strong> That is the end of Part Four. You now have one minute to check your answers to Part Four.</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('047a787e-2ea1-4002-8b7a-30935402ebb1', '16b5fe53-5af2-4dfc-8826-8dd5bb934d50', 'fillup', 'Questions 31-33', '<p>Complete the sentences below</p>
<p>Write <strong>NO MORE THAN TWOO WORDS</strong> for each answer.</p>
<p><span style="font-size: 12pt;"><strong>Driverless vehicle competition</strong></span></p>
<p>Undergraduates from both the engineering school and the {computer science} department can definitely take part in the project.</p>
<p>The automated vehicles will have to avoid obstacles such as {rocks}</p>
<p>The tutor mentions one vehicle which used technology such as {video cameras}, laser, and laptops to measure its surroundings.</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong>Narrator:</strong> You will hear a tutor talking to a group of students about a project to build a driverless vehicle. First you have some time to look at questions 31 to 40. Now listen carefully and answer questions 31 to forty.</p>\n<blockquote data-path-to-node=\"4\">\n<p data-path-to-node=\"4,0\"><strong>Dịch:</strong> <strong>Người dẫn chuyện:</strong> Bạn sẽ nghe một gia sư nói chuyện với một nhóm sinh viên về dự án chế tạo một phương tiện tự lái.</p>\n</blockquote>\n<p data-path-to-node=\"5\"><span data-path-to-node=\"5,0\"><strong>Lecturer:</strong> Hello everyone. I have an exciting announcement to make. The university has decided to enter an international competition next year. The competition is to make an automated vehicle—a kind of robot—that will be able to move quickly and accurately on its own. </span><span data-path-to-node=\"5,2\"><span class=\"citation-593\">The engineering school will be collaborating with the </span><strong><span class=\"citation-593\">(31) computer science</span></strong><span class=\"citation-593\"> department. </span></span><button class=\"button ng-star-inserted\" data-hveid=\"0\" data-ved=\"0CAAQvoAQahgKEwjzsNuUiJWRAxUAAAAAHQAAAAAQgA4\"></button></p>\n<blockquote data-path-to-node=\"6\">\n<p data-path-to-node=\"6,0\"><span data-path-to-node=\"6,0,0\"><strong>Dịch:</strong> <strong>Giảng viên:</strong> Cuộc thi là về việc chế tạo một phương tiện tự động—một loại robot—có khả năng di chuyển nhanh và chính xác một mình. </span><span data-path-to-node=\"6,0,2\"><span class=\"citation-592\">Trường kỹ thuật sẽ hợp tác với khoa </span><strong><span class=\"citation-592\">(31) khoa học máy tính</span></strong></span><span data-path-to-node=\"6,0,4\">.</span><button class=\"button ng-star-inserted\" data-hveid=\"0\" data-ved=\"0CAAQvoAQahgKEwjzsNuUiJWRAxUAAAAAHQAAAAAQgQ4\"></button></p>\n</blockquote>\n<p data-path-to-node=\"7\"><strong>Lecturer:</strong> The vehicles in the race must cover the whole distance without a human driver and quite autonomously identify and steer around corners and avoid unexpected hazards, things like <strong>(32) rocks</strong> for example. One design which we will be analyzing carefully in seminars built a three-dimensional picture of its surroundings using <strong>(33) video cameras</strong> and lasers.</p>\n<blockquote data-path-to-node=\"8\">\n<p data-path-to-node=\"8,0\"><strong>Dịch:</strong> Xe đua phải tự hành hoàn toàn, xác định và lái vòng qua các góc cua, và tránh các mối nguy hiểm bất ngờ, chẳng hạn như <strong>(32) đá</strong>. Một chiếc xe mà chúng ta sẽ phân tích đã xây dựng hình ảnh 3D xung quanh bằng cách sử dụng <strong>(33) camera video</strong> và tia laser.</p>\n</blockquote>\n<p data-path-to-node=\"9\"><strong>Lecturer:</strong> The sponsors are hoping to see innovative design ideas that they can transfer into commercial production. <strong>(34) The purpose of holding the race is to find useful new design features (C)</strong>. Programming skills will decide who eventually wins first prize. <strong>(35) The design will need technological expertise in this area above all (A: The software design)</strong>. Even after months of planning, many of the teams were amazed that the vehicles did what they wanted them to do at all. <strong>(36) They were surprised that the vehicles were as successful as they were (B)</strong>.</p>\n<blockquote data-path-to-node=\"10\">\n<p data-path-to-node=\"10,0\"><strong>Dịch:</strong> Các nhà tài trợ hy vọng tìm thấy ý tưởng thiết kế đổi mới để chuyển giao vào sản xuất thương mại. <strong>(34) Mục đích của cuộc đua là tìm kiếm các tính năng thiết kế mới hữu ích (C)</strong>. <strong>(35) Thành công sẽ phụ thuộc vào thiết kế phần mềm (A)</strong>, vì các kỹ năng lập trình sẽ quyết định ai chiến thắng. Nhiều đội đã ngạc nhiên khi thấy chiếc xe <strong>(36) đạt được thành công như đã đạt được (B)</strong>.</p>\n</blockquote>\n<hr data-path-to-node=\"11\" />\n<p data-path-to-node=\"13\"><strong>Lecturer:</strong> If any of you are interested, this is the plan of action:</p>\n<p data-path-to-node=\"14\">Firstly, at the beginning of May, we’ll be scheduling an introductory <strong>(37) seminar</strong> about the project.</p>\n<p data-path-to-node=\"15\">Later in the month (Late May), we’ll be asking you to submit a short essay letting us know why you feel you should be chosen, and tell us about any particular <strong>(38) skills</strong> that you have.</p>\n<p data-path-to-node=\"16\">Then in June, we’re organizing a trip to a factory…</p>\n<p data-path-to-node=\"17\">Then at the beginning of the next semester in September, we thought we’d hold a weekend workshop to share <strong>(39) ideas</strong> and see computer aided design demonstrations.</p>\n<p data-path-to-node=\"18\">The following month (January), we’ll choose the <strong>(40) team</strong> and start work in earnest.</p>\n<blockquote data-path-to-node=\"19\">\n<p data-path-to-node=\"19,0\"><strong>Dịch:</strong> Nếu bất kỳ ai trong số các bạn quan tâm, đây là kế hoạch hành động:</p>\n</blockquote>\n<blockquote data-path-to-node=\"20\">\n<p data-path-to-node=\"20,0\">Đầu tiên, vào đầu tháng Năm, chúng ta sẽ lên lịch một buổi <strong>(37) hội thảo</strong> giới thiệu về dự án.</p>\n</blockquote>\n<blockquote data-path-to-node=\"21\">\n<p data-path-to-node=\"21,0\">Cuối tháng Năm, chúng ta sẽ yêu cầu các bạn nộp một bài luận ngắn cho chúng tôi biết lý do tại sao bạn nghĩ mình nên được chọn, và nói về bất kỳ <strong>(38) kỹ năng</strong> cụ thể nào bạn có.</p>\n</blockquote>\n<blockquote data-path-to-node=\"22\">\n<p data-path-to-node=\"22,0\">Sau đó, vào tháng Chín, chúng ta sẽ tổ chức một buổi hội thảo cuối tuần để chia sẻ <strong>(39) ý tưởng</strong>.</p>\n</blockquote>\n<blockquote data-path-to-node=\"23\">\n<p data-path-to-node=\"23,0\">Tháng tiếp theo (tháng Giêng), chúng ta sẽ chọn <strong>(40) đội</strong> và bắt đầu công việc nghiêm túc.</p>\n</blockquote>\n<p data-path-to-node=\"24\"><strong>Narrator:</strong> That is the end of Section 4. You now have half a minute to check your answers.</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('d4273580-60db-49b3-808f-28c00aaa8487', 'd0161c1b-2bf2-48d5-84cd-fcfa9f229b9f', 'radio', 'Questions 36-40', NULL, '<p>Choose <strong>YES </strong>if the statement reflects the claims of the writer. <strong>NO </strong>– if the statement contradicts the claims of the writer. <strong>NOT GIVEN </strong>– if it is impossible to say what the writer thinks about this</p>
', 'multiple_choice_single', '[{"correct": 2, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "The needs of students in school have led to improvements in the teaching of history."}, {"correct": 0, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Academic and popular historians have different attitudes towards the value of innovations in communication."}, {"correct": 1, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "It is common for historians to play a major role in creating historical documentaries for television."}, {"correct": 0, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Articles in American History Review have explored aspects of modern history through popular films."}, {"correct": 2, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Developments in technology are influencing a range of academic subjects."}]', 'null', 'null', 'null', '[{"content": "<p>36. NOT GIVEN<br />\nKhông có đoạn nào nói rằng nhu cầu của học sinh giúp cải thiện việc dạy lịch sử → thông tin không được đề cập.</p>\n<p>37. YES<br />\n(Đoạn A, “&#8230;there are mainstream academics who continue to use only the written word&#8230; On the other hand, film and video&#8230; are probably the major influence on the public.”)<br />\n→ Cho thấy sử gia học thuật và đại chúng có quan điểm khác nhau về giá trị của đổi mới trong truyền thông.</p>\n<p>38. NO<br />\n(Đoạn B, “&#8230;professional historians have tended to avoid involvement in television programmes about history.”)<br />\n→ Nói rõ hầu hết sử gia không tham gia làm phim tài liệu, nên đáp án là NO.</p>\n<p>39. YES<br />\n(Đoạn E, “…Journals such as American History Review have played a significant role in this field.”)<br />\n→ Cho thấy American History Review có bài viết về lịch sử hiện đại qua phim ảnh.</p>\n<p>40. NOT GIVEN<br />\nKhông có đoạn nào nói rằng các lĩnh vực học thuật khác cũng bị ảnh hưởng bởi công nghệ – chỉ đề cập riêng đến ngành lịch sử, nên đáp án NOT GIVEN.</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('2e30e844-6f49-440c-ad79-d15b4dd1ae40', '7cede508-8583-4f43-8c37-47535900fab2', 'radio', 'Questions 1–6', NULL, '<p class="MsoNormal">Choose <strong>TRUE</strong> if the statement agrees with the information given in the text, choose <strong>FALSE</strong> if the statement contradicts the information, or choose <strong>NOT GIVEN</strong> if there is no information on this.</p>
', 'multiple-choice', '[{"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "During his 2007 dive, Michiels expected to encounter total darkness at about 15 metres."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Michiels could see the red markings on fish without the aid of the red filter."}, {"correct": 1, "options": [{"content": "TRUE "}, {"content": "FALSE "}, {"content": "NOT GIVEN"}], "question": "Other divers had assumed they would see fish with red markings."}, {"correct": 2, "options": [{"content": "TRUE "}, {"content": "FALSE "}, {"content": "NOT GIVEN"}], "question": "All the fish with red markings that Michiels found during his diving expeditions came from the Red Sea."}, {"correct": 1, "options": [{"content": "TRUE "}, {"content": "FALSE "}, {"content": "NOT GIVEN"}], "question": "Michiels first thought of the possibility that fish could fluoresce while he was in Germany."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Michiels remains uncertain as to what creates fluorescence in fish."}]', 'null', 'null', 'null', '[{"content": "<p>1. During his 2007 dive, Michiels expected to encounter total darkness at about 15 metres.</p>\n<ul data-path-to-node=\"3\">\n<li>\n<p data-path-to-node=\"3,0,0\"><strong class=\"\">Đáp án: TRUE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"3,1,0\"><strong class=\"\">Dẫn chứng:</strong><span class=\"\"> (Đoạn A) “In theory,</span> <strong class=\"\">once he reached about 15 metres, he should have been plunged into darkness</strong><span class=\"\">.</span><span class=\"\">“</span></p>\n</li>\n<li>\n<p data-path-to-node=\"3,2,0\"><strong class=\"\">Giải thích:</strong><span class=\"\"> Câu hỏi phản ánh đúng kỳ vọng lý thuyết của Michiels về độ sâu mà ánh sáng đỏ biến mất.</span></p>\n</li>\n</ul>\n<p>2. Michiels could see the red markings on fish without the aid of the red filter.</p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong class=\"\">Đáp án: TRUE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong class=\"\">Dẫn chứng:</strong><span class=\"\"> (Đoạn B) “</span><strong class=\"\">Even with the red filter removed</strong><span class=\"\">,</span><span class=\"\"> Michiels could pick them out without much trouble </span><strong class=\"\">once his eyes grew accustomed to the gloom</strong><span class=\"\">.</span><span class=\"\">“</span></p>\n</li>\n<li>\n<p data-path-to-node=\"5,2,0\"><strong class=\"\">Giải thích:</strong><span class=\"\"> Sau khi tháo kính lọc đỏ và quen với bóng tối,</span><span class=\"\"> Michiels vẫn có thể nhìn thấy các dấu hiệu màu đỏ.</span></p>\n</li>\n</ul>\n<p>3. Other divers had assumed they would see fish with red markings.</p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong class=\"\">Đáp án: FALSE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong class=\"\">Dẫn chứng:</strong><span class=\"\"> (Đoạn B) “It seems strange that no diver or researcher had spotted all this red before,</span><span class=\"\"> but as Michiels points out,</span> <strong class=\"\">no one saw it because no one expected to see it</strong><span class=\"\">.</span><span class=\"\">“</span></p>\n</li>\n<li>\n<p data-path-to-node=\"7,2,0\"><strong class=\"\">Giải thích:</strong><span class=\"\"> Các thợ lặn và nhà nghiên cứu khác không thấy màu đỏ vì họ </span><strong class=\"\">không mong đợi</strong><span class=\"\"> (expected) thấy nó,</span><span class=\"\"> mâu thuẫn với việc họ “had assumed” (đã giả định) sẽ thấy.</span></p>\n</li>\n</ul>\n<p>4. All the fish with red markings that Michiels found during his diving expeditions came from the Red Sea.</p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong>Đáp án: NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong>Dẫn chứng:</strong> (Đoạn A, B) Michiels tìm thấy các loài này ở Biển Đỏ (Red Sea), nhưng văn bản <strong>không nói rằng TẤT CẢ</strong> các loài cá có dấu hiệu đỏ mà ông tìm thấy trong các chuyến lặn khác nhau <strong>đều chỉ đến từ Biển Đỏ</strong>.</p>\n</li>\n</ul>\n<p>5. Michiels first thought of the possibility that fish could fluoresce while he was in Germany.</p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong>Đáp án: FALSE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong>Dẫn chứng:</strong> (Đoạn C) Michiels <strong>nghi ngờ sự phát quang</strong> (<strong>suspected fluorescence</strong>) ngay khi ông đang lặn ở Biển Đỏ (“At 20 metres down, there had to be some other explanation for the red Michiels was seeing. He <strong>suspected fluorescence</strong>.”). Ông chỉ <strong>xác nhận</strong> điều đó ở Đức (Đoạn D).</p>\n</li>\n<li>\n<p data-path-to-node=\"11,2,0\"><strong>Giải thích:</strong> Ý tưởng phát quang xuất hiện khi ông đang ở Ai Cập (lặn Biển Đỏ), không phải lần đầu tiên ở Đức.</p>\n</li>\n</ul>\n<p>6. Michiels remains uncertain as to what creates fluorescence in fish.</p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong>Đáp án: TRUE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong>Dẫn chứng:</strong> (Đoạn D) “However, Michiels says they are <strong>still not sure exactly what is fluorescing</strong>. ‘It’s not the crystals themselves. It’s probably a fluorescent protein built into the crystals, and <strong>we have a suspicion that it might be made by bacteria</strong>.’”</p>\n</li>\n<li>\n<p data-path-to-node=\"13,2,0\"><strong>Giải thích:</strong> Ông vẫn chưa chắc chắn về nguồn gốc chính xác của chất phát quang, chỉ nghi ngờ là protein hoặc vi khuẩn.</p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('e3f3849b-103e-4901-aef2-9d70326bc113', '7cede508-8583-4f43-8c37-47535900fab2', 'fillup', 'Questions 7–13', '<p>Complete the notes below.</p>
<p>Write <strong>ONE WORD ONLY</strong> from the passage for each answer.</p>
<p><strong>Michiels’s findings:</strong></p>
<p>Michiels has observed:</p>
<p>– 50 types of fish with red fluorescence in total</p>
<p>– markings mainly near the {head}</p>
<p>Some of Michiels’s beliefs are that:</p>
<p>– red fluorescence is used specifically for {communication} purposes</p>
<p>– fish, like some animals, use fluorescence to keep {enemies} away</p>
<p>– gobies depend on red fluorescence to show their {location}</p>
<p>– there are variations in the markings of fish among those {species} which are very similar</p>
<p>Other benefits of red fluorescence:</p>
<p>– fish cannot easily be seen near backgrounds of {corals} which give off a red light</p>
<p>– helps some fish catch their prey</p>
<p>The ability to see red amongst fish:</p>
<p>– the only fish proven to have this ability is the {seahorse}</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p>7. Michiels has observed: markings mainly near the <strong>head</strong>.</p>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong>Đáp án:</strong> <strong>head</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong>Dẫn chứng:</strong> (Đoạn E) “The most common markings tend to be on the body towards the <strong>head</strong> and to a lesser extent around the eyes, and then the fins.”</p>\n</li>\n</ul>\n<p>8. Some of Michiels’s beliefs are that: red fluorescence is used specifically for <strong>communication</strong> purposes.</p>\n<ul data-path-to-node=\"19\">\n<li>\n<p data-path-to-node=\"19,0,0\"><strong>Đáp án:</strong> <strong>communication</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"19,1,0\"><strong>Dẫn chứng:</strong> (Đoạn E) “…the distribution of these markings is one of the strongest indications that red fluorescence has a very particular function: <strong>communication</strong> with other members of the species.”</p>\n</li>\n</ul>\n<p>9. Fish, like some animals, use fluorescence to keep <strong>enemies</strong> away.</p>\n<ul data-path-to-node=\"21\">\n<li>\n<p data-path-to-node=\"21,0,0\"><strong>Đáp án:</strong> <strong>enemies</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"21,1,0\"><strong>Dẫn chứng:</strong> (Đoạn E) “…a whole range of animals employ fluorescence as a natural highlighter to boost the visibility of body parts they use to signal, for example to <strong>ward off enemies</strong>.” (Ward off enemies có nghĩa là giữ kẻ thù tránh xa).</p>\n</li>\n</ul>\n<p>10. Gobies depend on red fluorescence to show their <strong>location</strong>.</p>\n<ul data-path-to-node=\"23\">\n<li>\n<p data-path-to-node=\"23,0,0\"><strong>Đáp án:</strong> <strong>location</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"23,1,0\"><strong>Dẫn chứng:</strong> (Đoạn E) “…Michiels suspects that red-eyed gobies use signals to indicate their <strong>location</strong> and keep their group together.”</p>\n</li>\n</ul>\n<p>11. There are variations in the markings of fish among those <strong>species</strong> which are very similar.</p>\n<ul data-path-to-node=\"25\">\n<li>\n<p data-path-to-node=\"25,0,0\"><strong>Đáp án:</strong> <strong>species</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"25,1,0\"><strong>Dẫn chứng:</strong> (Đoạn F) “And closely related <strong>species</strong> do not have completely identical markings , which suggests they might be important in <strong>species</strong> recognition.”</p>\n</li>\n</ul>\n<p>12. Other benefits of red fluorescence: fish cannot easily be seen near backgrounds of <strong>corals</strong> which give off a red light.</p>\n<ul data-path-to-node=\"27\">\n<li>\n<p data-path-to-node=\"27,0,0\"><strong>Đáp án:</strong> <strong>corals</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"27,1,0\"><strong>Dẫn chứng:</strong> (Đoạn G) “During his first dive with the red filter, he noticed <strong>corals</strong> glow a dark but faint red too. Against this irregular red background, a fish that glows red all over would be hard to distinguish.”</p>\n</li>\n</ul>\n<p>13. The ability to see red amongst fish: the only fish proven to have this ability is the <strong>seahorse</strong>.</p>\n<ul data-path-to-node=\"29\">\n<li>\n<p data-path-to-node=\"29,0,0\"><strong>Đáp án:</strong> <strong>seahorse</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"29,1,0\"><strong>Dẫn chứng:</strong> (Đoạn H) “One exception is the <strong>seahorse</strong>, whose eyes are sensitive to red.”</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('698b24e1-17bf-4ad1-a4ca-ade361ffe7f9', '2ead78f1-f821-49d8-82fe-40276b10dfa0', 'matrix', 'Questions 14–17', NULL, '<p>Reading Passage 2 has seven sections, <strong>A-G</strong>.</p>
<p>Which section contains the following information?</p>
<p>Choose the correct letter, <strong>A-G</strong>, in boxes 14-17.</p>
', 'other', 'null', 'null', 'null', '{"layoutType": "simple", "legendTitle": null, "matrixItems": [{"itemText": "a prediction as to the direction in which the jellyfish population may spread", "correctCategoryLetter": "E"}, {"itemText": "a description of some physical characteristics of jellyfish", "correctCategoryLetter": "A"}, {"itemText": "an account of the consequences of jellyfish as lone survivors", "correctCategoryLetter": "F"}, {"itemText": "suggestions on how to avoid further jellyfish invasions", "correctCategoryLetter": "G"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}]}', '[{"content": "<p><strong>14. a prediction as to the direction in which the jellyfish population may spread</strong></p>\n<ul data-path-to-node=\"3\">\n<li><strong>Đáp án: E</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn E) “As water warms, tropical species are moving towards the poles. <strong>Many venomous jellyfish species are tropical and could move into more densely populated subtropical and temperate regions</strong>.”</li>\n<li><strong>Giải thích:</strong> Đoạn E dự đoán hướng lây lan địa lý (hướng về các cực – towards the poles, và các vùng ôn đới/cận nhiệt đới) do sự nóng lên toàn cầu (climate change).</li>\n</ul>\n<p><strong>15. a description of some physical characteristics of jellyfish</strong></p>\n<ul data-path-to-node=\"5\">\n<li><strong>Đáp án: A</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn A) “…they <strong>lack sharp claws, piercing teeth or even a brain</strong>. Despite this, they are armed with an amazing arsenal of weapons, especially the stinging power of their <strong>tentacles</strong>.”</li>\n<li><strong>Giải thích:</strong> Đoạn A mô tả các đặc điểm vật lý cơ bản (thiếu não, không có răng, có xúc tu chích).</li>\n</ul>\n<p><strong>16. an account of the consequences of jellyfish as lone survivors</strong></p>\n<ul data-path-to-node=\"7\">\n<li><strong>Đáp án: F</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn F) “One can thus think of two alternate states… one dominated by fish and the other by jellyfish. Unfortunately, where there is a jellyfish-dominated state then <strong>this does not support the nutritional needs of other fish, marine mammals, and seabirds</strong>.”</li>\n<li><strong>Giải thích:</strong> Đoạn F mô tả hậu quả của hệ sinh thái bị chi phối bởi sứa (“monoculture of jellyfish”)—chúng không hỗ trợ nhu cầu dinh dưỡng cho các loài khác (lone survivors).</li>\n</ul>\n<p><strong>17. suggestions on how to avoid further jellyfish invasions</strong></p>\n<ul data-path-to-node=\"9\">\n<li><strong>Đáp án: G</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn G) “Richardson and his colleagues <strong>propose focusing on ‘prevention rather than cure’</strong>. They <strong>recommend a halt to overfishing</strong> small fish… <strong>reducing the amount of fertilizer and sewage</strong> running off… and finally, if possible, <strong>confronting climate change</strong>.”</li>\n<li><strong>Giải thích:</strong> Đoạn G đưa ra các biện pháp đề xuất để ngăn chặn (avoid further) các cuộc xâm lăng của sứa trong tương lai.</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('3c74968e-2bc5-4429-be15-7c4bb9acfa9e', 'e9d314af-fb75-4b3e-86bf-0d5ae2e618c0', 'matching', 'Questions 14–19', NULL, '<p>The text has four sections. Choose the correct heading for each section and move it into the gap.</p>
', 'matching_features', 'null', 'null', '{"layoutType": "heading", "summaryText": null, "answerOptions": [{"optionText": "i The controversy around the word “toxic”"}, {"optionText": "ii Effects of different types of stress"}, {"optionText": "iii How to protect children from toxic stress"}, {"optionText": "iv An association of adverse experience with health problems and unhealthy habits"}, {"optionText": "v Body’s reactions in response to the perceived harmful event"}, {"optionText": "vi Signs of being under sustained stress"}, {"optionText": "vii Negative impacts of toxic stress on children’s mental health"}], "matchingItems": null}', 'null', '[{"content": "<p>1. v (Đoạn A, “We breathe faster, taking in more oxygen, muscles tense, our senses are sharpened and beads of sweat appear.”)</p>\n<p>2. ii (Đoạn B, “In those cases, our stress is considered “positive”, because it is temporary and helps us survive. But our bodies sometimes react in the same way to more mundane stressors, too.”)</p>\n<p>3. iv (Đoạn C, “…people who had experienced abuse or household dysfunction as children were more likely to have serious health problems, like cancer or liver diseases…”)</p>\n<p>4. vii (Đoạn D, “The burden of that stress, which is known as ‘allostatic load or overload,’ referring to the wear and tear that results from either too much stress…”)</p>\n<p>5. i (Đoạn E, “Toxic is a loaded word. Critics say the term is inherently judgmental and may appear to blame parents for external social circumstances over which they have little control.”)</p>\n<p>6. iii (Đoạn F, “Another one is to ensure love and support from a parent or caregiver. Young children’s stress responses are more stable, even in difficult situations, when they are with an adult they trust.”)</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('d1b74388-d22c-4910-b37b-d38494ea6ff3', '35cf7679-ae9c-4e0a-8d18-938a9d92a722', 'fillup', 'Questions 21–30', '<div class="quests-inner-desc">
<div class="txt">
<p>Complete the notes below.</p>
<p>Write <strong>NO MORE THAN THREE WORDS AND/OR A NUMBER</strong> for each answer.</p>
</div>
</div>
<div class="quests-des">
<div class="content-write">
<p><span style="font-size: 14pt;"><strong>Possible Course Change</strong></span></p>
<p>Name of student:                Sally Layman</p>
<p>Current course:                 {Economic History}</p>
<p>Date started:                      <span class="fill-history-correct">{last September}</span></p>
<p>Courses interested in: 1st choice  {Politics}</p>
<p>2nd choice  {Philosophy}</p>
<div dir="ltr" align="left">
<div class="choice-table-wrap">
<table class="choice-table" style="border-collapse: collapse; border-spacing: 1px; border: 1px solid #000000;" border="1"><colgroup> <col width="190"> <col width="174"> <col width="231"></colgroup>
<tbody>
<tr>
<td style="border-width: 1px; padding: 1px; border-color: #000000;">
<p dir="ltr"><strong>Problem</strong></p>
</td>
<td style="border-width: 1px; padding: 1px; border-color: #000000;">
<p dir="ltr"><strong>Strategies tried</strong></p>
</td>
<td style="border-width: 1px; padding: 1px; border-color: #000000;">
<p dir="ltr"><strong>Further strategies suggested</strong></p>
</td>
</tr>
<tr>
<td style="border-width: 1px; padding: 1px; border-color: #000000;">
<p dir="ltr">finds  {lectures difficult| the lectures difficult}</p>
</td>
<td style="border-width: 1px; padding: 1px; border-color: #000000;">
<p dir="ltr">recording them</p>
</td>
<td style="border-width: 1px; padding: 1px; border-color: #000000;">
<p dir="ltr">join other students in</p>
<p dir="ltr">a  <span class="fill-history-correct">{discussion group}</span></p>
</td>
</tr>
<tr>
<td style="border-width: 1px; padding: 1px; border-color: #000000;">
<p dir="ltr">{not enough tutorials}</p>
</td>
<td style="border-width: 1px; padding: 1px; border-color: #000000;">
<p dir="ltr">talking to tutor</p>
</td>
<td style="border-width: 1px; padding: 1px; border-color: #000000;">
<p dir="ltr">arrange meetings in advance</p>
</td>
</tr>
<tr>
<td style="border-width: 1px; padding: 1px; border-color: #000000;">
<p dir="ltr">bad assignment</p>
</td>
<td style="border-width: 1px; padding: 1px; border-color: #000000;">
<p dir="ltr">more background reading</p>
</td>
<td style="border-width: 1px; padding: 1px; border-color: #000000;">
<p dir="ltr">visit <span class="fill-history-correct">{student services}</span></p>
</td>
</tr>
</tbody>
</table>
</div>
</div>
<p>Date for next meeting:</p>
<p><span class="fill-history-correct">{17th of February |17 February| February 17| 17th February| 17 February}</span> at 3.30 p. m.</p>
<p>With:  <span class="fill-history-correct">{senior advisor| senior adviser}</span></p>
</div>
</div>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">PART 3: COURSE CHANGE DISCUSSION</strong></p>\n<p data-path-to-node=\"3\"><strong class=\"\" data-path-to-node=\"3\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> Excuse me,</span><span class=\"\"> Professor.</span><span class=\"\"> Can I talk to you for a minute?</span></p>\n<p data-path-to-node=\"4\"><strong class=\"\" data-path-to-node=\"4\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> Yes,</span><span class=\"\"> do come in.</span><span class=\"\"> So,</span><span class=\"\"> you’re Sally Lehmann,</span><span class=\"\"> that’s it?</span><span class=\"\"> You want to discuss with me changing courses,</span><span class=\"\"> right?</span></p>\n<p data-path-to-node=\"5\"><strong class=\"\" data-path-to-node=\"5\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> Yes,</span><span class=\"\"> alright.</span></p>\n<p data-path-to-node=\"6\"><strong class=\"\" data-path-to-node=\"6\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> What course are you doing at present,</span><span class=\"\"> Sally?</span></p>\n<p data-path-to-node=\"7\"><strong class=\"\" data-path-to-node=\"7\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> It’s </span><strong class=\"\" data-path-to-node=\"7\" data-index-in-node=\"12\">(Q21) Economic History</strong><span class=\"\">.</span></p>\n<p data-path-to-node=\"8\"><strong class=\"\" data-path-to-node=\"8\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> OK.</span><span class=\"\"> And when did you begin this course?</span></p>\n<p data-path-to-node=\"9\"><strong class=\"\" data-path-to-node=\"9\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> Let me think…</span><span class=\"\"> um,</span><span class=\"\"> it was </span><strong class=\"\" data-path-to-node=\"9\" data-index-in-node=\"34\">(Q22) last September</strong><span class=\"\">,</span><span class=\"\"> right.</span></p>\n<p data-path-to-node=\"10\"><strong class=\"\" data-path-to-node=\"10\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> Good.</span><span class=\"\"> Before we talk through all your problems with the course,</span><span class=\"\"> I want to know what courses you’d like to change to.</span></p>\n<p data-path-to-node=\"11\"><strong class=\"\" data-path-to-node=\"11\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> Well,</span><span class=\"\"> there are several courses that I thought about,</span><span class=\"\"> but my first choice would be </span><strong class=\"\" data-path-to-node=\"11\" data-index-in-node=\"90\">(Q23) Politics</strong><span class=\"\">.</span></p>\n<p data-path-to-node=\"12\"><strong class=\"\" data-path-to-node=\"12\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> Oh,</span><span class=\"\"> it’s one of the most popular courses in our college.</span></p>\n<p data-path-to-node=\"13\"><strong class=\"\" data-path-to-node=\"13\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> Yes,</span><span class=\"\"> I know.</span></p>\n<p data-path-to-node=\"14\"><strong class=\"\" data-path-to-node=\"14\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> So it means there might not be places available.</span></p>\n<p data-path-to-node=\"15\"><strong class=\"\" data-path-to-node=\"15\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> That’s right.</span></p>\n<p data-path-to-node=\"16\"><strong class=\"\" data-path-to-node=\"16\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> I’ll still make a note of that,</span><span class=\"\"> but it’s better to give another option.</span></p>\n<p data-path-to-node=\"17\"><strong class=\"\" data-path-to-node=\"17\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> Well,</span><span class=\"\"> I’ve thought of changing the course entirely to Business Studies,</span><span class=\"\"> but then I realised it is new to me,</span><span class=\"\"> so I think </span><strong class=\"\" data-path-to-node=\"17\" data-index-in-node=\"127\">(Q24) Philosophy</strong><span class=\"\"> might be a better choice.</span></p>\n<hr class=\"\" data-path-to-node=\"18\">\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">PROBLEMS &amp; STRATEGIES (Questions 25–30)</strong></p>\n<p data-path-to-node=\"20\"><strong class=\"\" data-path-to-node=\"20\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> Okay,</span><span class=\"\"> that’s useful to know.</span><span class=\"\"> Then let’s talk through any problems you’ve been having at the moment and see if there is any possibility for us to offer help.</span><span class=\"\"> After all,</span><span class=\"\"> with all the efforts that you’ve made already,</span><span class=\"\"> it’ll be a pity to give up the present course and completely start a new one.</span></p>\n<p data-path-to-node=\"21\"><strong class=\"\" data-path-to-node=\"21\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> Yes,</span><span class=\"\"> I agree with that.</span><span class=\"\"> I’ve learned something valuable about economic history.</span></p>\n<p data-path-to-node=\"22\"><strong class=\"\" data-path-to-node=\"22\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> Good.</span><span class=\"\"> Well,</span><span class=\"\"> let’s talk about your problems.</span><span class=\"\"> What do you think is your significant difficulty in the course?</span></p>\n<p data-path-to-node=\"23\"><strong class=\"\" data-path-to-node=\"23\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> Well,</span><span class=\"\"> I have to say,</span><span class=\"\"> the biggest problem is that the </span><strong class=\"\" data-path-to-node=\"23\" data-index-in-node=\"60\">(Q25) lectures are difficult</strong><span class=\"\">.</span></p>\n<p data-path-to-node=\"24\"><strong class=\"\" data-path-to-node=\"24\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> Okay.</span><span class=\"\"> And have you tried something to overcome this problem?</span></p>\n<p data-path-to-node=\"25\"><strong class=\"\" data-path-to-node=\"25\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> Yes,</span><span class=\"\"> I have.</span><span class=\"\"> I tried recording the lectures because I couldn’t follow what the lecturer said.</span></p>\n<p data-path-to-node=\"26\"><strong class=\"\" data-path-to-node=\"26\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> Yes,</span><span class=\"\"> that’s a good idea.</span><span class=\"\"> And did you find it helped?</span></p>\n<p data-path-to-node=\"27\"><strong class=\"\" data-path-to-node=\"27\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> To a certain extent but…</span></p>\n<p data-path-to-node=\"28\"><strong class=\"\" data-path-to-node=\"28\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> Well,</span><span class=\"\"> recording is a good strategy,</span><span class=\"\"> but I also advise you to take part in the </span><strong class=\"\" data-path-to-node=\"28\" data-index-in-node=\"89\">(Q26) discussion group</strong><span class=\"\"> with other fellow students to discuss the lectures and exchange ideas with them.</span></p>\n<p data-path-to-node=\"29\"><strong class=\"\" data-path-to-node=\"29\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> Yes,</span><span class=\"\"> I’ve seen some of my classmates doing that.</span><span class=\"\"> I’ll ask them if I can join.</span></p>\n<p data-path-to-node=\"30\"><strong class=\"\" data-path-to-node=\"30\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> Good,</span><span class=\"\"> I’m sure you’ll find it helps.</span><span class=\"\"> And any other problems?</span></p>\n<p data-path-to-node=\"31\"><strong class=\"\" data-path-to-node=\"31\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> Yes.</span><span class=\"\"> The second problem is,</span><span class=\"\"> I think there are </span><strong class=\"\" data-path-to-node=\"31\" data-index-in-node=\"53\">(Q27) not enough tutorials</strong><span class=\"\"> for this course.</span></p>\n<p data-path-to-node=\"32\"><strong class=\"\" data-path-to-node=\"32\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> OK,</span><span class=\"\"> I think you can talk to your tutor about this.</span></p>\n<p data-path-to-node=\"33\"><strong class=\"\" data-path-to-node=\"33\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> Yes,</span><span class=\"\"> I did that,</span><span class=\"\"> but the tutor is so busy that I must wait until she is available.</span></p>\n<p data-path-to-node=\"34\"><strong class=\"\" data-path-to-node=\"34\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> Why don’t you try arranging meetings ahead of time?</span></p>\n<p data-path-to-node=\"35\"><strong class=\"\" data-path-to-node=\"35\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> Well,</span><span class=\"\"> I can try this way.</span></p>\n<p data-path-to-node=\"36\"><strong class=\"\" data-path-to-node=\"36\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> Good.</span><span class=\"\"> But I suppose the thing that made me upset recently is my poor assignment grade.</span></p>\n<p data-path-to-node=\"37\"><strong class=\"\" data-path-to-node=\"37\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> Oh,</span><span class=\"\"> the grade is an important issue.</span><span class=\"\"> Well,</span><span class=\"\"> I think I’ve tried my best to achieve a good score.</span><span class=\"\"> I did more background reading than before for the last assignment we just submitted.</span></p>\n<p data-path-to-node=\"38\"><strong class=\"\" data-path-to-node=\"38\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> Good,</span><span class=\"\"> and did you feel that helped?</span></p>\n<p data-path-to-node=\"39\"><strong class=\"\" data-path-to-node=\"39\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> Oh yes,</span><span class=\"\"> I think so.</span></p>\n<p data-path-to-node=\"40\"><strong class=\"\" data-path-to-node=\"40\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> Well,</span><span class=\"\"> I think you can try another strategy,</span><span class=\"\"> which is to visit </span><strong class=\"\" data-path-to-node=\"40\" data-index-in-node=\"73\">(Q28) student services</strong><span class=\"\">,</span><span class=\"\"> which offer a lot of helpful advice on assignment preparation.</span></p>\n<p data-path-to-node=\"41\"><strong class=\"\" data-path-to-node=\"41\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> Oh,</span><span class=\"\"> I’ve never heard about that.</span></p>\n<p data-path-to-node=\"42\"><strong class=\"\" data-path-to-node=\"42\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> I’ll give you a booklet with details on this.</span><span class=\"\"> You’ll find it well worth trying.</span></p>\n<p data-path-to-node=\"43\"><strong class=\"\" data-path-to-node=\"43\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> OK,</span><span class=\"\"> I’ll certainly try it.</span></p>\n<p data-path-to-node=\"44\"><strong class=\"\" data-path-to-node=\"44\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> OK,</span><span class=\"\"> that’s all the problems.</span><span class=\"\"> Well,</span><span class=\"\"> I’ve made a record of our discussions and suggested strategies.</span><span class=\"\"> Typically,</span><span class=\"\"> we advise you to try out these suggestions for a short period and then come back to discuss the situation to see whether it is improved.</span><span class=\"\"> If not,</span><span class=\"\"> we will start considering alternative courses.</span></p>\n<p data-path-to-node=\"45\"><strong class=\"\" data-path-to-node=\"45\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> OK.</span><span class=\"\"> When shall I come back?</span></p>\n<p data-path-to-node=\"46\"><strong class=\"\" data-path-to-node=\"46\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> How about in a month’s time?</span></p>\n<p data-path-to-node=\"47\"><strong class=\"\" data-path-to-node=\"47\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> Okay,</span><span class=\"\"> that will be on the </span><strong class=\"\" data-path-to-node=\"47\" data-index-in-node=\"33\">(Q29) 17th of February</strong><span class=\"\"> (17 February).</span><span class=\"\"> How about half past three in the afternoon?</span><span class=\"\"> Is that alright for you?</span></p>\n<p data-path-to-node=\"48\"><strong class=\"\" data-path-to-node=\"48\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> Yes,</span><span class=\"\"> sure.</span><span class=\"\"> And where shall I meet you?</span> I’m afraid I will be on leave at that time, but I’ll leave this record to our <strong data-path-to-node=\"48\" data-index-in-node=\"128\">(Q30) senior advisor</strong>, and you will meet with him then in this office.</p>\n<p data-path-to-node=\"49\"><strong data-path-to-node=\"49\" data-index-in-node=\"0\">Sally:</strong> OK, good.</p>\n<p data-path-to-node=\"50\"><strong data-path-to-node=\"50\" data-index-in-node=\"0\">Professor:</strong> That’s it. Let’s see whether things can improve, Sally. OK?</p>\n<p data-path-to-node=\"51\"><strong data-path-to-node=\"51\" data-index-in-node=\"0\">Sally:</strong> Thanks very much. My pleasure, bye.</p>"}]', 0);
INSERT INTO public.questions VALUES ('6c8ef174-1c22-4741-858c-fd1de48d6375', 'e9d314af-fb75-4b3e-86bf-0d5ae2e618c0', 'radio', 'Questions 20–22', '<p>Choose TRUE if the statement agrees with the information given in the text, choose FALSE if the statement contradicts the information, or choose NOT GIVEN if there is no information on this.</p>
', '<p>Choose <strong>TRUE </strong>if the statement agrees with the information given in the text, choose <strong>FALSE</strong> if the statement contradicts the information, or choose <strong>NOT GIVEN </strong>if there is no information on this.</p>
', 'multiple_choice_single', '[{"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Felitti and Anda were the first to show that ACEs create impacts regarding health and habits later on in life."}, {"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Some children have the same level of vulnerability to stressful events."}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Several paediatricians consider poverty and racism the primary contributors to toxic stress."}]', 'null', 'null', 'null', '[{"content": "<p>7. TRUE (Đoạn C, “In 1998, two researchers, Vincent Felitti and Robert Anda, pioneered in publishing a study demonstrating that people who had experienced abuse or household dysfunction…”)</p>\n<p>8. FALSE (Đoạn B, “The effects are not the same in every child, and can be buffered by the support of a parent or caregiver, in which case the stress is considered “tolerable”.”)</p>\n<p>9. NOT GIVEN (Không có thông tin)</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('5557d764-6886-4e66-8f43-39f7ea26f765', 'bf725440-7036-485f-bc47-2dc540499522', 'radio', 'Questions 33–37', '', '<p data-path-to-node="10,0,0">Choose <strong data-path-to-node="10,0,0" data-index-in-node="0">YES</strong> if the statement agrees with the claims of the writer,<strong data-path-to-node="10,1,0" data-index-in-node="0">NO</strong> if the statement contradicts the claims of the writer,<strong data-path-to-node="10,2,0" data-index-in-node="0">NOT GIVEN</strong> if it is impossible to say what the writer thinks about this</p>', 'yes_no_not_given', '[{"correct": 0, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Many people who ended up winning prestigious intellectual prizes only reached an average standard when young."}, {"correct": 2, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Einstein’s failures as a young man were due to his lack of confidence."}, {"correct": 0, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "It is difficult to reach agreement on whether some children are actually born gifted."}, {"correct": 2, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Einstein was upset by the public’s view of his life’s work."}, {"correct": 1, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Einstein put his success down to the speed at which he dealt with scientific questions."}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">33. Many people who ended up winning prestigious intellectual prizes only reached an average standard when young. — {YES}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 3):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">\"Most <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"26\">Nobel prize winners</strong> [prestigious intellectual prizes] were <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"85\">unexceptional in childhood</strong> [average standard when young].\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Unexceptional\" có nghĩa là bình thường, không có gì nổi bật (tương ứng với \"average standard\"). Bài đọc khẳng định hầu hết những người thắng giải Nobel đều có tuổi thơ bình thường.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">34. Einstein’s failures as a young man were due to his lack of confidence. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 3):</strong> Bài đọc có nhắc đến các thất bại của Einstein như: chậm nói, trượt kỳ thi đầu vào đại học, chật vật trong công việc ban đầu.</p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả liệt kê các thất bại nhưng <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"47\">không hề giải thích nguyên nhân</strong> có phải là do ông \"thiếu tự tin\" (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"113\">lack of confidence</strong>) hay không.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">35. It is difficult to reach agreement on whether some children are actually born gifted. — {YES}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 5):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">\"While <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"27\">the jury is out on giftedness being innate</strong>...\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Thành ngữ \"the jury is out\" dùng để chỉ một vấn đề vẫn đang được tranh luận, chưa có quyết định cuối cùng hay sự thống nhất. Điều này đồng nghĩa với việc rất khó để đạt được sự đồng thuận (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"201\">difficult to reach agreement</strong>) về việc năng khiếu có phải là bẩm sinh (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"271\">innate/born gifted</strong>) hay không.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">36. Einstein was upset by the public’s view of his life’s work. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 10):</strong> Tác giả trích dẫn lời Einstein nói về trí thông minh và tính cách của ông.</p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ nêu quan điểm của Einstein về bản thân ông, <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"68\">không có thông tin</strong> nào cho thấy ông cảm thấy \"khó chịu\" (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"125\">upset</strong>) trước quan điểm của công chúng về các công trình nghiên cứu của mình.</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">37. Einstein put his success down to the speed at which he dealt with scientific questions. — {NO}</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 10):</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"21\">\"He once wrote: ''It’s not that I’m so smart, it’s just that <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"81\">I stay with problems longer</strong>.''\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Einstein cho rằng thành công của ông là do ông ở lại với các vấn đề <strong data-path-to-node=\"13,1,0\" data-index-in-node=\"80\">lâu hơn</strong> (kiên trì), trái ngược hoàn toàn với ý nói thành công nhờ vào <strong data-path-to-node=\"13,1,0\" data-index-in-node=\"150\">tốc độ</strong> (speed) xử lý câu hỏi nhanh.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('28ecb25b-354e-4265-a4bb-b79aa69d21b2', '2ead78f1-f821-49d8-82fe-40276b10dfa0', 'checkbox', 'Questions 18–19', NULL, '<p>Which <strong>TWO</strong> of these effects are mentioned by the writer of the text?</p>
', 'multiple_choice_many', 'null', '[{"option": "A. They have damaged the tourism industry in some areas.", "correct": false}, {"option": "B. They have led to a reduction in the oceans'' oxygen levels.", "correct": false}, {"option": "C. They have contributed to the decline in the Black Sea anchovy population.", "correct": true}, {"option": "D. They have caused the shrimp business in the Gulf of Mexico to shut down.", "correct": false}, {"option": "E. They have created financial hardship in the fishing industry.", "correct": true}]', 'null', 'null', '[{"content": "<p><strong>18–19. Which TWO of these effects are mentioned by the writer of the text?</strong></p>\n<ul data-path-to-node=\"12\">\n<li><strong>Đáp án: C (They have contributed to the decline in the Black Sea anchovy population.) và E (They have created financial hardship in the fishing industry.)</strong></li>\n<li><strong>Dẫn chứng cho C:</strong> (Đoạn B) “…a huge number of jellyfish… <strong>devastated the Black Sea</strong>, an ecosystem already weakened by <strong>overfishing of anchovies</strong>.” (Sứa ăn trứng cá cơm).</li>\n<li><strong>Dẫn chứng cho E:</strong> (Đoạn F) “One result of large jellyfish populations is the <strong>economic effect it has had on the fishing industry</strong>. In the Gulf of Mexico, shrimp fishermen are struggling with a jellyfish boom that fills nets, causing them to break and resulting in <strong>millions of dollars in losses</strong>.” (Thiệt hại kinh tế/tài chính).</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('5ef44800-8682-4fe0-8c7c-3779a04688d1', 'cf5f9017-f5ed-4b5c-a9dd-3988ce66ce2f', 'fillup', 'Questions 1 - 7 ', '<p class="MsoNormal" style="margin: 0in 7.05pt 8.0pt 0in;"><span style="font-size: 11.0pt; font-family: ''Arial'',sans-serif;">Complete the notes below.</span></p>
<p class="MsoNormal" style="margin: 0in 7.05pt 8.0pt 0in;"><em><span style="font-size: 11.0pt; font-family: ''Arial'',sans-serif;">Choose <strong>ONE WORD ONLY</strong> from the passage for each answer.</span></em></p>
<p style="text-align: center;"><strong><span style="font-size: 14.0pt; font-family: ''Arial'',sans-serif;">Pest control</span></strong></p>
<p><span style="font-size: 11.0pt; font-family: ''Arial'',sans-serif;">Early 20th-century problems in Australia</span></p>
<p><span style="font-size: 11.0pt; font-family: ''Arial'',sans-serif;">•<span style="mso-tab-count: 1;">      </span>The larvae of a type of {beetle} were a serious pest in sugar cane fields.</span></p>
<p><span style="font-size: 11.0pt; font-family: ''Arial'',sans-serif;">•<span style="mso-tab-count: 1;">      </span>Its larvae ate the {roots}<span style="mso-spacerun: yes;">  </span>of the plant.</span></p>
<p><span style="font-size: 11.0pt; font-family: ''Arial'',sans-serif;">•<span style="mso-tab-count: 1;">      </span>Chemical pesticides were unsatisfactory because they were:</span></p>
<p><span style="font-size: 11.0pt; font-family: ''Arial'',sans-serif;">–<span style="mso-tab-count: 1;">        </span>poisonous</span></p>
<p><span style="font-size: 11.0pt; font-family: ''Arial'',sans-serif;">–<span style="mso-tab-count: 1;">        {expensive}</span></span></p>
<p><span style="font-size: 11.0pt; font-family: ''Arial'',sans-serif;">–<span style="mso-tab-count: 1;">        </span>difficult to remove from the ground</span></p>
<p><span style="font-size: 11.0pt; font-family: ''Arial'',sans-serif;">Experiences with biological pest control</span></p>
<p><span style="font-size: 11.0pt; font-family: ''Arial'',sans-serif;">•<span style="mso-tab-count: 1;">      </span>The use of insects, plants and birds was widespread.</span></p>
<p><span style="font-size: 11.0pt; font-family: ''Arial'',sans-serif;">•<span style="mso-tab-count: 1;">      </span>In the 19th century French {gardeners}<span style="mso-spacerun: yes;"> </span>used toads.</span></p>
<p><span style="font-size: 11.0pt; font-family: ''Arial'',sans-serif;">•<span style="mso-tab-count: 1;">      </span>In Australia a {moth}<span style="mso-spacerun: yes;">  </span>stopped the spread of prickly-pear cactus.</span></p>
<p><span style="font-size: 11.0pt; font-family: ''Arial'',sans-serif;">•<span style="mso-tab-count: 1;">      </span>Cane toads were brought to Australia from {Hawaii}</span></p>
<p><span style="font-size: 11.0pt; font-family: ''Arial'',sans-serif;">•<span style="mso-tab-count: 1;">      </span>Cane toads proved to be a {failure} as pest control.</span></p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p><strong>1. Đáp án: beetle</strong></p>\n<ul data-path-to-node=\"3\">\n<li><strong>Dẫn chứng:</strong> “This was a species of <strong>beetle</strong> whose larvae, the infant form of the beetle, live underground…”</li>\n<li><strong>Giải thích:</strong> Bài đọc xác định đối tượng gây hại chính ở các cánh đồng mía là một loài bọ cánh cứng (beetle). Ấu trùng của loài bọ này mới là tác nhân trực tiếp phá hoại cây trồng.</li>\n</ul>\n<p><strong>2. Đáp án: roots</strong></p>\n<ul data-path-to-node=\"5\">\n<li><strong>Dẫn chứng:</strong> “The sugar cane plants were weakened or died because their <strong>roots</strong> were eaten by the larvae.”</li>\n<li><strong>Giải thích:</strong> Ấu trùng của bọ cánh cứng sống trong đất và ăn phần rễ (roots) của cây mía, khiến cây bị yếu đi hoặc chết, gây thiệt hại kinh tế.</li>\n</ul>\n<p><strong>3. Đáp án: expensive</strong></p>\n<ul data-path-to-node=\"7\">\n<li><strong>Dẫn chứng:</strong> “Chemicals like arsenic and copper were used, but these were not only <strong>expensive</strong> but also stayed in the environment…”</li>\n<li><strong>Giải thích:</strong> Các hóa chất diệt khuẩn thời kỳ đầu không được ưa chuộng vì chúng vừa tốn kém (expensive), vừa có độc tính tồn tại lâu dài trong môi trường.</li>\n</ul>\n<p><strong>4. Đáp án: gardeners</strong></p>\n<ul data-path-to-node=\"9\">\n<li><strong>Dẫn chứng:</strong> “…in 19th-century France toads were sold to <strong>gardeners</strong> at markets in Paris to eat insect pests in their gardens.”</li>\n<li><strong>Giải thích:</strong> Tại Pháp vào thế kỷ 19, những người làm vườn (gardeners) là nhóm đối tượng sử dụng cóc như một phương pháp diệt côn trùng tự nhiên trong khu vườn của họ.</li>\n</ul>\n<p><strong>5. Đáp án: moth</strong></p>\n<ul data-path-to-node=\"11\">\n<li><strong>Dẫn chứng:</strong> “…prevention of the increase of the exotic prickly-pear cactus by the introduction of a <strong>moth</strong> from Argentina.”</li>\n<li><strong>Giải thích:</strong> Tác giả đưa ra ví dụ về sự thành công của kiểm soát sinh học tại Úc khi sử dụng một loài bướm đêm (moth) để tiêu diệt cây xương rồng lê gai xâm lấn.</li>\n</ul>\n<p><strong>6. Đáp án: Hawaii</strong></p>\n<ul data-path-to-node=\"13\">\n<li><strong>Dẫn chứng:</strong> “…an Australian entomologist brought 101 cane toads from <strong>Hawaii</strong> and released them…”</li>\n<li><strong>Giải thích:</strong> Hawaii là địa điểm cụ thể mà các nhà khoa học đã thu thập 101 con cóc mía đầu tiên để mang về thả tại các đồn điền phía Bắc nước Úc.</li>\n</ul>\n<p><strong>7. Đáp án: failure</strong></p>\n<ul data-path-to-node=\"15\">\n<li><strong>Dẫn chứng:</strong> “…over the following years it became clear that the cane toads were a <strong>failure</strong>.”</li>\n<li><strong>Giải thích:</strong> Kế hoạch sử dụng cóc mía đã được chứng minh là một thất bại (failure) vì cóc sống trên mặt đất không thể ăn được ấu trùng bọ cánh cứng vốn sống sâu dưới rễ cây.</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('d422cfc9-2516-4401-a49c-24cb5d152803', '2ead78f1-f821-49d8-82fe-40276b10dfa0', 'checkbox', 'Questions 20–21', NULL, '<p>Which <strong>TWO</strong> of the following are possible causes of an increase in jellyfish numbers?</p>
', 'multiple_choice_many', 'null', '[{"option": "A. a shortage of small fish in the oceans", "correct": true}, {"option": "B. the dumping of chemicals into the oceans", "correct": true}, {"option": "C. a decline in biodiversity in the oceans", "correct": false}, {"option": "D. more competition among other fish in the oceans", "correct": false}, {"option": "E. a decrease in seabird populations", "correct": false}]', 'null', 'null', '[{"content": "<p><strong>20–21. Which TWO of the following are possible causes of an increase in jellyfish numbers?</strong></p>\n<ul data-path-to-node=\"15\">\n<li><strong>Đáp án: A (a shortage of small fish in the oceans) và B (the dumping of chemicals into the oceans)</strong></li>\n<li><strong>Dẫn chứng cho A:</strong> (Đoạn D) “<strong>Overfishing has removed fish</strong> from marine ecosystems… small fish appear to keep jellyfish in check by predation (on jellyfish when they are very small) and competition (when feeding). So, <strong>once we remove fish, jellyfish can proliferate</strong>.” (Thiếu cá nhỏ do đánh bắt quá mức).</li>\n<li><strong>Dẫn chứng cho B:</strong> (Đoạn D) “<strong>Eutrophication</strong> is another human-caused change… largely caused by <strong>fertilizer and waste run-off</strong>.” (Phân bón và nước thải chứa hóa chất nitrogen và phosphorus).</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('8114770e-6fe7-42e3-b52c-97dd5442e546', 'e9d314af-fb75-4b3e-86bf-0d5ae2e618c0', 'matrix', 'Questions 23–26', NULL, '<p>Look at the following people and the list of statements below.<br />
Match each person with the correct statement, A–E.<br />
Choose the correct letter A–E in boxes.</p>
', 'other', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": null, "matrixItems": [{"itemText": "Megan Gunnar", "correctCategoryLetter": "B"}, {"itemText": "Jenny Anderson", "correctCategoryLetter": "A"}, {"itemText": "John Devaney", "correctCategoryLetter": "D"}, {"itemText": "Nadine Burke Harris", "correctCategoryLetter": "C"}], "matrixCategories": [{"categoryText": "Traumatic experiences in childhood might lead to poor self-management.", "categoryLetter": "A"}, {"categoryText": "Supportive and responsive relationships with caring parents can prevent or reverse the damaging effects of toxic stress responses.", "categoryLetter": "B"}, {"categoryText": "Properly naming a type of stress can facilitate its treatment process.", "categoryLetter": "C"}, {"categoryText": "The real name of a particular form of stress could denounce a number of people.", "categoryLetter": "D"}, {"categoryText": "Toxic stress can cause the next generations to suffer from negative consequences on both mental and physical health problems.", "categoryLetter": "E"}]}', '[{"content": "<p>10. B (Đoạn F, “As Megan Gunnar, …basically the parent eats the stress: the kid cries, the parent comes, and it doesn’t need to kick in the big biological guns because the parent is the protective system”.”)</p>\n<p>11. A (Đoạn D, “As Jenny Anderson, senior reporter at Quartz, explains, “when a child lives with abuse, neglect, or is witness to violence, he or she is primed for that fight or flight all the time.”)</p>\n<p>12. D (Đoạn E, “The term, writes John Devaney, centenary chair of social work at the University of Edinburgh, “can stigmatise individuals and imply traumatic happenings in the past”.”)</p>\n<p>13. C (Đoạn E, “But Nadine Burke Harris, surgeon general of California, argues that naming the problem means we can dedicate resources to it so that paediatricians feel like they have tools to treat “toxic stress”.”)</p>\n"}]', 2);
INSERT INTO public.questions VALUES ('f7d0223e-501e-4a91-bea5-6a121d3ef1f6', 'd7d01f0a-07af-463b-bef3-a9fa68f2ee8e', 'radio', 'Questions 21–24', NULL, '<p>Choose the correct letter, A, B or C.</p>
<p><span style="font-size: 12pt;"><strong>Forensic Linguistics</strong></span></p>
', 'multiple_choice_single', '[{"correct": 1, "options": [{"content": "A. The dictionary definition was not very useful."}, {"content": "B. They could provide an example of the kind of work involved."}, {"content": "C. They should read about the subject to see how it is described."}], "question": "What do the students agree about defining forensic linguistics?"}, {"correct": 0, "options": [{"content": "A. it is not of good quality."}, {"content": "B. the accent is difficult to understand."}, {"content": "C. she doesn’t know if the speaker is male or female."}], "question": "Jen thinks it will be difficult to analyse the voice recording because"}, {"correct": 1, "options": [{"content": "A. because they’re being recorded"}, {"content": "B. because they’ve been told to"}, {"content": "C. because they feel uncomfortable about their accent"}], "question": "Why does Jen think that the ‘suspect’ might vary their voice patterns?"}, {"correct": 0, "options": [{"content": "A. She worries too much about her ability."}, {"content": "B. She often ignores the most important issues."}, {"content": "C. She has trouble getting started."}], "question": "What does Rob think about Jen’s approach to study?"}]', 'null', 'null', 'null', '[{"content": "<p data-start=\"403\" data-end=\"625\"><strong data-start=\"403\" data-end=\"411\">ROB:</strong> Hi Jen.<br data-start=\"419\" data-end=\"422\" /><strong data-start=\"422\" data-end=\"430\">JEN:</strong> Hi Rob. We need to look at this project we’re doing together in forensic linguistics.<br data-start=\"516\" data-end=\"519\" />🎧 <em data-start=\"522\" data-end=\"533\">Chào Jen.</em><br data-start=\"533\" data-end=\"536\" /><em data-start=\"536\" data-end=\"625\">Chào Rob. Mình cần xem lại dự án môn Ngôn ngữ học pháp y mà hai đứa đang làm cùng nhau.</em></p>\n<hr data-start=\"627\" data-end=\"630\" />\n<p data-start=\"632\" data-end=\"775\"><strong data-start=\"632\" data-end=\"640\">ROB:</strong> Sure. The first thing we have to do is define forensic linguistics.<br data-start=\"708\" data-end=\"711\" />🎧 <em data-start=\"714\" data-end=\"775\">Ừ, việc đầu tiên là phải định nghĩa “forensic linguistics”.</em></p>\n<hr data-start=\"777\" data-end=\"780\" />\n<p data-start=\"782\" data-end=\"1086\"><strong data-start=\"782\" data-end=\"790\">JEN:</strong> I thought we could say something like, “Linguistics involves the analysis of language, and forensic refers to using scientific techniques to solve crimes.”<br data-start=\"946\" data-end=\"949\" />🎧 <em data-start=\"952\" data-end=\"1086\">Mình nghĩ ta có thể nói: Ngôn ngữ học là nghiên cứu và phân tích ngôn ngữ, còn “forensic” nghĩa là dùng kỹ thuật khoa học để phá án.</em></p>\n<hr data-start=\"1088\" data-end=\"1091\" />\n<p data-start=\"1093\" data-end=\"1404\"><strong data-start=\"1093\" data-end=\"1101\">ROB:</strong> So forensic linguistics involves analyzing people’s use of language to find out whether they’ve committed a crime. What do you think of that as a definition?<br data-start=\"1259\" data-end=\"1262\" />🎧 <em data-start=\"1265\" data-end=\"1404\">Vậy “forensic linguistics” là phân tích cách con người dùng ngôn ngữ để xác định xem họ có phạm tội không. Cậu thấy định nghĩa đó ổn chứ?</em></p>\n<hr data-start=\"1406\" data-end=\"1409\" />\n<p data-start=\"1411\" data-end=\"1818\"><strong data-start=\"1411\" data-end=\"1419\">JEN:</strong> Sounds OK. I looked it up in my dictionary and got something similar. Then, <strong data-start=\"1496\" data-end=\"1513\">(Question 21)</strong> we can add something about <strong data-start=\"1541\" data-end=\"1635\">what forensic linguists actually do — like analyzing documents to find out who wrote them.</strong><br data-start=\"1635\" data-end=\"1638\" />🎧 <em data-start=\"1641\" data-end=\"1797\">Nghe ổn đấy. Mình tra từ điển cũng thấy gần giống. Mình nên thêm ví dụ cụ thể về công việc họ làm — <strong data-start=\"1742\" data-end=\"1796\">như phân tích tài liệu để tìm ra ai là người viết.</strong></em><br data-start=\"1797\" data-end=\"1800\" />✅ <strong data-start=\"1802\" data-end=\"1818\">Answer 21: B</strong></p>\n<hr data-start=\"1820\" data-end=\"1823\" />\n<p data-start=\"1825\" data-end=\"1932\"><strong data-start=\"1825\" data-end=\"1833\">ROB:</strong> Good point. Let’s do that. What about the actual project?<br data-start=\"1891\" data-end=\"1894\" />🎧 <em data-start=\"1897\" data-end=\"1932\">Ý hay đó. Còn dự án thật thì sao?</em></p>\n<hr data-start=\"1934\" data-end=\"1937\" />\n<p data-start=\"1939\" data-end=\"2058\"><strong data-start=\"1939\" data-end=\"1947\">JEN:</strong> I’m glad we chose voice identification as the topic.<br data-start=\"2000\" data-end=\"2003\" />🎧 <em data-start=\"2006\" data-end=\"2058\">Mình mừng vì đã chọn chủ đề “nhận dạng giọng nói”.</em></p>\n<hr data-start=\"2060\" data-end=\"2063\" />\n<p data-start=\"2065\" data-end=\"2386\"><strong data-start=\"2065\" data-end=\"2073\">ROB:</strong> Yeah, we’ve been given a voice recording of a possible suspect — not a real one, of course. So we’ve got to listen to the recording and analyze their voice. Should be okay.<br data-start=\"2246\" data-end=\"2249\" />🎧 <em data-start=\"2252\" data-end=\"2386\">Đúng vậy, ta được giao một bản ghi âm của nghi phạm giả — tất nhiên không phải thật. Nhiệm vụ là nghe và phân tích giọng nói của họ.</em></p>\n<hr data-start=\"2388\" data-end=\"2391\" />\n<p data-start=\"2393\" data-end=\"2907\"><strong data-start=\"2393\" data-end=\"2401\">JEN:</strong> Well, I’ve already listened to the recording, and I can’t even tell if it’s a man or a woman. But I guess that doesn’t matter. The accent’s a local one though. I’m not sure how that will affect anything. Where we’re really going to get in trouble is that <strong data-start=\"2657\" data-end=\"2674\">(Question 22)</strong> the recording is very unclear.<br data-start=\"2705\" data-end=\"2708\" />🎧 <em data-start=\"2711\" data-end=\"2886\">Mình nghe rồi mà không biết đó là giọng nam hay nữ. Có lẽ điều đó không quan trọng, nhưng giọng có vẻ địa phương. Tuy nhiên vấn đề lớn là <strong data-start=\"2850\" data-end=\"2885\">âm thanh cực kỳ kém chất lượng.</strong></em><br data-start=\"2886\" data-end=\"2889\" />✅ <strong data-start=\"2891\" data-end=\"2907\">Answer 22: A</strong></p>\n<hr data-start=\"2909\" data-end=\"2912\" />\n<p data-start=\"2914\" data-end=\"3005\"><strong data-start=\"2914\" data-end=\"2922\">ROB:</strong> I’m sure they’ve done that to test us.<br data-start=\"2961\" data-end=\"2964\" />🎧 <em data-start=\"2967\" data-end=\"3005\">Chắc họ cố tình làm vậy để thử mình.</em></p>\n<hr data-start=\"3007\" data-end=\"3010\" />\n<p data-start=\"3012\" data-end=\"3315\"><strong data-start=\"3012\" data-end=\"3020\">JEN:</strong> Yeah, and then we have to interview the suspect and make our own recording — face to face — and decide if it’s the same person as on the original recording, right?<br data-start=\"3184\" data-end=\"3187\" />🎧 <em data-start=\"3190\" data-end=\"3315\">Đúng rồi, rồi mình còn phải phỏng vấn nghi phạm và tự ghi âm lại – đối mặt trực tiếp – để xem có phải cùng người hay không.</em></p>\n<hr data-start=\"3317\" data-end=\"3320\" />\n<p data-start=\"3322\" data-end=\"3812\"><strong data-start=\"3322\" data-end=\"3330\">ROB:</strong> Yes. It’s not an exact science, but it’s usually pretty accurate. You can often tell even when they’ve got a cold it’s the same person. But they might do something like <strong data-start=\"3500\" data-end=\"3517\">(Question 23)</strong> speaking with another accent because the tutor suggests they do that just to test us.<br data-start=\"3603\" data-end=\"3606\" />🎧 <em data-start=\"3609\" data-end=\"3791\">Đúng, tuy không chính xác tuyệt đối nhưng thường khá chuẩn. Dù người đó bị cảm, vẫn nhận ra được giọng. Nhưng đôi khi họ <strong data-start=\"3731\" data-end=\"3790\">sẽ cố đổi giọng vì giảng viên bảo thế, chỉ để thử mình.</strong></em><br data-start=\"3791\" data-end=\"3794\" />✅ <strong data-start=\"3796\" data-end=\"3812\">Answer 23: B</strong></p>\n<hr data-start=\"3814\" data-end=\"3817\" />\n<p data-start=\"3819\" data-end=\"4088\"><strong data-start=\"3819\" data-end=\"3827\">ROB:</strong> So let’s get on with it then. Oh, and don’t start your usual self-doubt about whether you can do the work or not. You usually do OK in the end.<br data-start=\"3971\" data-end=\"3974\" />🎧 <em data-start=\"3977\" data-end=\"4088\">Vậy thì bắt đầu làm thôi. Và đừng có tự nghi ngờ khả năng mình như mọi lần nữa. Cậu lúc nào cũng làm được mà.</em></p>\n<hr data-start=\"4090\" data-end=\"4093\" />\n<p data-start=\"4095\" data-end=\"4275\"><strong data-start=\"4095\" data-end=\"4103\">JEN:</strong> My problem is creating things to worry about before I’ve even started!<br data-start=\"4174\" data-end=\"4177\" />🎧 <em data-start=\"4180\" data-end=\"4254\">Vấn đề của tớ là lúc nào cũng tự nghĩ ra chuyện để lo trước khi bắt đầu!</em><br data-start=\"4254\" data-end=\"4257\" />✅ <strong data-start=\"4259\" data-end=\"4275\">Answer 24: A</strong></p>\n"}]', 0);
INSERT INTO public.questions VALUES ('4f458a9d-0476-4a0f-8bcb-1cdefa89caff', 'd7d01f0a-07af-463b-bef3-a9fa68f2ee8e', 'checkbox', 'Questions 25 and 26', NULL, '<p>Choose <strong>TWO </strong>letters, A–E.</p>
<p>Which <strong>TWO</strong> books do Jen and Rob decide to get from the library?</p>
', 'multiple_choice_many', 'null', '[{"option": "A. Voice Identification", "correct": false}, {"option": "B. Modern Forensic Techniques", "correct": true}, {"option": "C. Language and Crime", "correct": false}, {"option": "D. Forensics Today", "correct": false}, {"option": "E. Research Methods in Forensic Linguistics", "correct": true}]', 'null', 'null', '[{"content": "<p data-start=\"4282\" data-end=\"4475\"><strong data-start=\"4282\" data-end=\"4290\">ROB:</strong> We’ll have to do some background reading first. I’ll go to the library later and get what we need.<br data-start=\"4389\" data-end=\"4392\" />🎧 <em data-start=\"4395\" data-end=\"4475\">Trước tiên, ta cần đọc tài liệu nền. Tớ sẽ ra thư viện lấy vài cuốn cần thiết.</em></p>\n<hr data-start=\"4477\" data-end=\"4480\" />\n<p data-start=\"4482\" data-end=\"5414\"><strong data-start=\"4482\" data-end=\"4490\">JEN:</strong> I’ve already looked at <em data-start=\"4514\" data-end=\"4531\">Forensics Today</em> — it didn’t say much about voice identification, so we needn’t bother with that one. <em data-start=\"4617\" data-end=\"4637\">Language and Crime</em> looks a bit more promising, doesn’t it? I’ve got that out of the library already. So we don’t need to worry about borrowing that. <em data-start=\"4768\" data-end=\"4810\">Research Methods in Forensic Linguistics</em>, I guess we ought to borrow that. And <em data-start=\"4849\" data-end=\"4871\">Voice Identification</em> will be a useful one — I’ll borrow that from our classmate George. He won’t need it for his project. But we should get out <em data-start=\"4995\" data-end=\"5023\">Modern Forensic Techniques</em> — we need all the help we can get on that subject.<br data-start=\"5074\" data-end=\"5077\" />🎧 <em data-start=\"5080\" data-end=\"5383\">Tớ xem “Forensics Today” rồi, không có gì về nhận dạng giọng nói, nên khỏi mượn. “Language and Crime” có vẻ hay hơn, tớ đã mượn rồi. “Research Methods in Forensic Linguistics” thì nên mượn thêm. “Voice Identification” hữu ích, tớ mượn từ bạn George. Ngoài ra nên lấy thêm “Modern Forensic Techniques”.</em><br data-start=\"5383\" data-end=\"5386\" />✅ <strong data-start=\"5388\" data-end=\"5414\">Answers 25 &amp; 26: B + E</strong></p>\n<hr data-start=\"5416\" data-end=\"5419\" />\n<p data-start=\"5421\" data-end=\"5668\"><strong data-start=\"5421\" data-end=\"5429\">ROB:</strong> OK, that’s sorted out. Now onto the practical stuff — I’m not sure about how we’re going to record the voices. I’m not too good on the technical side of things.<br data-start=\"5590\" data-end=\"5593\" />🎧 <em data-start=\"5596\" data-end=\"5668\">Ổn rồi. Giờ đến phần thực hành — tớ không rành lắm về kỹ thuật ghi âm.</em></p>\n<hr data-start=\"5670\" data-end=\"5673\" />\n<p data-start=\"5675\" data-end=\"5931\"><strong data-start=\"5675\" data-end=\"5683\">JEN:</strong> Me neither. We’d better work out what we’re doing. At least we get more than one opportunity to speak to the person playing the suspect.<br data-start=\"5820\" data-end=\"5823\" />🎧 <em data-start=\"5826\" data-end=\"5929\">Tớ cũng vậy, chắc phải tính trước. Ít ra ta được nói chuyện với người đóng vai nghi phạm hơn một lần.</em></p>\n<hr data-start=\"5933\" data-end=\"5936\" />\n<p data-start=\"5938\" data-end=\"6052\"><strong data-start=\"5938\" data-end=\"5946\">ROB:</strong> I just hope whoever it is won’t make the task too tricky.<br data-start=\"6004\" data-end=\"6007\" />🎧 <em data-start=\"6010\" data-end=\"6052\">Chỉ mong người đó đừng làm khó quá thôi.</em></p>\n<hr data-start=\"6054\" data-end=\"6057\" />\n<p data-start=\"6059\" data-end=\"6287\"><strong data-start=\"6059\" data-end=\"6067\">JEN:</strong> I’m sure they won’t be too hard on us. And as long as we do our research properly, it shouldn’t be too hard to do the rest of it.<br data-start=\"6197\" data-end=\"6200\" />🎧 <em data-start=\"6203\" data-end=\"6287\">Chắc họ sẽ không quá khắt khe đâu. Chỉ cần mình nghiên cứu kỹ, phần còn lại sẽ ổn.</em></p>\n<hr data-start=\"6289\" data-end=\"6292\" />\n<p data-start=\"6294\" data-end=\"6488\"><strong data-start=\"6294\" data-end=\"6302\">ROB:</strong> I’m more worried about fitting in the writing up — I know we’ve got loads of other assignments to finish as well.<br data-start=\"6416\" data-end=\"6419\" />🎧 <em data-start=\"6422\" data-end=\"6488\">Tớ chỉ lo không kịp viết báo cáo vì còn nhiều bài khác phải làm.</em></p>\n<hr data-start=\"6490\" data-end=\"6493\" />\n<p data-start=\"6495\" data-end=\"6730\"><strong data-start=\"6495\" data-end=\"6503\">JEN:</strong> Now Rob, let’s decide how we’re going to split the writing between us. Are you any good at introductions? They always seem to let me down.<br data-start=\"6642\" data-end=\"6645\" />🎧 <em data-start=\"6648\" data-end=\"6730\">Giờ chia phần viết nhé Rob. Cậu viết phần mở đầu tốt chứ? Tớ làm phần đó dở lắm.</em></p>\n<hr data-start=\"6732\" data-end=\"6735\" />\n<p data-start=\"6737\" data-end=\"6941\"><strong data-start=\"6737\" data-end=\"6745\">ROB:</strong> OK, leave that to me. Are you OK to do the literature review then? Maybe we should split that part.<br data-start=\"6845\" data-end=\"6848\" />🎧 <em data-start=\"6851\" data-end=\"6941\">Được, phần mở đầu để tớ. Cậu làm phần tổng quan tài liệu nhé, có thể chia đôi cũng được.</em></p>\n<hr data-start=\"6943\" data-end=\"6946\" />\n<p data-start=\"6948\" data-end=\"7162\"><strong data-start=\"6948\" data-end=\"6956\">JEN:</strong> I don’t mind writing the methodology section if you feel comfortable doing the discussion and conclusions.<br data-start=\"7063\" data-end=\"7066\" />🎧 <em data-start=\"7069\" data-end=\"7162\">Tớ sẽ viết phần “Phương pháp nghiên cứu”, nếu cậu thấy ổn với phần “Thảo luận và kết luận”.</em></p>\n<hr data-start=\"7164\" data-end=\"7167\" />\n<p data-start=\"7169\" data-end=\"7368\"><strong data-start=\"7169\" data-end=\"7177\">ROB:</strong> OK, and we can do the analysis between us as well.<br data-start=\"7228\" data-end=\"7231\" />🎧 <em data-start=\"7234\" data-end=\"7281\">Được, phần phân tích thì cả hai cùng làm nhé.</em><br data-start=\"7281\" data-end=\"7284\" />✅ <strong data-start=\"7286\" data-end=\"7318\">Answers 29: C (Introduction)</strong><br data-start=\"7318\" data-end=\"7321\" />✅ <strong data-start=\"7323\" data-end=\"7366\">Answer 30: E (Discussion &amp; Conclusions)</strong></p>\n"}]', 1);
INSERT INTO public.questions VALUES ('86b8a47f-259e-4dad-8ff1-474c17f55d52', 'd7d01f0a-07af-463b-bef3-a9fa68f2ee8e', 'checkbox', 'Questions 27 and 28', NULL, '<p>Choose <strong>TWO</strong> letters, A–E.</p>
<p>Which <strong>TWO</strong> practical considerations are both Jen and Rob concerned about?</p>
', 'multiple_choice_many', 'null', '[{"option": "A. how much time they have for writing up the project", "correct": true}, {"option": "B. being able to do enough research", "correct": false}, {"option": "C. only speaking to the ‘suspect’ once", "correct": false}, {"option": "D. using recording equipment", "correct": true}, {"option": "E. how easy it will be to contact the ‘suspect’", "correct": false}]', 'null', 'null', '[{"content": "<p>1</p>\n"}]', 2);
INSERT INTO public.questions VALUES ('41916573-00be-415f-9bbf-be19f0e04242', '390674a8-0f9c-4184-b071-7e638ff6fffb', 'matrix', 'Questions 21-23', '', '<p>Match each statement with the correct economist, <strong data-path-to-node="4" data-index-in-node="49">A, B, C or D</strong>, in boxes 21-23 on your answer sheet.</p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": "List of Economists", "matrixItems": [{"itemText": "A traditional approach may have helped predict a financial downturn.", "correctCategoryLetter": "D"}, {"itemText": "Some people invest conservatively and as a result make less money.", "correctCategoryLetter": "A"}, {"itemText": "It may be possible to predict short-term movements in share prices but not over the long term.", "correctCategoryLetter": "C"}], "matrixCategories": [{"categoryText": "Fischer and Lorie", "categoryLetter": "A"}, {"categoryText": "Myron Scholes", "categoryLetter": "B"}, {"categoryText": "Eugene Fama", "categoryLetter": "C"}, {"categoryText": "Robert Shiller", "categoryLetter": "D"}]}', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">21. A traditional approach may have helped predict a financial downturn. — {D. Robert Shiller}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn F):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“To have seen the <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"38\">2008 global financial crisis coming [predict a financial downturn]</strong>, he [Robert Shiller] argues, it would have better to <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"158\">go back to old-fashioned readings of history, studying institutions and laws [traditional approach]</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Robert Shiller lập luận rằng để dự báo được cuộc khủng hoảng tài chính 2008 (financial downturn), chúng ta nên quay lại cách đọc lịch sử kiểu cũ (traditional/old-fashioned approach) thay vì chỉ nhìn vào dữ liệu máy tính khô khan.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">22. Some people invest conservatively and as a result make less money. — {A. Fischer and Lorie}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn C):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“<strong data-path-to-node=\"7,0,0\" data-index-in-node=\"21\">Fisher and Lorie</strong> also observed that many people chose to invest in assets with <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"100\">lower returns [make less money]</strong> because they were <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"150\">cautious by nature [invest conservatively]</strong>, and were concerned about the risk…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Hai ông nhận thấy nhiều người có bản tính thận trọng (cautious/conservative) nên chọn các kênh đầu tư có lợi nhuận thấp (lower returns/less money) để tránh rủi ro mất mát.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">23. It may be possible to predict short-term movements in share prices but not over the long term. — {C. Eugene Fama}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn E):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">“<strong data-path-to-node=\"9,0,0\" data-index-in-node=\"21\">Fama</strong> did concede that there was some evidence of <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"70\">temporary short-term predictability</strong> in share prices… [but] all relevant information is reflected in share prices at any given moment, meaning there are <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"224\">no predictable movements</strong>…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Eugene Fama thừa nhận có bằng chứng về việc có thể dự báo được giá trong ngắn hạn (short-term predictability), nhưng về cơ bản thị trường là hiệu quả và giá biến động ngẫu nhiên, không thể dự báo lâu dài.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('6dc40c60-cb3b-4229-a929-6d4d8770f378', '765f01d6-abb7-41b8-b35a-3b839543d5ef', 'fillup', 'Questions 24 - 26', '<p>Complete the sentences below.</p>
<p>Choose <strong>NO MORE THAN TWO WORDS</strong> from the passage.</p>
<p data-path-to-node="45,0,0">The dingo replaced the {Tasmanian tiger} as the main predatory animal in Australia.</p>
<p data-path-to-node="45,1,0"> Foxes and cats are more likely to hunt native animals when there are fewer {rabbits}.</p>
<p data-path-to-node="45,2,0">Australian animals reproduce at a slow rate as a natural way of avoiding {overpopulation}.</p>', '', 'short_answer', 'null', 'null', 'null', 'null', '[{"content": "<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">24. The dingo replaced the {Tasmanian tiger} as the main predatory animal in Australia.</strong></p>\n<ul data-path-to-node=\"7,0,1\">\n<li>\n<p data-path-to-node=\"7,0,1,0,0\"><strong data-path-to-node=\"7,0,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…as the <strong data-path-to-node=\"7,0,1,0,0\" data-index-in-node=\"22\">Tasmanian tiger</strong> disappeared completely from Australia, dingoes became Australia’s top predators.” (Đoạn B)</p>\n</li>\n<li>\n<p data-path-to-node=\"7,0,1,1,0\"><strong data-path-to-node=\"7,0,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Khi loài hổ Tasmania biến mất, dingo đã thế chỗ để trở thành loài săn mồi đầu bảng.</p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">25. Foxes and cats are more likely to hunt native animals when there are fewer {rabbits}.</strong></p>\n<ul data-path-to-node=\"7,1,1\">\n<li>\n<p data-path-to-node=\"7,1,1,0,0\"><strong data-path-to-node=\"7,1,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “When bad seasons follow, <strong data-path-to-node=\"7,1,1,0,0\" data-index-in-node=\"37\">rabbit numbers are significantly reduced</strong> – and the… fox and cat populations are left with <strong data-path-to-node=\"7,1,1,0,0\" data-index-in-node=\"129\">little to eat besides native mammals</strong>.” (Đoạn C)</p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,1,1,0\"><strong data-path-to-node=\"7,1,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Thỏ là nguồn thức ăn chính. Khi số lượng <strong data-path-to-node=\"7,1,1,1,0\" data-index-in-node=\"53\">thỏ (rabbits)</strong> giảm đi, cáo và mèo buộc phải quay sang săn các loài động vật bản địa để sinh tồn.</p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"7,2,0\"><strong data-path-to-node=\"7,2,0\" data-index-in-node=\"0\">26. Australian animals reproduce at a slow rate as a natural way of avoiding {overpopulation}.</strong></p>\n<ul data-path-to-node=\"7,2,1\">\n<li>\n<p data-path-to-node=\"7,2,1,0,0\"><strong data-path-to-node=\"7,2,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Australian mammals generally reproduce much more slowly… an adaption to <strong data-path-to-node=\"7,2,1,0,0\" data-index-in-node=\"86\">prevent overpopulation</strong> in the arid environment…” (Đoạn D)</p>\n</li>\n<li>\n<p data-path-to-node=\"7,2,1,1,0\"><strong data-path-to-node=\"7,2,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc sinh sản chậm là một cơ chế tự nhiên để tránh tình trạng <strong data-path-to-node=\"7,2,1,1,0\" data-index-in-node=\"74\">quá tải dân số (overpopulation)</strong> trong môi trường khắc nghiệt.</p>\n</li>\n</ul>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('a25c68dd-069b-4d24-a922-9a059b2196a6', 'c5510d0d-d693-46b0-bcfc-6a770e29343d', 'matching', 'Question 27-30', '', '<p>Write the correct letter, <strong>A</strong>-<strong>G</strong>, in boxes 27-30 on your answer sheet.</p>', 'matching_name', 'null', 'null', '{"layoutType": "standard", "summaryText": "", "answerOptions": [{"optionText": "planning for the future."}, {"optionText": "predicting their errors."}, {"optionText": "continuing in the present situation."}, {"optionText": "recent findings on the most effective solutions to problems."}, {"optionText": "achieving a gain."}, {"optionText": "changes occurring externally."}, {"optionText": "a high level of agreement."}], "matchingItems": [{"questionPart": "K. C. Cole points out that avoiding a loss seems more important to people than", "correctAnswer": "E"}, {"questionPart": "According to Andrew S. Grove, it can be very dangerous for companies to ignore", "correctAnswer": "F"}, {"questionPart": "Reid J. Lifset argues that environmental agencies can benefit from", "correctAnswer": "D"}, {"questionPart": "The writer suggests that government leaders need to focus more on", "correctAnswer": "A"}]}', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">27. Đáp án: achieving a gain</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> \"People will risk a lot to <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"38\">prevent a loss</strong>... But they will usually risk very little if the only perceived outcome is a <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"130\">possible gain</strong>.\"</p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả chỉ ra tâm lý con người coi trọng việc tránh mất mát (avoiding a loss) hơn là việc đạt được lợi ích (achieving a gain).</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">28. Đáp án: changes occurring externally</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> \"Such a period of <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"29\">change in the outside world</strong> is filled with danger... because it is so easy for executives to try to <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"129\">disregard it</strong>...\"</p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Theo Andrew S. Grove, các công ty thường gặp nguy hiểm khi phớt lờ (ignore) những thay đổi đang diễn ra bên ngoài (changes occurring externally/outside world).</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">29. Đáp án: recent findings on the most effective solutions to problems.<br></strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> \"Once these <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"23\">‘leverage points’</strong> as he calls them, are located, many environmental organizations will be <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"113\">willing to risk the resources</strong>...\"</p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Reid J. Lifset lập luận rằng các tổ chức môi trường sẽ hưởng lợi (benefit) khi xác định được các \"điểm đòn bẩy\" (identifying leverage points) để tối ưu hóa nguồn lực.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">30. Đáp án: planning for the future</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> \"...urgent needs of the present take precedence over <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"64\">actions that would give rise to even more substantial gains in the future</strong>. Better consideration... for <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"167\">what lies ahead</strong> is essential.\"</p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả gợi ý các nhà lãnh đạo chính phủ cần tập trung nhiều hơn vào việc lập kế hoạch cho tương lai (planning for the future/what lies ahead) thay vì chỉ quan tâm đến hiện tại.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('3780dcf0-4a48-4ca1-867d-2f67f00c0658', '9a8c54d0-fadf-4120-aba9-afd6f8ef67b7', 'matrix', 'Questions 37 – 40', '', '<p>Write the correct letter, <strong data-path-to-node="17" data-index-in-node="26">A-H</strong>, in boxes 37-40 on your answer sheet.</p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "simple", "matrixItems": [{"itemText": "the reason the original festival was banned", "correctCategoryLetter": "C"}, {"itemText": "some advice about dealing with the local people", "correctCategoryLetter": "E"}, {"itemText": "the possible origins of the Straw Bear Festival", "correctCategoryLetter": "B"}, {"itemText": "the views of enthusiasts from outside the area", "correctCategoryLetter": "D"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}, {"categoryText": "H", "categoryLetter": "H"}]}', '[{"content": "<p><strong data-path-to-node=\"4\" data-index-in-node=\"0\">37. the reason the original festival was banned — {C}</strong></p>\n<ul data-path-to-node=\"5\">\n<li><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"11\">“The custom <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"23\">died out in 1909</strong> after a local police inspector <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"71\">forbade it as a form of begging</strong>…”</em></li>\n<li><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Banned” (bị cấm) tương ứng với “forbade”. Lý do được đưa ra là cảnh sát coi việc nhảy múa quyên tiền của chú gấu là một hình thức ăn xin (begging).</li>\n</ul>\n<p><strong data-path-to-node=\"6\" data-index-in-node=\"0\">38. some advice about dealing with the local people — {E}</strong></p>\n<ul data-path-to-node=\"7\">\n<li><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"11\">“‘<strong data-path-to-node=\"7,0,0\" data-index-in-node=\"13\">One should not be pushy with people from the Fens</strong> as they have little time for opinionated fools,’ <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"112\">Brian Kell warns me</strong>…”</em></li>\n<li><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Advice” (lời khuyên) ở đây chính là lời cảnh báo (warns) của Brian Kell. Ông khuyên tác giả không nên quá lấn lướt hay thúc ép (not be pushy) khi tiếp xúc với người dân địa phương vùng Fens.</li>\n</ul>\n<p><strong data-path-to-node=\"8\" data-index-in-node=\"0\">39. the possible origins of the Straw Bear Festival — {B}</strong></p>\n<ul data-path-to-node=\"9\">\n<li><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"11\">“No one knows from what precise point in history the Straw Bear Festival started… some <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"100\">speculate that the tradition stretches back to pre-history</strong>.”</em></li>\n<li><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Origins” (nguồn gốc) tương ứng với thông tin về việc lễ hội bắt đầu từ khi nào (started). Vì không ai biết chính xác nên họ chỉ có thể suy đoán (speculate) là nó có từ thời tiền sử.</li>\n</ul>\n<p><strong data-path-to-node=\"10\" data-index-in-node=\"0\">40. the views of enthusiasts from outside the area — {D}</strong></p>\n<ul data-path-to-node=\"11\">\n<li><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"11\">“‘It’s just got that <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"32\">weird atmosphere</strong>,’ <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"51\">Dorothy, an insurance broker who has travelled from Liverpool</strong> to attend… ‘I like it, but I wouldn’t want to live here,’ <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"173\">adds her husband, Frank</strong>.”</em></li>\n<li><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Dorothy và Frank là những người đam mê (enthusiasts) đến từ nơi khác (Liverpool – outside the area). Họ chia sẻ quan điểm (views) của mình về bầu không khí kỳ lạ và đặc trưng của lễ hội.</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('c4bdfbeb-d237-4759-928b-da2258886624', '403f3e29-d07f-4f13-9366-e914f1ca4312', 'matrix', 'Questions 1-6', NULL, '<p>The Passage has 8 paragraphs<strong> A-H</strong>.</p>
<p>Which paragraph contains the following information?</p>
<p>Choose the appropriate letter, A-H, in boxes 1-6 on your answer sheet.</p>
', 'classification', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": null, "matrixItems": [{"itemText": "categorizations of fish by swimming speed", "correctCategoryLetter": "G"}, {"itemText": "an example of fish capable of maintaining fast swimming for a long time", "correctCategoryLetter": "H"}, {"itemText": "how fish control stability", "correctCategoryLetter": "E"}, {"itemText": "frequency of the muscle movement of fish", "correctCategoryLetter": "C"}, {"itemText": "a mechanical model of fish skeleton", "correctCategoryLetter": "B"}, {"itemText": "energy storage devices in a fish", "correctCategoryLetter": "D"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}, {"categoryText": "H", "categoryLetter": "H"}]}', '[{"content": "<p>1. Categorizations of fish by swimming speed → G<br />(Đoạn G: “&#8230;we can broadly categorise fish into four groups: ‘sneakers’&#8230; ‘stayers’&#8230; ‘sprinters’&#8230; and ‘crawlers’.”)<br />→ Đoạn này nói rõ cách phân loại cá dựa theo tốc độ bơi.<br />→ Đáp án: G</p>\n<p> <br />2. An example of fish capable of maintaining fast swimming for a long time → H<br />(Đoạn H: “&#8230;anglers have recorded speeds in excess of 40 mph over longer periods for several species of tuna.”)<br />→ Cá tuna (cá ngừ) được nêu là ví dụ về loài có thể duy trì tốc độ cao trong thời gian dài.<br />→ Đáp án: H</p>\n<p> <br />3. How fish control stability → E<br />(Đoạn E: “&#8230;Their main function is to control the stability and direction of the fish.”)<br />→ Đoạn này mô tả vai trò của vây trong việc giữ thăng bằng và định hướng cho cá.<br />→ Đáp án: E</p>\n<p> <br />4. Frequency of the muscle movement of fish → C<br />(Đoạn C: “&#8230;The frequency of the waves varies from about 50/min in the dogfish to 170/min in the mackerel.”)<br />→ Đề cập cụ thể đến tần suất chuyển động của cơ bắp cá.<br />→ Đáp án: C</p>\n<p> <br />5. A mechanical model of fish skeleton → B<br />(Đoạn B: “&#8230;The skull acts as a fulcrum and the vertebrae act as levers.”)<br />→ Đoạn này ví hộp sọ như điểm tựa (fulcrum) và các đốt sống như đòn bẩy (levers), tức mô hình cơ học của xương cá.<br />→ Đáp án: B</p>\n<p> <br />6. Energy storage devices in a fish → D<br />(Đoạn D: “&#8230;the red muscle receives a good supply of blood and contains ample quantities of fat and glycogen, the storage form of glucose&#8230;” )<br />→ Mô tả các mô cơ đỏ chứa chất béo và glycogen – nguồn dự trữ năng lượng của cá.<br />→ Đáp án: D</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('d1d250f7-739f-42a3-ba64-7a51ed7e48e8', 'cf5f9017-f5ed-4b5c-a9dd-3988ce66ce2f', 'radio', 'Questions 8 - 13 ', NULL, '<p>Choose <strong>TRUE </strong>if the statement agrees with the information .<strong>FALSE </strong>if the statement contradicts with the information. <strong>NOT GIVEN </strong>if there is no information on this</p>
', 'multiple_choice_single', '[{"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "The outcome of the introduction of cane toads was immediately obvious."}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Rabbits were introduced to Australia to control weeds. "}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Walter Froggatt was criticised for his efforts to stop the introduction of the cane toad to Australia. "}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "The average size of cane toads has increased since their introduction."}, {"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Australian animals can eat cane toads safely."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "In many places cane toads are gaining control of the habitats of Australian fauna."}]', 'null', 'null', 'null', '[{"content": "<p><strong>8. Đáp án: FALSE</strong></p>\n<ul data-path-to-node=\"19\">\n<li><strong>Dẫn chứng:</strong> “However, <strong>over the following years</strong> it became clear that the cane toads were a failure.”</li>\n<li><strong>Giải thích:</strong> Câu hỏi cho rằng kết quả thấy rõ ngay lập tức, nhưng thực tế bài viết nêu rõ phải mất nhiều năm sau đó (over the following years) thì sự thất bại của dự án mới bộc lộ.</li>\n</ul>\n<p><strong>9. Đáp án: NOT GIVEN</strong></p>\n<ul data-path-to-node=\"21\">\n<li><strong>Dẫn chứng:</strong> “He forecast that cane toads might become as great a pest in Australia as rabbits.”</li>\n<li><strong>Giải thích:</strong> Bài đọc có nhắc đến thỏ như một loài gây hại nghiêm trọng tại Úc để so sánh với cóc mía, nhưng không hề đề cập đến mục đích ban đầu đưa thỏ vào Úc là để “diệt cỏ dại” (control weeds).</li>\n</ul>\n<p><strong>10. Đáp án: TRUE</strong></p>\n<ul data-path-to-node=\"23\">\n<li><strong>Dẫn chứng:</strong> “However, Froggatt’s peers <strong>rebuked</strong> him and eminent scientists branded his views ‘decidedly pessimistic’.”</li>\n<li><strong>Giải thích:</strong> Walter Froggatt là người duy nhất công khai phản đối việc đưa cóc mía vào Úc, và kết quả là ông đã bị các đồng nghiệp chỉ trích (rebuked) và bị coi là có cái nhìn quá bi quan.</li>\n</ul>\n<p><strong>11. Đáp án: NOT GIVEN</strong></p>\n<ul data-path-to-node=\"25\">\n<li><strong>Dẫn chứng:</strong> “Average-sized adults are 10-15 cm long and weigh more than a kilo.”</li>\n<li><strong>Giải thích:</strong> Bài đọc chỉ mô tả kích thước hiện tại của cóc mía mà không cung cấp dữ liệu so sánh với kích thước của chúng trong quá khứ để xác định xem chúng có to lên hay không.</li>\n</ul>\n<p><strong>12. Đáp án: FALSE</strong></p>\n<ul data-path-to-node=\"27\">\n<li><strong>Dẫn chứng:</strong> “…freshwater crocodiles, goannas (large lizards) and dingoes (wild dogs) <strong>have died</strong> after eating cane toads.”</li>\n<li><strong>Giải thích:</strong> Thông tin trong bài khẳng định các loài động vật bản địa Úc đã chết sau khi ăn cóc mía do chất độc của chúng, trái ngược hoàn toàn với nhận định “có thể ăn một cách an toàn” trong câu hỏi.</li>\n</ul>\n<p><strong>13. Đáp án: TRUE</strong></p>\n<ul data-path-to-node=\"29\">\n<li><strong>Dẫn chứng:</strong> “As their numbers increase, they are <strong>taking over</strong> more and more of the land where native Australian fauna live.”</li>\n<li><strong>Giải thích:</strong> Việc cóc mía đang “chiếm lĩnh” (taking over) các vùng đất sinh sống của động vật bản địa đồng nghĩa với việc chúng đang dần kiểm soát môi trường sống của các loài này.</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('9f6d63e5-f9a4-4e4c-86a9-da79270663f6', '2ead78f1-f821-49d8-82fe-40276b10dfa0', 'fillup', 'Questions 22–26', '<p>Complete the sentences below.</p>
<p>Write <strong>ONE WORD ONLY</strong> from the passage for each answer.</p>
<p>Some fish in the oceans may be unable to sustain population as the jellyfish eat their {eggs}  .</p>
<p>The state of jellyfish becoming the main ocean species has been named {monoculture}   .</p>
<p>Increasing numbers of jellyfish can damage {nets} used for commercial fishing.</p>
<p>Understanding basic facts about jellyfish, such as the {temperature} of the ocean which suits them best, may help control their numbers.</p>
<p>Richardson believes it is better to direct attention to {prevention} , instead of just trying to solve existing problems.</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p><strong>22. Some fish in the oceans may be unable to sustain population as the jellyfish eat their eggs .</strong></p>\n<ul data-path-to-node=\"18\">\n<li><strong>Đáp án:</strong> <strong>eggs</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn B) “…Atlantic Ocean natives… devastated the Black Sea… feeding on anchovy <strong>eggs</strong> and the plankton that young fish rely on.” (Sứa ăn trứng cá cơm).</li>\n</ul>\n<p><strong>23. The state of jellyfish becoming the main ocean species has been named monoculture.</strong></p>\n<ul data-path-to-node=\"20\">\n<li><strong>Đáp án:</strong> <strong>monoculture</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn F) “This state has been defined as a <strong>‘monoculture of jellyfish’</strong>…”</li>\n</ul>\n<p><strong>24. Increasing numbers of jellyfish can damage nets used for commercial fishing.</strong></p>\n<ul data-path-to-node=\"22\">\n<li><strong>Đáp án:</strong> <strong>nets</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn F) “…shrimp fishermen are struggling with a jellyfish boom that fills <strong>nets</strong>, causing them to break…”</li>\n</ul>\n<p><strong>25. Understanding basic facts about jellyfish, such as the temperature of the ocean which suits them best, may help control their numbers.</strong></p>\n<ul data-path-to-node=\"24\">\n<li><strong>Đáp án:</strong> <strong>temperature</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn G) “Experts say that a greater understanding of jellyfish, including their ideal water <strong>temperature</strong> and feeding habits, is necessary…”</li>\n</ul>\n<p><strong>26. Richardson believes it is better to direct attention to prevention, instead of just trying to solve existing problems.</strong></p>\n<ul data-path-to-node=\"26\">\n<li><strong>Đáp án:</strong> <strong>prevention</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn G) “Due to the difficulty of turning ecosystems around… Richardson and his colleagues propose focusing on <strong>‘prevention’</strong> rather than cure.”</li>\n</ul>\n"}]', 3);
INSERT INTO public.questions VALUES ('4ffa7e08-9018-4f5c-aec9-1afa4040bfcd', '05e1487f-d046-4b33-8ac5-23ffb9dfb4c4', 'fillup', 'Questions 30-40', '<p>Write <strong>ONE WORD ONLY</strong> for each answer.</p>
<p><span style="font-size: 12pt;"><strong>Geography – 331 Field Trip</strong></span></p>
<p><strong>The James Bay Road</strong></p>
<p>– At the starting point of the road, everyone must stop for {registration}.</p>
<p>– For safety reasons, there are {telephones}  on the highway.</p>
<p><strong>Radisson Research Centre</strong></p>
<p>– The Centre works with other institutes to research the region’s {ecology}.</p>
<p>– Security is the responsibility of Hydro Quebec.</p>
<p>– Lectures will discuss the effect of {insects} on the land.</p>
<p>– Outpost stations gather and publish research related to variations in the {climate}.</p>
<p><strong>The Trans-Taiga Road</strong></p>
<p>– The road is unpaved.</p>
<p>– Breakdowns are serious as car {repairs} are expensive.</p>
<p>– At hydro stations, engineers will discuss hydro production and the impact of rainfall.</p>
<p><strong>The Taiga</strong></p>
<p>– There are not many types of {plant} , but a good range of wildlife.</p>
<p>– The area known as Muskeg is dangerous as it has hidden {pools}.</p>
<p>– Photographs of birds should be taken for future {documentation}.</p>
<p>– Water samples will be checked for {pollution}.</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong>Narrator:</strong> You will hear a geography professor telling his class about an upcoming field trip to the far North of Quebec in Canada. First you have some time to look at questions thirty-one to forty. Now listen carefully and answer questions thirty-one to forty.</p>\n<p data-path-to-node=\"4\"><strong>Professor:</strong> Good morning. Next week is the Geography 331 field trip to the far North of Quebec. Today I’ll discuss your trip and your tasks. As you know you will be close to the Arctic Circle. You’re going to travel up the James Bay Road through a region that is very remote and uninhabited yet very beautiful.</p>\n<h3>The James Bay Road</h3>\n<p data-path-to-node=\"7\"><strong>Professor:</strong> The highway is six hundred and twenty kilometers long, but it’s fully paved for the entire length. Where the highway begins, there is a roadside office where you must stop. The road is remote, so your <span style=\"background-color: #f1c40f;\"><strong>(31) registration</strong> </span>is very important in case of an emergency.The office is staffed 24 hours per day, seven days per week. You have to sign in to go up the road and sign out upon your return. For additional safety, at different places along the highway,<span style=\"background-color: #f1c40f;\"> <strong>(32) telephones</strong> </span>have been installed, which connect with staff in the office. Remember there is no mobile service in this remote area.</p>\n<h3>Radisson Research Centre</h3>\n<p data-path-to-node=\"10\"><strong>Professor:</strong> The first work of your field trip is at the end of the James Bay Road in Radisson, a small town of only 300 inhabitants.You will stay at Radisson Research Centre, which works with various universities and Hydro Quebec to carry out studies into the<span style=\"background-color: #f1c40f;\"> </span><strong><span style=\"background-color: #f1c40f;\">(33) ecology</span> </strong>of the region.Because the research center and the road exist as a result of the development of hydroelectricity complexes in northern Quebec, Hydro Quebec is responsible for all emergency assistance and security of all visitors. Your first few days at the centre will be spent attending lectures about their past research. You will hear that they have paid particular attention to any disturbance to the land caused by <span style=\"background-color: #f1c40f;\"><strong>(34) insects</strong></span>. After that you will visit the various outpost stations.There are three of them, and when you visit them,you will be able to observe how data on the varying patterns of the <span style=\"background-color: #f1c40f;\"><strong>(35) climate</strong></span> is collected and published for scientific research.</p>\n<h3>The Trans-Taiga Road</h3>\n<p data-path-to-node=\"13\"><strong>Professor:</strong> The second part of your field trip is back down the James Bay Road to the Trans-Taiga Road, which is the northernmost continuous unpaved road in eastern North America. In fact, it’s very uneven gravel, so drivers have to be very careful.Hydro Quebec cautions that driving over rocks on the rough road may cause severe damage to the car. Any breakdown is serious as car <span style=\"background-color: #f1c40f;\"><strong>(36) repairs</strong></span> are costly.Along the way, you will be stopping at two hydroelectric generating stations, each on a different river. There you will meet with engineers who will explain and demonstrate how rainfall has an impact on producing electric energy.</p>\n<h3>The Taiga</h3>\n<p data-path-to-node=\"16\"><strong>Professor:</strong> Your last two days of the trip will be spent camping out in the Taiga on the Canadian Shield.Taiga is the Russian term for a type of forest. You’ll find the region is relatively poor in the number of <span style=\"background-color: #f1c40f;\"><strong>(37) plant</strong></span> species, yet there is a great variety of wildlife that can be seen. You’ll go to an area that once had forest fires, and you’ll see how the landscape has naturally small rocky hills which confine the lower wetlands.These low lying areas are called muskeg, which is made up of slowly decomposing plants. It is not safe to walk on it as it has <strong><span style=\"background-color: #f1c40f;\">(38) pools</span> </strong>hidden that are not easily seen, so keep to the rocks<strong>.</strong>. The muskeg is home to many small birds and waterfowl; in fact, there are at least 60 varieties, so keep your waterproof digital cameras handy so you can take plenty of pictures. Then we will have <span style=\"background-color: #f1c40f;\"><strong>(39) documentation</strong></span> of the existing waterfowl as some are becoming extinct. Water is a problem in this area, so you’ll also be collecting test tubes of water to bring back to our research lab for analysis. It needs to be monitored for <span style=\"background-color: #f1c40f;\"><strong>(40) pollution</strong></span>.that may be caused by rainfall coming from the south.</p>\n<p data-path-to-node=\"18\"><strong>Narrator:</strong> That is the end of Part Four. You now have one minute to check your answers to Part Four.</p>\n<p data-path-to-node=\"18\"> </p>\n<p data-path-to-node=\"18\">——————————–</p>\n<p data-path-to-node=\"18\"><strong>Bản dịch Song ngữ: Chuyến thực địa Bắc Quebec</strong></p>\n<table style=\"border-collapse: collapse; border: 2px solid #000000;\" border=\"1\" data-path-to-node=\"2\">\n<thead>\n<tr>\n<td style=\"border-width: 2px; border-color: #000000;\">\n<p><strong>Tiếng Anh (English)</strong></p>\n</td>\n<td style=\"border-width: 2px; border-color: #000000;\">\n<p><strong>Tiếng Việt (Vietnamese)</strong></p>\n</td>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td style=\"border-width: 2px; border-color: #000000;\">\n<p><span data-path-to-node=\"2,2,0,0\"><strong data-path-to-node=\"2,2,0,0\" data-index-in-node=\"0\">Professor:</strong> Good morning. Next week is the Geography 331 field trip to the far North of Quebec. Today I’ll discuss your trip and your tasks.</span></p>\n</td>\n<td style=\"border-width: 2px; border-color: #000000;\">\n<p><span data-path-to-node=\"2,2,1,0\"><strong data-path-to-node=\"2,2,1,0\" data-index-in-node=\"0\">Giáo sư:</strong> Chào buổi sáng. Tuần tới là chuyến đi thực địa của môn Địa lý 331 đến vùng cực Bắc Quebec. Hôm nay tôi sẽ thảo luận về chuyến đi và các nhiệm vụ của các em.</span></p>\n</td>\n</tr>\n<tr>\n<td style=\"border-width: 2px; border-color: #000000;\">\n<p><span data-path-to-node=\"2,3,0,0\">As you know you will be close to the Arctic Circle. You’re going to travel up the James Bay Road through a region that is very remote and uninhabited yet very beautiful.</span></p>\n</td>\n<td style=\"border-width: 2px; border-color: #000000;\">\n<p><span data-path-to-node=\"2,3,1,0\">Như các em đã biết, chúng ta sẽ ở gần Vòng Cực Bắc. Các em sẽ di chuyển dọc theo con đường James Bay xuyên qua một khu vực rất hẻo lánh, không có người ở nhưng lại cực kỳ tươi đẹp.</span></p>\n</td>\n</tr>\n<tr>\n<td style=\"border-width: 2px; border-color: #000000;\">\n<p><span data-path-to-node=\"2,4,0,0\">—</span></p>\n</td>\n<td style=\"border-width: 2px; border-color: #000000;\">\n<p><span data-path-to-node=\"2,4,1,0\">—</span></p>\n</td>\n</tr>\n<tr>\n<td style=\"border-width: 2px; border-color: #000000;\">\n<p><span data-path-to-node=\"2,5,0,0\"><strong data-path-to-node=\"2,5,0,0\" data-index-in-node=\"0\">The James Bay Road</strong></span></p>\n</td>\n<td style=\"border-width: 2px; border-color: #000000;\">\n<p><span data-path-to-node=\"2,5,1,0\"><strong data-path-to-node=\"2,5,1,0\" data-index-in-node=\"0\">Tuyến đường James Bay</strong></span></p>\n</td>\n</tr>\n<tr>\n<td style=\"border-width: 2px; border-color: #000000;\">\n<p><span data-path-to-node=\"2,6,0,0\">The highway is 620 kilometers long, but it’s fully paved for the entire length. Where the highway begins, there is a roadside office where you must stop.</span></p>\n</td>\n<td style=\"border-width: 2px; border-color: #000000;\">\n<p><span data-path-to-node=\"2,6,1,0\">Xa lộ này dài 620 km, nhưng toàn bộ chiều dài đều đã được trải nhựa. Tại điểm bắt đầu của xa lộ, có một văn phòng bên đường mà các em bắt buộc phải dừng lại.</span></p>\n</td>\n</tr>\n<tr>\n<td style=\"border-width: 2px; border-color: #000000;\">\n<p><span data-path-to-node=\"2,7,0,0\">The road is remote, so your <strong data-path-to-node=\"2,7,0,0\" data-index-in-node=\"28\">(31) registration</strong> is very important in case of an emergency. The office is staffed 24 hours per day, 7 days per week.</span></p>\n</td>\n<td style=\"border-width: 2px; border-color: #000000;\">\n<p><span data-path-to-node=\"2,7,1,0\">Con đường này rất hẻo lánh, vì vậy việc <strong data-path-to-node=\"2,7,1,0\" data-index-in-node=\"40\">(31) đăng ký</strong> của các em là rất quan trọng trong trường hợp khẩn cấp. Văn phòng luôn có nhân viên trực 24/7.</span></p>\n</td>\n</tr>\n<tr>\n<td style=\"border-width: 2px; border-color: #000000;\">\n<p><span data-path-to-node=\"2,8,0,0\">You have to sign in to go up the road and sign out upon your return. For additional safety, at different places along the highway, <strong data-path-to-node=\"2,8,0,0\" data-index-in-node=\"131\">(32) telephones</strong> have been installed, which connect with staff in the office. Remember there is no mobile service in this remote area.</span></p>\n</td>\n<td style=\"border-width: 2px; border-color: #000000;\">\n<p><span data-path-to-node=\"2,8,1,0\">Các em phải ký tên khi đi vào và ký tên xác nhận khi trở về. Để tăng cường an toàn, tại các địa điểm khác nhau dọc theo xa lộ, các <strong data-path-to-node=\"2,8,1,0\" data-index-in-node=\"131\">(32) điện thoại</strong> đã được lắp đặt để kết nối với nhân viên văn phòng. Hãy nhớ rằng không có sóng điện thoại di động ở khu vực hẻo lánh này.</span></p>\n</td>\n</tr>\n<tr>\n<td style=\"border-width: 2px; border-color: #000000;\">\n<p><span data-path-to-node=\"2,9,0,0\">—</span></p>\n</td>\n<td style=\"border-width: 2px; border-color: #000000;\">\n<p><span data-path-to-node=\"2,9,1,0\">—</span></p>\n</td>\n</tr>\n<tr>\n<td style=\"border-width: 2px; border-color: #000000;\">\n<p><span data-path-to-node=\"2,10,0,0\"><strong data-path-to-node=\"2,10,0,0\" data-index-in-node=\"0\">Radisson Research Centre</strong></span></p>\n</td>\n<td style=\"border-width: 2px; border-color: #000000;\">\n<p><span data-path-to-node=\"2,10,1,0\"><strong data-path-to-node=\"2,10,1,0\" data-index-in-node=\"0\">Trung tâm Nghiên cứu Radisson</strong></span></p>\n</td>\n</tr>\n<tr>\n<td style=\"border-width: 2px; border-color: #000000;\">\n<p><span data-path-to-node=\"2,11,0,0\">The first work of your field trip is at the end of the James Bay Road in Radisson, a small town of only 300 inhabitants.</span></p>\n</td>\n<td style=\"border-width: 2px; border-color: #000000;\">\n<p><span data-path-to-node=\"2,11,1,0\">Công việc đầu tiên của chuyến thực địa là ở cuối đường James Bay, tại Radisson, một thị trấn nhỏ chỉ có 300 dân.</span></p>\n</td>\n</tr>\n<tr>\n<td style=\"border-width: 2px; border-color: #000000;\">\n<p><span data-path-to-node=\"2,12,0,0\">You will stay at Radisson Research Centre, which works with various universities and Hydro Quebec to carry out studies into the <strong data-path-to-node=\"2,12,0,0\" data-index-in-node=\"128\">(33) ecology</strong> of the region.</span></p>\n</td>\n<td style=\"border-width: 2px; border-color: #000000;\">\n<p><span data-path-to-node=\"2,12,1,0\">Các em sẽ lưu trú tại Trung tâm Nghiên cứu Radisson, nơi hợp tác với nhiều trường đại học và cơ quan Thủy điện Quebec để thực hiện các nghiên cứu về <strong data-path-to-node=\"2,12,1,0\" data-index-in-node=\"149\">(33) hệ sinh thái</strong> của vùng.</span></p>\n</td>\n</tr>\n<tr>\n<td style=\"border-width: 2px; border-color: #000000;\">\n<p><span data-path-to-node=\"2,13,0,0\"><span class=\"citation-365 citation-end-365\">Because the research center and the road exist as a result of the development of hydroelectricity complexes in northern Quebec, Hydro Quebec is responsible for all emergency assistance and security of a<sup class=\"superscript\" data-turn-source-index=\"3\"><!----></sup></span>ll visitors.</span></p>\n</td>\n<td style=\"border-width: 2px; border-color: #000000;\">\n<p><span data-path-to-node=\"2,13,1,0\">Vì trung tâm nghiên cứu và con đường này tồn tại là kết quả của việc phát triển các tổ hợp thủy điện ở miền bắc Quebec, nên Thủy điện Quebec chịu trách nhiệm hỗ trợ khẩn cấp và an ninh cho tất cả du khách.</span></p>\n</td>\n</tr>\n<tr>\n<td style=\"border-width: 2px; border-color: #000000;\">\n<p><span data-path-to-node=\"2,14,0,0\">Your first few days at the centre will be spent attending lectures about their past research. You will hear that they have paid particular attention to any disturbance to the land caused by <strong data-path-to-node=\"2,14,0,0\" data-index-in-node=\"190\">(34) insects</strong>.</span></p>\n</td>\n<td style=\"border-width: 2px; border-color: #000000;\">\n<p><span data-path-to-node=\"2,14,1,0\">Những ngày đầu tiên tại trung tâm sẽ được dành để tham dự các bài giảng về các nghiên cứu trước đây. Các em sẽ được nghe rằng họ đặc biệt chú ý đến bất kỳ sự xáo trộn nào đối với vùng đất này do <strong data-path-to-node=\"2,14,1,0\" data-index-in-node=\"195\">(34) côn trùng</strong> gây ra.</span></p>\n</td>\n</tr>\n<tr>\n<td style=\"border-width: 2px; border-color: #000000;\">\n<p><span data-path-to-node=\"2,15,0,0\">After that you will visit the various outpost stations. There are three of them, and when you visit them, you will be able to observe how data on the varying patterns of the <strong data-path-to-node=\"2,15,0,0\" data-index-in-node=\"174\">(35) climate</strong> is collected and published for scientific research.</span></p>\n</td>\n<td style=\"border-width: 2px; border-color: #000000;\">\n<p><span data-path-to-node=\"2,15,1,0\">sau đó, các em sẽ đi thăm các trạm tiền tiêu khác nhau. Có tất cả ba trạm, và khi đến đó, các em sẽ được quan sát cách dữ liệu về các kiểu thay đổi của <strong data-path-to-node=\"2,15,1,0\" data-index-in-node=\"152\">(35) khí hậu</strong> được thu thập và công bố cho nghiên cứu khoa học.</span></p>\n</td>\n</tr>\n<tr>\n<td style=\"border-width: 2px; border-color: #000000;\">\n<p><span data-path-to-node=\"2,16,0,0\">—</span></p>\n</td>\n<td style=\"border-width: 2px; border-color: #000000;\">\n<p><span data-path-to-node=\"2,16,1,0\">—</span></p>\n</td>\n</tr>\n<tr>\n<td style=\"border-width: 2px; border-color: #000000;\">\n<p><span data-path-to-node=\"2,17,0,0\"><strong data-path-to-node=\"2,17,0,0\" data-index-in-node=\"0\">The Trans-Taiga Road</strong></span></p>\n</td>\n<td style=\"border-width: 2px; border-color: #000000;\">\n<p><span data-path-to-node=\"2,17,1,0\"><strong data-path-to-node=\"2,17,1,0\" data-index-in-node=\"0\">Tuyến đường Trans-Taiga</strong></span></p>\n</td>\n</tr>\n<tr>\n<td style=\"border-width: 2px; border-color: #000000;\">\n<p><span data-path-to-node=\"2,18,0,0\">The second part of your field trip is back down the James Bay Road to the Trans-Taiga Road, which is the northernmost continuous unpaved road in eastern North America.</span></p>\n</td>\n<td style=\"border-width: 2px; border-color: #000000;\">\n<p><span data-path-to-node=\"2,18,1,0\">Phần thứ hai của chuyến đi là quay trở lại đường James Bay để đến đường Trans-Taiga, đây là con đường không trải nhựa liên tục nằm xa nhất về phía bắc ở miền đông Bắc Mỹ.</span></p>\n</td>\n</tr>\n<tr>\n<td style=\"border-width: 2px; border-color: #000000;\">\n<p><span data-path-to-node=\"2,19,0,0\">In fact, it’s very uneven gravel, so drivers have to be very careful. Hydro Quebec cautions that driving over rocks on the rough road may cause severe damage to the car.</span></p>\n</td>\n<td style=\"border-width: 2px; border-color: #000000;\">\n<p><span data-path-to-node=\"2,19,1,0\">Thực tế, đó là đường sỏi rất gồ ghề, vì vậy tài xế phải cực kỳ cẩn thận. Thủy điện Quebec cảnh báo rằng việc lái xe qua đá trên con đường thô ráp này có thể gây hư hỏng nặng cho xe.</span></p>\n</td>\n</tr>\n<tr>\n<td style=\"border-width: 2px; border-color: #000000;\">\n<p><span data-path-to-node=\"2,20,0,0\">Any breakdown is serious as car <strong data-path-to-node=\"2,20,0,0\" data-index-in-node=\"32\">(36) repairs</strong> are costly. Along the way, you will be stopping at two hydroelectric generating stations, each on a different river.</span></p>\n</td>\n<td style=\"border-width: 2px; border-color: #000000;\">\n<p><span data-path-to-node=\"2,20,1,0\">Bất kỳ sự cố hỏng hóc nào cũng đều nghiêm trọng vì việc <strong data-path-to-node=\"2,20,1,0\" data-index-in-node=\"56\">(36) sửa chữa</strong> xe rất tốn kém. Trên đường đi, chúng ta sẽ dừng lại ở hai trạm phát điện thủy điện, mỗi trạm nằm trên một con sông khác nhau.</span></p>\n</td>\n</tr>\n<tr>\n<td style=\"border-width: 2px; border-color: #000000;\">\n<p><span data-path-to-node=\"2,21,0,0\">There you will meet with engineers who will explain and demonstrate how rainfall has an impact on producing electric energy.</span></p>\n</td>\n<td style=\"border-width: 2px; border-color: #000000;\">\n<p><span data-path-to-node=\"2,21,1,0\">Tại đó, các em sẽ gặp gỡ các kỹ sư, những người sẽ giải thích và trình bày cách lượng mưa có tác động đến việc sản xuất năng lượng điện.</span></p>\n</td>\n</tr>\n<tr>\n<td style=\"border-width: 2px; border-color: #000000;\">\n<p><span data-path-to-node=\"2,22,0,0\">—</span></p>\n</td>\n<td style=\"border-width: 2px; border-color: #000000;\">\n<p><span data-path-to-node=\"2,22,1,0\">—</span></p>\n</td>\n</tr>\n<tr>\n<td style=\"border-width: 2px; border-color: #000000;\">\n<p><span data-path-to-node=\"2,23,0,0\"><strong data-path-to-node=\"2,23,0,0\" data-index-in-node=\"0\">The Taiga</strong></span></p>\n</td>\n<td style=\"border-width: 2px; border-color: #000000;\">\n<p><span data-path-to-node=\"2,23,1,0\"><strong data-path-to-node=\"2,23,1,0\" data-index-in-node=\"0\">Rừng Taiga</strong></span></p>\n</td>\n</tr>\n<tr>\n<td style=\"border-width: 2px; border-color: #000000;\">\n<p><span data-path-to-node=\"2,24,0,0\">Your last two days of the trip will be spent camping out in the Taiga on the Canadian Shield. Taiga is the Russian term for a type of forest.</span></p>\n</td>\n<td style=\"border-width: 2px; border-color: #000000;\">\n<p><span data-path-to-node=\"2,24,1,0\">Hai ngày cuối cùng của chuyến đi sẽ được dành để cắm trại ở vùng Taiga trên nền Canadian Shield. Taiga là thuật ngữ tiếng Nga để chỉ một loại rừng phương Bắc.</span></p>\n</td>\n</tr>\n<tr>\n<td style=\"border-width: 2px; border-color: #000000;\">\n<p><span data-path-to-node=\"2,25,0,0\">You’ll find the region is relatively poor in the number of <strong data-path-to-node=\"2,25,0,0\" data-index-in-node=\"59\">(37) plant species</strong>, yet there is a great variety of wildlife that can be seen.</span></p>\n</td>\n<td style=\"border-width: 2px; border-color: #000000;\">\n<p><span data-path-to-node=\"2,25,1,0\">Các em sẽ thấy khu vực này tương đối nghèo nàn về số lượng <strong data-path-to-node=\"2,25,1,0\" data-index-in-node=\"59\">(37) các loài thực vật</strong>, tuy nhiên lại có sự đa dạng lớn về động vật hoang dã có thể quan sát được.</span></p>\n</td>\n</tr>\n<tr>\n<td style=\"border-width: 2px; border-color: #000000;\">\n<p><span data-path-to-node=\"2,26,0,0\">You’ll go to an area that once had forest fires, and you’ll see how the landscape has naturally small rocky hills which confine the lower wetlands.</span></p>\n</td>\n<td style=\"border-width: 2px; border-color: #000000;\">\n<p><span data-path-to-node=\"2,26,1,0\">Các em sẽ đến một khu vực từng xảy ra cháy rừng, và thấy cảnh quan có những ngọn đồi đá nhỏ tự nhiên bao quanh các vùng đất ngập nước thấp hơn.</span></p>\n</td>\n</tr>\n<tr>\n<td style=\"border-width: 2px; border-color: #000000;\">\n<p><span data-path-to-node=\"2,27,0,0\">These low lying areas are called muskeg, which is made up of slowly decomposing plants. It is not safe to walk on it as it has <strong data-path-to-node=\"2,27,0,0\" data-index-in-node=\"127\">(38) pools</strong> hidden that are not easily seen, so keep to the rocks.</span></p>\n</td>\n<td style=\"border-width: 2px; border-color: #000000;\">\n<p><span data-path-to-node=\"2,27,1,0\">Những khu vực trũng thấp này được gọi là muskeg (đầm lầy than bùn), được hình thành từ thực vật phân hủy chậm. Đi bộ trên đó không an toàn vì có những <strong data-path-to-node=\"2,27,1,0\" data-index-in-node=\"151\">(38) vũng nước</strong> ẩn khuất khó thấy, vì vậy hãy bám sát các mỏm đá.</span></p>\n</td>\n</tr>\n<tr>\n<td style=\"border-width: 2px; border-color: #000000;\">\n<p><span data-path-to-node=\"2,28,0,0\">The muskeg is home to many small birds and waterfowl; in fact, there are at least 60 varieties, so keep your waterproof digital cameras handy so you can take plenty of pictures.</span></p>\n</td>\n<td style=\"border-width: 2px; border-color: #000000;\">\n<p><span data-path-to-node=\"2,28,1,0\">Muskeg là nơi sinh sống của nhiều loài chim nhỏ và chim nước; thực tế có ít nhất 60 loại, vì vậy hãy luôn sẵn sàng máy ảnh kỹ thuật số chống nước để chụp thật nhiều ảnh.</span></p>\n</td>\n</tr>\n<tr>\n<td style=\"border-width: 2px; border-color: #000000;\">\n<p><span data-path-to-node=\"2,29,0,0\">Then we will have <strong data-path-to-node=\"2,29,0,0\" data-index-in-node=\"18\">(39) documentation</strong> of the existing waterfowl as some are becoming extinct.</span></p>\n</td>\n<td style=\"border-width: 2px; border-color: #000000;\">\n<p><span data-path-to-node=\"2,29,1,0\">Sau đó, chúng ta sẽ có <strong data-path-to-node=\"2,29,1,0\" data-index-in-node=\"23\">(39) tài liệu/dữ liệu ghi chép</strong> về các loài chim nước hiện có vì một số loài đang dần tuyệt chủng.</span></p>\n</td>\n</tr>\n<tr>\n<td style=\"border-width: 2px; border-color: #000000;\">\n<p><span data-path-to-node=\"2,30,0,0\">Water is a problem in this area, so you’ll also be collecting test tubes of water to bring back to our research lab for analysis. It needs to be monitored for <strong data-path-to-node=\"2,30,0,0\" data-index-in-node=\"159\">(40) pollution</strong> that may be caused by rainfall coming from the south.</span></p>\n</td>\n<td style=\"border-width: 2px; border-color: #000000;\">\n<p><span data-path-to-node=\"2,30,1,0\">Nước là một vấn đề ở khu vực này, vì vậy các em cũng sẽ thu thập các ống nghiệm chứa mẫu nước để mang về phòng thí nghiệm nghiên cứu phân tích. Cần phải giám sát tình trạng <strong data-path-to-node=\"2,30,1,0\" data-index-in-node=\"173\">(40) ô nhiễm</strong> có thể do lượng mưa đến từ phía nam gây ra.</span></p>\n</td>\n</tr>\n</tbody>\n</table>\n<p data-path-to-node=\"18\"> </p>\n"}]', 0);
INSERT INTO public.questions VALUES ('e1ca202b-b506-41cb-8afd-7a2ce2ce5209', '390674a8-0f9c-4184-b071-7e638ff6fffb', 'fillup', 'Questions 24-26', '<p>Complete the summary <span class="citation-3915 citation-end-3915">below.<sup class="superscript" data-turn-source-index="1"><!----></sup></span></p>
<div class="source-inline-chip-container ng-star-inserted"><!----><!----></div>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
<p><span class="citation-3914">Choose </span><strong data-path-to-node="16" data-index-in-node="7"><span class="citation-3914">ONE WORD ONLY</span></strong><span class="citation-3914 citation-end-3914"> from the passage for each answer.<sup class="superscript" data-turn-source-index="2"><!----></sup></span></p>
<div class="source-inline-chip-container ng-star-inserted"><!----><!----></div>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
<p><span class="citation-3913 citation-end-3913">Write your answers in boxes 24-26 on your answer sheet.<sup class="superscript" data-turn-source-index="3"><!----></sup></span></p>
<div class="source-inline-chip-container ng-star-inserted"><!----><!----></div>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
<p data-path-to-node="18"><strong data-path-to-node="18" data-index-in-node="0"><span class="citation-3912 citation-end-3912"><span style="font-size: 12pt;">The Beginnings of CRSP</span><sup class="superscript" data-turn-source-index="4"><!----></sup></span></strong></p>
<p class="source-inline-chip-container ng-star-inserted"><!----><!----></p>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
<p><span class="citation-3911">In 1958, a {banker}</span><span class="citation-3911 citation-end-3911"> working for a financial management company telephon<sup class="superscript" data-turn-source-index="5"><!----></sup></span>ed in Chicago to ask how well investments in shares performed in comparison to investments in low-risk assets. Fischer <span class="citation-3909 citation-3910">offered to find out and as a result the University of Chicago’s Center for Research in Security Prices (CRSP) was launched. Compiling the CRSP data was difficult because {computers}</span><span class="citation-3909 citation-3910"> were still being developed and information that had previously been on {paper}</span><span class="citation-3909 citation-3910 citation-end-3910"> needed to b<sup class="superscript" data-turn-source-index="6"><!----></sup></span><span class="citation-3909 citation-end-3909">e put onto magnetic tape.</span></p>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">24. banker — {In 1958, a banker working for a financial management company telephoned…}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn A):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“It all began in 1958 with a phone call from Louis Engel, a <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"80\">banker</strong> at Merrill Lynch, a US-based financial management company…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ rõ người thực hiện cuộc gọi là Louis Engel, một nhân viên ngân hàng (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"93\">banker</strong>) đang làm việc tại một công ty quản lý tài chính.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">25. computers — {…because computers were still being developed}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn B):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“Getting the CRSP data together was a tough process in what were then the <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"94\">early days of computers</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm “early days of computers” (những ngày đầu của máy tính) tương ứng với việc máy tính (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"101\">computers</strong>) vẫn đang trong quá trình phát triển (being developed).</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">26. paper — {…information that had previously been on paper needed to be put onto magnetic tape.}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn B):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">“…pieces of information… were transferred from <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"71\">paper</strong> in the exchange’s archive to <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"106\">magnetic tape</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Để đưa dữ liệu vào máy tính thời đó, các nhà nghiên cứu phải chuyển thông tin vốn đang nằm trên giấy tờ (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"117\">paper</strong>) trong kho lưu trữ sang dạng băng từ (magnetic tape).</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('91a0831a-a912-4f56-b767-df4b008e1ae8', '18276fc2-3e8f-4401-bba5-2e4cdd2d7122', 'radio', 'Questions 27–30', '', '<p>Choose the correct letter, A, B, C or D.</p>', 'multiple_choice', '[{"correct": 3, "options": [{"option_text": "A. to indicate that his article will cover several scientific fields"}, {"option_text": "B. to stress how much physics has changed in 400 years"}, {"option_text": "C. to persuade the reader to take him seriously"}, {"option_text": "D. to point out that his notions are not new"}], "question": "Why does the writer refer to Locke and Newton in the first paragraph?"}, {"correct": 2, "options": [{"option_text": "A. It was too complex for his contemporaries to understand."}, {"option_text": "B. It involved criticism of the way people behaved in society."}, {"option_text": "C. People felt that it devalued the accepted concept of humanity."}, {"option_text": "D. People assumed that it was intended as a joke."}], "question": "According to the writer, why was Freud''s theory of the unconscious mocked?"}, {"correct": 2, "options": [{"option_text": "A. how realistic most people''s memories are."}, {"option_text": "B. how hard it is to tell dreaming and waking apart."}, {"option_text": "C. how unusual it is to mistake a perception for a memory."}, {"option_text": "D. how valuable knowledge of the past can be."}], "question": "The writer describes Mr S failing to get up in order to demonstrate"}, {"correct": 0, "options": [{"option_text": "A. Perception involves much more than the data collected by the eyes."}, {"option_text": "B. Learning to see as an adult can be a time-consuming process."}, {"option_text": "C. Science is failing to devote enough attention to sight."}, {"option_text": "D. Human perception is remarkably reliable."}], "question": "What point is the writer making in the text as a whole?"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">27. D — to point out that his notions are not new</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"6,0,0\" data-index-in-node=\"26\">“Two of the great British men of the 17th century, the philosopher John Locke and the physicist Isaac Newton, were both aware that objects are not coloured...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả đưa ra các cột mốc lịch sử từ tận thế kỷ 17 nhằm nhấn mạnh rằng những khái niệm về việc vật thể và ánh sáng vốn dĩ không có màu sắc không phải là những khám phá mới mẻ (<strong data-path-to-node=\"6,1,0\" data-index-in-node=\"189\">not new</strong>), mà chúng đã được các vĩ nhân nhận thức từ 400 năm trước.</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">28. C — People felt that it devalued the accepted concept of humanity.</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"8,0,0\" data-index-in-node=\"26\">“...Freud’s notion of the unconscious, which was also initially treated with derision because it undermined the notion of humans as pre-eminently rational beings...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Thuyết vô thức của Freud bị chế giễu (<em data-path-to-node=\"8,1,0\" data-index-in-node=\"50\">mocked / treated with derision</em>) vì nó làm lung lay, hạ thấp (<em data-path-to-node=\"8,1,0\" data-index-in-node=\"111\">undermined</em>) tư tưởng coi con người là sinh vật có lý trí tối cao và phải tự chịu trách nhiệm cho hành vi của mình. Việc này đồng nghĩa với việc làm giảm giá trị khái niệm được thừa nhận về nhân tính (<strong data-path-to-node=\"8,1,0\" data-index-in-node=\"311\">devalued the accepted concept of humanity</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">29. C — how unusual it is to mistake a perception for a memory.</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"10,0,0\" data-index-in-node=\"26\">“Individual perceptions have a vividness that is rare for memories, which might be how we are able to separate them.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu chuyện ông Mr. S ngủ nướng do nhầm lẫn giữa việc \"nhìn thấy cái đồng hồ\" (thực tại) và \"nhớ về cái đồng hồ\" (quá khứ) là một trường hợp cực kỳ cá biệt. Tác giả mượn ví dụ này để phản đề rằng người bình thường rất hiếm khi nhầm lẫn như vậy (<strong data-path-to-node=\"10,1,0\" data-index-in-node=\"256\">how unusual it is</strong>), nhờ vào độ sống động (<em data-path-to-node=\"10,1,0\" data-index-in-node=\"298\">vividness</em>) của thị giác thực tế giúp ta phân định rõ ràng với ký ức.</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">30. A — Perception involves much more than the data collected by the eyes.</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"12,0,0\" data-index-in-node=\"26\">“Von Helmholtz thought that perceptions are unconscious inferences we make based on a combination of clues provided by the eyes and other senses, and knowledge of the world.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Thông điệp bao quát toàn bài viết khẳng định rằng quá trình nhận thức thị giác (<em data-path-to-node=\"12,1,0\" data-index-in-node=\"92\">perception</em>) không đơn giản chỉ là những dữ liệu hình ảnh cơ học do mắt thu về, mà nó là sự tổng hòa phức tạp kết hợp với trải nghiệm xúc giác, kiến thức nền và ký ức trong bộ não.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('c99a4827-11ae-402a-b652-bf28d26cc51f', '59e1c3d3-a2b2-4dc5-a326-dc3ce914c726', 'radio', 'Questions 1 – 7', '', '<p data-path-to-node="5,0,0">Choose<strong data-path-to-node="5,0,0" data-index-in-node="0"> TRUE</strong> if the statement agrees with the information,<strong data-path-to-node="5,1,0" data-index-in-node="0">FALSE</strong> if the statement contradicts the information,<strong data-path-to-node="5,2,0" data-index-in-node="0">NOT GIVEN</strong> if there is no information on this</p>', 'true_false_not_given', '[{"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The train company takes into account what passengers say about cleaning."}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The outside of each train is washed every night."}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The company owns 19,000 carriages in total."}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Passengers like the smell of the new toilet chemicals."}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The company may take the seat covers off if they find chewing gum on them."}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The train carriages all have new carpet which is easy to wash."}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "For the first time, the company is introducing brushes for cleaning the sides of the trains."}]', 'null', 'null', 'null', '[{"content": "<p><strong data-path-to-node=\"4\" data-index-in-node=\"0\">1. The train company takes into account what passengers say about cleaning. — {TRUE}</strong></p>\n<ul data-path-to-node=\"5\">\n<li><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"11\">“We’re making a conscious effort to change the areas that <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"69\">customers tell us</strong> we need to improve…”</em> và <em data-path-to-node=\"5,0,0\" data-index-in-node=\"113\">“Passengers also <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"130\">commented</strong> that…”</em></li>\n<li><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Take into account” (xem xét/để tâm) đồng nghĩa với việc lắng nghe những gì khách hàng nói (customers tell us/commented) để cải thiện dịch vụ.</li>\n</ul>\n<p><strong data-path-to-node=\"6\" data-index-in-node=\"0\">2. The outside of each train is washed every night. — {FALSE}</strong></p>\n<ul data-path-to-node=\"7\">\n<li><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"11\">“Each carriage goes through the train-washing machine <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"65\">every two days</strong>.”</em></li>\n<li><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc nói mặt ngoài (exterior/train-washing machine) được rửa <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"76\">2 ngày một lần</strong>, không phải <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"103\">mỗi đêm</strong> (every night). Lưu ý: Chỉ có phần bên trong (internally) mới được dọn dẹp mỗi đêm.</li>\n</ul>\n<p><strong data-path-to-node=\"8\" data-index-in-node=\"0\">3. The company owns 19,000 carriages in total. — {TRUE}</strong></p>\n<ul data-path-to-node=\"9\">\n<li><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"11\">“<strong data-path-to-node=\"9,0,0\" data-index-in-node=\"12\">All 19,000 carriages</strong> are cleaned every month…”</em></li>\n<li><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Khi bài viết nói “tất cả 19.000 toa tàu”, điều đó xác nhận tổng số lượng toa tàu mà công ty sở hữu là 19.000.</li>\n</ul>\n<p><strong data-path-to-node=\"10\" data-index-in-node=\"0\">4. Passengers like the smell of the new toilet chemicals. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"11\">\n<li><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"11\">“As a result, we’ve introduced different cleaning chemicals to… make them <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"87\">smell more fragrant</strong>.”</em></li>\n<li><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ nói công ty <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"36\">đã đưa vào sử dụng</strong> hóa chất mới để thơm hơn, nhưng <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"87\">không có thông tin</strong> phản hồi từ hành khách sau khi thay đổi (họ có thích mùi mới đó hay không). Đừng nhầm lẫn với việc họ “chê” mùi cũ ở đoạn trước đó.</li>\n</ul>\n<p><strong data-path-to-node=\"12\" data-index-in-node=\"0\">5. The company may take the seat covers off if they find chewing gum on them. — {TRUE}</strong></p>\n<ul data-path-to-node=\"13\">\n<li><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"11\">“If a seat cover… is damaged or soiled, with <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"58\">chewing gum</strong> for instance, we will <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"92\">remove it</strong> to clean…”</em></li>\n<li><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Remove it” đồng nghĩa với “take the seat covers off”. Việc này được thực hiện khi có kẹo cao su (chewing gum) dính vào.</li>\n</ul>\n<p><strong data-path-to-node=\"14\" data-index-in-node=\"0\">6. The train carriages all have new carpet which is easy to wash. — {FALSE}</strong></p>\n<ul data-path-to-node=\"15\">\n<li><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"15,0,0\" data-index-in-node=\"11\">“Special <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"20\">rubber floor tiles</strong>, which are cleaner and easier to maintain, have also been introduced on all our trains.”</em></li>\n<li><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc nói họ dùng <strong data-path-to-node=\"15,1,0\" data-index-in-node=\"32\">gạch lát sàn bằng cao su</strong> (rubber floor tiles), chứ không phải dùng <strong data-path-to-node=\"15,1,0\" data-index-in-node=\"99\">thảm</strong> (carpet). Hai vật liệu này hoàn toàn khác nhau.</li>\n</ul>\n<p><strong data-path-to-node=\"16\" data-index-in-node=\"0\">7. For the first time, the company is introducing brushes for cleaning the sides of the trains. — {FALSE}</strong></p>\n<ul data-path-to-node=\"17\">\n<li><strong data-path-to-node=\"17,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"17,0,0\" data-index-in-node=\"11\">“<strong data-path-to-node=\"17,0,0\" data-index-in-node=\"12\">Side brushes</strong> on the machines are also <strong data-path-to-node=\"17,0,0\" data-index-in-node=\"50\">being renewed and modified</strong> to make them more effective.”</em></li>\n<li><strong data-path-to-node=\"17,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi nói đây là “lần đầu tiên” (for the first time). Tuy nhiên, bài đọc nói các chổi bên (side brushes) đang được <strong data-path-to-node=\"17,1,0\" data-index-in-node=\"129\">thay mới và sửa đổi</strong> (renewed and modified), chứng tỏ chúng đã tồn tại từ trước đó rồi, không phải mới xuất hiện lần đầu.</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('31d2d792-3c7d-4fa0-8119-c3b36303bdd9', '110c3482-1cc7-4e36-96f6-0f1a64319db7', 'radio', 'Questions 27–31', NULL, '<p>Choose <strong>YES</strong> if the statement agrees with the claims of the writer, choose <strong>NO</strong> if the statement contradicts the claims of the writer, or <strong>NOT GIVEN</strong> if it is impossible to say what the writer thinks about this.</p>
', 'multiple_choice_single', '[{"correct": 1, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Mahy explores the traditional themes of New Zealand literature."}, {"correct": 2, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Mahy’s children’s books have been more popular than her teenage books."}, {"correct": 2, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Mahy and Knox have sometimes criticised each other’s work."}, {"correct": 0, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Mahy is welcoming to interviewers."}, {"correct": 1, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Mahy is at ease speaking about her experiences."}]', 'null', 'null', 'null', '[{"content": "<p><strong class=\"\">27. Mahy explores the traditional themes of New Zealand literature.</strong></p>\n<ul data-path-to-node=\"3\">\n<li><strong class=\"\">Đáp án: NO</strong></li>\n<li><strong class=\"\">Dẫn chứng:</strong><span class=\"\"> (Đoạn 1) &#8220;In our </span><strong class=\"\">solidly realist tradition</strong><span class=\"\">,</span><span class=\"\"> the linguistic fireworks of Mahy&#8217;s children&#8217;s fiction and the explorations of human behaviour in her supernatural teenage fiction </span><strong class=\"\">stand gloriously alone</strong><span class=\"\">.</span><span class=\"\">&#8220;</span></li>\n<li><strong class=\"\">Giải thích:</strong><span class=\"\"> Truyền thống văn học New Zealand là hiện thực (</span><em class=\"\">realist tradition</em><span class=\"\">),</span><span class=\"\"> nhưng tác phẩm của Mahy lại </span><strong class=\"\">đứng một mình</strong><span class=\"\"> (</span><em class=\"\">stand gloriously alone</em><span class=\"\">) và đi vào </span><strong class=\"\">lãnh thổ giàu trí tưởng tượng</strong><span class=\"\"> (</span><em class=\"\">imaginative territory</em><span class=\"\">),</span><span class=\"\"> tức là bà </span><strong class=\"\">không</strong><span class=\"\"> khám phá các chủ đề truyền thống.</span></li>\n</ul>\n<p><strong class=\"\">28. Mahy’s children’s books have been more popular than her teenage books.</strong></p>\n<ul data-path-to-node=\"5\">\n<li><strong class=\"\">Đáp án: NOT GIVEN</strong></li>\n<li><strong class=\"\">Dẫn chứng:</strong><span class=\"\"> Văn bản chỉ nói chung về sự độc đáo của cả hai thể loại (children&#8217;s fiction và supernatural teenage fiction) và mức độ nổi tiếng của một số tác phẩm trẻ em (</span><em class=\"\">Bubble Trouble</em><span class=\"\">,</span> <em class=\"\">The Great White Man-Eating Shark</em><span class=\"\">).</span></li>\n<li><strong class=\"\">Giải thích:</strong> <strong class=\"\">Không có thông tin</strong><span class=\"\"> so sánh trực tiếp mức độ phổ biến giữa sách thiếu nhi và sách tuổi teen của bà.</span></li>\n</ul>\n<p><strong class=\"\">29. Mahy and Knox have sometimes criticised each other’s work.</strong></p>\n<ul data-path-to-node=\"7\">\n<li><strong class=\"\">Đáp án: NOT GIVEN</strong></li>\n<li><strong class=\"\">Dẫn chứng:</strong><span class=\"\"> (Đoạn 1) &#8220;Mahy’s clearest heir,</span><span class=\"\"> I have always thought,</span><span class=\"\"> is Elizabeth Knox&#8230;</span><span class=\"\">&#8220;</span></li>\n<li><strong class=\"\">Giải thích:</strong><span class=\"\"> Tác giả chỉ so sánh Mahy với Elizabeth Knox và coi Knox là người thừa kế rõ ràng nhất của bà,</span> <strong class=\"\">không đề cập</strong><span class=\"\"> đến việc họ có phê bình công việc của nhau hay không.</span></li>\n</ul>\n<p><strong class=\"\">30. Mahy is welcoming to interviewers.</strong></p>\n<ul data-path-to-node=\"9\">\n<li><strong class=\"\">Đáp án: YES</strong></li>\n<li><strong class=\"\">Dẫn chứng:</strong><span class=\"\"> (Đoạn 1) &#8220;</span><strong class=\"\">As with all journalists, she is generous to a fault with her time and attention</strong><span class=\"\">&#8230;</span><span class=\"\">&#8220;</span></li>\n<li><strong class=\"\">Giải thích:</strong><span class=\"\"> Cụm từ &#8220;generous to a fault&#8221; (rộng lượng quá mức cần thiết) cho thấy bà rất niềm nở với các nhà báo.</span></li>\n</ul>\n<p><strong class=\"\">31. Mahy is at ease speaking about her experiences.</strong></p>\n<ul data-path-to-node=\"11\">\n<li><strong class=\"\">Đáp án: NO</strong></li>\n<li><strong class=\"\">Dẫn chứng:</strong><span class=\"\"> (Đoạn 1) &#8220;&#8230;</span><span class=\"\">as always—despite her careful consideration of questions and thoughtful answers—</span><strong class=\"\">I&#8217;m reminded she isn&#8217;t truly comfortable making herself or her life the heart of any conversation</strong><span class=\"\">.</span><span class=\"\">&#8220;</span></li>\n<li><strong class=\"\">Giải thích:</strong><span class=\"\"> Tác giả nhận thấy bà </span><strong class=\"\">không thực sự thoải mái</strong><span class=\"\"> khi nói về bản thân hoặc cuộc đời mình.</span></li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('15c0dec1-e8e6-470c-9437-b645fc448bd4', '16b5fe53-5af2-4dfc-8826-8dd5bb934d50', 'fillup', 'Question 37-40', '<p>Complete the table below.</p>
<p>Write <strong>ONE WORD ONLY</strong> for each answer.</p>
<table style="width: 77.4688%; height: 321.2px; border-collapse: collapse; border: 1px solid #000000;" border="1" data-path-to-node="4">
<thead>
<tr style="height: 36px;">
<td style="width: 13.2532%; border-width: 1px; border-color: #000000;"></td>
<td style="width: 81.5407%; text-align: left; border-width: 1px; border-color: #000000;"><span style="font-size: 12pt;"><strong>Schedule</strong></span></td>
</tr>
</thead>
<tbody>
