INSERT INTO public.questions VALUES ('4c3a05a5-8d72-40f1-8ee8-1885959f7277', '448b0593-6eed-4d20-be08-768265eb3048', 'fillup', 'Questions 1–3', '<p data-start="18" data-end="47">Complete the sentences below.</p>
<p data-start="49" data-end="132">Choose <strong data-start="56" data-end="98">NO MORE THAN TWO WORDS AND/OR A NUMBER</strong> from the passage for each answer.</p>
<p data-start="189" data-end="213"><span style="font-size: 14pt;"><strong>Urban farming in Paris</strong></span></p>
<p data-start="215" data-end="294">1 Vertical tubes are used to grow strawberries, {lettuces} and herbs.</p>
<p data-start="296" data-end="408">2 There will eventually be a daily harvest of as much as {1000 kg} in weight of fruit and vegetables.</p>
<p data-start="410" data-end="530">3 It may be possible that the farm’s produce will account for as much as 10% of the city’s {consumption|food} overall.</p>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', 'null', 0);
INSERT INTO public.questions VALUES ('a79819ec-42fe-4b6e-b4cf-dfa19a6b746a', '403f3e29-d07f-4f13-9366-e914f1ca4312', 'fillup', 'Questions 7-10', '<p>The diagram below gives information about fish fins and their purposes.</p>
<p>Complete the diagram with <strong>NO MORE THAN THREE WORDS</strong> from the passage for each blank</p>
<p><img decoding="async" src="data:image/png;base64," width="563" height="355" loading="lazy"></p>
<p><em>Write your answers in boxes <strong>7-10</strong> on your answer sheet.</em></p>
<p>{forward thrust }</p>
<p>{rolling and yawing }</p>
<p>{Pectoral and pelvic }</p>
<p>{slows and stops }</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p>7. forward thrust → F<br />(Đoạn F: “The tail fin, in its final lash may contribute as much as 40 per cent of the forward thrust.”)<br />→ Vây đuôi (tail fin) có vai trò tạo 40% lực đẩy về phía trước, giúp cá tiến tới.<br />→ Đáp án: forward thrust</p>\n<p> <br />8. rolling and yawing → F<br />(Đoạn F: “The median fins, that is, the dorsal, anal and ventral fins, control the rolling and yawing movements of the fish&#8230;”)<br />→ Vây lưng (dorsal fin) giúp kiểm soát chuyển động lắc ngang (rolling) và xoay hướng (yawing) của cá.<br />→ Đáp án: rolling and yawing</p>\n<p> <br />9. Pectoral and pelvic → F<br />(Đoạn F: “The paired fins, pectoral and pelvic act as hydroplanes and control the pitch of the fish&#8230;”)<br />→ Hai cặp vây ngực và vây bụng (paired fins) có tác dụng điều chỉnh độ cao – thấp của cá khi bơi.<br />→ Đáp án: Pectoral and pelvic</p>\n<p> <br />10. slows and stops → F<br />(Đoạn F: “The paired fins are also the means by which the fish slows down and stops.”)<br />→ Các vây đôi giúp làm chậm và dừng lại trong quá trình di chuyển.<br />→ Đáp án: slows and stops</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('f2a7f03c-ff1b-4bc6-9017-fd1c32c901cc', '59e1c3d3-a2b2-4dc5-a326-dc3ce914c726', 'matrix', 'Questions 8 – 14', '', '<p data-path-to-node="10">Write the correct letter, <strong data-path-to-node="10" data-index-in-node="153">A-E</strong>, in boxes 8-14 on your answer sheet.</p>
<p data-path-to-node="11"><em data-path-to-node="11" data-index-in-node="0"><strong data-path-to-node="11" data-index-in-node="0">NB</strong> You may use any letter more than once.</em></p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "simple", "matrixItems": [{"itemText": "The owner goes abroad to buy things for the shop.", "correctCategoryLetter": "D"}, {"itemText": "A number of different sellers use the same premises.", "correctCategoryLetter": "A"}, {"itemText": "It’s not on the ground floor.", "correctCategoryLetter": "B"}, {"itemText": "It sells things for outdoors.", "correctCategoryLetter": "D"}, {"itemText": "It specialises in materials and furnishing fabrics.", "correctCategoryLetter": "C"}, {"itemText": "It specialises in modern designs for the home.", "correctCategoryLetter": "B"}, {"itemText": "One of its specialities is carpets.", "correctCategoryLetter": "E"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}]}', '[{"content": "<p><strong data-path-to-node=\"4\" data-index-in-node=\"0\">8. The owner goes abroad to buy things for the shop. — {D} The Salon</strong></p>\n<ul data-path-to-node=\"5\">\n<li><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"11\">“<strong data-path-to-node=\"5,0,0\" data-index-in-node=\"12\">David Martin makes a trip there [France] each month</strong> to purchase fresh stock…”</em></li>\n<li><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc David Martin đi sang Pháp (France) mỗi tháng để mua hàng chính là hành động chủ cửa hàng đi ra nước ngoài (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"124\">goes abroad</strong>) để nhập hàng.</li>\n</ul>\n<p><strong data-path-to-node=\"6\" data-index-in-node=\"0\">9. A number of different sellers use the same premises. — {A} The Antiques Parade</strong></p>\n<ul data-path-to-node=\"7\">\n<li><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"11\">“…and the space is <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"32\">let to 12 dealers</strong>.”</em></li>\n<li><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Premises” (mặt bằng/địa điểm) của cửa hàng này được cho 12 đại lý (dealers) thuê lại. “Dealers” ở đây chính là những người bán hàng khác nhau (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"156\">different sellers</strong>).</li>\n</ul>\n<p><strong data-path-to-node=\"8\" data-index-in-node=\"0\">10. It’s not on the ground floor. — {B} Cultnote</strong></p>\n<ul data-path-to-node=\"9\">\n<li><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"11\">“<strong data-path-to-node=\"9,0,0\" data-index-in-node=\"12\">Upstairs</strong> at The Antiques Parade.”</em></li>\n<li><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cửa hàng này nằm ở “tầng trên” (upstairs), nghĩa là nó không nằm ở tầng trệt (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"90\">not on the ground floor</strong>).</li>\n</ul>\n<p><strong data-path-to-node=\"10\" data-index-in-node=\"0\">11. It sells things for outdoors. — {D} The Salon</strong></p>\n<ul data-path-to-node=\"11\">\n<li><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"11\">“…even plants and <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"31\">garden furniture</strong>…”</em></li>\n<li><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đồ nội thất sân vườn (garden furniture) là những vật dụng dùng cho không gian ngoài trời (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"102\">outdoors</strong>).</li>\n</ul>\n<p><strong data-path-to-node=\"12\" data-index-in-node=\"0\">12. It specialises in materials and furnishing fabrics. — {C} Daniels Interiors</strong></p>\n<ul data-path-to-node=\"13\">\n<li><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"11\">“…staggering range of <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"35\">12,000 cottons and linens</strong> to choose from for <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"80\">curtains and upholstery</strong>…”</em></li>\n<li><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Cottons and linens” (vải cotton và lanh) dùng cho rèm và bọc ghế chính là các loại vật liệu (<strong data-path-to-node=\"13,1,0\" data-index-in-node=\"106\">materials</strong>) và vải nội thất (<strong data-path-to-node=\"13,1,0\" data-index-in-node=\"134\">furnishing fabrics</strong>).</li>\n</ul>\n<p><strong data-path-to-node=\"14\" data-index-in-node=\"0\">13. It specialises in modern designs for the home. — {B} Cultnote</strong></p>\n<ul data-path-to-node=\"15\">\n<li><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"15,0,0\" data-index-in-node=\"11\">“Susan Peterson produces unusual <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"44\">contemporary furniture</strong>… influence of rock culture and <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"100\">today’s music scene</strong>.”</em></li>\n<li><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Contemporary” (đương đại) đồng nghĩa với “modern” (hiện đại). Thiết kế mang hơi thở của văn hóa rock và âm nhạc ngày nay khẳng định phong cách hiện đại của cửa hàng này.</li>\n</ul>\n<p><strong data-path-to-node=\"16\" data-index-in-node=\"0\">14. One of its specialities is carpets. — {E} Oriental Furnishings</strong></p>\n<ul data-path-to-node=\"17\">\n<li><strong data-path-to-node=\"17,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"17,0,0\" data-index-in-node=\"11\">“You can find <strong data-path-to-node=\"17,0,0\" data-index-in-node=\"25\">Turkish rugs, Indian floor coverings</strong>… The rugs are all hand-made…”</em></li>\n<li><strong data-path-to-node=\"17,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Rugs” (thảm nhỏ) và “floor coverings” (vật liệu trải sàn) là các từ đồng nghĩa hoặc cùng nhóm với thảm (<strong data-path-to-node=\"17,1,0\" data-index-in-node=\"117\">carpets</strong>).</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('765165a1-cc93-41c4-acce-ffbef2599739', 'e1e1482a-3e84-4eee-82e2-f3ea4a9b352f', 'checkbox', 'Questions 21-22', NULL, '<p>Choose <strong>TWO </strong>correct answers.</p>
<p>Which <strong>TWO </strong>of the following statements are true of bird migration?</p>
', 'multiple_choice_many', 'null', '[{"option": "Birds often fly further than they need to.", "correct": true}, {"option": "Birds travelling in family groups are safe.", "correct": false}, {"option": "Birds flying at night need less water.", "correct": true}, {"option": "Birds have much sharper eyesight than humans.", "correct": false}, {"option": "Only shorebirds are resistant to strong winds.", "correct": false}]', 'null', 'null', '[{"content": "<p data-path-to-node=\"1\">Câu 21: A (Birds often fly further than they need to)</p>\n<ul data-path-to-node=\"2\">\n<li>\n<p data-path-to-node=\"2,0,0\"><strong data-path-to-node=\"2,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 3, dòng 1-2.</p>\n</li>\n<li>\n<p data-path-to-node=\"2,1,0\"><strong data-path-to-node=\"2,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “One puzzling fact is that many birds journey much further than would be necessary just to find food and good weather.”</p>\n</li>\n<li>\n<p data-path-to-node=\"2,2,0\"><strong data-path-to-node=\"2,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc khẳng định một sự thật gây khó hiểu là nhiều loài chim thực hiện những hành trình xa hơn mức cần thiết so với việc chỉ đơn thuần là đi tìm thức ăn hay thời tiết tốt.</p>\n</li>\n</ul>\n<p data-path-to-node=\"3\">Câu 22: C (Birds travelling at night need less water)</p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 5, dòng 13-14.</p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…the danger of dehydration due to flying for long periods in warm, sunlit skies is reduced.”</p>\n</li>\n<li>\n<p data-path-to-node=\"4,2,0\"><strong data-path-to-node=\"4,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc di cư vào ban đêm giúp chim tránh được tình trạng mất nước (dehydration) so với khi bay dưới bầu trời nắng ấm vào ban ngày. Điều này đồng nghĩa với việc chúng cần ít nước hơn hoặc giữ nước tốt hơn khi bay đêm.</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('27b8143f-e678-4c23-b726-bf4f904f640e', '907b7ffc-b096-49c4-a1c9-3301e8020730', 'radio', 'Questions 1–8', NULL, '<p>Choose the correct answer.</p>
', 'multiple_choice_single', '[{"correct": 2, "options": [{"content": "18 people."}, {"content": "20 people."}, {"content": "38 people."}], "question": "The centre has enough accommodation for"}, {"correct": 0, "options": [{"content": "unavailable."}, {"content": "flooded."}, {"content": "booked."}], "question": "The meeting room is currently"}, {"correct": 1, "options": [{"content": "use the centre’s kitchen."}, {"content": "have meals cooked for them."}, {"content": "eat at restaurants outside."}], "question": "Visitors must tell the centre in advance if they want to"}, {"correct": 0, "options": [{"content": "get information about organic farming."}, {"content": "help to feed the animals."}, {"content": "watch a tractor demonstration."}], "question": "All visitors on the farm can"}, {"correct": 1, "options": [{"content": "learn to use map."}, {"content": "find their own food."}, {"content": "run through woodland."}], "question": "On the survival course people have to"}, {"correct": 2, "options": [{"content": "Exmoor National Park."}, {"content": "the beach."}, {"content": "a cycling route."}], "question": "From the centre it is easy to walk to"}, {"correct": 2, "options": [{"content": "cinema."}, {"content": "theatre."}, {"content": "museum."}], "question": "If the weather is bad visitors can go to a"}, {"correct": 0, "options": [{"content": "part of the cost in advance."}, {"content": "all the cost in advance."}, {"content": "all of the cost on arrival."}], "question": "Group who wish to stay at the centre must pay"}]', NULL, '{"layoutType": ["standard"], "summaryText": null, "answerOptions": null, "matchingItems": null}', '{"layoutType": ["standard"], "legendTitle": null, "matrixItems": null, "matrixCategories": null}', '[{"content": "<p class=\"MsoNormal\"><strong>SECTION 1</strong></p>\n<p class=\"MsoNormal\"><strong>Staff:</strong> Hello, Wincham Farm Centre.</p>\n<p class=\"MsoNormal\"><strong>Caller:</strong> Oh, hello. I want to arrange a weekend away for myself and some people from work, and we heard about your centre. I wonder if you could give me some details.</p>\n<p class=\"MsoNormal\"><strong>Staff:</strong> Yes, certainly. We are a residential centre attached to a working farm, and we organise educational activities for those guests who want them. Um, what else would you like to know?</p>\n<p class=\"MsoNormal\"><strong>Caller:</strong> Well firstly, what kind of accommodation have you got?</p>\n<p class=\"MsoNormal\"><strong>Staff:</strong> We’ve got eight rooms altogether, and <span style=\"text-decoration: underline;\"><span style=\"background-color: #ffe786;\"><strong>(1) we can sleep 38 at any one time (C: 38 people)</strong></span></span>. Three of the rooms have got 6 bunks and five of them have got 4 bunks.</p>\n<p class=\"MsoNormal\"><strong>Caller:</strong> Right, and what other facilities are there?</p>\n<p class=\"MsoNormal\"><strong>Staff:</strong> We have separate toilets and showers for each of the rooms. There’s a large dining room and a large meeting room which can be booked by groups in advance. But I’m afraid we had a flood in there last month and the floor was slightly damaged, so<span style=\"text-decoration: underline;\"> <span style=\"background-color: #ffe786;\"><strong>(2) unfortunately it’s out of use just now (A: unavailable)</strong></span></span>. We’ve got workmen coming in next week.</p>\n<p class=\"MsoNormal\"><strong>Caller:</strong> When were you thinking of staying? In three weeks’ time, September 28th.</p>\n<p class=\"MsoNormal\"><strong>Staff:</strong> Oh, it should be OK by then.</p>\n<p class=\"MsoNormal\"><strong>Caller:</strong> Oh well, that’s okay then. Uh, and what about food? Do you provide meals or is it self-catering?</p>\n<p class=\"MsoNormal\"><strong>Staff:</strong> We’re very flexible. <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(3) As long as you give us enough notice, we can cater for you (B: have meals cooked for them)</strong></span>, or if you prefer, you can just bring your own food and use the kitchen facilities. And some people prefer to eat out, which is also fine.</p>\n<p class=\"MsoNormal\"><strong>Caller:</strong> Fine. And I heard that your farm is organic. Does that mean that you only have crops and no animals?</p>\n<p class=\"MsoNormal\"><strong>Staff:</strong> Haha, it doesn’t actually. A lot of people seem to think that, but we do rear livestock as well. Organic means it’s all produced without the use of artificial fertilizers or pesticides.</p>\n<p class=\"MsoNormal\"><strong>Caller:</strong> I see, that sounds good. Um, could you tell me what sort of recreational activities are available either at the centre or in the area?</p>\n<p class=\"MsoNormal\"><strong>Staff:</strong> Yes, here at the centre, we offer farm tours; they’re very popular. <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(4) One of the farm managers shows people around and explains some of the principles of organic farming (A: get information about organic farming)</strong>.</span> And for any visitors who are really keen, you let them drive a tractor or feed the animals and so on—with supervision, of course.</p>\n<p class=\"MsoNormal\"><strong>Caller:</strong> I think a lot of our group would be interested in that. It’d make a change from factory work.</p>\n<p class=\"MsoNormal\"><strong>Staff:</strong> Well, if they fancy it, tell them to come prepared. Plenty of old clothing, especially footwear. It can be very messy and wet.</p>\n<p class=\"MsoNormal\"><strong>Caller:</strong> OK, I’ll warn them.</p>\n<div class=\"MsoNormal\" style=\"text-align: center;\" align=\"center\">\n<hr align=\"center\" size=\"2\" width=\"100%\" />\n</div>\n<p class=\"MsoNormal\"><strong>Staff:</strong> And another type of activity we do is survival courses, but that’s only for groups of five or more.</p>\n<p class=\"MsoNormal\"><strong>Caller:</strong> What do they involve? Things like map reading?</p>\n<p class=\"MsoNormal\"><strong>Staff:</strong> Well, not exactly. What it is, we’ve got a large area of woodland on the farm and we run this course there. <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(5) It’s mainly about collecting food and water (B: find their own food)</strong></span>, lighting a fire without any equipment, that kind of thing.</p>\n<p class=\"MsoNormal\"><strong>Caller:</strong> Hmm, this weekend could be hard work! Um, what about the area around the centre? What is there to do?</p>\n<p class=\"MsoNormal\"><strong>Staff:</strong> If you look at a map, you’ll see that we’re very well situated here. Our centre is about midway between the Exmoor National Park and the south coast.</p>\n<p class=\"MsoNormal\"><strong>Caller:</strong> Are they both within walking distance?</p>\n<p class=\"MsoNormal\"><strong>Staff:</strong> Well, they’re both a bit far unless you’re very fit, but they’re only about 30 minutes by road. And <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(6) there’s also a cycle path which starts quite near here, about 10 minutes’ walk away (C: a cycling route)</strong></span>. You can hire bikes at the starting point.</p>\n<p class=\"MsoNormal\"><strong>Caller:</strong> Um, what is there to do if the weather’s bad?</p>\n<p class=\"MsoNormal\"><strong>Staff:</strong> Well, on most Saturday evenings we show films here, and then once a month a group of local musicians performs in our meeting room. Hmm, and then Sherborne is only 14 miles away. It’s only a small town, but <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(7) it’s got a very good museum (C: museum)</strong> and an old abbey, which is well worth a visit.</span></p>\n<p class=\"MsoNormal\"><strong>Caller:</strong> Well, it sounds perfect for our purposes. Uh, one last thing, what about prices?</p>\n<p class=\"MsoNormal\"><strong>Staff:</strong> We charge a standard £14 a head for accommodation.</p>\n<p class=\"MsoNormal\"><strong>Caller:</strong> Right well, I’ve made a note of all that. I’ll get back to you with a firm booking. Can I do that by phone?</p>\n<p class=\"MsoNormal\"><strong>Staff:</strong> <span style=\"text-decoration: underline; background-color: #ffe786;\">Yes, you can, but <strong>(8) once you’ve made a booking, we would need a deposit within 5 days to secure it (A: part of the cost in advance)</strong>.</span> Then you just pay the balance when you’re here.</p>\n<p class=\"MsoNormal\"><strong>Caller:</strong> Oh yes, of course. Could you give me the address please?</p>\n<p class=\"MsoNormal\"><strong>Staff:</strong> Yes, it’s Wincham Farm, <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(9) Cotehele</strong> Road—that’s <strong>C-O-T-E-H-E-L-E</strong></span>—near Sherborne. And the postcode is <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(10) SH12 1LQ</strong>.</span></p>\n<p class=\"MsoNormal\"><strong>Caller:</strong> Thank you.</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('9965cccf-37b9-4a11-8801-4fae90b741a0', '403f3e29-d07f-4f13-9366-e914f1ca4312', 'fillup', 'Questions 11-13', '<p>Complete the summary below using <strong>NO MORE THAN THREE WORDS</strong> from the passage for each blank.</p>
<p><em>Write your answers in boxes <strong>11-13</strong> on your answer sheet.</em></p>
<p>Two types of muscles are involved in fish swimming. The majority of a fish’s body comprises the<br />{white muscle} , and the red muscle is found only at the roots of the fins and in a strip along the centre of each flank. For most of its routine movements, the fish uses a lot of its {fats and glycogen} saved in body, and white muscle is mostly used for short-term, fast swimming, such as escaping from {predator}</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p>11. white muscle → D<br />(Đoạn D: “The muscles involved in swimming are of two main types. The bulk of a fish’s body is composed of the so-called white muscle&#8230;”)<br />→ Tác giả nói rõ rằng phần lớn cơ thể cá được cấu tạo từ cơ trắng (white muscle) — loại cơ chính hỗ trợ vận động.<br />→ Đáp án: white muscle</p>\n<p> <br />12. fats and glycogen → D<br />(Đoạn D: “The red muscle receives a good supply of blood and contains ample quantities of fat and glycogen, the storage form of glucose&#8230;”)<br />→ Mô cơ đỏ chứa chất béo và glycogen, được dùng làm nguồn năng lượng dự trữ cho các hoạt động thường ngày.<br />→ Đáp án: fats and glycogen</p>\n<p> <br />13. predator → D<br />(Đoạn D: “&#8230;because it enables the fish to swim rapidly away from danger—by a predator, for instance&#8230;”)<br />→ Cơ trắng được kích hoạt khi cá phải bơi nhanh để trốn khỏi kẻ săn mồi (predator).<br />→ Đáp án: predator</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}]', 2);
INSERT INTO public.questions VALUES ('4d761e9b-9a73-4a12-92ab-ad44cfc9c8a4', 'e50b6d9f-0dd0-43be-9f00-ce6dd1c29a70', 'fillup', 'Questions 31-40', '<p data-start="57" data-end="210">Write <strong data-start="176" data-end="193">ONE WORD ONLY</strong> for each answer.</p>
<h3 style="text-align: center;" data-start="217" data-end="248"><span style="font-size: 14pt;"><strong data-start="221" data-end="248">Australian Lemon Myrtle</strong></span></h3>
<h4 data-start="250" data-end="280"><strong data-start="255" data-end="280">Types of Citrus Trees</strong></h4>
<ul data-start="281" data-end="546">
<li data-start="281" data-end="373">
<p data-start="283" data-end="373">Lemon Myrtle trees are commonly used as herbs, spices, or brewed into <strong data-start="353" data-end="371">{tea }</strong></p>
</li>
<li data-start="374" data-end="466">
<p data-start="376" data-end="466">Desert Lemon trees are similar, but they require a plenty of<strong data-start="437" data-end="455"> { water}</strong>to grow.</p>
</li>
<li data-start="467" data-end="546">
<p data-start="469" data-end="546">Finger lime trees are highly valued but easily affected by<strong data-start="528" data-end="546"> { diseases}</strong></p>
</li>
</ul>
<h4 data-start="553" data-end="593"><strong data-start="558" data-end="593">Cultivation and Natural Habitat</strong></h4>
<ul data-start="594" data-end="938">
<li data-start="594" data-end="664">
<p data-start="596" data-end="664">They are planted in spring to protect them from <strong data-start="644" data-end="662">{ frost}</strong></p>
</li>
<li data-start="665" data-end="749">
<p data-start="667" data-end="749">To avoid damage, they are usually planted in spring to escape<strong data-start="729" data-end="747"> {stresses }</strong></p>
</li>
<li data-start="750" data-end="814">
<p data-start="752" data-end="814">It is used either as a ripe fruit or as a<strong data-start="794" data-end="812"> {powder }</strong></p>
</li>
<li data-start="815" data-end="888">
<p data-start="817" data-end="888">In the wild, they are typically spread in<strong data-start="859" data-end="877"> {dry }</strong>regions.</p>
</li>
<li data-start="889" data-end="938">
<p data-start="891" data-end="938">They grow best in a<strong data-start="911" data-end="929"> {tropical }</strong>climate.</p>
</li>
</ul>
<h4 data-start="945" data-end="975">Other <strong data-start="950" data-end="975">uses and threat</strong></h4>
<ul data-start="976" data-end="1113">
<li data-start="976" data-end="1044">
<p data-start="978" data-end="1044">They are mainly used as a decoration, e.g. on<strong data-start="1024" data-end="1042"> {fish }</strong></p>
</li>
<li data-start="1045" data-end="1113">
<p data-start="1047" data-end="1113">They can be harmed by<strong data-start="1069" data-end="1087"> {insects }</strong>such as mites and borers.</p>
</li>
</ul>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p>LECTURER: Good afternoon everyone. Today, we’re going to explore a few remarkable native citrus species found in Australia, which are not only important ecologically but also increasingly popular in culinary and commercial industries.<br />\n🎧 Chào buổi chiều mọi người. Hôm nay, chúng ta sẽ tìm hiểu một vài loài cây họ cam chanh bản địa đáng chú ý ở Úc — không chỉ có vai trò sinh thái quan trọng mà còn ngày càng phổ biến trong ẩm thực và thương mại.</p>\n<p>🍋 Lemon Myrtle<br />\nLECTURER: Let’s begin with one of the most well-known examples — Lemon Myrtle. This evergreen tree, native to the subtropical rainforests of Queensland, is widely appreciated for its strong lemon aroma.<br />\n🎧 Hãy bắt đầu với ví dụ nổi tiếng nhất — cây Lemon Myrtle, loài cây thường xanh mọc tự nhiên trong rừng mưa cận nhiệt đới ở Queensland, được ưa chuộng vì hương chanh đậm đặc.</p>\n<p>LECTURER: People often use Lemon Myrtle in cooking, but one of its more traditional applications is steeping the leaves to create (Question 31) tea.<br />\n🎧 Người ta thường dùng Lemon Myrtle trong nấu ăn, nhưng một ứng dụng truyền thống hơn là dùng lá của nó để pha trà.<br />\n→ Answer 31: tea</p>\n<p>🌳 Desert Lemon<br />\nLECTURER: Now, Lemon Myrtle isn’t the only citrus-like tree found in Australia. Although Desert Lemon trees resemble other native citrus types, they won’t develop properly unless there is consistent and sufficient (Question 32) rain available.<br />\n🎧 Lemon Myrtle không phải là cây cam chanh duy nhất ở Úc. Dù cây Desert Lemon trông giống các loài cam bản địa khác, nhưng chúng sẽ không phát triển tốt nếu không có đủ mưa thường xuyên.<br />\n→ Answer 32: rain</p>\n<p>LECTURER: This need for regular water supply makes them more challenging to grow in areas prone to long dry spells.<br />\n🎧 Nhu cầu nước đều đặn khiến chúng khó trồng ở những vùng dễ hạn hán kéo dài.</p>\n<p>🍈 Finger Lime<br />\nLECTURER: Another fascinating species is the Finger Lime, sometimes referred to as “citrus caviar” due to its tiny bead-like juice vesicles.<br />\n🎧 Một loài thú vị khác là Finger Lime, còn được gọi là “trứng cá chanh” vì phần thịt quả có những hạt nhỏ như trứng cá.</p>\n<p>LECTURER: However, (Question 33) Finger Lime trees often struggle in wet climates where fungal and bacterial diseases spread quickly.<br />\n🎧 Tuy nhiên, cây Finger Lime thường gặp khó khăn ở vùng khí hậu ẩm, nơi các loại bệnh do nấm và vi khuẩn lan rất nhanh.<br />\n→ Answer 33: diseases</p>\n<p>🌱 Cultivation and Growth<br />\nLECTURER: When it comes to cultivation practices, timing is everything. Farmers usually begin planting during the spring months, as unexpected (Question 34) frost later in the year can severely damage young trees.<br />\n🎧 Khi nói đến việc trồng trọt, thời điểm là yếu tố then chốt. Nông dân thường trồng vào mùa xuân vì sương giá (frost) bất ngờ vào cuối năm có thể làm hỏng cây non.<br />\n→ Answer 34: frost</p>\n<p>LECTURER: This seasonal strategy helps to maximize growth while avoiding environmental (Question 35) stresses that could affect survival rates.<br />\n🎧 Chiến lược trồng theo mùa này giúp cây phát triển tối đa, đồng thời tránh các yếu tố gây căng thẳng môi trường ảnh hưởng đến khả năng sinh trưởng.<br />\n→ Answer 35: stresses</p>\n<p>LECTURER: In some recipes, the dried form — commonly referred to as a (Question 36) powder — is preferred over using the fully ripened fruit.<br />\n🎧 Trong một số công thức nấu ăn, người ta thường sử dụng dạng bột khô thay vì quả chín.<br />\n→ Answer 36: powder</p>\n<p>🌾 Habitat and Climate<br />\nLECTURER: From a geographical standpoint, distribution of these plants varies depending on species. These plants are naturally found in extremely (Question 37) dry ecosystems.<br />\n🎧 Về mặt địa lý, các loài này phân bố khác nhau tùy theo giống. Chúng thường mọc tự nhiên ở các vùng khô hạn.<br />\n→ Answer 37: dry</p>\n<p>LECTURER: Ideal growth occurs in consistently hot and humid environments, particularly in (Question 38) tropical zones where temperatures remain stable throughout the year.<br />\n🎧 Chúng phát triển tốt nhất trong môi trường nóng ẩm ổn định, đặc biệt ở vùng nhiệt đới có nhiệt độ ổn định quanh năm.<br />\n→ Answer 38: tropical</p>\n<p>🍽 Other Uses and Threats<br />\nLECTURER: Beyond function, some species are valued for aesthetics. Chefs often enhance the look of seafood dishes by adding colourful citrus zest, especially when presenting grilled (Question 39) fish.<br />\n🎧 Ngoài công dụng, một số loài còn được ưa chuộng vì tính thẩm mỹ. Các đầu bếp thường thêm vỏ cam chanh nhiều màu để trang trí món hải sản, đặc biệt là khi trình bày món cá nướng.<br />\n→ Answer 39: fish</p>\n<p>LECTURER: However, cultivation is not without its challenges. (Question 40) Pests pose a significant threat to these trees, with insects like borers and mites causing serious leaf damage.<br />\n🎧 Tuy nhiên, việc trồng trọt không hề dễ dàng. Sâu hại là mối đe dọa lớn với những loài cây này, các loại côn trùng như mọt và ve nhỏ có thể gây hư hại nghiêm trọng cho lá.<br />\n→ Answer 40: pests</p>\n"}, {"content": "<p class=\"MsoNormal\">Now lemon-murtral isn’t the only citrus-like tree found in Australia.</p>\n<p class=\"MsoNormal\">Although desert lemon trees resemble other native citrus types, they won’t develop properly unless there is consistent and sufficient rain available.</p>\n<p class=\"MsoNormal\">This need for regular <strong style=\"mso-bidi-font-weight: normal;\"><span style=\"color: red;\">water</span></strong> supply makes them more challenging to grow in areas prone to long dry spells, despite their name suggesting otherwise.</p>\n"}, {"content": "<p class=\"MsoNormal\">Another fascinating species is the finger lime, sometimes referred to as citrus caviar due to its tiny bead-like juice vesicles.</p>\n<p class=\"MsoNormal\">These are often used in gourmet dishes. However, finger lime trees, known for their culinary appeal, often struggle in wet climates where fungal and bacterial <strong style=\"mso-bidi-font-weight: normal;\"><span style=\"color: red;\">diseases</span></strong> tend to spread quickly.</p>\n<p class=\"MsoNormal\">This sensitivity has made commercial cultivation a bit risky, especially in regions with poor drainage or unpredictable weather.</p>\n"}, {"content": "<p class=\"MsoNormal\">When it comes to cultivation practices, timing is everything.</p>\n<p class=\"MsoNormal\">Farmers usually begin planting during the spring months as unexpected <strong style=\"mso-bidi-font-weight: normal;\"><span style=\"color: red;\">frost</span></strong> later in the year can severely damage young trees.</p>\n"}, {"content": "<p class=\"MsoNormal\">This seasonal strategy helps to maximize growth while avoiding environmental <strong style=\"mso-bidi-font-weight: normal;\"><span style=\"color: red;\">stresses</span></strong> that could affect survival rates.</p>\n"}, {"content": "<p class=\"MsoNormal\">Speaking of safety, it’s also important to mention that not every part of these trees is edible.</p>\n<p class=\"MsoNormal\">While generally safe, certain areas of the plant, especially the leaves, can be considered slightly toxic when eaten in significant amounts.</p>\n<p class=\"MsoNormal\">For this reason, growers and chefs alike must take precautions when handling or preparing these native ingredients.</p>\n<p class=\"MsoNormal\">As for processing, there’s more than one way to use the harvest.</p>\n<p class=\"MsoNormal\">In some recipes, the dried form, commonly referred to as a <strong style=\"mso-bidi-font-weight: normal;\"><span style=\"color: red;\">powder</span></strong>, is preferred over using the fully ripened fruit.</p>\n<p class=\"MsoNormal\">This allows the flavour to be preserved and used in spice blends, marinades or even herbal teas.</p>\n"}, {"content": "<p class=\"MsoNormal\">From a geographical standpoint, distribution of these plants varies depending on species.</p>\n<p class=\"MsoNormal\">These plants are naturally found in extremely <strong style=\"mso-bidi-font-weight: normal;\"><span style=\"color: red;\">dry</span></strong> ecosystems, with the desert landscape being one of their most common habitats.</p>\n<p class=\"MsoNormal\">Their resilience to harsh conditions has made them well suited for outback environments, although they still need proper care.</p>\n<p class=\"MsoNormal\">Even so, not all environments are equal.</p>\n"}, {"content": "<p class=\"MsoNormal\">Ideal growth occurs in consistently hot and humid environments, particularly in <strong style=\"mso-bidi-font-weight: normal;\"><span style=\"color: red;\">tropical</span></strong> zones where temperatures remain stable throughout the year.</p>\n<p class=\"MsoNormal\">This is why some commercial farms are now being established further north, where these conditions are more reliable year round.</p>\n<p class=\"MsoNormal\">Beyond function, some species are valued for aesthetics.</p>\n"}, {"content": "<p class=\"MsoNormal\">Chefs often enhance the look of seafood dishes by adding colourful citrus zest, especially when presenting grilled <strong style=\"mso-bidi-font-weight: normal;\"><span style=\"color: red;\">fish</span></strong> to guests.</p>\n<p class=\"MsoNormal\">This decorative touch adds both flavour and visual appeal, making native citrus a favourite in high-end cuisine.</p>\n<p class=\"MsoNormal\">However, cultivation is not without its challenges.</p>\n"}, {"content": "<p class=\"MsoNormal\">Pests pose a significant challenge to these trees, with certain species of <strong style=\"mso-bidi-font-weight: normal;\"><span style=\"color: red;\">insects</span></strong> like borars and mites causing serious leaf damage.</p>\n<p class=\"MsoNormal\">Farmers often need to monitor their orchards closely and use eco-friendly pest control methods to maintain healthy crops.</p>\n<p class=\"MsoNormal\">That brings us to the end of our overview.</p>\n<p class=\"MsoNormal\">As you can see, Australia’s native citrus species offer a mix of culinary richness, ecological uniqueness and agricultural complexity.</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('1574c537-260c-4dc8-aa85-f547b52d0708', 'c0247014-9198-4a16-9bbe-34a54aedee30', 'fillup', 'Questions 15 – 20', '<p>Complete the sentences below</p>
<p>Choose <strong>NO MORE THAN TWO WORDS AND/OR A NUMBER </strong>from the text each answer</p>
<p>Write your answers in boxes 15-20 on your answer sheet</p>
<p>The length of time and nature of work you can do is dependent on {your age}</p>
<p>There are {restrictions} on the number of hours, a young worker can be made to work in the week</p>
<p>If you have to be {on call} you may receive payment for other breaks as well as rest breaks</p>
<p>A young person must be given a rest break of {thirty minutes} after working a certain number of hours.</p>
<p>Daily rest should be a minimum of 12 hours and will be {uninterrupted} in most cases.</p>
<p>The only time when your breaks can be shortened is if there are {exceptional circumstances}</p>', '', 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p><strong data-path-to-node=\"4\" data-index-in-node=\"0\">15. The length of time and nature of work you can do is dependent on {your age}.</strong></p>\n<ul data-path-to-node=\"5\">\n<li><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"11\">“The number of hours you can work and the types of jobs you can do are <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"82\">determined by your age</strong>.”</em></li>\n<li><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Length of time” tương ứng với “number of hours”, “nature of work” tương ứng với “types of jobs”. Cụm từ “determined by” đồng nghĩa với “is dependent on” (phụ thuộc vào/được quyết định bởi).</li>\n</ul>\n<p><strong data-path-to-node=\"6\" data-index-in-node=\"0\">16. There are {restrictions} on the number of hours, a young worker can be made to work in the week.</strong></p>\n<ul data-path-to-node=\"7\">\n<li><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"11\">“…the employer is not allowed to ignore these <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"59\">restrictions</strong> [8 hours per day or 40 hours per week].”</em></li>\n<li><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc đưa ra các giới hạn về giờ làm (8h/ngày, 40h/tuần) và gọi chúng là các <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"91\">restrictions</strong> (sự hạn chế/quy định thắt chặt).</li>\n</ul>\n<p><strong data-path-to-node=\"8\" data-index-in-node=\"0\">17. If you have to be {on call} you may receive payment for other breaks as well as rest breaks.</strong></p>\n<ul data-path-to-node=\"9\">\n<li><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"11\">“Daily and weekly rest is almost never paid, <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"56\">unless you are on call</strong>.”</em></li>\n<li><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Thông thường các kỳ nghỉ dài (daily/weekly rest) không được trả lương, nhưng có một ngoại lệ là khi bạn ở trạng thái sẵn sàng làm việc khi có yêu cầu (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"163\">on call</strong>).</li>\n</ul>\n<p><strong data-path-to-node=\"10\" data-index-in-node=\"0\">18. A young person must be given a rest break of {thirty minutes} after working a certain number of hours.</strong></p>\n<ul data-path-to-node=\"11\">\n<li><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"11\">“Young workers who need to work for more than four and a half hours will get a rest break <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"101\">lasting 30 minutes</strong>…”</em></li>\n<li><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “A certain number of hours” ở đây là 4.5 tiếng. Sau khoảng thời gian này, họ phải được nghỉ giải lao <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"113\">30 phút</strong>.</li>\n</ul>\n<p><strong data-path-to-node=\"12\" data-index-in-node=\"0\">19. Daily rest should be a minimum of 12 hours and will be {uninterrupted} in most cases.</strong></p>\n<ul data-path-to-node=\"13\">\n<li><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"11\">“…you normally get 12 <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"35\">uninterrupted</strong> hours’ rest in each 24-hour period…”</em></li>\n<li><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “In most cases” tương ứng với “normally”. Khoản nghỉ ngơi 12 tiếng này thường phải diễn ra liên tục, không bị ngắt quãng (<strong data-path-to-node=\"13,1,0\" data-index-in-node=\"134\">uninterrupted</strong>).</li>\n</ul>\n<p><strong data-path-to-node=\"14\" data-index-in-node=\"0\">20. The only time when your breaks can be shortened is if there are {exceptional circumstances}.</strong></p>\n<ul data-path-to-node=\"15\">\n<li><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"15,0,0\" data-index-in-node=\"11\">“Your breaks and daily rest can only be reduced or excluded in <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"74\">exceptional circumstances</strong>.”</em></li>\n<li><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Shortened” (bị rút ngắn) đồng nghĩa với “reduced”. Điều này chỉ xảy ra trong những tình huống đặc biệt (<strong data-path-to-node=\"15,1,0\" data-index-in-node=\"117\">exceptional circumstances</strong>).</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('6a2d091e-9d9b-4034-b9b4-eff30947494d', '448b0593-6eed-4d20-be08-768265eb3048', 'fillup', 'Questions 4–7', '<p data-start="555" data-end="580">Complete the table below.</p>
<p data-start="582" data-end="640">Choose <strong data-start="589" data-end="606">ONE WORD ONLY</strong> from the passage for each answer.</p>
<table style="border-collapse: collapse; width: 99.999%; height: 137.246px;" border="1"><colgroup><col style="width: 24.9774%;"><col style="width: 24.9774%;"><col style="width: 24.9774%;"><col style="width: 24.9774%;"></colgroup>
<tbody>
<tr style="height: 36.4062px;">
<td style="text-align: center;" colspan="4"><span style="font-size: 12pt;"><strong>Intensive farming versus aeroponic urban farming</strong></span></td>
</tr>
<tr style="height: 33.6133px;">
<td> </td>
<td style="text-align: center;">Growth</td>
<td style="text-align: center;">Selection</td>
<td style="text-align: center;">Sale</td>
</tr>
<tr style="height: 33.6133px;">
<td><strong>Intensive farming</strong></td>
<td>
<p>• wide range of {pesticides} used</p>
<p>• techniques pollute air</p>
</td>
<td>
<p>• quality not good</p>
<p>• varieties of fruit and vegetables chosen that can survive long {journeys}</p>
</td>
<td>• {producers} receive very little of overall income</td>
</tr>
<tr style="height: 33.6133px;">
<td><strong>Aeroponic urban farming</strong></td>
<td>
<p>• no soil used</p>
<p>• nutrients added to water, which is recycled</p>
</td>
<td>• produce chosen because of its {flavour|flavor}</td>
<td> </td>
</tr>
</tbody>
</table>
<p data-start="642" data-end="695"> </p>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', 'null', 1);
INSERT INTO public.questions VALUES ('0ee26dac-65c3-491e-a2a6-521919968dcf', 'e1e1482a-3e84-4eee-82e2-f3ea4a9b352f', 'fillup', 'Questions 23-26', '<div class="quests-inner-desc">
<div class="txt">
<p>Complete the sentences below.</p>
<p>Write <strong>NO MORE THAN TWO WORDS</strong> from the passage for each answer.</p>
</div>
</div>
<div class="quests-des">
<div class="content-write">
<p>It is a great mystery that young birds like cuckoos can find their wintering grounds without {parental guidance}</p>
<p>Evidence shows birds can tell directions like a {compass} by observing the sun and the stars.</p>
<p>One advantage for birds flying at night is that they can avoid contact with {daytime predators}</p>
<p>Laboratory tests show that birds can detect weather without {visible} signs.</p>
</div>
</div>', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"1\">Câu 23: parental guidance</h3>\n<ul data-path-to-node=\"2\">\n<li><strong data-path-to-node=\"2,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 4, dòng 1-2.</li>\n<li><strong data-path-to-node=\"2,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “One of the greatest mysteries is how young birds know how to find the traditional wintering areas without <strong data-path-to-node=\"2,1,0\" data-index-in-node=\"118\">parental guidance</strong>.”</li>\n<li><strong data-path-to-node=\"2,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc nêu rõ một trong những bí ẩn lớn nhất là làm thế nào những con chim non như chim cúc cu có thể tìm thấy nơi tránh rét mà không cần sự “hướng dẫn của bố mẹ” (parental guidance).</li>\n</ul>\n<h3 data-path-to-node=\"3\">Câu 24: compass</h3>\n<ul data-path-to-node=\"4\">\n<li><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 5, dòng 1-2.</li>\n<li><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Mounting evidence has confirmed that birds use the positions of the sun and stars to obtain <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"104\">compass</strong> directions.”</li>\n<li><strong data-path-to-node=\"4,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Các bằng chứng cho thấy chim sử dụng vị trí của mặt trời và các vì sao để xác định phương hướng giống như một chiếc “lạt bàn” (compass).</li>\n</ul>\n<h3 data-path-to-node=\"5\">Câu 25: daytime predators</h3>\n<ul data-path-to-node=\"6\">\n<li><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 5, dòng 15-16.</li>\n<li><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “<strong data-path-to-node=\"6,1,0\" data-index-in-node=\"12\">Daytime predators</strong> are avoided and the danger of dehydration… is reduced.”</li>\n<li><strong data-path-to-node=\"6,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Một trong những lợi ích của việc bay vào ban đêm là chim có thể tránh được sự tiếp xúc hoặc tấn công từ các “động vật săn mồi ban ngày” (daytime predators).</li>\n</ul>\n<h3 data-path-to-node=\"7\">Câu 26: visible</h3>\n<ul data-path-to-node=\"8\">\n<li><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 6, dòng 4-5.</li>\n<li><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Often birds react to weather changes before there is any <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"69\">visible</strong> sign of them.”</li>\n<li><strong data-path-to-node=\"8,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Các bài kiểm tra trong phòng thí nghiệm và quan sát thực tế cho thấy chim có phản ứng với sự thay đổi thời tiết ngay cả khi chưa có bất kỳ dấu hiệu “có thể nhìn thấy được” (visible) nào.</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('d55fd397-eda2-4647-a362-8a725685598c', 'a3611f3d-1993-46d2-961c-4d320a323d1d', 'fillup', 'Questions 31–40', '<div class="quests-inner-desc">
<div class="txt">
<p>Write<strong> ONE WORD ONLY </strong>for each answer.</p>
</div>
</div>
<div class="quests-des">
<div class="content-write">
<p class="ql-align-center" style="text-align: center;"><strong>RESEARCH ON BIRDS IN AUSTRALIA</strong></p>
<p><strong>The study Cunningham in 1995</strong></p>
<p>– It aimed to study birds which were {protected} in cities.</p>
<p><strong>Methodology</strong></p>
<p>– Researchers were able to {estimate} rather than count the number of birds by some methods, such as random sampling.</p>
<p>– Research studied bird’s companionship habits using a {mapping} system.</p>
<p>– Research attached tags to birds’ legs to identify their {trends}<span class="fill-history-correct"> </span>over time.</p>
<p><strong>Findings</strong></p>
<p>– Birds tended to choose the same nesting site in which they were raised.</p>
<p>– Human activities such as {pollution} had a negative effect on the reproduction of birds.</p>
<p><strong>Measures taken by local organisation:</strong></p>
<p>– To increase birds’ rate of {survival} in various ways.</p>
<p>– To reduce the dangers caused by {wind} farms, e.g. colliding with turbines.</p>
<p><strong>The study by Conway in 2006</strong></p>
<p>– Researchers monitored the {frequency} of birds’ nocturnal callings during flight.</p>
<p>– {recordings}<strong> </strong>were taken to listening to birds’ sounds.</p>
<p>– Data could be collected through noise detection devices placed at a great {distance}</p>
</div>
</div>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"2\">PART 4: BIRD RESEARCH IN AUSTRALIA</h3>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Lecturer:</strong> Good afternoon. This is the <span class=\"citation-1299 citation-1300 citation-end-1300\">third session of the series of lectures on wildlife. For this lecture, we’re going to look at two studies on the habitats of birds and protection measures taken in Australia, including the basic methodology and rela</span><span class=\"citation-1299 citation-end-1299\">ted areas of resear</span>ch.</p>\n<div class=\"source-inline-chip-container ng-star-inserted\"></div>\n<p>&nbsp;</p>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Lecturer:</strong> Now <span class=\"citation-1298 citation-end-1298\">let me give you some background information about the first research project on birds. The study was carried out by R. B. Cunningham and his team from the Australian National University in 1995. The primary goal was to detect the breeding ha</span>bits and resting sites of some birds, especially those <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"4\" data-index-in-node=\"310\">(31) protected</strong></span> species in urban regions. These species included birds like peregrine falcons and kestrels in Australia.</p>\n<div class=\"source-inline-chip-container ng-star-inserted\"></div>\n<p>&nbsp;</p>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">Lecturer:</strong> <span class=\"citation-1296 citation-1297 citation-end-1297\">The bird data set consisted of a total of 153 species recorded from 946 sites. One might expect that in order to obtain valid data on their distribution patterns and population densities, researchers had to count through binoculars</span><span class=\"citation-1296 citation-end-1296\">. Instead, they managed to</span> <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"5\" data-index-in-node=\"268\">(32) estimate</strong></span> with various standard distance sampling methods like random sampling.</p>\n<div class=\"source-inline-chip-container ng-star-inserted\"></div>\n<p>&nbsp;</p>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">Lecturer:</strong> In addition, a <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"6\" data-index-in-node=\"25\">(33) mapping</strong></span> system was used to study their companionship behaviour. It recorded proposed birds’ nesting sites to monitor the mating behavior <span class=\"citation-1295\">of targeted species. To obtain valid data of birds’ whereabouts, researchers attached identity tags to birds’ </span><span class=\"citation-1294 citation-1295 citation-end-1295\">legs transmitting radio signals. The tagging process was done when the birds were between five and seven days of ag</span><span class=\"citation-1294\">e. After the initial tagging, data was collected from subsets of radio-tagged birds, making it possible to assess the </span><span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"6\" data-index-in-node=\"510\"><span class=\"citation-1294 citation-end-1294\">(</span>34) trends</strong></span> of birds over 15 months.</p>\n<div class=\"source-inline-chip-container ng-star-inserted\"></div>\n<p>&nbsp;</p>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Lecturer:</strong> So what did they find? Well, as it turned out, many of the birds tagged had the tendency to nest in the same habitat where they grew up. Their nesting sites were quite varied and included freshwater reed beds, tidal reed beds, agricultural crops and man-made sites. Even though naturally occurring nests were common, birds sometimes accidentally nested in man-made devices like power towers, chimneys and tunnels.</p>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">Lecturer:</strong> This research also studied the impact of humans on bird communities and found out that <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"8\" data-index-in-node=\"97\">(35) <span class=\"citation-1292 citation-1293\">pollution</span></strong></span><span class=\"citation-1292 citation-1293 citation-end-1293\"> had contributed greatly to the declining birth rates of some species which were considered to be extinct or threatened to vanish from the study area. These species are dependent on natural forests because of their breeding holes; they will become extinct when local natural for</span><span class=\"citation-1292 citation-end-1292\">ests continue to be polluted heav</span>ily.</p>\n<div class=\"source-inline-chip-container ng-star-inserted\"></div>\n<p>&nbsp;</p>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Lecturer:</strong> A number of measures were thus taken by members from local animal conservation organizations to boost their alarming <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"9\" data-index-in-node=\"127\">(36) <span class=\"citation-1291\">survival</span></strong></span><span class=\"citation-1291 citation-end-1291\"> rates. Firstly, breeding boxes were placed in trees, taking on the role of breeding holes that were contaminated. Protection guidelines were also introduced strictly prohibiting killing, disturbance and habitat destruction</span>.</p>\n<div class=\"source-inline-chip-container ng-star-inserted\"></div>\n<p>&nbsp;</p>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">Lecturer:</strong> A further measure was taken to ensure the safety of birds from <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"10\" data-index-in-node=\"73\">(37) wind</strong></span> farms. In fact, birds are sometimes shed <span class=\"citation-1288 citation-1289 citation-1290 citation-end-1290\">by wind turbine blades. A great deal of work was done on how to prevent them from colliding with turbines. A case in point was protecting space for bird migration by ensuring that migratory routes were kept free. Falcons generally cope well with wind turbines but not in weather conditions where visibility is b</span><span class=\"citation-1288 citation-1289 citation-end-1289\">ad. So with knowledge of how fast falcons fly, bird stations in northern Australia can notify wind farms further south of the falcons’ approach so that turbines can be shut </span><span class=\"citation-1288 citation-end-1288\">down as they pass by.</span></p>\n<div class=\"source-inline-chip-container ng-star-inserted\"></div>\n<p>&nbsp;</p>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Lecturer:</strong> Then another piece of research was done a couple of years later by Conway in 2006. His team detected the calling <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"11\" data-index-in-node=\"123\">(38) frequency</strong> </span>of seabirds <span class=\"citation-1287 citation-end-1287\">flying at night. Acoustic signals are important communication tools for birds. These signals can indicate social cohesion, prey location and breeding behavior. Courtship songs are common among various species during mating seaso</span>ns.</p>\n<div class=\"source-inline-chip-container ng-star-inserted\"></div>\n<p>&nbsp;</p>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">Lecturer:</strong> Surveyors also took <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"12\" data-index-in-node=\"30\">(39) <span class=\"citation-1286\">recordings</span></strong></span><span class=\"citation-1286 citation-end-1286\"> of the sounds of all the individual birds detected. A tablet PC was used to process detailed information like sound pitch, spectrum length and timing of surveys. To minimize the disturbance on the bird comm</span>unity, all the sounds were recorded from a <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"12\" data-index-in-node=\"295\">(40) distance</strong></span> using microphones to detect noise.</p>\n<div class=\"source-inline-chip-container ng-star-inserted\"></div>\n<p>&nbsp;</p>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">Lecturer:</strong> They found that the <span class=\"citation-1285 citation-end-1285\">probability of call events was much higher for solitary birds communicating early and late in the day. Further analyses indicated that during foraging, the frequency of calls was significantly greater for birds encountering schoolin</span>g fish. The results of this study showed that increased calling activity in the presence of more profitable prey could be of crucial importance to seabirds that benefit from group foraging.</p>\n<div class=\"source-inline-chip-container ng-star-inserted\"></div>\n<p>&nbsp;</p>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">Lecturer:</strong> So, does anyone have more questions on…</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('e15baebf-8cee-433b-a76e-f03dfa54c1a4', '110c3482-1cc7-4e36-96f6-0f1a64319db7', 'matching', 'Questions 32–35', NULL, '<p>Complete the summary using the list of words and phrases, <strong>A–I</strong>, below.</p>
<p>Write the correct letter, <strong>A–I</strong>, in boxes 32–35 on your answer sheet.</p>
', 'matching', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p><span style=\"font-size: 12pt;\"><strong>Theories about Mahy’s style</strong></span></p>\n<p>Mahy’s determination to earn a living from writing has encouraged her to find the ideas for her work in {B everyday} places. The stories themselves are set in locations that are {E exotic and ordinary} . In terms of characterisation, almost all of her books feature unruly people, and very often an adolescent who possesses {I magical} abilities. Finally, the endings of the stories tend to be {H unsurprising but satisfying} .</p>", "answerOptions": [{"optionText": "A disruptive and unpredictable"}, {"optionText": "B everyday"}, {"optionText": "C loveable"}, {"optionText": "D controversial"}, {"optionText": "E exotic and ordinary"}, {"optionText": "F isolated"}, {"optionText": "G unconfident"}, {"optionText": "H unsurprising but satisfying"}, {"optionText": "I magical"}], "matchingItems": null}', 'null', '[{"content": "<p><strong>32. Mahy’s determination to earn a living from writing has encouraged her to find the ideas for her work in B. everyday places.</strong></p>\n<ul data-path-to-node=\"16\">\n<li><strong>Đáp án:</strong> <strong>B (everyday)</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 2) &#8220;&#8230;it has been a matter of going out and finding inspiration from <strong>her immediate environment</strong>: the writing on the side of a bus; a spelling mistake in a note to herself&#8230;&#8221;</li>\n<li><strong>Giải thích:</strong> &#8220;Immediate environment&#8221; (môi trường xung quanh trực tiếp) và các ví dụ (xe buýt, lỗi chính tả) cho thấy bà lấy ý tưởng từ những nơi <strong>hàng ngày</strong> (<strong>everyday</strong>).</li>\n</ul>\n<p><strong>33. The stories themselves are set in locations that are  E. exotic and ordinary.</strong></p>\n<ul data-path-to-node=\"18\">\n<li><strong>Đáp án:</strong> <strong>E (exotic and ordinary)</strong></li>\n<li><strong><span class=\"citation-7\">Dẫn chứng:</span></strong><span class=\"citation-7\"> (Đoạn 2) &#8220;&#8230;the settings for her stories are delightfully varied, as these books celebrate the dramatic plot twists and unpredictability of adventures on the </span><strong><span class=\"citation-7\">high seas or in Antarctica</span></strong><span class=\"citation-7\">, and also in quite </span><strong><span class=\"citation-7\">unassuming places like the library or even down the back of a chair at home</span></strong><span class=\"citation-7 citation-end-7\">.&#8221;</span></li>\n<li><strong>Giải thích:</strong> Các địa điểm bao gồm những nơi xa lạ (high seas/Antarctica &#8211; <strong>exotic</strong>) và những nơi quen thuộc (library/back of a chair &#8211; <strong>ordinary</strong>).</li>\n</ul>\n<p><strong>34. &#8230;and very often an adolescent who possesses  I. magical abilities.</strong></p>\n<ul data-path-to-node=\"20\">\n<li><strong>Đáp án:</strong> <strong>I (magical)</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 3) &#8220;Her fictions often have at their heart a young adult burdened with <strong>special powers, such as the ability to cast spells</strong>&#8230;&#8221;</li>\n<li><strong>Giải thích:</strong> &#8220;Special powers&#8221; và khả năng &#8220;cast spells&#8221; (yểm bùa) là những khả năng <strong>phép thuật</strong> (<strong>magical</strong>).</li>\n</ul>\n<p><strong>35. Finally, the endings of the stories tend to be H. unsurprising but satisfying.</strong></p>\n<ul data-path-to-node=\"22\">\n<li><strong>Đáp án:</strong> <strong>H (unsurprising but satisfying)</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 3) &#8220;&#8230;while the conclusions of her tales are usually <strong>predictable</strong>, they leave the reader feeling <strong>absolutely complete</strong>&#8230;&#8221;</li>\n<li><strong>Giải thích:</strong> &#8220;Predictable&#8221; đồng nghĩa với <strong>unsurprising</strong>, và &#8220;absolutely complete&#8221; đồng nghĩa với <strong>satisfying</strong>.</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('e4570a41-f06c-44ca-8420-ba3979b756cf', '13d9b396-732d-4205-bc1f-b1b99d9f7ed1', 'fillup', 'Questions 31–40', '<div class="quests-inner-desc">
<div class="txt">
<p>Write <strong>ONE WORD ONLY </strong>for each answer.</p>
</div>
</div>
<div class="quests-des">
<div class="content-write">
<p class="ql-align-center" style="text-align: center;"><strong>Crocodile Study</strong></p>
<p><strong>Background</strong></p>
<p>– Type of crocodile studied: crocodiles found in salt water</p>
<p>– Location of study: Northern Territory, Australia</p>
<p>– Significance of study: unique because it was the first time a {satellite} had been used to track crocodiles</p>
<p><strong>Previous studies:</strong></p>
<p>– done using {radio}</p>
<p>– stressful method, also unreliable due to loss of the {signal}</p>
<p><strong>Reasons for study: </strong>the management of crocodiles by the government may not be effective</p>
<p><strong>Research questions:</strong></p>
<p>– How far can crocodiles travel?</p>
<p>– How easily can crocodiles {navigate}?</p>
<p><strong>Challenge: </strong>crocodiles are difficult to observe because they avoid {people}</p>
<p><strong>Details of study:</strong></p>
<p>– number of crocodiles involved: three</p>
<p>– method: crocodiles were measured and Tagged hen relocated using a {helicopter}</p>
<p>– monitoring: scientists got data from a transmitter located on the crocodile’s {head}</p>
<p><strong>Results of study:</strong></p>
<p>– Each crocodile</p>
<p>– first stayed at the site for a few weeks, moving in a random way</p>
<p>– then took the most {direct} way home</p>
<p><strong>Conclusions:</strong></p>
<p>– a change in policy is needed</p>
<p>– when travelling long distances, crocodiles may use</p>
<p>i. their own senses and the position of the {sun}</p>
<p>ii. a similar system to {birds}</p>
</div>
</div>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<h2 data-path-to-node=\"2\">PART 4</h2>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Lecturer:</strong> Hello everybody. I’ve just arrived back from my field trip and Professor Martin has asked me to tell you about it today in our research forum. As many of you know already, my dissertation relates to crocodile behaviour. My specialty is the saltwater crocodile, which is much larger than the freshwater crocodile.</p>\n<p data-path-to-node=\"4\">I’ve just come back from the Northern Territory where I’ve been part of a groundbreaking study observing crocodile movements. Ah, it’s not the only time crocodile movements have been followed, but this study is unique because we tracked crocodiles using a <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"4\" data-index-in-node=\"256\">(31) satellite</strong></span>. Up until now, studies like this one have only been able to track crocodile movements using <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"4\" data-index-in-node=\"363\">(32) radio</strong></span>. Not only was this method more stressful for the animal, which had to be caught several times, but it was also not very reliable as the <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"4\" data-index-in-node=\"510\">(33) signal</strong></span> was often lost.</p>\n<p data-path-to-node=\"5\">So you might be wondering why we chose to track crocodiles. Well, crocodile attacks on people and livestock are rare, but when they do happen, the government believes that the “problem” crocodile should be relocated rather than killed. But can we be sure that the crocodile won’t simply return to the place where it came from?</p>\n<p data-path-to-node=\"6\">So we designed a study to try to answer these questions. We wanted to establish firstly how far crocodiles can travel over a period of time. The second thing that we wanted to know was how easy is it for crocodiles to <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"6\" data-index-in-node=\"218\">(34) navigate</strong></span>? Could they find their own way home again if they were moved to another location? Of course, the biggest challenge when observing crocodiles is that they are very secretive animals. They stay well away from <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"6\" data-index-in-node=\"439\">(35) people</strong></span> if they can, which makes them really difficult to follow.</p>\n<p data-path-to-node=\"7\">I’ll give you some information about the design of the study now. There were three crocodiles in our study, all from the Northern Territory and measuring between 3 and 4.5 meters in length. The crocodiles were captured, measured and tagged, and then taken by <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"7\" data-index-in-node=\"259\">(36) helicopter</strong></span> to new locations up to 400 km away from where they were found.</p>\n<p data-path-to-node=\"8\">We were then able to use the tracking data to monitor their movements. We used a specially designed transmitter which we attached to each animal’s <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"8\" data-index-in-node=\"147\">(37) head</strong></span>. The transmitter collected the data and relayed it back to us.</p>\n<p data-path-to-node=\"9\">The results of our study were quite astounding. After they were released, each crocodile remained in the release site for some weeks, making random movements around the site each day. But then they each swam home, traveling by the most <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"9\" data-index-in-node=\"236\">(38) direct</strong></span> route. These crocodiles showed remarkable navigational skills and stamina to swim such long voyages.</p>\n<p data-path-to-node=\"10\">So what conclusions did we draw from this? Well, we proved that crocodiles are clearly capable of making marathon swims to find their way home. This meant that the current policy should be reconsidered.</p>\n<p data-path-to-node=\"11\">You might be wondering how the crocodiles managed to get home. We concluded that they used factors such as sight and smell, as well as their position to the <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"11\" data-index-in-node=\"157\">(39) sun</strong></span> to point their way. It’s a little-known fact that crocodiles are more closely related to <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"11\" data-index-in-node=\"255\">(40) birds</strong></span> than they are to any other reptile, so we believe it’s possible that they use the same system to negotiate long journeys. Now that the study has been completed…</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('18fd6572-7585-4dec-af42-5bff0db09ad5', 'e204614c-0476-4f25-9ff9-bf6839e25159', 'fillup', 'Questions 31–40', '<p class="MsoNormal">Write <strong>ONE WORD ONLY</strong> for each answer.</p>
<p class="MsoNormal" style="text-align: left;" align="center"><strong><span style="font-size: 14.0pt; line-height: 115%;">Science in the Future</span></strong></p>
<p class="MsoNormal" style="line-height: 150%;">Science were asked to predict changes in their own field in the next 50 years</p>
<p class="MsoNormal" style="line-height: 150%;"><strong>Computer science</strong></p>
<p class="MsoListParagraphCxSpFirst" style="text-indent: -.25in; line-height: 150%; mso-list: l1 level1 lfo1;"><!-- [if !supportLists]--><span style="font-family: Symbol; mso-fareast-font-family: Symbol; mso-bidi-font-family: Symbol;"><span style="mso-list: Ignore;">–<span style="font: 7.0pt ''Times New Roman'';">        </span></span></span><!--[endif]-->The invention of computers is as significant as the discovery of how to create and use {fire}</p>
<p class="MsoListParagraphCxSpLast" style="text-indent: -.25in; line-height: 150%; mso-list: l1 level1 lfo1;"><!-- [if !supportLists]--><span style="font-family: Symbol; mso-fareast-font-family: Symbol; mso-bidi-font-family: Symbol;"><span style="mso-list: Ignore;">–<span style="font: 7.0pt ''Times New Roman'';">        </span></span></span><!--[endif]-->Computer will be seen as being {intelligent}</p>
<p class="MsoNormal" style="line-height: 150%;"><strong>Psychology</strong></p>
<p class="MsoListParagraphCxSpFirst" style="text-indent: -.25in; line-height: 150%; mso-list: l0 level1 lfo2;"><!-- [if !supportLists]--><span style="font-family: Symbol; mso-fareast-font-family: Symbol; mso-bidi-font-family: Symbol;"><span style="mso-list: Ignore;">–<span style="font: 7.0pt ''Times New Roman'';">        </span></span></span><!--[endif]-->Research will become much more {varied} , and also more practical since more {women} will be working in the field.</p>
<p class="MsoListParagraphCxSpLast" style="text-indent: -.25in; line-height: 150%; mso-list: l0 level1 lfo2;"><!-- [if !supportLists]--><span style="font-family: Symbol; mso-fareast-font-family: Symbol; mso-bidi-font-family: Symbol;"><span style="mso-list: Ignore;">–<span style="font: 7.0pt ''Times New Roman'';">        </span></span></span><!--[endif]-->Imaging devices will give information about the behaviour of the {brain}.</p>
<p class="MsoNormal" style="line-height: 150%;"><strong>Genetics</strong></p>
<p class="MsoListParagraphCxSpFirst" style="text-indent: -.25in; line-height: 150%; mso-list: l3 level1 lfo3;"><!-- [if !supportLists]--><span style="font-family: Symbol; mso-fareast-font-family: Symbol; mso-bidi-font-family: Symbol;"><span style="mso-list: Ignore;">–<span style="font: 7.0pt ''Times New Roman'';">        </span></span></span><!--[endif]-->With increased life expectancy, it is important to consider the {quality} of elderly people’s lives.</p>
<p class="MsoListParagraphCxSpMiddle" style="text-indent: -.25in; line-height: 150%; mso-list: l3 level1 lfo3;"><!-- [if !supportLists]--><span style="font-family: Symbol; mso-fareast-font-family: Symbol; mso-bidi-font-family: Symbol;"><span style="mso-list: Ignore;">–<span style="font: 7.0pt ''Times New Roman'';">        </span></span></span><!--[endif]-->Knowledge of a person’s genome will indicate whether they are likely to be affected by a {disease} .</p>
<p class="MsoListParagraphCxSpLast" style="text-indent: -.25in; line-height: 150%; mso-list: l3 level1 lfo3;"><!-- [if !supportLists]--><span style="font-family: Symbol; mso-fareast-font-family: Symbol; mso-bidi-font-family: Symbol;"><span style="mso-list: Ignore;">–<span style="font: 7.0pt ''Times New Roman'';">        </span></span></span><!--[endif]-->The approach to treatment will be on an increasingly {personal} basis.</p>
<p class="MsoNormal" style="line-height: 150%;"><strong>Zoology</strong></p>
<p class="MsoListParagraphCxSpFirst" style="text-indent: -.25in; line-height: 150%; mso-list: l2 level1 lfo4;"><!-- [if !supportLists]--><span style="font-family: Symbol; mso-fareast-font-family: Symbol; mso-bidi-font-family: Symbol;"><span style="mso-list: Ignore;">–<span style="font: 7.0pt ''Times New Roman'';">        </span></span></span><!--[endif]-->People can explore the world via satellite.</p>
<p class="MsoListParagraphCxSpMiddle" style="text-indent: -.25in; line-height: 150%; mso-list: l2 level1 lfo4;"><!-- [if !supportLists]--><span style="font-family: Symbol; mso-fareast-font-family: Symbol; mso-bidi-font-family: Symbol;"><span style="mso-list: Ignore;">–<span style="font: 7.0pt ''Times New Roman'';">        </span></span></span><!--[endif]-->For example, it is possible to see the effects of the destruction of {forests} in East Africa.</p>
<p class="MsoListParagraphCxSpLast" style="text-indent: -.25in; line-height: 150%; mso-list: l2 level1 lfo4;"><!-- [if !supportLists]--><span style="font-family: Symbol; mso-fareast-font-family: Symbol; mso-bidi-font-family: Symbol;"><span style="mso-list: Ignore;">–<span style="font: 7.0pt ''Times New Roman'';">        </span></span></span><!--[endif]-->Such increased awareness should enable us to do more to look after the {planet}</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<h2 data-path-to-node=\"2\">PART 4</h2>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Lecturer:</strong> In this final lecture of our course on the history of science, I would like to look to the future and tell you about some predictions that have been made about scientific developments. The content for my talk is based on some research in which 30 scientific leaders were invited to comment on the developments that they envisage as likely to come about in their own discipline within 50 years. After summarizing some of their most interesting contributions for you, I’ll ask you to give me your opinions as to the likelihood of these changes occurring within this timescale. You may also like to suggest some other likely changes yourselves.</p>\n<p data-path-to-node=\"4\">So first, let’s start with <strong data-path-to-node=\"4\" data-index-in-node=\"27\">computer science</strong>, as this is clearly an area where there are bound to be dramatic developments. And even more significantly perhaps, these developments are likely to impact on every other field of learning. The invention of computers represents an enormous leap forward in the field of human endeavour. It could indeed be considered as being as momentous a development as when our predecessors in caves first learned to make <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"4\" data-index-in-node=\"452\">(31) fire</strong></span> and use it for all sorts of purposes. In the future, the computational revolution is certain to be generally recognized as a transformation as significant as, say, the Industrial Revolution.</p>\n<p data-path-to-node=\"5\">The computer scientists in the study I referred to felt that in the coming decades lives will be significantly enhanced by automated reasoning systems of different types. There was considerable agreement that people will increasingly perceive these computer systems as <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"5\" data-index-in-node=\"269\">(32) intelligent</strong>,</span> although many of these <span class=\"citation-177 citation-end-177\">will be deployed behind the scenes; others will be in the foreground serving in an elegant, often collaborative manner to help people do their jobs, to learn and teach, to reflect and remember, to plan and d</span>ecide.</p>\n<div class=\"source-inline-chip-container ng-star-inserted\"></div>\n<p data-path-to-node=\"6\">Without going into further detail about this at this point, let’s turn to what predictions <strong data-path-to-node=\"6\" data-index-in-node=\"91\">psychologists</strong> had to make. Their key point was that psychological research would inevitably become increasingly <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"6\" data-index-in-node=\"203\">(33) varied</strong></span>. It would move into such areas as behavioral economics and social neuroscience. There is likely to be further expansion into domains with more practical relevance. As increasing numbers of <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"6\" data-index-in-node=\"404\">(34) women</strong></span> become research scientists, so areas such as health, environment, family and social identity will receive more attention. At the same time as they broaden their horizons, psychologists will also intensify their search to discover what exactly determines how we act. They will be assisted in this by imaging devices that will be inserted into the <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"6\" data-index-in-node=\"761\">(35) brain</strong></span> and provide a great deal of information about how it behaves. There should be some fascinating discoveries coming to light very soon.</p>\n<p data-path-to-node=\"7\">Another field that is currently undergoing enormous changes is that of <strong data-path-to-node=\"7\" data-index-in-node=\"71\">genetics</strong>. It is not new to suggest that average life expectancy is likely to continue rising in most countries. However today, geneticists emphasize that it is vital that the increasing number of the elderly in society must take <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"7\" data-index-in-node=\"300\">(36) quality</strong></span> of life into account. So how will genetics help this to happen?</p>\n<p data-path-to-node=\"8\">To start with, they hope to develop technologies that can sequence each person’s genome extremely cheaply. This information about our DNA enables healthcare providers to predict our likelihood of suffering from any particular <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"8\" data-index-in-node=\"226\">(37) disease</strong></span>. From there on, it is a matter of weighing up various factors with a view to determining what can be done to minimize each individual’s level of risk. With such information in hand, new treatments will be developed and the current “one size fits all” approach to healthcare will give way to a more <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"8\" data-index-in-node=\"537\">(38) personal</strong></span> approach.</p>\n<p data-path-to-node=\"9\">The final subject area that I wish to bring to your attention is that of <strong data-path-to-node=\"9\" data-index-in-node=\"73\">zoology</strong>. Once again, computers and technology have a key role to play here. Experts comment specifically on the importance of satellites for future developments in this field. These enable people to explore the world from their homes, offices and schools. It is now possible, for instance, to go online and see for yourself the abundant wildlife in one part of East Africa and, in the surrounding region, the harm people have done by destroying the <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"9\" data-index-in-node=\"522\">(39) forests</strong></span>, all supposedly in the name of development. Zoologists believe the breakthrough that lies ahead is how people act on such information as this. They hope that we will learn to connect our minds to our hearts and apply this knowledge to help protect our <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"9\" data-index-in-node=\"787\">(40) planet</strong>.</span> They express a clear hope that a greater understanding of the consequences of human short-sightedness will make people anxious to rectify what we can before it is too late.</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('d55b7a08-e2f6-4105-8159-d6f96f0bad0e', 'a69425d0-931c-43f5-ac18-3517566437e6', 'radio', 'Questions 1-6', NULL, '<p>Choose <strong>TRUE </strong>if the statement agrees with the information given in the text, choose <strong>FALSE </strong>if the statement contradicts the information, or choose <strong>NOT GIVEN </strong>if there is no information on this.</p>
', 'multiple_choice_single', '[{"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Bocherens'' findings on cave bears involve measuring the length of complete bones"}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Bocherens was the first person to conduct analytical research on cave bears in a laboratory"}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Cave bears have been extinct for 25,000 years"}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "At one time, people thought the excavated remains of bears were those of dragons"}, {"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Modern grizzly bears are similar in size to cave bears"}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Neanderthals understood cave bear behavior better than modern humans did"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">1. Bocherens’ findings on cave bears involve measuring the length of complete bones.</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"8\">NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “He dissolves 30,000-year-old animal bones in hydrochloric acid… until what’s left is a speck of powder… biography of a cave bear as told through its chemical components.”</p>\n</li>\n<li>\n<p data-path-to-node=\"5,2,0\"><strong data-path-to-node=\"5,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc mô tả rất kỹ quy trình Bocherens dùng hóa chất để biến xương thành bột nhằm phân tích thành phần hóa học (isotopes). Tuy nhiên, bài <strong data-path-to-node=\"5,2,0\" data-index-in-node=\"152\">không đề cập</strong> đến việc ông có đo chiều dài của những khúc xương còn nguyên vẹn hay không.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">2. Bocherens was the first person to conduct analytical research on cave bears in a laboratory.</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"8\">NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Bocherens is at the forefront of research on the bear…”</p>\n</li>\n<li>\n<p data-path-to-node=\"7,2,0\"><strong data-path-to-node=\"7,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả nói Bocherens là người “đi đầu” (<em data-path-to-node=\"7,2,0\" data-index-in-node=\"53\">at the forefront</em>) trong lĩnh vực này, nhưng điều đó không đồng nghĩa với việc ông là người “đầu tiên” (<em data-path-to-node=\"7,2,0\" data-index-in-node=\"156\">the first</em>) thực hiện nghiên cứu trong phòng thí nghiệm.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">3. Cave bears have been extinct for 25,000 years.</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"8\">TRUE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…a European species that died out 25,000 years ago.”</p>\n</li>\n<li>\n<p data-path-to-node=\"9,2,0\"><strong data-path-to-node=\"9,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Thông tin trong câu hỏi khớp hoàn toàn với dẫn chứng trong bài (died out = extinct).</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">4. At one time, people thought the excavated remains of bears were those of dragons.</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"8\">TRUE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…in the Middle Ages, the massive skulls were attributed to dragons…”</p>\n</li>\n<li>\n<p data-path-to-node=\"11,2,0\"><strong data-path-to-node=\"11,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Vào thời Trung cổ, người ta từng cho rằng những hộp sọ khổng lồ khai quật được là của loài rồng.</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">5. Modern grizzly bears are similar in size to cave bears.</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"8\">FALSE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Males weighed up to 1,500 pounds—50% more than the largest modern grizzly bears.”</p>\n</li>\n<li>\n<p data-path-to-node=\"13,2,0\"><strong data-path-to-node=\"13,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Gấu hang nặng hơn 50% so với loài gấu xám lớn nhất hiện nay, vì vậy chúng không thể có kích thước “tương đương” (<em data-path-to-node=\"13,2,0\" data-index-in-node=\"125\">similar</em>) được.</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">6. Neanderthals understood cave bear behavior better than modern humans did.</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"8\">NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Initially, cave bears shared the continent of Europe… with Neanderthals… Modern humans arrived… and were soon aware of the bears.”</p>\n</li>\n<li>\n<p data-path-to-node=\"15,2,0\"><strong data-path-to-node=\"15,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ nói cả người Neanderthal và người hiện đại đều tiếp xúc với loài gấu này, nhưng <strong data-path-to-node=\"15,2,0\" data-index-in-node=\"104\">không có sự so sánh</strong> nào về việc ai hiểu tập tính của chúng tốt hơn.</p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('b53d2742-86cd-4538-9a5e-c2e92c0c4fbe', 'a69425d0-931c-43f5-ac18-3517566437e6', 'fillup', 'Questions 7-13', '<p>Complete the notes below.</p>
<p>Choose <strong>ONE WORD ONLY</strong> from the passage for each answer.</p>
<div class="s-block-item s-repeatable-item s-block-sortable-item s-blog-post-section blog-section">
<div class="container">
<div class="sixteen columns">
<div class="s-blog-section-inner">
<div class="s-component s-text ">
<div class="">
<div class="s-component-content s-font-body" style="text-align: center;"><span style="font-size: 12pt;"><strong>Research into the existence and disappearance of cave bears</strong></span></div>
<div class="s-component-content s-font-body">
<p><strong>Evidence from the Chauvet Cave in France</strong></p>
<ul>
<li>
<p>Paintings on the walls include bears.</p>
</li>
<li>
<p>Over a hundred {skeletons} of cave bears together with paw prints were found on the floor of the cave.</p>
</li>
<li>
<p>The<strong> </strong>{skull} of a cave bear was found in a prominent position in the cave.</p>
</li>
</ul>
<p><strong>Evidence from the Hohle Fels Cave in the Swabian Jura in Germany</strong></p>
<ul>
<li>
<p>Bones and tools found in the cave indicate it provided<strong> </strong>{shelter} for both bears and humans.</p>
</li>
</ul>
<p><strong>Susanne Munzel’s Findings</strong></p>
<ul>
<li>
<p>A spear point in the vertebra of a bear indicates that a hunt had taken place.</p>
</li>
<li>
<p>Marks on the bones of bears indicate the removal of flesh.</p>
</li>
</ul>
<p><strong>Hervé Bocherens’ Findings</strong></p>
<ul>
<li>
<p>Isotopes from the bones indicate that {plants} were the cave bears’ preferred food.</p>
</li>
</ul>
<p><strong>Factors Leading to the Disappearance of the Cave Bear</strong></p>
<p><strong>Climate Change</strong></p>
<ul>
<li>
<p>The Ice Age changed vegetation growth in {Europe}.</p>
</li>
<li>
<p>Bears were forced to migrate.</p>
</li>
<li>
<p>Support for the above explanation comes from a study of changes in the DNA in the {teeth} of the population of cave bears near the Danube River at this time.</p>
</li>
</ul>
<p><strong>Human Population Expansion</strong></p>
<ul>
<li>
<p>Competition from Neanderthals and modern humans for caves may have reduced opportunities for cave bears to {hibernate}.</p>
</li>
</ul>
</div>
</div>
</div>
</div>
</div>
</div>
</div>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">7. skeletons</strong></p>\n<ul data-path-to-node=\"19\">\n<li>\n<p data-path-to-node=\"19,0,0\"><strong data-path-to-node=\"19,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…the floor is covered with 150 cave bear <strong data-path-to-node=\"19,0,0\" data-index-in-node=\"55\">skeletons</strong>…” (Đoạn 6)</p>\n</li>\n<li>\n<p data-path-to-node=\"19,1,0\"><strong data-path-to-node=\"19,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Sàn hang Chauvet có tới 150 bộ xương gấu hang.</p>\n</li>\n</ul>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">8. skull</strong></p>\n<ul data-path-to-node=\"21\">\n<li>\n<p data-path-to-node=\"21,0,0\"><strong data-path-to-node=\"21,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…a cave bear <strong data-path-to-node=\"21,0,0\" data-index-in-node=\"27\">skull</strong> was perched on a stone slab in the center of one chamber…” (Đoạn 6)</p>\n</li>\n<li>\n<p data-path-to-node=\"21,1,0\"><strong data-path-to-node=\"21,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Một hộp sọ gấu được đặt ở vị trí trang trọng trên một phiến đá giữa phòng.</p>\n</li>\n</ul>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">9. shelter</strong></p>\n<ul data-path-to-node=\"23\">\n<li>\n<p data-path-to-node=\"23,0,0\"><strong data-path-to-node=\"23,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…cave bears and human beings sought <strong data-path-to-node=\"23,0,0\" data-index-in-node=\"50\">shelter</strong> here from winter weather.” (Đoạn 8)</p>\n</li>\n<li>\n<p data-path-to-node=\"23,1,0\"><strong data-path-to-node=\"23,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Các bằng chứng cho thấy hang Hohle Fels là nơi trú ẩn của cả gấu và người.</p>\n</li>\n</ul>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">10. plants</strong></p>\n<ul data-path-to-node=\"25\">\n<li>\n<p data-path-to-node=\"25,0,0\"><strong data-path-to-node=\"25,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…Bocherens has found that cave bears ate mainly <strong data-path-to-node=\"25,0,0\" data-index-in-node=\"62\">plants</strong>.” (Phần Why Did Cave Bears Go Extinct?)</p>\n</li>\n<li>\n<p data-path-to-node=\"25,1,0\"><strong data-path-to-node=\"25,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Phân tích Isotopes (đồng vị) cho thấy thức ăn ưa thích của loài này là thực vật.</p>\n</li>\n</ul>\n<p data-path-to-node=\"26\"><strong data-path-to-node=\"26\" data-index-in-node=\"0\">11. Europe</strong></p>\n<ul data-path-to-node=\"27\">\n<li>\n<p data-path-to-node=\"27,0,0\"><strong data-path-to-node=\"27,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…altered the distribution of plant species across <strong data-path-to-node=\"27,0,0\" data-index-in-node=\"64\">Europe</strong>.” (Phần Why Did Cave Bears Go Extinct?)</p>\n</li>\n<li>\n<p data-path-to-node=\"27,1,0\"><strong data-path-to-node=\"27,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Kỷ băng hà đã làm thay đổi sự phân bố thực vật trên khắp châu Âu.</p>\n</li>\n</ul>\n<p data-path-to-node=\"28\"><strong data-path-to-node=\"28\" data-index-in-node=\"0\">12. teeth</strong></p>\n<ul data-path-to-node=\"29\">\n<li>\n<p data-path-to-node=\"29,0,0\"><strong data-path-to-node=\"29,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…according to a DNA analysis of <strong data-path-to-node=\"29,0,0\" data-index-in-node=\"46\">teeth</strong> found near the Danube River.” (Phần Why Did Cave Bears Go Extinct?)</p>\n</li>\n<li>\n<p data-path-to-node=\"29,1,0\"><strong data-path-to-node=\"29,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Nghiên cứu DNA trên răng gấu tìm thấy ở sông Danube hỗ trợ cho giả thuyết về sự di cư.</p>\n</li>\n</ul>\n<p data-path-to-node=\"30\"><strong data-path-to-node=\"30\" data-index-in-node=\"0\">13. hibernate</strong></p>\n<ul data-path-to-node=\"31\">\n<li>\n<p data-path-to-node=\"31,0,0\"><strong data-path-to-node=\"31,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…cave bears had fewer safe places to <strong data-path-to-node=\"31,0,0\" data-index-in-node=\"51\">hibernate</strong>.” (Đoạn cuối)</p>\n</li>\n<li>\n<p data-path-to-node=\"31,1,0\"><strong data-path-to-node=\"31,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Sự gia tăng dân số của con người chiếm dụng các hang động khiến gấu hang không còn chỗ để ngủ đông.</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('12676471-bb98-4a07-a416-388ce0614667', '110c3482-1cc7-4e36-96f6-0f1a64319db7', 'radio', 'Questions 36-40', NULL, '<p>Choose the correct letter, A, B, C or D.</p>
', 'multiple_choice_single', '[{"correct": 1, "options": [{"content": "A. It is partly based on true history."}, {"content": "B. It was restructured in the writing process."}, {"content": "C. It is quite different from conventional fantasy."}, {"content": "D. It does not reflect the usual themes in Mahy’s work."}], "question": "What does the writer say about The Magician of Hoad?"}, {"correct": 2, "options": [{"content": "A. was first illustrated in 1991."}, {"content": "B. is written in plain language."}, {"content": "C. is an old favourite for many families."}, {"content": "D. has not been read aloud by Mahy."}], "question": "According to the writer, Bubble Trouble"}, {"correct": 3, "options": [{"content": "A. show how Mahy''s style has changed."}, {"content": "B. criticise Mahy''s children''s stories."}, {"content": "C. describe how new media have changed reading."}, {"content": "D. illustrate Mahy''s popularity with different generations."}], "question": "The writer''s purpose in the fifth paragraph is to"}, {"correct": 2, "options": [{"content": "A. Readers sometimes do not finish Mahy’s books."}, {"content": "B. Mahy actively encourages feedback from readers."}, {"content": "C. Readers are necessary in order to complete a book."}, {"content": "D. Mahy does not realise how important readers are."}], "question": "According to the sixth paragraph, which of the following is true?"}, {"correct": 1, "options": [{"content": "A. comparing Mahy’s writing to David Hill’s"}, {"content": "B. giving an example of Mahy’s influence"}, {"content": "C. explaining why Mahy’s language is humorous"}, {"content": "D. criticising the way Mahy plays with words"}], "question": "What is the writer doing in the final paragraph?"}]', 'null', 'null', 'null', '[{"content": "<p><strong>36. What does the writer say about <em>The Magician of Hoad</em>?</strong></p>\n<ul data-path-to-node=\"26\">\n<li><strong>Đáp án: B. It was restructured in the writing process.</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 4) &#8220;The story ballooned at one point to 800 pages and has been through <strong>at least two substantial rewrites</strong>.&#8221;</li>\n<li><strong>Giải thích:</strong> Việc trải qua nhiều lần viết lại đáng kể (&#8220;substantial rewrites&#8221;) cho thấy cuốn sách đã được <strong>tái cấu trúc</strong> (<strong>restructured</strong>).</li>\n</ul>\n<p><strong>37. According to the writer, <em>Bubble Trouble</em></strong></p>\n<ul data-path-to-node=\"28\">\n<li><strong>Đáp án: C. is an old favourite for many families.</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 5) &#8220;<strong>Perhaps more than any other work, <em>Bubble Trouble</em> is the Mahy that New Zealand children and their parents know so well</strong>&#8230;&#8221;</li>\n<li><strong>Giải thích:</strong> Việc được nhiều gia đình biết rõ chứng tỏ nó là một tác phẩm được yêu thích từ lâu (<strong>old favourite</strong>).</li>\n</ul>\n<p><strong>38. The writer&#8217;s purpose in the fifth paragraph is to</strong></p>\n<ul data-path-to-node=\"30\">\n<li><strong>Đáp án: D. illustrate Mahy&#8217;s popularity with different generations.</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 6) Tác giả liệt kê các tác phẩm của Mahy được đọc qua các thập kỷ khác nhau: &#8220;late 1960s&#8221; (tác giả đọc), &#8220;1970s&#8221; (con gái riêng của tác giả), &#8220;80s and 90s&#8221; (con của tác giả), &#8220;21st century&#8221; (cháu của tác giả).</li>\n<li><strong>Giải thích:</strong> Việc này cho thấy sự nổi tiếng <strong>liên tục</strong> và <strong>kéo dài qua nhiều thế hệ</strong>.</li>\n</ul>\n<p><strong>39. According to the sixth paragraph, which of the following is true?</strong></p>\n<ul data-path-to-node=\"32\">\n<li><strong>Đáp án: C. Readers are necessary in order to complete a book.</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 7) &#8220;a book is not properly finished, she has often said, <strong>until it has been read, because a reader brings something important to the book</strong>.&#8221;</li>\n<li><strong>Giải thích:</strong> Quan điểm của Mahy là cuốn sách chưa hoàn thành cho đến khi có người đọc.</li>\n</ul>\n<p><strong>40. What is the writer doing in the final paragraph?</strong></p>\n<ul data-path-to-node=\"34\">\n<li><strong>Đáp án: B. giving an example of Mahy’s influence</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 9) Tác giả kể lại câu chuyện của David Hill, một nhà văn khác, người đã bị <strong>ảnh hưởng</strong> (<em>&#8220;affected by her peculiarly alert way of looking at the world&#8221;</em>) bởi cách Mahy nhìn thế giới và chơi chữ.</li>\n<li><strong>Giải thích:</strong> Câu chuyện của Hill là một bằng chứng rõ ràng về <strong>tầm ảnh hưởng</strong> của Mahy đối với các nhà văn khác.</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('6940eebd-9e8a-40f0-ba75-328cab60408c', '3153cf39-3063-4779-8f50-99f72bffc690', 'matching', 'Questions 14–20', '<p dir="ltr">Complete the summary below.</p>
<p>Write <strong id="docs-internal-guid-68a0c3b3-7fff-b8aa-1568-d3896c570928">NO MORE THAN TWO WORDS </strong>from the passage for each answer.</p>
<p style="text-align: center;"><strong>Malaria in 19th-century Italy</strong></p>
<p>Up until the late nineteenth century, experts failed to make the connection between malaria and {insects}. The most popular belief at the time was the {miasma} theory, which upheld the idea that diseases were carried by unclean air. Another common idea was that malaria was a {hereditary} disease, and as a result people from certain parts of the country were often held responsible for the spread of epidemics. Malaria was particularly widespread in rural regions, where {life expectancy} could be extremely short.</p>
', '<p>The text has seven paragraphs. Choose the correct heading for each paragraph and move it into the gap.</p>', 'matching_features', 'null', 'null', '{"layoutType": "heading", "summaryText": null, "answerOptions": [{"optionText": "The impact of musical performance on the etiquette of applause"}, {"optionText": "The negative effects of applause on a kind of public performer"}, {"optionText": "The initial emergence of applause as a behaviour in the theatre"}, {"optionText": "A form of applause that is more far-reaching than before"}, {"optionText": "The use of applause by political figures to evaluate their own popularity"}, {"optionText": "How music can influence an audience’s level of applause"}, {"optionText": "The different methods of applause employed in ancient times, besides clapping"}, {"optionText": "The re-emergence and disappearance of fake appreciation"}, {"optionText": "How the theatrical world copied the world of politics in giving applause"}, {"optionText": "The use of applause in working out how popular an opponent was"}], "matchingItems": null}', 'null', '[{"content": "<p data-path-to-node=\"3,0,0\"><strong class=\"\" data-path-to-node=\"3,0,0\" data-index-in-node=\"0\">14. Paragraph 1: The initial emergence of applause as a behaviour in the theatre</strong></p>\n<ul>\n<li data-path-to-node=\"3,0,1,0,0\"><strong class=\"\" data-path-to-node=\"3,0,1,0,0\" data-index-in-node=\"0\">Vị trí:</strong><span class=\"\"> Đoạn 1,</span><span class=\"\"> dòng 3-6.</span></li>\n<li data-path-to-node=\"3,0,1,1,0\"><strong class=\"\" data-path-to-node=\"3,0,1,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> “…</span><span class=\"\">the common way to end a play was for the chief actor to yell ‘Valete et plaudite!</span><span class=\"\">’…</span><span class=\"\"> signaling to the audience that it was time for them to give praise…</span><span class=\"\">“</span></li>\n<li data-path-to-node=\"3,0,1,2,0\"><strong class=\"\" data-path-to-node=\"3,0,1,2,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Đoạn này nói về sự xuất hiện ban đầu của việc vỗ tay trong nhà hát La Mã như một hiệu lệnh kết thúc vở kịch.</span></li>\n</ul>\n<p><strong class=\"\" data-path-to-node=\"3,1,0\" data-index-in-node=\"0\">15. Paragraph 2: The use of applause by political figures to evaluate their own popularity</strong></p>\n<ul>\n<li data-path-to-node=\"3,1,1,0,0\"><strong class=\"\" data-path-to-node=\"3,1,1,0,0\" data-index-in-node=\"0\">Vị trí:</strong><span class=\"\"> Đoạn 2,</span><span class=\"\"> dòng 4-7.</span></li>\n<li data-path-to-node=\"3,1,1,1,0\"><strong class=\"\" data-path-to-node=\"3,1,1,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> “One of the chief methods they used to </span><strong class=\"\" data-path-to-node=\"3,1,1,1,0\" data-index-in-node=\"50\">estimate their standing</strong><span class=\"\"> with the people was gauging the greetings they got…</span><span class=\"\"> an ancient type of </span><strong class=\"\" data-path-to-node=\"3,1,1,1,0\" data-index-in-node=\"147\">opinion poll</strong><span class=\"\">.</span><span class=\"\">“</span></li>\n<li data-path-to-node=\"3,1,1,2,0\"><strong class=\"\" data-path-to-node=\"3,1,1,2,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Các nhà lãnh đạo dùng tiếng vỗ tay như một cuộc thăm dò ý kiến để đánh giá mức độ ủng hộ (popularity) của dân chúng dành cho mình.</span></li>\n</ul>\n<p data-path-to-node=\"3,2,0\"><strong class=\"\" data-path-to-node=\"3,2,0\" data-index-in-node=\"0\">16. Paragraph 3: The use of applause in working out how popular an opponent was</strong></p>\n<ul>\n<li data-path-to-node=\"3,2,1,0,0\"><strong class=\"\" data-path-to-node=\"3,2,1,0,0\" data-index-in-node=\"0\">Vị trí:</strong><span class=\"\"> Đoạn 3,</span><span class=\"\"> dòng 1-3.</span></li>\n<li data-path-to-node=\"3,2,1,1,0\"><strong class=\"\" data-path-to-node=\"3,2,1,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> “Clever leaders…</span><span class=\"\"> researched their </span><strong class=\"\" data-path-to-node=\"3,2,1,1,0\" data-index-in-node=\"47\">rivals</strong><span class=\"\">,</span><span class=\"\"> too.</span><span class=\"\"> Cicero…</span><span class=\"\"> taking notes to see what kind of greeting each official got…</span><span class=\"\"> who was beloved…</span><span class=\"\"> and who was not.</span><span class=\"\">“</span></li>\n<li data-path-to-node=\"3,2,1,2,0\"><strong class=\"\" data-path-to-node=\"3,2,1,2,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Không chỉ đánh giá bản thân,</span><span class=\"\"> họ còn dùng tiếng vỗ tay để đo lường mức độ yêu mến của dân chúng dành cho đối thủ (rivals/opponent).</span></li>\n</ul>\n<p data-path-to-node=\"3,3,0\"><strong class=\"\" data-path-to-node=\"3,3,0\" data-index-in-node=\"0\">17. Paragraph 4: The different methods of applause employed in ancient times, besides clapping</strong></p>\n<ul>\n<li data-path-to-node=\"3,3,1,0,0\"><strong class=\"\" data-path-to-node=\"3,3,1,0,0\" data-index-in-node=\"0\">Vị trí:</strong><span class=\"\"> Đoạn 4,</span><span class=\"\"> dòng 4-7.</span></li>\n<li data-path-to-node=\"3,3,1,1,0\"><strong class=\"\" data-path-to-node=\"3,3,1,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> “…</span><span class=\"\">strategies of applause were much more varied than clapping alone…</span><span class=\"\"> ranging from claps,</span><span class=\"\"> to </span><strong class=\"\" data-path-to-node=\"3,3,1,1,0\" data-index-in-node=\"106\">snaps</strong><span class=\"\">…</span><span class=\"\"> to </span><strong class=\"\" data-path-to-node=\"3,3,1,1,0\" data-index-in-node=\"118\">waves</strong><span class=\"\">…</span><span class=\"\"> waving a special </span><strong class=\"\" data-path-to-node=\"3,3,1,1,0\" data-index-in-node=\"144\">handkerchief</strong><span class=\"\">.</span><span class=\"\">“</span></li>\n<li data-path-to-node=\"3,3,1,2,0\"><strong class=\"\" data-path-to-node=\"3,3,1,2,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Liệt kê các hình thức tán thưởng khác ngoài vỗ tay như búng tay,</span><span class=\"\"> vẫy vạt áo toga hoặc vẫy khăn tay.</span><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----></li>\n</ul>\n<p data-path-to-node=\"3,4,0\"><strong class=\"\" data-path-to-node=\"3,4,0\" data-index-in-node=\"0\">18. Paragraph 5: The re-emergence and disappearance of fake appreciation</strong></p>\n<ul>\n<li data-path-to-node=\"3,4,1,0,0\"><strong class=\"\" data-path-to-node=\"3,4,1,0,0\" data-index-in-node=\"0\">Vị trí:</strong><span class=\"\"> Đoạn 5,</span><span class=\"\"> dòng 1-3 và câu cuối.</span></li>\n<li data-path-to-node=\"3,4,1,1,0\"><strong class=\"\" data-path-to-node=\"3,4,1,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> “…</span><span class=\"\">bringing back the Roman practice of hiring </span><strong class=\"\" data-path-to-node=\"3,4,1,1,0\" data-index-in-node=\"58\">professional applauders</strong><span class=\"\">…</span><span class=\"\"> The claque lost its power once people became aware of its tricks.</span><span class=\"\">“</span></li>\n<li data-path-to-node=\"3,4,1,2,0\"><strong class=\"\" data-path-to-node=\"3,4,1,2,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Nói về sự trở lại của việc thuê người vỗ tay giả (fake) ở Pháp và sự thoái trào của nó khi các mánh khóe bị bại lộ.</span></li>\n</ul>\n<p data-path-to-node=\"3,5,0\"><strong class=\"\" data-path-to-node=\"3,5,0\" data-index-in-node=\"0\">19. Paragraph 6: The impact of musical performance on the etiquette of applause</strong></p>\n<ul>\n<li data-path-to-node=\"3,5,1,0,0\"><strong class=\"\" data-path-to-node=\"3,5,1,0,0\" data-index-in-node=\"0\">Vị trí:</strong><span class=\"\"> Đoạn 6,</span><span class=\"\"> dòng 1-4.</span></li>\n<li data-path-to-node=\"3,5,1,1,0\"><strong class=\"\" data-path-to-node=\"3,5,1,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> “In the 18th century,</span><span class=\"\"> symphonies and concerts became more serious…</span><span class=\"\"> Knowing when to maintain silence…</span><span class=\"\"> became a mark of </span><strong class=\"\" data-path-to-node=\"3,5,1,1,0\" data-index-in-node=\"133\">sophistication</strong><span class=\"\">.</span><span class=\"\">“</span></li>\n<li data-path-to-node=\"3,5,1,2,0\"><strong class=\"\" data-path-to-node=\"3,5,1,2,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Sự thay đổi trong âm nhạc (nghiêm túc hơn) đã định hình lại quy tắc ứng xử (etiquette) của khán giả:</span><span class=\"\"> phải biết lúc nào im lặng,</span><span class=\"\"> lúc nào vỗ tay.</span></li>\n</ul>\n<p data-path-to-node=\"3,6,0\"><strong class=\"\" data-path-to-node=\"3,6,0\" data-index-in-node=\"0\">20. Paragraph 7: A form of applause that is more far-reaching than before</strong></p>\n<ul>\n<li data-path-to-node=\"3,6,1,0,0\"><strong class=\"\" data-path-to-node=\"3,6,1,0,0\" data-index-in-node=\"0\">Vị trí:</strong><span class=\"\"> Đoạn 7,</span><span class=\"\"> dòng 1-3.</span></li>\n<li data-path-to-node=\"3,6,1,1,0\"><strong class=\"\" data-path-to-node=\"3,6,1,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> “In the 21st century we’re reinventing applause…</span><span class=\"\"> digital world allows us to link and share…</span><span class=\"\"> no longer momentary…</span><span class=\"\"> but is far more </span><strong class=\"\" data-path-to-node=\"3,6,1,1,0\" data-index-in-node=\"146\">permanent</strong><span class=\"\">.</span><span class=\"\">“</span></li>\n<li data-path-to-node=\"3,6,1,2,0\"><strong class=\"\" data-path-to-node=\"3,6,1,2,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Tiếng vỗ tay thời kỹ thuật số (like,</span><span class=\"\"> share,</span><span class=\"\"> comment) có sức lan tỏa rộng lớn và tồn tại lâu bền hơn so với tiếng vỗ tay tức thời ngày xưa.</span></li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('80f1b210-6132-467d-afc7-3a16a8dc7ddb', 'f2fe0ae0-c73a-48d6-bf14-a52f3b6b05b9', 'radio', 'Questions 21–25', '', '<p>Choose the correct answer.</p>', 'multiple_choice', '[{"correct": 1, "options": [{"option_text": "give both sides of an argument."}, {"option_text": "express personal opinions."}, {"option_text": "present a range of views."}], "question": "Katy thinks it might be inappropriate for academic essays to"}, {"correct": 2, "options": [{"option_text": "withhold their own views."}, {"option_text": "avoid too much repetition."}, {"option_text": "refer to the title."}], "question": "The tutor says that in one type of conclusion students should"}, {"correct": 0, "options": [{"option_text": "There is a standard format for references."}, {"option_text": "Presentation is not assessed at this level."}, {"option_text": "Book titles should be underlined."}], "question": "What does the tutor say about the bibliography?"}, {"correct": 1, "options": [{"option_text": "They provide evidence of how widely a student has read."}, {"option_text": "They are useful for defining difficult concepts."}, {"option_text": "There is a tendency to use too few of them."}], "question": "What advice does the tutor give about quotations?"}, {"correct": 0, "options": [{"option_text": "done more thorough research."}, {"option_text": "analysed his data more carefully."}, {"option_text": "given his views more clearly."}], "question": "John suggests that the writer of the first essay should have"}]', 'null', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">SECTION 3: ACADEMIC ESSAY WRITING</strong></h3>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Tutor:</strong> Morning Katie. Morning John. I want to talk about essays today and what the requirements are for this university—what kinds of things we look for when we''re grading them, okay? So let''s look at those two sample essays I gave you last week. I asked you to read them and to think about their strong and weak points. Do either of you have any general comments or questions about the first one, Katie?</p>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Katie:</strong> Um, well, the writer''s made it quite clear what his own views are about this subject. <span style=\"text-decoration: underline;\"><span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"4\" data-index-in-node=\"93\">(Q21) But I thought in academic essays you weren''t supposed to do that. I thought you were meant to present all the different arguments and just appear to be neutral</strong></span></span> about which one you think is best.</p>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">Tutor:</strong> Students do sometimes come down quite firmly on one particular side, and that''s okay, as long as they can show that they''ve given balanced consideration to all the issues. Do you see what I mean? John, you''re looking a bit uncertain. Did you want to say something?</p>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">John:</strong> Well, what if you don''t feel as sure about the debate as this student?</p>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Tutor:</strong> There''s another type of conclusion that''s valid when you''re writing at this level. People don''t have to come down strongly on a particular side. They can say in the essay that the process of researching a particular topic has identified the importance of a range of studies that support different viewpoints. <strong data-path-to-node=\"7\" data-index-in-node=\"316\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(Q22) And then they return to the title of the assignment</span>.</strong> I''d say that it''s a good idea to use some of the actual words that are in the title; it shows the reader that you''re still on track.</p>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">John:</strong> Can I just ask you something about the bibliography?</p>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Tutor:</strong> Of course, um...</p>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">John:</strong> This person''s used italics when he refers to book titles in the reference section, but I thought we had to underline them.</p>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Tutor:</strong> <strong data-path-to-node=\"11\" data-index-in-node=\"7\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(Q23) Actually, he''s done it in the way we set out in the university study guide. That is the appropriate convention for titles</span>.</strong> You might think it''s trivial, but presenting references appropriately is one of the requirements of a degree at this level.</p>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">Katie:</strong> I looked in the study guide to see what it said about quotations. The essay''s got a lot of quite long ones, and I was a bit surprised by that.</p>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">Tutor:</strong> Using a range of quotations is a way of showing that you have actually read quite widely, isn''t it? Well, not really, unfortunately. Some students just pick out extracts to quote without actually reading the whole thing. It''s really a matter of using quotations appropriately. <strong data-path-to-node=\"13\" data-index-in-node=\"284\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(Q24) So when exactly should we use quotes? Particularly where there are definitions involved... terms that need defining for instance</span>.</strong> Why not cite someone else''s definition rather than dream one up yourself?</p>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">John:</strong> What about the way the writer discusses research findings? <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"14\" data-index-in-node=\"65\">(Q25) One thing that struck me was the approach of the student to some of the things he''d read... I''ve always felt that it''s just up to me to go to the primary sources and find out.</strong></span></p>\n<hr data-path-to-node=\"15\">\n<h3 data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">THE SECOND ESSAY (Questions 26–30)</strong></h3>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">Tutor:</strong> Now let''s look at the second essay then. Did you think this student answered the question?</p>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">Katie/John:</strong> Yes.</p>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">Tutor:</strong> Good, because really that''s the bottom line. The minimum criterion for an assignment is relevance. Secondly, what about the overall structure?</p>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">Katie:</strong> Sometimes writers mix different subtopics up, so it''s quite difficult to follow the logic of the essay. <strong data-path-to-node=\"20\" data-index-in-node=\"111\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(Q26) But here I think they''re separated very clearly (sub-topics)</span>.</strong></p>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">John:</strong> Yes, I mean it is very clear, but is it okay to use subheadings and bullet points like this? I mean, <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"21\" data-index-in-node=\"107\">(Q27) in things like reports they can be very useful I know, but is it alright to use them in academic essays?</strong></span></p>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">Tutor:</strong> Well, my general feeling is that it''s best just to use paragraphs to signal changes of topic.</p>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">John:</strong><span style=\"text-decoration: underline;\"> </span><strong data-path-to-node=\"23\" data-index-in-node=\"6\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(Q28) One thing I thought was really good about this essay was the way the writer always gives examples to support statements</span>.</strong> He never just assumes that explanations are enough.</p>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">Tutor:</strong> Yes, I''m glad you brought that up. It''s very helpful for the reader.</p>\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">Katie:</strong> Another thing that helps the reader is the way he uses words and phrases to <strong data-path-to-node=\"25\" data-index-in-node=\"83\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(Q29) connect (link) his ideas</span>.</strong> You mean things like \"however\" and \"on the other hand\"?</p>\n<p data-path-to-node=\"26\"><strong data-path-to-node=\"26\" data-index-in-node=\"0\">Tutor:</strong> Yes, that really is one of the hallmarks of a good essay. Now, you may feel at this early stage that your writing skills are rusty, but <strong data-path-to-node=\"26\" data-index-in-node=\"143\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(Q30) reading is the key I think</span>.</strong> As you read more and more extensively, you''ll find that your own use of academic language will improve.</p>"}]', 0);
INSERT INTO public.questions VALUES ('e9239a6c-257a-4b6e-bf5e-68af2a88c0b5', 'f2fe0ae0-c73a-48d6-bf14-a52f3b6b05b9', 'fillup', 'Questions 26–30', '<p>Complete the sentences below.</p>
<p>Write <strong>ONE WORD ONLY</strong> for each answer.</p>
<ul>
<li>
<p>The tutor says that the most basic requirement of an essay is relevance.</p>
</li>
<li>
<p>Katy thinks the writer separates different {subtopics|sub-topics} very clearly.</p>
</li>
<li>
<p>John feels that bullet points and sub-headings might be more appropriate for {reports} than for essays.</p>
</li>
<li>
<p>The tutor thinks that paragraphs should be used to structure essays.</p>
</li>
<li>
<p>John particularly admires the way the writer backs up his statements with {examples}</p>
</li>
<li>
<p>Katy likes the writer''s use of language to link his {ideas}</p>
</li>
<li>
<p>The tutor thinks that wide {reading} helps to develop writing ability</p>
</li>
</ul>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', 'null', 1);
INSERT INTO public.questions VALUES ('be4fcb63-a510-42c1-bf94-9cf5d8ba413c', '949f02d5-892c-45d4-a229-f14d6bf74318', 'radio', 'Questions 7–13', NULL, '<p>Choose <strong>TRUE </strong>if the statement agrees with the information given in the text, choose <strong>FALSE </strong>if the statement contradicts the information, or choose <strong>NOT GIVEN </strong>if there is no information on this.</p>
', 'multiple_choice_single', '[{"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "The Italians were the first to make pencils out of wood."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "The Germans used different types of wood to produce pencils."}, {"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "More clay in a pencil makes it write more darkly."}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "After the HB code was introduced, it very quickly became used by all manufacturers."}, {"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "English pencil factories have now all closed down."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "American astronauts used pencils on their early journeys into space."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "The use of graphite pencils is unlikely to continue into the future."}]', NULL, '{"layoutType": ["standard"], "summaryText": null, "answerOptions": null, "matchingItems": null}', '{"layoutType": ["standard"], "legendTitle": null, "matrixItems": null, "matrixCategories": null}', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">7. The Italians were the first to make pencils out of wood.</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Đáp án:</strong> TRUE</p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 4, dòng 1.</p>\n</li>\n<li>\n<p data-path-to-node=\"4,2,0\"><strong data-path-to-node=\"4,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “The <strong data-path-to-node=\"4,2,0\" data-index-in-node=\"16\">Italians originally invented the wooden casing</strong> to hold a thin rod of plumbago firmly in place for ease of writing.”</p>\n</li>\n<li>\n<p data-path-to-node=\"4,3,0\"><strong data-path-to-node=\"4,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc khẳng định người Ý là những người đầu tiên phát minh ra vỏ bọc bằng gỗ để giữ lõi than chì. “Invented the wooden casing” tương ứng với “make pencils out of wood”.</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">8. The Germans used different types of wood to produce pencils.</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Đáp án:</strong> NOT GIVEN</p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 4, dòng 6.</p>\n</li>\n<li>\n<p data-path-to-node=\"6,2,0\"><strong data-path-to-node=\"6,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “The Germans took this technique and developed it further by applying mass-production techniques to pencils.”</p>\n</li>\n<li>\n<p data-path-to-node=\"6,3,0\"><strong data-path-to-node=\"6,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ nói người Đức tiếp nhận kỹ thuật từ người Ý và áp dụng sản xuất hàng loạt (mass-production). Văn bản <strong data-path-to-node=\"6,3,0\" data-index-in-node=\"125\">không đề cập</strong> đến việc họ có sử dụng “nhiều loại gỗ khác nhau” (different types of wood) hay không.</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">9. More clay in a pencil makes it write more darkly.</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Đáp án:</strong> FALSE</p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 4, dòng 10–13.</p>\n</li>\n<li>\n<p data-path-to-node=\"8,2,0\"><strong data-path-to-node=\"8,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Adding <strong data-path-to-node=\"8,2,0\" data-index-in-node=\"19\">more clay</strong> to the mixture helped make the pencil <strong data-path-to-node=\"8,2,0\" data-index-in-node=\"67\">harder, sharper, and more precise</strong>… More <strong data-path-to-node=\"8,2,0\" data-index-in-node=\"109\">graphite</strong> helped make a pencil mark that was <strong data-path-to-node=\"8,2,0\" data-index-in-node=\"153\">softer, thicker and darker</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"8,3,0\"><strong data-path-to-node=\"8,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Theo bài đọc, nhiều sét (clay) hơn làm bút chì cứng và sắc nét hơn, còn nhiều than chì (graphite) hơn mới làm nét bút đậm hơn (darker). Vì vậy, câu phát biểu này sai hoàn toàn so với thông tin bài cung cấp.</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">10. After the HB code was introduced, it very quickly became used by all manufacturers.</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Đáp án:</strong> NOT GIVEN</p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 5.</p>\n</li>\n<li>\n<p data-path-to-node=\"10,2,0\"><strong data-path-to-node=\"10,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Pencil manufactures all over the world still use this so-called HB grading system today.”</p>\n</li>\n<li>\n<p data-path-to-node=\"10,3,0\"><strong data-path-to-node=\"10,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc cho biết ngày nay các nhà sản xuất trên toàn thế giới vẫn dùng hệ thống HB, nhưng <strong data-path-to-node=\"10,3,0\" data-index-in-node=\"102\">không có thông tin</strong> về việc nó có được tất cả các nhà sản xuất sử dụng “rất nhanh chóng” (very quickly) ngay sau khi ra đời hay không.</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">11. English pencil factories have now all closed down.</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Đáp án:</strong> FALSE</p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 6, dòng cuối.</p>\n</li>\n<li>\n<p data-path-to-node=\"12,2,0\"><strong data-path-to-node=\"12,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…and <strong data-path-to-node=\"12,2,0\" data-index-in-node=\"19\">England’s pencil industry continues to thrive</strong> in the nearby town of Keswick.”</p>\n</li>\n<li>\n<p data-path-to-node=\"12,3,0\"><strong data-path-to-node=\"12,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc khẳng định ngành công nghiệp bút chì của Anh vẫn đang “thịnh vượng” (thrive) tại thị trấn Keswick, trái ngược với ý kiến cho rằng tất cả các nhà máy đã đóng cửa.</p>\n</li>\n</ul>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">12. American astronauts used pencils on their early journeys into space.</strong></p>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Đáp án:</strong> TRUE</p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong data-path-to-node=\"14,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn cuối, dòng 8.</p>\n</li>\n<li>\n<p data-path-to-node=\"14,2,0\"><strong data-path-to-node=\"14,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “In actual fact, <strong data-path-to-node=\"14,2,0\" data-index-in-node=\"28\">both American and Russian astronauts were equipped with pencils</strong> in their respective country’s <strong data-path-to-node=\"14,2,0\" data-index-in-node=\"122\">first space flights</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"14,3,0\"><strong data-path-to-node=\"14,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc xác nhận sự thật là cả phi hành gia Mỹ và Nga đều được trang bị bút chì trong những chuyến bay vào không gian đầu tiên của họ.</p>\n</li>\n</ul>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">13. The use of graphite pencils is unlikely to continue into the future.</strong></p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Đáp án:</strong> FALSE</p>\n</li>\n<li>\n<p data-path-to-node=\"16,1,0\"><strong data-path-to-node=\"16,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn cuối, dòng cuối.</p>\n</li>\n<li>\n<p data-path-to-node=\"16,2,0\"><strong data-path-to-node=\"16,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “And there is <strong data-path-to-node=\"16,2,0\" data-index-in-node=\"25\">nothing to suggest that we are likely to invent anything better than graphite</strong> to use in our Pencils.”</p>\n</li>\n<li>\n<p data-path-to-node=\"16,3,0\"><strong data-path-to-node=\"16,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả tin rằng không có gì cho thấy chúng ta sẽ phát minh ra thứ gì tốt hơn than chì, điều này ngụ ý việc sử dụng bút chì than chì sẽ còn tiếp tục lâu dài, trái ngược với từ “unlikely” (không có khả năng) trong câu hỏi.</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('cc717df7-68fc-404f-8361-0a4c0a64fa5c', '54b5d50e-2b92-428b-97f1-575db48b7897', 'matrix', 'Questions 14–18', '', '<p>Reading Passage 2 has seven sections <strong data-path-to-node="29" data-index-in-node="37">A–G</strong>.</p>
<p>Which section contains the following information?</p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "simple", "matrixItems": [{"itemText": "Preference of using one side of the body in animal species.", "correctCategoryLetter": "C"}, {"itemText": "How likely one-handedness is born.", "correctCategoryLetter": "A"}, {"itemText": "The age when the preference of using one hand is settled.", "correctCategoryLetter": "B"}, {"itemText": "Occupations usually found in left-handed population.", "correctCategoryLetter": "F"}, {"itemText": "A reference to an early discovery of each hemisphere''s function", "correctCategoryLetter": "D"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}]}', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">14. Preference of using one side of the body in animal species. — {C}</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “Furthermore, <strong data-path-to-node=\"4,0,0\" data-index-in-node=\"25\">specialization on either side of the body is common among animals</strong>. Cats will favor one paw… Horses stomp… Certain crabs…”</p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn C liệt kê các ví dụ về việc động vật (mèo, ngựa, cua) cũng có xu hướng thuận một bên cơ thể.</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">15. How likely one-handedness is born. — {A}</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “The probability that two right-handed people would have a left-handed child is only about <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"102\">9.5 percent</strong>… rises to <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"126\">19.5 percent</strong>… and <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"146\">26 percent</strong>…”</p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn A đưa ra các số liệu thống kê cụ thể về khả năng (xác suất) một đứa trẻ sinh ra thuận tay trái dựa trên tay thuận của bố mẹ.</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">16. The age when the preference of using one hand is settled. — {B}</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…children do not settle on either their right or left hand until they are <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"88\">two or three years old</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cuối đoạn B đề cập đến độ tuổi cụ thể (2 hoặc 3 tuổi) mà trẻ em mới thực sự xác định được tay thuận của mình.</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">17. Occupations usually found in left-handed population. — {F}</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…lefties are prevalent among <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"43\">artists, composers and the generally acknowledged great political thinkers</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn F liệt kê các nghề nghiệp (họa sĩ, nhà soạn nhạc, nhà chính trị) thường thấy ở những người thuận tay trái.</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">18. A reference to an early discovery of each hemisphere’s function. — {D}</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “Interest in hemispheres dates back to at least <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"59\">1836</strong>… French physician <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"84\">Marc Dax</strong> reported…”</p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn D nhắc đến Marc Dax năm 1836, người đầu tiên phát hiện ra sự phân chia chức năng giữa hai bán cầu não thông qua các bệnh nhân bị tổn thương não.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('00dc38f4-51c1-43fd-8d53-e9f64c626419', '0778d422-07f1-437e-ada1-069a2f7d5b56', 'matrix', 'Questions 14–17', '', '<p>Write the correct letter, <strong>A–E</strong>, in boxes 14–17 on your answer sheet.</p>
<p><strong>NB</strong> You may use any letter more than once. </p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "simple", "matrixItems": [{"itemText": "a reference to the interest shown by large corporations in herbal remedies", "correctCategoryLetter": "D"}, {"itemText": "examples of the uses of one particular herbal medicine", "correctCategoryLetter": "A"}, {"itemText": "a warning that small companies cannot afford stricter controls of the herbal medicine industry", "correctCategoryLetter": "E"}, {"itemText": "a statement by one expert about the effectiveness and limitations of herbal medicines", "correctCategoryLetter": "D"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}]}', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">14. D — {a reference to the interest shown by large corporations in herbal remedies}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"11\">“Natural health products are big sellers in pharmacies, and <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"71\">global pharmaceutical companies are buying up natural supplement brands or developing their own</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Large corporations\" (các tập đoàn lớn) được cụ thể hóa bằng cụm từ \"global pharmaceutical companies\" (các công ty dược phẩm toàn cầu). Việc các tập đoàn này đi thu mua lại các thương hiệu thực phẩm bổ sung tự nhiên hoặc tự phát triển dòng sản phẩm riêng chính là minh chứng rõ ràng cho sự quan tâm (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"312\">interest</strong>) của họ đối với các phương thuốc thảo dược (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"365\">herbal remedies / natural supplement</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">15. A — {examples of the uses of one particular herbal medicine}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"11\">“Take <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"17\">arnica</strong>, for example, <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"38\">a popular pharmaceutical herb used to treat bruises and joint problems</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"One particular herbal medicine\" (một loại thảo dược cụ thể) ở đây chính là cây kim sa (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"100\">arnica</strong>). Đoạn A đã đưa ra các ví dụ về công dụng của nó (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"157\">examples of the uses</strong>) là dùng để chữa trị các vết bầm tím (<em data-path-to-node=\"7,1,0\" data-index-in-node=\"216\">treat bruises</em>) và các vấn đề về xương khớp (<em data-path-to-node=\"7,1,0\" data-index-in-node=\"260\">joint problems</em>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">16. E — {a warning that small companies cannot afford stricter controls of the herbal medicine industry}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"11\">“But others argue that <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"34\">more regulation would be prohibitively expensive for all but the largest manufacturers – a change, cautions Clair, that would probably put some local companies out of business</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Stricter controls\" (sự kiểm soát chặt chẽ hơn) tương ứng với cụm từ \"more regulation\" (nhiều quy định pháp lý hơn). \"Small companies\" (các công ty nhỏ) tương ứng với từ \"local companies\" (các công ty địa phương, phân biệt với <em data-path-to-node=\"9,1,0\" data-index-in-node=\"239\">largest manufacturers</em>). Lời cảnh báo (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"277\">a warning / cautions Clair</strong>) chỉ ra rằng việc thắt chặt này sẽ vô cùng đắt đỏ (<em data-path-to-node=\"9,1,0\" data-index-in-node=\"355\">prohibitively expensive</em> - không thể chi trả nổi / <em data-path-to-node=\"9,1,0\" data-index-in-node=\"405\">cannot afford</em>) và có thể khiến các công ty này bị phá sản (<em data-path-to-node=\"9,1,0\" data-index-in-node=\"464\">put out of business</em>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">17. D — {a statement by one expert about the effectiveness and limitations of herbal medicines}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"11\">“‘<strong data-path-to-node=\"11,0,0\" data-index-in-node=\"13\">It doesn’t do everything</strong>,’ he [Rasmussen] says, ‘<strong data-path-to-node=\"11,0,0\" data-index-in-node=\"62\">but there’s a lot it does do, particularly in terms of preventative health care</strong>.’”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"One expert\" (một chuyên gia) ở đây là ông Phil Rasmussen. Phát biểu của ông chứa đựng cả hai mặt: Sự hiệu quả (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"124\">effectiveness</strong> - <em data-path-to-node=\"11,1,0\" data-index-in-node=\"140\">there’s a lot it does do / preventative health care</em>) và mặt hạn chế (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"209\">limitations</strong> - <em data-path-to-node=\"11,1,0\" data-index-in-node=\"223\">It doesn’t do everything / nó không phải là vạn năng</em>). Do đó thông tin này hoàn toàn thuộc về đoạn D.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('d52700e4-4991-4ae6-9d35-51f6f9a1eb9f', 'a3a37e43-58a0-4926-8fea-b8360816b266', 'fillup', 'Questions 1–8', '<div class="quests-inner-desc">
<div class="txt">
<p>Complete the notes below.</p>
<p>Write <strong>ONE WORD ONLY</strong> from the passage for each answer.</p>
<h3 style="text-align: center;"><strong>History of the bar code</strong></h3>
<h3><strong>1948 – 1952</strong></h3>
<p>Methods of recording information automatically were developed by Silver and Woodland.</p>
<p>1st system:</p>
<ul style="list-style-type: circle;">
<li>used ultraviolet light and a special type of {ink}</li>
<li>problems: expensive and not permanent</li>
</ul>
<p>2nd system:</p>
<ul style="list-style-type: circle;">
<li>based on technology used in Morse Code and also for the {soundtracks} of films</li>
<li>problems: {unreliable} and expensive</li>
</ul>
<h3><strong>1970s</strong></h3>
<p>Availability of cheaper {lasers} meant scanning technology spread more widely</p>
<p>Problem: lack of {standardization} in code systems</p>
<p>April 1973: committee agreed on one universal product code (UPC)</p>
<p>June 1974: pack of Juicy Fruit chewing gum sold with bar-code scanner</p>
<p>Advantages of bar-code system:</p>
<ul style="list-style-type: circle;">
<li>supermarkets needed to spend less on labour</li>
<li>the {speed} of checkouts increased</li>
<li>doing inventories was much cheaper</li>
</ul>
<h3><strong>Present day</strong></h3>
<p>Users of bar codes include:</p>
<ul style="list-style-type: circle;">
<li>retail companies</li>
<li>airlines</li>
<li>staff in hospitals</li>
<li>participants in {marathons}</li>
<li>scientists studying {bees}</li>
</ul>
</div>
</div>
', NULL, 'gap_filling', NULL, NULL, '{"layoutType": ["standard"], "summaryText": null, "answerOptions": null, "matchingItems": null}', '{"layoutType": ["standard"], "legendTitle": null, "matrixItems": null, "matrixCategories": null}', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">1. used ultraviolet light and a special type of {ink}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"8\">ink</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn B, dòng 2.</p>\n</li>\n<li>\n<p data-path-to-node=\"5,2,0\"><strong data-path-to-node=\"5,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Their first idea was to use patterns printed with an <strong data-path-to-node=\"5,2,0\" data-index-in-node=\"65\">ink</strong> that would glow under ultraviolet light…”</p>\n</li>\n<li>\n<p data-path-to-node=\"5,3,0\"><strong data-path-to-node=\"5,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Hệ thống đầu tiên của Silver và Woodland sử dụng một loại mực đặc biệt có khả năng phát sáng dưới tia cực tím.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">2. based on technology used in Morse Code and also for the {soundtracks} of films</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"8\">soundtracks</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn B, dòng 7.</p>\n</li>\n<li>\n<p data-path-to-node=\"7,2,0\"><strong data-path-to-node=\"7,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…using elements from two established technologies: Morse code… and the method used to record <strong data-path-to-node=\"7,2,0\" data-index-in-node=\"109\">soundtracks</strong> in movies.”</p>\n</li>\n<li>\n<p data-path-to-node=\"7,3,0\"><strong data-path-to-node=\"7,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Hệ thống mã vạch tuyến tính thứ hai được xây dựng dựa trên sự kết hợp giữa mã Morse và công nghệ ghi âm dải âm thanh trong phim ảnh.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">3. problems: {unreliable} and expensive</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"8\">unreliable</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn B, dòng cuối.</p>\n</li>\n<li>\n<p data-path-to-node=\"9,2,0\"><strong data-path-to-node=\"9,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…the fact that their scanning equipment was rather <strong data-path-to-node=\"9,2,0\" data-index-in-node=\"65\">unreliable</strong>, made the idea a non-starter at that time.”</p>\n</li>\n<li>\n<p data-path-to-node=\"9,3,0\"><strong data-path-to-node=\"9,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Vào thời điểm đó, chi phí cao và thiết bị quét hoạt động không ổn định (không đáng tin cậy) khiến ý tưởng chưa thể thực hiện.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">4. Availability of cheaper {lasers} meant scanning technology spread more widely</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"8\">lasers</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn C, dòng 1.</p>\n</li>\n<li>\n<p data-path-to-node=\"11,2,0\"><strong data-path-to-node=\"11,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Scanning systems made little progress until the 1970s, when <strong data-path-to-node=\"11,2,0\" data-index-in-node=\"72\">lasers</strong> became affordable.”</p>\n</li>\n<li>\n<p data-path-to-node=\"11,3,0\"><strong data-path-to-node=\"11,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Sự xuất hiện của tia laser với giá thành rẻ vào những năm 1970 đã tạo bước ngoặt cho công nghệ quét mã vạch phát triển.</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">5. Problem: lack of {standardization} in code systems</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"8\">standardization</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn C, dòng 2-3.</p>\n</li>\n<li>\n<p data-path-to-node=\"13,2,0\"><strong data-path-to-node=\"13,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…each with its own proprietary code, but there was no <strong data-path-to-node=\"13,2,0\" data-index-in-node=\"68\">standardization</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"13,3,0\"><strong data-path-to-node=\"13,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Trước khi có UPC, mỗi cửa hàng/nhà máy dùng một loại mã riêng, dẫn đến việc thiếu sự quy chuẩn hóa chung.</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">6. the {speed} of checkouts increased</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"8\">speed</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn G, dòng 6.</p>\n</li>\n<li>\n<p data-path-to-node=\"15,2,0\"><strong data-path-to-node=\"15,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “These included checking out items at twice the <strong data-path-to-node=\"15,2,0\" data-index-in-node=\"59\">speed</strong> compared to using traditional equipment…”</p>\n</li>\n<li>\n<p data-path-to-node=\"15,3,0\"><strong data-path-to-node=\"15,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Một trong những lợi thế lớn nhất là tốc độ thanh toán tại quầy tăng gấp đôi so với phương pháp truyền thống.</p>\n</li>\n</ul>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">7. participants in {marathons}</strong></p>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong data-path-to-node=\"17,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"17,0,0\" data-index-in-node=\"8\">marathons</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong data-path-to-node=\"17,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn H, dòng 4.</p>\n</li>\n<li>\n<p data-path-to-node=\"17,2,0\"><strong data-path-to-node=\"17,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Runners in major <strong data-path-to-node=\"17,2,0\" data-index-in-node=\"29\">marathons</strong> set off with bar codes on their vests…”</p>\n</li>\n<li>\n<p data-path-to-node=\"17,3,0\"><strong data-path-to-node=\"17,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Ngày nay, vận động viên chạy marathon cũng sử dụng mã vạch trên áo để theo dõi.</p>\n</li>\n</ul>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">8. scientists studying {bees}</strong></p>\n<ul data-path-to-node=\"19\">\n<li>\n<p data-path-to-node=\"19,0,0\"><strong data-path-to-node=\"19,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"19,0,0\" data-index-in-node=\"8\">bees</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"19,1,0\"><strong data-path-to-node=\"19,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn H, dòng cuối.</p>\n</li>\n<li>\n<p data-path-to-node=\"19,2,0\"><strong data-path-to-node=\"19,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Tiny bar codes have even been mounted on <strong data-path-to-node=\"19,2,0\" data-index-in-node=\"53\">bees</strong> by researchers to track their movements.”</p>\n</li>\n<li>\n<p data-path-to-node=\"19,3,0\"><strong data-path-to-node=\"19,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Các nhà khoa học thậm chí còn gắn mã vạch siêu nhỏ lên loài ong để nghiên cứu di chuyển của chúng.</p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('cf43c87b-7f17-4658-a64b-76c73bd4f155', '070c2ae9-80cd-44bb-a907-42ae423bb2c2', 'radio', 'Questions 21–24', '', '<p>Choose the correct letter, <strong>A</strong>, <strong>B </strong>or <strong>C</strong>.</p>
<p><span style="font-size: 12pt;"><strong>Presentation on African art</strong></span></p>', 'multiple_choice', '[{"correct": 1, "options": [{"option_text": "A. He read several journal articles."}, {"option_text": "B. He attended an exhibition."}, {"option_text": "C. He spent some time in Nigeria."}], "question": "What first attracted Terence to the topic of Ife sculptures?"}, {"correct": 2, "options": [{"option_text": "A. abstract designs."}, {"option_text": "B. fish and wild animals."}, {"option_text": "C. people."}], "question": "In his presentation Terence will focus on sculptures featuring"}, {"correct": 0, "options": [{"option_text": "A. He received money from an arts organisation."}, {"option_text": "B. His mother and father paid for him."}, {"option_text": "C. He wrote about the trip for a newspaper."}], "question": "How did Terence finance his trip to Ife?"}, {"correct": 1, "options": [{"option_text": "A. helping at an archaeological site"}, {"option_text": "B. the professor he met"}, {"option_text": "C. the artists he got to know"}], "question": "What was most memorable for Terence about his trip?"}]', 'null', 'null', 'null', '[{"content": "<p data-start=\"67\" data-end=\"235\">Tutor: Okay Terence, now I’ve looked through your preliminary outline and notes for the presentation on the art of the Ife region in Africa – that’s in Nigeria right?</p>\n<p data-start=\"237\" data-end=\"324\">Terence: Yes, I’m concentrating on life sculptures from the 12th to the 15th century.</p>\n<p data-start=\"326\" data-end=\"455\">Tutor: How did you get interested in that? I know there have been some recent articles in the journals about African sculpture.</p>\n<p data-start=\"457\" data-end=\"748\">Terence: Well I’ve read most of those now, but <strong><span style=\"background-color: #f1c40f;\">(21) initially I got my introduction to this at a special display at the City Museum a few years ago</span></strong>. I just happened to be there and saw these works and thought they were fantastic, and I even went to Nigeria last summer to see more of them.</p>\n<p data-start=\"750\" data-end=\"894\">Tutor: I’ve seen the photos for your presentation and I must say the sculptures are gorgeous portrayals of what appear to be kings and Queens.</p>\n<p data-start=\"896\" data-end=\"1249\">Terence: <span style=\"background-color: #f1c40f;\"><strong>(22) Yes I decided to concentrate on those as they’re the most typical</strong></span>. They’re interesting because they’re so naturalistic, unlike the abstract figures we often associate with African art. There’s also a lovely sculpture of a mudfish and one of the scaly crocodile, but I didn’t get very good pictures of those so I won’t spend long on them.</p>\n<p data-start=\"1251\" data-end=\"1361\">Tutor: Right. So what was the city of Ife like when these works were made? It’s on the Niger River isn’t it?</p>\n<p data-start=\"1363\" data-end=\"1523\">Terence: Yeah, the boat traffic’s what made it a center of commerce then as it still is today, but nowadays it’s better known as the home of a big university.</p>\n<p data-start=\"1525\" data-end=\"1587\">Tutor: Speaking of modern day life, tell me about your trip.</p>\n<p data-start=\"1589\" data-end=\"1951\">Terence: Ha, I was incredibly lucky to be able to get enough money to go. My parents encouraged me but they couldn’t afford to send me. <span style=\"background-color: #f1c40f;\"><strong>(23) I applied for a grant from the Arts Council and in the end I got it</strong></span>. I also wrote a series of articles about my trip for the local newspaper but I didn’t get any money for that. I was just pleased to get them published.</p>\n<p data-start=\"1953\" data-end=\"1992\">Tutor: And the highlight of the trip?</p>\n<p data-start=\"1994\" data-end=\"2350\">Terence: <span style=\"background-color: #f1c40f;\"><strong>(24) That had to be meeting a professor working on the site in Ife</strong></span> who had been a young boy when they first discovered the sculptures by accident at a building site in 1938. He had been working at the site, of course I also got to talk to lots of artists who are working there today, and I got to try my hand at making a little sculpture myself.</p>\n<hr data-start=\"2352\" data-end=\"2355\">\n<p data-start=\"2357\" data-end=\"2488\">Tutor: Well let’s see what you might do to improve what you’re planning for your presentation. About the sculptures themselves…</p>\n<p data-start=\"2490\" data-end=\"2708\">Terence: I think <span style=\"background-color: #f1c40f;\"><strong>(25/26) I need to add as much as possible about the details of the way they were made</strong></span>. Of course, I can’t add anything about the artists who made them because nobody really knows anything about them.</p>\n<p data-start=\"2710\" data-end=\"2937\">Tutor: All good points, and you’ve certainly said enough about what the sculptures depict and what the subjects are, that’s well covered. But <span style=\"background-color: #f1c40f;\"><strong>(25/26) I’d make some bigger photos of them so you can clearly see the fine detail</strong></span>.</p>\n<p data-start=\"2939\" data-end=\"3175\">Terence: Okay, and I would limit my personal reactions to these works of art if I were you. I know you think they’re fantastic. You’re right, I’ll contain my enthusiasm. What about the section of the presentation which I call history?</p>\n<p data-start=\"3177\" data-end=\"3349\">Terence: <span style=\"background-color: #f1c40f;\"><strong>(27/28) I’d like to go into more depth about the history of that whole area, you know in the countries around Nigeria</strong></span>. That would make the presentation stronger.</p>\n<p data-start=\"3351\" data-end=\"3664\">Tutor: But I think you’ve covered the situation regarding the rulers of the country quite well and you’ve got plenty already about what the Ife people were doing then and the way their society was structured. And in fact I think you could cut out the bit about modern Nigerian history because it’s not relevant.</p>\n<p data-start=\"3666\" data-end=\"3853\">Terence: I agree that doesn’t fit, <span style=\"background-color: #f1c40f;\"><strong>(27/28) but perhaps I should concentrate more on the religious beliefs</strong></span>, since all these sculptures do seem to have some kind of religious association.</p>\n<p data-start=\"3855\" data-end=\"4092\">Tutor: Good, I can lend you a book on that. Now, probably the part the class will find most interesting is the report of your trip to Nigeria and the research you did there. So I gather you managed to use the university library in Ife?</p>\n<p data-start=\"4094\" data-end=\"4547\">Terence: Yes, as soon as I had explained why I wanted the information, that was no problem; they couldn’t have been more helpful. <span style=\"background-color: #f1c40f;\"><strong>(29/30) There were some interesting accounts of how the first sculptures were found and what happened to them, which I want to include</strong></span>. What struck me when I saw the sculptures in Nigeria is the extent to which 20th century European artists were influenced by them, but that’s beyond the scope of my presentation I think.</p>\n<p data-start=\"4549\" data-end=\"4646\">Tutor: Yes. What about the sources of the materials they used? You don’t mention that anywhere.</p>\n<p data-start=\"4648\" data-end=\"4888\">Terence: <span style=\"background-color: #f1c40f;\"><strong>(29/30) I didn’t manage to find out much about that</strong></span>. I want to cover <span style=\"background-color: #f1c40f;\"><strong>(29/30) the theories about who the original sculptors were though</strong></span>… the idea that a lot of them may have been made by the same person. That’s very interesting.</p>\n<p data-start=\"4890\" data-end=\"4982\">Tutor: It is, isn’t it? Right, well thanks for all the advice. Now I think I need to work.</p>"}]', 0);
INSERT INTO public.questions VALUES ('f45f39f8-aa4e-4b2e-91de-289b3b02822d', 'de8e13ca-75a0-430e-8ef4-9a7c3b1083b1', 'fillup', 'Questions 24-26', '<p>Complete the summary below.</p>
<p>Choose <strong>ONE WORD ONLY</strong> from the passage for each answer.</p>
<p style="text-align: center;"><span style="font-size: 12pt;"><strong>The bluestriped fangblenny</strong></span></p>
<p>Dr Karen Cheney studies the bluestriped fanblenny on {reefs} off Queensland’s coast. She found that the fangblenny was able to make itself resemble other fish by adjusting its colouration. The fangblenny impersonates the striped cleaner wrasse, a fish that is welcomed by other specie as it gets rid of their {parasites} The fangblenny can approach its {prey} without drawing the attention of predators or disturbing the work of the striped cleaner.</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p><strong data-path-to-node=\"27\" data-index-in-node=\"0\">24. reefs</strong></p>\n<ul data-path-to-node=\"28\">\n<li><strong data-path-to-node=\"28,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn <strong data-path-to-node=\"28,0,0\" data-index-in-node=\"16\">D</strong>: “On Queensland’s <strong data-path-to-node=\"28,0,0\" data-index-in-node=\"36\">reefs</strong>, scientists have been studying another ocean dweller…”</li>\n<li><strong data-path-to-node=\"28,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tiến sĩ Karen Cheney nghiên cứu loài cá Bluestriped fangblenny tại các rạn san hô (reefs).</li>\n</ul>\n<p><strong data-path-to-node=\"29\" data-index-in-node=\"0\">25. parasites</strong></p>\n<ul data-path-to-node=\"30\">\n<li><strong data-path-to-node=\"30,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn <strong data-path-to-node=\"30,0,0\" data-index-in-node=\"16\">D</strong>: “…cleaner wrasse which eats the <strong data-path-to-node=\"30,0,0\" data-index-in-node=\"53\">parasites</strong> on larger fish.”</li>\n<li><strong data-path-to-node=\"30,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cá bống dọn dẹp (cleaner wrasse) giúp các loài cá lớn loại bỏ ký sinh trùng (parasites).</li>\n</ul>\n<p><strong data-path-to-node=\"31\" data-index-in-node=\"0\">26. prey</strong></p>\n<ul data-path-to-node=\"32\">\n<li><strong data-path-to-node=\"32,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn <strong data-path-to-node=\"32,0,0\" data-index-in-node=\"16\">D</strong>: “…the disguise also lets it get closer to <strong data-path-to-node=\"32,0,0\" data-index-in-node=\"63\">prey</strong>.”</li>\n<li><strong data-path-to-node=\"32,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Nhờ giả dạng cá dọn dẹp, cá Fangblenny có thể tiếp cận con mồi (<strong data-path-to-node=\"32,1,0\" data-index-in-node=\"76\">prey</strong>) của nó một cách dễ dàng mà không bị nghi ngờ.</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('10e1bbfd-3e6e-411f-b835-d5a878f2e758', '070c2ae9-80cd-44bb-a907-42ae423bb2c2', 'checkbox', 'Questions 25-26', '', '<p data-start="903" data-end="929">Choose <strong>TWO </strong>letters, <strong>A</strong>–<strong>E</strong>.</p>
<p data-start="931" data-end="1021">Which <strong>TWO </strong>additions will Terence make to the part of the presentation on the sculptures?</p>', 'multiple_choice', 'null', '[{"correct": true, "option_text": "A. enlarged pictures of the sculptures"}, {"correct": false, "option_text": "B. more material about the subjects"}, {"correct": false, "option_text": "C. more about his personal opinion of the art works"}, {"correct": true, "option_text": "D. extra information about the techniques used"}, {"correct": false, "option_text": "E. additional information about the artists"}]', 'null', 'null', 'null', 1);
INSERT INTO public.questions VALUES ('6e79d24d-2ffe-42c7-b6ba-9c6b4ca59083', '070c2ae9-80cd-44bb-a907-42ae423bb2c2', 'checkbox', 'Questions 27-28', '', '<p data-start="1287" data-end="1313">Choose <strong>TWO </strong>letters, <strong>A</strong>–<strong>E</strong>.</p>
<p data-start="1315" data-end="1381">Which <strong>TWO </strong>additions will Terence make to the section on history?</p>', 'multiple_choice', 'null', '[{"correct": false, "option_text": "A. data about the kings in the Ife area"}, {"correct": true, "option_text": "B. extra information about the surrounding region"}, {"correct": true, "option_text": "C. examination of the beliefs of the Ife people"}, {"correct": false, "option_text": "D. an explanation of the development of modern Ife"}, {"correct": false, "option_text": "E. more details of past activities of the Ife people"}]', 'null', 'null', 'null', 2);
INSERT INTO public.questions VALUES ('6392cd8f-d94d-4413-ab17-ef11b5567f0f', '5ef1e11c-4642-4793-a096-ba56f8d6b7ab', 'matrix', 'Questions 27–31', NULL, '<p>Reading Passage 3 has eight paragraphs, <strong>A-H</strong>.</p>
<p>Which paragraph contains the following information?</p>
<p>Choose the correct letter, <strong>A-H</strong>, in boxes 27-31.</p>
<p>NB You may use any letter more than once.</p>
', 'classification', 'null', 'null', 'null', '{"layoutType": "simple", "legendTitle": null, "matrixItems": [{"itemText": "the part of cocoa trees used for chocolate production", "correctCategoryLetter": "F"}, {"itemText": "annual chocolate consumption per capita in the United States", "correctCategoryLetter": "H"}, {"itemText": "the higher likelihood of cultivated cocoa trees being attacked by insects", "correctCategoryLetter": "F"}, {"itemText": "a community which developed a preference for sweetened chocolate beverages", "correctCategoryLetter": "E"}, {"itemText": "an approach by which ancient Mexicans could acquire cocoa beans", "correctCategoryLetter": "D"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}, {"categoryText": "H", "categoryLetter": "H"}]}', '[{"content": "<p data-path-to-node=\"2\"><strong>27. the part of cocoa trees used for chocolate production</strong></p>\n<ul data-path-to-node=\"3\">\n<li>\n<p data-path-to-node=\"3,0,0\"><strong>Đáp án: F</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"3,1,0\"><strong>Dẫn chứng:</strong> (Đoạn F) “These pods contain the <strong>beans</strong> used in chocolate production.”</p>\n</li>\n<li>\n<p data-path-to-node=\"3,2,0\"><strong>Giải thích:</strong> Đoạn F mô tả quả (pod) và hạt (<strong>beans</strong>) là bộ phận của cây được dùng để sản xuất sô cô la.</p>\n</li>\n</ul>\n<p data-path-to-node=\"4\"><strong>28. annual chocolate consumption per capita in the United States</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong>Đáp án: H</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong>Dẫn chứng:</strong> (Đoạn H) “<strong>On average, Americans consume over five kilogrammes of chocolate per person each year</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"5,2,0\"><strong>Giải thích:</strong> Đoạn H cung cấp số liệu thống kê về mức tiêu thụ sô cô la hàng năm tính trên đầu người (per capita) ở Mỹ.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong>29. the higher likelihood of cultivated cocoa trees being attacked by insects</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong>Đáp án: F</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong>Dẫn chứng:</strong> (Đoạn F) “<strong>Unexpectedly, cocoa trees grown on farms are more vulnerable to disease and pests than their wild counterparts</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"7,2,0\"><strong>Giải thích:</strong> Đoạn F so sánh khả năng bị bệnh dịch và sâu bệnh (bao gồm côn trùng/insects) của cây trồng (cultivated) so với cây dại (wild counterparts).</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong>30. a community which developed a preference for sweetened chocolate beverages</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong>Đáp án: E</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong>Dẫn chứng:</strong> (Đoạn E) “<strong>Spanish elite first developed a taste for sweetened chocolate drinks</strong>…”</p>\n</li>\n<li>\n<p data-path-to-node=\"9,2,0\"><strong>Giải thích:</strong> Đoạn E nói về việc giới tinh hoa Tây Ban Nha (Spanish elite/community) là những người đầu tiên phát triển sở thích uống sô cô la có đường.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong>31. an approach by which ancient Mexicans could acquire cocoa beans</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong>Đáp án: D</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong>Dẫn chứng:</strong> (Đoạn D) “The Aztec civilisation in Mexico… Accordingly, <strong>they sourced cocoa beans through extensive trade networks</strong>…”</p>\n</li>\n<li>\n<p data-path-to-node=\"11,2,0\"><strong>Giải thích:</strong> Đoạn D mô tả cách người Aztec (Mexicans) thu mua hạt ca cao thông qua mạng lưới thương mại (trade networks), do không thể tự trồng.</p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('a5535b56-f744-473c-8acf-11ea4148ca02', '3153cf39-3063-4779-8f50-99f72bffc690', 'checkbox', 'Questions 21–22', '', '<p>Choose <strong>TWO</strong> correct answers.</p>
<p>Which <strong>TWO</strong> of the following statements are true of the ‘claque’ in France?</p>', 'multiple_choice', 'null', '[{"correct": true, "option_text": "As a practice in France, it first appeared in the 16th century."}, {"correct": false, "option_text": "It did not become a widespread practice within France."}, {"correct": false, "option_text": "The cost of hire depended on the fame of the client."}, {"correct": true, "option_text": "Claqueurs were divided into different categories."}, {"correct": false, "option_text": "The practice did not extend beyond France to other countries."}]', 'null', 'null', '[{"content": "<p data-path-to-node=\"1\"><strong data-path-to-node=\"1\" data-index-in-node=\"0\">21. As a practice in France, it first appeared in the 16th century.</strong></p>\n<ul data-path-to-node=\"2\">\n<li>\n<p data-path-to-node=\"2,0,0\"><strong data-path-to-node=\"2,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 5, dòng 1–3.</p>\n</li>\n<li>\n<p data-path-to-node=\"2,1,0\"><strong data-path-to-node=\"2,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “16th-century French poet Jean Daurat is credited with <strong data-path-to-node=\"2,1,0\" data-index-in-node=\"66\">bringing back the Roman practice</strong> of hiring professional applauders. In France, this group became known as a ‘claque’.”</p>\n</li>\n<li>\n<p data-path-to-node=\"2,2,0\"><strong data-path-to-node=\"2,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc xác nhận rằng hình thức thuê người vỗ tay chuyên nghiệp (claque) bắt đầu xuất hiện trở lại tại Pháp vào thế kỷ 16 nhờ công của nhà thơ Jean Daurat. Đây là mốc thời gian đầu tiên mà hoạt động này được ghi nhận tại quốc gia này.</p>\n</li>\n</ul>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">22. Claqueurs were divided into different categories.</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 5, dòng 9–13.</p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “The claque also underwent a kind of <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"48\">classification</strong>: the <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"68\">rieurs</strong> (laughers)… the <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"93\">pleureurs</strong> (criers)… the <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"119\">commissaires</strong> (officers)…”</p>\n</li>\n<li>\n<p data-path-to-node=\"4,2,0\"><strong data-path-to-node=\"4,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Những người vỗ tay thuê (claqueurs) không chỉ làm một nhiệm vụ duy nhất mà được phân loại thành nhiều nhóm chuyên biệt: nhóm chuyên cười lớn (rieurs), nhóm giả vờ khóc (pleureurs) hay nhóm chuyên ghi nhớ tác phẩm để điều hướng sự chú ý của khán giả (commissaires). Điều này khớp hoàn toàn với ý “được chia thành các danh mục/loại khác nhau” trong câu hỏi.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('0ca8cf92-6a9e-490c-a059-30afd17bffd5', '798c40f7-b5a7-4fb8-bca5-9da55386ab0f', 'fillup', 'Questions 27–32', '<p data-start="69" data-end="163"><span style="font-size: 12pt;">Complete the table</span><br data-start="91" data-end="94"><span style="font-size: 12pt;">Choose <strong>NO MORE THAN THREE WORDS</strong> from the passage for each answer.</span></p>
<p data-start="165" data-end="220"><span style="font-size: 12pt;">Write your answers in boxes 27–32 on your answer sheet.</span></p>
<h3 style="text-align: center;" data-start="227" data-end="254"><span style="font-size: 12pt;"><strong data-start="231" data-end="254">Source of knowledge</strong></span></h3>
<p data-start="256" data-end="502"><span style="font-size: 12pt;">Examples</span><br data-start="268" data-end="271"><span style="font-size: 12pt;">Personal experience</span><br data-start="294" data-end="297"><span style="font-size: 12pt;">Symptoms of a {bad cough} and tiredness</span><br data-start="355" data-end="358"><span style="font-size: 12pt;">Doctor’s measurement by taking {blood pressure} and temperature</span><br data-start="435" data-end="438"><span style="font-size: 12pt;">Common judgment from {families and friends} around you</span></p>
<h3 style="text-align: center;" data-start="509" data-end="538"><span style="font-size: 12pt;"><strong data-start="513" data-end="536">Scientific evidence</strong></span></h3>
<p data-start="540" data-end="752"><span style="font-size: 12pt;">Medical knowledge from the general {Practitioner}</span><br data-start="605" data-end="608"><span style="font-size: 12pt;">e.g. doctor’s medical {Diagnosis}</span><br data-start="660" data-end="663"><span style="font-size: 12pt;">Examine the medical hypothesis with the previous drill and {background}</span></p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p>27. bad cough<br />(Đoạn C: “You have a bad cough and always seem to be tired.”)<br />→ Dấu hiệu ban đầu do trải nghiệm cá nhân — biểu hiện rõ ràng là ho nặng và mệt mỏi.<br />→ Đáp án: bad cough<br /> <br />28. blood pressure<br />(Đoạn C: “&#8230;listens to your chest and heart, takes your temperature and blood pressure&#8230;”)<br />→ Bác sĩ đo huyết áp và nhiệt độ để thu thập dữ liệu y học.<br />→ Đáp án: blood pressure<br /> <br />29. families and friends<br />(Đoạn G: “Comments from friends and family such as ‘you do look ill’ or ‘that’s a bad cough’ might be another source of knowledge.”)<br />→ Những người thân và bạn bè xung quanh là nguồn nhận xét thông thường giúp nhận biết tình trạng bệnh.<br />→ Đáp án: families and friends<br /> <br />30. Practitioner<br />(Đoạn H: “Perhaps the most influential and authoritative source of knowledge is the medical knowledge provided by the general practitioner.”)<br />→ Nguồn kiến thức y học đến từ bác sĩ đa khoa (general practitioner).<br />→ Đáp án: Practitioner<br /> <br />31. Diagnosis<br />(Đoạn D: “&#8230;you now have proof that you are ill&#8230; This is the result of&#8230; the diagnosis of someone who has the status of a medical expert.”)<br />→ Kết luận của bác sĩ chính là chẩn đoán y học (medical diagnosis).<br />→ Đáp án: Diagnosis<br /> <br />32. background<br />(Đoạn I: “Given the doctor’s medical training and background, she may hypothesize ‘is this now pneumonia?’&#8230;”)<br />→ Khi kiểm tra giả thuyết, bác sĩ dựa vào kinh nghiệm và nền tảng kiến thức (background) đã có.<br />→ Đáp án: background<br /> <br /> <br /> </p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('e8cd2e43-1760-4227-aad8-939857675b44', '798c40f7-b5a7-4fb8-bca5-9da55386ab0f', 'matrix', 'Questions 33–40', NULL, '<p>Which paragraph contains the following information?</p>
<p>Choose the correct letter <strong>A–I</strong>, in boxes 33–40 on your answer sheet.</p>
', 'other', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": null, "matrixItems": [{"itemText": "the contrast between the nature of personal judgment and the nature of doctor’s diagnosis", "correctCategoryLetter": "E"}, {"itemText": "a reference of culture about pressure", "correctCategoryLetter": "F"}, {"itemText": "sick leave will not be permitted without the professional diagnosis", "correctCategoryLetter": "H"}, {"itemText": "how doctors’ opinions are regarded in society", "correctCategoryLetter": "H"}, {"itemText": "the illness of patients can become part of new knowledge", "correctCategoryLetter": "I"}, {"itemText": "a description of knowledge drawn from non-specialized sources other than personal knowledge", "correctCategoryLetter": "G"}, {"itemText": "an example of collective judgment from personal experience and professional doctor", "correctCategoryLetter": "D"}, {"itemText": "a reference that some people do not realize they are ill", "correctCategoryLetter": "B"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}, {"categoryText": "H", "categoryLetter": "H"}, {"categoryText": "I", "categoryLetter": "I"}]}', '[{"content": "<p>33. E – the contrast between the nature of personal judgment and the nature of doctor’s diagnosis<br />(Đoạn E: “you decide to consult the doctor in the first place because you feel unwell… However, the doctor’s expert diagnosis is based on experience and training&#8230;”)<br />→ Đoạn này thể hiện sự đối lập giữa nhận định cá nhân (feeling unwell) và chẩn đoán chuyên môn của bác sĩ.<br />→ Đáp án: E<br /> <br />34. F – a reference of culture about pressure<br />(Đoạn F: “Over the past decade, for example, Western culture has seen a significant emphasis on stress-related illness in the media&#8230; Reference to being ‘stressed out’ has become a common response…”)<br />→ Đề cập rõ đến ảnh hưởng văn hoá phương Tây về bệnh do căng thẳng (stress).<br />→ Đáp án: F<br /> <br />35. H – sick leave will not be permitted without the professional diagnosis<br />(Đoạn H: “We need an expert medical diagnosis in order to obtain the necessary certificate if we need to be off work…”)<br />→ Nói rằng nghỉ bệnh sẽ không được chấp nhận nếu không có chẩn đoán chuyên môn của bác sĩ.<br />→ Đáp án: H<br /> <br />36. H – how doctors’ opinions are regarded in society<br />(Đoạn H: “The knowledge of the medical sciences is privileged in this respect in contemporary Western culture. Medical practitioners are also seen as having the required expert knowledge&#8230;”)<br />→ Thể hiện vai trò và sự tôn trọng của xã hội dành cho bác sĩ.<br />→ Đáp án: H<br /> <br />37. I – the illness of patients can become part of new knowledge<br />(Đoạn I: “Given the doctor’s medical training and background… This results in new knowledge and new experience both for you and for the doctor.”)<br />→ Kinh nghiệm chẩn đoán bệnh của bác sĩ giúp hình thành kiến thức mới.<br />→ Đáp án: I<br /> <br />38. G – a description of knowledge drawn from non-specialized sources other than personal knowledge<br />(Đoạn G: “Comments from friends and family… Complementary health practices, such as holistic medicine, produce their own sets of knowledge…”)<br />→ Nguồn kiến thức đến từ bạn bè, người thân và y học thay thế (không chuyên môn).<br />→ Đáp án: G<br /> <br />39. D – an example of collective judgment from personal experience and professional doctor<br />(Đoạn D: “Although you still have the same symptoms&#8230; you now have proof that you are ill. This is the result of the combination of your own subjective experience and the diagnosis of a medical expert.”)<br />→ Đây là ví dụ về sự kết hợp giữa cảm nhận cá nhân và đánh giá của bác sĩ.<br />→ Đáp án: D<br /> <br />40. B – a reference that some people do not realize they are ill<br />(Đoạn B: “At other times, people may be suffering from a disease and fail to be aware of the illness until it has reached a late stage…”)<br />→ Đề cập đến những người mắc bệnh nhưng không nhận ra.<br />→ Đáp án: B<br /> <br /> <br /> </p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('b06614c6-a748-45d7-93e5-3f24067e3822', '49a8ee2f-6bf3-4fc5-bfb1-67addbc87b1b', 'fillup', 'Questions 11-20', '<p><span style="mso-bidi-font-size: 13.0pt; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;">Write <strong>NO MORE THAN TWO WORDS AND/OR A NUMBER</strong> for each answer.</span></p>
<p><strong><span style="font-size: 16.0pt; mso-bidi-font-size: 13.0pt; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;">Introduction to the Evening Course</span></strong></p>
<p><strong><span style="mso-bidi-font-size: 13.0pt; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;">Class time</span></strong></p>
<p style="line-height: normal; padding-left: 40px;"><span style="mso-bidi-font-size: 13.0pt; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;">&#8211; evening class starts at: {7:30 | 7.30} p.m.</span></p>
<p><strong><span style="mso-bidi-font-size: 13.0pt; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;">Feedback</span></strong></p>
<p style="line-height: normal; padding-left: 40px;"><span style="mso-bidi-font-size: 13.0pt; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;">&#8211; submit complaints to the {administrative officer } </span></p>
<p><strong><span style="mso-bidi-font-size: 13.0pt; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;">Beverage:</span></strong></p>
<p style="line-height: normal; padding-left: 40px;"><span style="mso-bidi-font-size: 13.0pt; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;">&#8211; drinking water available on the second floor</span></p>
<p style="line-height: normal; padding-left: 40px;"><span style="mso-bidi-font-size: 13.0pt; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;">&#8211; hot drinks: in the {common room}</span></p>
<p><strong><span style="mso-bidi-font-size: 13.0pt; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;">Parking:</span></strong></p>
<p style="line-height: normal; padding-left: 40px;"><span style="mso-bidi-font-size: 13.0pt; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;">&#8211; a {permit}  is required</span></p>
<p><strong><span style="mso-bidi-font-size: 13.0pt; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;">Late-night private study:</span></strong></p>
<p style="line-height: normal; padding-left: 40px;"><span style="mso-bidi-font-size: 13.0pt; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;">&#8211; ask the {security offer}</span>  for permission</p>
<p><strong><span style="mso-bidi-font-size: 13.0pt; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;">Important facts of the new course</span></strong></p>
<p style="line-height: normal; padding-left: 40px;"><span style="mso-bidi-font-size: 13.0pt; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;">&#8211; The course will last for {12 weeks | twelve weeks}</span></p>
<p style="line-height: normal; padding-left: 40px;"><span style="mso-bidi-font-size: 13.0pt; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;">&#8211; The {fire drill}</span>  is once a month</p>
<p style="line-height: normal; padding-left: 40px;"><span style="mso-bidi-font-size: 13.0pt; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;">&#8211; Valuable belongings are to be kept in the {locker | lockers} for safe storage</span></p>
<p style="line-height: normal; padding-left: 40px;"><span style="mso-bidi-font-size: 13.0pt; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;">&#8211; The unpaid tutorial fees can be paid by {cash} </span></p>
<p style="line-height: normal; padding-left: 40px;"><span style="mso-bidi-font-size: 13.0pt; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;">&#8211; There will be a required seminar followed by a {reception}  next week</span></p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p>Good morning! I believe your holiday was fun. Well, we are back to school now, back to work, so let us all adjust. And in case your notes are dusty, you can go clean them up. It’s a new session. First up, we would be making slight adjustments to some of our classes this time around.</p>\n<blockquote>\n<p><strong>Dịch:</strong> Chào buổi sáng! Tôi tin rằng kỳ nghỉ của các bạn rất vui. Vâng, giờ chúng ta đã trở lại trường học, trở lại công việc, vì vậy hãy cùng nhau điều chỉnh. Và nếu tài liệu của các bạn bám bụi, các bạn có thể đi lau dọn chúng. Đây là một học kỳ mới. Đầu tiên, chúng ta sẽ có một vài điều chỉnh nhỏ đối với một số lớp học trong học kỳ này.</p>\n</blockquote>\n<h3><strong>Class time (Thời gian học)</strong></h3>\n<p>Last session, we used to have our evening classes by 8 PM, but now it has been shifted up to <strong>(11) seven thirty (7.30)</strong> PM. This enables you to have time to rest before the next day, as we noticed that the evening classes took too much time, and many times you were all tired before it was over.</p>\n<blockquote>\n<p><strong>Dịch:</strong> Học kỳ trước, lớp buổi tối của chúng ta thường bắt đầu lúc 8 giờ tối, nhưng giờ đã được chuyển lên <strong>(11) 7 giờ 30 phút (7.30)</strong> tối. Điều này giúp các bạn có thời gian nghỉ ngơi trước ngày hôm sau, vì chúng tôi nhận thấy các lớp buổi tối thường kéo dài quá lâu và nhiều lần các bạn đều mệt mỏi trước khi kết thúc.</p>\n</blockquote>\n<h3><strong>Feedback (Phản hồi)</strong></h3>\n<p>The centre manager used to be in charge of addressing negative feedback from students. As new duties have been assigned to the manager, the <strong>(12) administrative officer</strong> will now take over the responsibility for handling complaints.</p>\n<blockquote>\n<p><strong>Dịch:</strong> Quản lý trung tâm trước đây phụ trách việc giải quyết các phản hồi tiêu cực từ sinh viên. Do quản lý đã được giao các nhiệm vụ mới, <strong>(12) nhân viên hành chính</strong> sẽ tiếp quản trách nhiệm xử lý các khiếu nại.</p>\n</blockquote>\n<h3><strong>Beverage (Đồ uống)</strong></h3>\n<p>Additionally, we have received complaints regarding the distance of the drinking water access from the main building. To address this, a new access point will be added on the ground floor, clearly marked with signage. However, following an incident last session involving spillage, hot drinks will no longer be permitted in the computer room; please consume them only in the <strong>(13) common room</strong>.</p>\n<blockquote>\n<p><strong>Dịch:</strong> Ngoài ra, chúng tôi đã nhận được khiếu nại về khoảng cách từ tòa nhà chính đến khu vực lấy nước uống. Để giải quyết vấn đề này, một điểm lấy nước mới sẽ được bổ sung ở tầng trệt (Lưu ý: Nước uống có ở <em>ground floor</em>, không phải <em>second floor</em> theo thông tin trong bài). Tuy nhiên, sau một sự cố đổ tràn xảy ra vào học kỳ trước, đồ uống nóng sẽ không còn được phép mang vào phòng máy tính; vui lòng chỉ tiêu thụ chúng trong <strong>(13) phòng sinh hoạt chung</strong>.</p>\n</blockquote>\n<h3><strong>Parking (Đỗ xe)</strong></h3>\n<p>It is also important to note that this session, you would need a <strong>(14) permit</strong> to park in the parking lot due to the congestion in recent times, and the fact that we want to be able to regulate who uses the lot. If you do not get a permit, you would get a fine.</p>\n<blockquote>\n<p><strong>Dịch:</strong> Điều quan trọng cần lưu ý là trong học kỳ này, các bạn sẽ cần <strong>(14) giấy phép</strong> để đỗ xe trong bãi đỗ xe, do tình trạng tắc nghẽn gần đây và thực tế là chúng tôi muốn kiểm soát ai được sử dụng bãi đỗ. Nếu các bạn không có giấy phép, các bạn sẽ bị phạt.</p>\n</blockquote>\n<h3><strong>Late-night private study (Học khuya)</strong></h3>\n<p>In the same vein of trying to up security measures, staying on your own to study after midnight would not be open to everyone without permission; you would have to see the <strong>(15) security officer</strong> for that.</p>\n<blockquote>\n<p><strong>Dịch:</strong> Tương tự như việc cố gắng tăng cường các biện pháp an ninh, việc tự học một mình sau nửa đêm sẽ không được mở cho tất cả mọi người mà không có sự cho phép; các bạn sẽ phải gặp <strong>(15) nhân viên an ninh</strong> để xin phép.</p>\n</blockquote>\n<h3><strong>Important facts of the new course (Thông tin Khóa học quan trọng)</strong></h3>\n<p>Please note that this semester will run for the usual 13 weeks, including one week for a break. With this course spanning <strong>(16) 12 weeks</strong>, it is expedient that you study well and keep striving to graduate with flying colours.</p>\n<blockquote>\n<p><strong>Dịch:</strong> Xin lưu ý rằng học kỳ này sẽ kéo dài 13 tuần như thường lệ, bao gồm một tuần nghỉ. Với khóa học kéo dài <strong>(16) 12 tuần</strong>, điều quan trọng là các bạn phải học tập chăm chỉ và tiếp tục phấn đấu tốt nghiệp với kết quả xuất sắc.</p>\n</blockquote>\n<p>According to recommendation, our <strong>(17) fire drill</strong> remains once in a month, as it has always been. This is for everyone’s safety.</p>\n<blockquote>\n<p><strong>Dịch:</strong> Theo khuyến nghị, buổi <strong>(17) diễn tập phòng cháy chữa cháy</strong> của chúng ta vẫn diễn ra mỗi tháng một lần như thường lệ. Điều này là vì sự an toàn của tất cả mọi người.</p>\n</blockquote>\n<p>Last semester, we noticed that lots of valuables were reported missing. This semester we are taking steps to prevent such incidents from recurring. The installation of <strong>(18) lockers</strong> serves as a measure to enhance security and minimize the risk of theft. Do remember to use them. Also, we do not want to find things lying aimlessly around. We have directed our cleaning staff to pick such items up and put them away. We might not be able to accept requests for retrieval until the end of the semester.</p>\n<blockquote>\n<p><strong>Dịch:</strong> Học kỳ trước, chúng tôi nhận thấy nhiều vật có giá trị đã bị báo cáo mất. Học kỳ này, chúng tôi đang thực hiện các bước để ngăn chặn những sự cố như vậy tái diễn. Việc lắp đặt <strong>(18) tủ khóa</strong> là một biện pháp tăng cường an ninh và giảm thiểu rủi ro trộm cắp. Hãy nhớ sử dụng chúng. Ngoài ra, chúng tôi không muốn tìm thấy đồ đạc nằm lung tung. (Phần sau nói về việc không nhận lại đồ cho đến cuối học kỳ).</p>\n</blockquote>\n<p>We recently received some complaints about the cashless policy on tutorial fees. Well, we always want to make life easier for our students, and so have reviewed it this semester. If you chose to pay the initial fees through electronic modes last month, you can now settle the unpaid tutorial fees by <strong>(19) cash</strong>.</p>\n<blockquote>\n<p><strong>Dịch:</strong> Gần đây, chúng tôi đã nhận được một số khiếu nại về chính sách không dùng tiền mặt đối với phí hướng dẫn. Vâng, chúng tôi luôn muốn làm cho cuộc sống của sinh viên dễ dàng hơn, và do đó đã xem xét lại chính sách này trong học kỳ này. Nếu tháng trước bạn chọn thanh toán phí ban đầu qua các phương thức điện tử, giờ đây bạn có thể thanh toán phí hướng dẫn chưa thanh toán bằng <strong>(19) tiền mặt</strong>.</p>\n</blockquote>\n<p>There will be a required seminar followed by a <strong>(20) reception</strong> next week.</p>\n<blockquote>\n<p><strong>Dịch:</strong> Sẽ có một buổi hội thảo bắt buộc, tiếp theo là một buổi <strong>(20) chiêu đãi</strong> vào tuần tới.</p>\n</blockquote>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('6c6bfea0-c492-4499-ab05-6a3c7682924d', '070c2ae9-80cd-44bb-a907-42ae423bb2c2', 'checkbox', 'Questions 29-30', '', '<p data-start="1671" data-end="1697">Choose <strong>TWO </strong>letters, <strong>A</strong>–<strong>E</strong>.</p>
<p data-start="1699" data-end="1788">Which <strong>TWO </strong>features of his research in Nigeria will Terence discuss in his presentation?</p>', 'multiple_choice', 'null', '[{"correct": false, "option_text": "A. the influence of the sculptures on western artists"}, {"correct": true, "option_text": "B. the uncertainty over who made the sculptures"}, {"correct": false, "option_text": "C. the sources of the materials used for the sculptures"}, {"correct": true, "option_text": "D. the problems he faced in collecting information"}]', 'null', 'null', 'null', 3);
INSERT INTO public.questions VALUES ('3d80b317-5f7f-4634-a881-3a458819bd1c', '54b5d50e-2b92-428b-97f1-575db48b7897', 'matching', 'Questions 19–22', '', '<p data-path-to-node="4"><span class="citation-14525 citation-14526 citation-end-14526">Match each researcher with the correct finding.</span></p>
<p data-path-to-node="5"><span class="citation-14523 citation-14524">Write the correct letter </span><strong data-path-to-node="5" data-index-in-node="25"><span class="citation-14523 citation-14524">A-G</span></strong><span class="citation-14523 citation-14524 citation-end-14524"> in boxes 19-22 on your answer</span><span class="citation-14523 citation-end-14523"> sheet.</span></p>', 'matching_name', 'null', 'null', '{"layoutType": "standard", "summaryText": "", "answerOptions": [{"optionText": "Early language evolution is correlated to body movement and thus affecting the preference of use of one hand."}, {"optionText": "No single biological component determines the handedness of a child."}, {"optionText": "Each hemisphere of the brain is in charge of different body functions."}, {"optionText": "Language process is mainly centered in the left-hemisphere of the brain."}, {"optionText": " Speech difficulties are often caused by brain damage."}, {"optionText": "The rate of development of one side of the body has influence on hemisphere preference in fetus."}, {"optionText": "Brain function already matures by the end of the fetal stage."}], "matchingItems": [{"questionPart": "Marian Annett", "correctAnswer": "B"}, {"questionPart": "Peter Hepper", "correctAnswer": "F"}, {"questionPart": "Brenda Milner & Theodore Rasmussen", "correctAnswer": "D"}, {"questionPart": "Michael Corballis", "correctAnswer": "A"}]}', 'null', '[{"content": "<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">19. Marian Annett — {B: No single biological component determines the handedness of a child.}</strong></p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…hypothesized that <strong data-path-to-node=\"16,0,0\" data-index-in-node=\"33\">no single gene determines handedness</strong>.” (Đoạn A)</p>\n</li>\n<li>\n<p data-path-to-node=\"16,1,0\"><strong data-path-to-node=\"16,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “No single gene” tương ứng với “no single biological component” (không có một thành phần sinh học/gen duy nhất nào quyết định).</p>\n</li>\n</ul>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">20. Peter Hepper — {F: The rate of development of one side of the body has influence on hemisphere preference in fetus.}</strong></p>\n<ul data-path-to-node=\"18\">\n<li>\n<p data-path-to-node=\"18,0,0\"><strong data-path-to-node=\"18,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “Hepper speculates that fetuses tend to prefer whichever side of the body is <strong data-path-to-node=\"18,0,0\" data-index-in-node=\"88\">developing quicker</strong> and that their movements… <strong data-path-to-node=\"18,0,0\" data-index-in-node=\"135\">influence the brain’s development</strong>.” (Đoạn B)</p>\n</li>\n<li>\n<p data-path-to-node=\"18,1,0\"><strong data-path-to-node=\"18,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Hepper cho rằng tốc độ phát triển (rate of development) của một bên cơ thể ảnh hưởng đến sự phát triển của bán cầu não tương ứng ở thai nhi.</p>\n</li>\n</ul>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">21. Brenda Milner &amp; Theodore Rasmussen — {D: Language process is mainly centered in the left-hemisphere of the brain.}</strong></p>\n<ul data-path-to-node=\"20\">\n<li>\n<p data-path-to-node=\"20,0,0\"><strong data-path-to-node=\"20,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…confirmed the theory… In <strong data-path-to-node=\"20,0,0\" data-index-in-node=\"42\">96 percent of right-handed people, language is processed much more intensely in the left hemisphere</strong>.” (Đoạn E)</p>\n</li>\n</ul>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">22. Michael Corballis — {A: Early language evolution is correlated to body movement and thus affecting the preference of use of one hand.}</strong></p>\n<ul data-path-to-node=\"22\">\n<li>\n<p data-path-to-node=\"22,0,0\"><strong data-path-to-node=\"22,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…think that the origin of human speech lies in <strong data-path-to-node=\"22,0,0\" data-index-in-node=\"61\">gestures</strong>… If the left hemisphere began to dominate speech, it would have <strong data-path-to-node=\"22,0,0\" data-index-in-node=\"136\">dominated gestures</strong>, too… the <strong data-path-to-node=\"22,0,0\" data-index-in-node=\"167\">right hand developed more strongly</strong>.” (Đoạn E)</p>\n</li>\n<li>\n<p data-path-to-node=\"22,1,0\"><strong data-path-to-node=\"22,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Ông cho rằng ngôn ngữ tiến hóa từ cử động (gestures), điều này kéo theo sự phát triển của tay thuận.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('51ace818-dc1a-4259-8c6b-babbaea052d2', 'c2b0c6b9-a53e-4cf0-8128-076ce9f9476b', 'checkbox', 'Questions 25-26', NULL, '<p>Choose <strong>TWO </strong>letters, A–E.</p>
<p>Which <strong>TWO </strong>recommendations does the tutor make about Laura’s questionnaire?</p>
', 'multiple_choice_many', 'null', '[{"option": "A. Leave a space for contact details.", "correct": false}, {"option": "B. Specify a completion date.", "correct": false}, {"option": "C. Provide a mixture of question types.", "correct": true}, {"option": "D. Keep the length to a minimum.", "correct": false}, {"option": "E. Trial it on someone before finalising it.", "correct": true}]', 'null', 'null', '[{"content": "<p>1</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('c0edcde0-33a7-497d-83b9-0fa2775da996', 'd7316798-0ad9-4b70-b2ec-78d7e4085832', 'fillup', 'Questions 31–40', '<div class="quests-inner-desc">
<div class="txt">
<p>Write <strong>ONE WORD ONLY</strong> for each answer.</p>
</div>
</div>
<div class="quests-des">
<div class="content-write">
<p class="ql-align-center" style="text-align: center;"><span style="font-size: 12pt;"><strong>The Music of Salvatore Sciarrino</strong></span></p>
<p><strong>Biographical details</strong></p>
<ul>
<li data-list="bullet">He was born in Palermo in 1947</li>
<li data-list="bullet">He moved to Rome in 1969 and took a course in electronic music, which influenced his style as a composer.</li>
</ul>
<p><strong>Work</strong></p>
<ul>
<li data-list="bullet">In the 1970s he composed a lot of music and taught until 1982.</li>
<li data-list="bullet">As well as music, he has written many {essays} .</li>
<li data-list="bullet">He has worn many awards – including one in 2011 for {originality} in music.</li>
</ul>
<p><strong>Musical characteristics</strong></p>
<ul>
<li data-list="bullet">Surprisingly, his music often features {silence} and very soft sounds.</li>
<li data-list="bullet">His music uses unusual instrument techniques, e.g. violins often produce sounds which resemble those found in {nature} .</li>
<li data-list="bullet">He is seen as a {pioneer} of music.</li>
<li data-list="bullet">Sciarrino compares his music to a distant {volcano} .</li>
</ul>
<p><strong>Concert piece</strong></p>
<ul>
<li data-list="bullet">for piano, chorus and orchestra</li>
<li data-list="bullet">finished in 1979 and written in memory of a {friend}</li>
<li data-list="bullet">very difficult to play</li>
<li data-list="bullet">starts with a noise that sounds like {thunder} , produced by two people moving large pieces of {metal}<span class="fill-history-correct"> </span>although the music is unusual, it has a traditional {structure}</li>
</ul>
</div>
</div>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<h2 data-path-to-node=\"2\">SECTION 4</h2>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Lecturer:</strong> Good morning. We’re really pleased that our university is going to hold a concert featuring the music of the Italian composer Salvatore Sciarrino. He’s considered one of the leading composers of modern classical music in Europe. His music is highly unusual, so in order to prepare you for this concert, I’m going to talk about his life and music.</p>\n<p data-path-to-node=\"4\">First, some biographical details. Salvatore Sciarrino was born in the Italian city of Palermo in 1947. Though he did receive some music lessons, he is mainly self-taught as a composer. After a few years of university in his home city, he moved to Rome in 1969 where he studied electronic music. This experience served as a turning point in the development of Sciarrino as a composer.</p>\n<p data-path-to-node=\"5\">Turning to his work, he composed a great deal in the 1970s and was a music teacher until 1982. Apart from composing music and teaching, he has also produced a large number of <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"5\" data-index-in-node=\"175\">(31) essays</strong></span> on a range of topics, such as the philosophy behind his work and musical form. Throughout his career, he has won numerous prestigious awards, most notably a major prize in 2011 which recognized his musical <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"5\" data-index-in-node=\"393\">(32) originality</strong></span>. So you could say that he is one of the most important composers of our times.</p>\n<p data-path-to-node=\"6\">Now I’ll talk about the characteristics of his music, which some people are a bit surprised by. The first thing that many listeners will notice about Sciarrino’s music is the frequent use of <span style=\"text-decoration: underline;\"><span style=\"background-color: #fbeeb8;\"><strong data-path-to-node=\"6\" data-index-in-node=\"191\">(33) silence</strong></span></span>. What is also striking about his music is his preference for extremely soft sounds that are sometimes at such a low volume that they can hardly be heard. The other unusual aspect of his music is that he frequently requires musicians to play their instruments in unconventional ways so that, for example, a violin may end up sounding very strange and creating sounds we generally associate with <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"6\" data-index-in-node=\"598\">(34) nature</strong>.</span> Actually, his novel instrumental techniques have often been imitated by other composers. As a result, he’s widely regarded as a <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"6\" data-index-in-node=\"739\">(35) pioneer</strong></span> in terms of creating new sounds. It may sound strange, but Sciarrino himself has likened his music to a <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"6\" data-index-in-node=\"856\">(36) volcano</strong></span> viewed from afar. As you’ll see, it builds up slowly to an exciting climax.</p>\n<p data-path-to-node=\"7\">Let’s move on to talk about the particular piece that we’ll hear at the concert. Many people consider it to be his finest work to date. It’s an immense piece of music for piano, chorus and orchestra that was completed in 1979. The work is dedicated to a <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"7\" data-index-in-node=\"254\">(37) friend</strong></span> who died unexpectedly, so it was written as a kind of memorial. In many ways, it is representative of his work as a whole in terms of the sound that it creates. It’s technically formidable and it’s a very challenging piece for musicians to play.</p>\n<p data-path-to-node=\"8\">The piece opens with a low sound of great complexity that is similar to <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"8\" data-index-in-node=\"72\">(38) thunder</strong></span>. This low-pitched noise is sustained almost uninterrupted for 45 minutes, which may sound quite boring, but I found it to be very haunting and atmospheric. The sound, by the way, is created by large vibrating sheets of <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"8\" data-index-in-node=\"304\">(39) metal</strong></span>, which are slowly manipulated by two percussionists. There are very quiet and strange chords produced by string instruments and very complex piano melodies that quietly appear and then disappear. Even though the piece will be, for many people, very unusual in terms of the sounds it creates, it actually has a very conventional <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"8\" data-index-in-node=\"643\">(40) structure</strong></span>, which is just another surprising aspect of Sciarrino’s work. Now, let’s move on to another work…</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('eef8c25a-56fe-4766-a153-ac2e5f1b2272', '54b5d50e-2b92-428b-97f1-575db48b7897', 'radio', 'Questions 23-26', '', '<p data-path-to-node="15,0,0"><span class="citation-14515">Choose</span><strong data-path-to-node="15,0,0" data-index-in-node="0"><span class="citation-14515"> YES</span></strong><span class="citation-14515 citation-end-14515"> if the statement agrees with the information,</span><strong data-path-to-node="15,1,0" data-index-in-node="0"><span class="citation-14514">NO</span></strong><span class="citation-14514 citation-end-14514"> if the statement contradicts the information,</span><strong data-path-to-node="15,2,0" data-index-in-node="0"><span class="citation-14513 citation-end-14513">NOT GIV</span>EN</strong> if there is no information on this</p>', 'yes_no_not_given', '[{"correct": 0, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "The study of twins shows that genetic determination is not the only factor for left-handedness."}, {"correct": 1, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Marc Dax''s report was widely accepted in his time."}, {"correct": 2, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "John Wada based his findings on his research of people with language problems."}, {"correct": 2, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "There tend to be more men with left-handedness than women."}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">23. The study of twins shows that genetic determination is not the only factor for left-handedness. — {YES}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p id=\"p-rc_0a97e7d5286ffc0d-20\" data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn A):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“<span class=\"citation-91\">One in five sets of identical twins involves one right-handed and one left-handed person, despite the fact that their genetic material is the same. </span><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"169\"><span class=\"citation-91 citation-end-91\">Genes therefore, are not solely responsible for handednes<sup class=\"superscript\" data-turn-source-index=\"1\"><!----></sup></span>s</strong>.”</em></p>\n<div class=\"source-inline-chip-container ng-star-inserted\"><!----><!----></div>\n<p><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Nghiên cứu về các cặp song sinh cùng trứng (có cùng bộ gen) nhưng vẫn có đứa thuận tay trái, đứa thuận tay phải đã chứng minh rằng gen không phải là yếu tố duy nhất (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"178\">not the only factor / not solely responsible</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">24. Marc Dax’s report was widely accepted in his time. — {NO}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn D):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“At the conference, Dax elaborated on his theory… <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"72\">Other experts showed little interest in the Frenchman’s ideas</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc khẳng định các chuyên gia khác “ít quan tâm” (<em data-path-to-node=\"7,1,0\" data-index-in-node=\"66\">showed little interest</em>) đến ý tưởng của Dax vào thời điểm đó. Điều này trái ngược hoàn toàn với việc được “chấp nhận rộng rãi” (<em data-path-to-node=\"7,1,0\" data-index-in-node=\"194\">widely accepted</em>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">25. John Wada based his findings on his research of people with language problems. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn E):</strong> <em data-path-to-node=\"4,0,0\" data-index-in-node=\"20\">\"In 1949 neurosurgeon <strong data-path-to-node=\"4,0,0\" data-index-in-node=\"42\">John Wada devised the first test</strong>... By injecting an anesthetic... Wada temporarily paralyzed one side of a <strong data-path-to-node=\"4,0,0\" data-index-in-node=\"149\">healthy brain</strong>, enabling him to more closely study the other side’s capabilities.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc mô tả phương pháp của John Wada là thực hiện các bài kiểm tra trên <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"87\">\"healthy brain\"</strong> (não bộ khỏe mạnh). Tuy nhiên, bài đọc <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"142\">không cung cấp thông tin</strong> xác nhận liệu ông có từng thực hiện nghiên cứu trên những người gặp vấn đề về ngôn ngữ (<strong data-path-to-node=\"4,1,0\" data-index-in-node=\"255\">people with language problems</strong>) hay không. Do thiếu dữ kiện để khẳng định hoặc phủ định mối liên hệ này, ta chọn <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"367\">NOT GIVEN</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">26. There tend to be more men with left-handedness than women. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn D có nhắc đến <em data-path-to-node=\"11,0,0\" data-index-in-node=\"30\">“more than 40 men and women”</em> trong nghiên cứu của Marc Dax, và đoạn F, G nói về các thiên tài thuận tay trái.</p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Mặc dù bài đọc có nhắc đến cả nam và nữ thuận tay trái, nhưng <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"74\">không hề có bất kỳ số liệu so sánh</strong> nào khẳng định nam giới thuận tay trái nhiều hơn nữ giới hay ngược lại.</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('bef892af-cde0-4190-935b-adbcaac4dd42', 'dbacd114-bc6d-4555-8bf4-9a61ae6536e4', 'fillup', ' Questions 31–40', '<div class="quests-inner-desc">
<div class="txt">
<p><em>Write </em><strong><em>ONE WORD AND/OR A NUMBER</em></strong><em> for each answer.</em></p>
</div>
</div>
<div class="quests-des">
<div class="content-write">
<p class="ql-align-center" style="text-align: center;"><strong>GASTROPODS (SNAILS AND SLUGS)</strong></p>
<p><strong>Evolution</strong></p>
<p>– minerals in the bodies of gastropods are like those in the {sea}</p>
<p>– fossils date back 500 million years</p>
<p><strong>Physical features</strong></p>
<p>– single, muscular foot</p>
<p>– radula (used for feeding)</p>
<p>– Shell (snails only)</p>
<p>– size: British shells range from 1.5-50 mm</p>
<p>– form: most shells coil to the {right}</p>
<p>– some shells have ribs, spines or {hair}</p>
<p>– they have various colours and patterns</p>
<p><strong>Feeding habits</strong></p>
<p>– mainly feed on rotting plants, fungi or algae</p>
<p>– some eat live animals, e.g. shield slugs eat {worms}</p>
<p><strong>Predators</strong></p>
<p>– birds, frogs, flies</p>
<p>– humans – snails were probably introduced to Britain as food in the {1ST Century}</p>
<p>– many gastropods have particular types of {defences|defenses} itself slippery …, e.g. glutinous snail makes</p>
<p><strong>Habitats</strong></p>
<p>– gastropods prefer dampness and shade</p>
<p>– {dry} conditions are worst</p>
<p>– biggest variety is found in old, natural habitats, e.g. {forests} and meadowland</p>
<p>– highly specialized species live in unusual habitats, e.g. blind snail lives entirely below the {ground}</p>
<p>– good indicators of the quality of the {environment}</p>
</div>
</div>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<h2 data-path-to-node=\"2\">PART 4</h2>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Lecturer:</strong> Good morning everyone. In this module, we’ve been looking at various field survey methods and now I’m going to give you a brief introduction to the specific organism that we’ll be focusing on during our first field trip, and that’s the gastropod.</p>\n<p data-path-to-node=\"4\">Gastropods are invertebrates—their organisms without a backbone—and they’re more commonly known as snails, or if they haven’t got a shell, slugs. Now in terms of their evolution, gastropods go back a long way. As with other primitive animals, the minerals in their body fluids are very similar to the mineral composition of the <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"4\" data-index-in-node=\"328\">(31) sea</strong></span>, indicating that they began life there; and their fossilized remains have been found in rocks dating back at least 500 million years.</p>\n<p data-path-to-node=\"5\">Looking at the physical features of the gastropods, well, they all have one muscular foot for swimming or walking. This foot is lubricated with mucus, and it’s this that leaves the sticky trail that you see behind snails and slugs. They also have an organ called a radula, which they use for feeding. Then of course the snails, though not the slugs, have a shell. In terms of their dimensions, snail shells in Britain range from the dwarf snail, which is 1.5 millimeters long, to the Roman snail, whose shell can be as big as 50 millimeters.</p>\n<p data-path-to-node=\"6\">As well as size variations, you get a lot of differences in the form of snail shells. For example, the majority coil to the <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"6\" data-index-in-node=\"124\">(32) right</strong></span>, but there are a few that coil to the left. Then some shells, for instance the plated snail, have regularly spaced ribs, while the prickly snail has prominent spines. There are even a number of species with <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"6\" data-index-in-node=\"342\">(33) hair</strong></span> on their shells. Colours on the shells also vary as do patterns, so appearances are really varied.</p>\n<p data-path-to-node=\"7\">Okay, let’s turn now to feeding habits. Most of you who are gardeners will know to your cost that some gastropods eat healthy plants, but you may not realize that these are the minority. Most species feed on rotting plants, or they eat fungi and algae. Some species eat dead animals, and there are some that are actually carnivorous—they prey on live animals. For example, the shield slug feeds on <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"7\" data-index-in-node=\"398\">(34) worms</strong></span>.</p>\n<p data-path-to-node=\"8\">And apart from their own feeding habits, I should point out that gastropods themselves have plenty of predators. Birds and frogs are the main ones, but there’s even an entire family of flies that have specialized in preying on gastropods. And of course last but not least, I should mention human predators. It was the Romans who probably first introduced edible snails into Britain during the <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"8\" data-index-in-node=\"393\">(35) 1st century</strong></span>, and they are still eaten today. In fact, the collection of wild snails for cooking has caused local extinctions of one species, which is also under threat internationally.</p>\n<p data-path-to-node=\"9\">So there are lots of predators, but to protect themselves, gastropods have often developed special <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"9\" data-index-in-node=\"99\">(36) defences</strong></span>. I’ll just give you one example: the glutinous snail avoids predators by folding its mantle over its shell and turning itself into a very slippery blob of jelly.</p>\n<p data-path-to-node=\"10\">Well turning now to gastropod habitats. Most species like dampness and shade. In general, both very hot and very cold weather is bad for gastropods, but <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"10\" data-index-in-node=\"153\">(37) dry</strong></span> conditions are the least favourable. Snails cope with this by withdrawing into their shells, and often they form a thick film of mucus over the mouth of their shell to minimize loss of water.</p>\n<p data-path-to-node=\"11\">Habitats with a long stable history tend to support the biggest range of gastropod species. So for instance, long-established <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"11\" data-index-in-node=\"126\">(38) forests</strong></span> usually support more species than newer plantations of trees, and old natural meadowland is much better than land which has recently been farmed. And there is a small number of highly specialized species that live in unusual habitats. For instance, the blind snail spends its whole life buried under the <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"11\" data-index-in-node=\"443\">(39) ground</strong></span>. It’s been reported living at depths of 2 meters and particularly likes the cavities in old buried bones apparently, but species like these are exceptional.</p>\n<p data-path-to-node=\"12\">But wherever they live, gastropods are often sensitive to pollution and they don’t thrive in areas contaminated by agrochemicals. This means that they are a reliable indication of how healthy our <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"12\" data-index-in-node=\"196\">(40) environment</strong></span> is. Now at this point I’d like to consider habitat management in relation…</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('cb1c04c7-66df-4a42-aba4-471f7e8ecebd', 'a898dd2b-74a5-424a-9c77-bd770c69fbec', 'fillup', 'Questions 31 - 40', '<p>Write <strong>ONE WORD ONLY</strong> for each answer.</p>
<p><span style="font-size: 14pt;"><strong>Ancient cave art symbols</strong></span></p>
<p><strong>The most common symbols include:</strong></p>
<p>simple shapes, e.g. dots and a {triangle}<br>more complex shapes, e.g. a wavy line to represent a {horse}</p>
<p><strong>How the hand symbol was made</strong></p>
<p>The paint was made by mixing charcoal with {fat}   and saliva.<br>The paint was applied using something similar to a {straw}<br>Applying paint made an unusual {noise} and also caused lightheadedness.</p>
<p><strong>The importance of the symbols:</strong></p>
<p>Researchers are developing a database to help identify any patterns.<br>The symbols are likely to be a {code} used by different groups.<br>A sequence of five of the symbols has been found on cave walls in Spain and on a {necklace}  made from a deer’s teeth.</p>
<p><strong>What researchers disagree about</strong></p>
<p>Some researchers say the symbols were part of the ‘Great Leap Forward’ which also included innovations such as the first {boat}<br>Others say the discovery in Africa of earlier artefacts such as types of {arrows}  disproves the theory.<br>It is likely that some art painted on {wood} did not survive.</p>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Lecturer:</strong> Hello everyone. My presentation today is about the cave paintings produced by prehistoric artists about 30,000 years ago, and in particular, the symbols that appear in or near these paintings. These symbols are found deep in caves in many countries around the world, but the ones I’m going to talk about today are mainly European.</p>\n<p data-path-to-node=\"4\">Firstly, a little about the most common symbols. The symbols that have been discovered are of different shapes and sizes. Some are easily recognizable as they’re quite simple. The most basic are just a series of dots, <strong data-path-to-node=\"4\" data-index-in-node=\"218\"><span style=\"background-color: #f1c40f;\">(Q31) but they may also include forms such as the triangle</span>.</strong> However, other symbols are more complex. A case in point is the wavy line. This is sometimes used on its own, but the same wavy line is also used as part of a larger picture of a horse, <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"4\" data-index-in-node=\"464\">(Q32) so we think this is what the wavy line represents (a horse).</strong></span></p>\n<p data-path-to-node=\"5\">One very important symbol is what’s called the hand symbol. This frequently appears on the walls of caves. I’ll talk about it in a bit more detail. Firstly, how it was made. The paint itself was made up from a variety of things that cave artists would have had access to. They had fire, so charcoal was one ingredient. <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"5\" data-index-in-node=\"319\">(Q33) Another was the fat from the animals they would have hunted</strong></span>, and lastly, the saliva from their own mouths.</p>\n<p data-path-to-node=\"6\">Then there’s the question of how they actually applied the runny paint onto the walls of the cave. It certainly wouldn’t have been easy. They would have had to use something hollow. <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"6\" data-index-in-node=\"182\">(Q34) In fact, it’s likely to have looked like a straw—you know, like the kind we use for drinking nowadays.</strong></span> They’d have sucked the paint up into it, then blown it out.</p>\n<p data-path-to-node=\"7\">Researchers have recently recreated both the paint and the processes used to make the hand symbols. The artist would have first put his hand flat against the wall, then blown the paint onto the wall, creating an outline of the hand. The researchers who’ve tried to recreate the process have said that not only is it a difficult technique to master, but<span style=\"background-color: #f1c40f;\"> <strong data-path-to-node=\"7\" data-index-in-node=\"353\">(Q35) also that a strange noise is produced.</strong></span> It also led them to feel lightheaded, so we can only imagine that these cave artists felt the same.</p>\n<p data-path-to-node=\"8\">I’m sure you’ll agree that these symbols are really interesting, but they’re also of vital importance. Researchers have now identified a total of 26 symbols commonly used in France and Spain. We only have this knowledge thanks to a database that’s been created and which is being added to all the time. It clearly demonstrates that many symbols are often used in particular combinations, even if they’re in different places.</p>\n<p data-path-to-node=\"9\"><span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">(Q36) Although researchers don’t believe that these symbols are a language as such, they are happy to call them a type of code.</strong> </span>There is evidence to support this idea. One sequence of five symbols is particularly common in caves in Spain. <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"9\" data-index-in-node=\"239\">(Q37) Exactly the same sequence of five symbols has been found carved into a necklace made from the teeth of a red deer.</strong></span> So it appears that this combination of symbols may have had a special meaning.</p>\n<p data-path-to-node=\"10\">Of course, many of these explanations are theory as opposed to hard facts, which is why there is disagreement among researchers about the significance of what we are seeing. One theory is called the “Great Leap Forward”. <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"10\" data-index-in-node=\"221\">(Q38) The idea is that around 35,000 years ago, there was a sudden increase in creativity which led to the invention of the boat</strong></span>, among other things.</p>\n<p data-path-to-node=\"11\">However, not everyone agrees. In fact, many scientists believe that what has been found in Africa seems to indicate that this increase in creativity happened much earlier. <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"11\" data-index-in-node=\"172\">(Q39) One example of an artifact that is offered to support the idea is the discovery of different sorts of arrows</strong></span>, which would have been used for hunting. These scientists suggest that the reason more symbols haven’t been found from this earlier time is <strong data-path-to-node=\"11\" data-index-in-node=\"427\"><span style=\"background-color: #f1c40f;\">(Q40) because they would have been painted on things that did not survive, such as wood</span>.</strong> In fact, we’re very lucky that caves have protected these specimens as well as they have, or we might never have known what these artists were capable of.</p>"}]', 0);
INSERT INTO public.questions VALUES ('d0f0fb60-0f1b-4acd-a838-45482ecb7c7f', '8c3f6ab2-4ae5-482a-b137-2f2b191e482b', 'matrix', 'Questions 18-21', NULL, '<p>Look at the following statements (Questions 18-21) and the list of researchers below.</p>
<p>Choose each statement with the correct researcher, А, В, C or D.</p>
', 'classification', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": "List of researchers", "matrixItems": [{"itemText": "The transplanting of certain genes into tomatoes can change their shape.", "correctCategoryLetter": "B"}, {"itemText": "The flavour of the heirloom tomato is largely dependent on actual yield and cultivation.", "correctCategoryLetter": "C"}, {"itemText": "A new type of tomato can be produced that is stronger than the original heirloom tomato yet equally sweet and flavoursome.", "correctCategoryLetter": "D"}, {"itemText": "The wide variety of heirloom tomatoes is due to only a small number of genes.", "correctCategoryLetter": "A"}], "matrixCategories": [{"categoryText": "Steven Tanlestey", "categoryLetter": "A"}, {"categoryText": "Esther van der Knaap", "categoryLetter": "B"}, {"categoryText": "Roger Chetelat", "categoryLetter": "C"}, {"categoryText": "Doug Heath", "categoryLetter": "D"}]}', '[{"content": "<p>18. The wide variety of heirloom tomatoes is due to only a small number of genes.</p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong>Nhà nghiên cứu:</strong> <strong>A (Steven Tanksley)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong>Dẫn chứng:</strong> (Đoạn A) Tanksley khẳng định: &#8220;There’re probably <strong>no more than 10 mutant genes that create the diversity of heirlooms</strong> you see.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"6,2,0\"><strong>Giải thích:</strong> Steven Tanksley là nhà di truyền học tại Đại học Cornell, người đã chỉ ra rằng sự đa dạng bề ngoài của cà chua heirloom thực chất chỉ do một số lượng rất nhỏ gen đột biến quyết định.</p>\n</li>\n</ul>\n<p>19. The transplanting of certain genes into tomatoes can change their shape.</p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong>Nhà nghiên cứu:</strong> <strong>B (Esther van der Knap)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong>Dẫn chứng:</strong> (Đoạn D) Esther van der Knap đã lấy một gen từ cà chua heirloom và chèn vào một loài hoang dã. Cô <strong>&#8220;observed that, as a result, the tiny fruits became shaped like pears.&#8221;</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"8,2,0\"><strong>Giải thích:</strong> Esther van der Knap đã tiến hành thí nghiệm cấy gen và quan sát thấy sự thay đổi hình dạng của quả cà chua.</p>\n</li>\n</ul>\n<p>20. The flavour of the heirloom tomato is largely dependent on actual yield and cultivation.</p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong>Nhà nghiên cứu:</strong> <strong>C (Roger Chetelat)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong>Dẫn chứng:</strong> (Đoạn E) Roger Chetelat giải thích rằng <strong>&#8220;heirlooms taste may have less to do with their genes than with the productivity of the plant and the growing environment&#8221;</strong>.</p>\n</li>\n<li>\n<p data-path-to-node=\"10,2,0\"><strong>Giải thích:</strong> Roger Chetelat lập luận rằng hương vị của cà chua heirloom phụ thuộc chủ yếu vào năng suất thực tế và môi trường trồng trọt, chứ không hẳn là do gen.</p>\n</li>\n</ul>\n<p>21. A new type of tomato can be produced that is stronger than the original heirloom tomato yet equally sweet and flavoursome.</p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong>Nhà nghiên cứu:</strong> <strong>D (Doug Heath)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong>Dẫn chứng:</strong> (Đoạn F) Doug Heath đã tạo ra giống cà chua lai tạo mới có 12 gen kháng bệnh (khỏe hơn/stronger) và <strong>&#8220;claims he is also able to maintain a comparable flavor and sugar profile&#8221;</strong> (duy trì hương vị và độ ngọt tương đương).</p>\n</li>\n<li>\n<p data-path-to-node=\"12,2,0\"><strong>Giải thích:</strong> Doug Heath là nhà lai tạo đã chứng minh có thể khắc phục các lỗi di truyền của heirloom để tạo ra một giống khỏe mạnh hơn mà vẫn giữ được hương vị mong muốn.</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('72d00ebc-1c45-4e9f-8326-5076d01bd04b', 'a9624dae-18e8-4616-95b5-e898d297063b', 'radio', 'Questions 27-31', NULL, '<p>Choose the correct answers</p>
', 'multiple_choice_single', '[{"correct": 3, "options": [{"content": "A. underestimated the role of family played in Stevenson’s life."}, {"content": "B. overestimated the writer’s works in the literature history."}, {"content": "C. exaggerated Stevenson’s religious belief in his works."}, {"content": "D. elevated Stevenson’s role as a writer."}], "question": "Stevenson’s biographers KF and CP"}, {"correct": 3, "options": [{"content": "A. the public give a more fair criticism to Stevenson’s works."}, {"content": "B. recent criticism has been justified."}, {"content": "C. the style of Stevenson’s works overweigh his faults in his life."}, {"content": "D. Stevenson’s works’ drawback is lack of ethical nature."}], "question": "The main point of the second paragraph is"}, {"correct": 1, "options": [{"content": "A. do not provide plot twists well."}, {"content": "B. cannot be used by writers to show moral values."}, {"content": "C. are more fashionable art form."}, {"content": "D. can be found in other’s works but not in Stevenson’s."}], "question": "According to the author, adventure stories"}, {"correct": 0, "options": [{"content": "A. They describe the life of people in Scotland."}, {"content": "B. They are commonly regarded as real literature."}, {"content": "C. They were popular during Stevenson’s life."}, {"content": "D. They transcend the local culture and stories."}], "question": "What does the author say about Stevenson’s works?"}, {"correct": 2, "options": [{"content": "A. made his family envy him so much."}, {"content": "B. should be responsible for his death."}, {"content": "C. gained more attention from the public than his works."}, {"content": "D. didn’t well prepare his life in Samoa."}], "question": "The lifestyle of Stevenson"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">27. Stevenson’s biographers KF and CP</strong></p>\n<ul data-path-to-node=\"3\">\n<li>\n<p data-path-to-node=\"3,0,0\"><strong data-path-to-node=\"3,0,0\" data-index-in-node=\"0\">Đáp án: D. elevated Stevenson’s role as a writer.</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"3,1,0\"><strong data-path-to-node=\"3,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 1, câu cuối: <em data-path-to-node=\"3,1,0\" data-index-in-node=\"29\">“Instead, they focused on his writing, and <strong data-path-to-node=\"3,1,0\" data-index-in-node=\"72\">gave high praise to his writing style and skill</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"3,2,0\"><strong data-path-to-node=\"3,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Thay vì chỉ trích đời tư, hai nhà tiểu sử KF và CP tập trung vào việc ca ngợi phong cách và kỹ năng viết lách của Stevenson. Hành động này giúp nâng cao vị thế và vai trò của ông với tư cách là một nhà văn trong mắt công chúng.</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">28. The main point of the second paragraph is</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Đáp án: D. Stevenson’s works’ drawback is lack of ethical nature.</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 2: <em data-path-to-node=\"6,1,0\" data-index-in-node=\"19\">“…he became an example of an author with <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"62\">corrupt ethics and lack of moral</strong>… many critics still assert that despite his skill, his literary works still <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"173\">lack moral value</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"6,2,0\"><strong data-path-to-node=\"6,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Nội dung chính của đoạn 2 xoay quanh những ý kiến tiêu cực cho rằng các tác phẩm của Stevenson thiếu đi giá trị đạo đức hoặc có nội dung suy đồi. Đây được coi là điểm yếu lớn nhất (<strong data-path-to-node=\"6,2,0\" data-index-in-node=\"193\">drawback</strong>) khiến tác phẩm của ông bị loại khỏi chương trình giảng dạy.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">29. According to the author, adventure stories</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Đáp án: B. cannot be used by writers to show moral values.</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 3: <em data-path-to-node=\"9,1,0\" data-index-in-node=\"19\">“Many of us believe adventure stories… ultimately <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"71\">can’t teach moral principles</strong>. The plot points are one-dimensional and <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"141\">rarely offer a deeper moral meaning</strong>…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,2,0\"><strong data-path-to-node=\"9,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả phân tích rằng thể loại truyện phiêu lưu mà Stevenson theo đuổi thường bị đánh giá là nông cạn, chỉ tập trung vào các tình tiết giật gân, ly kỳ mà không có khả năng truyền tải hay giáo dục các giá trị đạo đức sâu sắc cho người đọc.</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">30. What does the author say about Stevenson’s works?</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Đáp án: A. They describe the life of people in Scotland.</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 4: <em data-path-to-node=\"12,1,0\" data-index-in-node=\"19\">“Stevenson’s works… <strong data-path-to-node=\"12,1,0\" data-index-in-node=\"41\">captured the unique day to day life of average Scottish people</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"12,2,0\"><strong data-path-to-node=\"12,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Một đặc điểm nổi bật trong tác phẩm của Stevenson được tác giả nhắc đến là khả năng mô tả chân thực và sống động cuộc sống hàng ngày của tầng lớp bình dân tại Scotland vào thế kỷ 19, mang lại những hiểu biết giá trị về văn hóa địa phương.</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">31. The lifestyle of Stevenson</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Đáp án: C. gained more attention from the public than his works.</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 5: <em data-path-to-node=\"15,1,0\" data-index-in-node=\"19\">“Some even argue that his <strong data-path-to-node=\"15,1,0\" data-index-in-node=\"45\">personal life eventually outshone his writing</strong>… interest in Stevenson’s life had <strong data-path-to-node=\"15,1,0\" data-index-in-node=\"127\">taken the place of interest in his works</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"15,2,0\"><strong data-path-to-node=\"15,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Do cuộc đời của Stevenson có nhiều biến cố (sức khỏe yếu, chuyển đến sống tại đảo Samoa, sở thích du hành), công chúng thường có xu hướng quan tâm và bàn tán về lối sống của ông nhiều hơn là tập trung vào giá trị các tác phẩm văn học mà ông để lại.</p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('a004337e-d662-4c50-99de-36755566848f', '06af1a69-1a4b-4d54-a58f-91cc45328f06', 'matrix', 'Questions 27 – 32', '', '<p>Which paragraph contains the following information?</p>
<p>Write the correct letter, <strong data-path-to-node="11" data-index-in-node="139">A-F</strong>, in boxes 27-32 on your answer sheet.</p>
<p><strong>NB You may use any letter more than once.</strong></p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "simple", "matrixItems": [{"itemText": "disagreement with the view that employing talented people enables companies to achieve top performance", "correctCategoryLetter": "A"}, {"itemText": "a description of what individuals have to do on a regular basis to improve their performance", "correctCategoryLetter": "E"}, {"itemText": "the evidence that exceptional talent exists in all areas of life", "correctCategoryLetter": "B"}, {"itemText": "how different ways of evaluating achievement at work can cause different reactions in employees", "correctCategoryLetter": "F"}, {"itemText": "the belief that the time when an assessment is carried out affects its accuracy", "correctCategoryLetter": "C"}, {"itemText": "the extent to which different talented individuals have contributed to their particular area of achievement", "correctCategoryLetter": "B"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}]}', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">27. Disagreement with the view that employing talented people enables companies to achieve top performance — {A}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “This idea, that… those firms with the best people do the best – is both <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"86\">flawed and harmful</strong> to people and organisations.” (Đoạn A)</p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả trực tiếp bày tỏ sự không đồng tình (disagreement) với quan niệm rằng cứ có người giỏi nhất là công ty sẽ hoạt động tốt nhất.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">28. A description of what individuals have to do on a regular basis to improve their performance — {E}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…exceptional performance doesn’t happen without around <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"69\">ten years of nearly daily, deliberate practice for about four hours a day</strong>…” (Đoạn E)</p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn E mô tả chi tiết những gì cá nhân cần làm hàng ngày (luyện tập có chủ đích trong 10 năm) để cải thiện và đạt được hiệu suất xuất sắc.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">29. The evidence that exceptional talent exists in all areas of life — {B}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “There is no question that in <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"41\">every field, from sports to computer programming to music</strong>, there are people who are better than the rest.” (Đoạn B)</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">30. How different ways of evaluating achievement at work can cause different reactions in employees — {F}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “Dweck identified two sets of goals… <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"50\">performance goals</strong>… prone to helpless behaviour… and <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"106\">learning goals</strong>… strive for higher performance.” (Đoạn F)</p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn F phân tích cách đánh giá dựa trên “mục tiêu hiệu suất” hoặc “mục tiêu học hỏi” dẫn đến những phản ứng (reactions) khác nhau của nhân viên sau thất bại.</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">31. The belief that the time when an assessment is carried out affects its accuracy — {C}</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"11\">“If performance naturally varies, any <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"49\">measurement taken at a single point in time</strong>, such as when someone is being hired, will have <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"141\">error and imprecision</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả lập luận rằng vì phong độ con người luôn thay đổi, nên việc đánh giá tại một thời điểm duy nhất (ví dụ lúc tuyển dụng) sẽ dẫn đến sự thiếu chính xác và sai lệch.</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">32. The extent to which different talented individuals have contributed to their particular area of achievement — {B}</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…in music, <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"25\">16 individuals have produced about 50 per cent</strong> of the Western classical music… while another <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"120\">235 composers have produced the remaining half</strong>.” (Đoạn B)</p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đây là số liệu cụ thể về mức độ đóng góp (extent of contribution) của các cá nhân ngôi sao so với phần còn lại.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('588190e3-d99a-4a20-9477-80cd40e66d8b', '18276fc2-3e8f-4401-bba5-2e4cdd2d7122', 'radio', 'Questions 31–36', '', '<p>Choose <strong data-start="157" data-end="164">YES</strong> – if the statement agrees with the claims of the writer, <strong data-start="223" data-end="229">NO</strong> – if the statement contradicts the claims of the writer, <strong data-start="288" data-end="301">NOT GIVEN</strong> – if it is impossible to say what the writer thinks about this</p>', 'yes_no_not_given', '[{"correct": 1, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Sydney Bradford relied on recollections of objects he had been told about to help him see after his operation"}, {"correct": 2, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "People who only start to see as adults can learn to see as other people do in time"}, {"correct": 0, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "People who have gained their sight as adults find certain activities harder to do than before"}, {"correct": 1, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "It is evident now that sight involves the eyes and one particular area of the brain"}, {"correct": 2, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "The mask experiment is particularly useful in training people who are regaining their sight"}, {"correct": 0, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "People with perfect vision can fail to interpret objects correctly under certain circumstances"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">31. NO — Sydney Bradford relied on recollections of objects he had been told about to help him see after his operation.</strong></p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"16,0,0\" data-index-in-node=\"26\">“It was his touch memories that enabled him to perceive them with his eyes.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"16,1,0\"><strong data-path-to-node=\"16,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi nói Bradford dựa vào ký ức về những thứ <em data-path-to-node=\"16,1,0\" data-index-in-node=\"60\">được người khác kể cho nghe</em> (<em data-path-to-node=\"16,1,0\" data-index-in-node=\"89\">had been told about</em>). Ngược lại, bài đọc khẳng định ông hoàn toàn dựa vào ký ức xúc giác — tức là những thứ ông đã tự tay chạm vào trước đó (<strong data-path-to-node=\"16,1,0\" data-index-in-node=\"230\">touch memories</strong>). Thông tin sai lệch bản chất nên đáp án là <strong data-path-to-node=\"16,1,0\" data-index-in-node=\"289\">NO</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">32. NOT GIVEN — People who only start to see as adults can learn to see as other people do in time.</strong></p>\n<ul data-path-to-node=\"18\">\n<li>\n<p data-path-to-node=\"18,0,0\"><strong data-path-to-node=\"18,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"18,0,0\" data-index-in-node=\"26\">“Since his operation, his sight has gradually improved as he learns to see, for example, by understanding how shadows represent depth and tell us about the shape of things.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"18,1,0\"><strong data-path-to-node=\"18,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ đề cập rằng thị lực của Mike May (người mù bẩm sinh được phẫu thuật khi lớn) đang tiến triển dần dần khi ông học cách hiểu về bóng tối và chiều sâu. Tuy nhiên, văn bản <strong data-path-to-node=\"18,1,0\" data-index-in-node=\"192\">hoàn toàn không khẳng định hay đảm bảo</strong> liệu những người như ông có thể nhìn được hoàn toàn bình thường giống như bao người khác theo thời gian (<em data-path-to-node=\"18,1,0\" data-index-in-node=\"336\">learn to see as other people do in time</em>) hay không. Do đó đáp án là <strong data-path-to-node=\"18,1,0\" data-index-in-node=\"404\">NOT GIVEN</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">33. YES — People who have gained their sight as adults find certain activities harder to do than before.</strong></p>\n<ul data-path-to-node=\"20\">\n<li>\n<p data-path-to-node=\"20,0,0\"><strong data-path-to-node=\"20,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"20,0,0\" data-index-in-node=\"26\">“He had been a champion blind skier, but following the operation, he would have to shut his eyes while skiing to block out what he now found was a terrifying sight.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"20,1,0\"><strong data-path-to-node=\"20,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Khi còn mù, Mike May là một nhà vô địch trượt tuyết. Nhưng sau khi phẫu thuật mở mắt, ông thấy việc trượt tuyết trở nên đáng sợ đến mức phải nhắm mắt lại khi thực hiện. Điều này chứng tỏ việc sáng mắt lại khiến một số hoạt động của ông trở nên khó khăn hơn trước (<strong data-path-to-node=\"20,1,0\" data-index-in-node=\"276\">harder to do than before</strong>). Đáp án là <strong data-path-to-node=\"20,1,0\" data-index-in-node=\"313\">YES</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">34. NO — It is evident now that sight involves the eyes and one particular area of the brain.</strong></p>\n<ul data-path-to-node=\"22\">\n<li>\n<p data-path-to-node=\"22,0,0\"><strong data-path-to-node=\"22,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"22,0,0\" data-index-in-node=\"26\">“Seeing used to be thought of as taking place only in the eyes, and in quite specialised brain regions; but now it seems that half the brain is occupied with seeing...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"22,1,0\"><strong data-path-to-node=\"22,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi khẳng định thị giác chỉ liên quan đến mắt và <em data-path-to-node=\"22,1,0\" data-index-in-node=\"65\">một vùng bộ não cụ thể</em> (<em data-path-to-node=\"22,1,0\" data-index-in-node=\"89\">one particular area</em>). Ngược lại, bài đọc viết rằng đó là quan niệm cũ, còn hiện nay khoa học chứng minh có đến <strong data-path-to-node=\"22,1,0\" data-index-in-node=\"200\">nửa bộ não</strong> tham gia vào quá trình nhìn (<em data-path-to-node=\"22,1,0\" data-index-in-node=\"240\">half the brain</em>). Thông tin mâu thuẫn hoàn toàn nên đáp án là <strong data-path-to-node=\"22,1,0\" data-index-in-node=\"301\">NO</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">35. NOT GIVEN — The mask experiment is particularly useful in training people who are regaining their sight.</strong></p>\n<ul data-path-to-node=\"24\">\n<li>\n<p data-path-to-node=\"24,0,0\"><strong data-path-to-node=\"24,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"24,0,0\" data-index-in-node=\"26\">“...people not seeing a hollow face as hollow is the most revealing experiment on perception.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"24,1,0\"><strong data-path-to-node=\"24,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc có nhắc đến thí nghiệm mặt nạ (<em data-path-to-node=\"24,1,0\" data-index-in-node=\"51\">mask experiment</em>) nhằm chứng minh người bình thường nhìn thế giới dựa trên kỳ vọng và định kiến có sẵn, chứ <strong data-path-to-node=\"24,1,0\" data-index-in-node=\"158\">không hề có bất kỳ thông tin nào</strong> nói về việc thí nghiệm này được ứng dụng để huấn luyện người đang phục hồi thị lực. Đáp án là <strong data-path-to-node=\"24,1,0\" data-index-in-node=\"285\">NOT GIVEN</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">36. YES — People with perfect vision can fail to interpret objects correctly under certain circumstances.</strong></p>\n<ul data-path-to-node=\"26\">\n<li>\n<p data-path-to-node=\"26,0,0\"><strong data-path-to-node=\"26,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"26,0,0\" data-index-in-node=\"26\">“The unsettling truth from brain science is that even people with no visual impairment see what, at some level, they expect to see, and often miss things as they really are.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"26,1,0\"><strong data-path-to-node=\"26,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"People with perfect vision\" tương ứng với cụm \"people with no visual impairment\" (người không bị tật về mắt). Việc họ nhìn theo kỳ vọng và bỏ lỡ bản chất thật của sự vật (<em data-path-to-node=\"26,1,0\" data-index-in-node=\"184\">miss things as they really are</em>) đồng nghĩa với việc họ diễn giải sai lệch vật thể trong một số hoàn cảnh (<strong data-path-to-node=\"26,1,0\" data-index-in-node=\"290\">fail to interpret objects correctly</strong>). Đáp án là <strong data-path-to-node=\"26,1,0\" data-index-in-node=\"338\">YES</strong>.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('ae10db7f-9c77-47c8-ac12-5e16472c049a', '9a8c1800-c392-4cf3-92d3-758ab1d1e443', 'fillup', 'Questions 1–6', '<p><span style="font-size: 12pt; font-family: arial, helvetica, sans-serif; color: #15191e;">Complete the notes below.</span></p>
<p><span style="font-family: arial, helvetica, sans-serif;"><span style="font-size: 12pt; color: #15191e;">Write </span><strong><span style="font-size: 12pt; color: #15191e; border: 1pt none windowtext; padding: 0cm;">ONE WORD ONLY</span></strong><span style="font-size: 12pt; color: #15191e;"> from the passage for each answer.</span></span></p>
<p><span style="font-family: arial, helvetica, sans-serif;"><strong><span style="font-size: 12pt; color: #15191e; border: 1pt none windowtext; padding: 0cm;">Dolls</span></strong><span style="font-size: 12pt; color: #15191e;"> </span></span></p>
<p><span style="font-family: arial, helvetica, sans-serif;"><strong><span style="font-size: 12pt; color: #15191e; border: 1pt none windowtext; padding: 0cm;">Earliest known dolls</span></strong></span></p>
<p><span style="font-family: arial, helvetica, sans-serif;"><!-- [if !supportLists]--><span style="font-size: 10pt; color: #15191e;"><span style="mso-list: Ignore;">o<span style="font-style: normal; font-variant: normal; font-size-adjust: none; font-kerning: auto; font-optical-sizing: auto; font-feature-settings: normal; font-variation-settings: normal; font-weight: normal; font-stretch: normal; font-size: 7pt; line-height: normal;">    </span></span></span><!--[endif]--><span style="font-size: 12pt; color: #15191e;">represented religious figures</span></span></p>
<p><span style="font-family: arial, helvetica, sans-serif;"><!-- [if !supportLists]--><span style="font-size: 10pt; color: #15191e;"><span style="mso-list: Ignore;">o<span style="font-style: normal; font-variant: normal; font-size-adjust: none; font-kerning: auto; font-optical-sizing: auto; font-feature-settings: normal; font-variation-settings: normal; font-weight: normal; font-stretch: normal; font-size: 7pt; line-height: normal;">    </span></span></span><!--[endif]--><span style="font-size: 12pt; color: #15191e;">used as toys</span></span></p>
<p><span style="font-family: arial, helvetica, sans-serif;"><strong><span style="font-size: 12pt; color: #15191e; border: 1pt none windowtext; padding: 0cm;">Egypt, 2000 BC</span></strong></span></p>
<p><span style="font-family: arial, helvetica, sans-serif;"><!-- [if !supportLists]--><span style="font-size: 10pt; color: #15191e;"><span style="mso-list: Ignore;">o<span style="font-style: normal; font-variant: normal; font-size-adjust: none; font-kerning: auto; font-optical-sizing: auto; font-feature-settings: normal; font-variation-settings: normal; font-weight: normal; font-stretch: normal; font-size: 7pt; line-height: normal;">    </span></span></span><!--[endif]--><span style="font-size: 12pt; color: #15191e;">bodies were made of wood</span></span></p>
<p><span style="font-family: arial, helvetica, sans-serif;"><!-- [if !supportLists]--><span style="font-size: 10pt; color: #15191e;"><span style="mso-list: Ignore;">o<span style="font-style: normal; font-variant: normal; font-size-adjust: none; font-kerning: auto; font-optical-sizing: auto; font-feature-settings: normal; font-variation-settings: normal; font-weight: normal; font-stretch: normal; font-size: 7pt; line-height: normal;">    <span style="font-size: 10pt;">{clay}</span></span></span></span><span style="font-size: 12pt; color: #15191e;"> was used for the hair</span></span></p>
<p><span style="font-family: arial, helvetica, sans-serif;"><strong><span style="font-size: 12pt; color: #15191e; border: 1pt none windowtext; padding: 0cm;">Ancient Greece and Rome</span></strong></span></p>
<p><span style="font-family: arial, helvetica, sans-serif;"><!-- [if !supportLists]--><span style="font-size: 10pt; color: #15191e;"><span style="mso-list: Ignore;">o<span style="font-style: normal; font-variant: normal; font-size-adjust: none; font-kerning: auto; font-optical-sizing: auto; font-feature-settings: normal; font-variation-settings: normal; font-weight: normal; font-stretch: normal; font-size: 7pt; line-height: normal;">    </span></span></span><!--[endif]--><span style="font-size: 12pt; color: #15191e;">dolls were given to {goddesses}</span><span style="font-size: 12pt; color: #15191e;"> by older girls</span></span></p>
<p><span style="font-family: arial, helvetica, sans-serif;"><strong><span style="font-size: 12pt; color: #15191e; border: 1pt none windowtext; padding: 0cm;">600 BC</span></strong></span></p>
<p><span style="font-family: arial, helvetica, sans-serif;"><!-- [if !supportLists]--><span style="font-size: 10pt; color: #15191e;"><span style="mso-list: Ignore;">o<span style="font-style: normal; font-variant: normal; font-size-adjust: none; font-kerning: auto; font-optical-sizing: auto; font-feature-settings: normal; font-variation-settings: normal; font-weight: normal; font-stretch: normal; font-size: 7pt; line-height: normal;">    </span></span></span><!--[endif]--><span style="font-size: 12pt; color: #15191e;">realistic dolls had separate clothes and {limbs}</span><span style="font-size: 12pt; color: #15191e;"> that could be put in different positions</span></span></p>
<p><span style="font-family: arial, helvetica, sans-serif;"><strong><span style="font-size: 12pt; color: #15191e; border: 1pt none windowtext; padding: 0cm;">17th and 18th centuries</span></strong></span></p>
<p><span style="font-family: arial, helvetica, sans-serif;"><!-- [if !supportLists]--><span style="font-size: 10pt; color: #15191e;"><span style="mso-list: Ignore;">o<span style="font-style: normal; font-variant: normal; font-size-adjust: none; font-kerning: auto; font-optical-sizing: auto; font-feature-settings: normal; font-variation-settings: normal; font-weight: normal; font-stretch: normal; font-size: 7pt; line-height: normal;">    </span></span></span><!--[endif]--><span style="font-size: 12pt; color: #15191e;">dolls made of {wax}</span><span style="font-size: 12pt; color: #15191e;"> became more common</span></span></p>
<p><span style="font-family: arial, helvetica, sans-serif;"><!-- [if !supportLists]--><span style="font-size: 10pt; color: #15191e;"><span style="mso-list: Ignore;">o<span style="font-style: normal; font-variant: normal; font-size-adjust: none; font-kerning: auto; font-optical-sizing: auto; font-feature-settings: normal; font-variation-settings: normal; font-weight: normal; font-stretch: normal; font-size: 7pt; line-height: normal;">    </span></span></span><!--[endif]--><span style="font-size: 12pt; color: #15191e;">moulds made of {plaster}</span></span></p>
<p><span style="font-family: arial, helvetica, sans-serif;"><strong><span style="font-size: 12pt; color: #15191e; border: 1pt none windowtext; padding: 0cm;">1800s</span></strong></span></p>
<p><span style="font-family: arial, helvetica, sans-serif;"><!-- [if !supportLists]--><span style="font-size: 10pt; color: #15191e;"><span style="mso-list: Ignore;">o<span style="font-style: normal; font-variant: normal; font-size-adjust: none; font-kerning: auto; font-optical-sizing: auto; font-feature-settings: normal; font-variation-settings: normal; font-weight: normal; font-stretch: normal; font-size: 7pt; line-height: normal;">    </span></span></span><!--[endif]--><span style="font-size: 12pt; color: #15191e;">new manufacturing process developed</span></span></p>
<p><span style="font-family: arial, helvetica, sans-serif;"><!-- [if !supportLists]--><span style="font-size: 10pt; color: #15191e;"><span style="mso-list: Ignore;">o<span style="font-style: normal; font-variant: normal; font-size-adjust: none; font-kerning: auto; font-optical-sizing: auto; font-feature-settings: normal; font-variation-settings: normal; font-weight: normal; font-stretch: normal; font-size: 7pt; line-height: normal;">    </span></span></span><!--[endif]--><span style="font-size: 12pt; color: #15191e;">new group of mixtures known as {composition}</span></span></p>
<p><span style="font-family: arial, helvetica, sans-serif;"><!-- [if !supportLists]--><span style="font-size: 10pt; color: #15191e;"><span style="mso-list: Ignore;">o<span style="font-style: normal; font-variant: normal; font-size-adjust: none; font-kerning: auto; font-optical-sizing: auto; font-feature-settings: normal; font-variation-settings: normal; font-weight: normal; font-stretch: normal; font-size: 7pt; line-height: normal;">    </span></span></span><!--[endif]--><span style="font-size: 12pt; color: #15191e;">recipes for these mixtures kept secret</span></span></p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<h3>1. Egypt, 2000 BC… <strong>clay</strong> was used for the hair</h3>\n<ul data-path-to-node=\"3\">\n<li><strong>Đáp án:</strong> <strong>clay</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn B) “Dolls constructed of flat pieces of wood, painted with various designs, and with ‘hair’ made of <strong>clay</strong>, have often been found in Egyptian graves dating back to 2000 BC.”</li>\n</ul>\n<h3>2. Ancient Greece and Rome… dolls were given to <strong>goddesses</strong> by older girls</h3>\n<ul data-path-to-node=\"5\">\n<li><strong>Đáp án:</strong> <strong>goddesses</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn C) “Girls from ancient Greece and Rome offered their wooden dolls to <strong>goddesses</strong> after they were too ‘grown-up’ to play with dolls.”</li>\n</ul>\n<h3>3. 600 BC… realistic dolls had separate clothes and <strong>limbs</strong> that could be put in different positions</h3>\n<ul data-path-to-node=\"7\">\n<li><strong>Đáp án:</strong> <strong>limbs</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn C) “That ideal led to the creation of dolls with <strong>movable limbs</strong> and removable garments, dating back to 600 BC.”</li>\n</ul>\n<h3>4. 17th and 18th centuries… dolls made of <strong>wax</strong> became more common</h3>\n<ul data-path-to-node=\"9\">\n<li><strong>Đáp án:</strong> <strong>wax</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn F) “In addition to wooden dolls, <strong>wax</strong> dolls grew in popularity in the 17th and 18th centuries.”</li>\n</ul>\n<h3>5. 17th and 18th centuries… moulds made of <strong>plaster</strong></h3>\n<ul data-path-to-node=\"11\">\n<li><strong>Đáp án:</strong> <strong>plaster</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn F) “Wax dollmakers would model a doll’s head in wax or clay, and then cover it with <strong>plaster</strong> to create a mould.”</li>\n</ul>\n<h3>6. 1800s… new group of mixtures known as <strong>composition</strong></h3>\n<ul data-path-to-node=\"13\">\n<li><strong>Đáp án:</strong> <strong>composition</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn E) “<strong>‘Composition’</strong> is a collective term for mixtures of pulped wood or paper that were used to make doll heads and bodies.”</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('062236f2-64fa-42f6-8fac-9b873b812841', '9a8c1800-c392-4cf3-92d3-758ab1d1e443', 'radio', 'Questions 7–13', NULL, '<p><span style="font-family: arial, helvetica, sans-serif;"><span style="font-size: 12pt; color: black; border: 1pt none windowtext; padding: 0cm; background: white;">Choose </span><strong><span style="font-size: 12pt; color: black; border: 1pt none windowtext; padding: 0cm; background: white;">TRUE</span></strong><span style="font-size: 12pt; color: black; border: 1pt none windowtext; padding: 0cm; background: white;"> if the statement agrees with the information given in the text, choose </span><strong><span style="font-size: 12pt; color: black; border: 1pt none windowtext; padding: 0cm; background: white;">FALSE</span></strong><span style="font-size: 12pt; color: black; border: 1pt none windowtext; padding: 0cm; background: white;"> if the statement contradicts the information, or choose </span><strong><span style="font-size: 12pt; color: black; border: 1pt none windowtext; padding: 0cm; background: white;">NOT GIVEN</span></strong><span style="font-size: 12pt; color: black; border: 1pt none windowtext; padding: 0cm; background: white;"> if there is no information on this.</span></span></p>
', 'multiple-choice', '[{"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE "}, {"content": "NOT GIVEN"}], "question": "Bisque dolls appear less realistic than dolls made of china."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE "}, {"content": "NOT GIVEN"}], "question": "French dolls tended to cost more than German bisque dolls."}, {"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE "}, {"content": "NOT GIVEN"}], "question": "The first rag dolls were made in the 1850s."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE "}, {"content": "NOT GIVEN"}], "question": "Only dolls made of cotton or linen are classified as cloth dolls. "}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE "}, {"content": "NOT GIVEN"}], "question": "Dolls made of celluloid tended to lose their colour."}, {"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE "}, {"content": "NOT GIVEN"}], "question": "Composition dolls lasted longer than the plastic dolls that were made in the 1940s."}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE "}, {"content": "NOT GIVEN"}], "question": "Doll collectors prefer a doll to be dressed in its original clothing."}]', 'null', 'null', 'null', '[{"content": "<p>7. Bisque dolls appear less realistic than dolls made of china.</p>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong>Đáp án: FALSE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong>Dẫn chứng:</strong> (Đoạn G) “Bisque, which is porcelain fired twice with colour added to it after the first firing, <strong>looked more like skin than china did</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"17,2,0\"><strong>Giải thích:</strong> Bisque trông giống da người hơn (more like skin) so với china, tức là <strong>thực tế hơn</strong>, mâu thuẫn với nhận định “less realistic” (kém thực tế hơn).</p>\n</li>\n</ul>\n<p>8. French dolls tended to cost more than German bisque dolls.</p>\n<ul data-path-to-node=\"19\">\n<li>\n<p data-path-to-node=\"19,0,0\"><strong>Đáp án: TRUE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"19,1,0\"><strong>Dẫn chứng:</strong> (Đoạn H) “Although the French dolls were <strong>unrivalled in their artistry</strong>, German bisque dolls became quite popular because <strong>they were not as expensive</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"19,2,0\"><strong>Giải thích:</strong> Nếu búp bê Đức (bisque dolls) phổ biến vì chúng rẻ hơn (not as expensive), điều đó có nghĩa là búp bê Pháp (French dolls) <strong>đắt hơn</strong> (cost more).</p>\n</li>\n</ul>\n<p>9. The first rag dolls were made in the 1850s.</p>\n<ul data-path-to-node=\"21\">\n<li>\n<p data-path-to-node=\"21,0,0\"><strong>Đáp án: FALSE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"21,1,0\"><strong>Dẫn chứng:</strong> (Đoạn I) “<strong>For many centuries, rag dolls were made by mothers for their children</strong>… <strong>Commercially produced rag dolls were first introduced in the 1850s</strong> by English and American manufacturers.”</p>\n</li>\n<li>\n<p data-path-to-node=\"21,2,0\"><strong>Giải thích:</strong> Búp bê vải (rag dolls) đã tồn tại hàng thế kỷ (made by mothers); chỉ có búp bê vải được <strong>sản xuất thương mại</strong> (Commercially produced) mới bắt đầu vào những năm 1850.</p>\n</li>\n</ul>\n<p>10. Only dolls made of cotton or linen are classified as cloth dolls.</p>\n<ul data-path-to-node=\"23\">\n<li>\n<p data-path-to-node=\"23,0,0\"><strong>Đáp án: TRUE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"23,1,0\"><strong>Dẫn chứng:</strong> (Đoạn I) “The term ‘rag doll’ refers generically to dolls made of any fabric. <strong>‘Cloth doll’ refers to a subset of rag dolls made of linen or cotton</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"23,2,0\"><strong>Giải thích:</strong> Định nghĩa rõ ràng rằng “cloth doll” là tập hợp con của rag dolls, được làm bằng linen <strong>hoặc</strong> cotton.</p>\n</li>\n</ul>\n<p>11. Dolls made of celluloid tended to lose their colour.</p>\n<ul data-path-to-node=\"25\">\n<li>\n<p data-path-to-node=\"25,0,0\"><strong>Đáp án: TRUE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"25,1,0\"><strong>Dẫn chứng:</strong> (Đoạn J) “However, celluloid fell out of favour because of its extreme flammability and <strong>propensity to fade in bright light</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"25,2,0\"><strong>Giải thích:</strong> “Propensity to fade” (khuynh hướng phai màu) đồng nghĩa với việc mất màu (lose their colour).</p>\n</li>\n</ul>\n<p>12. Composition dolls lasted longer than the plastic dolls that were made in the 1940s.</p>\n<ul data-path-to-node=\"27\">\n<li>\n<p data-path-to-node=\"27,0,0\"><strong>Đáp án: FALSE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"27,1,0\"><strong>Dẫn chứng:</strong> (Đoạn K) “Hard plastic dolls were manufactured in the 1940s… They resembled composition dolls, but they were <strong>much more durable</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"27,2,0\"><strong>Giải thích:</strong> Búp bê nhựa cứng (plastic dolls) bền hơn (more durable) búp bê composition, mâu thuẫn với nhận định composition dolls bền hơn.</p>\n</li>\n</ul>\n<p>13. Doll collectors prefer a doll to be dressed in its original clothing.</p>\n<ul data-path-to-node=\"29\">\n<li>\n<p data-path-to-node=\"29,0,0\"><strong>Đáp án: NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"29,1,0\"><strong>Giải thích:</strong> Văn bản mô tả lịch sử các loại búp bê, vật liệu, và sự phổ biến của chúng, nhưng <strong>không có thông tin</strong> về sở thích của nhà sưu tầm đối với quần áo gốc của búp bê.</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('73f633de-5e7f-4e8f-ab33-52929fab7f3b', '627cc1ed-b0d3-4630-aee6-1fef5d44f653', 'fillup', 'Questions 6-13', '<p><strong>Complete the sentences below.</strong></p>
<p>Choose <strong>ONE WORD ONLY</strong> from the passage for each answer. Write your answers in boxes 6-13 on your answer sheet.</p>
<p>In France, people started to overcome their disgust about potatoes because the King put a potato {flower} in his buttonhole.</p>
<p>Frederick realised the potential of potatoes but he had to handle the {prejudice}against potatoes from ordinary people.</p>
<p>The King of Prussia adopted some {reverse} psychology to make people accept potatoes.</p>
<p>Before 1800, the English people preferred eating {meat} with bread, butter and cheese.</p>
<p>The obvious way to deal with England food problems was to grow high yielding potato {crops}</p>
<p>The Irish {soil} and climate suited potatoes well.</p>
<p>Between 1780 and 1841, based on the {cultivation} of the potatoes, the Irish population doubled to eight million.</p>
<p>The potato’s high yields helped the poorest farmers to produce much healthier food almost without {investment} or hard physical work.</p>
', NULL, 'gap_filling', NULL, NULL, '{"layoutType": ["standard"], "summaryText": null, "answerOptions": null, "matchingItems": null}', '{"layoutType": ["standard"], "legendTitle": null, "matrixItems": null, "matrixCategories": null}', '[{"content": "<p>6. In France, people started to overcome their disgust about potatoes because the King put a potato <strong>flower</strong> in his buttonhole.</p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong class=\"\">Đáp án:</strong> <strong class=\"\">flower</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong class=\"\">Dẫn chứng:</strong><span class=\"\"> (Đoạn 6) “…</span><span class=\"\">Louis XVI began to sport a potato </span><strong class=\"\">flower</strong><span class=\"\"> in his buttonhole…</span><span class=\"\">“</span></p>\n</li>\n<li>\n<p data-path-to-node=\"15,2,0\"><strong class=\"\">Giải thích:</strong><span class=\"\"> Vua Louis XVI cài hoa khoai tây (potato flower) lên áo để khuyến khích dân chúng chấp nhận.</span></p>\n</li>\n</ul>\n<p>7. Frederick realised the potential of potatoes but he had to handle the <strong>prejudice</strong> against potatoes from ordinary people.</p>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong class=\"\">Đáp án:</strong> <strong class=\"\">prejudice</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong class=\"\">Dẫn chứng:</strong><span class=\"\"> (Đoạn 7) “…</span><span class=\"\">Frederick the Great of Prussia saw the potato’s potential…</span><span class=\"\"> but faced the challenge of overcoming the </span><strong class=\"\">people’s prejudice</strong> against the plant.”</p>\n</li>\n<li>\n<p data-path-to-node=\"17,2,0\"><strong>Giải thích:</strong> Vua Phổ phải đối mặt với định kiến/thành kiến (prejudice) của dân chúng.</p>\n</li>\n</ul>\n<p>8. The King of Prussia adopted some <strong>reverse</strong> psychology to make people accept potatoes.</p>\n<ul data-path-to-node=\"19\">\n<li>\n<p data-path-to-node=\"19,0,0\"><strong>Đáp án:</strong> <strong>reverse</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"19,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 7) “Trying a less direct approach to encourage his subjects to begin planting potatoes, Frederick used a bit of <strong>reverse psychology</strong>…”</p>\n</li>\n<li>\n<p data-path-to-node=\"19,2,0\"><strong>Giải thích:</strong> Frederick đã dùng tâm lý ngược (reverse psychology) để dụ dân chúng ăn cắp khoai tây về trồng.</p>\n</li>\n</ul>\n<p>9. Before 1800, the English people preferred eating <strong>meat</strong> with bread, butter and cheese.</p>\n<ul data-path-to-node=\"21\">\n<li>\n<p data-path-to-node=\"21,0,0\"><strong>Đáp án:</strong> <strong>meat</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"21,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 8) “Prior to 1800, the English diet had consisted primarily of <strong>meat</strong>, supplemented by bread, butter and cheese.”</p>\n</li>\n<li>\n<p data-path-to-node=\"21,2,0\"><strong>Giải thích:</strong> Chế độ ăn chủ yếu của người Anh trước 1800 là thịt (meat).</p>\n</li>\n</ul>\n<p>10. The obvious way to deal with England food problems was to grow high yielding potato <strong>crops</strong>.</p>\n<ul data-path-to-node=\"23\">\n<li>\n<p data-path-to-node=\"23,0,0\"><strong>Đáp án:</strong> <strong>crops</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"23,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 8) “High-yielding, easily prepared potato <strong>crops</strong><span class=\"animating\"> were the obvious solution to England’s food problems.</span>“</p>\n</li>\n<li>\n<p data-path-to-node=\"23,2,0\"><strong>Giải thích:</strong> Các vụ mùa khoai tây cho năng suất cao là giải pháp rõ ràng cho vấn đề lương thực.</p>\n</li>\n</ul>\n<p>11. The Irish <strong>soil</strong> and climate suited potatoes well.</p>\n<ul data-path-to-node=\"25\">\n<li>\n<p data-path-to-node=\"25,0,0\"><strong>Đáp án:</strong> <strong>soil</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"25,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 9) “The potato was well suited to the Irish <strong>soil</strong> and climate…”</p>\n</li>\n<li>\n<p data-path-to-node=\"25,2,0\"><strong>Giải thích:</strong> Đất đai (soil) và khí hậu Ireland rất phù hợp với khoai tây.</p>\n</li>\n</ul>\n<p>12. Between 1780 and 1841, based on the <strong>cultivation</strong> of the potatoes, the Irish population doubled to eight million.</p>\n<ul data-path-to-node=\"27\">\n<li>\n<p data-path-to-node=\"27,0,0\"><strong>Đáp án:</strong> <strong>cultivation</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"27,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 10) “The Irish population doubled to eight million between 1780 and 1841, without any significant expansion of industry or reform of agricultural techniques beyond the widespread <strong>cultivation</strong> of the potato.”</p>\n</li>\n<li>\n<p data-path-to-node=\"27,2,0\"><strong>Giải thích:</strong> Sự gia tăng dân số dựa trên việc trồng trọt/canh tác (cultivation) khoai tây rộng rãi.</p>\n</li>\n</ul>\n<p>13. The potato’s high yields helped the poorest farmers to produce much healthier food almost without <strong>investment</strong> or hard physical work.</p>\n<ul data-path-to-node=\"29\">\n<li>\n<p data-path-to-node=\"29,0,0\"><strong>Đáp án:</strong> <strong>investment</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"29,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 10) “…the potato’s high yields allowed even the poorest farmers to produce more healthy food than they needed with scarcely any <strong>investment</strong> or hard labour.”</p>\n</li>\n<li>\n<p data-path-to-node=\"29,2,0\"><strong>Giải thích:</strong> Năng suất cao của khoai tây giúp nông dân nghèo không cần đầu tư (investment).</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('10fe2a31-2db9-4a9a-b859-28da772a7db7', 'dc7bc774-25b8-4b2b-aeed-14104a420804', 'fillup', 'Question 1-10', '<p>Write <strong>ONE WORD AND/OR NUMBER</strong> for each answer.</p>
<table class="MsoNormalTable" style="border-collapse: collapse; mso-table-layout-alt: fixed; border: none; mso-yfti-tbllook: 1536; mso-padding-alt: 0in 5.4pt 0in 5.4pt; mso-border-insideh: cell-none; mso-border-insidev: cell-none;" border="1" width="602" cellspacing="0" cellpadding="0">
